// ═══════════════════════════════════════════════════════════════
// UNIT 1: Willkommen in Deutschland
// Story: Verumius arrives at BER, gets on wrong train, meets Dr. Yilmaz
// CEFR: A1.1 - Survival German, first words, first verbs
// ═══════════════════════════════════════════════════════════════
{n:1,lang:"de",srcLang:"en",track:"v2",title:"Willkommen in Deutschland",sub:"Airport arrival, wrong train, first German words",icon:"\u2708\uFE0F",level:"A1.1",color:"#7B5EE8",lessons:[

// ─── L1: Ankunft ───
{id:"deu_r1l1",title:"Ankunft",icon:"\u2708\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Willkommen in Deutschland",desc:"Verumius arrives in Germany for the first time. But things don't go as planned...",goals:["Learn basic greetings","Understand simple questions","Survive your first German conversation"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-ber-airport",trg:"Flughafen Berlin Brandenburg. Die Türen öffnen sich. Warme Luft, fremde Stimmen, deutsche Schilder überall. Verumius atmet tief ein. Er ist da.",src:"Berlin Brandenburg Airport. The doors open. Warm air, unfamiliar voices, German signs everywhere. Verumius takes a deep breath. He is here."},
{type:"teach",trg:"Hallo",src:"Hello",note:"The most common informal greeting in German.",example:"A: Hallo! Wie geht's?\nB: Hallo! Gut, danke!",exampleSrc:"A: Hello! How's it going?\nB: Hello! Good, thanks!",funFact:"'Hallo' only became common in German in the early 1900s, borrowed from English telephone culture. Before that, Germans said 'Guten Tag.'"},
{type:"teach",trg:"Entschuldigung",src:"Excuse me / Sorry",note:"Used to get attention or to apologize.",example:"A: Entschuldigung, wo ist der Bahnhof?\nB: Geradeaus und dann links.",exampleSrc:"A: Excuse me, where is the train station?\nB: Straight ahead and then left.",funFact:"15 letters long! Literally 'un-guilt-ification.' Germans build words like LEGO bricks: Ent + schuld + ig + ung."},
{type:"teach",trg:"der Zug",src:"the train",note:"Masculine noun. Plural: die Züge.",example:"A: Wann fährt der Zug?\nB: Der Zug fährt um 14 Uhr.",exampleSrc:"A: When does the train leave?\nB: The train leaves at 2 PM.",funFact:"'Zug' literally means 'pull.' The word also means 'a gulp' of beer and 'a move' in chess. Context is everything!"},
{type:"teach",trg:"fahren",src:"to drive / to go (by vehicle)",note:"Irregular verb: ich fahre, du fährst, er fährt.",example:"A: Fahren Sie nach Hamburg?\nB: Nein, ich fahre nach Berlin.",exampleSrc:"A: Are you going to Hamburg?\nB: No, I'm going to Berlin.",funFact:"The ae in 'fährst/fährt' is a stem vowel change. Many common German verbs do this: schlafen to schläft, laufen to läuft."},
{type:"verb_table",title:"fahren (to drive/go)",groups:[{label:"Present tense (stem change: a → ä)",rows:[{pronoun:"ich",form:"fahre",src:"I drive"},{pronoun:"du",form:"fährst",src:"you drive"},{pronoun:"er/sie/es",form:"fährt",src:"he/she/it drives"},{pronoun:"wir",form:"fahren",src:"we drive"},{pronoun:"ihr",form:"fahrt",src:"you all drive"},{pronoun:"sie/Sie",form:"fahren",src:"they/you (formal) drive"}]}],note:"Stem vowel a changes to ä in du and er/sie/es forms. Same pattern: schlafen, laufen, waschen."},
{type:"tip",title:"Stem-Changing Verbs",text:"Some German verbs change their vowel in the du and er/sie/es forms.\n\nfahren: du fährst, er fährt\nschlafen: du schläfst, er schläft\nsprechen: du sprichst, er spricht\n\nThe ich, wir, ihr, and Sie forms stay regular."},
{type:"mc",q:"What does 'Entschuldigung' mean?",opts:["Excuse me","Thank you","Goodbye","Hello"],ans:"Excuse me",hint:"Think about getting someone's attention on the street."},
{type:"mc",q:"'Der Zug fährt um 14 Uhr.' What is leaving at 2 PM?",opts:["The bus","The train","The plane","The taxi"],ans:"The train",hint:"This masculine noun is related to pulling."},
{type:"teach",trg:"sprechen",src:"to speak",note:"Irregular: ich spreche, du sprichst, er spricht.",example:"A: Sprechen Sie Deutsch?\nB: Ja, ein bisschen.",exampleSrc:"A: Do you speak German?\nB: Yes, a little bit.",funFact:"Related to English 'speak.' Both come from the same ancient root. German kept the 'spr-' cluster that English simplified."},
{type:"verb_table",title:"sprechen (to speak)",groups:[{label:"Present tense (stem change: e → i)",rows:[{pronoun:"ich",form:"spreche",src:"I speak"},{pronoun:"du",form:"sprichst",src:"you speak"},{pronoun:"er/sie/es",form:"spricht",src:"he/she/it speaks"},{pronoun:"wir",form:"sprechen",src:"we speak"},{pronoun:"ihr",form:"sprecht",src:"you all speak"},{pronoun:"sie/Sie",form:"sprechen",src:"they/you (formal) speak"}]}],note:"Stem vowel e changes to i in du and er/sie/es. Same pattern: geben, nehmen, essen."},
{type:"teach",trg:"ein bisschen",src:"a little bit",note:"Used to soften statements. Very handy when learning!",example:"A: Können Sie Deutsch?\nB: Ja, ein bisschen.",exampleSrc:"A: Can you speak German?\nB: Yes, a little.",funFact:"'Bisschen' comes from 'Biss' (bite). So 'ein bisschen' literally means 'one little bite.' A bite-sized amount!"},
{type:"fb",s:"Sprechen Sie {1}?",a:["Deutsch"],opts:["Deutsch","Hamburg","Zug","Entschuldigung"],hint:"What language are you asking about in this sentence?",sSrc:"Do you speak {1}?"},
{type:"mc",q:"Verumius says 'Ich spreche ein bisschen Deutsch.' What does this mean?",opts:["I speak perfect German","I don't speak German","I speak a little German","I want to learn German"],ans:"I speak a little German",hint:"'Ein bisschen' means a small, bite-sized amount."},
{type:"teach",trg:"der Bahnhof",src:"the train station",note:"Masculine noun. Compound: Bahn (track) + Hof (yard).",example:"A: Wo ist der Bahnhof?\nB: Der Bahnhof ist dort drüben.",exampleSrc:"A: Where is the train station?\nB: The train station is over there.",funFact:"Germans love compound nouns. Bahnhof = track-yard. Hauptbahnhof = main-track-yard. Bahnhofsviertel = track-yard-quarter!"},
{type:"teach",trg:"nach",src:"to / toward (a city or country)",note:"Used with city and country names. 'Ich fahre nach Berlin.'",example:"A: Wohin fährst du?\nB: Ich fahre nach Deutschland.",exampleSrc:"A: Where are you going?\nB: I'm going to Germany.",funFact:"'Nach' is one of those small German words with big power. It means 'to' (nach Berlin), 'after' (nach dem Essen), and even 'according to' (nach meiner Meinung). Context decides which meaning applies."},
{type:"mc",q:"Verumius says 'Ich fahre nach Berlin.' What does 'nach' mean here?",opts:["away from","inside of","together with","to / toward"],ans:"to / toward",hint:"He is traveling in the direction of Berlin."},
{type:"fb",s:"Ich fahre {1} Hamburg.",a:["nach"],opts:["nach","in","von","mit"],hint:"Which preposition means 'to' when talking about traveling to a city?",sSrc:"I am going {1} Hamburg."},
{type:"mc",q:"Which word means 'the train station' in German?",opts:["der Bahnhof","der Zug","der Ausgang","das Gleis"],ans:"der Bahnhof",hint:"This compound noun names a place where tracks meet."},
{type:"match",pairs:[{trg:"Hallo",src:"Hello"},{trg:"Entschuldigung",src:"Excuse me"},{trg:"der Zug",src:"the train"},{trg:"sprechen",src:"to speak"},{trg:"der Bahnhof",src:"the train station"},{trg:"ein bisschen",src:"a little bit"}]}
]},

// ─── L2: Erste Wörter ───
{id:"deu_r1l2",title:"Erste Wörter",icon:"\uD83D\uDDE3\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Erste Wörter",desc:"Your survival vocabulary for day one in Germany. These twelve words will get you through airports, shops, and awkward silences.",goals:["Master essential greetings and farewells","Introduce yourself in German","Ask for help when you're lost"]},
{type:"teach",trg:"Guten Tag",src:"Good day (formal greeting)",note:"The standard formal greeting, used any time of day.",example:"A: Guten Tag! Ich bin Dr. Yilmaz.\nB: Guten Tag! Freut mich.",exampleSrc:"A: Good day! I am Dr. Yilmaz.\nB: Good day! Nice to meet you.",funFact:"Germans have greetings for every time of day: Guten Morgen (morning), Guten Tag (day), Guten Abend (evening). In Bavaria, you'll hear 'Grüß Gott' instead."},
{type:"teach",trg:"Tschüss",src:"Bye",note:"Informal farewell. Pronounced like 'choose' with a softer ch.",example:"A: Ich muss gehen. Tschüss!\nB: Tschüss! Bis morgen!",exampleSrc:"A: I have to go. Bye!\nB: Bye! See you tomorrow!",funFact:"'Tschüss' evolved from the French 'adieu' (to God), which became 'adjuees' in dialect, then 'tschuess.' A French farewell in German clothing!"},
{type:"teach",trg:"Auf Wiedersehen",src:"Goodbye (formal)",note:"Literally: 'Until seeing again.' The formal farewell.",example:"A: Vielen Dank für Ihre Hilfe!\nB: Gern geschehen. Auf Wiedersehen!",exampleSrc:"A: Thank you very much for your help!\nB: You're welcome. Goodbye!",funFact:"'Auf Wiedersehen' is literally 'upon again-seeing.' On the phone, Germans say 'Auf Wiederhören' (upon again-hearing) instead. Precision in every farewell!"},
{type:"teach",trg:"Danke",src:"Thank you",note:"Short and essential. 'Danke schön' is more polite.",example:"A: Hier ist Ihr Kaffee.\nB: Danke!",exampleSrc:"A: Here is your coffee.\nB: Thank you!",funFact:"'Danke' and English 'thank' are cousins. Both come from the same Germanic root meaning 'to think.' Thanking someone originally meant 'I will think of what you did.'"},
{type:"teach",trg:"Bitte",src:"Please / You're welcome / Here you go",note:"Three meanings! Context tells you which one.",example:"A: Kann ich einen Kaffee haben, bitte?\nB: Bitte schön!",exampleSrc:"A: Can I have a coffee, please?\nB: Here you go!",funFact:"'Bitte' is the Swiss Army knife of German words. 'Bitte' (please), 'Bitte!' (you're welcome), 'Bitte?' (pardon?), 'Bitte schön' (here you go). One word, four jobs."},
{type:"mc",q:"A waiter hands you a coffee and says 'Bitte schön!' What does this mean here?",opts:["Please order","Thank you","Here you go","Goodbye"],ans:"Here you go",hint:"The waiter is handing something to you, not asking."},
{type:"fb",s:"Vielen {1}!",a:["Dank"],opts:["Dank","Bitte","Tag","Nacht"],hint:"'Vielen ___' is the formal way to express gratitude.",sSrc:"Many ___!"},
{type:"teach",trg:"Ja",src:"Yes",note:"Pronounced 'yah.' Simple and direct.",example:"A: Sind Sie Verumius?\nB: Ja, das bin ich!",exampleSrc:"A: Are you Verumius?\nB: Yes, that's me!",funFact:"In casual speech, Germans often say 'Ja' as a filler word, like English 'yeah' or 'right.' You might hear 'Ja, also...' (Yeah, so...) constantly."},
{type:"teach",trg:"Nein",src:"No",note:"Pronounced 'nine' (like the number). Clear and firm.",example:"A: Sprechen Sie Französisch?\nB: Nein, leider nicht.",exampleSrc:"A: Do you speak French?\nB: No, unfortunately not.",funFact:"Germans are known for directness. A German 'Nein' means no. No softening, no maybe. In business, this directness is respected, not rude."},
{type:"mc",q:"Someone asks 'Sprechen Sie Japanisch?' and you don't. What do you say?",opts:["Ja","Nein","Danke","Bitte"],ans:"Nein",hint:"You need the word for a negative answer here."},
{type:"teach",trg:"Ich bin...",src:"I am...",note:"From the verb 'sein' (to be). The most basic self-intro.",example:"A: Wer sind Sie?\nB: Ich bin Verumius.",exampleSrc:"A: Who are you?\nB: I am Verumius.",funFact:"'Bin' is one of the most irregular forms in German. Sein conjugates: ich bin, du bist, er ist, wir sind, ihr seid, sie sind. Almost every form is different!"},
{type:"teach",trg:"Wie heißen Sie?",src:"What is your name? (formal)",note:"Literally: 'How are-called you?' Uses the formal Sie.",example:"A: Guten Tag! Wie heißen Sie?\nB: Ich heiße Anna. Und Sie?",exampleSrc:"A: Good day! What is your name?\nB: My name is Anna. And you?",funFact:"'Heissen' literally means 'to be called.' Germans don't 'have' a name, they 'are called' it. The informal version is 'Wie heißt du?'"},
{type:"fb",s:"Guten Tag! {1} heißen Sie?",a:["Wie"],opts:["Wie","Was","Wo","Wer"],hint:"You need the question word meaning 'how' here.",sSrc:"Good day! {1} is your name?"},
{type:"teach",trg:"Woher kommen Sie?",src:"Where do you come from? (formal)",note:"Woher = where from. Kommen = to come. Sie = you (formal).",example:"A: Woher kommen Sie?\nB: Ich komme aus Italien.",exampleSrc:"A: Where do you come from?\nB: I come from Italy.",funFact:"'Woher' splits into 'wo' (where) + 'her' (from/towards the speaker). German has 'wohin' too: 'wo' + 'hin' (to/away from speaker). Direction matters!"},
{type:"teach",trg:"Deutschland",src:"Germany",note:"Neuter noun: das Deutschland. No plural needed.",example:"A: Wo sind wir?\nB: Wir sind in Deutschland!",exampleSrc:"A: Where are we?\nB: We are in Germany!",funFact:"Every language has a different name for Germany. French: Allemagne. Italian: Germania. Finnish: Saksa. Polish: Niemcy. The Germans call themselves 'Deutsche' from an old word meaning 'the people.'"},
{type:"mc",q:"Verumius says 'Ich komme aus Italien.' Where is he from?",opts:["Germany","France","Spain","Italy"],ans:"Italy",hint:"'Italien' sounds very similar to its English equivalent."},
{type:"teach",trg:"Ich verstehe nicht",src:"I don't understand",note:"'Verstehen' = to understand. 'Nicht' = not.",example:"A: Der Zug fährt von Gleis siebzehn.\nB: Entschuldigung, ich verstehe nicht.",exampleSrc:"A: The train departs from platform seventeen.\nB: Excuse me, I don't understand.",funFact:"You'll use this phrase a LOT as a beginner. 'Verstehen' literally means 'to stand before' something, as if standing in front of an idea until you grasp it."},
{type:"teach",trg:"wiederholen",src:"to repeat",note:"A formal request: 'Können Sie das bitte wiederholen?'",example:"A: Ich verstehe nicht. Können Sie das wiederholen?\nB: Natürlich! Der Zug fährt um neun.",exampleSrc:"A: I don't understand. Can you repeat that?\nB: Of course! The train leaves at nine.",funFact:"'Wieder' (again) + 'holen' (to fetch). To repeat is to 'fetch again.' Germans build meaning by stacking simple words together."},
{type:"mc",q:"You didn't catch what someone said. Which phrase asks them to say it again?",opts:["Können Sie das wiederholen?","Ich bin Verumius, freut mich.","Woher kommen Sie eigentlich?","Tschüss, bis morgen dann!"],ans:"Können Sie das wiederholen?",hint:"You need the verb that means 'to fetch again.'"},
{type:"fb",s:"Ich {1} nicht.",a:["verstehe"],opts:["verstehe","spreche","heiße","komme"],hint:"Which verb means 'to understand' in German?",sSrc:"I do not {1}."},
{type:"teach",trg:"gehen",src:"to go (on foot)",note:"Regular present tense: ich gehe, du gehst, er geht.",example:"A: Ich muss gehen. Tschüss!\nB: Tschüss! Bis morgen!",exampleSrc:"A: I have to go. Bye!\nB: Bye! See you tomorrow!",funFact:"'Wie geht es Ihnen?' literally means 'How goes it to you?' One of the first verbs every German learner needs."},
{type:"verb_table",title:"gehen (to go on foot)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"gehe",src:"I go"},{pronoun:"du",form:"gehst",src:"you go"},{pronoun:"er/sie/es",form:"geht",src:"he/she/it goes"},{pronoun:"wir",form:"gehen",src:"we go"},{pronoun:"ihr",form:"geht",src:"you all go"},{pronoun:"sie/Sie",form:"gehen",src:"they/you (formal) go"}]}],note:"Regular in present tense. Wie geht es Ihnen? = How are you?"},
{type:"teach",trg:"sagen",src:"to say / to tell",note:"Regular: ich sage, du sagst, er sagt.",example:"A: Was sagt er?\nB: Er sagt 'Guten Tag!'",exampleSrc:"A: What does he say?\nB: He says 'Good day!'",funFact:"You will see 'sagt' constantly in German texts. 'Verumius sagt...' = Verumius says... Essential narrative word."},
{type:"teach",trg:"machen",src:"to do / to make",note:"Regular: ich mache, du machst, er macht.",example:"A: Was machst du?\nB: Ich mache meine Hausaufgaben.",exampleSrc:"A: What are you doing?\nB: I'm doing my homework.",funFact:"One of German's most versatile verbs. 'Das macht nichts' = that doesn't matter. 'Das macht Spaß' = that's fun. 'Mach's gut!' = take care!"},
{type:"verb_table",title:"machen (to make/do)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"mache",src:"I do/make"},{pronoun:"du",form:"machst",src:"you do/make"},{pronoun:"er/sie/es",form:"macht",src:"he/she/it does/makes"},{pronoun:"wir",form:"machen",src:"we do/make"},{pronoun:"ihr",form:"macht",src:"you all do/make"},{pronoun:"sie/Sie",form:"machen",src:"they/you (formal) do/make"}]}],note:"Regular. Das macht nichts = That doesn't matter."},
{type:"teach",trg:"etwas",src:"something / a little",note:"Used everywhere: 'Ich möchte etwas trinken.' = I'd like something to drink.",example:"A: Möchtest du etwas essen?\nB: Ja, etwas Brot bitte.",exampleSrc:"A: Would you like something to eat?\nB: Yes, some bread please.",funFact:"'Etwas' can mean 'something' or 'a bit.' 'Etwas Wasser' = some water. 'Etwas Neues' = something new."},
{type:"match",pairs:[{trg:"Guten Tag",src:"Good day"},{trg:"Tschüss",src:"Bye"},{trg:"Danke",src:"Thank you"},{trg:"Bitte",src:"Please"},{trg:"Ich bin...",src:"I am..."},{trg:"Wie heißen Sie?",src:"What is your name?"},{trg:"Deutschland",src:"Germany"},{trg:"gehen",src:"to go"}]}
]},

// ─── L3: Im falschen Zug ───
{id:"deu_r1l3",title:"Im falschen Zug",icon:"\uD83D\uDE82",xp:15,board:true,steps:[
{type:"intro",title:"Im falschen Zug",desc:"Verumius and Dr. Yilmaz are on the ICE train. She teaches him how to ask questions in German. But when the ticket inspector arrives, Verumius discovers a small problem...",goals:["Learn the 7 German W-question words","Understand W-question word order","Survive a ticket inspection"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-ice-train",trg:"Im ICE. Verumius sitzt am Fenster. Draußen fliegen Felder und Dörfer vorbei. Dr. Yilmaz öffnet ihr Notizbuch und lächelt.",src:"On the ICE train. Verumius sits by the window. Outside, fields and villages fly past. Dr. Yilmaz opens her notebook and smiles."},
{type:"story",speaker:"Yilmaz",trg:"So, Verumius. In German, every question starts with a W-Wort. Wer, was, wo, woher, wohin, wann, wie. Seven little words that open every door.",src:"So, Verumius. In German, every question starts with a W-word. Who, what, where, where from, where to, when, how. Seven little words that open every door."},
{type:"teach",speaker:"yilmaz",trg:"wer",src:"who",note:"Asks about a person. Always at the start of the question.",example:"A: Wer ist das?\nB: Das ist mein Bruder.",exampleSrc:"A: Who is that?\nB: That is my brother.",funFact:"'Wer' and English 'who' are ancient cousins. Both come from Proto-Germanic 'hwaz.' English lost the 'w' sound, German kept it."},
{type:"teach",speaker:"yilmaz",trg:"was",src:"what",note:"Asks about things, actions, or ideas.",example:"A: Was machst du?\nB: Ich lese ein Buch.",exampleSrc:"A: What are you doing?\nB: I am reading a book.",funFact:"'Was' and English 'what' share the same root. In casual German, 'was' often gets shortened to 'wat' in Berlin dialect. Berliners love dropping letters."},
{type:"teach",speaker:"yilmaz",trg:"wo",src:"where",note:"Asks about location. Static position, not direction.",example:"A: Wo wohnst du?\nB: Ich wohne in Berlin.",exampleSrc:"A: Where do you live?\nB: I live in Berlin.",funFact:"German splits 'where' into three words: 'wo' (where at), 'woher' (where from), and 'wohin' (where to). English just uses 'where' for all three!"},
{type:"teach",speaker:"yilmaz",trg:"woher",src:"where from",note:"Asks about origin or direction of approach.",example:"A: Woher kommst du?\nB: Ich komme aus der Türkei.",exampleSrc:"A: Where do you come from?\nB: I come from Turkey.",funFact:"'Wo' + 'her' (toward the speaker). 'Her' indicates movement TOWARD you. If someone is coming your way, it is 'herkommen.' If they are going away, it is 'hinkommen.'"},
{type:"teach",speaker:"yilmaz",trg:"wohin",src:"where to",note:"Asks about destination or direction of travel.",example:"A: Wohin fährst du?\nB: Ich fahre nach Hamburg.",exampleSrc:"A: Where are you going?\nB: I am going to Hamburg.",funFact:"'Wo' + 'hin' (away from the speaker). A common mistake for learners: 'Wo gehst du?' means 'Where ARE you?' not 'Where are you GOING?' For going, always use 'wohin.'"},
{type:"story",speaker:"Verumius",trg:"Okay, ich probiere. Wohin... fährt... dieser Zug?",src:"Okay, I'll try. Where... does... this train go?"},
{type:"story",speaker:"Yilmaz",trg:"Sehr gut! Der Zug fährt nach Hamburg. Und wohin fährst DU?",src:"Very good! The train goes to Hamburg. And where are YOU going?"},
{type:"teach",speaker:"yilmaz",trg:"wann",src:"when",note:"Asks about time. Expect a clock time or day as answer.",example:"A: Wann kommst du?\nB: Ich komme um drei Uhr.",exampleSrc:"A: When are you coming?\nB: I am coming at three o'clock.",funFact:"English 'when' and German 'wann' are the same word, just spelled differently. Both come from Proto-Germanic 'hwannai.' You already know this one!"},
{type:"teach",speaker:"yilmaz",trg:"wie",src:"how",note:"Asks about manner, condition, or method.",example:"A: Wie geht es Ihnen?\nB: Gut, danke! Und Ihnen?",exampleSrc:"A: How are you?\nB: Good, thanks! And you?",funFact:"'Wie heißen Sie?' literally asks 'How are you called?' not 'What is your name?' German uses 'wie' (how) where English uses 'what' in many phrases."},
{type:"tip",title:"W-Question Word Order",text:"German W-questions follow a strict pattern:\n\nW-Wort + Verb + Subject + Rest\n\nWo wohnst du? (Where live you?)\nWas machst du? (What do you?)\nWann kommst du? (When come you?)\n\nThe verb is ALWAYS in position 2.\nThe subject slides to position 3.\nThis is called V2 word order."},
{type:"mc",q:"You want to ask about someone's location. Which W-word fits?",opts:["wann","wer","wo","wie"],ans:"wo",hint:"This word asks about a static location."},
{type:"fb",s:"{1} fährt der Zug? Um 14 Uhr.",a:["Wann"],opts:["Wann","Wo","Wer","Was"],hint:"The answer is a time, so the question asks about timing.",sSrc:"{1} does the train leave? At 2 PM."},
{type:"mc",q:"'Wohin gehst du?' asks about your ___.",opts:["hometown origin","destination","full name","arrival time"],ans:"destination",hint:"'Hin' indicates movement away from the speaker."},
{type:"fb",s:"{1} kommst du? Aus Italien.",a:["Woher"],opts:["Woher","Wohin","Wo","Wann"],hint:"The answer names an origin country, so the question asks about source.",sSrc:"{1} do you come from? From Italy."},
{type:"teach",trg:"die Fahrkarte",src:"the ticket",note:"Feminine noun. Fahrt (journey) + Karte (card) = travel card.",example:"A: Haben Sie Ihre Fahrkarte?\nB: Ja, hier bitte!",exampleSrc:"A: Do you have your ticket?\nB: Yes, here please!",funFact:"Germans compound 'Fahrt' (journey) + 'Karte' (card) into one word. A Fahrkarte is literally a 'journey card.' You can also say 'Ticket' in modern German, but Fahrkarte is the official Deutsche Bahn term."},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-ice-inspector",trg:"Der Schaffner kommt. Ein großer Mann mit Uniform und strengem Blick.",src:"The ticket inspector arrives. A tall man in uniform with a stern look."},
{type:"story",speaker:"inspector",trg:"Fahrkarte, bitte!",src:"Ticket, please!"},
{type:"story",speaker:"Verumius",trg:"Hier, bitte! ...Moment. Hier steht Berlin. Aber Sie sagten, der Zug fährt nach Hamburg?",src:"Here, please! ...Wait. This says Berlin. But you said the train goes to Hamburg?"},
{type:"story",speaker:"Yilmaz",trg:"Oh. Du bist im falschen Zug, Verumius.",src:"Oh. You are on the wrong train, Verumius."},
{type:"mc",q:"What does the ticket inspector say when he arrives?",opts:["Wohin fahren Sie?","Guten Morgen!","Fahrkarte, bitte!","Wie heißen Sie?"],ans:"Fahrkarte, bitte!",hint:"He needs to see a specific travel document."}
]},

// ─── L4: Ich bin, du bist ───
{id:"deu_r1l4",title:"Ich bin, du bist",icon:"\uD83D\uDD24",xp:15,board:true,steps:[
{type:"intro",title:"Ich bin, du bist, er ist",desc:"The two most important verbs in any language: to be and to have. Master 'sein' and 'haben,' and you can describe almost anything.",goals:["Conjugate sein (to be) in present tense","Conjugate haben (to have) in present tense","Understand du vs. Sie","Learn basic regular verb endings"]},
{type:"verb_table",title:"sein (to be)",groups:[{label:"Present tense",rows:[
{pronoun:"ich",form:"bin",src:"I am"},
{pronoun:"du",form:"bist",src:"you are (informal)"},
{pronoun:"er/sie/es",form:"ist",src:"he/she/it is"},
{pronoun:"wir",form:"sind",src:"we are"},
{pronoun:"ihr",form:"seid",src:"you all are"},
{pronoun:"sie/Sie",form:"sind",src:"they are / you are (formal)"}
]}],note:"Sein is completely irregular. Every form looks different. The good news: it is the same in almost every European language. English 'am/are/is,' Spanish 'soy/eres/es.'"},
{type:"verb_table",title:"haben (to have)",groups:[{label:"Present tense",rows:[
{pronoun:"ich",form:"habe",src:"I have"},
{pronoun:"du",form:"hast",src:"you have (informal)"},
{pronoun:"er/sie/es",form:"hat",src:"he/she/it has"},
{pronoun:"wir",form:"haben",src:"we have"},
{pronoun:"ihr",form:"habt",src:"you all have"},
{pronoun:"sie/Sie",form:"haben",src:"they have / you have (formal)"}
]}],note:"Haben drops the 'b' in du hast and er hat. Otherwise, the endings follow the regular pattern: -e, -st, -t, -en, -t, -en."},
{type:"teach",trg:"ich / du / er / sie / es",src:"I / you / he / she / it",note:"The singular pronouns. 'Du' is informal, for friends and family.",example:"A: Bist du müde?\nB: Ja, ich bin sehr müde!",exampleSrc:"A: Are you tired?\nB: Yes, I am very tired!",funFact:"'Du' is the ancient familiar form, from Proto-Germanic. English lost its equivalent 'thou' centuries ago. Germans still use 'du' for everyone they are close to."},
{type:"teach",trg:"wir / ihr / sie / Sie",src:"we / you all / they / you (formal)",note:"Plural pronouns. 'Sie' (capital S) is the formal 'you.'",example:"A: Seid ihr Studenten?\nB: Ja, wir sind Studenten.",exampleSrc:"A: Are you all students?\nB: Yes, we are students.",funFact:"The formal 'Sie' is actually the third person plural ('they'). Addressing someone as 'they' was once a sign of extreme respect, creating distance. It stuck around!"},
{type:"teach",trg:"Sie",src:"you (formal)",note:"Always capitalized. Used with strangers, bosses, officials, older people.",example:"A: Sind Sie Herr Müller?\nB: Ja, ich bin Herr Müller.",exampleSrc:"A: Are you Mr. Müller?\nB: Yes, I am Mr. Müller.",funFact:"The du/Sie divide is serious. Using 'du' with your boss without being invited to is a social misstep. The boss decides when to switch. This moment is called 'das Duzen anbieten.'"},
{type:"tip",title:"Du or Sie?",text:"Use 'du' with:\n- Friends and family\n- Children and teenagers\n- Fellow students\n- People who offer it\n\nUse 'Sie' with:\n- Strangers over ~16\n- Officials, police, doctors\n- Your boss (until they offer du)\n- Customer service\n\nWhen in doubt, use Sie. It is always safer to be too formal than too casual."},
{type:"mc",q:"How do you say 'I am Verumius' in German?",opts:["Ich bist Verumius","Ich bin Verumius","Ich ist Verumius","Ich sind Verumius"],ans:"Ich bin Verumius",hint:"Match the pronoun 'ich' to its correct form of sein."},
{type:"fb",s:"Du {1} im falschen Zug!",a:["bist"],opts:["bist","bin","ist","sind"],hint:"Which form of sein goes with the pronoun 'du'?",sSrc:"You {1} on the wrong train!"},
{type:"mc",q:"'Wir ___ Studenten.' Fill in the correct form of sein.",opts:["bin","bist","ist","sind"],ans:"sind",hint:"The pronoun 'wir' needs the same form as 'sie' (they)."},
{type:"fb",s:"Er {1} eine Fahrkarte nach Berlin.",a:["hat"],opts:["hat","hast","habe","haben"],hint:"Which form of haben goes with 'er'?",sSrc:"He {1} a ticket to Berlin."},
{type:"mc",q:"'Ich ___ einen Koffer.' Which verb form completes this?",opts:["hast","hat","habe","haben"],ans:"habe",hint:"The first person singular always ends in -e."},
{type:"tip",title:"Verb in Position 2 (V2 Rule)",text:"In German statements, the conjugated verb is ALWAYS in the second position.\n\nIch bin Verumius. (I am Verumius.)\nHeute bin ich müde. (Today am I tired.)\nIn Berlin wohne ich. (In Berlin live I.)\n\nNo matter what starts the sentence, the verb stays in slot 2.\nThe subject moves around the verb to make room."},
{type:"teach",trg:"kommen",src:"to come",note:"Regular verb. Follows the standard pattern: -e, -st, -t, -en, -t, -en.",example:"A: Woher kommen Sie?\nB: Ich komme aus der Schweiz.",exampleSrc:"A: Where do you come from?\nB: I come from Switzerland.",funFact:"'Kommen' and English 'come' are the same ancient word. Both from Proto-Germanic 'kwemana.' German just added an extra 'm.' The pronunciation barely changed in 2,000 years."},
{type:"verb_table",title:"kommen (to come)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"komme",src:"I come"},{pronoun:"du",form:"kommst",src:"you come"},{pronoun:"er/sie/es",form:"kommt",src:"he/she/it comes"},{pronoun:"wir",form:"kommen",src:"we come"},{pronoun:"ihr",form:"kommt",src:"you all come"},{pronoun:"sie/Sie",form:"kommen",src:"they/you (formal) come"}]}],note:"Regular conjugation. Woher kommen Sie? = Where do you come from?"},
{type:"teach",trg:"lernen",src:"to learn",note:"Regular: ich lerne, du lernst, er lernt, wir lernen.",example:"A: Was lernst du?\nB: Ich lerne Deutsch!",exampleSrc:"A: What are you learning?\nB: I am learning German!",funFact:"'Lernen' and English 'learn' are twins. 'Lehren' (to teach) is the cousin. A Lehrer is a teacher. A Lehrling is an apprentice, someone still learning."},
{type:"verb_table",title:"lernen (to learn)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"lerne",src:"I learn"},{pronoun:"du",form:"lernst",src:"you learn"},{pronoun:"er/sie/es",form:"lernt",src:"he/she/it learns"},{pronoun:"wir",form:"lernen",src:"we learn"},{pronoun:"ihr",form:"lernt",src:"you all learn"},{pronoun:"sie/Sie",form:"lernen",src:"they/you (formal) learn"}]}],note:"Regular pattern: stem + -e, -st, -t, -en, -t, -en. Same for: wohnen, kaufen, spielen, kochen."},
{type:"teach",trg:"wohnen",src:"to live / to reside",note:"Regular: ich wohne, du wohnst, er wohnt, wir wohnen.",example:"A: Wo wohnst du?\nB: Ich wohne in München.",exampleSrc:"A: Where do you live?\nB: I live in Munich.",funFact:"'Wohnen' means to reside somewhere. 'Leben' means to be alive. Germans say 'Ich wohne in Berlin' (I reside in Berlin) but 'Ich lebe gern' (I enjoy being alive). Two different concepts!"},
{type:"verb_table",title:"wohnen (to live/reside)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"wohne",src:"I live"},{pronoun:"du",form:"wohnst",src:"you live"},{pronoun:"er/sie/es",form:"wohnt",src:"he/she/it lives"},{pronoun:"wir",form:"wohnen",src:"we live"},{pronoun:"ihr",form:"wohnt",src:"you all live"},{pronoun:"sie/Sie",form:"wohnen",src:"they/you (formal) live"}]}],note:"Regular pattern. Wo wohnen Sie? = Where do you live?"},
{type:"tip",title:"Regular Verb Endings",text:"Remove -en from the infinitive to get the stem, then add:\n\nich: -e (ich komme)\ndu: -st (du kommst)\ner/sie/es: -t (er kommt)\nwir: -en (wir kommen)\nihr: -t (ihr kommt)\nsie/Sie: -en (sie kommen)\n\nThis pattern works for most German verbs.\nSein and haben are the big exceptions."},
{type:"fb",s:"Woher {1} Sie?",a:["kommen"],opts:["kommen","kommst","komme","kommt"],hint:"The formal Sie uses the same ending as wir and sie (they).",sSrc:"Where {1} you from?"},
{type:"mc",q:"'Du ___ in Hamburg.' Which form of wohnen is correct?",opts:["wohne","wohnst","wohnt","wohnen"],ans:"wohnst",hint:"The du-form always ends in -st for regular verbs."},
{type:"fb",s:"Wir {1} Deutsch.",a:["lernen"],opts:["lernen","lernst","lernt","lerne"],hint:"The wir-form keeps the full infinitive ending.",sSrc:"We {1} German."},
{type:"teach",trg:"heute",src:"today",note:"Adverb. One of the most common German words.",example:"A: Was machst du heute?\nB: Heute lerne ich Deutsch.",exampleSrc:"A: What are you doing today?\nB: Today I'm learning German.",funFact:"From Old High German 'hiutu.' When heute starts a sentence, the verb moves to position 2 and the subject flips behind it: 'Heute bin ich müde.'"},
{type:"mc",q:"Which sentence follows correct V2 word order?",opts:["Heute ich bin müde.","Ich heute müde bin.","Muede ich bin heute.","Heute bin ich müde."],ans:"Heute bin ich müde.",hint:"The verb must be in the second position, right after the first element."},
{type:"fb",s:"Sie {1} aus Deutschland.",a:["kommt"],opts:["kommt","kommen","kommst","komme"],hint:"Third person singular: she does something, ending in -t.",sSrc:"She {1} from Germany."},
// --- Recycling: L1-L3 vocab in conjugation context ---
{type:"fb",s:"Verumius {1} ein bisschen Deutsch.",a:["spricht"],opts:["spricht","spreche","sprichst","sprechen"],hint:"Which form of sprechen goes with a name or 'er'?",sSrc:"Verumius {1} a little German."},
{type:"mc",q:"Dr. Yilmaz asks formally: 'Woher ___ Sie?' Which verb completes this?",opts:["komme","kommen","kommst","kommt"],ans:"kommen",hint:"The formal Sie uses the same verb ending as wir."}
]},

// ─── L5: Zahlen und Zeit ───
{id:"deu_r1l5",title:"Zahlen und Zeit",icon:"\uD83D\uDD22",xp:15,board:true,steps:[
{type:"intro",title:"Zahlen und Zeit",desc:"Numbers are the backbone of travel. You need them for time, platforms, prices, and addresses. Let's count to twenty, then put numbers to work at the station.",goals:["Count from 0 to 20 in German","Ask and tell the time","Use transport words: departure, arrival, platform, delay"]},
{type:"teach",kind:"word",trg:"null",src:"zero",phonetic:"NOOL",example:"A: Wie viele Tickets hast du?\nB: Null. Ich habe noch keine gekauft.",exampleSrc:"A: How many tickets do you have?\nB: Zero. I haven't bought any yet.",note:"Same word as English 'null' in programming.\nUsed for phone numbers, scores, temperatures.",funFact:"German 'null' comes from Latin 'nulla' (none). The concept of zero arrived in Europe from India via Arabic mathematicians in the Middle Ages."},
{type:"teach",kind:"word",trg:"eins",src:"one",phonetic:"AINSS",example:"A: Wie viele Koffer hast du?\nB: Nur eins. Ich reise leicht.",exampleSrc:"A: How many suitcases do you have?\nB: Just one. I travel light.",note:"When counting alone: eins.\nBefore a noun: ein/eine/einen (changes with gender).",funFact:"English 'one' and German 'eins' share the same Proto-Germanic root *ainaz. They sounded nearly identical 2,000 years ago."},
{type:"teach",kind:"word",trg:"zwei",src:"two",phonetic:"TSVAI",example:"A: Zwei Kaffee, bitte.\nB: Kommt sofort!",exampleSrc:"A: Two coffees, please.\nB: Coming right up!",note:"On the phone, Germans say 'zwo' instead of 'zwei'\nto avoid confusion with 'drei'.",funFact:"Germans say 'zwo' on the phone because 'zwei' and 'drei' sound too similar over a bad connection. Military and aviation use 'zwo' as standard."},
{type:"teach",kind:"word",trg:"drei",src:"three",phonetic:"DRAI",example:"A: Wie viele Kinder haben Sie?\nB: Drei. Zwei Jungen und ein Mädchen.",exampleSrc:"A: How many children do you have?\nB: Three. Two boys and one girl.",note:"Rhymes with English 'dry'.\nThe 'dr' is a clean /dr/, not like English 'thr'.",funFact:"The number three is sacred across Germanic cultures. Norse mythology has three Norns, three roots of Yggdrasil, and Odin hung for three nights."},
{type:"teach",kind:"word",trg:"vier",src:"four",phonetic:"FEER",example:"A: Der Zug kommt um vier Uhr.\nB: Perfekt, dann haben wir noch Zeit.",exampleSrc:"A: The train comes at four o'clock.\nB: Perfect, then we still have time.",note:"Pronounced with a long 'ee' sound.\nSpelled the same as Dutch 'vier'.",funFact:"German and Dutch spell 'four' identically: v-i-e-r. English swapped the 'v' for an 'f' during the Great Vowel Shift, but the family resemblance is obvious."},
{type:"teach",kind:"word",trg:"fünf",src:"five",phonetic:"FUENF",example:"A: Fünf Euro für ein Wasser?\nB: Willkommen am Flughafen!",exampleSrc:"A: Five euros for a water?\nB: Welcome to the airport!",note:"The u has an umlaut: fu\u0308nf.\nPractice rounding your lips for the u\u0308 sound.",funFact:"The word 'fist' (Faust in German) is related to 'five', because a fist is five fingers closed. Same root across all Germanic languages."},
{type:"teach",kind:"word",trg:"sechs",src:"six",phonetic:"ZEKS",example:"A: Gleis sechs, richtig?\nB: Ja, Gleis sechs. Beeil dich!",exampleSrc:"A: Platform six, right?\nB: Yes, platform six. Hurry up!",note:"The 'ch' after 's' creates a /ks/ sound.\nDo not pronounce the 'ch' separately.",funFact:"'Six' is one of the most stable words in Indo-European languages. Latin sex, Greek hex, Sanskrit sas, German sechs. All from one root over 6,000 years old."},
{type:"mc",q:"How do you say 'two coffees, please' in German?",opts:["Drei Kaffee, bitte","Zwei Kaffee, bitte","Eins Kaffee, bitte","Vier Kaffee, bitte"],ans:"Zwei Kaffee, bitte",hint:"Which number means two?"},
{type:"fb",s:"Verumius fragt: 'Gleis {1}, richtig?' Er braucht Bahnsteig 6.",a:["sechs"],opts:["sechs","drei","null","Uhr"],hint:"Which German number word means six?",sSrc:"Verumius asks: 'Platform {1}, right?' He needs platform 6."},
{type:"teach",kind:"word",trg:"sieben",src:"seven",phonetic:"ZEE-ben",example:"A: Der Film beginnt um sieben.\nB: Dann gehen wir jetzt los!",exampleSrc:"A: The movie starts at seven.\nB: Then let's go now!",note:"Two syllables: ZEE-ben.\nEnglish 'seven' and German 'sieben' are clearly related.",funFact:"The number seven appears more in human culture than any other: seven days, seven continents, seven deadly sins, seven wonders. Psychologists call it 'the magical number'."},
{type:"teach",kind:"word",trg:"acht",src:"eight",phonetic:"AHKT",example:"A: Der Zug fährt um acht.\nB: Morgens oder abends?",exampleSrc:"A: The train departs at eight.\nB: Morning or evening?",note:"The 'ch' is a soft back-of-throat sound.\nSame as Dutch 'acht', identical spelling.",funFact:"German 'acht' and English 'eight' look nothing alike, but they come from the same root. English lost the 'ch' sound and respelled it, but the 'gh' in 'eight' is the ghost of that old throat sound."},
{type:"teach",kind:"word",trg:"neun",src:"nine",phonetic:"NOYN",example:"A: Ich bin um neun da.\nB: Gut, ich warte im Cafe.",exampleSrc:"A: I will be there at nine.\nB: Good, I will wait in the cafe.",note:"Rhymes with 'coin' in English.\nThe 'eu' diphthong = /oy/ sound.",funFact:"The 'eu' sound in German always makes /oy/. Once you know this, words like 'neu' (new), 'Freund' (friend), and 'neun' all click."},
{type:"teach",kind:"word",trg:"zehn",src:"ten",phonetic:"TSAYN",example:"A: Zehn Minuten noch!\nB: Dann schaffen wir es.",exampleSrc:"A: Ten more minutes!\nB: Then we will make it.",note:"Begins with /ts/ sound, like 'tsunami'.\nThis word is the building block for 13-19.",funFact:"'Zehn' is the base of the entire teen number system in German. Once you know 'zehn', you can build thirteen through nineteen by putting the ones digit in front of it."},
{type:"mc",q:"Was ist sieben plus drei?",opts:["elf","neun","zehn","acht"],ans:"zehn",hint:"Add seven and three together."},
{type:"match",pairs:[{trg:"sieben",src:"seven"},{trg:"acht",src:"eight"},{trg:"neun",src:"nine"},{trg:"zehn",src:"ten"}]},
{type:"teach",kind:"word",trg:"elf",src:"eleven",phonetic:"ELF",example:"A: Die Besprechung ist um elf.\nB: Elf Uhr? Perfekt.",exampleSrc:"A: The meeting is at eleven.\nB: Eleven o'clock? Perfect.",note:"Same spelling in Dutch and German.\nDoes NOT follow the -zehn pattern.",funFact:"Eleven and twelve are unique in Germanic languages. They come from 'one left over' and 'two left over' after counting to ten. That is why they do not follow the teen pattern like dreizehn does."},
{type:"teach",kind:"word",trg:"zwölf",src:"twelve",phonetic:"TSVUELF",example:"A: Es ist schon zwölf!\nB: Mittagspause!",exampleSrc:"A: It is already twelve!\nB: Lunch break!",note:"The o has an umlaut: zwo\u0308lf.\nLike elf, it has its own form, not base+zehn.",funFact:"Unlike French (which resets at 17 with dix-sept) or Danish (which uses a base-20 system), German keeps it simple. Only 11 and 12 are irregular. Everything from 13 onward follows a clear pattern."},
{type:"tip",title:"The Teen Pattern: 13-20",text:"From 13 to 19, German puts the ones digit FIRST, then adds -zehn:\n\n13 = drei + zehn = dreizehn\n14 = vier + zehn = vierzehn\n15 = fünf + zehn = fünfzehn\n16 = sechs + zehn = sechzehn (drops the s!)\n17 = sieben + zehn = siebzehn (drops the -en!)\n18 = acht + zehn = achtzehn\n19 = neun + zehn = neunzehn\n20 = zwanzig (new word)\n\nNote: sechzehn and siebzehn shorten slightly for easier pronunciation.",deepDive:"Why ones-digit FIRST? German reverses the order compared to English for teens: English says 'thirteen' (three-ten), and German says 'dreizehn' (three-ten) in the same order. But this reversal becomes dramatic with larger numbers: 24 in German is 'vierundzwanzig' (four-and-twenty). This ones-first pattern continues all the way to 99 and is one of the biggest number hurdles for English speakers learning German."},
{type:"teach",kind:"word",trg:"zwanzig",src:"twenty",phonetic:"TSVAN-tsig",example:"A: Wie alt bist du?\nB: Ich bin zwanzig.",exampleSrc:"A: How old are you?\nB: I am twenty.",note:"The first 'tens' number. After this: dreißig (30), vierzig (40), fünfzig (50).",funFact:"'Zwanzig' comes from 'zwei' (two) + an old suffix for 'ten groups.' English 'twenty' follows the same logic: 'twen' (two) + 'ty' (tens). Same word, different costume."},
{type:"teach",kind:"word",trg:"die Uhr",src:"the clock / o'clock",phonetic:"dee OOR",example:"A: Wie spät ist es?\nB: Es ist drei Uhr.",exampleSrc:"A: What time is it?\nB: It is three o'clock.",note:"Feminine noun: die Uhr.\nAlso means 'watch' (wristwatch).\nUsed after numbers for time: drei Uhr = 3 o'clock.",funFact:"Germans use 24-hour time in all official contexts. Train schedules, appointments, and TV guides say '14 Uhr' not '2 PM'. Only casual speech uses 12-hour time."},
{type:"teach",kind:"phrase",trg:"Wie spät ist es?",src:"What time is it?",phonetic:"vee SHPAYT ist ess",example:"A: Entschuldigung, wie spät ist es?\nB: Es ist halb drei.",exampleSrc:"A: Excuse me, what time is it?\nB: It is half past two.",note:"Literally: how late is it?\nThe standard way to ask the time in German.",funFact:"Germans say 'halb drei' for 2:30, meaning 'half of three' (halfway to three). English speakers expect 'half three' to mean 3:30. This causes more confusion than almost any other German time expression."},
{type:"teach",kind:"word",trg:"die Abfahrt",src:"departure",phonetic:"dee AP-fart",example:"A: Wann ist die Abfahrt?\nB: In zehn Minuten, Gleis vier.",exampleSrc:"A: When is the departure?\nB: In ten minutes, platform four.",note:"Feminine: die Abfahrt.\nAb = away/off. Fahrt = journey/ride.\nYou will see this on every train station display.",funFact:"German builds compound words by stacking parts together. Ab (away) + Fahrt (journey) = Abfahrt (departure). An (toward) + Kunft (coming) = Ankunft (arrival). Once you see the pattern, compound words stop being scary."},
{type:"teach",kind:"word",trg:"die Ankunft",src:"arrival",phonetic:"dee AN-koonft",example:"A: Die Ankunft ist um neun Uhr.\nB: Gut, dann hole ich dich ab.",exampleSrc:"A: The arrival is at nine o'clock.\nB: Good, then I will pick you up.",note:"Feminine: die Ankunft.\nAn = toward. Kunft = coming.\nOpposite of Abfahrt.",funFact:"Kunft is an old German word for 'coming' that survives only in compounds: Ankunft (arrival), Zukunft (future, literally 'toward-coming'), Herkunft (origin, literally 'from-coming')."},
{type:"teach",kind:"word",trg:"das Gleis",src:"platform / track",phonetic:"dass GLAISS",example:"A: Welches Gleis?\nB: Gleis sieben, ganz am Ende.",exampleSrc:"A: Which platform?\nB: Platform seven, all the way at the end.",note:"Neuter: das Gleis.\nAt train stations, platforms are numbered.\nBahnsteig also means platform but Gleis is standard on displays.",funFact:"German train stations use 'Gleis' (track/rail) for platform numbers, while English uses 'platform'. If you hear 'Gleis 7', you are going to the tracks labeled 7, not necessarily the seventh building."},
{type:"teach",kind:"word",trg:"die Verspätung",src:"delay",phonetic:"dee fer-SHPAY-toong",example:"A: Hat der Zug Verspätung?\nB: Ja, fünf Minuten.",exampleSrc:"A: Is the train delayed?\nB: Yes, five minutes.",note:"Feminine: die Verspätung.\nVer- = prefix. Spät = late. -ung = noun ending.\nYou will hear this word a lot in Germany.",funFact:"Deutsche Bahn delays are so famous that Germans made a word for being happy about an on-time train: Puenktlichkeitsfreude. (That is a joke, but the sentiment is real. DB delays are a national running gag.)"},
{type:"mc",q:"What does 'die Verspätung' mean?",opts:["departure","delay","arrival","platform"],ans:"delay",hint:"Think about what travelers complain about most."},
{type:"fb",s:"Der Zug fährt um {1} Uhr.",a:["acht"],opts:["acht","Gleis","Abfahrt","Zug"],hint:"Insert a number to complete the departure time.",sSrc:"The train departs at {1} o'clock."},
{type:"mc",q:"'Das Gleis' is which grammatical gender?",opts:["Masculine (der)","Feminine (die)","Neuter (das)","Plural (die)"],ans:"Neuter (das)",hint:"Look at the article in front of Gleis."},
{type:"match",pairs:[{trg:"die Abfahrt",src:"departure"},{trg:"die Ankunft",src:"arrival"},{trg:"das Gleis",src:"platform"},{trg:"die Verspätung",src:"delay"}]},
{type:"mc",q:"How do you ask 'What time is it?' in German?",opts:["Was ist die Uhr?","Wann ist es?","Wo ist die Zeit?","Wie spät ist es?"],ans:"Wie spät ist es?",hint:"Literally: how late is it?"},
{type:"fb",s:"Die Ankunft ist um {1} Uhr.",a:["neun"],opts:["neun","Gleis","Verspätung","Abfahrt"],hint:"Insert a number for the arrival time.",sSrc:"The arrival is at {1} o'clock."},
{type:"mc",q:"What is 'sechzehn' in English?",opts:["six","sixteen","sixty","seventeen"],ans:"sixteen",hint:"sechs + zehn, with a small spelling shortcut."},
// --- Recycling: L1-L3 vocab with numbers/time context ---
{type:"fb",s:"{1}, wie spät ist es?",a:["Entschuldigung"],opts:["Entschuldigung","Danke","Bitte","Tschüss"],hint:"You need the polite attention-getter from Lesson 1.",sSrc:"{1}, what time is it?"},
{type:"drag_fill",s:"Ich {1} nach Berlin. Der Zug fährt um {2} Uhr.",blanks:{"1":"fahre","2":"zehn"},pool:["fahre","zehn","bin","drei","links"],hint:"Combine the travel verb from Lesson 1 with a number from this lesson.",sSrc:"I {1} to Berlin. The train leaves at {2} o'clock."}
]},

// ─── L6: Berlin Hauptbahnhof ───
{id:"deu_r1l6",title:"Berlin Hauptbahnhof",icon:"\uD83D\uDE82",xp:15,board:true,steps:[
{type:"intro",title:"Berlin Hauptbahnhof",desc:"Verumius steps off the train and into Berlin Hauptbahnhof, one of Europe's largest glass-and-steel stations. The noise, the crowds, the signs. Time to find the exit and grab something to eat.",goals:["Navigate with direction words","Order food for the first time","Use vocabulary from the whole unit together"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-berlin-hbf",trg:"Der Zug hält. Verumius steht auf und schaut durch das Fenster. Berlin Hauptbahnhof. Überall Glas und Stahl. Menschen laufen in alle Richtungen.",src:"The train stops. Verumius stands up and looks through the window. Berlin Hauptbahnhof. Glass and steel everywhere. People running in all directions."},
{type:"teach",kind:"word",trg:"der Ausgang",src:"exit",phonetic:"dehr OWS-gang",example:"A: Wo ist der Ausgang?\nB: Dort drüben, links.",exampleSrc:"A: Where is the exit?\nB: Over there, on the left.",note:"Masculine: der Ausgang.\nAus = out. Gang = way/corridor.\nEvery station and building has signs for the Ausgang.",funFact:"Eingang (entrance) is the opposite: Ein (in) + Gang (way). German station signs always show both. If you see a green running man, that is the Notausgang (emergency exit)."},
{type:"teach",kind:"word",trg:"links",src:"left",phonetic:"LINKS",example:"A: Wo ist Gleis drei?\nB: Links, dann geradeaus.",exampleSrc:"A: Where is platform three?\nB: Left, then straight ahead.",note:"Same word in Dutch: links.\nUsed on its own as a direction: Geh links! (Go left!)",funFact:"German 'links' and Dutch 'links' are identical. English once had a similar word but replaced it with 'left' from Old English 'lyft' (weak). The left hand was the 'weak' hand."},
{type:"teach",kind:"word",trg:"rechts",src:"right",phonetic:"REKHTS",example:"A: Ist die U-Bahn rechts?\nB: Ja, rechts und dann die Treppe runter.",exampleSrc:"A: Is the metro on the right?\nB: Yes, right and then down the stairs.",note:"Same word in Dutch: rechts.\nAlso means 'law/justice' in compounds: Recht = right/law.",funFact:"'Rechts' and 'right' share a root meaning 'straight' or 'correct'. Across many languages, the right side got associated with correctness and law, while left got associated with being clumsy or sinister (from Latin sinister = left)."},
{type:"teach",kind:"word",trg:"geradeaus",src:"straight ahead",phonetic:"ge-RAH-de-OWS",example:"A: Und dann?\nB: Geradeaus bis zur Ampel.",exampleSrc:"A: And then?\nB: Straight ahead until the traffic light.",note:"Gerade = straight. Aus = out.\nOne long word, three syllables: ge-RA-de-aus.",funFact:"German loves gluing words together. Geradeaus is gerade (straight) + aus (out/onward). Once you start seeing these compound parts, long German words become puzzles you can solve."},
{type:"tip",title:"Asking for Directions",text:"The key phrase for directions:\n\nWo ist...? = Where is...?\nWo ist der Ausgang? = Where is the exit?\nWo ist das Gleis? = Where is the platform?\n\nCommon answers use:\nlinks = left\nrechts = right\ngeradeaus = straight ahead\ndort drüben = over there\n\nCombine them: Links, dann geradeaus. (Left, then straight ahead.)",deepDive:"'Wo' asks WHERE something IS (location). 'Wohin' asks WHERE something is GOING (direction/destination).\n\nWo ist der Ausgang? (Where is the exit? Location.)\nWohin gehst du? (Where are you going? Direction.)\n\nFor now, 'Wo ist...' covers all your direction-asking needs. Wohin comes later when you learn movement verbs."},
{type:"mc",q:"You are lost in the station. You ask: 'Wo ist ___?'",opts:["die Richtung links","einfach geradeaus","sofort rechts","der Ausgang"],ans:"der Ausgang",hint:"You need to find the way out."},
{type:"fb",s:"Geh {1}, dann geradeaus.",a:["links"],opts:["links","Ausgang","Uhr","Gleis"],hint:"Fill in the direction: go ___, then straight.",sSrc:"Go {1}, then straight ahead."},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-berlin-hbf-interior",trg:"Verumius fragt eine Frau: 'Entschuldigung, wo ist der Ausgang?' Sie lächelt: 'Geradeaus, dann rechts.' Er folgt den Schildern. Überall Reisende mit Koffern.",src:"Verumius asks a woman: 'Excuse me, where is the exit?' She smiles: 'Straight ahead, then right.' He follows the signs. Travelers with suitcases everywhere."},
{type:"mc",q:"What direction did the woman give first?",opts:["geradeaus","nach links","nach rechts","nach oben"],ans:"geradeaus",hint:"She said two directions. What came before 'then right'?"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-doener-stand",trg:"Vor dem Bahnhof sieht Verumius einen Dönerstand. Der Duft ist unglaublich. Er geht hin und liest die Karte: Döner Kebab 5 Euro.",src:"Outside the station, Verumius sees a Döner stand. The smell is incredible. He walks over and reads the menu: Döner Kebab 5 euros."},
{type:"teach",kind:"phrase",trg:"Einen Döner, bitte!",src:"A Döner, please!",phonetic:"AI-nen DUH-ner BIT-te",example:"A: Was darf es sein?\nB: Einen Döner, bitte!",exampleSrc:"A: What would you like?\nB: A Döner, please!",note:"Einen = a (masculine accusative).\nBitte = please. Always add bitte!\nThis is the simplest way to order food.",funFact:"Berlin has over 1,600 Döner stands. The modern Döner Kebab as Germans know it was invented in Berlin in 1972 by Kadir Nurman, a Turkish immigrant. It is now Germany's most eaten street food, beating even the Bratwurst."},
{type:"mc",q:"How does Verumius order his Döner?",opts:["Guten Tag, Döner!","Einen Döner, bitte!","Wo ist der Döner?","Döner, Abfahrt!"],ans:"Einen Döner, bitte!",hint:"The polite ordering formula ends with a single magic word."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-doener-stand",trg:"Der Mann am Stand lächelt: 'Mit alles?' Verumius nickt. 'Fünf Euro.' Verumius zahlt und beisst rein. Es ist das Beste, was er je gegessen hat.",src:"The man at the stand smiles: 'With everything?' Verumius nods. 'Five euros.' Verumius pays and takes a bite. It is the best thing he has ever eaten."},
{type:"mc",q:"Which word means 'exit' in German?",opts:["die Ankunft","die Abfahrt","der Ausgang","das Gleis"],ans:"der Ausgang",hint:"Aus = out. Gang = way."},
{type:"fb",s:"Die Abfahrt ist um {1} Uhr.",a:["sieben"],opts:["sieben","rechts","Ausgang","Verspätung"],hint:"Insert a number for the departure time.",sSrc:"The departure is at {1} o'clock."},
{type:"match",pairs:[{trg:"links",src:"left"},{trg:"rechts",src:"right"},{trg:"geradeaus",src:"straight ahead"},{trg:"der Ausgang",src:"exit"}]},
{type:"mc",q:"You arrive at a Berlin Döner stand. The vendor asks 'Was darf es sein?' You want a Döner. You say:",opts:["Wo ist der Döner?","Guten Morgen, Döner","Die Verspätung, bitte","Einen Döner, bitte!"],ans:"Einen Döner, bitte!",hint:"Use the polite ordering formula from this lesson."},
{type:"mc",q:"What does 'geradeaus' mean?",opts:["straight ahead","turning left first","going back right","taking the exit"],ans:"straight ahead",hint:"This compound word combines 'gerade' and 'aus' into a direction."},
{type:"fb",s:"Entschuldigung, wo ist {1} Ausgang?",a:["der"],opts:["der","die","das","ein"],hint:"Ausgang is a masculine noun. Which article fits?",sSrc:"Excuse me, where is {1} exit?"},
// --- Recycling: L2-L3 vocab in directions context ---
{type:"fb",s:"{1} heißen Sie?",a:["Wie"],opts:["Wie","Wo","Was","Wann"],hint:"Dr. Yilmaz used this W-word for asking names. It also starts the greeting you learned.",sSrc:"{1} is your name?"},
{type:"mc",q:"Verumius cannot read the menu at the Döner stand. He says: 'Ich ___ nicht.'",opts:["verstehe","spreche","fahre","komme"],ans:"verstehe",hint:"Verumius said this to the conductor when he could not follow the announcement."}
]},

// ─── L7: Alles zusammen! (Quiz) ───
{id:"deu_r1l7",title:"Alles zusammen!",icon:"\uD83C\uDFC6",xp:20,board:true,steps:[
{type:"intro",title:"Alles zusammen!",desc:"Time to show what you've learned! This quiz covers everything from Unit 1: greetings, questions, verbs, numbers, and directions.",goals:["Test your German survival skills","Combine vocabulary from all lessons","Prove you're ready for Unit 2"]},
{type:"mc",q:"You meet your new landlord at 3 PM. Which greeting is most appropriate?",opts:["Gute Nacht","Tschüss","Guten Tag","Hallo, Alter"],ans:"Guten Tag",hint:"This is the standard formal daytime greeting."},
{type:"mc",q:"'Woher kommen Sie?' Which information is this question asking for?",opts:["Where you come from","What your name is","How you are feeling","Where you are going"],ans:"Where you come from",hint:"'Woher' combines 'wo' with a word for direction."},
{type:"fb",s:"Ich {1} Verumius.",a:["bin"],opts:["bin","bist","ist","sind"],hint:"Which form of 'sein' goes with 'ich'?",sSrc:"I {1} Verumius."},
{type:"mc",q:"Dr. Yilmaz asks about your friend: 'Woher ___ er?' Which form of 'sein' fits?",opts:["bin","ist","bist","sind"],ans:"ist",hint:"Think about which conjugation matches 'er.'"},
{type:"mc",q:"You hear 'Der Zug fährt um siebzehn Uhr.' What time does the train leave?",opts:["7 AM","5 AM","5 PM","7 PM"],ans:"5 PM",hint:"'Siebzehn' is seven plus ten in the 24-hour system."},
{type:"fb",s:"A: Wie geht es Ihnen?\nB: Gut, {1}!",a:["danke"],opts:["danke","bitte","ja","nein"],hint:"You need the polite word for 'thank you' here.",sSrc:"A: How are you?\nB: Fine, {1}!"},
{type:"drag_fill",s:"Verumius: {1}, wo ist der {2}?",blanks:{"1":"Entschuldigung","2":"Bahnhof"},pool:["Entschuldigung","Bahnhof","Danke","Zug","Tschüss"],hint:"He is politely asking for directions to the train station.",sSrc:"Verumius: {1}, where is the {2}?"},
{type:"mc",q:"Verumius needs to catch a train. Which word does he need?",opts:["der Bus","das Taxi","das Flugzeug","der Zug"],ans:"der Zug",hint:"This word literally means 'pull' in German."},
{type:"fb",s:"Mein Zug fährt um {1} Uhr.",a:["drei"],opts:["drei","zwei","vier","fünf"],hint:"Which German number word means 'three'?",sSrc:"My train leaves at {1} o'clock."},
{type:"match",pairs:[{trg:"Hallo",src:"Hello"},{trg:"Guten Tag",src:"Good day"},{trg:"Danke",src:"Thank you"},{trg:"Bitte",src:"Please / You're welcome"},{trg:"Tschüss",src:"Bye"},{trg:"Auf Wiedersehen",src:"Goodbye (formal)"}]},
{type:"mc",q:"Someone says 'Gehen Sie geradeaus und dann links.' Where should you go?",opts:["Straight ahead and then left","Straight ahead and then right","Turn around and go left","Go back and turn right"],ans:"Straight ahead and then left",hint:"The first direction word means moving forward without turning."},
{type:"tr",q:"How do you say 'Excuse me, where is the train station?' in German?",a:"Entschuldigung, wo ist der Bahnhof?",hint:"Start with the long word for 'excuse me.'"},
{type:"drag_fill",s:"Ich {1} müde und du {2} auch müde.",blanks:{"1":"bin","2":"bist"},pool:["bin","bist","ist","sind","seid"],hint:"Fill in the correct forms of 'sein' for 'ich' and 'du.'",sSrc:"I {1} tired and you {2} also tired."},
{type:"mc",q:"'Wir ___ zwei Koffer.' Which verb form completes this?",opts:["habe","haben","hat","habt"],ans:"haben",hint:"'Wir' always takes the same form as the infinitive."},
{type:"fb",s:"Er {1} einen Hund.",a:["hat"],opts:["hat","habe","haben","habt"],hint:"Which form of 'haben' goes with 'er'?",sSrc:"He {1} a dog."},
{type:"mc",q:"Which question word would you use to ask 'What is your name?'",opts:["Wo","Wann","Wie","Warum"],ans:"Wie",hint:"In German, you ask 'How are you called?' not 'What is your name?'"},
{type:"drag_fill",s:"{1} Tag! {2} ist die U-Bahn?",blanks:{"1":"Guten","2":"Wo"},pool:["Guten","Wo","Danke","Wie","Nein"],hint:"Greet someone formally, then ask where the subway is.",sSrc:"{1} day! {2} is the subway?"},
{type:"match",pairs:[{trg:"eins",src:"one"},{trg:"fünf",src:"five"},{trg:"zehn",src:"ten"},{trg:"zwanzig",src:"twenty"},{trg:"sieben",src:"seven"},{trg:"drei",src:"three"}]},
{type:"fb",s:"Gehen Sie geradeaus und dann {1}.",a:["rechts"],opts:["rechts","links","zurück","geradeaus"],hint:"Which word means 'right' as a direction?",sSrc:"Go straight ahead and then {1}."},
{type:"tr",q:"How do you say 'I don't understand. Can you repeat that?' in German?",a:"Ich verstehe nicht. Können Sie das wiederholen?",hint:"Start with 'I understand not' then ask politely to repeat."},
{type:"mc",q:"Verumius is lost. He says: 'Entschuldigung, ich bin Verumius. Ich verstehe nicht. Wo ist der Bahnhof, bitte?' How many different things is he doing in this sentence?",opts:["Two: greeting the inspector and requesting a map","Three: apologizing, stating his name, asking directions","One: politely requesting station directions only","Four: apologizing, introducing, admitting confusion, asking directions"],ans:"Four: apologizing, introducing, admitting confusion, asking directions",hint:"Count each separate action Verumius performs in order."}
]},

// ─── L8: Der erste Abend ───
{id:"deu_r1l8",title:"Der erste Abend",icon:"\uD83C\uDF19",xp:15,board:true,steps:[
{type:"intro",title:"Der erste Abend",desc:"Night falls over Berlin. Verumius sits in his hostel room, looking at the city lights. His first day in Germany is over. What a ride.",goals:["Learn evening and night vocabulary","Discover German greeting customs by time of day","Reflect on everything you've learned in Unit 1"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hostel-evening",trg:"Das Hostel ist klein, aber gemütlich. Verumius sitzt auf dem Bett und schaut aus dem Fenster. Die Lichter von Berlin funkeln in der Nacht.",src:"The hostel is small but cozy. Verumius sits on the bed and looks out the window. The lights of Berlin sparkle in the night."},
{type:"teach",trg:"das Hostel",src:"the hostel",note:"Neuter noun. A budget place to sleep in a new city.",example:"A: Wo schläfst du in Berlin?\nB: In einem Hostel in Mitte.",exampleSrc:"A: Where are you sleeping in Berlin?\nB: In a hostel in Mitte.",funFact:"Germany has over 500 youth hostels in the DJH network, the world's oldest hostel association, founded in 1909. A teacher wanted cheap travel for students!"},
{type:"teach",trg:"müde",src:"tired",note:"Adjective. Ich bin müde = I am tired.",example:"A: Wie geht es dir?\nB: Ich bin so müde. Was für ein Tag!",exampleSrc:"A: How are you?\nB: I'm so tired. What a day!",funFact:"Germans have a word for the tiredness you feel in spring: 'Frühjahrsmüdigkeit' (spring tiredness). It is so common that doctors write articles about it every March."},
{type:"teach",trg:"der Mensch",src:"the person / human being",note:"Masculine noun. Plural: die Menschen. Refers to humans in general.",example:"A: Jeder Mensch braucht Freunde.\nB: Das stimmt. Ohne Menschen ist das Leben langweilig.\nA: Du bist ein guter Mensch, Verumius.",exampleSrc:"A: Every person needs friends.\nB: That is true. Without people, life is boring.\nA: You are a good person, Verumius.",funFact:"'Mensch' is one of the oldest German words, from Proto-Germanic 'manniskaz.' It also works as an exclamation: 'Mensch!' = 'Man!' or 'Wow!' Germans shout it when surprised."},
{type:"teach",trg:"Gute Nacht",src:"Good night",note:"Used when going to bed. 'Nacht' is feminine, so 'Gute' not 'Guten.'",example:"A: Ich gehe schlafen. Gute Nacht!\nB: Gute Nacht! Schlaf gut!",exampleSrc:"A: I'm going to sleep. Good night!\nB: Good night! Sleep well!",funFact:"Notice: 'Guten Tag' (masculine) but 'Gute Nacht' (feminine). The ending changes because German adjectives must agree with the noun's gender. Your first taste of gender agreement!"},
{type:"teach",trg:"morgen",src:"tomorrow",note:"Lowercase 'morgen' = tomorrow. Capital 'der Morgen' = the morning.",example:"A: Was machst du morgen?\nB: Morgen gehe ich zum Brandenburger Tor.",exampleSrc:"A: What are you doing tomorrow?\nB: Tomorrow I'm going to the Brandenburg Gate.",funFact:"Same word, two meanings. 'Morgen' (tomorrow) and 'der Morgen' (morning). 'Morgen früh' means 'tomorrow morning.' And 'Guten Morgen' means 'Good morning.' Context is king!"},
{type:"teach",trg:"Guten Morgen",src:"Good morning",note:"Used until about 11 AM. 'Morgen' is masculine, so 'Guten.'",example:"A: Guten Morgen, Frau Schmidt!\nB: Guten Morgen! Kaffee?",exampleSrc:"A: Good morning, Mrs. Schmidt!\nB: Good morning! Coffee?",funFact:"In northern Germany, people just say 'Moin!' at any time of day. It sounds like 'Morgen' but actually comes from Low German 'moi dag' (good day). One syllable does the job of two words."},
{type:"teach",trg:"Guten Abend",src:"Good evening",note:"Used from about 6 PM. 'Abend' is masculine, so 'Guten.'",example:"A: Guten Abend! Haben Sie reserviert?\nB: Ja, auf den Namen Verumius.",exampleSrc:"A: Good evening! Do you have a reservation?\nB: Yes, under the name Verumius.",funFact:"In restaurants, 'Guten Abend' is the expected greeting. Walk in without saying it and the waiter might think you're rude. Germans notice when you skip greetings."},
{type:"tip",title:"German Greetings by Time of Day",text:"Germans greet differently depending on the clock:\n\nGuten Morgen: until ~11 AM\nGuten Tag: ~11 AM to ~6 PM\nGuten Abend: after ~6 PM\nGute Nacht: when going to bed\n\nNotice: Morgen, Tag, Abend are masculine (Guten). Nacht is feminine (Gute). The adjective ending changes with the gender!",deepDive:"In Bavaria and Austria, 'Grüß Gott' (God greets you) replaces all daytime greetings. In northern Germany, 'Moin' is used any time of day, despite coming from 'Morgen.' In Switzerland, 'Gruezi' is standard. Germany has more regional greetings than most countries!"},
{type:"mc",q:"Verumius calls Dr. Yilmaz at 9 PM. Which greeting should he use?",opts:["Guten Morgen","Guten Abend","Guten Tag","Gute Nacht"],ans:"Guten Abend",hint:"9 PM is after 6 PM but before bedtime."},
{type:"fb",s:"Verumius ist sehr {1} nach seinem ersten Tag.",a:["müde"],opts:["müde","gut","klein","schnell"],hint:"After a long day of travel, how would you feel?",sSrc:"Verumius is very {1} after his first day."},
{type:"tip",title:"Your First Day Survival Kit",text:"The 20 most useful phrases from Unit 1:\n\n1. Hallo / Guten Tag (greeting)\n2. Tschüss / Auf Wiedersehen (farewell)\n3. Danke / Bitte (thanks / please)\n4. Ja / Nein (yes / no)\n5. Ich bin... (I am...)\n6. Wie heißen Sie? (What's your name?)\n7. Woher kommen Sie? (Where from?)\n8. Ich verstehe nicht (I don't understand)\n9. Können Sie das wiederholen? (Can you repeat?)\n10. Wo ist der Bahnhof? (Where is the station?)",deepDive:"These 20 phrases cover about 80% of beginner survival situations. Language learning follows the Pareto principle: a small core of words and phrases handles most daily interactions. Master these, and you can navigate airports, ask for help, introduce yourself, and politely admit confusion. That is a LOT for day one."},
{type:"mc",q:"It is 11 PM and Verumius is going to sleep. What does he say to the hostel receptionist?",opts:["Gute Nacht","Guten Abend","Guten Morgen","Guten Tag"],ans:"Gute Nacht",hint:"He is going to bed, not just arriving in the evening."},
{type:"match",pairs:[{trg:"Guten Morgen",src:"Good morning"},{trg:"Guten Tag",src:"Good day"},{trg:"Guten Abend",src:"Good evening"},{trg:"Gute Nacht",src:"Good night"}]},
{type:"drag_fill",s:"Verumius: Ich bin so {1}. {2} Nacht, Berlin!",blanks:{"1":"müde","2":"Gute"},pool:["müde","Gute","Guten","morgen","schnell"],hint:"Verumius is tired and saying goodnight to the city.",sSrc:"Verumius: I am so {1}. {2} night, Berlin!"},
{type:"fb",s:"Heute arbeite ich. {1} gehe ich zum Brandenburger Tor!",a:["Morgen"],opts:["Morgen","Heute","Gestern","Abend"],hint:"Today Verumius works. When is his sightseeing trip?",sSrc:"Today I am working. {1} I am going to the Brandenburg Gate!"},
{type:"tr",q:"How do you say 'Good night! I am tired.' in German?",a:"Gute Nacht! Ich bin müde.",hint:"Remember: 'Nacht' is feminine, so the adjective ending changes."},
{type:"fb",s:"Es ist 14 Uhr. Guten {1}! Wie heißen Sie?",a:["Tag"],opts:["Tag","Morgen","Abend","Nacht"],hint:"It is 2 PM. Which time-of-day greeting fits the afternoon?",sSrc:"It is 2 PM. Good {1}! What is your name?"},
{type:"drag_fill",s:"{1} Morgen! Ich bin Verumius. {2} kommen Sie?",blanks:{"1":"Guten","2":"Woher"},pool:["Guten","Woher","Danke","Tschüss","Nein"],hint:"Greet someone formally in the morning, then ask where they are from.",sSrc:"{1} morning! I am Verumius. {2} do you come from?"},
{type:"mc",q:"Which pair of words are OPPOSITES in German?",opts:["Danke / Bitte","Hallo / Guten Tag","links / rechts","wer / was"],ans:"links / rechts",hint:"One means left, the other means right."},
{type:"fb",s:"Wie {1} ist es?",a:["spät"],opts:["spät","gut","viel","heiss"],hint:"The German phrase literally asks 'How late is it?'",sSrc:"How {1} is it?"},
// --- Recycling: L1-L6 vocab in evening context ---
{type:"mc",q:"Verumius texts Dr. Yilmaz: 'Danke für alles! Ich ___ jetzt in Berlin.' Which verb form fits?",opts:["bist","bin","ist","sind"],ans:"bin",hint:"Verumius is talking about himself. Which form of sein matches ich?"},
{type:"fb",s:"Verumius sagt: 'Ich {1} aus Italien.'",a:["komme"],opts:["komme","kommen","kommst","kommt"],hint:"What is the ich-form ending for regular verbs?",sSrc:"Verumius says: 'I {1} from Italy.'"},
{type:"mc",q:"Verumius lies in bed, smiling. What will he do tomorrow in Berlin?",opts:["Explore the city and practice more German","Take the next flight back home to Italy","Stay in bed all day and forget Germany","Give up learning and try a different hobby"],ans:"Explore the city and practice more German",hint:"Verumius is tired but excited about his adventure."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-berlin-night",trg:"Er lächelt. Morgen wird er das Brandenburger Tor sehen. Morgen wird er mehr Deutsch sprechen. Aber jetzt: Gute Nacht, Berlin.",src:"He smiles. Tomorrow he will see the Brandenburg Gate. Tomorrow he will speak more German. But for now: Good night, Berlin."}
]}

,

{id:"deu_r1l9",title:"Bausteine",icon:"🧱",xp:15,board:true,steps:[
{type:"intro",title:"Bausteine",desc:"The building blocks of every German sentence: conjunctions, adverbs, prepositions, and question words. These small words connect everything together.",goals:["Learn essential conjunctions: und, aber, oder, auch","Master key question words: wer, was, wo, wann, warum, wie","Use adverbs and prepositions in simple sentences"]},
{type:"teach",trg:"und",src:"and",note:"The most common German conjunction. Connects words, phrases, and clauses.",example:"A: Ich spreche Deutsch und Englisch.\nB: Und ich spreche Deutsch und Spanisch!",exampleSrc:"A: I speak German and English.\nB: And I speak German and Spanish!",funFact:"'Und' comes from the same root as English 'and'. Both trace back to Proto-Germanic *unda."},
{type:"teach",trg:"aber",src:"but",note:"Conjunction expressing contrast. Does not change word order.",example:"A: Kommst du mit?\nB: Ich will, aber ich habe keine Zeit.",exampleSrc:"A: Are you coming along?\nB: I want to, but I have no time.",funFact:"Germans love combining 'aber' with emphasis: 'Aber ja!' (But of course!) is a very common enthusiastic yes."},
{type:"teach",trg:"oder",src:"or",note:"Conjunction for alternatives. Used in questions and statements.",example:"A: Kaffee oder Tee?\nB: Tee, bitte.",exampleSrc:"A: Coffee or tea?\nB: Tea, please.",funFact:"'Oder?' tacked onto the end of a statement is the German equivalent of 'right?' or 'isn't it?' Very common in daily speech."},
{type:"teach",trg:"auch",src:"also, too",note:"Adverb meaning 'also' or 'too'. Position varies in the sentence.",example:"A: Ich lerne Deutsch.\nB: Ich auch!",exampleSrc:"A: I am learning German.\nB: Me too!",funFact:"'Auch' is one of the ten most frequent words in German. You will hear it in almost every conversation."},
{type:"teach",trg:"hier",src:"here",note:"Adverb of place. Indicates the speaker's location.",example:"A: Wo ist das Hotel?\nB: Das Hotel ist hier.",exampleSrc:"A: Where is the hotel?\nB: The hotel is here.",funFact:"'Hier' is related to English 'here'. Both come from Proto-Germanic *her, meaning 'in this place'."},
{type:"teach",trg:"nicht",src:"not",note:"Negation adverb. Usually placed before what it negates.",example:"A: Sprichst du Spanisch?\nB: Nein, ich spreche nicht Spanisch.",exampleSrc:"A: Do you speak Spanish?\nB: No, I do not speak Spanish.",funFact:"Word order with 'nicht' is one of the trickiest parts of German grammar. It usually goes before adjectives and at the end before verbs."},
{type:"teach",trg:"sehr",src:"very",note:"Intensifying adverb. Placed before the word it intensifies.",example:"A: Wie ist das Essen?\nB: Das Essen ist sehr gut!",exampleSrc:"A: How is the food?\nB: The food is very good!",funFact:"'Sehr' originally meant 'painfully' in Middle High German. Over centuries, it softened from 'painfully much' to simply 'very'."},
{type:"teach",trg:"gut",src:"good, well",note:"Adjective and adverb. Comparative: besser. Superlative: am besten.",example:"A: Wie geht es dir?\nB: Mir geht es gut, danke!",exampleSrc:"A: How are you?\nB: I am doing well, thanks!",funFact:"'Gut' and English 'good' are cousins from Proto-Germanic *godaz. The irregular comparative 'besser' mirrors English 'better'."},
{type:"teach",trg:"für",src:"for",note:"Preposition. Always takes the accusative case.",example:"A: Ist das Geschenk für mich?\nB: Ja, das ist für dich!",exampleSrc:"A: Is the gift for me?\nB: Yes, it is for you!",funFact:"'Für' is cognate with English 'for'. Both come from Proto-Germanic *furi, meaning 'before' or 'in front of'."},
{type:"teach",trg:"in",src:"in, into",note:"Preposition. Takes dative (location) or accusative (direction).",example:"A: Wo wohnst du?\nB: Ich wohne in Berlin.",exampleSrc:"A: Where do you live?\nB: I live in Berlin.",funFact:"'In' is one of the rare words that is spelled and means the same in English, German, Dutch, and Latin. A true European word."},
{type:"teach",trg:"man",src:"one, people (in general)",note:"Indefinite pronoun. Used for general statements. Always third person singular.",example:"A: Wie sagt man das auf Deutsch?\nB: Man sagt 'Entschuldigung'.",exampleSrc:"A: How does one say that in German?\nB: One says 'Entschuldigung'.",funFact:"'Man' is not the same as 'der Mann' (the man). It is an impersonal pronoun, like French 'on'. Very useful for avoiding passive voice."},
{type:"teach",trg:"nichts",src:"nothing",note:"Indefinite pronoun. Opposite of 'alles' (everything).",example:"A: Was hast du heute gemacht?\nB: Nichts. Ich war zu Hause.",exampleSrc:"A: What did you do today?\nB: Nothing. I was at home.",funFact:"'Nichts' literally comes from 'nicht' + 's'. The 's' ending turned 'not' into 'nothing'. Compare: English 'naught' from 'no' + 'whit'."},
{type:"teach",trg:"wer",src:"who",note:"Question word for people. Nominative case.",example:"A: Wer ist das?\nB: Das ist mein Bruder.",exampleSrc:"A: Who is that?\nB: That is my brother.",funFact:"'Wer' is the ancestor of English 'who'. Old English still had 'hwa', which became 'who'. The German form stayed closer to the original."},
{type:"teach",trg:"was",src:"what",note:"Question word for things. Also used in exclamations.",example:"A: Was ist das?\nB: Das ist ein Buch.",exampleSrc:"A: What is that?\nB: That is a book.",funFact:"'Was' doubles as a casual replacement for 'etwas' (something) in spoken German: 'Hast du was?' means 'Do you have something?'"},
{type:"teach",trg:"wo",src:"where",note:"Question word for location. For direction, use 'wohin'.",example:"A: Wo bist du?\nB: Ich bin im Park.",exampleSrc:"A: Where are you?\nB: I am in the park.",funFact:"German has three 'where' words: 'wo' (where at), 'wohin' (where to), and 'woher' (where from). English used to have these too: where, whither, whence."},
{type:"teach",trg:"wann",src:"when",note:"Question word for time.",example:"A: Wann kommst du?\nB: Ich komme um drei Uhr.",exampleSrc:"A: When are you coming?\nB: I am coming at three o'clock.",funFact:"'Wann' is only for questions. For 'when' in statements (When I was young...), German uses 'als' or 'wenn' instead."},
{type:"teach",trg:"warum",src:"why",note:"Question word for reasons. Synonyms: wieso, weshalb.",example:"A: Warum lernst du Deutsch?\nB: Ich lerne Deutsch, weil ich in Berlin wohne.",exampleSrc:"A: Why are you learning German?\nB: I am learning German because I live in Berlin.",funFact:"German has three words for 'why': warum, wieso, weshalb. They are interchangeable in everyday speech. 'Warum' is the most common."},
{type:"teach",trg:"wie",src:"how",note:"Question word for manner or condition. Also used for 'what is your name?'",example:"A: Wie heißt du?\nB: Ich heiße Anna.",exampleSrc:"A: What is your name?\nB: My name is Anna.",funFact:"'Wie heißt du?' literally means 'How are you called?' Germans ask for your name with 'how', not 'what'. A different way of thinking about identity."},
{type:"teach",trg:"wie viel",src:"how much, how many",note:"Two-word question phrase for amounts and quantities.",example:"A: Wie viel kostet das?\nB: Das kostet drei Euro.",exampleSrc:"A: How much does that cost?\nB: That costs three euros.",funFact:"For countable things, some Germans use 'wie viele' (how many), but in casual speech 'wie viel' covers both 'how much' and 'how many'."},
{type:"teach",trg:"woher",src:"where from",note:"Question word for origin. Literally: wo + her (where + from).",example:"A: Woher kommst du?\nB: Ich komme aus Frankreich.",exampleSrc:"A: Where are you from?\nB: I am from France.",funFact:"'Woher kommst du?' is one of the first questions you will hear in Germany. Germans are genuinely curious about where people come from."},
{type:"mc",q:"Which word means 'but' in German?",opts:["und","aber","oder","auch"],ans:"aber",hint:"This conjunction expresses a contrast between two ideas."},
{type:"fb",s:"Ich spreche Deutsch {1} Englisch.",a:"und",opts:["und","aber","oder","nicht"],hint:"You need a word that connects two equal items together.",sSrc:"I speak German {1} English."},
{type:"mc",q:"'Wie viel kostet das?' asks about...",opts:["the price of something","the name of something","the location of something","the time of something"],ans:"the price of something",hint:"Think about what information 'how much' would give you."},
{type:"match",pairs:[{trg:"wo",src:"where"},{trg:"wann",src:"when"},{trg:"wer",src:"who"},{trg:"warum",src:"why"},{trg:"was",src:"what"}]},
{type:"fb",s:"Ich spreche {1} Spanisch.",a:"nicht",opts:["nicht","nichts","sehr","gut"],hint:"You need the negation word that goes before what is being denied.",sSrc:"I speak {1} Spanish."}
]},

{id:"deu_r1l10",title:"Wer bist du?",icon:"🪪",xp:15,board:true,steps:[
{type:"intro",title:"Wer bist du?",desc:"Learn the vocabulary you need for forms, introductions, and telling people about yourself. Names, addresses, birthdays, and formal greetings.",goals:["Learn identity words: Name, Vorname, Adresse, Geburtstag","Master formal greetings: Herr, Frau, herzlich willkommen","Fill out forms and introduce yourself with confidence"]},
{type:"teach",trg:"der Name",src:"the name",note:"Masculine noun. Plural: die Namen. Used for full name or surname.",example:"A: Wie ist Ihr Name?\nB: Mein Name ist Schneider.",exampleSrc:"A: What is your name?\nB: My name is Schneider.",funFact:"'Name' is nearly universal across European languages: English 'name', Latin 'nomen', Greek 'onoma'. All from the same ancient root."},
{type:"teach",trg:"der Vorname",src:"the first name",note:"Masculine noun. Plural: die Vornamen. Literally: 'fore-name'.",example:"A: Wie ist Ihr Vorname?\nB: Mein Vorname ist Thomas.",exampleSrc:"A: What is your first name?\nB: My first name is Thomas.",funFact:"Germany has naming laws. Until 2008, parents had to choose from an approved list. The name must clearly indicate gender and not harm the child."},
{type:"teach",trg:"der Familienname",src:"the surname, family name",note:"Masculine noun. Plural: die Familiennamen. Also called 'der Nachname'.",example:"A: Und der Familienname?\nB: Mein Familienname ist Weber.",exampleSrc:"A: And the surname?\nB: My surname is Weber.",funFact:"The most common German surname is Mueller (miller). Other top names are Schmidt (smith), Schneider (tailor), Fischer (fisher), all based on old professions."},
{type:"teach",trg:"die Adresse",src:"the address",note:"Feminine noun. Plural: die Adressen.",example:"A: Wie ist Ihre Adresse?\nB: Meine Adresse ist Berliner Str. 12.",exampleSrc:"A: What is your address?\nB: My address is Berliner Str. 12.",funFact:"In German addresses, the street name comes first and the house number comes after: 'Berliner Str. 12', not '12 Berliner Str.'"},
{type:"teach",trg:"das Alter",src:"the age",note:"Neuter noun. No common plural. From 'alt' (old).",example:"A: Wie alt bist du?\nB: Ich bin 25 Jahre alt.",exampleSrc:"A: How old are you?\nB: I am 25 years old.",funFact:"Germans say 'Wie alt bist du?' (How old are you?) literally. The word 'Alter' also means 'dude' in youth slang: 'Hey, Alter!'"},
{type:"teach",trg:"die Anrede",src:"the form of address, title",note:"Feminine noun. Plural: die Anreden. Used on forms for Herr/Frau.",example:"A: Anrede: Herr oder Frau?\nB: Herr, bitte.",exampleSrc:"A: Form of address: Mr. or Mrs.?\nB: Mr., please.",funFact:"German forms always start with 'Anrede'. Until recently, 'Fraulein' (Miss) was common, but it is now considered outdated and even offensive."},
{type:"teach",trg:"der Familienstand",src:"the marital status",note:"Masculine noun. No common plural. Common on official forms.",example:"A: Familienstand?\nB: Ledig.",exampleSrc:"A: Marital status?\nB: Single.",funFact:"German marital status options on forms include: ledig (single), verheiratet (married), geschieden (divorced), verwitwet (widowed)."},
{type:"teach",trg:"der Geburtstag",src:"the birthday",note:"Masculine noun. Plural: die Geburtstage. Literally: birth + day.",example:"A: Wann ist dein Geburtstag?\nB: Mein Geburtstag ist am 5. Mai.",exampleSrc:"A: When is your birthday?\nB: My birthday is on May 5th.",funFact:"Germans celebrate with 'Geburtstagskuchen' (birthday cake). The birthday person often brings cake to work or school, not the other way around!"},
{type:"teach",trg:"das Geburtsjahr",src:"the year of birth",note:"Neuter noun. Plural: die Geburtsjahre. Literally: birth + year.",example:"A: Geburtsjahr?\nB: 1998.",exampleSrc:"A: Year of birth?\nB: 1998.",funFact:"German compound nouns can get very long. 'Geburtsjahr' is mild. Try 'Geburtsurkunde' (birth certificate) or 'Geburtstagsuberraschungsparty' (birthday surprise party)."},
{type:"teach",trg:"der Geburtsort",src:"the place of birth",note:"Masculine noun. Plural: die Geburtsorte. Literally: birth + place.",example:"A: Wo ist dein Geburtsort?\nB: Mein Geburtsort ist Hamburg.",exampleSrc:"A: Where is your place of birth?\nB: My place of birth is Hamburg.",funFact:"Your Geburtsort is permanently recorded in German civil records. Even if you move ten times, your birthplace follows you on every official document."},
{type:"teach",trg:"der Pass",src:"the passport",note:"Masculine noun. Plural: die Passe. Short for 'Reisepass' (travel passport).",example:"A: Haben Sie Ihren Pass?\nB: Ja, hier ist mein Pass.",exampleSrc:"A: Do you have your passport?\nB: Yes, here is my passport.",funFact:"The German passport is one of the most powerful in the world, allowing visa-free travel to over 190 countries."},
{type:"teach",trg:"die Sprache",src:"the language",note:"Feminine noun. Plural: die Sprachen. From 'sprechen' (to speak).",example:"A: Welche Sprachen sprichst du?\nB: Ich spreche zwei Sprachen.",exampleSrc:"A: Which languages do you speak?\nB: I speak two languages.",funFact:"'Sprache' comes from 'sprechen' (to speak). Germany alone has dozens of regional dialects, some so different they are almost separate languages."},
{type:"teach",trg:"die Frau",src:"the woman, Mrs.",note:"Feminine noun. Plural: die Frauen. Also used as the formal title 'Mrs./Ms.'",example:"A: Guten Tag, Frau Klein!\nB: Guten Tag! Wie geht es Ihnen?",exampleSrc:"A: Good day, Mrs. Klein!\nB: Good day! How are you?",funFact:"'Frau' replaced 'Fraulein' as the standard address for all women, married or not. Using 'Fraulein' today sounds old-fashioned or condescending."},
{type:"teach",trg:"der Herr",src:"the gentleman, Mr.",note:"Masculine noun. Plural: die Herren. Formal title for men.",example:"A: Guten Morgen, Herr Mueller!\nB: Guten Morgen! Schon, Sie zu sehen.",exampleSrc:"A: Good morning, Mr. Mueller!\nB: Good morning! Nice to see you.",funFact:"'Herr' literally means 'lord' or 'master'. It is also the word used for God in German: 'der Herr'. Quite a formal little word!"},
{type:"teach",trg:"der Dank",src:"the thanks, gratitude",note:"Masculine noun. No common plural. 'Vielen Dank' = many thanks.",example:"A: Hier ist dein Kaffee.\nB: Vielen Dank!",exampleSrc:"A: Here is your coffee.\nB: Many thanks!",funFact:"'Danke' (thanks) comes from 'Dank'. Germans have many gratitude levels: 'danke', 'vielen Dank', 'herzlichen Dank', 'tausend Dank' (a thousand thanks)."},
{type:"teach",trg:"der Gruß",src:"the greeting",note:"Masculine noun. Plural: die Gruesse. 'Mit freundlichen Gruessen' = sincerely (in letters).",example:"A: Viele Gruesse aus Berlin!\nB: Danke, viele Gruesse zurueck!",exampleSrc:"A: Many greetings from Berlin!\nB: Thanks, many greetings back!",funFact:"Emails and letters in German almost always end with 'Mit freundlichen Gruessen' (with friendly greetings), the equivalent of 'sincerely' or 'best regards'."},
{type:"teach",trg:"das Wiedersehen",src:"the reunion, seeing again",note:"Neuter noun. From 'wieder' (again) + 'sehen' (to see). Used in 'Auf Wiedersehen'.",example:"A: Ich muss gehen. Auf Wiedersehen!\nB: Auf Wiedersehen! Bis bald!",exampleSrc:"A: I have to go. Goodbye!\nB: Goodbye! See you soon!",funFact:"'Auf Wiedersehen' literally means 'until seeing again'. On the phone, Germans say 'Auf Wiederhoren' (until hearing again) instead."},
{type:"teach",trg:"herzlich willkommen",src:"heartfelt welcome, warm welcome",note:"Two words: herzlich (heartfelt, from Herz = heart) + willkommen (welcome).",example:"A: Herzlich willkommen in Deutschland!\nB: Vielen Dank! Ich bin sehr froh.",exampleSrc:"A: A warm welcome to Germany!\nB: Many thanks! I am very happy.",funFact:"'Herzlich' comes from 'das Herz' (the heart). Germans express warmth through the heart: herzlich (heartfelt), herzhaft (hearty), beherzt (courageous, literally 'be-hearted')."},
{type:"mc",q:"What does 'der Vorname' mean?",opts:["the surname","the first name","the address","the nickname"],ans:"the first name",hint:"When introducing yourself, which name do people say before the family name?"},
{type:"fb",s:"Wann ist dein {1}?",a:"Geburtstag",opts:["Geburtstag","Geburtsort","Geburtsjahr","Familienstand"],hint:"This question asks about the calendar day you were born.",sSrc:"When is your {1}?"},
{type:"match",pairs:[{trg:"der Name",src:"the name"},{trg:"die Adresse",src:"the address"},{trg:"die Sprache",src:"the language"},{trg:"der Pass",src:"the passport"},{trg:"das Alter",src:"the age"}]},
{type:"mc",q:"How do you say 'goodbye' in German?",opts:["Herzlich willkommen","Vielen Dank","Auf Wiedersehen","Guten Morgen"],ans:"Auf Wiedersehen",hint:"It literally means 'until seeing again'. Think about parting words."},
{type:"fb",s:"Guten Morgen, {1} Mueller!",a:"Herr",opts:["Herr","Frau","Name","Dank"],hint:"You need the formal title used for men before their surname.",sSrc:"Good morning, {1} Mueller!"}
]},

{id:"deu_r1l11",title:"Die Zahlen",icon:"\u{1F522}",xp:15,board:true,steps:[
{type:"intro",title:"Die Zahlen",desc:"Learn the numbers you are still missing: 2, 4, 6, and 11 through 19.",goals:["Count from 1 to 20 without gaps","Understand the -zehn pattern for teens","Use numbers in simple sentences"]},
{type:"tip",title:"Das Zehn-Muster",text:"German teens (13\u201319) follow a simple pattern:\nRoot number + zehn.\n\ndrei + zehn = dreizehn (13)\nvier + zehn = vierzehn (14)\nf\u00fcnf + zehn = f\u00fcnfzehn (15)\n\nWatch for small spelling changes:\nsechs becomes sech- (sechzehn)\nsieben becomes sieb- (siebzehn)"},
{type:"teach",trg:"zwei",src:"two (2)",note:"One of the first numbers every learner needs.",example:"A: Wie viele Kinder hast du?\nB: Ich habe zwei Kinder.",exampleSrc:"A: How many children do you have?\nB: I have two children.",funFact:"Zwei sometimes becomes zwo in spoken German to avoid confusion with drei on the phone."},
{type:"teach",trg:"vier",src:"four (4)",note:"Pronounced like English 'fear' but shorter.",example:"A: Wie viele Personen?\nB: Wir sind vier Personen.",exampleSrc:"A: How many people?\nB: We are four people.",funFact:"A Viertel (quarter) comes from vier. Ein Viertel means one fourth."},
{type:"teach",trg:"sechs",src:"six (6)",note:"The -chs sounds like 'ks' in English.",example:"A: Wie viele Eier brauchen wir?\nB: Wir brauchen sechs Eier.",exampleSrc:"A: How many eggs do we need?\nB: We need six eggs.",funFact:"A Sechser was old slang for a lucky number in the German lottery."},
{type:"teach",trg:"elf",src:"eleven (11)",note:"An irregular number. Does not follow the -zehn pattern.",example:"A: Wie viele Spieler hat ein Team?\nB: Ein Team hat elf Spieler.",exampleSrc:"A: How many players does a team have?\nB: A team has eleven players.",funFact:"Elf comes from Old Germanic meaning 'one left over' after counting to ten."},
{type:"teach",trg:"zw\u00f6lf",src:"twelve (12)",note:"Another irregular number. Does not follow the -zehn pattern.",example:"A: Wie viele Monate hat ein Jahr?\nB: Ein Jahr hat zw\u00f6lf Monate.",exampleSrc:"A: How many months does a year have?\nB: A year has twelve months.",funFact:"Like English twelve, zw\u00f6lf is a leftover from a base-12 counting system."},
{type:"teach",trg:"dreizehn",src:"thirteen (13)",note:"drei + zehn = dreizehn. The teen pattern starts here.",example:"A: Wie alt ist dein Sohn?\nB: Er ist dreizehn Jahre alt.",exampleSrc:"A: How old is your son?\nB: He is thirteen years old.",funFact:"In Germany, 13 is considered unlucky too, but less so than in English-speaking countries."},
{type:"teach",trg:"vierzehn",src:"fourteen (14)",note:"vier + zehn = vierzehn. Regular pattern.",example:"A: Wie viele Tage noch?\nB: Noch vierzehn Tage.",exampleSrc:"A: How many days left?\nB: Fourteen more days.",funFact:"Vierzehn Tage (14 days) is the standard German way to say two weeks."},
{type:"teach",trg:"f\u00fcnfzehn",src:"fifteen (15)",note:"f\u00fcnf + zehn = f\u00fcnfzehn. Regular pattern.",example:"A: Wann beginnt der Film?\nB: Der Film beginnt um f\u00fcnfzehn Uhr.",exampleSrc:"A: When does the movie start?\nB: The movie starts at fifteen o'clock (3 PM).",funFact:"Germans use 24-hour time in daily life. F\u00fcnfzehn Uhr means 3 PM."},
{type:"teach",trg:"sechzehn",src:"sixteen (16)",note:"sechs loses the -s: sech + zehn = sechzehn.",example:"A: Wie alt bist du?\nB: Ich bin sechzehn Jahre alt.",exampleSrc:"A: How old are you?\nB: I am sixteen years old.",funFact:"At 16, Germans can legally buy beer and wine. The drinking age for spirits is 18."},
{type:"teach",trg:"siebzehn",src:"seventeen (17)",note:"sieben loses the -en: sieb + zehn = siebzehn.",example:"A: Wie viele Leute kommen?\nB: Siebzehn Leute kommen.",exampleSrc:"A: How many people are coming?\nB: Seventeen people are coming.",funFact:"Siebzehn und vier (17 and 4) is the German name for the card game Blackjack."},
{type:"teach",trg:"achtzehn",src:"eighteen (18)",note:"acht + zehn = achtzehn. Regular pattern.",example:"A: Wann bist du achtzehn?\nB: Ich bin im Mai achtzehn.",exampleSrc:"A: When do you turn eighteen?\nB: I turn eighteen in May.",funFact:"At 18, Germans reach full legal adulthood and can vote, drive, and buy all alcohol."},
{type:"teach",trg:"neunzehn",src:"nineteen (19)",note:"neun + zehn = neunzehn. Regular pattern.",example:"A: Wie viele Studenten sind hier?\nB: Hier sind neunzehn Studenten.",exampleSrc:"A: How many students are here?\nB: There are nineteen students here.",funFact:"The number 19 has no special cultural meaning in German, but it rhymes nicely in counting songs."},
{type:"teach",trg:"neu",src:"new",note:"Adjective. Changes form with gender: ein neuer Freund, eine neue Tasche, ein neues Buch.",example:"A: Ist das dein Handy?\nB: Ja, es ist ganz neu.",exampleSrc:"A: Is that your phone?\nB: Yes, it is brand new.",funFact:"Neu is related to English new, Dutch nieuw, and Latin novus. All from the same ancient root."},
{type:"teach",trg:"g\u00fcltig",src:"valid",note:"Used for tickets, documents, and passes. Opposite: ung\u00fcltig (invalid).",example:"A: Ist dein Ticket noch g\u00fcltig?\nB: Ja, es ist noch g\u00fcltig.",exampleSrc:"A: Is your ticket still valid?\nB: Yes, it is still valid.",funFact:"You will see g\u00fcltig on every train ticket and museum pass in Germany."},
{type:"mc",q:"Wie sagt man 'sixteen' auf Deutsch?",opts:["sechzehn","siebzehn","f\u00fcnfzehn","achtzehn"],ans:"sechzehn",hint:"Sechs loses its final -s before -zehn."},
{type:"fb",s:"Ein Jahr hat {1} Monate.",a:["zw\u00f6lf"],opts:["zw\u00f6lf","elf","dreizehn","zehn"],hint:"Think about the calendar year.",sSrc:"A year has {1} months."},
{type:"match",pairs:[{trg:"elf",src:"11"},{trg:"vierzehn",src:"14"},{trg:"neunzehn",src:"19"},{trg:"sechs",src:"6"},{trg:"zw\u00f6lf",src:"12"}]},
{type:"mc",q:"Welche Zahl ist 'vier + zehn'?",opts:["vierzehn","dreizehn","sechzehn","f\u00fcnfzehn"],ans:"vierzehn",hint:"Add the root number directly to zehn."}
]},

{id:"deu_r1l12",title:"Unsere Welt",icon:"\u{1F30D}",xp:15,board:true,steps:[
{type:"intro",title:"Unsere Welt",desc:"Talk about countries, nationalities, and the wider world.",goals:["Name countries and nationalities in German","Use deutsch, europ\u00e4isch, and ausl\u00e4ndisch","Describe things with nicht and sehr"]},
{type:"teach",trg:"das Land",src:"the country",note:"Neuter noun. Plural: die L\u00e4nder. Also means 'land' or 'countryside'.",example:"A: Aus welchem Land kommst du?\nB: Ich komme aus Deutschland.",exampleSrc:"A: Which country do you come from?\nB: I come from Germany.",funFact:"Bundesland means 'federal state.' Germany has 16 Bundesl\u00e4nder."},
{type:"teach",trg:"die Heimat",src:"the homeland",note:"Feminine noun. A deeply emotional word in German. No exact English equivalent.",example:"A: Vermisst du deine Heimat?\nB: Ja, manchmal vermisse ich meine Heimat.",exampleSrc:"A: Do you miss your homeland?\nB: Yes, sometimes I miss my homeland.",funFact:"Heimat carries a sense of belonging and identity. There are Heimat museums, Heimat films, and even a Heimat ministry."},
{type:"teach",trg:"die Welt",src:"the world",note:"Feminine noun. Plural: die Welten (rare, mostly in fantasy contexts).",example:"A: Die Welt ist sehr gro\u00df.\nB: Ja, ich will die Welt sehen.",exampleSrc:"A: The world is very big.\nB: Yes, I want to see the world.",funFact:"Weltmeister (world champion) is a favorite German compound. Germany loves being Weltmeister in anything."},
{type:"teach",trg:"das Europa",src:"Europe",note:"Neuter noun. Used with article in some contexts, without in others.",example:"A: Warst du schon in Europa?\nB: Ja, ich lebe in Europa.",exampleSrc:"A: Have you been to Europe?\nB: Yes, I live in Europe.",funFact:"The name Europa comes from Greek mythology. Europa was a princess abducted by Zeus."},
{type:"teach",trg:"der Europ\u00e4er",src:"the European (male person)",note:"Masculine noun. Feminine: die Europ\u00e4erin.",example:"A: Bist du Europ\u00e4er?\nB: Ja, ich bin Europ\u00e4er.",exampleSrc:"A: Are you European?\nB: Yes, I am European.",funFact:"The suffix -er for male persons and -erin for female persons is the standard German pattern for nationalities."},
{type:"teach",trg:"europ\u00e4isch",src:"European (adjective)",note:"Adjective. Used to describe things, not people. Die europ\u00e4ische Union.",example:"A: Ist das europ\u00e4isch?\nB: Ja, das ist ein europ\u00e4isches Produkt.",exampleSrc:"A: Is that European?\nB: Yes, that is a European product.",funFact:"The suffix -isch is the most common way to form adjectives from place names in German."},
{type:"teach",trg:"deutsch",src:"German (adjective)",note:"Adjective. Lowercase when used as an adjective, capitalized as a noun: Deutsch (the language).",example:"A: Sprichst du Deutsch?\nB: Ja, ich lerne Deutsch.",exampleSrc:"A: Do you speak German?\nB: Yes, I am learning German.",funFact:"Deutsch originally meant 'of the people' from an old word for 'people' or 'nation.'"},
{type:"teach",trg:"die Deutsche",src:"the German woman",note:"Feminine noun. Masculine: der Deutsche. Plural: die Deutschen.",example:"A: Ist sie Deutsche?\nB: Ja, sie ist Deutsche.",exampleSrc:"A: Is she German?\nB: Yes, she is German.",funFact:"Der/die Deutsche is one of the few nationalities in German that works like an adjective noun. Most others use -er/-erin."},
{type:"teach",trg:"das Ausland",src:"abroad, foreign country",note:"Neuter noun. No plural. Im Ausland = abroad.",example:"A: Arbeitest du im Ausland?\nB: Ja, ich arbeite im Ausland.",exampleSrc:"A: Do you work abroad?\nB: Yes, I work abroad.",funFact:"Aus (out) + Land (country) = Ausland. The opposite is Inland (domestic)."},
{type:"teach",trg:"der Ausl\u00e4nder",src:"the foreigner (male)",note:"Masculine noun. Feminine: die Ausl\u00e4nderin. Plural: die Ausl\u00e4nder.",example:"A: Bist du Ausl\u00e4nder?\nB: Ja, ich komme aus England.",exampleSrc:"A: Are you a foreigner?\nB: Yes, I come from England.",funFact:"Ausl\u00e4nderamt (foreigners' office) is where non-Germans register. Now often called Ausl\u00e4nderbeh\u00f6rde."},
{type:"teach",trg:"ausl\u00e4ndisch",src:"foreign",note:"Adjective. Ausl\u00e4ndisches Essen = foreign food.",example:"A: Magst du ausl\u00e4ndisches Essen?\nB: Ja, ich liebe ausl\u00e4ndisches Essen.",exampleSrc:"A: Do you like foreign food?\nB: Yes, I love foreign food.",funFact:"Germany has a huge variety of ausl\u00e4ndische Restaurants. D\u00f6ner Kebab is the most popular fast food in the country."},
{type:"teach",trg:"international",src:"international",note:"Adjective. Same word in many languages. Ein internationaler Flughafen.",example:"A: Ist Berlin international?\nB: Ja, Berlin ist sehr international.",exampleSrc:"A: Is Berlin international?\nB: Yes, Berlin is very international.",funFact:"This word looks the same in English, French, Spanish, and German. A true international word."},
{type:"teach",trg:"nicht",src:"not",note:"Adverb. Placed before the word it negates. Ich bin nicht m\u00fcde.",example:"A: Bist du m\u00fcde?\nB: Nein, ich bin nicht m\u00fcde.",exampleSrc:"A: Are you tired?\nB: No, I am not tired.",funFact:"Nicht is one of the top 10 most used words in German. You will hear it in almost every conversation."},
{type:"teach",trg:"sehr",src:"very",note:"Adverb. Placed before adjectives and adverbs. Das ist sehr gut.",example:"A: Wie ist das Essen?\nB: Es ist sehr gut!",exampleSrc:"A: How is the food?\nB: It is very good!",funFact:"Sehr originally meant 'painfully' in Old German. Over time it softened to just mean 'very.'"},
{type:"mc",q:"Wie sagt man 'foreign' auf Deutsch?",opts:["ausl\u00e4ndisch","europ\u00e4isch","international","deutsch"],ans:"ausl\u00e4ndisch",hint:"Think about the word Ausland (abroad)."},
{type:"fb",s:"Ich arbeite im {1}.",a:["Ausland"],opts:["Ausland","Heimat","Welt","Land"],hint:"This neuter noun means abroad.",sSrc:"I work {1}."},
{type:"match",pairs:[{trg:"die Welt",src:"the world"},{trg:"die Heimat",src:"the homeland"},{trg:"das Land",src:"the country"},{trg:"der Ausl\u00e4nder",src:"the foreigner"},{trg:"deutsch",src:"German (adj.)"}]},
{type:"mc",q:"Was bedeutet 'sehr'?",opts:["very","not","also","always"],ans:"very",hint:"It makes adjectives stronger."},
{type:"fb",s:"Nein, ich bin {1} m\u00fcde.",a:["nicht"],opts:["nicht","sehr","auch","schon"],hint:"This word turns a sentence negative.",sSrc:"No, I am {1} tired."}
]},

{id:"deu_r1l13",title:"Am Flughafen",icon:"\u2708\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Am Flughafen",desc:"Learn essential airport vocabulary and useful verbs for travel situations.",goals:["Name airport objects in German","Use verbs like fragen, finden, and wissen","Understand the difference between kennen and wissen"]},
{type:"teach",trg:"der Flughafen",src:"the airport",note:"Masculine noun. Flug (flight) + Hafen (harbor) = flight harbor. Plural: die Flugh\u00e4fen.",example:"A: Wo ist der Flughafen?\nB: Der Flughafen ist in der N\u00e4he.",exampleSrc:"A: Where is the airport?\nB: The airport is nearby.",funFact:"Frankfurt Flughafen is the busiest airport in Germany and a major European hub."},
{type:"teach",trg:"das Flugzeug",src:"the airplane",note:"Neuter noun. Flug (flight) + Zeug (thing/stuff) = flight thing. Plural: die Flugzeuge.",example:"A: Siehst du das Flugzeug?\nB: Ja, es ist sehr gro\u00df!",exampleSrc:"A: Do you see the airplane?\nB: Yes, it is very big!",funFact:"Zeug means stuff or thing. Werkzeug (tool), Spielzeug (toy), Fahrzeug (vehicle) all follow this pattern."},
{type:"teach",trg:"der Abflug",src:"the departure",note:"Masculine noun. Ab (away) + Flug (flight). Opposite: die Ankunft (arrival).",example:"A: Wann ist der Abflug?\nB: Der Abflug ist um acht Uhr.",exampleSrc:"A: When is the departure?\nB: The departure is at eight o'clock.",funFact:"At German airports, look for Abflug (departures) and Ankunft (arrivals) on the big screens."},
{type:"teach",trg:"das Gep\u00e4ck",src:"the luggage",note:"Neuter noun. No plural. Always singular, like English 'luggage'.",example:"A: Wo ist dein Gep\u00e4ck?\nB: Mein Gep\u00e4ck ist hier.",exampleSrc:"A: Where is your luggage?\nB: My luggage is here.",funFact:"Gep\u00e4ckband (luggage belt) is the baggage carousel. Handgep\u00e4ck is carry-on luggage."},
{type:"teach",trg:"der Koffer",src:"the suitcase",note:"Masculine noun. Plural: die Koffer.",example:"A: Ist das dein Koffer?\nB: Ja, das ist mein Koffer.",exampleSrc:"A: Is that your suitcase?\nB: Yes, that is my suitcase.",funFact:"Koffer comes from French coffre (chest). Kofferraum is the trunk of a car: suitcase room."},
{type:"teach",trg:"die Reise",src:"the trip, the journey",note:"Feminine noun. Plural: die Reisen. Gute Reise! = Have a good trip!",example:"A: Wie war die Reise?\nB: Die Reise war sehr gut.",exampleSrc:"A: How was the trip?\nB: The trip was very good.",funFact:"Reiseb\u00fcro (travel agency) and Reisepass (passport) are common compounds with Reise."},
{type:"teach",trg:"das Ticket",src:"the ticket",note:"Neuter noun. Plural: die Tickets. Also: die Fahrkarte (for trains/buses).",example:"A: Hast du das Ticket?\nB: Ja, ich habe das Ticket hier.",exampleSrc:"A: Do you have the ticket?\nB: Yes, I have the ticket here.",funFact:"Ticket is borrowed from English but fully adopted in German. Flugticket = flight ticket."},
{type:"teach",trg:"der Zoll",src:"customs",note:"Masculine noun. At the airport: Haben Sie etwas zu verzollen? (Do you have anything to declare?)",example:"A: Wo ist der Zoll?\nB: Der Zoll ist nach der Ankunft.",exampleSrc:"A: Where is customs?\nB: Customs is after arrival.",funFact:"Zoll also means 'inch' in German. Two completely different meanings from the same word."},
{type:"teach",trg:"antworten",src:"to answer",note:"Regular verb. Ich antworte, du antwortest, er/sie antwortet.",example:"A: Kannst du bitte antworten?\nB: Ja, ich antworte sofort.",exampleSrc:"A: Can you please answer?\nB: Yes, I will answer right away.",funFact:"Antworten takes a dative object: Ich antworte dir (I answer you), not Ich antworte dich."},
{type:"teach",trg:"bedeuten",src:"to mean",note:"Regular verb. Was bedeutet das? = What does that mean?",example:"A: Was bedeutet 'Flughafen'?\nB: Es bedeutet 'airport'.",exampleSrc:"A: What does 'Flughafen' mean?\nB: It means 'airport'.",funFact:"Was bedeutet...? is one of the most useful phrases for language learners. Use it often!"},
{type:"teach",trg:"buchstabieren",src:"to spell",note:"Regular verb. K\u00f6nnen Sie das buchstabieren? = Can you spell that?",example:"A: Wie ist Ihr Name?\nB: Ich buchstabiere: M-\u00dc-L-L-E-R.",exampleSrc:"A: What is your name?\nB: I will spell it: M-U-L-L-E-R.",funFact:"Buchstabe means letter (of the alphabet). Buchstabieren literally means 'to do letters.'"},
{type:"teach",trg:"danken",src:"to thank",note:"Regular verb. Ich danke dir = I thank you (informal). Ich danke Ihnen = I thank you (formal).",example:"A: Hier ist Ihr Ticket.\nB: Ich danke Ihnen!",exampleSrc:"A: Here is your ticket.\nB: I thank you!",funFact:"Danke (thanks) comes from danken. Dankesch\u00f6n and Danke sehr are more emphatic forms."},
{type:"teach",trg:"entschuldigen",src:"to excuse",note:"Regular verb. Entschuldigen Sie! = Excuse me! (formal). Entschuldigung! = Sorry!",example:"A: Entschuldigen Sie, wo ist der Zoll?\nB: Der Zoll ist dort dr\u00fcben.",exampleSrc:"A: Excuse me, where is customs?\nB: Customs is over there.",funFact:"Ent- (un-) + Schuld (guilt) + -igen = to un-guilt someone. Literally: to remove guilt."},
{type:"teach",trg:"finden",src:"to find",note:"Irregular verb. Ich finde, du findest. Past: ich fand.",example:"A: Findest du den Koffer?\nB: Ja, ich finde ihn!",exampleSrc:"A: Can you find the suitcase?\nB: Yes, I found it!",funFact:"Ich finde das gut means 'I think that is good.' Finden is also used for opinions."},
{type:"teach",trg:"fragen",src:"to ask",note:"Regular verb. Ich frage, du fragst. Die Frage (noun) = the question.",example:"A: Kann ich dich etwas fragen?\nB: Ja, frag mich!",exampleSrc:"A: Can I ask you something?\nB: Yes, ask me!",funFact:"Fragen takes an accusative object: Ich frage dich. But you say: Ich frage nach dem Weg (I ask for the way)."},
{type:"teach",trg:"kennen",src:"to know (a person or place)",note:"Irregular verb. Ich kenne, du kennst. Past: ich kannte. For people, places, and things you are familiar with.",example:"A: Kennst du Berlin?\nB: Ja, ich kenne Berlin gut.",exampleSrc:"A: Do you know Berlin?\nB: Yes, I know Berlin well.",funFact:"Kennen is about personal familiarity. You kennen a friend, a city, a song."},
{type:"teach",trg:"wissen",src:"to know (a fact)",note:"Irregular verb. Ich wei\u00df, du wei\u00dft, er/sie wei\u00df. For facts and information.",example:"A: Wei\u00dft du, wann der Abflug ist?\nB: Nein, ich wei\u00df es nicht.",exampleSrc:"A: Do you know when the departure is?\nB: No, I do not know.",funFact:"Wissen is for facts. Kennen is for familiarity. Ich wei\u00df, dass Berlin gro\u00df ist (fact). Ich kenne Berlin (familiarity)."},
{type:"tip",title:"kennen oder wissen?",text:"Both mean 'to know' but they are used differently.\n\nkennen = to know a person, place, or thing (personal familiarity)\n\u2022 Ich kenne deinen Bruder. (I know your brother.)\n\u2022 Kennst du dieses Lied? (Do you know this song?)\n\nwissen = to know a fact or piece of information\n\u2022 Ich wei\u00df die Antwort. (I know the answer.)\n\u2022 Wei\u00dft du, wo der Flughafen ist? (Do you know where the airport is?)"},
{type:"mc",q:"Welches Wort bedeutet 'suitcase'?",opts:["der Koffer","das Gep\u00e4ck","das Ticket","der Zoll"],ans:"der Koffer",hint:"This masculine noun comes from the French word for chest."},
{type:"fb",s:"Was {1} das auf Deutsch?",a:["bedeutet"],opts:["bedeutet","findet","fragt","kennt"],hint:"This verb is used to ask for the meaning of a word.",sSrc:"What {1} that in German?"},
{type:"mc",q:"'Ich _____ Berlin gut.' Which verb fits? You have visited Berlin many times.",opts:["kenne","wei\u00df","frage","finde"],ans:"kenne",hint:"This is about personal familiarity with a place."},
{type:"match",pairs:[{trg:"der Flughafen",src:"the airport"},{trg:"das Flugzeug",src:"the airplane"},{trg:"die Reise",src:"the trip"},{trg:"der Abflug",src:"the departure"},{trg:"der Zoll",src:"customs"}]}
]}
]},

// ═══════════════════════════════════════════════════════════════
// UNIT 2: Entschuldigung, wo ist...?
// Story: Verumius lost in Berlin, jaywalking, directions, Döner stand
// CEFR: A1.1 - Places, directions, articles, nominative case
// ═══════════════════════════════════════════════════════════════
{n:2,lang:"de",srcLang:"en",track:"v2",title:"Entschuldigung, wo ist...?",sub:"Lost in Berlin, directions, articles, jaywalking",icon:"\uD83D\uDDFA\uFE0F",level:"A1.1",color:"#7B5EE8",lessons:[
// --- L1: Rosa Himmel uber Berlin (Story Intro) ---
{id:"deu_r2l1",title:"Rosa Himmel über Berlin",icon:"\uD83C\uDF05",xp:15,board:true,steps:[
{type:"intro",title:"Rosa Himmel über Berlin",desc:"Verumius stands at the Brandenburger Tor with an upside-down map. Pink dawn light. German street names everywhere. Time to learn the city.",goals:["Learn Berlin landmarks and places","Master first direction words","Understand noun genders through articles"]},
{type:"story",speaker:"narrator",mood:"excited",art:"de-brandenburger-tor",trg:"Brandenburger Tor. Rosa Himmel. Verumius steht mit einem Stadtplan. Der Stadtplan ist falsch herum. Er dreht ihn. Jetzt ist alles noch verwirrender.",src:"Brandenburg Gate. Pink sky. Verumius stands with a city map. The map is upside down. He turns it. Now everything is even more confusing."},
{type:"teach",trg:"die Straße",src:"the street",note:"Feminine noun. Plural: die Straßen.",example:"A: Wie heißt diese Straße?\nB: Das ist die Friedrichstraße.",exampleSrc:"A: What is this street called?\nB: This is Friedrichstraße.",funFact:"Germany has about 650,000 streets. The longest street name? Bischofszeller Straße. The ß (Eszett) is unique to German."},
{type:"teach",trg:"der Platz",src:"the square, plaza",note:"Masculine noun. Plural: die Plätze.",example:"A: Wo ist der Alexanderplatz?\nB: Der Alexanderplatz ist dort drüben.",exampleSrc:"A: Where is Alexanderplatz?\nB: Alexanderplatz is over there.",funFact:"Alexanderplatz was named after Russian Tsar Alexander I. Berliners call it 'Alex.' Every German city has a central Platz."},
{type:"teach",trg:"die Brücke",src:"the bridge",note:"Feminine noun. Plural: die Brücken.",example:"A: Die Brücke ist schön!\nB: Ja, Berlin hat viele Brücken.",exampleSrc:"A: The bridge is beautiful!\nB: Yes, Berlin has many bridges.",funFact:"Berlin has more bridges than Venice. About 1,700! The Oberbaumbrücke is the most famous, connecting Kreuzberg and Friedrichshain."},
{type:"teach",trg:"die Kirche",src:"the church",note:"Feminine noun. Plural: die Kirchen.",example:"A: Ist das eine Kirche?\nB: Ja, das ist die Gedächtniskirche.",exampleSrc:"A: Is that a church?\nB: Yes, that is the Memorial Church.",funFact:"The Kaiser-Wilhelm-Gedächtniskirche was deliberately left half-ruined after WWII as a peace memorial. Berliners call it 'der hohle Zahn' (the hollow tooth)."},
{type:"teach",trg:"das Rathaus",src:"the city hall",note:"Neuter noun. Compound: Rat (council) + Haus (house).",example:"A: Wo ist das Rathaus?\nB: Das Rathaus ist am Alexanderplatz.",exampleSrc:"A: Where is city hall?\nB: City hall is at Alexanderplatz.",funFact:"Berlin's Rathaus is called 'Rotes Rathaus' because of its red bricks, not its politics. Compound nouns take the gender of the LAST word: Haus = das."},
{type:"teach",trg:"links",src:"left",note:"Direction word. No gender (adverb).",example:"A: Wohin gehe ich?\nB: Gehen Sie links.",exampleSrc:"A: Where do I go?\nB: Go left.",funFact:"In old Germanic tradition, 'links' was considered the unlucky side. Left-handers were once forced to switch hands. The word is related to 'link' (sly/cunning)."},
{type:"teach",trg:"rechts",src:"right",note:"Direction word. No gender (adverb).",example:"A: Ist die Apotheke rechts?\nB: Ja, rechts an der Ecke.",exampleSrc:"A: Is the pharmacy on the right?\nB: Yes, on the right at the corner.",funFact:"'Recht' also means 'right/correct' and 'law.' Rechts = right in every sense. 'Das Recht' = the law. 'Du hast recht' = you are right."},
{type:"teach",trg:"geradeaus",src:"straight ahead",note:"Direction word. Compound: gerade (straight) + aus (out).",example:"A: Wo ist der Bahnhof?\nB: Immer geradeaus!",exampleSrc:"A: Where is the station?\nB: Straight ahead!",funFact:"Germans love building compound direction words. Geradeaus = straight-out. You will hear this more than any other direction word."},
{type:"teach",trg:"wohin",src:"where to",note:"Question word for direction/destination.",example:"A: Wohin fährst du?\nB: Ich fahre nach Berlin.",exampleSrc:"A: Where are you going?\nB: I am going to Berlin.",funFact:"German splits 'where' into three: wo (where at), woher (where from), wohin (where to). English lost this precision centuries ago."},
{type:"tip",title:"Gender Color Code",text:"Every German noun has a gender. Watch the colors on every word card:\n\nder = blue (masculine)\ndie = crimson (feminine)\ndas = green (neuter)\n\nYour brain will start seeing patterns. Trust the colors."},
{type:"mc",q:"Verumius needs to go straight. Which direction word?",opts:["geradeaus","links","rechts","wohin"],ans:"geradeaus",hint:"This compound word means 'straight-out.'"},
{type:"fb",s:"Die Kirche ist {1}, nicht rechts.",a:["links"],opts:["links","geradeaus","wohin","hier"],hint:"The opposite of rechts (right) is...",sSrc:"The church is {1}, not right."},
{type:"mc",q:"Which article goes with 'Rathaus'?",opts:["das Rathaus","der Rathaus","die Rathaus","ein Rathaus"],ans:"das Rathaus",hint:"Compound nouns take the gender of the last word. Haus is neuter."},
{type:"match",pairs:[{trg:"die Straße",src:"street"},{trg:"der Platz",src:"square"},{trg:"die Brücke",src:"bridge"},{trg:"die Kirche",src:"church"},{trg:"das Rathaus",src:"city hall"}]},
{type:"fb",s:"Berlin hat viele {1}. Die Oberbaumbrücke ist berühmt.",a:["Brücken"],opts:["Brücken","Straßen","Plätze","Kirchen"],hint:"Structures that cross rivers or canals. Berlin has 1,700 of them.",sSrc:"Berlin has many {1}. The Oberbaumbrücke is famous."},
{type:"mc",q:"German splits 'where' into three words. Which asks about direction?",opts:["wohin","wo","woher","warum"],ans:"wohin",hint:"This question word asks WHERE TO, not where at or where from."}
]},
// --- L2: Die Stadt erkunden (Vocab: Places + Transport) ---
{id:"deu_r2l2",title:"Die Stadt erkunden",icon:"\uD83C\uDFD9\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Die Stadt erkunden",desc:"Learn the places you will see (and get lost trying to find) in a German city. Every noun comes with its article and gender color.",goals:["Learn 30+ place and transport words","Recognize noun gender patterns","Navigate a German city with confidence"]},
{type:"teach",trg:"die Stadt",src:"the city / town",note:"Feminine noun. Plural: die Städte (note the umlaut!).\nOne of the most common German nouns. Used in many compounds.",example:"A: Gefällt dir die Stadt?\nB: Ja, Berlin ist eine tolle Stadt!\nA: Welche Stadt in Deutschland magst du am liebsten?",exampleSrc:"A: Do you like the city?\nB: Yes, Berlin is a great city!\nA: Which city in Germany do you like the most?",funFact:"German builds dozens of compounds from Stadt: Innenstadt (city center), Stadtplan (city map), Hauptstadt (capital city), Altstadt (old town), Stadtrat (city council). Learn Stadt and you unlock them all."},
{type:"teach",trg:"die Apotheke",src:"the pharmacy",note:"Feminine noun. Marked with a red A symbol.",example:"A: Ich brauche Medizin. Wo ist die Apotheke?\nB: Die Apotheke ist um die Ecke.",exampleSrc:"A: I need medicine. Where is the pharmacy?\nB: The pharmacy is around the corner.",funFact:"German pharmacies sell medicine only. For shampoo, toothpaste, or vitamins, you need a Drogerie (like dm or Rossmann). Two different shops!"},
{type:"teach",trg:"die Bank",src:"the bank",note:"Feminine noun. Also means 'the bench'!",example:"A: Wo ist die Bank?\nB: Die Bank ist neben dem Hotel.",exampleSrc:"A: Where is the bank?\nB: The bank is next to the hotel.",funFact:"Die Bank means both 'the bank' and 'the bench.' Context tells you which. At a park, it is a bench. On a street with glass doors, it is a bank."},
{type:"teach",trg:"die Bibliothek",src:"the library",note:"Feminine noun. From Greek 'bibliotheke.'",example:"A: Hast du ein Buch?\nB: Nein, ich gehe in die Bibliothek.",exampleSrc:"A: Do you have a book?\nB: No, I am going to the library.",funFact:"Berlin's Staatsbibliothek has over 11 million books. The word comes from Greek: biblion (book) + theke (storage). Same root as 'Bible.'"},
{type:"teach",trg:"die Bäckerei",src:"the bakery",note:"Feminine noun. The -ei ending is ALWAYS feminine.",example:"A: Wo kaufst du Brot?\nB: In der Bäckerei natürlich!",exampleSrc:"A: Where do you buy bread?\nB: At the bakery, of course!",funFact:"Germany has about 11,000 bakeries. That is more than McDonald's, Burger King, and Starbucks combined. Words ending in -ei are always feminine (die)."},
{type:"teach",trg:"das Café",src:"the cafe",note:"Neuter noun. das Café = the place, der Kaffee = the drink.",example:"A: Gehen wir ins Café?\nB: Ja, ich möchte einen Kaffee.",exampleSrc:"A: Shall we go to the cafe?\nB: Yes, I would like a coffee.",funFact:"das Café = the place where you drink. der Kaffee = the drink itself. Different genders, different meanings. Berlin has over 2,000 cafes."},
{type:"teach",trg:"das Geschäft",src:"the shop, store, business",note:"Neuter noun. More formal than 'Laden.'",example:"A: Ist das Geschäft noch auf?\nB: Nein, es ist geschlossen.",exampleSrc:"A: Is the store still open?\nB: No, it is closed.",funFact:"Geschäft means both 'shop' and 'business.' A Geschäftsmann is a businessman. A Geschäftsfrau is a businesswoman. German loves transparent compounds."},
{type:"teach",trg:"die Innenstadt",src:"the city center",note:"Feminine noun. Compound: Innen (inner) + Stadt (city).",example:"A: Wo ist die Innenstadt?\nB: Die Innenstadt ist am Alexanderplatz.",exampleSrc:"A: Where is the city center?\nB: The city center is at Alexanderplatz.",funFact:"Literally 'inner city.' Germans build nouns by stacking: Innen + Stadt. The gender follows the last word: Stadt = die."},
{type:"teach",trg:"das Kino",src:"the cinema",note:"Neuter noun. From Greek 'kinema' (movement).",example:"A: Was läuft im Kino?\nB: Ein deutscher Film!",exampleSrc:"A: What is playing at the cinema?\nB: A German film!",funFact:"Germans say 'Wir gehen ins Kino' even when they mean streaming at home. Berlin hosts the Berlinale, one of the world's biggest film festivals."},
{type:"teach",trg:"der Markt",src:"the market",note:"Masculine noun. Plural: die Märkte.",example:"A: Wann ist der Markt?\nB: Der Markt ist am Samstag.",exampleSrc:"A: When is the market?\nB: The market is on Saturday.",funFact:"Every German town has a weekly Wochenmarkt. Berlin's Turkish Market on the Maybachufer is legendary for fresh produce and street food."},
{type:"mc",q:"You need bread. Which place do you look for?",opts:["die Bäckerei","die Bank","die Bibliothek","die Apotheke"],ans:"die Bäckerei",hint:"Think of Bäcker (baker). Where does a baker work?"},
{type:"teach",trg:"der Laden",src:"the shop (casual)",note:"Masculine noun. More casual than Geschäft.",example:"A: Kennst du den Laden?\nB: Ja, der Laden ist gut.",exampleSrc:"A: Do you know that shop?\nB: Yes, the shop is good.",funFact:"Laden feels small and personal. Geschäft feels professional and formal. A family bookshop is a Laden. A department store is a Geschäft."},
{type:"teach",trg:"das Restaurant",src:"the restaurant",note:"Neuter noun. Pronounced res-toh-RAHNG.",example:"A: Gehen wir ins Restaurant?\nB: Ja, ich habe Hunger!",exampleSrc:"A: Shall we go to the restaurant?\nB: Yes, I am hungry!",funFact:"Pronounced more German than French: res-toh-RAHNG. Tipping in Germany is usually 5-10%, not the 15-20% Americans expect."},
{type:"teach",trg:"das Schloss",src:"the castle, palace",note:"Neuter noun. Also means 'lock'!",example:"A: Ist das ein Schloss?\nB: Ja, das Schloss Charlottenburg.",exampleSrc:"A: Is that a castle?\nB: Yes, Charlottenburg Palace.",funFact:"Das Schloss means both 'the castle' and 'the lock.' Context saves you. Germany has over 20,000 castles and palaces."},
{type:"teach",trg:"das Auto",src:"the car",note:"Neuter noun. Short for Automobil.",example:"A: Hast du ein Auto?\nB: Nein, ich fahre mit dem Bus.",exampleSrc:"A: Do you have a car?\nB: No, I take the bus.",funFact:"Germany invented the automobile. Karl Benz built the first one in 1886. The Autobahn has sections with no speed limit. Germans take driving very seriously."},
{type:"teach",trg:"die U-Bahn",src:"the subway",note:"Feminine noun. U = Untergrund (underground).",example:"A: Nehmen wir die U-Bahn?\nB: Ja, die U-Bahn ist schnell.",exampleSrc:"A: Shall we take the subway?\nB: Yes, the subway is fast.",funFact:"U = Untergrund. Berlin's first U-Bahn line opened in 1902. Today there are 10 lines and 175 stations. The yellow trains are iconic."},
{type:"teach",trg:"die S-Bahn",src:"the city train",note:"Feminine noun. S = Schnell (fast) or Stadt (city).",example:"A: Die S-Bahn kommt in zwei Minuten.\nB: Gut, wir nehmen die S-Bahn.",exampleSrc:"A: The S-Bahn comes in two minutes.\nB: Good, we will take the S-Bahn.",funFact:"S-Bahn runs above ground through the city. Berlin's S-Bahn ring circles the center. Together with U-Bahn, it forms one of Europe's best transit networks."},
{type:"teach",trg:"das Fahrrad",src:"the bicycle",note:"Neuter noun. Compound: Fahr (drive) + Rad (wheel).",example:"A: Fährst du mit dem Fahrrad?\nB: Ja, ich fahre jeden Tag.",exampleSrc:"A: Do you ride a bicycle?\nB: Yes, I ride every day.",funFact:"Fahr + Rad = drive-wheel. Berlin has over 1,000 km of bike paths. Many Berliners use a Fahrrad as their main transport."},
{type:"match",pairs:[{trg:"die Apotheke",src:"pharmacy"},{trg:"das Café",src:"cafe"},{trg:"der Markt",src:"market"},{trg:"die Bäckerei",src:"bakery"},{trg:"das Kino",src:"cinema"},{trg:"die U-Bahn",src:"subway"}]},
{type:"teach",trg:"der Stadtplan",src:"the city map",note:"Masculine noun. Compound: Stadt (city) + Plan (plan).",example:"A: Hast du einen Stadtplan?\nB: Ja, aber er ist falsch herum!",exampleSrc:"A: Do you have a city map?\nB: Yes, but it is upside down!",funFact:"Stadt + Plan. Verumius should have used a better one. Compound nouns take the gender of the last word: Plan = der."},
{type:"teach",trg:"der Eingang",src:"the entrance",note:"Masculine noun. Ein (in) + Gang (walk).",example:"A: Wo ist der Eingang?\nB: Der Eingang ist dort.",exampleSrc:"A: Where is the entrance?\nB: The entrance is there.",funFact:"Ein + Gang = in-walk. The exit? Ausgang = out-walk. Germany loves building logical compound nouns."},
{type:"teach",trg:"die Haltestelle",src:"the bus/tram stop",note:"Feminine noun. Halte (stop) + Stelle (place).",example:"A: Ist hier eine Haltestelle?\nB: Ja, die Haltestelle ist dort.",exampleSrc:"A: Is there a stop here?\nB: Yes, the stop is over there.",funFact:"Halte + Stelle = stop-place. Every German city marks its Haltestellen with a green H sign."},
{type:"teach",trg:"die Kreuzung",src:"the intersection",note:"Feminine noun. From Kreuz (cross). The -ung ending = always die.",example:"A: An der Kreuzung links abbiegen.\nB: Danke!",exampleSrc:"A: Turn left at the intersection.\nB: Thanks!",funFact:"From Kreuz (cross). Where streets cross. The -ung ending is ALWAYS feminine: die Kreuzung, die Richtung, die Verbindung."},
{type:"tip",title:"Gender Patterns",text:"Words ending in -ung, -ei, -keit, -heit, -ie are ALWAYS feminine (die).\nWords ending in -chen are ALWAYS neuter (das).\nCompound nouns take the gender of the LAST word.\nThese rules cover hundreds of nouns."},
{type:"mc",q:"Which word means 'connection' for transit?",opts:["die Verbindung","die Kreuzung","die Haltestelle","der Bahnsteig"],ans:"die Verbindung",hint:"The -ung ending tells you it is feminine. This word is about connecting routes."},
{type:"mc",q:"You need medicine. You look for...",opts:["die Apotheke","die Bäckerei","die Bank","das Café"],ans:"die Apotheke",hint:"The red A symbol marks these in Germany."}
]},
// --- L3: Entschuldigung, können Sie mir helfen? (Story Dev) ---
{id:"deu_r2l3",title:"Können Sie mir helfen?",icon:"\uD83D\uDE4B",xp:15,board:true,steps:[
{type:"intro",title:"Können Sie mir helfen?",desc:"Verumius has a map but no phone signal. Time to ask actual humans for help. In German. With formal address.",goals:["Learn modal verbs können/müssen/dürfen","Master polite request phrases","Survive the jaywalking incident"]},
{type:"teach",trg:"können",src:"can, to be able to",note:"Modal verb. Ich kann, du kannst, er kann, wir können.",example:"A: Können Sie mir helfen?\nB: Ja, natürlich!",exampleSrc:"A: Can you help me?\nB: Yes, of course!",funFact:"'Können Sie...?' is the magic phrase that opens every polite request in German. Learn this before anything else."},
{type:"teach",trg:"müssen",src:"must, to have to",note:"Modal verb. Ich muss, du musst, er muss, wir müssen.",example:"A: Ich muss zum Bahnhof.\nB: Der Bahnhof ist geradeaus.",exampleSrc:"A: I must get to the station.\nB: The station is straight ahead.",funFact:"Unlike English 'must,' German müssen is just neutral obligation. 'Ich muss gehen' means 'I have to go,' not a dramatic declaration."},
{type:"teach",trg:"dürfen",src:"may, to be allowed to",note:"Modal verb. Ich darf, du darfst, er darf, wir dürfen.",example:"A: Darf ich fragen?\nB: Ja, natürlich dürfen Sie!",exampleSrc:"A: May I ask?\nB: Yes, of course you may!",funFact:"'Darf ich?' (May I?) is the German politeness superpower. Use it before touching, asking, or entering. It never fails."},
{type:"teach",trg:"möchten",src:"would like",note:"Polite form. Ich möchte, du möchtest, er möchte.",example:"A: Was möchten Sie?\nB: Ich möchte einen Kaffee, bitte.",exampleSrc:"A: What would you like?\nB: I would like a coffee, please.",funFact:"Technically a subjunctive of mögen. Germans use möchten much more than 'ich will' (which sounds demanding). Möchten is the polite choice."},
{type:"teach",trg:"doch",src:"yes! (contradicting a negative), indeed",note:"Untranslatable particle. Contradicts a negative statement.",example:"A: Du sprichst kein Deutsch!\nB: Doch! Ein bisschen!",exampleSrc:"A: You don't speak German!\nB: Yes I do! A little!",funFact:"Untranslatable! Someone says 'You can't.' You say 'Doch!' = 'Yes I CAN!' English has no single word for this. Germans use it constantly."},
{type:"teach",trg:"mal",src:"just, once (softener)",note:"Makes requests sound friendlier and less demanding.",example:"A: Schau mal!\nB: Was ist das?",exampleSrc:"A: Just look!\nB: What is that?",funFact:"'Schau mal' = just look. 'Sag mal' = tell me. Mal makes everything sound friendlier. Without it, commands sound harsh."},
{type:"teach",trg:"nach",src:"to (cities/countries), after",note:"Preposition with multiple meanings.",example:"A: Ich fahre nach Berlin.\nB: Wann fährst du?",exampleSrc:"A: I am going to Berlin.\nB: When are you going?",funFact:"'Nach Berlin' = to Berlin. 'Nach links' = to the left. 'Nach dem Essen' = after the meal. One little word, enormous reach."},
{type:"teach",trg:"zu",src:"to (specific places/people)",note:"Preposition. 'Zum' = zu + dem, 'Zur' = zu + der.",example:"A: Ich gehe zum Bahnhof.\nB: Der Bahnhof ist nicht weit.",exampleSrc:"A: I am going to the station.\nB: The station is not far.",funFact:"'Zu' for specific places: zum Bahnhof, zur Apotheke. 'Nach' for cities/countries: nach Berlin. This distinction does not exist in English."},
{type:"teach",trg:"neben",src:"next to, beside",note:"Preposition of location.",example:"A: Wo ist die Bank?\nB: Die Bank ist neben der Apotheke.",exampleSrc:"A: Where is the bank?\nB: The bank is next to the pharmacy.",funFact:"'Die Bank ist neben der Apotheke.' Neben = physically beside something. Very useful for giving directions."},
{type:"teach",trg:"geben",src:"to give",note:"Irregular: ich gebe, du gibst, er gibt.",example:"A: Können Sie mir den Stadtplan geben?\nB: Ja, hier bitte!",exampleSrc:"A: Can you give me the city map?\nB: Yes, here you go!",funFact:"'Es gibt' = there is/are (literally 'it gives'). 'Es gibt viele Cafés in Berlin' = There are many cafes in Berlin. One of German's most common phrases."},
{type:"verb_table",title:"geben (to give)",groups:[{label:"Present tense (stem change: e → i)",rows:[{pronoun:"ich",form:"gebe",src:"I give"},{pronoun:"du",form:"gibst",src:"you give"},{pronoun:"er/sie/es",form:"gibt",src:"he/she/it gives"},{pronoun:"wir",form:"geben",src:"we give"},{pronoun:"ihr",form:"gebt",src:"you all give"},{pronoun:"sie/Sie",form:"geben",src:"they/you (formal) give"}]}],note:"Key phrase: es gibt = there is/are. Literally: it gives."},
{type:"teach",trg:"zeigen",src:"to show, to point",note:"Regular verb. Very useful for directions.",example:"A: Können Sie mir den Weg zeigen?\nB: Ja, geradeaus und dann links.",exampleSrc:"A: Can you show me the way?\nB: Yes, straight ahead then left.",funFact:"'Können Sie mir zeigen?' = Can you show me? Point and ask. This gets you anywhere in Germany."},
{type:"teach",trg:"lesen",src:"to read",note:"Irregular: ich lese, du liest, er liest.",example:"A: Kannst du das lesen?\nB: Ja, das ist Deutsch!",exampleSrc:"A: Can you read that?\nB: Yes, that is German!",funFact:"Irregular: the vowel changes from e to ie in du/er forms. Ich lese, du liest. German and English 'read' share the same ancient root."},
{type:"verb_table",title:"lesen (to read)",groups:[{label:"Present tense (stem change: e → ie)",rows:[{pronoun:"ich",form:"lese",src:"I read"},{pronoun:"du",form:"liest",src:"you read"},{pronoun:"er/sie/es",form:"liest",src:"he/she/it reads"},{pronoun:"wir",form:"lesen",src:"we read"},{pronoun:"ihr",form:"lest",src:"you all read"},{pronoun:"sie/Sie",form:"lesen",src:"they/you (formal) read"}]}],note:"Stem vowel e changes to ie in du and er/sie/es. Same pattern: empfehlen (empfiehlt)."},
{type:"teach",trg:"hören",src:"to hear",note:"Regular verb. Zuhören = to listen actively.",example:"A: Hörst du die Musik?\nB: Ja, ich höre sie!",exampleSrc:"A: Do you hear the music?\nB: Yes, I hear it!",funFact:"Hören = to hear passively. Zuhören = to listen actively. 'Hör zu!' = Listen! Adding zu changes passive hearing to active listening."},
{type:"teach",trg:"verstehen",src:"to understand",note:"Inseparable prefix verb: ver + stehen.",example:"A: Verstehen Sie mich?\nB: Ja, ich verstehe!",exampleSrc:"A: Do you understand me?\nB: Yes, I understand!",funFact:"Ver + stehen = to stand before something mentally. 'Ich verstehe' is one of the most useful sentences you will ever learn in German."},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-berlin-street",trg:"Verumius steht an einer Kreuzung. Die Ampel ist rot. Er wartet. Und wartet. Dann geht er. FEHLER! Eine ältere Frau ruft: 'Das darf man NICHT! Die Ampel ist ROT!'",src:"Verumius stands at an intersection. The light is red. He waits. And waits. Then he crosses. MISTAKE! An elderly woman calls out: 'You must NOT do that! The light is RED!'"},
{type:"tip",title:"Jaywalking in Germany",text:"In Germany, crossing on a red light is genuinely frowned upon, especially if children are watching. You might get a lecture from a complete stranger. It is not law enforcement people fear. It is social judgment. Verumius learned this the hard way."},
{type:"mc",q:"Verumius asks for help. Which is most polite?",opts:["Können Sie mir helfen?","Hilf mir!","Wo ist das?","Gib mir den Weg!"],ans:"Können Sie mir helfen?",hint:"Polite requests use a modal verb with the formal pronoun."},
{type:"mc",q:"Someone says 'Du sprichst kein Deutsch.' You DO speak German. You reply:",opts:["Doch!","Nein!","Ja!","Bitte!"],ans:"Doch!",hint:"This special word contradicts a negative statement."},
{type:"fb",s:"Entschuldigung, {1} Sie mir bitte den Weg zeigen?",a:["können"],opts:["können","müssen","dürfen","möchten"],hint:"Which modal expresses ability and polite requests?",sSrc:"Excuse me, {1} you please show me the way?"}
]},
// --- L4: Der, die, das (Grammar) ---
{id:"deu_r2l4",title:"Der, die, das",icon:"\uD83D\uDD24",xp:15,board:true,steps:[
{type:"intro",title:"Der, die, das: Das Artikelmonster",desc:"The German article system: three genders, one monster. But there are patterns that make it learnable.",goals:["Master definite articles (der/die/das)","Learn indefinite articles (ein/eine)","Discover noun gender patterns"]},
{type:"tip",title:"The Nominative Case",text:"The subject of a sentence (who/what DOES the action) uses the nominative case.\n\nder Mann sieht = the man sees\ndie Frau steht = the woman stands\ndas Kind spielt = the child plays\n\nNominative articles: der (masculine), die (feminine), das (neuter), die (plural)."},
{type:"teach",trg:"groß",src:"big, tall, great",note:"Predicative adjective. No ending after 'sein' (to be).",example:"A: Ist das Hotel groß?\nB: Ja, das Hotel ist sehr groß!",exampleSrc:"A: Is the hotel big?\nB: Yes, the hotel is very big!",funFact:"Deutschland means 'land of the people.' Deutsch originally meant 'of the people' in Old High German."},
{type:"teach",trg:"klein",src:"small, little",note:"Predicative adjective. Opposite of groß.",example:"A: Die Bäckerei ist klein.\nB: Ja, aber das Brot ist gut!",exampleSrc:"A: The bakery is small.\nB: Yes, but the bread is good!",funFact:"'Klein aber fein' = small but fine. A beloved German saying about quality over size."},
{type:"teach",trg:"lang",src:"long",note:"For physical length. 'Lange' for time duration.",example:"A: Die Straße ist lang.\nB: Ja, sehr lang!",exampleSrc:"A: The street is long.\nB: Yes, very long!",funFact:"'Lang' for physical length: die Straße ist lang. Add -e for time: 'Wie lange?' = How long (in time)?"},
{type:"teach",trg:"kurz",src:"short (length or time)",note:"Opposite of lang.",example:"A: Ist der Weg kurz?\nB: Ja, nur fünf Minuten.",exampleSrc:"A: Is the way short?\nB: Yes, only five minutes.",funFact:"'Kurz und knapp' = short and concise. Germans value brevity in speech."},
{type:"verb_table",title:"Definite Articles: Nominative",label:"The subject case",groups:[{header:"der/die/das/die",rows:[{pronoun:"Masculine",form:"der",src:"the (masc)"},{pronoun:"Feminine",form:"die",src:"the (fem)"},{pronoun:"Neuter",form:"das",src:"the (neut)"},{pronoun:"Plural",form:"die",src:"the (pl)"}]}]},
{type:"verb_table",title:"Indefinite Articles: Nominative",label:"A/an in the subject case",groups:[{header:"ein/eine/ein",rows:[{pronoun:"Masculine",form:"ein",src:"a (masc)"},{pronoun:"Feminine",form:"eine",src:"a (fem)"},{pronoun:"Neuter",form:"ein",src:"a (neut)"},{pronoun:"Plural",form:"\u2014",src:"(no indefinite plural)"}]}]},
{type:"tip",title:"Gender Patterns",text:"-ung = die (Richtung, Kreuzung, Verbindung)\n-ei = die (Bäckerei)\n-heit/-keit = die (Freiheit, Möglichkeit)\n-chen = das (Mädchen, Brötchen)\nCompound nouns = gender of LAST word (Stadtplan: Plan = der)\nDays, months, seasons = der\n\nThese patterns cover about 65% of German nouns."},
{type:"teach",trg:"die Frage",src:"the question",note:"Feminine noun. 'Keine Frage!' = No doubt!",example:"A: Ich habe eine Frage.\nB: Ja, bitte?",exampleSrc:"A: I have a question.\nB: Yes, please?",funFact:"'Keine Frage!' = No question about it! No doubt! Germans say this when something is obviously true."},
{type:"teach",trg:"das Problem",src:"the problem",note:"Neuter noun. Same as English.",example:"A: Gibt es ein Problem?\nB: Nein, kein Problem!",exampleSrc:"A: Is there a problem?\nB: No, no problem!",funFact:"'Kein Problem!' Same in English and German. One of the easiest words to remember. Always neuter: das Problem."},
{type:"teach",trg:"das Beispiel",src:"the example",note:"Neuter noun. 'Zum Beispiel' (z.B.) = for example.",example:"A: Kannst du ein Beispiel geben?\nB: Ja, zum Beispiel: der Hund.",exampleSrc:"A: Can you give an example?\nB: Yes, for example: the dog.",funFact:"'Zum Beispiel' (z.B.) = 'for example.' You will see z.B. everywhere in German texts. It is the German equivalent of e.g."},
{type:"mc",q:"___ Apotheke ist neben ___ Hotel.",opts:["Die ... dem","Der ... die","Das ... der","Die ... das"],ans:"Die ... dem",hint:"Apotheke is feminine (die). Hotel is neuter (das), and after neben it becomes dem."},
{type:"mc",q:"Das Hotel ist ___. (big)",opts:["groß","große","großes","großer"],ans:"groß",hint:"After 'sein' (is), adjectives have NO ending. Just the base form."},
{type:"teach",trg:"schnell",src:"fast, quick",note:"Adjective/adverb. No ending after sein.",example:"A: Ist der Zug schnell?\nB: Ja, der ICE ist sehr schnell!",exampleSrc:"A: Is the train fast?\nB: Yes, the ICE is very fast!",funFact:"Germans on the Autobahn define 'schnell' differently than most humans. Some sections have no speed limit at all."},
{type:"teach",trg:"langsam",src:"slow",note:"Adjective/adverb. Opposite of schnell.",example:"A: Können Sie langsam sprechen?\nB: Ja, ich spreche langsam.",exampleSrc:"A: Can you speak slowly?\nB: Yes, I will speak slowly.",funFact:"'Langsam, bitte!' = Slowly, please! Your survival phrase when Germans talk too fast. You will use this daily."},
{type:"teach",trg:"anfangen",src:"to start, to begin",note:"Separable verb: Ich fange an.",example:"A: Wann fangen wir an?\nB: Wir fangen um neun an.",exampleSrc:"A: When do we start?\nB: We start at nine.",funFact:"Separable: 'Ich fange an.' The 'an' goes to the end. Synonymous with beginnen, but anfangen is more casual."},
{type:"teach",trg:"aufhören",src:"to stop, to quit",note:"Separable verb: Hör auf!",example:"A: Hör auf!\nB: Okay, ich höre auf.",exampleSrc:"A: Stop it!\nB: Okay, I will stop.",funFact:"Separable: 'Hör auf!' = Stop it! One of the first commands German kids learn. Auf = up/open, hören = to hear."},
{type:"fb",s:"{1} Straße ist lang und breit.",a:["Die"],opts:["Die","Der","Das","Ein"],hint:"Straße is feminine. Which definite article matches?",sSrc:"{1} street is long and wide."},
{type:"mc",q:"Which is correct?",opts:["Das Museum ist groß.","Das Museum ist großes.","Der Museum ist groß.","Das Museum ist große."],ans:"Das Museum ist groß.",hint:"This noun is neuter. Predicative adjectives need no ending."},
{type:"drag_fill",s:"{1} Café ist klein, aber {2} Restaurant ist groß.",blanks:{"1":"Das","2":"das"},pool:["Das","das","Der","die","Die"],hint:"Café and Restaurant are both neuter. Sentence-initial gets capital D.",sSrc:"{1} café is small, but {2} restaurant is big."},
{type:"mc",q:"Words ending in -ung are always...",opts:["feminine (die)","masculine (der)","neuter (das)","depends on the word"],ans:"feminine (die)",hint:"Richtung, Kreuzung, Verbindung, Besichtigung... all die."}
]},
// --- L5: Unterwegs in der Stadt (Vocab: Verbs + Adjectives) ---
{id:"deu_r2l5",title:"Unterwegs in der Stadt",icon:"\uD83D\uDEB6",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs in der Stadt",desc:"Verumius wanders Berlin. Every shop, every sign, every scene is a vocabulary lesson. Today: essential verbs and adjectives.",goals:["Learn 30+ everyday verbs","Master descriptive adjectives","Describe places and situations"]},
{type:"teach",trg:"essen",src:"to eat",note:"Irregular: ich esse, du isst, er isst.",example:"A: Was isst du?\nB: Ich esse einen Döner.",exampleSrc:"A: What are you eating?\nB: I am eating a Döner.",funFact:"Irregular: ich esse, du isst. 'Du isst' sounds exactly like 'du ist' (you are). Context saves you every time."},
{type:"verb_table",title:"essen (to eat)",groups:[{label:"Present tense (stem change: e → i)",rows:[{pronoun:"ich",form:"esse",src:"I eat"},{pronoun:"du",form:"isst",src:"you eat"},{pronoun:"er/sie/es",form:"isst",src:"he/she/it eats"},{pronoun:"wir",form:"essen",src:"we eat"},{pronoun:"ihr",form:"esst",src:"you all eat"},{pronoun:"sie/Sie",form:"essen",src:"they/you (formal) eat"}]}],note:"du isst sounds like du ist (you are). Context saves you!"},
{type:"teach",trg:"bestellen",src:"to order",note:"Inseparable prefix verb. Regular conjugation.",example:"A: Ich möchte bestellen.\nB: Was möchten Sie?",exampleSrc:"A: I would like to order.\nB: What would you like?",funFact:"'Ich möchte bestellen' = your restaurant survival phrase. In German restaurants, you often need to actively call the waiter."},
{type:"teach",trg:"bezahlen",src:"to pay",note:"Inseparable prefix verb. Regular.",example:"A: Kann ich bezahlen?\nB: Bar oder mit Karte?",exampleSrc:"A: Can I pay?\nB: Cash or card?",funFact:"Many German shops still prefer cash. 'Nur Bargeld' (cash only) signs are common. Germans love their cash."},
{type:"teach",trg:"kaufen",src:"to buy",note:"Regular verb. Ver+kaufen = to sell.",example:"A: Ich kaufe Brot.\nB: In der Bäckerei?",exampleSrc:"A: I am buying bread.\nB: At the bakery?",funFact:"Kaufen = buy. Verkaufen = sell. The ver- prefix reverses the meaning. Kaufhaus = department store."},
{type:"verb_table",title:"kaufen (to buy)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"kaufe",src:"I buy"},{pronoun:"du",form:"kaufst",src:"you buy"},{pronoun:"er/sie/es",form:"kauft",src:"he/she/it buys"},{pronoun:"wir",form:"kaufen",src:"we buy"},{pronoun:"ihr",form:"kauft",src:"you all buy"},{pronoun:"sie/Sie",form:"kaufen",src:"they/you (formal) buy"}]}],note:"Regular pattern. Einkaufen (separable) = to shop: Ich kaufe ein."},
{type:"teach",trg:"kochen",src:"to cook",note:"Regular verb. Related to Küche (kitchen).",example:"A: Kannst du kochen?\nB: Ja, ich koche gern!",exampleSrc:"A: Can you cook?\nB: Yes, I like to cook!",funFact:"Related to English 'kitchen' (Küche). Both come from Latin 'coquere' (to cook). German kept the K sound."},
{type:"verb_table",title:"kochen (to cook)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"koche",src:"I cook"},{pronoun:"du",form:"kochst",src:"you cook"},{pronoun:"er/sie/es",form:"kocht",src:"he/she/it cooks"},{pronoun:"wir",form:"kochen",src:"we cook"},{pronoun:"ihr",form:"kocht",src:"you all cook"},{pronoun:"sie/Sie",form:"kochen",src:"they/you (formal) cook"}]}],note:"Regular pattern. Der Koch = the cook (noun). Die Küche = the kitchen."},
{type:"teach",trg:"arbeiten",src:"to work",note:"Regular verb. Arbeit = work (noun).",example:"A: Wo arbeitest du?\nB: Ich arbeite in Berlin.",exampleSrc:"A: Where do you work?\nB: I work in Berlin.",funFact:"Arbeit means both 'work' and 'effort/craft.' German workers are protected by some of Europe's strongest labor laws."},
{type:"verb_table",title:"arbeiten (to work)",groups:[{label:"Present tense (regular, -eten verb)",rows:[{pronoun:"ich",form:"arbeite",src:"I work"},{pronoun:"du",form:"arbeitest",src:"you work"},{pronoun:"er/sie/es",form:"arbeitet",src:"he/she/it works"},{pronoun:"wir",form:"arbeiten",src:"we work"},{pronoun:"ihr",form:"arbeitet",src:"you all work"},{pronoun:"sie/Sie",form:"arbeiten",src:"they/you (formal) work"}]}],note:"Verbs ending in -ten/-den add extra -e- in du/er/ihr forms for pronunciation: du arbeitest (not arbeitst)."},
{type:"teach",trg:"besetzt",src:"occupied, taken",note:"Past participle used as adjective.",example:"A: Ist der Platz besetzt?\nB: Ja, leider.",exampleSrc:"A: Is this seat taken?\nB: Yes, unfortunately.",funFact:"'Ist der Platz besetzt?' = Is this seat taken? If you do not ask, Germans will tell you anyway."},
{type:"teach",trg:"geschlossen",src:"closed",note:"Past participle of schließen (to close).",example:"A: Ist das Geschäft auf?\nB: Nein, es ist geschlossen.",exampleSrc:"A: Is the shop open?\nB: No, it is closed.",funFact:"You will see 'geschlossen' on every shop door on Sundays. Germany's Sonntagsruhe (Sunday rest) means most shops close. Bakeries sometimes open Sunday morning."},
{type:"teach",trg:"falsch",src:"wrong, false",note:"Adjective. Opposite of richtig.",example:"A: Ist das richtig?\nB: Nein, das ist falsch!",exampleSrc:"A: Is that correct?\nB: No, that is wrong!",funFact:"'Falsche Richtung!' = Wrong direction! Verumius hears this a lot on his Berlin adventures."},
{type:"teach",trg:"richtig",src:"right, correct",note:"Adjective. Opposite of falsch.",example:"A: Ist das richtig?\nB: Ja, richtig!",exampleSrc:"A: Is that correct?\nB: Yes, correct!",funFact:"'Richtig!' is how Germans say 'Exactly!' in conversation. Short, direct, affirming."},
{type:"mc",q:"Das Café ist ___. Alle Tische haben Leute.",opts:["besetzt","geschlossen","falsch","fremd"],ans:"besetzt",hint:"The cafe is not closed, it is full. Every table has people."},
{type:"teach",trg:"fremd",src:"foreign, strange, unfamiliar",note:"Adjective. Not negative, just unfamiliar.",example:"A: Ich bin fremd hier.\nB: Kein Problem, ich helfe dir!",exampleSrc:"A: I am a stranger here.\nB: No problem, I will help you!",funFact:"'Ich bin fremd hier' = I am a stranger here. Not negative. Just means unfamiliar with the place."},
{type:"teach",trg:"bekannt",src:"well-known, famous",note:"Adjective. Past participle of bekennen.",example:"A: Ist das Brandenburger Tor bekannt?\nB: Ja, es ist sehr bekannt!",exampleSrc:"A: Is the Brandenburg Gate well-known?\nB: Yes, it is very famous!",funFact:"'Das Brandenburger Tor ist bekannt.' The opposite of fremd in a way. Bekannt = known, fremd = unknown."},
{type:"teach",trg:"klar",src:"clear, obvious",note:"Adjective/adverb. 'Alles klar?' = All clear?",example:"A: Alles klar?\nB: Ja, alles klar!",exampleSrc:"A: Everything clear?\nB: Yes, all clear!",funFact:"'Alles klar?' = Everything clear? / All good? One of the most common German phrases. Use it constantly."},
{type:"teach",trg:"gleich",src:"same, equal; right away",note:"Two meanings! Context tells you which.",example:"A: Die Farben sind gleich.\nB: Ich komme gleich!",exampleSrc:"A: The colors are the same.\nB: I will be there right away!",funFact:"Two meanings! 'Das ist gleich' = that is the same. 'Ich komme gleich' = I am coming right away. Context decides."},
{type:"teach",trg:"spielen",src:"to play",note:"Regular verb. Spielplatz = playground.",example:"A: Was spielst du?\nB: Ich spiele Gitarre.",exampleSrc:"A: What do you play?\nB: I play guitar.",funFact:"Spielplatz = playground. Spielen covers both playing games and playing music. 'Klavier spielen' = to play piano."},
{type:"verb_table",title:"spielen (to play)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"spiele",src:"I play"},{pronoun:"du",form:"spielst",src:"you play"},{pronoun:"er/sie/es",form:"spielt",src:"he/she/it plays"},{pronoun:"wir",form:"spielen",src:"we play"},{pronoun:"ihr",form:"spielt",src:"you all play"},{pronoun:"sie/Sie",form:"spielen",src:"they/you (formal) play"}]}],note:"Regular pattern. Fußball spielen = to play football."},
{type:"teach",trg:"sitzen",src:"to sit (state)",note:"State verb: already sitting. Setzen = to sit down (action).",example:"A: Wo sitzt du?\nB: Ich sitze im Café.",exampleSrc:"A: Where are you sitting?\nB: I am sitting in the cafe.",funFact:"Sitzen = you ARE sitting (state). Setzen = you SIT DOWN (action). German distinguishes between the motion and the result."},
{type:"teach",trg:"liegen",src:"to lie, to be located",note:"State verb. Legen = to lay/put (action).",example:"A: Wo liegt Berlin?\nB: Berlin liegt an der Spree.",exampleSrc:"A: Where is Berlin located?\nB: Berlin is on the Spree river.",funFact:"Liegen = it is lying there (state). Legen = you lay it down (action). 'Berlin liegt an der Spree' = Berlin is situated on the Spree."},
{type:"mc",q:"Die Tür ist ___. Wir können nicht hinein.",opts:["geschlossen","besetzt","groß","richtig"],ans:"geschlossen",hint:"The door is shut. We cannot go in."},
{type:"fb",s:"Ich möchte etwas {1}.",a:["bestellen"],opts:["bestellen","bezahlen","bleiben","bringen"],hint:"You want to order something at a restaurant.",sSrc:"I would like to {1} something."},
{type:"mc",q:"'Alles klar?' means:",opts:["Everything clear?","Everything false?","Everything closed?","Everyone here?"],ans:"Everything clear?",hint:"Break this greeting into its two short parts and translate each."},
{type:"match",pairs:[{trg:"essen",src:"to eat"},{trg:"kaufen",src:"to buy"},{trg:"arbeiten",src:"to work"},{trg:"kochen",src:"to cook"},{trg:"bezahlen",src:"to pay"}]},
{type:"fb",s:"Ist der Platz {1}?",a:["besetzt"],opts:["besetzt","geschlossen","bekannt","fremd"],hint:"You want to know if the seat is taken.",sSrc:"Is the seat {1}?"},
{type:"tip",title:"Action vs State Verb Pairs",text:"German distinguishes between doing something and the result:\n\nlegen (to lay) vs liegen (it is lying)\nsetzen (to seat) vs sitzen (it is sitting)\nstellen (to place) vs stehen (it is standing)\n\nThe -e- verb is the ACTION. The -i- verb is the STATE."}
]},
// --- L6: Der Döner-Umweg (Story Climax) ---
{id:"deu_r2l6",title:"Der Döner-Umweg",icon:"\uD83C\uDF2F",xp:15,board:true,steps:[
{type:"intro",title:"Der Döner-Umweg",desc:"Verumius has been walking for an hour. He is hungry, lost, and his map is useless. Then he smells something incredible from a Döner stand by the Spree.",goals:["Learn travel and transport verbs","Navigate public transport in German","Discover Berlin's Döner culture"]},
{type:"teach",trg:"fahren",src:"to drive, to go by vehicle",note:"Irregular: ich fahre, du fährst, er fährt.",example:"A: Fährst du mit dem Bus?\nB: Nein, ich fahre mit der U-Bahn.",exampleSrc:"A: Are you going by bus?\nB: No, I am going by subway.",funFact:"The ä in fährst/fährt is a stem vowel change. Many common German verbs do this: schlafen to schläft, laufen to läuft."},
{type:"teach",trg:"nehmen",src:"to take",note:"Irregular: ich nehme, du nimmst, er nimmt.",example:"A: Welchen Zug nimmst du?\nB: Ich nehme den ICE nach Hamburg.",exampleSrc:"A: Which train are you taking?\nB: I am taking the ICE to Hamburg.",funFact:"Irregular: the e becomes i in du/er forms. 'Ich nehme den Bus' = I will take the bus. Essential for transit."},
{type:"verb_table",title:"nehmen (to take)",groups:[{label:"Present tense (stem change: e → i + consonant change)",rows:[{pronoun:"ich",form:"nehme",src:"I take"},{pronoun:"du",form:"nimmst",src:"you take"},{pronoun:"er/sie/es",form:"nimmt",src:"he/she/it takes"},{pronoun:"wir",form:"nehmen",src:"we take"},{pronoun:"ihr",form:"nehmt",src:"you all take"},{pronoun:"sie/Sie",form:"nehmen",src:"they/you (formal) take"}]}],note:"Double change: e → i AND h → mm. One of German's most irregular common verbs."},
{type:"teach",trg:"laufen",src:"to walk, to run",note:"Irregular: ich laufe, du läufst, er läuft.",example:"A: Laufen wir?\nB: Ja, der Bahnhof ist nicht weit.",exampleSrc:"A: Shall we walk?\nB: Yes, the station is not far.",funFact:"In northern Germany, laufen = to walk. In southern Germany, laufen = to run. Geography changes meaning!"},
{type:"verb_table",title:"laufen (to walk/run)",groups:[{label:"Present tense (stem change: au → äu)",rows:[{pronoun:"ich",form:"laufe",src:"I walk/run"},{pronoun:"du",form:"läufst",src:"you walk/run"},{pronoun:"er/sie/es",form:"läuft",src:"he/she/it walks/runs"},{pronoun:"wir",form:"laufen",src:"we walk/run"},{pronoun:"ihr",form:"lauft",src:"you all walk/run"},{pronoun:"sie/Sie",form:"laufen",src:"they/you (formal) walk/run"}]}],note:"au → äu in du/er forms. Northern Germany: walk. Southern Germany: run."},
{type:"teach",trg:"einsteigen",src:"to get in, to board",note:"Separable: Steigen Sie ein!",example:"A: Bitte einsteigen!\nB: Danke, ich steige ein.",exampleSrc:"A: Please board!\nB: Thanks, I am boarding.",funFact:"Separable: 'Steigen Sie ein!' = Board! Ein = in. You hear this on every platform: 'Bitte einsteigen, die Türen schließen!'"},
{type:"teach",trg:"aussteigen",src:"to get out, to exit",note:"Separable: Bitte aussteigen!",example:"A: Wir müssen hier aussteigen.\nB: Okay, ich steige aus.",exampleSrc:"A: We have to get out here.\nB: Okay, I am getting out.",funFact:"'Bitte aussteigen!' = Please exit! You hear this on every U-Bahn. Aus = out. Ein and aus are opposite prefixes."},
{type:"teach",trg:"umsteigen",src:"to transfer, to change trains",note:"Separable: Sie müssen umsteigen.",example:"A: Muss ich umsteigen?\nB: Ja, am Alexanderplatz.",exampleSrc:"A: Do I need to transfer?\nB: Yes, at Alexanderplatz.",funFact:"Um = around/change. 'Sie müssen am Alexanderplatz umsteigen' = You have to transfer at Alexanderplatz. A daily Berlin experience."},
{type:"teach",trg:"der Spaß",src:"fun",note:"Masculine noun. 'Das macht Spaß!' = That is fun!",example:"A: Macht Berlin Spaß?\nB: Ja, Berlin macht viel Spaß!",exampleSrc:"A: Is Berlin fun?\nB: Yes, Berlin is a lot of fun!",funFact:"'Das macht Spaß!' = That is fun! (literally 'That makes fun'). 'Viel Spaß!' = Have fun! Germans use 'machen' (to make) with fun, not 'haben' (to have)."},
{type:"teach",trg:"das Stück",src:"piece, item",note:"Neuter noun. 'Ein Stück Kuchen' = a piece of cake.",example:"A: Ein Stück, bitte!\nB: Hier, ein Stück Döner.",exampleSrc:"A: One piece, please!\nB: Here, one piece of Döner.",funFact:"'Ein Stück' is how you order at counters. 'Zwei Stück' for two pieces. At a bakery: 'Drei Stück Brötchen, bitte.'"},
{type:"teach",trg:"bekommen",src:"to get, to receive",note:"FALSE FRIEND! Not 'to become'!",example:"A: Ich bekomme einen Döner.\nB: Mit alles?",exampleSrc:"A: I am getting a Döner.\nB: With everything?",funFact:"FAMOUS FALSE FRIEND! 'Bekommen' does NOT mean 'to become.' 'Ich bekomme einen Döner' = I am GETTING a Döner, NOT 'I am becoming a Döner.'"},
{type:"teach",trg:"der Fluss",src:"the river",note:"Masculine noun. Berlin's river: die Spree.",example:"A: Ist das ein Fluss?\nB: Ja, das ist die Spree.",exampleSrc:"A: Is that a river?\nB: Yes, that is the Spree.",funFact:"Berlin's river is die Spree, but Fluss itself is masculine (der Fluss). The Spree flows through the heart of Berlin."},
{type:"teach",trg:"die Sonne",src:"the sun",note:"Feminine noun. 'Sonnenschein' = sunshine.",example:"A: Die Sonne scheint!\nB: Ja, endlich Sonne in Berlin!",exampleSrc:"A: The sun is shining!\nB: Yes, finally sun in Berlin!",funFact:"'Sonnenschein' = sunshine. Germans celebrate sun like it is a miracle. In Berlin, where grey skies dominate, a sunny day changes the whole city's mood."},
{type:"teach",trg:"der See",src:"the lake",note:"Masculine noun. But die See = the sea!",example:"A: Gehen wir zum See?\nB: Ja, der See ist schön.",exampleSrc:"A: Shall we go to the lake?\nB: Yes, the lake is beautiful.",funFact:"GENDER TRAP! der See = the lake. die See = the sea. Same word, different gender, different meaning! Berlin has many lakes (Seen) for summer swimming."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-doener-stand",trg:"Verumius steht am Döner-Stand an der Spree. Die Sonne scheint. Der Verkäufer fragt: 'Mit alles?' Verumius versteht nicht und sagt: 'Ja, ja!' Er bekommt einen riesigen Döner.",src:"Verumius stands at the Döner stand by the Spree. The sun is shining. The seller asks: 'With everything?' Verumius does not understand and says: 'Yes, yes!' He gets a massive Döner."},
{type:"mc",q:"'Ich bekomme einen Kaffee' means:",opts:["I am getting a coffee","I am becoming a coffee","I am buying a coffee","I am making a coffee"],ans:"I am getting a coffee",hint:"Bekommen is a famous false friend. It means 'to receive/get,' not 'to become.'"},
{type:"mc",q:"'der See' means ___, but 'die See' means ___.",opts:["the lake / the sea","the sea / the lake","the river / the lake","the lake / the river"],ans:"the lake / the sea",hint:"Same word, different gender = completely different meaning."},
{type:"fb",s:"Ich möchte {1}, bitte. Ein Stück.",a:["bestellen"],opts:["bestellen","bezahlen","bekommen","bleiben"],hint:"You want to place an order.",sSrc:"I would like {1}, please. One piece."},
{type:"mc",q:"You need to change trains. The announcement says:",opts:["Bitte umsteigen!","Bitte einsteigen!","Bitte aussteigen!","Bitte aufstehen!"],ans:"Bitte umsteigen!",hint:"'Um' means change/around. Which verb means to transfer?"},
{type:"fb",s:"Können Sie mir die {1} zum Bahnhof zeigen?",a:["Richtung"],opts:["Richtung","Kreuzung","Haltestelle","Ecke"],hint:"You are asking someone to show you the direction to the station.",sSrc:"Can you show me the {1} to the train station?"},
{type:"tip",title:"Döner Culture",text:"Germany eats about 720 million Döner Kebabs per year.\nBerlin alone has over 1,600 Döner shops.\nThe German Döner was invented in Berlin in the 1970s by Turkish immigrants.\nIt is now Germany's most popular fast food, ahead of burgers and pizza."}
]},
// --- L7: Alles zusammen! (Quiz) ---
{id:"deu_r2l7",title:"Alles zusammen!",icon:"\uD83C\uDFC6",xp:20,board:true,steps:[
{type:"intro",title:"Alles zusammen!",desc:"Time to test everything: directions, articles, places, adjectives, and verbs. Show what you have learned in Unit 2!",goals:["Test all Unit 2 vocabulary","Demonstrate article mastery","Apply direction and place knowledge"]},
{type:"teach",trg:"abfahren",src:"to depart (vehicle)",note:"Separable: Der Zug fährt um 10 Uhr ab.",example:"A: Wann fährt der Zug ab?\nB: Der Zug fährt um zehn ab.",exampleSrc:"A: When does the train depart?\nB: The train departs at ten.",funFact:"Separable: 'Der Zug fährt um 10 Uhr ab.' Ab = away/off. The 'ab' flies to the end of the sentence."},
{type:"teach",trg:"ankommen",src:"to arrive",note:"Separable: Wann kommen Sie an?",example:"A: Wann kommst du an?\nB: Ich komme um drei an.",exampleSrc:"A: When do you arrive?\nB: I arrive at three.",funFact:"Separable: 'Wann kommen Sie an?' = When do you arrive? An = at. Arrival is literally 'coming at' a place."},
{type:"teach",trg:"besuchen",src:"to visit",note:"Inseparable prefix verb. Be- verbs never separate.",example:"A: Ich besuche das Museum.\nB: Welches Museum?",exampleSrc:"A: I am visiting the museum.\nB: Which museum?",funFact:"Inseparable: be- prefix verbs NEVER separate. 'Ich besuche' stays together. For sightseeing, use besichtigen. For people, use besuchen."},
{type:"teach",trg:"fliegen",src:"to fly",note:"Irregular. Past: flog.",example:"A: Fliegst du nach Berlin?\nB: Ja, ich fliege morgen.",exampleSrc:"A: Are you flying to Berlin?\nB: Yes, I am flying tomorrow.",funFact:"Fliegen, Flug, Flughafen, Flugzeug: the Flug- family covers everything airborne. All from the same root meaning 'to fly.'"},
{type:"teach",trg:"gefallen",src:"to please, to like",note:"The thing you like is the SUBJECT. Dative construction.",example:"A: Berlin gefällt mir!\nB: Mir auch!",exampleSrc:"A: I like Berlin! (Berlin pleases me!)\nB: Me too!",funFact:"'Berlin gefällt mir!' = Berlin pleases me! = I like Berlin. The thing you like is the SUBJECT. This is backwards from English."},
{type:"teach",trg:"schließen",src:"to close",note:"Irregular. Past participle: geschlossen.",example:"A: Das Museum schließt um 18 Uhr.\nB: Dann müssen wir uns beeilen!",exampleSrc:"A: The museum closes at 6 PM.\nB: Then we need to hurry!",funFact:"Formal version of 'zumachen.' 'Das Museum schließt' = the museum closes. 'Geschlossen' = closed (adjective)."},
{type:"teach",trg:"gern(e)",src:"gladly, with pleasure",note:"Added after a verb to mean 'like doing.'",example:"A: Ich laufe gern.\nB: Ich auch! Berlin ist toll zum Laufen.",exampleSrc:"A: I like walking.\nB: Me too! Berlin is great for walking.",funFact:"Verb + gern = enjoy doing. 'Ich laufe gern' = I like to walk. 'Ich koche gern' = I like to cook. Simple and powerful."},
{type:"teach",trg:"leider",src:"unfortunately",note:"Adverb. Used constantly in German.",example:"A: Kommst du mit?\nB: Leider nein, ich muss arbeiten.",exampleSrc:"A: Are you coming along?\nB: Unfortunately no, I have to work.",funFact:"'Leider nein' = Unfortunately no. Germans use this constantly. It softens a rejection without being rude."},
{type:"teach",trg:"trinken",src:"to drink",note:"Irregular past (trank), but regular present.",example:"A: Was möchten Sie trinken?\nB: Einen Kaffee, bitte.",exampleSrc:"A: What would you like to drink?\nB: A coffee, please.",funFact:"'Trinkgeld' = tip (literally 'drink money'). In Germany, tips are usually 5-10% of the bill, rounded up."},
{type:"verb_table",title:"trinken (to drink)",groups:[{label:"Present tense (regular)",rows:[{pronoun:"ich",form:"trinke",src:"I drink"},{pronoun:"du",form:"trinkst",src:"you drink"},{pronoun:"er/sie/es",form:"trinkt",src:"he/she/it drinks"},{pronoun:"wir",form:"trinken",src:"we drink"},{pronoun:"ihr",form:"trinkt",src:"you all drink"},{pronoun:"sie/Sie",form:"trinken",src:"they/you (formal) drink"}]}],note:"Regular in present tense. Was trinken Sie? = What are you drinking?"},
{type:"mc",q:"Wie komme ich zum Bahnhof? ___ und dann ___.",opts:["Geradeaus ... links","Links ... geradeaus","Rechts ... Süden","Norden ... rechts"],ans:"Geradeaus ... links",hint:"The most common direction pattern: straight ahead, then turn."},
{type:"mc",q:"Das ist ___ Kirche.",opts:["eine","ein","einer","eines"],ans:"eine",hint:"Kirche is feminine (die Kirche). What is the feminine indefinite article?"},
{type:"fb",s:"{1} Museum ist sehr bekannt.",a:["Das"],opts:["Das","Der","Die","Ein"],hint:"Museum is neuter. Which definite article?",sSrc:"{1} museum is very well-known."},
{type:"mc",q:"Die Straße ist ___. (long)",opts:["lang","lange","langer","langes"],ans:"lang",hint:"After 'ist,' adjectives have NO ending. Base form only."},
{type:"mc",q:"In 'Der Mann sucht den Bahnhof,' who is performing the action?",opts:["The man","The station","The verb","The article"],ans:"The man",hint:"The subject DOES the action. Which case is nominative here?"},
{type:"match",pairs:[{trg:"geradeaus",src:"straight ahead"},{trg:"die Kreuzung",src:"intersection"},{trg:"umsteigen",src:"to transfer"},{trg:"geschlossen",src:"closed"},{trg:"ankommen",src:"to arrive"},{trg:"leider",src:"unfortunately"}]},
{type:"mc",q:"'Berlin gefällt mir' means:",opts:["I like Berlin","Berlin falls down","I feel Berlin","Berlin is gone"],ans:"I like Berlin",hint:"Gefallen = to please. The subject does the pleasing, not the experiencing."},
{type:"fb",s:"Ich fliege {1} Berlin.",a:["nach"],opts:["nach","zu","bei","an"],hint:"For traveling TO cities and countries, which preposition do you use?",sSrc:"I am flying {1} Berlin."},
{type:"drag_fill",s:"Entschuldigung, {1} ist {2} Apotheke? Ich {3} Medizin.",blanks:{"1":"wo","2":"die","3":"brauche"},pool:["wo","die","brauche","wohin","der","kaufe"],hint:"Where (location) is the (feminine) pharmacy? I need medicine.",sSrc:"Excuse me, {1} is {2} pharmacy? I {3} medicine."},
{type:"mc",q:"Which compound noun is NEUTER?",opts:["das Rathaus","der Parkplatz","die Innenstadt","der Stadtplan"],ans:"das Rathaus",hint:"Compound nouns take the gender of the LAST word."}
]},
// --- L8: Morgen versuche ich es nochmal (Resolution) ---
{id:"deu_r2l8",title:"Morgen versuche ich es nochmal",icon:"\uD83C\uDF07",xp:15,board:true,steps:[
{type:"intro",title:"Morgen versuche ich es nochmal",desc:"Day 1 in Berlin is ending. The Bürgeramt? Not found. But Verumius discovered something better: the art of being lost in Berlin.",goals:["Learn sondern vs aber","Master denn as conjunction","Reflect on Unit 2 vocabulary"]},
{type:"teach",trg:"sondern",src:"but rather (after negation)",note:"ONLY follows nicht/kein. Corrects a negative.",example:"A: Das ist nicht die Bank.\nB: Nein, sondern die Apotheke!",exampleSrc:"A: That is not the bank.\nB: No, but rather the pharmacy!",funFact:"'Nicht das Bürgeramt, sondern der Döner-Stand.' Sondern ONLY follows a negation. Aber = but (general). Sondern = but RATHER (correcting)."},
{type:"teach",trg:"die Idee",src:"the idea",note:"Feminine noun. From Greek via French.",example:"A: Ich habe eine Idee!\nB: Was für eine Idee?",exampleSrc:"A: I have an idea!\nB: What kind of idea?",funFact:"Same root as English 'idea.' German borrowed it from Greek via French. Die Idee is always feminine."},
{type:"teach",trg:"die Sache",src:"the thing, matter",note:"Feminine noun. More formal than 'Ding.'",example:"A: Das ist meine Sache.\nB: Okay, ich frage nicht mehr.",exampleSrc:"A: That is my business.\nB: Okay, I will not ask again.",funFact:"'Das ist meine Sache' = That is my business/matter. More formal than 'Ding' (thing). 'Tatsache' = fact (literally 'deed-thing')."},
{type:"tip",title:"Aber vs Sondern",text:"Aber = but (general contrast):\nDas Hotel ist klein, aber schön.\n\nSondern = but rather (corrects a negation):\nDas ist nicht die Bank, sondern die Apotheke.\n\nRule: If there is 'nicht' or 'kein' before 'but,' use sondern.\nOtherwise, use aber."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-spree-sunset",trg:"Sonnenuntergang an der Spree. Verumius sitzt auf einer Bank. Döner-Reste, ein nutzloser Stadtplan und ein Lächeln. Nicht das Bürgeramt, sondern den besten Döner in Berlin gefunden.",src:"Sunset on the Spree. Verumius sits on a bench. Döner remains, a useless city map, and a smile. Not the Bürgeramt, but the best Döner in Berlin found."},
{type:"mc",q:"Das ist nicht die Bank, ___ die Apotheke.",opts:["sondern","aber","denn","und"],ans:"sondern",hint:"After a negation (nicht), which 'but' corrects the statement?"},
{type:"tip",title:"Denn: Two Lives",text:"Particle in questions: 'Was ist denn das?' (adds curiosity)\n\nConjunction meaning 'because/for':\n'Ich gehe ins Café, denn ich bin müde.'\n\nYou learned the particle earlier. Now you know the conjunction too."},
{type:"mc",q:"Ich gehe zum Bahnhof, ___ ich fahre nach München.",opts:["denn","sondern","aber","dann"],ans:"denn",hint:"You are giving the REASON (because) you are going to the station."},
{type:"fb",s:"Das Museum ist nicht klein, {1} groß.",a:["sondern"],opts:["sondern","aber","denn","und"],hint:"After 'nicht' plus correcting = which conjunction?",sSrc:"The museum is not small, {1} big."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-berlin-montage",trg:"Ein Tag in Berlin: der falsche Stadtplan, die rote Ampel, der beste Döner. Verumius sagt: 'Morgen versuche ich es nochmal. Berlin gefällt mir.'",src:"One day in Berlin: the wrong map, the red traffic light, the best Döner. Verumius says: 'Tomorrow I will try again. I like Berlin.'"},
{type:"tip",title:"Berlin Survival Guide",text:"What Verumius learned today:\n\nKönnen Sie mir helfen? = Can you help me?\nEntschuldigung, wo ist...? = Excuse me, where is...?\nGeradeaus, dann links/rechts = Straight, then left/right\nNEVER cross on red (social death)\n'Mit alles?' at the Döner stand = With everything?\nDöner is always a good decision."},
{type:"mc",q:"'Berlin gefällt mir' uses which pattern?",opts:["The thing you like is the subject","The person who likes is the subject","Gefallen needs accusative","Berlin is the object"],ans:"The thing you like is the subject",hint:"Berlin does the 'pleasing.' Berlin is the subject in nominative."},
{type:"match",pairs:[{trg:"sondern",src:"but rather (after negation)"},{trg:"denn",src:"because, for"},{trg:"die Idee",src:"idea"},{trg:"die Sache",src:"thing, matter"},{trg:"gefallen",src:"to please, to like"}]},
{type:"tip",title:"Gender Cheat Sheet: Unit 2",text:"-ung = die (Richtung, Kreuzung, Verbindung, Öffnungszeit)\n-ei = die (Bäckerei)\n-e = usually die (Straße, Brücke, Kirche, Ecke, Sonne)\n-chen = das (coming in Unit 3!)\nCompound nouns = gender of LAST word\nLatin/Greek loans = often das (Hotel, Café, Museum, Kino)\nder See = lake, die See = sea (the ultimate trap)"},
{type:"fb",s:"Berlin {1} mir!",a:["gefällt"],opts:["gefällt","gefallt","gefalle","gefällst"],hint:"Berlin is singular (it). What ending does gefallen get for er/sie/es?",sSrc:"Berlin {1} me!"},
{type:"mc",q:"Which sentence uses 'sondern' correctly?",opts:["Ich trinke nicht Tee, sondern Kaffee.","Das Hotel ist groß, sondern teuer.","Ich gehe sondern zum Markt.","Die Sonne sondern scheint."],ans:"Ich trinke nicht Tee, sondern Kaffee.",hint:"This conjunction corrects a negation. Look for nicht/kein before it."},
{type:"story",speaker:"narrator",mood:"excited",art:"de-berlin-night",trg:"Verumius geht nach Hause. Morgen: das Bürgeramt. Deutsche Bürokratie wartet. Formulare, Wartenummern und das Wort 'Formular' werden ihn verfolgen. Aber heute: Gute Nacht, Berlin.",src:"Verumius walks home. Tomorrow: the Bürgeramt. German bureaucracy awaits. Forms, queue numbers, and the word 'Formular' will haunt him. But tonight: Good night, Berlin."}
]}

,

{id:"deu_r2l9",title:"Kleine Wörter, große Wirkung",icon:"💡",xp:15,board:true,steps:[
{type:"intro",title:"Kleine Wörter, große Wirkung",desc:"Small words with big impact! Learn essential adverbs, connectors, and prepositions that glue German sentences together.",goals:["Learn 20 essential adverbs, prepositions, and connectors","Use time words like jetzt, bald, schon in sentences","Navigate conversations with auf, durch, über, vor"]},
{type:"teach",trg:"bald",src:"soon",note:"Adverb of time. Very common in everyday speech.",example:"A: Wann kommt der Bus?\nB: Er kommt bald.",exampleSrc:"A: When does the bus come?\nB: It comes soon.",funFact:"Germans say 'Bis bald!' (See you soon!) as a casual goodbye."},
{type:"teach",trg:"dann",src:"then",note:"Adverb. Used to sequence events or actions.",example:"A: Zuerst gehen wir ins Museum.\nB: Und dann?\nA: Dann essen wir Pizza.",exampleSrc:"A: First we go to the museum.\nB: And then?\nA: Then we eat pizza.",funFact:"Dann is one of the top 50 most frequent German words."},
{type:"teach",trg:"immer",src:"always",note:"Adverb of frequency. Opposite: nie (never).",example:"A: Fährst du immer mit dem Bus?\nB: Ja, ich fahre immer mit dem Bus.",exampleSrc:"A: Do you always take the bus?\nB: Yes, I always take the bus.",funFact:"'Immer geradeaus' (always straight ahead) is the most common direction you will hear in Germany."},
{type:"teach",trg:"jetzt",src:"now",note:"Adverb of time. Emphasizes the present moment.",example:"A: Wann gehen wir?\nB: Jetzt! Komm!",exampleSrc:"A: When do we go?\nB: Now! Come!",funFact:"In southern Germany and Austria, people often say 'jetzt' as 'jetz' or even 'etz'."},
{type:"teach",trg:"nie",src:"never",note:"Adverb of frequency. Opposite: immer (always).",example:"A: Fährst du mit dem Taxi?\nB: Nein, ich fahre nie mit dem Taxi.",exampleSrc:"A: Do you take the taxi?\nB: No, I never take the taxi.",funFact:"The phrase 'nie wieder' (never again) is used for strong emphasis."},
{type:"teach",trg:"noch",src:"still, yet",note:"Adverb. Context changes meaning: noch = still, noch nicht = not yet.",example:"A: Bist du noch im Hotel?\nB: Ja, ich bin noch hier.",exampleSrc:"A: Are you still at the hotel?\nB: Yes, I am still here.",funFact:"'Noch ein Bier, bitte!' (Another beer, please!) is a survival phrase in Germany."},
{type:"teach",trg:"nur",src:"only",note:"Adverb. Limits or restricts what follows.",example:"A: Wie viel kostet das?\nB: Nur zwei Euro.",exampleSrc:"A: How much does that cost?\nB: Only two euros.",funFact:"Nur is related to English 'narrow'. Both come from the idea of restriction."},
{type:"teach",trg:"oft",src:"often",note:"Adverb of frequency. Between immer and manchmal.",example:"A: Gehst du oft ins Kino?\nB: Ja, ich gehe oft ins Kino.",exampleSrc:"A: Do you go to the cinema often?\nB: Yes, I go to the cinema often.",funFact:"The comparative form is 'öfter' (more often), with an umlaut."},
{type:"teach",trg:"schon",src:"already",note:"Adverb. Can also express surprise or reassurance.",example:"A: Ist der Zug schon da?\nB: Ja, er ist schon am Gleis.",exampleSrc:"A: Is the train already there?\nB: Yes, it is already at the platform.",funFact:"'Schon gut' means 'it is alright' and is used to reassure someone."},
{type:"teach",trg:"sofort",src:"immediately",note:"Adverb. Stronger than 'bald' (soon).",example:"A: Wann kann ich das Zimmer haben?\nB: Sofort! Es ist fertig.",exampleSrc:"A: When can I have the room?\nB: Immediately! It is ready.",funFact:"German bureaucrats love this word. 'Sofortige Maßnahmen' means immediate measures."},
{type:"teach",trg:"vielleicht",src:"perhaps, maybe",note:"Adverb. Softens statements and suggestions.",example:"A: Gehen wir ins Museum?\nB: Ja, vielleicht am Nachmittag.",exampleSrc:"A: Shall we go to the museum?\nB: Yes, perhaps in the afternoon.",funFact:"Vielleicht literally breaks down to 'viel' (much) + 'leicht' (easy/light), meaning 'easily possible'."},
{type:"teach",trg:"wieder",src:"again",note:"Adverb. Indicates repetition.",example:"A: Der Bus ist weg!\nB: Kein Problem. Er kommt wieder.",exampleSrc:"A: The bus is gone!\nB: No problem. It comes again.",funFact:"'Auf Wiedersehen' literally means 'until seeing again'. It is the formal goodbye."},
{type:"teach",trg:"an",src:"on, at (a surface or location)",note:"Preposition. Used for surfaces and specific locations.",example:"A: Wo ist die Karte?\nB: Sie ist an der Wand.",exampleSrc:"A: Where is the map?\nB: It is on the wall.",funFact:"An der Haltestelle (at the bus stop) is one of the most common uses of 'an'."},
{type:"teach",trg:"auf",src:"on, upon, on top of",note:"Preposition. Used for horizontal surfaces.",example:"A: Wo ist mein Handy?\nB: Es ist auf dem Tisch.",exampleSrc:"A: Where is my phone?\nB: It is on the table.",funFact:"'Auf Deutsch' means 'in German'. You use 'auf' for languages."},
{type:"teach",trg:"durch",src:"through",note:"Preposition. Always takes accusative case.",example:"A: Wie komme ich zum Park?\nB: Gehen Sie durch die Straße.",exampleSrc:"A: How do I get to the park?\nB: Go through the street.",funFact:"A 'Durchgang' (throughway) combines durch + Gang (walk). Very logical!"},
{type:"teach",trg:"gegen",src:"against, around (time)",note:"Preposition. Also used for approximate times: gegen 8 Uhr.",example:"A: Wann kommst du?\nB: Gegen drei Uhr.",exampleSrc:"A: When are you coming?\nB: Around three o'clock.",funFact:"'Dagegen' (against it) is a common compound. Germans love stacking prepositions onto words."},
{type:"teach",trg:"über",src:"over, about, across",note:"Preposition. 'Über' also means 'about' a topic.",example:"A: Wie komme ich zum Museum?\nB: Gehen Sie über die Brücke.",exampleSrc:"A: How do I get to the museum?\nB: Go over the bridge.",funFact:"The English word 'uber' (as in uber-cool) comes directly from German über."},
{type:"teach",trg:"vor",src:"before, in front of",note:"Preposition. Time: vor einer Stunde (an hour ago). Place: vor dem Haus.",example:"A: Wo treffen wir uns?\nB: Vor dem Bahnhof.",exampleSrc:"A: Where do we meet?\nB: In front of the train station.",funFact:"'Vorgestern' means 'the day before yesterday'. Vor + gestern = before yesterday."},
{type:"teach",trg:"ab",src:"from (a point in time or place)",note:"Preposition. Marks a starting point: ab Montag (from Monday).",example:"A: Ab wann ist das Museum offen?\nB: Ab neun Uhr.",exampleSrc:"A: From when is the museum open?\nB: From nine o'clock.",funFact:"At airports, 'Abflug' (departure) uses 'ab' (away) + 'Flug' (flight)."},
{type:"teach",trg:"breit",src:"wide, broad",note:"Adjective. Opposite: schmal (narrow).",example:"A: Ist die Straße breit?\nB: Ja, sie ist sehr breit.",exampleSrc:"A: Is the street wide?\nB: Yes, it is very wide.",funFact:"The Kurfürstendamm in Berlin is one of the broadest avenues in Europe."},
{type:"mc",q:"What does 'vielleicht' mean?",opts:["perhaps","always","never","soon"],ans:"perhaps",hint:"Think of a word that expresses uncertainty."},
{type:"fb",s:"Der Zug kommt {1}. Wir müssen warten.",a:["bald"],opts:["bald","nie","schon","wieder"],hint:"The train is arriving in the near future.",sSrc:"The train comes {1}. We have to wait."},
{type:"mc",q:"'Gehen Sie über die Brücke.' What does 'über' mean here?",opts:["over","under","next to","behind"],ans:"over",hint:"You cross something from one side to the other."},
{type:"match",pairs:[{trg:"jetzt",src:"now"},{trg:"immer",src:"always"},{trg:"oft",src:"often"},{trg:"nie",src:"never"},{trg:"noch",src:"still"}]}
]},

{id:"deu_r2l10",title:"Wo ist das?",icon:"📍",xp:15,board:true,steps:[
{type:"intro",title:"Wo ist das?",desc:"Verumius needs to find his way around Berlin. Learn the names of places you will encounter in any German city.",goals:["Learn 18 city places and location nouns","Ask and answer 'Where is...?' questions","Navigate with confidence using place vocabulary"]},
{type:"teach",trg:"die Bäckerei",src:"the bakery",note:"Feminine noun. Plural: die Bäckereien.",example:"A: Wo ist die Bäckerei?\nB: Die Bäckerei ist um die Ecke.",exampleSrc:"A: Where is the bakery?\nB: The bakery is around the corner.",funFact:"Germany has over 10,000 bakeries. Fresh Brötchen (rolls) every morning is a national tradition."},
{type:"teach",trg:"der Bahnsteig",src:"the platform",note:"Masculine noun. Plural: die Bahnsteige. Bahn (railway) + Steig (path).",example:"A: Von welchem Bahnsteig fährt der Zug?\nB: Von Bahnsteig drei.",exampleSrc:"A: From which platform does the train leave?\nB: From platform three.",funFact:"German train stations announce 'Vorsicht am Bahnsteig!' (Caution at the platform!) before every train."},
{type:"teach",trg:"der Ausgang",src:"the exit",note:"Masculine noun. Plural: die Ausgänge. Aus (out) + Gang (way).",example:"A: Wo ist der Ausgang?\nB: Der Ausgang ist dort links.",exampleSrc:"A: Where is the exit?\nB: The exit is there on the left.",funFact:"Green 'Ausgang' signs are everywhere in Germany. They follow strict EU safety rules."},
{type:"teach",trg:"der Eingang",src:"the entrance",note:"Masculine noun. Plural: die Eingänge. Ein (in) + Gang (way).",example:"A: Ist das der Eingang?\nB: Nein, der Eingang ist auf der anderen Seite.",exampleSrc:"A: Is that the entrance?\nB: No, the entrance is on the other side.",funFact:"Eingang and Ausgang are perfect opposites: Ein (in) vs. Aus (out) + Gang (way)."},
{type:"teach",trg:"das Geschäft",src:"the shop, the business",note:"Neuter noun. Plural: die Geschäfte.",example:"A: Ist das Geschäft noch offen?\nB: Ja, bis acht Uhr.",exampleSrc:"A: Is the shop still open?\nB: Yes, until eight o'clock.",funFact:"On Sundays, almost all Geschäfte in Germany are closed. It is the law!"},
{type:"teach",trg:"die Haltestelle",src:"the stop, the station",note:"Feminine noun. Plural: die Haltestellen. Halte (hold/stop) + Stelle (place).",example:"A: Wo ist die Haltestelle?\nB: Die Haltestelle ist vor dem Hotel.",exampleSrc:"A: Where is the bus stop?\nB: The bus stop is in front of the hotel.",funFact:"Every Haltestelle in Germany has a name. Locals navigate by stop names, not street numbers."},
{type:"teach",trg:"der Kindergarten",src:"the kindergarten",note:"Masculine noun. Plural: die Kindergärten. Kinder (children) + Garten (garden).",example:"A: Wo ist der Kindergarten?\nB: Er ist neben der Schule.",exampleSrc:"A: Where is the kindergarten?\nB: It is next to the school.",funFact:"English borrowed this word directly from German! It literally means 'children's garden'."},
{type:"teach",trg:"der Kiosk",src:"the kiosk",note:"Masculine noun. Plural: die Kioske.",example:"A: Kann ich dort eine Zeitung kaufen?\nB: Ja, am Kiosk.",exampleSrc:"A: Can I buy a newspaper there?\nB: Yes, at the kiosk.",funFact:"German kiosks sell newspapers, snacks, cigarettes, and transit tickets. They are mini convenience stores."},
{type:"teach",trg:"der Laden",src:"the shop, the store",note:"Masculine noun. Plural: die Läden. More casual than Geschäft.",example:"A: Kennst du den Laden?\nB: Ja, der Laden ist sehr gut.",exampleSrc:"A: Do you know the shop?\nB: Yes, the shop is very good.",funFact:"'Laden' originally meant 'a shutter or plank', because shops used to have wooden shutters you opened for business."},
{type:"teach",trg:"das Lokal",src:"the restaurant, the pub",note:"Neuter noun. Plural: die Lokale. A casual place to eat or drink.",example:"A: Gibt es hier ein gutes Lokal?\nB: Ja, das Lokal am Platz ist super.",exampleSrc:"A: Is there a good restaurant here?\nB: Yes, the restaurant at the square is great.",funFact:"A 'Stammlokal' is a local pub where regulars always go. Very important in German culture!"},
{type:"teach",trg:"der Ort",src:"the place, the town",note:"Masculine noun. Plural: die Orte.",example:"A: Was für ein Ort ist das?\nB: Das ist ein kleiner Ort in Bayern.",exampleSrc:"A: What kind of place is that?\nB: That is a small town in Bavaria.",funFact:"Many German town names end in -burg (castle), -dorf (village), or -heim (home)."},
{type:"teach",trg:"der Platz",src:"the square, the seat",note:"Masculine noun. Plural: die Plätze. Both a city square and a seat.",example:"A: Ist dieser Platz frei?\nB: Ja, bitte setzen Sie sich.",exampleSrc:"A: Is this seat free?\nB: Yes, please sit down.",funFact:"Alexanderplatz in Berlin is one of Germany's most famous squares, often just called 'Alex'."},
{type:"teach",trg:"die Praxis",src:"the doctor's office",note:"Feminine noun. Plural: die Praxen.",example:"A: Wo ist die Praxis?\nB: Die Praxis ist im zweiten Stock.",exampleSrc:"A: Where is the doctor's office?\nB: The doctor's office is on the second floor.",funFact:"In Germany, most doctors have their own Praxis (private practice) rather than working in hospitals."},
{type:"teach",trg:"das Schwimmbad",src:"the swimming pool",note:"Neuter noun. Plural: die Schwimmbäder. Schwimmen (swim) + Bad (bath).",example:"A: Gehen wir ins Schwimmbad?\nB: Ja, gute Idee!",exampleSrc:"A: Shall we go to the swimming pool?\nB: Yes, good idea!",funFact:"Germany has over 6,000 public Schwimmbäder. Many towns have both indoor (Hallenbad) and outdoor (Freibad) pools."},
{type:"teach",trg:"die Sehenswürdigkeit",src:"the sight, the attraction",note:"Feminine noun. Plural: die Sehenswürdigkeiten. A famously long German word!",example:"A: Was ist die beste Sehenswürdigkeit?\nB: Das Brandenburger Tor!",exampleSrc:"A: What is the best attraction?\nB: The Brandenburg Gate!",funFact:"Sehenswürdigkeit has 19 letters. It breaks down to sehen (see) + würdig (worthy) + keit (suffix). Literally: a thing worthy of seeing."},
{type:"teach",trg:"die Mitte",src:"the middle, the center",note:"Feminine noun. No common plural form.",example:"A: Wo liegt das Hotel?\nB: In der Mitte der Stadt.",exampleSrc:"A: Where is the hotel?\nB: In the center of the city.",funFact:"Berlin-Mitte is the central district of Berlin, home to the Reichstag and Museum Island."},
{type:"teach",trg:"die Achtung",src:"attention, caution",note:"Feminine noun. Very common in announcements.",example:"A: Achtung! Der Zug kommt.\nB: Danke für die Warnung!",exampleSrc:"A: Attention! The train is coming.\nB: Thanks for the warning!",funFact:"You will hear 'Achtung!' in every German train station. It is the universal warning word."},
{type:"teach",trg:"die Information",src:"the information",note:"Feminine noun. Plural: die Informationen. Also an information desk.",example:"A: Wo ist die Information?\nB: Die Information ist am Eingang.",exampleSrc:"A: Where is the information desk?\nB: The information desk is at the entrance.",funFact:"Germans often abbreviate this to 'Info'. 'Die Info-Tafel' is the information board."},
{type:"mc",q:"What does 'die Haltestelle' mean?",opts:["the bus stop","the bakery","the exit","the entrance"],ans:"the bus stop",hint:"Think of a place where vehicles pause to let people on and off."},
{type:"fb",s:"Wo ist der {1}? Ich möchte rausgehen.",a:["Ausgang"],opts:["Ausgang","Eingang","Platz","Laden"],hint:"You want to leave, so you need the way out.",sSrc:"Where is the {1}? I want to go outside."},
{type:"mc",q:"Verumius asks: 'Ist dieser Platz frei?' What is he asking about?",opts:["a seat","a shop","a bakery","a platform"],ans:"a seat",hint:"This word has two meanings. Here, someone wants to sit down in a specific spot."},
{type:"match",pairs:[{trg:"die Bäckerei",src:"bakery"},{trg:"der Kindergarten",src:"kindergarten"},{trg:"das Schwimmbad",src:"swimming pool"},{trg:"die Praxis",src:"doctor's office"},{trg:"die Mitte",src:"center"}]}
]},

{id:"deu_r2l11",title:"Unterwegs",icon:"🚌",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs",desc:"Verumius is navigating Berlin's famous transit system. Learn words for transport, directions, and getting around the city.",goals:["Learn 20 transport and direction words","Use compass directions: Norden, Süden, Osten, Westen","Understand contractions like am and ins"]},
{type:"teach",trg:"der Anschluss",src:"the connection (transit)",note:"Masculine noun. Plural: die Anschlüsse. A connecting train or bus.",example:"A: Habe ich Anschluss nach München?\nB: Ja, der Anschluss ist in zehn Minuten.",exampleSrc:"A: Do I have a connection to Munich?\nB: Yes, the connection is in ten minutes.",funFact:"Missing your Anschluss is a real fear for German commuters. The phrase is 'den Anschluss verpassen'."},
{type:"teach",trg:"die Autobahn",src:"the highway, the motorway",note:"Feminine noun. Plural: die Autobahnen. Auto (car) + Bahn (way).",example:"A: Fahren wir über die Autobahn?\nB: Ja, das ist schneller.",exampleSrc:"A: Are we taking the highway?\nB: Yes, that is faster.",funFact:"Some sections of the German Autobahn have no speed limit. The recommended speed is 130 km/h."},
{type:"teach",trg:"die Bahn",src:"the railway, the train",note:"Feminine noun. Plural: die Bahnen. Short for Eisenbahn (iron way).",example:"A: Fährst du mit der Bahn?\nB: Ja, ich fahre mit der Bahn nach Hamburg.",exampleSrc:"A: Are you going by train?\nB: Yes, I am going by train to Hamburg.",funFact:"Deutsche Bahn (DB) is Germany's national railway. Germans love to joke about its delays."},
{type:"teach",trg:"der Fahrer",src:"the driver",note:"Masculine noun. Plural: die Fahrer. From fahren (to drive).",example:"A: Wer ist der Fahrer?\nB: Der Fahrer heißt Thomas.",exampleSrc:"A: Who is the driver?\nB: The driver's name is Thomas.",funFact:"A 'Busfahrer' is a bus driver, a 'Taxifahrer' is a taxi driver. German loves compound nouns!"},
{type:"teach",trg:"das Fahrrad",src:"the bicycle",note:"Neuter noun. Plural: die Fahrräder. Fahr (drive/ride) + Rad (wheel).",example:"A: Hast du ein Fahrrad?\nB: Ja, ich fahre jeden Tag mit dem Fahrrad.",exampleSrc:"A: Do you have a bicycle?\nB: Yes, I ride my bicycle every day.",funFact:"Germany has over 75,000 km of bike paths. Many cities have more cyclists than drivers."},
{type:"teach",trg:"das Gleis",src:"the track, the platform",note:"Neuter noun. Plural: die Gleise. Used at train stations.",example:"A: Von welchem Gleis fährt der Zug?\nB: Von Gleis fünf.",exampleSrc:"A: From which track does the train leave?\nB: From track five.",funFact:"Gleis and Bahnsteig both refer to platforms, but Gleis focuses on the track number."},
{type:"teach",trg:"der Lkw",src:"the truck",note:"Masculine noun. Short for Lastkraftwagen (load-power-vehicle).",example:"A: Was ist das?\nB: Das ist ein großer Lkw.",exampleSrc:"A: What is that?\nB: That is a big truck.",funFact:"Lastkraftwagen has 15 letters. No wonder Germans abbreviate it to Lkw!"},
{type:"teach",trg:"die S-Bahn",src:"the city train, the commuter rail",note:"Feminine noun. S stands for Schnell (fast) or Stadt (city).",example:"A: Nehmen wir die S-Bahn?\nB: Ja, die S-Bahn ist schneller als der Bus.",exampleSrc:"A: Shall we take the S-Bahn?\nB: Yes, the S-Bahn is faster than the bus.",funFact:"Berlin's S-Bahn ring (Ringbahn) goes in a circle around the city. Locals call it 'der Ring'."},
{type:"teach",trg:"die Straßenbahn",src:"the tram, the streetcar",note:"Feminine noun. Plural: die Straßenbahnen. Straße (street) + Bahn (way).",example:"A: Fährt hier eine Straßenbahn?\nB: Ja, die Straßenbahn kommt alle zehn Minuten.",exampleSrc:"A: Does a tram run here?\nB: Yes, the tram comes every ten minutes.",funFact:"Berlin removed its trams in the west during the Cold War but kept them in the east. They are back everywhere now."},
{type:"teach",trg:"der Norden",src:"the north",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt Hamburg?\nB: Hamburg liegt im Norden.",exampleSrc:"A: Where is Hamburg?\nB: Hamburg is in the north.",funFact:"Northern Germany (Norddeutschland) is flat and windy. People there are known for being direct and dry-humored."},
{type:"teach",trg:"der Süden",src:"the south",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt München?\nB: München liegt im Süden.",exampleSrc:"A: Where is Munich?\nB: Munich is in the south.",funFact:"Southern Germany (Bayern and Baden-Württemberg) has mountains, beer gardens, and a very distinct dialect."},
{type:"teach",trg:"der Osten",src:"the east",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt Dresden?\nB: Dresden liegt im Osten.",exampleSrc:"A: Where is Dresden?\nB: Dresden is in the east.",funFact:"After reunification in 1990, Germans still say 'im Osten' and 'im Westen' to refer to the former East and West."},
{type:"teach",trg:"der Westen",src:"the west",note:"Masculine noun. No plural. Direction word.",example:"A: Wo liegt Köln?\nB: Köln liegt im Westen.",exampleSrc:"A: Where is Cologne?\nB: Cologne is in the west.",funFact:"Cologne (Köln) in western Germany is famous for its cathedral and its own beer style, Kölsch."},
{type:"teach",trg:"am",src:"at the (contraction of an + dem)",note:"Preposition+article contraction. Used for locations and days.",example:"A: Wo treffen wir uns?\nB: Am Bahnhof, am Montag.",exampleSrc:"A: Where do we meet?\nB: At the train station, on Monday.",funFact:"'Am' is used with days (am Montag), times (am Morgen), and places (am Flughafen)."},
{type:"teach",trg:"ins",src:"into the (contraction of in + das)",note:"Preposition+article contraction. Used with neuter nouns for direction.",example:"A: Wohin gehst du?\nB: Ich gehe ins Kino.",exampleSrc:"A: Where are you going?\nB: I am going to the cinema.",funFact:"Ins Kino, ins Theater, ins Museum. These are the classic 'ins' phrases every German learner needs."},
{type:"teach",trg:"hoch",src:"high, tall",note:"Adjective/adverb. Describes height or elevation.",example:"A: Ist der Turm hoch?\nB: Ja, er ist sehr hoch.",exampleSrc:"A: Is the tower tall?\nB: Yes, it is very tall.",funFact:"The Zugspitze (2,962 m) is Germany's highest mountain. 'Hoch' describes its peak perfectly."},
{type:"teach",trg:"weit",src:"far, wide",note:"Adjective/adverb. Used for distance. Opposite: nah (near).",example:"A: Ist der Bahnhof weit?\nB: Nein, nur fünf Minuten zu Fuß.",exampleSrc:"A: Is the train station far?\nB: No, only five minutes on foot.",funFact:"'Wie weit ist es?' (How far is it?) is the essential travel question in Germany."},
{type:"teach",trg:"so",src:"so, such, like this",note:"Adverb. Very versatile. Used for emphasis and comparison.",example:"A: Berlin ist so groß!\nB: Ja, die Stadt ist wirklich so groß.",exampleSrc:"A: Berlin is so big!\nB: Yes, the city is really that big.",funFact:"'So' is one of the most overused filler words in German. 'Also, so, ja...' starts many sentences."},
{type:"teach",trg:"all",src:"all, every",note:"Pronoun/determiner. Changes form: alle (plural), alles (everything).",example:"A: Sind alle da?\nB: Ja, alle sind da.",exampleSrc:"A: Is everyone here?\nB: Yes, everyone is here.",funFact:"'Alles klar?' (All clear? / Everything okay?) is an extremely common German greeting and check-in phrase."},
{type:"teach",trg:"daneben",src:"next to it, beside it",note:"Adverb. Combines da (there) + neben (next to).",example:"A: Wo ist die Apotheke?\nB: Siehst du das Geschäft? Daneben.",exampleSrc:"A: Where is the pharmacy?\nB: Do you see the shop? Next to it.",funFact:"German has many da- words: daneben, davor, dahinter, darüber. They all mean 'there + preposition'."},
{type:"mc",q:"What does 'die Straßenbahn' mean?",opts:["the tram","the highway","the bicycle","the truck"],ans:"the tram",hint:"It rides on streets and runs on rails."},
{type:"fb",s:"Ich gehe {1} Kino.",a:["ins"],opts:["ins","am","auf","im"],hint:"You are going INTO a neuter place.",sSrc:"I am going {1} the cinema."},
{type:"mc",q:"Hamburg liegt im... ?",opts:["Norden","Süden","Osten","Westen"],ans:"Norden",hint:"This port city is near the coast of the North Sea."},
{type:"match",pairs:[{trg:"das Fahrrad",src:"bicycle"},{trg:"die Autobahn",src:"highway"},{trg:"das Gleis",src:"track"},{trg:"die S-Bahn",src:"city train"},{trg:"der Lkw",src:"truck"}]}
]},

{id:"deu_r2l12",title:"Kommen und Gehen",icon:"🚶",xp:15,board:true,steps:[
{type:"intro",title:"Kommen und Gehen",desc:"Verumius is always on the move in Berlin. Learn the verbs for coming, going, searching, and everything in between.",goals:["Learn 18 movement and action verbs","Use separable verbs like abholen, mitkommen, umsteigen","Talk about travel actions and plans"]},
{type:"teach",trg:"abfliegen",src:"to depart (by plane)",note:"Separable verb: ab + fliegen. Ich fliege morgen ab.",example:"A: Wann fliegst du ab?\nB: Ich fliege um acht Uhr ab.",exampleSrc:"A: When do you depart?\nB: I depart at eight o'clock.",funFact:"At German airports, 'Abflug' (departure) boards are yellow. 'Ankunft' (arrival) boards are white."},
{type:"teach",trg:"abholen",src:"to pick up (a person or thing)",note:"Separable verb: ab + holen. Ich hole dich ab.",example:"A: Kannst du mich abholen?\nB: Ja, ich hole dich am Bahnhof ab.",exampleSrc:"A: Can you pick me up?\nB: Yes, I will pick you up at the station.",funFact:"Germans are punctual about Abholen. If they say 15:00, they mean 15:00, not 15:05."},
{type:"teach",trg:"besichtigen",src:"to visit, to tour (a place)",note:"Inseparable verb. Wir besichtigen das Schloss.",example:"A: Was machen wir heute?\nB: Wir besichtigen das Brandenburger Tor.",exampleSrc:"A: What are we doing today?\nB: We are visiting the Brandenburg Gate.",funFact:"Besichtigen is more formal than besuchen. You besichtigen monuments but besuchen friends."},
{type:"teach",trg:"halten",src:"to hold, to stop",note:"Strong verb: er hält. Also used for buses: Der Bus hält hier.",example:"A: Hält der Bus hier?\nB: Ja, der Bus hält an dieser Haltestelle.",exampleSrc:"A: Does the bus stop here?\nB: Yes, the bus stops at this stop.",funFact:"'Halt!' on its own means 'Stop!' It is used by police and in everyday speech."},
{type:"teach",trg:"stehen",src:"to stand",note:"Irregular verb. Ich stehe, du stehst, er steht.",example:"A: Wo stehst du?\nB: Ich stehe vor dem Museum.",exampleSrc:"A: Where are you standing?\nB: I am standing in front of the museum.",funFact:"'Wie steht es?' literally means 'How does it stand?' but it means 'What is the score?' or 'How are things?'"},
{type:"teach",trg:"suchen",src:"to search, to look for",note:"Regular verb. Ich suche, du suchst.",example:"A: Was suchst du?\nB: Ich suche den Ausgang.",exampleSrc:"A: What are you looking for?\nB: I am looking for the exit.",funFact:"Google's German slogan was once 'Gut gesucht ist halb gefunden' (Well searched is half found)."},
{type:"teach",trg:"wandern",src:"to hike",note:"Regular verb. Ich wandere, du wanderst.",example:"A: Gehst du gern wandern?\nB: Ja, ich wandere jedes Wochenende.",exampleSrc:"A: Do you like hiking?\nB: Yes, I hike every weekend.",funFact:"Germany has over 200,000 km of marked hiking trails. Wandern is a national passion."},
{type:"teach",trg:"bleiben",src:"to stay, to remain",note:"Irregular verb. Ich bleibe, du bleibst. Past: geblieben.",example:"A: Wie lange bleibst du in Berlin?\nB: Ich bleibe drei Tage.",exampleSrc:"A: How long are you staying in Berlin?\nB: I am staying three days.",funFact:"'Bleib gesund!' (Stay healthy!) became a very popular farewell during the pandemic years."},
{type:"teach",trg:"dauern",src:"to last, to take (time)",note:"Regular verb. Es dauert zwei Stunden.",example:"A: Wie lange dauert die Fahrt?\nB: Sie dauert eine Stunde.",exampleSrc:"A: How long does the trip take?\nB: It takes one hour.",funFact:"'Das dauert ewig!' (That takes forever!) is a common complaint, especially about bureaucracy."},
{type:"teach",trg:"helfen",src:"to help",note:"Strong verb: er hilft (stem changes e to i). Takes dative.",example:"A: Können Sie mir helfen?\nB: Ja, natürlich. Wie kann ich helfen?",exampleSrc:"A: Can you help me?\nB: Yes, of course. How can I help?",funFact:"'Hilfe!' (Help!) is the German emergency shout. You will hear it in every action movie dubbed into German."},
{type:"teach",trg:"leihen",src:"to lend, to borrow",note:"Strong verb. Ich leihe dir mein Buch. Context determines lend vs. borrow.",example:"A: Kannst du mir dein Handy leihen?\nB: Ja, hier bitte.",exampleSrc:"A: Can you lend me your phone?\nB: Yes, here you go.",funFact:"German uses the same word for lend AND borrow. Context makes the meaning clear."},
{type:"teach",trg:"mitkommen",src:"to come along",note:"Separable verb: mit + kommen. Kommst du mit?",example:"A: Ich gehe ins Museum. Kommst du mit?\nB: Ja, ich komme gern mit!",exampleSrc:"A: I am going to the museum. Are you coming along?\nB: Yes, I would love to come along!",funFact:"'Kommst du mit?' is one of the most common German invitations. Short, direct, friendly."},
{type:"teach",trg:"zeigen",src:"to show",note:"Regular verb. Ich zeige, du zeigst.",example:"A: Können Sie mir den Weg zeigen?\nB: Ja, ich zeige Ihnen den Weg.",exampleSrc:"A: Can you show me the way?\nB: Yes, I will show you the way.",funFact:"'Zeig mal!' (Show me!) is how Germans ask to see something. Very direct and casual."},
{type:"teach",trg:"mitnehmen",src:"to take along",note:"Separable verb: mit + nehmen. Er nimmt mich mit.",example:"A: Nimmst du den Regenschirm mit?\nB: Ja, ich nehme ihn mit.",exampleSrc:"A: Are you taking the umbrella along?\nB: Yes, I am taking it along.",funFact:"'Zum Mitnehmen' means 'to go' for food. 'Hier essen oder mitnehmen?' is the German 'for here or to go?'"},
{type:"teach",trg:"weiterfahren",src:"to continue driving, to drive on",note:"Separable verb: weiter + fahren. Wir fahren weiter.",example:"A: Steigen wir hier aus?\nB: Nein, wir fahren weiter bis Alexanderplatz.",exampleSrc:"A: Do we get off here?\nB: No, we continue to Alexanderplatz.",funFact:"Weiter means 'further'. Germans add it to many verbs: weitergehen (walk on), weitermachen (continue)."},
{type:"teach",trg:"umsteigen",src:"to transfer, to change (trains/buses)",note:"Separable verb: um + steigen. Sie steigen in Frankfurt um.",example:"A: Muss ich umsteigen?\nB: Ja, Sie steigen in Hauptbahnhof um.",exampleSrc:"A: Do I have to transfer?\nB: Yes, you transfer at the main station.",funFact:"Umsteigen is a survival word for German public transit. Every journey planner shows where to transfer."},
{type:"teach",trg:"auf sein",src:"to be open",note:"Separable: Das Geschäft ist auf. Colloquial for 'offen sein'.",example:"A: Ist die Bäckerei auf?\nB: Ja, sie ist bis sechs auf.",exampleSrc:"A: Is the bakery open?\nB: Yes, it is open until six.",funFact:"'Auf' here means open. 'Zu' means closed. 'Die Tür ist auf/zu' (The door is open/closed)."},
{type:"teach",trg:"grade",src:"just, right now (colloquial)",note:"Colloquial form of 'gerade'. Very common in spoken German.",example:"A: Was machst du grade?\nB: Ich bin grade am Bahnhof.",exampleSrc:"A: What are you doing right now?\nB: I am at the train station right now.",funFact:"'Gerade' is the standard form, but 'grade' is what you hear in casual Berlin speech."},
{type:"mc",q:"What does 'umsteigen' mean?",opts:["to transfer","to depart","to arrive","to search"],ans:"to transfer",hint:"You leave one train and get on another one."},
{type:"fb",s:"Wie lange {1} die Fahrt nach Hamburg?",a:["dauert"],opts:["dauert","bleibt","hilft","sucht"],hint:"You are asking about how much time the trip takes.",sSrc:"How long {1} the trip to Hamburg?"},
{type:"mc",q:"'Kommst du mit?' is an invitation to... ?",opts:["come along","stay home","go away","be quiet"],ans:"come along",hint:"The speaker wants company on their outing."},
{type:"match",pairs:[{trg:"abholen",src:"to pick up"},{trg:"bleiben",src:"to stay"},{trg:"wandern",src:"to hike"},{trg:"suchen",src:"to search"},{trg:"helfen",src:"to help"}]}
]},

{id:"deu_r2l13",title:"Rund um die Stadt",icon:"🏙️",xp:15,board:true,steps:[
{type:"intro",title:"Rund um die Stadt",desc:"Verumius is becoming a true Berlin explorer. Learn words for sights, information, nature, and everything you need as a tourist.",goals:["Learn 20 city and tourism vocabulary words","Ask for help and information confidently","Describe sights, views, and places"]},
{type:"teach",trg:"der Blick",src:"the view, the glance",note:"Masculine noun. Plural: die Blicke.",example:"A: Wie ist der Blick von hier?\nB: Der Blick ist fantastisch!",exampleSrc:"A: How is the view from here?\nB: The view is fantastic!",funFact:"'Auf den ersten Blick' means 'at first glance'. It is also the German title of the movie 'Love at First Sight'."},
{type:"teach",trg:"die Hilfe",src:"the help",note:"Feminine noun. Plural: die Hilfen.",example:"A: Brauchst du Hilfe?\nB: Ja, ich brauche Hilfe mit der Karte.",exampleSrc:"A: Do you need help?\nB: Yes, I need help with the map.",funFact:"'Erste Hilfe' means 'first aid'. Every German driver must carry a first aid kit in their car by law."},
{type:"teach",trg:"die Ansage",src:"the announcement",note:"Feminine noun. Plural: die Ansagen. An + Sage (saying).",example:"A: Hast du die Ansage gehört?\nB: Ja, der Zug hat Verspätung.",exampleSrc:"A: Did you hear the announcement?\nB: Yes, the train is delayed.",funFact:"Train announcements in Germany always start with 'Meine Damen und Herren' (Ladies and gentlemen)."},
{type:"teach",trg:"die Auskunft",src:"the information, the information desk",note:"Feminine noun. Plural: die Auskünfte. Aus (out) + Kunft (coming).",example:"A: Wo bekomme ich Informationen?\nB: Fragen Sie an der Auskunft.",exampleSrc:"A: Where can I get information?\nB: Ask at the information desk.",funFact:"'Telefonauskunft' was the phone directory service. Before smartphones, you called 11833 for any number."},
{type:"teach",trg:"das Beispiel",src:"the example",note:"Neuter noun. Plural: die Beispiele. Bei (by) + Spiel (play).",example:"A: Kannst du mir ein Beispiel geben?\nB: Ja, zum Beispiel das hier.",exampleSrc:"A: Can you give me an example?\nB: Yes, for example this one.",funFact:"'Zum Beispiel' (for example), abbreviated 'z.B.', is one of the most common phrases in written German."},
{type:"teach",trg:"die Durchsage",src:"the PA announcement",note:"Feminine noun. Plural: die Durchsagen. Durch (through) + Sage (saying).",example:"A: Was war das?\nB: Das war eine Durchsage. Der Zug kommt später.",exampleSrc:"A: What was that?\nB: That was an announcement. The train is coming later.",funFact:"Durchsage literally means 'saying through' because the message goes through the speaker system."},
{type:"teach",trg:"das Schild",src:"the sign",note:"Neuter noun. Plural: die Schilder.",example:"A: Was steht auf dem Schild?\nB: Auf dem Schild steht: Ausgang.",exampleSrc:"A: What does the sign say?\nB: The sign says: Exit.",funFact:"German road signs follow strict color rules: blue for highways, yellow for federal roads, white for city streets."},
{type:"teach",trg:"die Vorsicht",src:"the caution, the care",note:"Feminine noun. No common plural. Vor (before) + Sicht (sight).",example:"A: Vorsicht! Die Straße ist nass.\nB: Danke, ich passe auf.",exampleSrc:"A: Careful! The street is wet.\nB: Thanks, I will be careful.",funFact:"'Vorsicht, Stufe!' (Caution, step!) is written on almost every doorstep in Germany."},
{type:"teach",trg:"das Meer",src:"the sea",note:"Neuter noun. Plural: die Meere.",example:"A: Warst du schon am Meer?\nB: Ja, die Nordsee ist wunderschön.",exampleSrc:"A: Have you been to the sea?\nB: Yes, the North Sea is beautiful.",funFact:"Germany has two seas: the Nordsee (North Sea) and the Ostsee (Baltic Sea). Both are popular vacation spots."},
{type:"teach",trg:"der See",src:"the lake",note:"Masculine noun! Plural: die Seen. Not the same as 'die See' (the sea).",example:"A: Gehen wir zum See?\nB: Ja, der See ist sehr schön.",exampleSrc:"A: Shall we go to the lake?\nB: Yes, the lake is very beautiful.",funFact:"Watch out! 'Der See' (masculine) = lake. 'Die See' (feminine) = sea. Same spelling, different genders, different meanings!"},
{type:"teach",trg:"der Ausflug",src:"the excursion, the day trip",note:"Masculine noun. Plural: die Ausflüge. Aus (out) + Flug (flight).",example:"A: Machen wir einen Ausflug?\nB: Ja, wir machen einen Ausflug nach Potsdam.",exampleSrc:"A: Shall we take a day trip?\nB: Yes, we are taking a day trip to Potsdam.",funFact:"Day trips (Ausflüge) from Berlin to Potsdam, Spreewald, or Sachsenhausen are very popular."},
{type:"teach",trg:"das Foto",src:"the photo",note:"Neuter noun. Plural: die Fotos.",example:"A: Kann ich ein Foto machen?\nB: Ja, natürlich! Lächeln!",exampleSrc:"A: Can I take a photo?\nB: Yes, of course! Smile!",funFact:"Germans say 'ein Foto machen' (make a photo), not 'take a photo'. Different verb, same action!"},
{type:"teach",trg:"die Führung",src:"the guided tour",note:"Feminine noun. Plural: die Führungen. From führen (to lead).",example:"A: Gibt es eine Führung?\nB: Ja, die Führung beginnt um elf Uhr.",exampleSrc:"A: Is there a guided tour?\nB: Yes, the tour starts at eleven o'clock.",funFact:"Free walking tours (kostenlose Führungen) are popular in Berlin. You just give a tip at the end."},
{type:"teach",trg:"die Karte",src:"the map, the ticket, the card",note:"Feminine noun. Plural: die Karten. Context determines meaning.",example:"A: Hast du eine Karte?\nB: Ja, ich habe eine Karte von Berlin.",exampleSrc:"A: Do you have a map?\nB: Yes, I have a map of Berlin.",funFact:"Karte means map, ticket, AND card. 'Fahrkarte' = transit ticket. 'Eintrittskarte' = admission ticket. 'Kreditkarte' = credit card."},
{type:"teach",trg:"der Prospekt",src:"the brochure, the flyer",note:"Masculine noun. Plural: die Prospekte.",example:"A: Haben Sie einen Prospekt?\nB: Ja, hier ist der Prospekt vom Museum.",exampleSrc:"A: Do you have a brochure?\nB: Yes, here is the museum brochure.",funFact:"Tourist information centers in Germany always have stacks of free Prospekte for every attraction."},
{type:"teach",trg:"das Reisebüro",src:"the travel agency",note:"Neuter noun. Plural: die Reisebüros. Reise (travel) + Büro (office).",example:"A: Wo buche ich die Reise?\nB: Im Reisebüro am Platz.",exampleSrc:"A: Where do I book the trip?\nB: At the travel agency at the square.",funFact:"Despite the internet, Germany still has thousands of Reisebüros. Many Germans prefer booking trips in person."},
{type:"teach",trg:"der Reiseführer",src:"the travel guide (book or person)",note:"Masculine noun. Plural: die Reiseführer. Reise (travel) + Führer (guide).",example:"A: Hast du einen Reiseführer?\nB: Ja, der Reiseführer empfiehlt dieses Lokal.",exampleSrc:"A: Do you have a travel guide?\nB: Yes, the guide recommends this restaurant.",funFact:"The Lonely Planet and Baedeker travel guides were pioneers. Baedeker, founded in 1827 in Germany, invented the modern guidebook."},
{type:"teach",trg:"ander",src:"other, different",note:"Pronoun/adjective. Changes form: der andere, die andere, das andere.",example:"A: Möchtest du dieses Hotel?\nB: Nein, das andere Hotel ist besser.",exampleSrc:"A: Would you like this hotel?\nB: No, the other hotel is better.",funFact:"'Unter anderem' (among other things), abbreviated 'u.a.', is very common in German writing."},
{type:"teach",trg:"alles",src:"everything",note:"Pronoun. The neuter form of 'all'. Alles klar? = All clear?",example:"A: Hast du alles?\nB: Ja, ich habe alles. Wir können gehen.",exampleSrc:"A: Do you have everything?\nB: Yes, I have everything. We can go.",funFact:"'Alles Gute!' (All the best!) is the standard wish for birthdays, farewells, and any occasion."},
{type:"teach",trg:"der Eintritt",src:"the entry, the admission",note:"Masculine noun. Ein (in) + Tritt (step). Admission fee: der Eintrittspreis.",example:"A: Was kostet der Eintritt?\nB: Der Eintritt kostet zehn Euro.",exampleSrc:"A: How much is the admission?\nB: The admission is ten euros.",funFact:"Many Berlin museums have 'Eintritt frei' (free admission) on the first Sunday of each month."},
{type:"mc",q:"'Der See' is masculine and means 'the lake'. What does 'die See' (feminine) mean?",opts:["the sea","the lake","the river","the pond"],ans:"the sea",hint:"Changing the article from masculine to feminine gives a completely different body of water."},
{type:"fb",s:"Was kostet der {1}?",a:["Eintritt"],opts:["Eintritt","Ausflug","Blick","Prospekt"],hint:"You want to know the price to get into a place.",sSrc:"How much does the {1} cost?"},
{type:"mc",q:"What does 'Vorsicht!' mean when you see it on a sign?",opts:["Caution!","Welcome!","Exit!","Open!"],ans:"Caution!",hint:"This word warns you to be careful about something."},
{type:"match",pairs:[{trg:"das Foto",src:"photo"},{trg:"die Karte",src:"map/ticket"},{trg:"das Schild",src:"sign"},{trg:"die Hilfe",src:"help"},{trg:"das Meer",src:"sea"}]}
]}
]},
// ═══════════════════════════════════════════════════════════════
// UNIT 3: Die Wohnungssuche - The 14-Page Hausordnung
// Story: Verumius finds an apartment, meets Hildi, survives the Hausordnung
// CEFR: A1.1 - Family, home, furniture, separable verbs, possessives
// ═══════════════════════════════════════════════════════════════
{n:3,lang:"de",srcLang:"en",track:"v2",title:"Die Wohnungssuche",sub:"Family, home, furniture & the 14-page Hausordnung",icon:"🏠",level:"A1.1",color:"#7B5EE8",lessons:[

// ─── L1: Wohnung frei ───
{id:"deu_r3l1",title:"Wohnung frei",icon:"🏠",xp:15,board:true,steps:[
{type:"intro",title:"Die Wohnungssuche",desc:"Verumius needs an apartment. Fast. One listing catches his eye: 3 rooms, balcony, Prenzlauer Berg. One call changes everything.",goals:["Learn housing vocabulary","Understand rent and utilities","Meet Frau Hildegard Schreiber"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-prenzlauer-berg-rain",trg:"Prenzlauer Berg. Regen. Verumius steht vor einem Laternenpfahl voller Wohnungsanzeigen. Eine ist rot eingekreist: '3 Zimmer, Balkon, Prenzlauer Berg. 650 Euro warm.' Er macht ein Foto.",src:"Prenzlauer Berg. Rain. Verumius stands in front of a lamppost covered in apartment listings. One is circled in red: '3 rooms, balcony, Prenzlauer Berg. 650 euros warm.' He takes a photo."},
{type:"teach",trg:"die Wohnung",src:"the apartment",note:"Feminine noun. The standard word for a rented apartment.",example:"A: Hast du eine Wohnung?\nB: Nein, ich suche eine Wohnung.",exampleSrc:"A: Do you have an apartment?\nB: No, I am looking for an apartment.",funFact:"Germans say 'warm' rent (Warmmiete, includes heating) and 'cold' rent (Kaltmiete, without). Always ask which one. You WILL be asked."},
{type:"teach",trg:"das Haus",src:"the house",note:"Neuter noun. Plural: die Häuser.",example:"A: Wohnst du in einem Haus?\nB: Nein, in einer Wohnung.",exampleSrc:"A: Do you live in a house?\nB: No, in an apartment.",funFact:"Most Germans rent. Homeownership is around 50%, the lowest in Europe. 'Mehrfamilienhaus' (multi-family house) is where most people live."},
{type:"teach",trg:"das Zimmer",src:"the room",note:"Neuter noun. Plural stays: die Zimmer.",example:"A: Wie viele Zimmer hat die Wohnung?\nB: Drei Zimmer.",exampleSrc:"A: How many rooms does the apartment have?\nB: Three rooms.",funFact:"'3-Zimmer-Wohnung' means 3 rooms PLUS kitchen and bathroom. Kitchen and bath do not count as Zimmer. Surprise!"},
{type:"teach",trg:"mieten",src:"to rent (as tenant)",note:"Regular verb. Ich miete, du mietest, er mietet.",example:"A: Möchtest du die Wohnung mieten?\nB: Ja, ich möchte mieten!",exampleSrc:"A: Would you like to rent the apartment?\nB: Yes, I would like to rent!",funFact:"'Mieter' = tenant. 'Vermieter' = landlord. The 'ver-' prefix flips the meaning, like 'buy' vs 'sell.'"},
{type:"teach",trg:"die Miete",src:"the rent",note:"Feminine noun. Monthly payment for your apartment.",example:"A: Wie hoch ist die Miete?\nB: Die Miete ist 650 Euro.",exampleSrc:"A: How much is the rent?\nB: The rent is 650 euros.",funFact:"Average Berlin rent has doubled since 2010. The 'Mietpreisbremse' (rent brake) tries to slow it down. Results: mixed."},
{type:"teach",trg:"kosten",src:"to cost",note:"Regular verb. Was kostet das? = What does that cost?",example:"A: Was kostet die Wohnung?\nB: Sie kostet 650 Euro warm.",exampleSrc:"A: What does the apartment cost?\nB: It costs 650 euros including utilities.",funFact:"Germans ask 'Was kostet das?' more than 'Wie viel kostet das?' Both work, but the short version is more natural."},
{type:"teach",trg:"brauchen",src:"to need",note:"Regular verb. Ich brauche, du brauchst, er braucht.",example:"A: Was brauchst du?\nB: Ich brauche eine Wohnung!",exampleSrc:"A: What do you need?\nB: I need an apartment!",funFact:"In spoken German, 'brauchen' sometimes replaces 'müssen' with 'nicht': 'Du brauchst nicht kommen' = you don't need to come."},
{type:"teach",trg:"der Balkon",src:"the balcony",note:"Masculine noun. Also: das Fenster (the window), der Flur (the hallway).",example:"A: Hat die Wohnung einen Balkon?\nB: Ja, einen kleinen Balkon.",exampleSrc:"A: Does the apartment have a balcony?\nB: Yes, a small balcony.",funFact:"Balkon is borrowed from French. Fenster comes from Latin 'fenestra.' German loves borrowing words and making them feel German."},
{type:"teach",trg:"der Schlüssel",src:"the key",note:"Masculine noun. Plural: die Schlüssel.",example:"A: Wo ist der Schlüssel?\nB: Hier ist der Schlüssel.",exampleSrc:"A: Where is the key?\nB: Here is the key.",funFact:"'Erdgeschoss' = ground floor (floor 0). 'Erster Stock' = what Americans call the 2nd floor. This WILL confuse you."},
{type:"teach",trg:"der Vermieter",src:"the landlord",note:"Masculine. Feminine: die Vermieterin. The person who rents out.",example:"A: Wer ist der Vermieter?\nB: Frau Schreiber ist die Vermieterin.",exampleSrc:"A: Who is the landlord?\nB: Mrs. Schreiber is the landlady.",funFact:"'Nachbar' (neighbor) literally means 'near-dweller.' Your Nachbar will know your schedule better than you do."},
{type:"teach",trg:"planen",src:"to plan",note:"Regular verb. Also: der Anfang (beginning), das Ende (end).",example:"A: Was planst du?\nB: Ich plane den Umzug.",exampleSrc:"A: What are you planning?\nB: I am planning the move.",funFact:"'Aller Anfang ist schwer' = every beginning is hard. A German proverb you will hear constantly."},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-hildi-phone-call",trg:"Verumius ruft an. Eine Stimme, präzise und kurz: 'Schreiber. Besichtigung morgen, 14 Uhr. Pünktlich.' Klick. Lena schreibt: 'Hildi Schreiber? Viel Glück. Du brauchst es.'",src:"Verumius calls. A voice, precise and clipped: 'Schreiber. Viewing tomorrow, 2 PM. Punctual.' Click. Lena texts: 'Hildi Schreiber? Good luck. You need it.'"},
{type:"mc",q:"'Wie viele Zimmer hat die Wohnung?' What are Zimmer?",opts:["rooms","windows","floors","doors"],ans:"rooms",hint:"A '3-Zimmer-Wohnung' has three of these, plus kitchen and bathroom."},
{type:"fb",s:"Die {1} ist 650 Euro warm.",a:["Miete"],opts:["Miete","Wohnung","Straße","Brücke"],hint:"The monthly payment to live somewhere. Warm includes heating costs.",sSrc:"The {1} is 650 euros all-inclusive."},
{type:"match",pairs:[{trg:"die Wohnung",src:"apartment"},{trg:"das Zimmer",src:"room"},{trg:"der Schlüssel",src:"key"},{trg:"die Miete",src:"rent"},{trg:"der Balkon",src:"balcony"}]},
{type:"mc",q:"Verumius needs an apartment. Which verb means 'to rent'?",opts:["mieten","kosten","planen","brauchen"],ans:"mieten",hint:"The tenant does this action. The landlord does the opposite with a ver- prefix."}
]},

// ─── L2: Meine Familie, dein Problem ───
{id:"deu_r3l2",title:"Meine Familie, dein Problem",icon:"👨‍👩‍👧‍👦",xp:15,board:true,steps:[
{type:"intro",title:"Meine Familie",desc:"Verumius needs to fill out a tenant form. 'Familienstand?' Lena starts asking questions. Time to learn every family member.",goals:["All core family vocabulary","Extended family and relationships","Possessive articles: mein, dein, sein"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-video-call",trg:"Nacht vor der Besichtigung. Verumius macht einen Videoanruf mit Lena. Sie fragt: 'Selbstauskunft? Familienstand?' Er starrt auf das Formular.",src:"Night before the viewing. Verumius video-calls Lena. She asks: 'Tenant disclosure form? Marital status?' He stares at the form."},
{type:"teach",trg:"die Familie",src:"the family",note:"Feminine noun. Plural: die Familien.",example:"A: Was ist dein Familienstand?\nB: Ledig. Ich bin ledig.",exampleSrc:"A: What is your marital status?\nB: Single. I am single.",funFact:"'Familienstand' on German forms means marital status. Options: ledig, verheiratet, geschieden. Verumius checks 'ledig' with relief."},
{type:"teach",trg:"der Vater",src:"the father",note:"Masculine. Informal: Papa, Mama.",example:"A: Wer ist das?\nB: Das ist mein Vater.",exampleSrc:"A: Who is that?\nB: That is my father.",funFact:"'Mutti' is what Angela Merkel was nicknamed. Every German kid says 'Mama' first."},
{type:"teach",trg:"die Mutter",src:"the mother",note:"Feminine. Plural: die Mütter (with umlaut!).",example:"A: Wo ist deine Mutter?\nB: Meine Mutter ist zu Hause.",exampleSrc:"A: Where is your mother?\nB: My mother is at home.",funFact:"'Mutter' and English 'mother' share the same 5,000-year-old root. One of the oldest words in any language."},
{type:"teach",trg:"der Bruder",src:"the brother",note:"Masculine. Plural: die Brüder.",example:"A: Hast du Geschwister?\nB: Ja, einen Bruder und eine Schwester.",exampleSrc:"A: Do you have siblings?\nB: Yes, a brother and a sister.",funFact:"'Bruder' and 'brother' share a 5,000-year-old Proto-Indo-European root. Some words survive everything."},
{type:"teach",trg:"die Schwester",src:"the sister",note:"Feminine. Plural: die Schwestern.",example:"A: Wie heißt deine Schwester?\nB: Meine Schwester heißt Sofia.",exampleSrc:"A: What is your sister's name?\nB: My sister's name is Sofia.",funFact:"'Schwester' also means 'nurse' in German hospitals. 'Krankenschwester' = sick-sister = nurse. Now you can't unhear it."},
{type:"teach",trg:"der Sohn",src:"the son",note:"Masculine. Plural: die Söhne.",example:"A: Ist das dein Sohn?\nB: Nein, das ist meine Tochter.",exampleSrc:"A: Is that your son?\nB: No, that is my daughter.",funFact:"'Tochter' is cognate with English 'daughter.' The 'T' and 'D' swap is a regular Germanic sound shift called Grimm's Law."},
{type:"teach",trg:"die Tochter",src:"the daughter",note:"Feminine. Plural: die Töchter.",example:"A: Wie alt ist Ihre Tochter?\nB: Meine Tochter ist zehn.",exampleSrc:"A: How old is your daughter?\nB: My daughter is ten.",funFact:"Jacob Grimm (yes, the fairy tale Grimm) discovered the sound shift law. He was also a linguist, not just a storyteller."},
{type:"teach",trg:"das Kind",src:"the child",note:"Neuter noun! Plural: die Kinder.",example:"A: Wie viele Kinder hast du?\nB: Zwei Kinder und ein Baby.",exampleSrc:"A: How many children do you have?\nB: Two children and a baby.",funFact:"'Kindergarten' is German's most famous export word. It means 'children's garden.' English borrowed it unchanged."},
{type:"teach",trg:"das Mädchen",src:"the girl",note:"Neuter! DAS Mädchen. The -chen suffix ALWAYS makes a word neuter.",example:"A: Wer spielt im Garten?\nB: Der Junge und das Mädchen.",exampleSrc:"A: Who is playing in the garden?\nB: The boy and the girl.",funFact:"Mädchen is DAS (neuter), not die, because -chen (diminutive) forces neuter. Same rule: Brötchen (das), Häuschen (das), Kätzchen (das)."},
{type:"teach",trg:"der Junge",src:"the boy",note:"Masculine. Plural: die Jungen.",example:"A: Wie heißt der Junge?\nB: Der Junge heißt Max.",exampleSrc:"A: What is the boy's name?\nB: The boy's name is Max.",funFact:"'Junge' literally means 'young one.' It is the male counterpart to Mädchen. In some dialects, 'Bub' is used instead."},
{type:"teach",trg:"der Mann",src:"the man / the husband",note:"Masculine. Means both 'man' and 'husband.' Context decides.",example:"A: Mein Mann heißt Thomas.\nB: Und meine Ehefrau heißt Anna.",exampleSrc:"A: My husband's name is Thomas.\nB: And my wife's name is Anna.",funFact:"'Ehefrau' and 'Ehemann' are the formal terms for wife and husband. On forms you will see 'Ehepartner.'"},
{type:"teach",trg:"die Eltern",src:"the parents",note:"ALWAYS plural. There is no singular 'ein Elter' in normal German.",example:"A: Wo sind deine Eltern?\nB: Meine Eltern wohnen in Hamburg.",exampleSrc:"A: Where are your parents?\nB: My parents live in Hamburg.",funFact:"'Geschwister' (siblings) is also plural-only. German has several words that exist only in plural: Eltern, Geschwister, Leute (people)."},
{type:"teach",trg:"die Geschwister",src:"the siblings",note:"Always plural. Bruder + Schwester = Geschwister.",example:"A: Hast du Geschwister?\nB: Ja, zwei Geschwister.",exampleSrc:"A: Do you have siblings?\nB: Yes, two siblings.",funFact:"Asking 'Hast du Geschwister?' is the standard German small-talk question about family. The answer reveals brothers and sisters at once."},
{type:"teach",trg:"der Großvater",src:"the grandfather",note:"Masculine. Informal: der Opa.",example:"A: Mein Großvater ist 80 Jahre alt.\nB: Und deine Großmutter?",exampleSrc:"A: My grandfather is 80 years old.\nB: And your grandmother?",funFact:"'Groß' = big/grand. Großvater = grand-father. The pattern is transparent. In English it is the same: grand + parent."},
{type:"teach",trg:"die Großmutter",src:"the grandmother",note:"Feminine. Informal: die Oma.",example:"A: Mein Opa kocht gern.\nB: Meine Oma auch!",exampleSrc:"A: My grandpa likes to cook.\nB: My grandma too!",funFact:"Every German kid has an Oma who bakes Kuchen (cake). Opa and Oma are what children actually say. Großvater is formal."},
{type:"teach",trg:"die Freundin",src:"the girlfriend / female friend",note:"Feminine. Context matters: 'meine Freundin' usually = girlfriend.",example:"A: Ist das deine Freundin?\nB: Nein, das ist eine Freundin.",exampleSrc:"A: Is that your girlfriend?\nB: No, that is a (female) friend.",funFact:"'Meine Freundin' with possessive usually means girlfriend. 'Eine Freundin von mir' usually means a female friend. Subtle but important."},
{type:"teach",trg:"ledig",src:"single (unmarried)",note:"Adjective. Used on German forms for marital status.",example:"A: Bist du verheiratet?\nB: Nein, ich bin ledig.",exampleSrc:"A: Are you married?\nB: No, I am single.",funFact:"German forms demand precision: ledig (single), verheiratet (married), geschieden (divorced), verwitwet (widowed). Germans document EVERYTHING."},
{type:"teach",trg:"verheiratet",src:"married",note:"Adjective/past participle of 'heiraten' (to marry).",example:"A: Sind Sie verheiratet?\nB: Ja, seit zehn Jahren.",exampleSrc:"A: Are you married?\nB: Yes, for ten years.",funFact:"'Heiraten' = to marry. 'Verheiratet' = married (state). The 'ver-' prefix turns the action into a completed state."},
{type:"teach",trg:"geschieden",src:"divorced",note:"Adjective/past participle of 'scheiden' (to separate).",example:"A: Ist er verheiratet?\nB: Nein, er ist geschieden.",exampleSrc:"A: Is he married?\nB: No, he is divorced.",funFact:"Germany's divorce rate is about 35%. The process is relatively straightforward but requires a mandatory one-year separation period."},
{type:"teach",trg:"geboren",src:"born",note:"Past participle. 'Ich bin 1995 geboren.'",example:"A: Wann bist du geboren?\nB: Ich bin 1998 geboren.",exampleSrc:"A: When were you born?\nB: I was born in 1998.",funFact:"On German forms: 'Geburtsdatum' = date of birth. 'Geburtsort' = place of birth. Both required everywhere."},
{type:"tip",title:"Possessive Articles: mein, dein, sein",text:"Possessives follow the ein-pattern:\n\nmein Bruder (my brother, der-noun)\nmeine Schwester (my sister, die-noun)\nmein Kind (my child, das-noun)\n\nmein = my, dein = your (informal), sein = his\nAll three work the same way.\n\nRule: no ending for der/das-nouns, -e for die-nouns and all plurals."},
{type:"teach",trg:"mein / meine",src:"my",note:"Mein for der/das-nouns. Meine for die-nouns and plurals.",example:"A: Mein Bruder wohnt in Berlin.\nB: Meine Schwester auch.",exampleSrc:"A: My brother lives in Berlin.\nB: My sister too.",funFact:"'Mein' follows the exact same ending pattern as 'ein/eine.' Learn one, you know the other."},
{type:"teach",trg:"dein / deine",src:"your (informal)",note:"Dein for der/das-nouns. Deine for die-nouns and plurals.",example:"A: Ist das dein Hund?\nB: Ja, das ist mein Hund.",exampleSrc:"A: Is that your dog?\nB: Yes, that is my dog.",funFact:"'Dein' follows the exact same pattern as 'mein.' The possessives are a copy-paste job with different first letters."},
{type:"teach",trg:"sein / seine",src:"his",note:"Sein for der/das-nouns. Seine for die-nouns and plurals.",example:"A: Sein Opa ist nett.\nB: Seine Oma auch.",exampleSrc:"A: His grandpa is nice.\nB: His grandma too.",funFact:"'Sein' also means 'to be.' 'Sein Bruder ist nett' = His brother is nice. Two meanings of 'sein' in one sentence."},
{type:"mc",q:"'Meine _____ heißt Anna.' Which family member fits?",opts:["Bruder","Schwester","Sohn","Vater"],ans:"Schwester",hint:"'Meine' signals a die-noun. Which is feminine? Anna is a woman's name."},
{type:"mc",q:"'Das ist ___ Sohn.' (his)",opts:["mein","dein","sein","meine"],ans:"sein",hint:"'His' son. Der Sohn is masculine. No -e ending needed."},
{type:"mc",q:"'Mein _____ und meine Großmutter sind meine Großeltern.'",opts:["Großvater","Opa","Bruder","Enkel"],ans:"Großvater",hint:"The male grandparent. The formal word paired with Großmutter."},
{type:"fb",s:"Mein {1} und meine Schwester sind Geschwister.",a:["Bruder"],opts:["Bruder","Mutter","Tochter","Kind"],hint:"Male sibling paired with Schwester.",sSrc:"My {1} and my sister are siblings."},
{type:"mc",q:"'Der _____ spielt mit dem Mädchen.'",opts:["Junge","Mann","Opa","Enkel"],ans:"Junge",hint:"The boy. Male counterpart to das Mädchen."},
{type:"mc",q:"Auf dem Formular steht: 'Geschlecht: _____'",opts:["männlich","ledig","geboren","jung"],ans:"männlich",hint:"The form asks about gender, not marital status or age."},
{type:"match",pairs:[{trg:"der Opa",src:"grandpa"},{trg:"die Oma",src:"grandma"},{trg:"die Schwester",src:"sister"},{trg:"der Junge",src:"boy"},{trg:"die Eltern",src:"parents"}]},
{type:"fb",s:"Meine Oma ist 1940 {1}.",a:["geboren"],opts:["geboren","jung","alt","ledig"],hint:"She came into the world in 1940. Which word means 'born'?",sSrc:"My grandma was {1} in 1940."},
{type:"mc",q:"Verumius ist _____.",opts:["verheiratet","geschieden","ledig","Enkel"],ans:"ledig",hint:"Not married, not divorced. The single option."},
{type:"fb",s:"Die Wohnung {1} 650 Euro warm.",a:["kostet"],opts:["kostet","mietet","braucht","kauft"],hint:"How much does the apartment cost? Which verb expresses price?",sSrc:"The apartment {1} costs 650 euros all-inclusive."},
{type:"mc",q:"What does 'warm' mean in 'Die Miete ist 650 Euro warm'?",opts:["Including heating costs","The apartment is warm","Expensive rent","Summer price only"],ans:"Including heating costs",hint:"Warmmiete vs Kaltmiete. One includes utility costs, the other does not."},
{type:"match",pairs:[{trg:"die Wohnung",src:"apartment"},{trg:"die Miete",src:"rent"},{trg:"der Schlüssel",src:"key"},{trg:"der Vermieter",src:"landlord"},{trg:"mieten",src:"to rent"}]},
{type:"mc",q:"'Hildi Schreiber? Viel Glück!' What is Lena warning about?",opts:["A strict landlady","A broken apartment","High rent","A long commute"],ans:"A strict landlady",hint:"Lena wishes him luck. That reaction tells you the person has a strong personality."}
]},

// ─── L3: Besichtigung um 14 Uhr ───
{id:"deu_r3l3",title:"Besichtigung um 14 Uhr",icon:"🔑",xp:15,board:true,steps:[
{type:"intro",title:"Die Besichtigung",desc:"Verumius arrives at 13:58. Hildi opens the door at exactly 14:00. Time to learn the rooms, furniture, and spatial prepositions.",goals:["Room vocabulary","Furniture basics","Prepositions: hinter, zwischen, neben"]},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-hildi-door",trg:"13:58. Verumius steht vor der Tür. Um genau 14:00 öffnet sie sich. Silbernes Haar, Lesebrille an einer Kette, gebügelte Bluse. 'Herr Verumius? Schreiber. Pünktlich. Gut.' Sie dreht sich um. Er folgt.",src:"13:58. Verumius stands at the door. At exactly 14:00 it opens. Silver hair, reading glasses on a chain, pressed blouse. 'Mr. Verumius? Schreiber. Punctual. Good.' She turns. He follows."},
{type:"teach",trg:"die Küche",src:"the kitchen",note:"Feminine noun. Sacred space in German apartments.",example:"A: Wo ist die Küche?\nB: Hier links.",exampleSrc:"A: Where is the kitchen?\nB: Here on the left.",funFact:"'Küche' comes from Latin 'coquina' (cooking place). The German kitchen is sacred. NEVER leave dishes in the sink. Hildi will know."},
{type:"teach",trg:"das Wohnzimmer",src:"the living room",note:"Neuter. Compound: Wohn(living) + Zimmer(room).",example:"A: Das Wohnzimmer ist groß.\nB: Und das Schlafzimmer?",exampleSrc:"A: The living room is big.\nB: And the bedroom?",funFact:"German room names are transparent compounds: Wohn+Zimmer, Schlaf+Zimmer, Bade+Zimmer. Learn 'Zimmer' and decode any room."},
{type:"teach",trg:"das Schlafzimmer",src:"the bedroom",note:"Neuter. Schlaf(sleep) + Zimmer(room).",example:"A: Wo ist das Schlafzimmer?\nB: Am Ende des Flurs.",exampleSrc:"A: Where is the bedroom?\nB: At the end of the hallway.",funFact:"'Schlaf' comes from 'schlafen' (to sleep). Compound logic: where you sleep = Schlafzimmer. Where you bathe = Badezimmer."},
{type:"teach",trg:"das Bad",src:"the bathroom",note:"Neuter. Short for Badezimmer. Also: die Dusche (shower).",example:"A: Hat das Bad eine Dusche?\nB: Ja, die Dusche ist neu.",exampleSrc:"A: Does the bathroom have a shower?\nB: Yes, the shower is new.",funFact:"In many German apartments, the Toilette is a separate tiny room from the Bad. Ask 'Wo ist die Toilette?' and you might get a different room."},
{type:"teach",trg:"die Toilette",src:"the toilet / restroom",note:"Feminine. Often a separate room from the bathroom!",example:"A: Wo ist die Toilette?\nB: Neben dem Bad.",exampleSrc:"A: Where is the restroom?\nB: Next to the bathroom.",funFact:"'Toilette' is borrowed from French. In many German buildings, Toilette and Bad are separate rooms. Ask for the right one."},
{type:"teach",trg:"der Boden",src:"the floor",note:"Masculine. Also: das Dach (roof), der Garten (garden).",example:"A: Der Boden ist neu.\nB: Und das Dach?",exampleSrc:"A: The floor is new.\nB: And the roof?",funFact:"'Dachgarten' = rooftop garden. German compounds just stack: Dach + Garten. You can build words forever."},
{type:"teach",trg:"die Treppe",src:"the stairs / staircase",note:"Feminine. 'Treppenhaus' = stairwell.",example:"A: Gibt es einen Aufzug?\nB: Nein, nur die Treppe.",exampleSrc:"A: Is there an elevator?\nB: No, only the stairs.",funFact:"Hildi's building: 4th floor, no elevator. Legs of steel required. Many older German buildings have no Aufzug."},
{type:"teach",trg:"der Raum",src:"the room / space",note:"Masculine. More formal than Zimmer. Plural: die Räume.",example:"A: Wie viele Räume hat die Wohnung?\nB: Drei Räume und eine Küche.",exampleSrc:"A: How many rooms does the apartment have?\nB: Three rooms and a kitchen.",funFact:"'Raum' scales from tiny to cosmic: 'Wohnraum' = living space. 'Weltraum' = outer space. One word, from a room to the cosmos."},
{type:"teach",trg:"der Kühlschrank",src:"the fridge / refrigerator",note:"Masculine. Compound: Kühl(cool) + Schrank(cabinet).",example:"A: Funktioniert der Kühlschrank?\nB: Ja, er ist neu.",exampleSrc:"A: Does the fridge work?\nB: Yes, it is new.",funFact:"German compound nouns describe what the thing does: Kühlschrank (cool-cabinet), Handschuh (hand-shoe = glove), Staubsauger (dust-sucker = vacuum)."},
{type:"teach",trg:"der Tisch",src:"the table",note:"Masculine. Also: der Stuhl (chair), die Lampe (lamp).",example:"A: Ist die Lampe dabei?\nB: Nein, Sie brauchen eine Lampe.",exampleSrc:"A: Is the lamp included?\nB: No, you need a lamp.",funFact:"When you move into a German apartment, it often has NO lamps, no kitchen cabinets, sometimes no floor. You bring EVERYTHING."},
{type:"teach",trg:"die Möbel",src:"the furniture",note:"Always plural! One piece = ein Möbelstück.",example:"A: Sind Möbel dabei?\nB: Nein, keine Möbel.",exampleSrc:"A: Is furniture included?\nB: No, no furniture.",funFact:"'Möbel' is always plural. There is no singular 'ein Möbel.' You say 'ein Möbelstück' (a furniture-piece). Germans are precise."},
{type:"teach",trg:"die Ordnung",src:"the order / tidiness",note:"Feminine. 'Ordnung muss sein!' = There must be order!",example:"A: Die Ordnung ist wichtig.\nB: Ja, Ordnung muss sein!",exampleSrc:"A: Order is important.\nB: Yes, there must be order!",funFact:"Hildi's 'Hausordnung' literally means 'house-order.' Rules for everything. Germans have Ordnung for everything."},
{type:"teach",trg:"die Reparatur",src:"the repair",note:"Feminine. From Latin 'reparare.'",example:"A: Der Kühlschrank ist kaputt.\nB: Ich mache die Reparatur.",exampleSrc:"A: The fridge is broken.\nB: I will do the repair.",funFact:"If something breaks, call the Vermieter. Hildi handles all Reparaturen herself. Nothing stays broken in her building."},
{type:"teach",trg:"alleine",src:"alone",note:"Adverb. Also 'allein.' Both forms used interchangeably.",example:"A: Wohnst du alleine?\nB: Ja, ich wohne alleine.",exampleSrc:"A: Do you live alone?\nB: Yes, I live alone.",funFact:"'Wohnst du alleine?' is what every German landlord asks to gauge how many people will use the apartment."},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-apartment-tour",trg:"Hildi führt ihn durch die Wohnung. 'Das Wohnzimmer. 28 Quadratmeter.' Sie misst mit den Augen. 'Die Küche. Der Kühlschrank funktioniert. Der Boden ist neu.' Alles klingt wie ein Rechtsdokument.",src:"Hildi walks him through the apartment. 'The living room. 28 square meters.' She measures with her eyes. 'The kitchen. The fridge works. The floor is new.' Everything sounds like a legal document."},
{type:"teach",trg:"die Nebenkosten",src:"the utility costs",note:"Always plural. The hidden 'second rent.'",example:"A: Wie hoch sind die Nebenkosten?\nB: 200 Euro im Monat.",exampleSrc:"A: How much are the utility costs?\nB: 200 euros per month.",funFact:"Nebenkosten = costs BESIDE the rent: heating, water, trash, building insurance. The 'zweite Miete' (second rent). Always ask."},
{type:"teach",trg:"erklären",src:"to explain",note:"Regular verb. Also: empfehlen (to recommend, irregular).",example:"A: Können Sie das erklären?\nB: Natürlich. Ich erkläre alles.",exampleSrc:"A: Can you explain that?\nB: Of course. I explain everything.",funFact:"Hildi erklärt everything. In extreme detail. Whether you asked or not. Thoroughness is a virtue in German culture."},
{type:"teach",trg:"hinter",src:"behind",note:"Preposition. Also: zwischen (between), neben (next to).",example:"A: Wo ist der Schrank?\nB: Hinter der Tür.",exampleSrc:"A: Where is the wardrobe?\nB: Behind the door.",funFact:"Spatial prepositions answer 'wo?' (where). Full dative case comes in A2. For now, learn the positions."},
{type:"tip",title:"Spatial Prepositions: Where Things Are",text:"Three new position words:\n\nhinter = behind (hinter dem Schrank)\nzwischen = between (zwischen Küche und Bad)\nneben = next to (neben dem Fenster)\n\nThey combine with articles to describe where things are.\nThe full dative case comes in A2.\nFor now, learn the positions."},
{type:"mc",q:"Der Kühlschrank steht in der _____.",opts:["Küche","Schlafzimmer","Garten","Dach"],ans:"Küche",hint:"Where do you keep food cold?"},
{type:"fb",s:"Das Wohnzimmer ist {1} der Küche und dem Schlafzimmer.",a:["zwischen"],opts:["zwischen","hinter","neben","unter"],hint:"The living room is in the MIDDLE of two other rooms.",sSrc:"The living room is {1} the kitchen and the bedroom."},
{type:"mc",q:"Wo ist die Toilette? _____ dem Bad.",opts:["Neben","Hinter","Zwischen","Auf"],ans:"Neben",hint:"The toilet room is right next to the bathroom."},
{type:"match",pairs:[{trg:"die Küche",src:"the kitchen"},{trg:"das Bad",src:"the bathroom"},{trg:"die Treppe",src:"the stairs"},{trg:"die Toilette",src:"the restroom"},{trg:"der Raum",src:"the room/space"}]},
{type:"mc",q:"'Die Möbel _____ neu.'",opts:["ist","sind","hat","bist"],ans:"sind",hint:"Möbel is always plural. Which plural verb form?"}
]},

// ─── L4: Aufräumen, einziehen, umziehen ───
{id:"deu_r3l4",title:"Aufräumen, einziehen, umziehen",icon:"📦",xp:15,board:true,steps:[
{type:"intro",title:"Trennbare Verben",desc:"Some German verbs split in two. The prefix flies to the end of the sentence like a boomerang. Time to master separable verbs and complete the possessives.",goals:["Separable verb conjugation","Remaining possessives: ihr, unser","Home action verbs"]},
{type:"tip",title:"Separable Verbs: The Boomerang Prefix",text:"Some German verbs split in present tense.\n\naufräumen (to tidy up) becomes:\nIch räume auf. (I tidy up.)\n\nThe prefix (auf-) goes to the END.\nCommon separable prefixes: auf-, ein-, um-, mit-, an-, ab-, aus-.\n\nIf the prefix can stand alone as a word, the verb is probably separable."},
{type:"teach",trg:"aufräumen",src:"to tidy up",note:"Separable: ich räume auf, du räumst auf, er räumt auf.",example:"A: Räumst du auf?\nB: Ja, ich räume gerade auf.",exampleSrc:"A: Are you tidying up?\nB: Yes, I am tidying up right now.",funFact:"Hildi's favorite verb. 'Räumen Sie bitte auf!' The 'auf' flies to the end. German apartments must be aufgeräumt at all times."},
{type:"teach",trg:"einziehen",src:"to move in",note:"Separable: ich ziehe ein. Opposite: ausziehen (move out).",example:"A: Wann ziehst du ein?\nB: Ich ziehe morgen ein.",exampleSrc:"A: When are you moving in?\nB: I am moving in tomorrow.",funFact:"The opposite 'ausziehen' (move out) separates the same way. 'Ausziehen' also means 'to undress.' Context saves you."},
{type:"teach",trg:"umziehen",src:"to move / relocate",note:"Separable when stressed on UM-: wir ziehen um.",example:"A: Wir ziehen nächste Woche um.\nB: Wohin zieht ihr um?",exampleSrc:"A: We are moving next week.\nB: Where are you moving to?",funFact:"Two meanings depending on stress: UMziehen (separable) = to relocate. umZIEHEN (inseparable) = to change clothes. Stress matters!"},
{type:"teach",trg:"anmachen",src:"to turn on / switch on",note:"Separable: mach das Licht an! Opposite: ausmachen.",example:"A: Machst du das Licht an?\nB: Nein, ich mache es aus.",exampleSrc:"A: Are you turning the light on?\nB: No, I am turning it off.",funFact:"'An' and 'aus' are opposites. Both separable. Hildi's Hausordnung has rules about when to anmachen and ausmachen the hallway lights."},
{type:"teach",trg:"ausmachen",src:"to turn off / switch off",note:"Separable: mach das Licht aus!",example:"A: Mach bitte das Licht aus.\nB: Okay, ich mache es aus.",exampleSrc:"A: Please turn the light off.\nB: Okay, I am turning it off.",funFact:"'Ausmachen' also means 'to matter': 'Das macht nichts aus' = that does not matter. One verb, two very different meanings."},
{type:"teach",trg:"anziehen",src:"to put on / get dressed",note:"Separable: ich ziehe mich an. Also: to attract.",example:"A: Was ziehst du an?\nB: Das sieht gut aus!",exampleSrc:"A: What are you putting on?\nB: That looks good!",funFact:"'Anziehen' also means 'to attract' (einen Magneten anziehen). Three meanings: get dressed, put on clothes, attract."},
{type:"teach",trg:"putzen",src:"to clean (surfaces)",note:"Regular: ich putze, du putzt. Surface cleaning.",example:"A: Ich putze die Fenster.\nB: Und ich wasche die Kleidung.",exampleSrc:"A: I am cleaning the windows.\nB: And I am washing the clothes.",funFact:"'Putzen' is surface cleaning (floors, windows). 'Waschen' is water cleaning (clothes, hands). 'Baden' is soaking in a tub. Germans distinguish."},
{type:"teach",trg:"waschen",src:"to wash",note:"Irregular: ich wasche, du wäschst, er wäscht.",example:"A: Wäschst du die Kleidung?\nB: Ja, ich wasche alles.",exampleSrc:"A: Are you washing the clothes?\nB: Yes, I am washing everything.",funFact:"'Waschen' has a stem vowel change: a becomes ä in du/er forms. Like fahren to fährst. The strong verbs strike again."},
{type:"verb_table",title:"waschen (to wash)",groups:[{label:"Present tense (stem change: a → ä)",rows:[{pronoun:"ich",form:"wasche",src:"I wash"},{pronoun:"du",form:"wäschst",src:"you wash"},{pronoun:"er/sie/es",form:"wäscht",src:"he/she/it washes"},{pronoun:"wir",form:"waschen",src:"we wash"},{pronoun:"ihr",form:"wascht",src:"you all wash"},{pronoun:"sie/Sie",form:"waschen",src:"they/you (formal) wash"}]}],note:"Same a → ä pattern as fahren and schlafen."},
{type:"teach",trg:"funktionieren",src:"to function / to work",note:"Regular: der Kühlschrank funktioniert.",example:"A: Funktioniert die Lampe?\nB: Nein, sie funktioniert nicht.",exampleSrc:"A: Does the lamp work?\nB: No, it does not work.",funFact:"Germans love this verb for machines and systems. If something 'funktioniert nicht,' prepare for a 3-week repair wait."},
{type:"teach",trg:"unterschreiben",src:"to sign",note:"Inseparable! unter- stays attached: ich unterschreibe.",example:"A: Vermieten Sie die Wohnung?\nB: Ja, unterschreiben Sie hier.",exampleSrc:"A: Are you renting out the apartment?\nB: Yes, sign here.",funFact:"'Unter' + 'schreiben' = write-under. Inseparable because 'unter-' cannot stand alone as a preposition here. The prefix stays glued."},
{type:"teach",trg:"vermieten",src:"to rent out (as landlord)",note:"Inseparable! ver- stays: ich vermiete.",example:"A: Vermieten Sie die Wohnung?\nB: Ja, ab sofort.",exampleSrc:"A: Are you renting out the apartment?\nB: Yes, starting now.",funFact:"'Vermieten' is the landlord's side of 'mieten.' Hildi vermietet streng aber fair (strict but fair)."},
{type:"teach",trg:"möglich",src:"possible",note:"Adjective. 'Ist das möglich?' = Is that possible?",example:"A: Ist ein Hund möglich?\nB: Nein, das ist nicht möglich.",exampleSrc:"A: Is a dog possible?\nB: No, that is not possible.",funFact:"'Möglichkeit' = possibility. Hildi on pets: 'Haustiere sind nicht möglich.' End of discussion."},
{type:"mc",q:"'Ich _____ morgen _____.' (einziehen)",opts:["ziehe...ein","einziehe","ziehe...um","räume...ein"],ans:"ziehe...ein",hint:"Moving IN, not relocating. The prefix separates in present tense."},
{type:"mc",q:"'Hildi _____ jeden Tag _____.' (aufräumen)",opts:["räumt...auf","aufräumt","putzt...auf","räumt...ein"],ans:"räumt...auf",hint:"Third person singular of this verb. Remember: the prefix separates to the end."},
{type:"fb",s:"Wir ziehen nächste Woche {1}.",a:["um"],opts:["um","auf","ein","aus"],hint:"Relocating, not moving in. Which prefix means 'around/re-'?",sSrc:"We are moving {1} next week."},
{type:"mc",q:"'Mach das Licht _____!' (turn on)",opts:["an","aus","auf","ein"],ans:"an",hint:"Switching ON, not off. Which prefix?"},
{type:"tip",title:"Possessive Articles: Full Set",text:"mein (my), dein (your), sein (his)\nihr (her / their), unser (our)\neuer (your, plural), Ihr (your, formal)\n\nALL follow the ein-pattern:\nno ending for der/das-nouns\n-e ending for die-nouns and plurals\n\nmein Bruder, meine Schwester, mein Kind\nihr Bruder, ihre Schwester, ihr Kind"},
{type:"teach",trg:"ihr / ihre",src:"her / their",note:"'Ihr' means BOTH 'her' and 'their.' Context decides.",example:"A: Ist das ihr Schlüssel?\nB: Ja, das ist ihre Wohnung.",exampleSrc:"A: Is that her key?\nB: Yes, that is her apartment.",funFact:"Capital 'Ihr' = formal 'your.' Lowercase 'ihr' = her or their. Three meanings in two letters. Welcome to German pronouns."},
{type:"teach",trg:"unser / unsere",src:"our",note:"Unser for der/das-nouns. Unsere for die-nouns and plurals.",example:"A: Ist das unsere Küche?\nB: Ja, das ist unser Bad.",exampleSrc:"A: Is that our kitchen?\nB: Yes, that is our bathroom.",funFact:"'Unser' sometimes loses the -e- in casual speech: 'unsre Wohnung.' But Hildi would NEVER abbreviate."},
{type:"teach",trg:"der Baum",src:"the tree",note:"Masculine. Plural: die Bäume.",example:"A: Der Baum im Garten ist groß.\nB: Ja, sehr groß!",exampleSrc:"A: The tree in the garden is big.\nB: Yes, very big!",funFact:"'Baum' is cognate with English 'beam' (originally a tree trunk). 'Weihnachtsbaum' = Christmas tree."},
{type:"teach",trg:"Liebling-",src:"favorite (prefix)",note:"Attach to any noun: Lieblingsfarbe, Lieblingsessen.",example:"A: Was ist dein Lieblingsessen?\nB: Pizza!",exampleSrc:"A: What is your favorite food?\nB: Pizza!",funFact:"Just attach 'Lieblings-' to any noun to make it 'favorite.' Lieblingsbuch, Lieblingslied, Lieblingsstadt. Infinite favorites."},
{type:"mc",q:"'Das ist _____ Wohnung.' (our)",opts:["unsere","unser","mein","seine"],ans:"unsere",hint:"'Our' with a die-noun. Die Wohnung needs the -e ending."},
{type:"fb",s:"Frau Müller sagt: '{1} Kinder spielen im Garten.'",a:["Meine"],opts:["Meine","Seine","Unsere","Ihre"],hint:"She is talking about her OWN children. Plural possessive needs -e ending.",sSrc:"Frau Müller says: '{1} children are playing in the garden.'"},
{type:"mc",q:"Which verb is separable?",opts:["funktionieren","unterschreiben","anmachen","reparieren"],ans:"anmachen",hint:"Separable prefixes can stand alone as words: an, auf, ein, um, aus."},
{type:"mc",q:"'Das _____ gut _____!' (aussehen)",opts:["sieht...aus","aussieht","sieht...an","macht...aus"],ans:"sieht...aus",hint:"'That looks good.' The prefix 'aus' separates to the end."},
{type:"match",pairs:[{trg:"aufräumen",src:"to tidy up"},{trg:"einziehen",src:"to move in"},{trg:"anmachen",src:"to turn on"},{trg:"ausmachen",src:"to turn off"},{trg:"vermieten",src:"to rent out"}]}
]},

// ─── L5: Alles muss raus! ───
{id:"deu_r3l5",title:"Alles muss raus!",icon:"🛋️",xp:15,board:true,steps:[
{type:"intro",title:"Möbel und Plurale",desc:"The apartment is empty. Verumius needs EVERYTHING. Time to learn furniture, adjectives, and the five German plural patterns.",goals:["Furniture vocabulary","Noun plural patterns","Welch-/jed-/all- words"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-empty-apartment",trg:"Verumius schickt Lena ein Foto der leeren Wohnung. 'Keine Möbel?' 'Nein. Alles leer. Ich brauche ALLES.' 'Willkommen in Deutschland. Dein Kühlschrank, dein Problem.'",src:"Verumius sends Lena a photo of the empty apartment. 'No furniture?' 'No. All empty. I need EVERYTHING.' 'Welcome to Germany. Your fridge, your problem.'"},
{type:"teach",trg:"das Bett",src:"the bed",note:"Neuter. Plural: die Betten.",example:"A: Ich brauche ein Bett.\nB: Und einen Schrank.",exampleSrc:"A: I need a bed.\nB: And a wardrobe.",funFact:"German apartments often come WITHOUT a wardrobe. You buy, install, and remove it when you leave. Yes, really."},
{type:"teach",trg:"der Schrank",src:"the wardrobe / cabinet",note:"Masculine. Plural: die Schränke.",example:"A: Wo steht der Schrank?\nB: Im Schlafzimmer.",exampleSrc:"A: Where is the wardrobe?\nB: In the bedroom.",funFact:"'Kühlschrank' = cool cabinet. 'Kleiderschrank' = clothes cabinet. German compound logic at its finest."},
{type:"teach",trg:"der Computer",src:"the computer",note:"Masculine. Borrowed from English, German pronunciation.",example:"A: Hast du einen Computer?\nB: Ja, er steht auf dem Tisch.",exampleSrc:"A: Do you have a computer?\nB: Yes, it is on the table.",funFact:"Germans say 'Computer' with German pronunciation: com-PYOO-ter. The word 'Rechner' (calculator) is the German alternative but less common."},
{type:"teach",trg:"der Fernseher",src:"the TV / television",note:"Masculine. Literally: far-seer.",example:"A: Hast du einen Fernseher?\nB: Nein, nur einen Computer.",exampleSrc:"A: Do you have a TV?\nB: No, only a computer.",funFact:"'Fernseher' literally means 'far-seer.' German loves descriptive compounds. English 'television' does the same: tele(far) + vision(seeing)."},
{type:"teach",trg:"das Regal",src:"the shelf / bookcase",note:"Neuter. FALSE FRIEND: not 'regal' (royal)!",example:"A: Wo steht das Regal?\nB: Im Wohnzimmer.",exampleSrc:"A: Where is the bookcase?\nB: In the living room.",funFact:"'Regal' in German = shelf unit. In English 'regal' = royal. Completely different words that look identical. A classic false friend."},
{type:"teach",trg:"der Herd",src:"the stove / cooker",note:"Masculine. May belong to previous tenant, not landlord!",example:"A: Hat die Küche einen Herd?\nB: Ja, der Herd ist neu.",exampleSrc:"A: Does the kitchen have a stove?\nB: Yes, the stove is new.",funFact:"'Herd' comes from the same root as English 'hearth.' In German apartments, you may need to buy your own stove. The previous tenant takes theirs."},
{type:"teach",trg:"das Sofa",src:"the sofa / couch",note:"Neuter. Same word in English, French, and German.",example:"A: Wo ist das Sofa?\nB: Im Wohnzimmer.",exampleSrc:"A: Where is the sofa?\nB: In the living room.",funFact:"Originally from Arabic 'suffah' (bench). 'Couchkartoffel' = couch potato. Yes, Germans translated that idiom literally."},
{type:"teach",trg:"das Licht",src:"the light",note:"Neuter. 'Mach das Licht an!' = Turn the light on!",example:"A: Das Licht ist aus.\nB: Mach das Licht an!",exampleSrc:"A: The light is off.\nB: Turn the light on!",funFact:"'Feuer' (fire) is also neuter: das Feuer. Hildi's Hausordnung, paragraph 9: no open Feuer in the apartment."},
{type:"teach",trg:"der Aufzug",src:"the elevator / lift",note:"Masculine. Literally: up-pull.",example:"A: Gibt es einen Aufzug?\nB: Nein, keinen Aufzug. Nur die Treppe.",exampleSrc:"A: Is there an elevator?\nB: No elevator. Only the stairs.",funFact:"Many older German buildings have no Aufzug. Hildi's building: 4th floor, kein Aufzug. Your groceries, your problem."},
{type:"tip",title:"The Five Plural Patterns",text:"German has 5 main plural patterns:\n\n1. -e: der Tisch, die Tische\n2. -er: das Kind, die Kinder\n3. -en/-n: die Lampe, die Lampen\n4. -s: das Auto, die Autos\n5. No change: das Zimmer, die Zimmer\n\nSome add umlaut: der Stuhl, die Stühle\nALL plurals use 'die' as article."},
{type:"teach",trg:"frei",src:"free / available",note:"Adjective. 'Wohnung frei' = apartment available.",example:"A: Ist die Wohnung frei?\nB: Ja, sie ist frei.",exampleSrc:"A: Is the apartment available?\nB: Yes, it is available.",funFact:"'Eintritt frei' = free entry. 'Frei' means both 'available' and 'free of charge.' Context decides."},
{type:"teach",trg:"zu",src:"too / to",note:"Swiss Army knife word: zu groß (too big), zu Hause (at home).",example:"A: Die Wohnung ist zu klein.\nB: Nein, sie ist groß genug.",exampleSrc:"A: The apartment is too small.\nB: No, it is big enough.",funFact:"'Zu' has endless uses: 'zu groß' (too big), 'zu Hause' (at home), 'zum Bahnhof' (to the station). One tiny word, endless power."},
{type:"teach",trg:"alle",src:"everyone / all (people)",note:"Plural pronoun for people. 'Alles' = everything (things).",example:"A: Ist alles klar?\nB: Ja, alles klar!",exampleSrc:"A: Is everything clear?\nB: Yes, all clear!",funFact:"'Alle' = all people. 'Alles' = all things. 'Alles klar?' (everything clear?) is the most German response to any explanation."},
{type:"teach",trg:"jeder / jede / jedes",src:"every / each",note:"Follows der/die/das pattern: jeder (m), jede (f), jedes (n).",example:"A: Jeder Tag ist anders.\nB: Ja, jede Woche auch.",exampleSrc:"A: Every day is different.\nB: Yes, every week too.",funFact:"'Jeden Tag' = every day. The accusative form. 'Jeder' follows the same ending pattern as der/die/das."},
{type:"teach",trg:"welcher / welche / welches",src:"which",note:"Same pattern: welcher (m), welche (f), welches (n).",example:"A: Welches Zimmer?\nB: Das Schlafzimmer.",exampleSrc:"A: Which room?\nB: The bedroom.",funFact:"'Welche Farbe?' = which color? 'Welcher' follows der/die/das endings. Learn one pattern, decode three words."},
{type:"mc",q:"Plural of 'der Stuhl'?",opts:["die Stuhle","die Stühle","die Stühlen","die Stuhl"],ans:"die Stühle",hint:"Pattern 1: -e ending plus umlaut on the vowel. All plurals use 'die.'"},
{type:"mc",q:"Plural of 'das Kind'?",opts:["die Kinder","die Kindes","die Kinden","die Kinds"],ans:"die Kinder",hint:"Pattern 2 adds -er. Apply it to 'Kind.'"},
{type:"fb",s:"Die Lampe -> die {1}",a:["Lampen"],opts:["Lampen","Lampes","Lampeer","Lampe"],hint:"Die-nouns often just add -n. Pattern 3.",sSrc:"The lamp -> the {1} (plural)."},
{type:"mc",q:"'_____ Zimmer ist das Schlafzimmer?'",opts:["Welches","Welcher","Welche","Welchem"],ans:"Welches",hint:"Das Zimmer is neuter. Which welch- form matches das?"},
{type:"fb",s:"{1} Tag räumt Hildi auf.",a:["Jeden"],opts:["Jeden","Jede","Jedes","Jeder"],hint:"'Every day.' Der Tag is masculine, accusative case here.",sSrc:"{1} day Hildi tidies up."},
{type:"match",pairs:[{trg:"das Bett",src:"the bed"},{trg:"der Herd",src:"the stove"},{trg:"das Sofa",src:"the sofa"},{trg:"der Aufzug",src:"the elevator"},{trg:"das Licht",src:"the light"}]},
{type:"mc",q:"Die Wohnung ist _____. (available)",opts:["frei","allein","eigen","besonder"],ans:"frei",hint:"Available for renting. Not lonely, not special, not own."},
{type:"mc",q:"'_____ ist neu in der Wohnung.' (everything)",opts:["Alles","Alle","All","Aller"],ans:"Alles",hint:"Referring to things, not people. Which form means 'everything'?"},
{type:"mc",q:"'Kein _____. Wir nehmen die Treppe.'",opts:["Aufzug","Herd","Sofa","Licht"],ans:"Aufzug",hint:"No elevator. We take the stairs instead."}
]},

// ─── L6: Die Hausordnung ───
{id:"deu_r3l6",title:"Die Hausordnung",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"Die Hausordnung",desc:"Hildi opens a massive binder. 14 pages of rules. Three and a half hours later, Verumius has an apartment. And a Hausordnung.",goals:["Conjunctions: also, denn","Reflexive pronoun: sich","Rent calculation with numbers"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-hausordnung",trg:"Der Küchentisch. Zwei Tassen Tee, unberührt. Ein riesiger Ordner: 'HAUSORDNUNG' in Schreibmaschinenschrift. Hildi öffnet Seite 1. Die Uhr zeigt 14:15.",src:"The kitchen table. Two cups of tea, untouched. A massive binder: 'HAUSORDNUNG' in typewriter font. Hildi opens page 1. The clock reads 14:15."},
{type:"teach",trg:"also",src:"so / therefore",note:"FALSE FRIEND: does NOT mean 'also' in English!",example:"A: Also, die Miete ist 650 Euro.\nB: Also gut. Und die Nebenkosten?",exampleSrc:"A: So, the rent is 650 euros.\nB: Alright then. And the utilities?",funFact:"'Also' in German means 'so/therefore,' NOT 'also.' This false friend traps every English speaker. 'Auch' is the German word for 'also.'"},
{type:"teach",trg:"denn",src:"because / since (conjunction)",note:"Coordinating conjunction. Does NOT change word order.",example:"A: Ich putze, denn Hildi kommt.\nB: Gute Idee!",exampleSrc:"A: I am cleaning, because Hildi is coming.\nB: Good idea!",funFact:"'Denn' as a conjunction means 'because.' But 'denn' as a particle adds curiosity: 'Was ist denn das?' (What IS that?). Two lives, one tiny word."},
{type:"teach",trg:"sich",src:"oneself (reflexive pronoun)",note:"Third person reflexive: er wäscht sich = he washes himself.",example:"A: Er wäscht sich.\nB: Sie wäscht sich auch.",exampleSrc:"A: He washes himself.\nB: She washes herself too.",funFact:"'Sich' is for er/sie/es/sie(pl). You will see it everywhere in German. Full reflexive verbs come in A2. For now, just recognize it."},
{type:"teach",trg:"beide",src:"both",note:"'Beide Zimmer sind groß.' Refers to exactly two items.",example:"A: Ich vergleiche beide Wohnungen.\nB: Beide sind schön.",exampleSrc:"A: I am comparing both apartments.\nB: Both are nice.",funFact:"'Beide' always refers to exactly two. For more than two, use 'alle.' 'Beide' and English 'both' are cognates."},
{type:"teach",trg:"teilen",src:"to share / to divide",note:"Regular verb. 'Wir teilen die Kosten.'",example:"A: Teilen wir die Miete?\nB: Ja, wir teilen alles.",exampleSrc:"A: Shall we split the rent?\nB: Yes, we share everything.",funFact:"'Teilen' means both 'to share' and 'to divide.' Like English 'to split.' Social media: 'Teile diesen Beitrag' = share this post."},
{type:"teach",trg:"schicken",src:"to send",note:"Regular: ich schicke, du schickst.",example:"A: Schick mir eine Nachricht.\nB: Okay, ich schicke sie jetzt.",exampleSrc:"A: Send me a message.\nB: Okay, I am sending it now.",funFact:"'Schicken' is the everyday word for sending. 'Senden' is more formal (broadcasting). 'Ich schicke dir eine SMS' = I'll text you."},
{type:"teach",trg:"die Blume",src:"the flower",note:"Feminine. Plural: die Blumen.",example:"A: Die Blumen sind schön.\nB: Danke, sie sind für dich.",exampleSrc:"A: The flowers are beautiful.\nB: Thanks, they are for you.",funFact:"Hildi has Blumen on every windowsill. German landladies judge you by your Blumen. 'Blumenkohl' = cauliflower (flower-cabbage)."},
{type:"teach",trg:"die Hilfe",src:"the help",note:"Feminine. 'Hilfe!' = Help! 'Erste Hilfe' = first aid.",example:"A: Brauchst du Hilfe?\nB: Ja, bitte! Hilfe!",exampleSrc:"A: Do you need help?\nB: Yes, please! Help!",funFact:"'Hilfe!' is one of the first German words tourists learn. Verumius may need Hilfe understanding Hildi's 14-page Hausordnung."},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-recycling",trg:"Montage. Die Uhr: 14:45... 15:30... 16:00. Hildi hat nicht aufgehört. 'Paragraph 7: Mülltrennung.' Sie zeigt auf ein Wandbild mit SECHS Recycling-Kategorien. Verumius' Augen werden groß. Der Tee ist komplett kalt.",src:"Montage. The clock: 14:45... 15:30... 16:00. Hildi has not stopped. 'Paragraph 7: Waste separation.' She points to a wall chart with SIX recycling categories. Verumius's eyes widen. The tea is completely cold."},
{type:"tip",title:"Numbers for Rent",text:"Rent math in German:\n\n100 = hundert\n200 = zweihundert\n650 = sechshundertfünfzig\n\n'Die Miete kostet 650 Euro.'\nNebenkosten stated separately:\n'Plus 200 Euro Nebenkosten.'\nTotal: '850 Euro warm.'\n\nAlways ask: 'Ist das warm oder kalt?'"},
{type:"mc",q:"Die Miete: 750 Euro. Nebenkosten: 150 Euro. Warm: _____ Euro.",opts:["900","750","600","850"],ans:"900",hint:"Warmmiete = Miete + Nebenkosten. Add the two numbers."},
{type:"fb",s:"Ich putze jeden Tag, {1} Hildi das möchte.",a:["denn"],opts:["denn","also","aber","und"],hint:"Giving a reason. 'Because' Hildi wants it.",sSrc:"I clean every day, {1} Hildi wants it that way."},
{type:"mc",q:"'Er wäscht _____.' (himself)",opts:["sich","mich","dich","uns"],ans:"sich",hint:"He washes HIMself. Third person reflexive pronoun."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-hildi-signing",trg:"Hildi schließt den Ordner. 'Haben Sie Fragen?' Verumius: 'Also... die Miete?' '650 Euro plus 200 Nebenkosten. 850 warm.' Pause. 'Und... wann kann ich einziehen?' Hildi lächelt fast. Fast. 'Unterschreiben Sie hier.'",src:"Hildi closes the binder. 'Any questions?' Verumius: 'So... the rent?' '650 euros plus 200 utilities. 850 warm.' Pause. 'And... when can I move in?' Hildi almost smiles. Almost. 'Sign here.'"},
{type:"mc",q:"'Ich vergleiche _____ Wohnungen.' (both)",opts:["beide","jede","alle","ander"],ans:"beide",hint:"Comparing two specific apartments. Not every or all."},
{type:"fb",s:"Die Wohnung kostet achthundertfünfzig Euro. Das ist {1} Euro.",a:["850"],opts:["850","750","580","805"],hint:"Acht-hundert-fünfzig. Break it apart: 800 + 50.",sSrc:"The apartment costs eight hundred and fifty euros. That is {1} euros."},
{type:"match",pairs:[{trg:"also",src:"so/therefore"},{trg:"denn",src:"because"},{trg:"beide",src:"both"},{trg:"sich",src:"oneself"},{trg:"die Hilfe",src:"the help"}]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-hildi-key",trg:"Verumius unterschreibt. Hildi gibt ihm den Schlüssel. Zum ersten Mal spricht sie leise: 'Möchten Sie... Tee? Frischen?' Die Kamera zeigt den Ordner, die Schlüssel, den kalten Tee. Hildi geht schon in die Küche. Verumius hält den Schlüssel und grinst. Die Uhr: 17:30. Dreieinhalb Stunden.",src:"Verumius signs. Hildi hands over the key. For the first time, she speaks softly: 'Would you like... tea? Fresh?' The camera shows the binder, the keys, the cold tea. Hildi is already walking to the kitchen. Verumius holds the key and grins. Clock: 17:30. Three and a half hours."}
]},

// ─── L7: Die Prüfung ───
{id:"deu_r3l7",title:"Die Prüfung",icon:"📝",xp:20,board:true,steps:[
{type:"intro",title:"Alles zusammen",desc:"Comprehensive quiz. Everything from Unit 3: family, home, furniture, separable verbs, possessives, plurals, and numbers.",goals:["Test all Unit 3 vocabulary","Test all 4 grammar constructs","Review through Verumius's moving story"]},
{type:"teach",trg:"packen",src:"to pack",note:"Regular: ich packe. 'Ich packe meinen Koffer.'",example:"A: Packst du schon?\nB: Ja, ich packe alles ein.",exampleSrc:"A: Are you packing already?\nB: Yes, I am packing everything.",funFact:"'Ich packe meinen Koffer' is a famous German memory game. Each player adds an item. Verumius is packing to move into Hildi's apartment."},
{type:"teach",trg:"wohin",src:"where to (direction)",note:"Wo = where (location). Wohin = where to (direction).",example:"A: Wohin gehst du?\nB: Ich gehe nach Hause.",exampleSrc:"A: Where are you going?\nB: I am going home.",funFact:"'Wo bist du?' (where are you?) vs 'Wohin gehst du?' (where are you going?). Germans distinguish strictly between location and direction."},
{type:"teach",trg:"der Blick",src:"the view / glance",note:"Masculine. 'Der Blick aus dem Fenster.'",example:"A: Der Blick ist wunderbar.\nB: Ja, man sieht ganz Berlin!",exampleSrc:"A: The view is wonderful.\nB: Yes, you can see all of Berlin!",funFact:"Hildi's apartment has a Blick over the Prenzlauer Berg rooftops. Worth the Hausordnung."},
{type:"mc",q:"'Meine Mutter und mein Vater sind meine _____.'",opts:["Eltern","Geschwister","Kinder","Enkel"],ans:"Eltern",hint:"Mother + father together = what family unit?"},
{type:"fb",s:"Hildi räumt jeden Morgen {1}.",a:["auf"],opts:["auf","ein","um","aus"],hint:"Tidying UP. Which prefix got separated and sent to the end?",sSrc:"Hildi tidies {1} every morning."},
{type:"mc",q:"'Das ist _____ Küche.' (our)",opts:["unsere","unser","mein","seine"],ans:"unsere",hint:"'Our' with die Küche. Die-nouns need the -e ending."},
{type:"mc",q:"'_____ Stuhl möchten Sie?'",opts:["Welchen","Welcher","Welches","Welche"],ans:"Welchen",hint:"Der Stuhl is masculine. 'Möchten' uses accusative: welch-en."},
{type:"fb",s:"Zwei Kinder, drei {1}, vier Stühle.",a:["Betten"],opts:["Betten","Betts","Better","Bette"],hint:"Plural of das Bett. The -en pattern.",sSrc:"Two children, three {1}, four chairs."},
{type:"mc",q:"Miete: 550 Euro. Nebenkosten: 200 Euro. Warm: _____ Euro.",opts:["750","550","350","700"],ans:"750",hint:"Add rent + utilities for the Warmmiete."},
{type:"mc",q:"'Mein Bruder und _____ Schwester wohnen zusammen.' (his)",opts:["seine","sein","ihr","meine"],ans:"seine",hint:"HIS sister. Die Schwester needs the -e ending possessive."},
{type:"fb",s:"Der Fernseher steht {1} dem Bett und dem Schrank.",a:["zwischen"],opts:["zwischen","neben","hinter","vor"],hint:"The TV is in the MIDDLE of two furniture pieces.",sSrc:"The TV stands {1} the bed and the wardrobe."},
{type:"mc",q:"'Wir _____ nächste Woche _____.' (umziehen)",opts:["ziehen...um","umziehen","ziehen...ein","räumen...um"],ans:"ziehen...um",hint:"Relocating. The prefix separates in present tense."},
{type:"drag_fill",s:"Ich {1} morgen {2} und {3} die Wohnung {4}.",blanks:{"1":"ziehe","2":"ein","3":"räume","4":"auf"},pool:["ziehe","ein","räume","auf","um","putze"],hint:"Moving in AND tidying up. Two separable verbs in one sentence.",sSrc:"I {1} tomorrow {2} and {3} the apartment {4}."},
{type:"mc",q:"Plural of 'die Lampe'?",opts:["die Lampen","die Lampes","die Lampeen","die Lampe"],ans:"die Lampen",hint:"Die-nouns with -e ending typically just add -n."},
{type:"fb",s:"{1} gehst du?",a:["Wohin"],opts:["Wohin","Wo","Was","Wer"],hint:"Asking about direction/destination, not location.",sSrc:"{1} are you going?"},
{type:"mc",q:"Dreihundertfünfundsiebzig Euro = _____ Euro.",opts:["375","357","735","573"],ans:"375",hint:"Drei-hundert-fünf-und-siebzig: 300 + 5 + 70."},
{type:"match",pairs:[{trg:"aufräumen",src:"to tidy up"},{trg:"einziehen",src:"to move in"},{trg:"die Miete",src:"the rent"},{trg:"der Schlüssel",src:"the key"},{trg:"die Nebenkosten",src:"the utilities"}]},
{type:"mc",q:"'_____ Kinder spielen im Garten.' (all)",opts:["Alle","Alles","Jedes","Beide"],ans:"Alle",hint:"All children (people, plural). Not 'everything' (things)."},
{type:"fb",s:"Der {1} aus dem Fenster ist wunderbar.",a:["Blick"],opts:["Blick","Balkon","Boden","Baum"],hint:"The VIEW from the window. What you see when you look out.",sSrc:"The {1} from the window is wonderful."},
{type:"mc",q:"Verumius _____ seine Sachen. (packen)",opts:["packt","packen","putzt","räumt"],ans:"packt",hint:"He packs. Third person singular, regular verb."},
{type:"mc",q:"'_____ ist dein Lieblingsessen?'",opts:["Was","Welches","Wohin","Wer"],ans:"Was",hint:"Asking 'what' is your favorite food. No options presented."},
{type:"fb",s:"Ich brauche einen Schrank, ein Regal und zwei {1}.",a:["Stühle"],opts:["Stühle","Stuhle","Stühlen","Stuhl"],hint:"Plural of der Stuhl. Umlaut + -e pattern.",sSrc:"I need a wardrobe, a shelf, and two {1}."},
{type:"mc",q:"'Hildi erklärt _____ Hausordnung.' (every)",opts:["jede","jeder","jedes","alle"],ans:"jede",hint:"Die Hausordnung is feminine. Which 'every' matches die?"}
]},

// ─── L8: Willkommen zu Hause ───
{id:"deu_r3l8",title:"Willkommen zu Hause",icon:"🏡",xp:15,board:true,steps:[
{type:"intro",title:"Willkommen zu Hause",desc:"Moving day. Verumius opens the door with HIS key. Empty rooms, a view over Prenzlauer Berg, and a surprise from Hildi.",goals:["Review all Unit 3 content","German housing culture","Verumius's first home in Germany"]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-apartment-morning",trg:"Morgen. Verumius öffnet die Wohnungstür mit SEINEM Schlüssel. Sonnenlicht durch das Fenster. Leere Räume. Ein Blick über die Dächer von Prenzlauer Berg. Seine Kisten stehen im Flur. Eine ist beschriftet: 'KÜCHE.' Eine andere: 'SCHLAFZIMMER.' Eine dritte, in Lenas Handschrift: 'MUT.'",src:"Morning. Verumius opens the apartment door with HIS key. Sunlight through the window. Empty rooms. A view over the Prenzlauer Berg rooftops. His boxes are stacked in the hallway. One is labeled: 'KITCHEN.' Another: 'BEDROOM.' A third, in Lena's handwriting: 'COURAGE.'"},
{type:"tip",title:"German Housing Culture",text:"Moving in Germany is an EVENT.\n\nUmzug (the move) involves:\n1. Renting a Transporter (moving van)\n2. Recruiting friends with beer and pizza promises (Umzugsbier)\n3. Spending 3 days building IKEA furniture\n\nYour Nachbarn will judge how quickly you hang curtains.\nAnd Hildi will notice."},
{type:"mc",q:"'Verumius zieht heute _____.' (in)",opts:["ein","um","auf","aus"],ans:"ein",hint:"Moving INTO the apartment. Which separable prefix means 'in'?"},
{type:"tip",title:"Mülltrennung: Waste Separation",text:"Germany has up to 6 waste categories:\n\nBiomüll (organic)\nPapiermüll (paper)\nRestmüll (residual)\nGelber Sack (packaging)\nGlas (glass, sorted by color!)\nSondermüll (hazardous)\n\nGetting it wrong earns a note from your Nachbar.\nOr from Hildi."},
{type:"fb",s:"Die Küche ist {1} dem Wohnzimmer und dem Bad.",a:["zwischen"],opts:["zwischen","neben","hinter","vor"],hint:"The kitchen is in the MIDDLE of two rooms.",sSrc:"The kitchen is {1} the living room and the bathroom."},
{type:"mc",q:"'_____ Wohnung gehört Hildi.' (every)",opts:["Jede","Jeder","Jedes","Alle"],ans:"Jede",hint:"Die Wohnung is feminine. Which 'every' matches die?"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-hildi-plant",trg:"Verumius packt aus. Türklingel. Hildi, mit einer kleinen Pflanze. 'Für Ihre Fensterbank. Willkommen.' Sie sieht eine offene Kiste mit Tellern. 'Die Teller gehören ins Regal, nicht auf den Boden.' Sie dreht sich um und geht. Verumius stellt die Teller ins Regal.",src:"Verumius unpacks. Doorbell. Hildi, holding a small plant. 'For your windowsill. Welcome.' She sees an open box with plates. 'The plates belong on the shelf, not on the floor.' She turns and leaves. Verumius puts the plates on the shelf."},
{type:"tip",title:"The SCHUFA",text:"Germany's credit scoring system.\n\nEvery landlord demands a Schufa-Auskunft (credit report).\nNo SCHUFA = almost impossible to rent.\n\nNew arrivals with no German credit history face a Catch-22:\nNeed an apartment to build credit.\nNeed credit to get an apartment.\n\nVerumius got lucky. Hildi trusts punctuality over paperwork."},
{type:"mc",q:"'Seine Schwester und _____ Bruder kommen zum Umzug.' (his)",opts:["sein","seine","ihr","ihre"],ans:"sein",hint:"HIS brother. Der Bruder is masculine. No -e ending."},
{type:"fb",s:"Ich {1} alle Möbel für die Wohnung.",a:["brauche"],opts:["brauche","braucht","brauchen","brauchst"],hint:"'I need.' First person singular present tense.",sSrc:"I {1} all the furniture for the apartment."},
{type:"mc",q:"Plural of 'das Zimmer'?",opts:["die Zimmer","die Zimmers","die Zimmern","die Zimmere"],ans:"die Zimmer",hint:"Some nouns don't change in plural. Just the article switches to 'die.'"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-balkon-evening",trg:"Abend. Verumius auf dem Balkon. Lena ruft an. 'Wie ist die Wohnung?' 'Groß. Hell. Neben dem Schlafzimmer ist ein Garten.' 'Und Hildi?' 'Sie hat mir eine Pflanze geschenkt. Und dann meine Teller korrigiert.' 'Das ist Liebe, Verumius. Deutsche Liebe.'",src:"Evening. Verumius on the balcony. Lena calls. 'How is the apartment?' 'Big. Bright. Next to the bedroom is a garden.' 'And Hildi?' 'She gave me a plant. And then corrected my plates.' 'That is love, Verumius. German love.'"},
{type:"match",pairs:[{trg:"aufräumen",src:"to tidy up"},{trg:"die Nebenkosten",src:"utilities"},{trg:"das Schlafzimmer",src:"bedroom"},{trg:"wohin",src:"where to"},{trg:"beide",src:"both"}]},
{type:"mc",q:"Vierhundertneunundachtzig Euro = _____ Euro.",opts:["489","498","849","948"],ans:"489",hint:"Vier-hundert-neun-und-achtzig: 400 + 9 + 80."},
{type:"fb",s:"Hildi sagt: 'Die Teller gehören ins {1}, nicht auf den Boden.'",a:["Regal"],opts:["Regal","Küche","Balkon","Bett"],hint:"A piece of furniture with shelves where you store plates and cups.",sSrc:"Hildi says: 'The plates belong on the {1}, not on the floor.'"},
{type:"mc",q:"What does the Hausordnung regulate?",opts:["Quiet hours and shared spaces","Rent payments","Grocery shopping times","Bus schedules"],ans:"Quiet hours and shared spaces",hint:"The house rules document that every German apartment building has."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-apartment-night",trg:"Nacht. Die Wohnung ist halb ausgepackt. Eine Lampe beleuchtet das Wohnzimmer. Die Hausordnung liegt auf dem Tisch, bei Seite 1. Draußen leuchtet Prenzlauer Berg. Verumius' Handy vibriert. Eine Nachricht von Hildi: 'Die Ruhezeit beginnt um 22 Uhr. Gute Nacht.' Er lächelt. Macht das Licht aus.",src:"Night. The apartment is half-unpacked. One lamp illuminates the living room. The Hausordnung sits on the table, bookmarked at page 1. Outside, Prenzlauer Berg glows. Verumius's phone buzzes. A text from Hildi: 'Quiet hours begin at 10 PM. Good night.' He smiles. Turns off the light."}
]},

,

{id:"deu_r3l9",title:"Die ganze Familie",icon:"👨‍👩‍👧‍👦",xp:15,board:true,steps:[
{type:"intro",title:"Die ganze Familie",desc:"Verumius fills out forms for his new apartment. Time to learn all the family and personal vocabulary that German bureaucracy demands.",goals:["Describe family members and relationships","Fill in personal forms","Talk about people's ages and status"]},
{type:"teach",trg:"die Ehefrau",src:"the wife",note:"Feminine noun. Plural: die Ehefrauen. Formal word for wife.",example:"A: Ist das deine Ehefrau?\nB: Ja, das ist meine Ehefrau Maria.",exampleSrc:"A: Is that your wife?\nB: Yes, that is my wife Maria.",funFact:"'Ehe' means marriage, 'Frau' means woman. So Ehefrau = marriage-woman. Very literal, very German."},
{type:"teach",trg:"der Ehemann",src:"the husband",note:"Masculine noun. Plural: die Ehemänner. Formal word for husband.",example:"A: Wo ist dein Ehemann?\nB: Mein Ehemann ist bei der Arbeit.",exampleSrc:"A: Where is your husband?\nB: My husband is at work.",funFact:"Ehe + Mann = marriage-man. In everyday speech, 'mein Mann' (my man) is more common than 'mein Ehemann.'"},
{type:"teach",trg:"der Partner",src:"the partner (male)",note:"Masculine noun. Plural: die Partner. Used for unmarried couples.",example:"A: Wohnt dein Partner auch hier?\nB: Ja, wir wohnen zusammen.",exampleSrc:"A: Does your partner also live here?\nB: Yes, we live together.",funFact:"Germany was one of the first countries to offer registered partnerships (Lebenspartnerschaft). 'Partner' is gender-neutral in meaning but grammatically masculine."},
{type:"teach",trg:"die Partnerin",src:"the partner (female)",note:"Feminine noun. Plural: die Partnerinnen. Female form of Partner.",example:"A: Kommt deine Partnerin auch?\nB: Ja, meine Partnerin kommt später.",exampleSrc:"A: Is your partner coming too?\nB: Yes, my partner is coming later.",funFact:"German adds '-in' to make feminine forms: Partner/Partnerin, Lehrer/Lehrerin, Arzt/Ärztin. This is changing with gender-inclusive language debates."},
{type:"teach",trg:"die Großeltern",src:"the grandparents",note:"Plural noun (always plural). Großmutter + Großvater = Großeltern.",example:"A: Wo wohnen deine Großeltern?\nB: Meine Großeltern wohnen in Hamburg.",exampleSrc:"A: Where do your grandparents live?\nB: My grandparents live in Hamburg.",funFact:"'Groß' means big/great. So grandparents are literally 'great-parents.' Some families use Oma/Opa instead of the formal Großmutter/Großvater."},
{type:"teach",trg:"die Bekannte",src:"the acquaintance (female)",note:"Feminine noun. Male: der Bekannte. From 'bekannt' (known).",example:"A: Wer ist das?\nB: Das ist eine Bekannte von mir.",exampleSrc:"A: Who is that?\nB: That is an acquaintance of mine.",funFact:"In German social culture, the line between Bekannte (acquaintance) and Freund (friend) is sharp. Germans may know someone for years and still call them a Bekannte."},
{type:"teach",trg:"die Verwandte",src:"the relative (female)",note:"Feminine noun. Male: der Verwandte. Related to 'verwandt' (related).",example:"A: Hast du Verwandte in Berlin?\nB: Ja, eine Verwandte wohnt in Kreuzberg.",exampleSrc:"A: Do you have relatives in Berlin?\nB: Yes, a relative lives in Kreuzberg.",funFact:"'Verwandt' comes from 'wandeln' (to change/turn). Relatives are people who have 'turned toward' the same family tree."},
{type:"teach",trg:"die Hausfrau",src:"the housewife",note:"Feminine noun. Plural: die Hausfrauen.",example:"A: Was macht deine Mutter?\nB: Sie ist Hausfrau.",exampleSrc:"A: What does your mother do?\nB: She is a housewife.",funFact:"The word is falling out of favor in modern Germany. Many prefer 'Elternteil zu Hause' (parent at home) as a gender-neutral alternative."},
{type:"teach",trg:"der Hausmann",src:"the house husband / stay-at-home dad",note:"Masculine noun. Plural: die Hausmänner.",example:"A: Und dein Vater?\nB: Er ist Hausmann. Er kocht sehr gut!",exampleSrc:"A: And your father?\nB: He is a house husband. He cooks very well!",funFact:"Germany has generous parental leave (Elternzeit). More and more German fathers take time off. 'Hausmann' is becoming more common."},
{type:"teach",trg:"das Baby",src:"the baby",note:"Neuter noun. Plural: die Babys. Borrowed from English.",example:"A: Ist das euer Baby?\nB: Ja, sie heißt Emma.",exampleSrc:"A: Is that your baby?\nB: Yes, her name is Emma.",funFact:"German borrowed 'Baby' from English. Before that, the word was 'Säugling' (literally: suckling). 'Baby' won because it is shorter and cuter."},
{type:"teach",trg:"die Erwachsene",src:"the adult (female)",note:"Feminine noun. Male: der Erwachsene. From 'erwachsen' (grown up).",example:"A: Ist das Ticket für Erwachsene?\nB: Ja, Kinder zahlen weniger.",exampleSrc:"A: Is the ticket for adults?\nB: Yes, children pay less.",funFact:"'Erwachsen' literally means 'grown out of.' An adult is someone who has grown out of childhood. Same logic as English 'grown-up.'"},
{type:"teach",trg:"die Jugendliche",src:"the teenager / young person (female)",note:"Feminine noun. Male: der Jugendliche. From 'Jugend' (youth).",example:"A: Gibt es einen Rabatt für Jugendliche?\nB: Ja, Jugendliche zahlen die Hälfte.",exampleSrc:"A: Is there a discount for teenagers?\nB: Yes, teenagers pay half.",funFact:"In Germany, Jugendliche (14-17) have special legal status. They can work limited hours, see certain movies, and drink beer/wine at 16."},
{type:"teach",trg:"die Leute",src:"the people",note:"Plural only noun (no singular). Always 'die Leute.'",example:"A: Viele Leute sind hier!\nB: Ja, Berlin hat viele Leute.",exampleSrc:"A: Many people are here!\nB: Yes, Berlin has many people.",funFact:"'Leute' has no singular form. For one person, say 'der Mensch' (human) or 'die Person' (person). 'Leute' always means a group."},
{type:"mc",q:"Your neighbor introduces her partner. She says 'Das ist mein ___.' Which word fits for a male partner?",opts:["Ehemann","Ehefrau","Partnerin","Hausfrau"],ans:"Ehemann",hint:"She is introducing a male person she is married to."},
{type:"fb",s:"Meine {1} wohnen in Hamburg. Sie sind sehr alt.",a:["Großeltern"],opts:["Großeltern","Leute","Kinder","Freunde"],hint:"These family members are from the generation above your parents.",sSrc:"My {1} live in Hamburg. They are very old."},
{type:"mc",q:"You see a sign: 'Ermäßigung für Jugendliche.' Who gets the discount?",opts:["Teenagers","Seniors","Adults","Babies"],ans:"Teenagers",hint:"Jugendliche are young people, typically 14 to 17 years old."},
{type:"match",pairs:[{trg:"die Ehefrau",src:"wife"},{trg:"der Ehemann",src:"husband"},{trg:"die Großeltern",src:"grandparents"},{trg:"die Leute",src:"people"},{trg:"das Baby",src:"baby"},{trg:"die Verwandte",src:"relative"}]},
{type:"fb",s:"Das ist meine {1}. Sie wohnt auch in Berlin.",a:["Bekannte"],opts:["Bekannte","Freundin","Großeltern","Leute"],hint:"Not a close friend, just someone you know. An acquaintance.",sSrc:"This is my {1}. She also lives in Berlin."}
]},

{id:"deu_r3l10",title:"Zu Hause",icon:"🏡",xp:15,board:true,steps:[
{type:"intro",title:"Zu Hause",desc:"The apartment needs work. Broken things, missing furniture, and German has a word for everything around the house.",goals:["Describe your home and surroundings","Talk about household activities","Use prepositions unter and zwischen"]},
{type:"teach",trg:"das Apartment",src:"the apartment (small/furnished)",note:"Neuter noun. Plural: die Apartments. Often a furnished studio.",example:"A: Wohnst du in einem Apartment?\nB: Ja, ein kleines Apartment in Mitte.",exampleSrc:"A: Do you live in an apartment?\nB: Yes, a small apartment in Mitte.",funFact:"Germans distinguish: Apartment (small, often furnished), Wohnung (regular apartment), Haus (house). English just says 'apartment' for everything."},
{type:"teach",trg:"der Garten",src:"the garden",note:"Masculine noun. Plural: die Gärten. The umlaut appears in plural.",example:"A: Habt ihr einen Garten?\nB: Ja, ein kleiner Garten hinter dem Haus.",exampleSrc:"A: Do you have a garden?\nB: Yes, a small garden behind the house.",funFact:"Germans love their Kleingärten (allotment gardens). Berlin alone has over 70,000 Schrebergärten where city dwellers grow vegetables and grill."},
{type:"teach",trg:"der Stock",src:"the floor / story (of a building)",note:"Masculine noun. 'Im ersten Stock' = on the first floor (UK: ground+1).",example:"A: In welchem Stock wohnst du?\nB: Im dritten Stock.",exampleSrc:"A: Which floor do you live on?\nB: On the third floor.",funFact:"German floors start counting from zero: Erdgeschoss (ground floor) is 0, erster Stock is 1. Your '3rd floor' is Germany's '2nd floor.' Confusion guaranteed."},
{type:"teach",trg:"der Quadratmeter",src:"the square meter",note:"Masculine noun. Abbreviated: qm or m2. Used for apartment sizes.",example:"A: Wie groß ist die Wohnung?\nB: 65 Quadratmeter.",exampleSrc:"A: How big is the apartment?\nB: 65 square meters.",funFact:"German apartment ads always list size in qm. A typical Berlin 2-room apartment is 50-65 qm. Anything under 30 qm is a Mikrowohnung."},
{type:"teach",trg:"der Hund",src:"the dog",note:"Masculine noun. Plural: die Hunde.",example:"A: Darf ich einen Hund haben?\nB: Nein, Hunde sind hier verboten!",exampleSrc:"A: May I have a dog?\nB: No, dogs are forbidden here!",funFact:"Germany is very dog-friendly. Dogs ride the U-Bahn, sit in restaurants, and have their own tax: the Hundesteuer. Yes, you pay tax for your dog."},
{type:"teach",trg:"das Feuer",src:"the fire",note:"Neuter noun. Plural: die Feuer. Also means 'light' (for a cigarette).",example:"A: Feuer! Feuer!\nB: Ruf die Feuerwehr!",exampleSrc:"A: Fire! Fire!\nB: Call the fire department!",funFact:"'Feuerwehr' (fire defense), 'Feuerwerk' (fireworks), 'Feuerzeug' (fire-thing = lighter). German builds fire words like a construction kit."},
{type:"teach",trg:"die Hausaufgabe",src:"the homework",note:"Feminine noun. Plural: die Hausaufgaben. Literally: house-task.",example:"A: Hast du deine Hausaufgaben gemacht?\nB: Nein, ich hatte keine Zeit!",exampleSrc:"A: Did you do your homework?\nB: No, I had no time!",funFact:"Haus + Aufgabe = house + task. German school kids have been complaining about Hausaufgaben since the 1800s. Some German states are debating banning them."},
{type:"teach",trg:"aufstehen",src:"to get up / stand up",note:"Separable verb: ich stehe auf, du stehst auf.",example:"A: Wann stehst du auf?\nB: Ich stehe um sieben Uhr auf.",exampleSrc:"A: When do you get up?\nB: I get up at seven o'clock.",funFact:"Auf (up) + stehen (to stand) = to stand up. In separable verbs, the prefix flies to the end: 'Ich stehe morgen früh auf.' The verb literally splits in two."},
{type:"teach",trg:"baden",src:"to bathe / take a bath",note:"Regular verb: ich bade, du badest.",example:"A: Duschst du oder badest du?\nB: Ich bade gern. Das ist entspannend.",exampleSrc:"A: Do you shower or bathe?\nB: I like bathing. It is relaxing.",funFact:"Baden-Württemberg (a German state) is named after its famous baths. The Romans built thermal baths there 2,000 years ago. Baden literally means 'bathing.'"},
{type:"teach",trg:"öffnen",src:"to open",note:"Regular verb: ich öffne, du öffnest. Opposite: schließen.",example:"A: Können Sie das Fenster öffnen?\nB: Ja, natürlich.",exampleSrc:"A: Can you open the window?\nB: Yes, of course.",funFact:"Germans have strong opinions about fresh air: 'Lüften' (airing out) is a daily ritual. You open all windows for 5-10 minutes, even in winter. It is called Stoßlüften."},
{type:"teach",trg:"reparieren",src:"to repair / fix",note:"Regular verb: ich repariere, du reparierst. From Latin.",example:"A: Kannst du das reparieren?\nB: Nein, ich rufe einen Handwerker.",exampleSrc:"A: Can you repair that?\nB: No, I will call a repairman.",funFact:"Getting a Handwerker (repairman) in Germany is an adventure. Appointments are weeks away, and they give you a 4-hour window. Germans joke: 'Der Handwerker kommt zwischen 8 und 16 Uhr.'"},
{type:"teach",trg:"legen",src:"to lay / put (horizontally)",note:"Regular verb: ich lege. Different from stellen (put upright) and setzen (sit).",example:"A: Wohin soll ich das Buch legen?\nB: Leg es auf den Tisch.",exampleSrc:"A: Where should I put the book?\nB: Put it on the table.",funFact:"German distinguishes HOW you place things: legen (lay flat), stellen (stand up), hängen (hang). English just says 'put.' This drives English speakers crazy."},
{type:"teach",trg:"stellen",src:"to put / place (upright)",note:"Regular verb: ich stelle. For things that stand: bottles, glasses, books upright.",example:"A: Stell die Flasche in den Kühlschrank.\nB: Welchen Kühlschrank?",exampleSrc:"A: Put the bottle in the fridge.\nB: Which fridge?",funFact:"Stellen vs legen: a book lying flat on a table = legen. A book standing upright on a shelf = stellen. Germans are very precise about spatial positions."},
{type:"teach",trg:"allein",src:"alone / by oneself",note:"Adverb/adjective. Also spelled 'alleine' in casual speech.",example:"A: Wohnst du allein?\nB: Nein, ich wohne mit Hildi.",exampleSrc:"A: Do you live alone?\nB: No, I live with Hildi.",funFact:"Kevin allein zu Haus is the German title of 'Home Alone.' 'Allein' can mean lonely too: 'Ich fühle mich allein.' Context matters."},
{type:"teach",trg:"alt",src:"old",note:"Adjective. Comparative: älter. Superlative: am ältesten.",example:"A: Wie alt bist du?\nB: Ich bin 25 Jahre alt.",exampleSrc:"A: How old are you?\nB: I am 25 years old.",funFact:"'Wie alt bist du?' literally asks 'How old are you?' German uses 'alt' where English uses 'old.' Even babies: 'Das Baby ist drei Monate alt.'"},
{type:"teach",trg:"jung",src:"young",note:"Adjective. Comparative: jünger. Superlative: am jüngsten.",example:"A: Ist Berlin eine junge Stadt?\nB: Ja, viele junge Leute wohnen hier.",exampleSrc:"A: Is Berlin a young city?\nB: Yes, many young people live here.",funFact:"Alt and jung are perfect antonyms. The umlaut in jünger matches älter. Both change their vowel in comparative, just like English old/older, young/younger."},
{type:"teach",trg:"unter",src:"under / below / among",note:"Preposition. Takes dative (location) or accusative (movement).",example:"A: Wo ist die Katze?\nB: Unter dem Tisch.",exampleSrc:"A: Where is the cat?\nB: Under the table.",funFact:"'Unter uns' means 'between us' (a secret). 'Unter der Woche' means 'during the week.' German uses 'unter' for many situations where English uses different prepositions."},
{type:"teach",trg:"zwischen",src:"between / among",note:"Preposition. Takes dative (location) or accusative (movement).",example:"A: Wo ist die Bank?\nB: Zwischen dem Kino und der Post.",exampleSrc:"A: Where is the bank?\nB: Between the cinema and the post office.",funFact:"'Zwischen' and English 'tween/between' share the same root. Both come from the number two (zwei/two). Between = by two things."},
{type:"mc",q:"Hildi says: 'Stell die Flasche in den Kühlschrank.' What does 'stellen' mean?",opts:["to place upright","to lay flat","to hang up","to throw away"],ans:"to place upright",hint:"Think about how bottles are positioned. German has a specific verb for vertical placement."},
{type:"fb",s:"Wann {1} du morgens auf?",a:["stehst"],opts:["stehst","machst","gehst","legst"],hint:"The separable verb for getting out of bed. Prefix is 'auf.'",sSrc:"When do you {1} up in the mornings?"},
{type:"mc",q:"'Unter dem Tisch' means:",opts:["Under the table","On the table","Next to the table","Behind the table"],ans:"Under the table",hint:"'Unter' describes a position below something."},
{type:"match",pairs:[{trg:"der Garten",src:"garden"},{trg:"der Hund",src:"dog"},{trg:"das Feuer",src:"fire"},{trg:"alt",src:"old"},{trg:"jung",src:"young"},{trg:"allein",src:"alone"}]}
]},

{id:"deu_r3l11",title:"Wie siehst du aus?",icon:"👤",xp:15,board:true,steps:[
{type:"intro",title:"Wie siehst du aus?",desc:"Describing people, their appearance, and what they do at home. Plus some important verbs for daily life.",goals:["Describe people with adjectives","Use aussehen, ausziehen, gehören","Learn hell, kaputt, männlich, weiblich"]},
{type:"teach",trg:"hell",src:"bright / light (color)",note:"Adjective. Opposite: dunkel (dark). Also means 'clear.'",example:"A: Ist das Zimmer hell?\nB: Ja, sehr hell! Viel Sonne.",exampleSrc:"A: Is the room bright?\nB: Yes, very bright! Lots of sun.",funFact:"'Hellblau' = light blue, 'hellgrün' = light green. German builds color shades by adding 'hell' (light) or 'dunkel' (dark) as a prefix."},
{type:"teach",trg:"kaputt",src:"broken / out of order",note:"Adjective. Very common in everyday speech.",example:"A: Der Aufzug ist kaputt.\nB: Schon wieder? Das ist immer so!",exampleSrc:"A: The elevator is broken.\nB: Again? It is always like this!",funFact:"English borrowed 'kaput' from German (via French 'capot'). In German, 'Ich bin kaputt' means 'I am exhausted,' not 'I am broken.' People use it after a long day."},
{type:"teach",trg:"männlich",src:"male / masculine",note:"Adjective. Used on forms, not typically in casual speech.",example:"A: Geschlecht: männlich oder weiblich?\nB: Männlich.",exampleSrc:"A: Gender: male or female?\nB: Male.",funFact:"On German forms, you will see: männlich (m), weiblich (w), and increasingly divers (d) as a third gender option, recognized by law since 2018."},
{type:"teach",trg:"weiblich",src:"female / feminine",note:"Adjective. Used on forms. Related to 'Weib' (archaic word for woman).",example:"A: Ist die Katze männlich oder weiblich?\nB: Weiblich. Sie heißt Luna.",exampleSrc:"A: Is the cat male or female?\nB: Female. Her name is Luna.",funFact:"'Weiblich' comes from 'Weib,' an old German word for woman. Today 'Weib' is considered rude (like 'wench'). The adjective 'weiblich' survived and is perfectly normal."},
{type:"teach",trg:"aussehen",src:"to look / appear",note:"Separable verb: du siehst aus, er sieht aus. 'Wie siehst du aus?'",example:"A: Du siehst müde aus.\nB: Ja, ich habe schlecht geschlafen.",exampleSrc:"A: You look tired.\nB: Yes, I slept badly.",funFact:"Aus (out) + sehen (to see) = to look like. 'Gut aussehen' means to look good. 'Das sieht gut aus' means 'that looks good.' One of the most common separable verbs."},
{type:"teach",trg:"ausziehen",src:"to move out / to undress",note:"Separable verb: ich ziehe aus. Two meanings depending on context!",example:"A: Wann ziehst du aus?\nB: Nächsten Monat. Ich habe eine neue Wohnung.",exampleSrc:"A: When are you moving out?\nB: Next month. I have a new apartment.",funFact:"Ausziehen means 'to move out' AND 'to undress.' 'Ich ziehe die Schuhe aus' = I take off my shoes. 'Ich ziehe aus der Wohnung aus' = I move out. Context saves you."},
{type:"teach",trg:"gehören",src:"to belong to",note:"Regular verb with dative: 'Das gehört mir' = That belongs to me.",example:"A: Wem gehört das Buch?\nB: Das gehört mir!",exampleSrc:"A: Who does the book belong to?\nB: That belongs to me!",funFact:"'Gehören' uses dative: mir, dir, ihm, ihr. 'Das gehört mir' (that belongs to me), never 'mich.' This is one of the first dative verbs you learn."},
{type:"teach",trg:"euer",src:"your (plural, masculine/neuter)",note:"Possessive pronoun for 'ihr' (you all). Changes with gender: euer/eure.",example:"A: Ist das euer Hund?\nB: Ja, das ist unser Hund Max.",exampleSrc:"A: Is that your (plural) dog?\nB: Yes, that is our dog Max.",funFact:"'Euer' drops the middle 'e' when adding endings: eure (not euere), eurem (not euerem). This is for easier pronunciation. Even Germans sometimes stumble on this."},
{type:"teach",trg:"eure",src:"your (plural, feminine/plural)",note:"Feminine/plural form of 'euer.' 'Eure Wohnung' = your apartment.",example:"A: Wo ist eure Wohnung?\nB: Unsere Wohnung ist im dritten Stock.",exampleSrc:"A: Where is your (plural) apartment?\nB: Our apartment is on the third floor.",funFact:"Possessives in German: mein (my), dein (your-singular), sein/ihr (his/her), unser (our), euer (your-plural), ihr (their). All take the same endings."},
{type:"teach",trg:"unsre",src:"our (short form of unsere)",note:"Informal short form. Full form: unsere. 'Unsre Kinder' = our children.",example:"A: Sind das unsre Nachbarn?\nB: Ja, unsre neuen Nachbarn.",exampleSrc:"A: Are those our neighbors?\nB: Yes, our new neighbors.",funFact:"'Unsre' is the casual contraction of 'unsere.' Both are correct. You'll hear 'unsre' in speech and see 'unsere' in writing. Same as English 'our' vs. formal 'our.'"},
{type:"teach",trg:"weiter-",src:"further / onward (prefix)",note:"Separable prefix meaning 'continue.' Weitermachen = continue doing.",example:"A: Sollen wir weitermachen?\nB: Ja, machen wir weiter!",exampleSrc:"A: Should we continue?\nB: Yes, let's continue!",funFact:"'Weiter' turns any verb into 'keep doing X': weiterlesen (keep reading), weiterfahren (keep driving), weitersprechen (keep talking). One prefix, infinite possibilities."},
{type:"mc",q:"The elevator sign says 'Außer Betrieb.' Hildi says 'Er ist kaputt.' What does kaputt mean?",opts:["broken","new","expensive","fast"],ans:"broken",hint:"Something that does not work anymore. Out of order."},
{type:"fb",s:"Du {1} heute sehr müde aus.",a:["siehst"],opts:["siehst","machst","gehst","bist"],hint:"The separable verb for appearance. 'Aus' splits off to the end.",sSrc:"You {1} very tired today."},
{type:"mc",q:"'Wem gehört das Buch?' Which case does 'gehören' require?",opts:["Dative","Accusative","Nominative","Genitive"],ans:"Dative",hint:"The answer uses mir, dir, ihm, not mich, dich, ihn."},
{type:"fb",s:"Ist das {1} Hund?",a:["euer"],opts:["euer","eure","unser","mein"],hint:"You are asking a group of people about their male dog. Masculine possessive.",sSrc:"Is that {1} dog?"},
{type:"mc",q:"'Er zieht nächsten Monat aus.' What does 'ausziehen' mean here?",opts:["to move out","to undress","to arrive","to stay"],ans:"to move out",hint:"This person is leaving their current home. Think about changing residences."},
{type:"match",pairs:[{trg:"kaputt",src:"broken"},{trg:"hell",src:"bright"},{trg:"aussehen",src:"to look/appear"},{trg:"ausziehen",src:"to move out"},{trg:"gehören",src:"to belong to"},{trg:"männlich",src:"male"}]}
]}
]},
// ═══════════════════════════════════════════════════════════════
// UNIT 4: Im Supermarkt -- Speed Checkout Survival
// Story: Verumius's first German supermarket trip, accusative case, food+drinks
// CEFR: A1.1 - Shopping, food, money, accusative, kein, imperative
// ═══════════════════════════════════════════════════════════════
{n:4,lang:"de",srcLang:"en",track:"v2",title:"Im Supermarkt",sub:"Shopping, food & the accusative case",icon:"🛒",level:"A1.1",color:"#7B5EE8",lessons:[

// ─── L1: Einkaufswagen-Panik ───
{id:"deu_r4l1",title:"Einkaufswagen-Panik",icon:"🛒",xp:15,board:true,steps:[
{type:"intro",title:"Speed Checkout Survival",desc:"Verumius enters a German supermarket for the first time. Shopping carts need a coin. Cashiers don't bag. Cash is king. Survival starts now.",goals:["Shopping vocabulary","Money words and payment","Navigate a German supermarket"]},
{type:"teach",trg:"einkaufen",src:"to shop / go grocery shopping",note:"Separable: ich kaufe ein, du kaufst ein.",example:"A: Wo kaufst du ein?\nB: Ich kaufe im Supermarkt ein.",exampleSrc:"A: Where do you shop?\nB: I shop at the supermarket.",funFact:"Germans plan grocery trips like military operations. List, bags, coins for the cart. No impulse buying. Hildi would approve."},
{type:"teach",trg:"der Kunde / die Kundin",src:"the customer (m/f)",note:"Masculine: der Kunde. Feminine: die Kundin.",example:"A: Sind Sie Kunde hier?\nB: Ja, ich bin Kundin.",exampleSrc:"A: Are you a customer here?\nB: Yes, I am a customer.",funFact:"German always has male + female forms for people: Kunde/Kundin, Verkäufer/Verkäuferin. The gendered forms are standard."},
{type:"teach",trg:"die Kasse",src:"the checkout / register",note:"Feminine. Where you pay.",example:"A: Wo ist die Kasse?\nB: Die Kasse ist dort hinten.",exampleSrc:"A: Where is the checkout?\nB: The checkout is back there.",funFact:"German cashiers sit down. They will NEVER bag your groceries. You bag. Fast. While the next customer's items are already on the belt."},
{type:"teach",trg:"der Verkäufer",src:"the salesperson",note:"Masculine. Feminine: die Verkäuferin.",example:"A: Der Verkäufer ist nett.\nB: Ja, er hilft mir.",exampleSrc:"A: The salesperson is nice.\nB: Yes, he is helping me.",funFact:"Literally 'the seller.' German loves compound transparency. Ver+käufer from ver+kaufen."},
{type:"teach",trg:"der Preis",src:"the price",note:"Masculine. Plural: die Preise.",example:"A: Wie ist der Preis?\nB: Der Preis ist gut.",exampleSrc:"A: How is the price?\nB: The price is good.",funFact:"'Preis' sounds like 'price' because it IS the same Germanic root. Preiswert = price-worthy = good value."},
{type:"teach",trg:"bezahlen",src:"to pay (for something)",note:"Regular. Also: zahlen = to pay (in general).",example:"A: Ich möchte bezahlen.\nB: Bar oder mit Karte?",exampleSrc:"A: I would like to pay.\nB: Cash or card?",funFact:"'Bezahlen' = pay for something specific. 'Zahlen' = pay in general. Both work at the register. 'Zahlen, bitte!' = check, please!"},
{type:"teach",trg:"das Geld",src:"the money",note:"Neuter. Also: der Euro, der Cent.",example:"A: Hast du Geld?\nB: Ja, ich habe zwanzig Euro.",exampleSrc:"A: Do you have money?\nB: Yes, I have twenty euros.",funFact:"Euro coins show different countries on the back. German euros have the Brandenburg Gate, an eagle, or an oak leaf. Collect them all!"},
{type:"teach",trg:"die Kreditkarte",src:"the credit card",note:"Feminine. Many German shops still don't accept them!",example:"A: Nehmen Sie Kreditkarte?\nB: Nein, nur bar.",exampleSrc:"A: Do you accept credit card?\nB: No, cash only.",funFact:"Many German shops STILL don't take cards. Cash is king. Always carry Bargeld. The Bäckerei, the Kiosk, the Döner stand: bar only."},
{type:"teach",trg:"kaufen",src:"to buy",note:"Regular. Opposite: verkaufen (to sell).",example:"A: Ich kaufe Brot.\nB: Der Laden verkauft gutes Brot.",exampleSrc:"A: I buy bread.\nB: The shop sells good bread.",funFact:"Kauf = buy. Ver+kauf = sell. The ver- prefix flips meaning. Like mieten/vermieten from Unit 3."},
{type:"teach",trg:"das Angebot",src:"the offer / special deal",note:"Neuter. Also: die Tasche (bag), der Schuh (shoe), die Jacke (jacket).",example:"A: Das Angebot ist gut!\nB: Ja, sehr günstig.",exampleSrc:"A: The offer is great!\nB: Yes, very good value.",funFact:"'Sonderangebot' = special offer. Germans plan shopping around Angebote. The weekly flyer is sacred. Hildi has a filing system."},
{type:"teach",trg:"die Rechnung",src:"the bill / receipt",note:"Feminine. Also: der Automat (machine).",example:"A: Kann ich die Rechnung haben?\nB: Hier, bitte.",exampleSrc:"A: Can I have the bill?\nB: Here you go.",funFact:"'Automat' = any machine: Kaffeeautomat, Parkscheinautomat, Pfandautomat (bottle deposit machine). Germans automate everything."},
{type:"teach",trg:"die Kleidung",src:"the clothing",note:"Feminine. Collective noun, always singular.",example:"A: Ich brauche neue Kleidung.\nB: Die Kleidung ist teuer.",exampleSrc:"A: I need new clothes.\nB: The clothing is expensive.",funFact:"Like Obst and Gemüse, Kleidung is always singular. For individual items: der Schuh (shoe), die Jacke (jacket), die Tasche (bag)."},
{type:"tip",title:"Story Setup",text:"Verumius stands outside REWE.\nHe needs a Euro coin for the Einkaufswagen (shopping cart).\nHe has only a 50-Euro bill.\nThe Pfandautomat blinks at him.\n\nPfand = bottle deposit. Germans return bottles to machines for money.\nEvery bottle has a Pfand value (8-25 cents).\nThe adventure begins."},
{type:"mc",q:"Verumius asks 'Nehmen Sie Kreditkarte?' The cashier says 'Nein.' What must he use?",opts:["Bargeld (cash)","eine App","einen Scheck","eine Überweisung"],ans:"Bargeld (cash)",hint:"Many German shops only accept one form of payment. Not plastic."},
{type:"fb",s:"Das {1} ist gut! Ich kaufe die Jacke.",a:["Angebot"],opts:["Angebot","Geld","Preis","Kasse"],hint:"A special deal or discount that makes something cheaper than usual.",sSrc:"The {1} is good! I am buying the jacket."},
{type:"match",pairs:[{trg:"einkaufen",src:"to shop"},{trg:"bezahlen",src:"to pay"},{trg:"der Preis",src:"price"},{trg:"die Kasse",src:"checkout"},{trg:"das Geld",src:"money"}]},
{type:"mc",q:"'Lebensmittel' literally means:",opts:["means of life","food store","daily shopping","fresh goods"],ans:"means of life",hint:"Translate each part of this compound noun separately."}
]},

// ─── L2: Obst, Gemüse und Chaos ───
{id:"deu_r4l2",title:"Obst, Gemüse und Chaos",icon:"🍎",xp:15,board:true,steps:[
{type:"intro",title:"Obst, Gemüse und Chaos",desc:"The produce aisle. 22 food words and 10 drink words, each with its article. Germany has 3,200 bread varieties. UNESCO agrees.",goals:["22 food words with gender","10 drink words with gender","Master der/die/das for food"]},
{type:"teach",trg:"das Obst",src:"the fruit (collective)",note:"Neuter. ALWAYS singular. Never 'Obste.'",example:"A: Ich esse gern Obst.\nB: Welches Obst magst du?",exampleSrc:"A: I like eating fruit.\nB: Which fruit do you like?",funFact:"Obst is always singular in German. You never say 'Obste.' Same with Gemüse. German hates pluralizing categories."},
{type:"teach",trg:"der Apfel",src:"the apple",note:"Masculine. Plural: die Äpfel (umlaut!).",example:"A: Der Apfel ist rot.\nB: Ich kaufe drei Äpfel.",exampleSrc:"A: The apple is red.\nB: I am buying three apples.",funFact:"Plural changes the vowel: Apfel to Äpfel. Umlaut magic! Same pattern: Vater to Väter, Bruder to Brüder."},
{type:"teach",trg:"die Banane",src:"the banana",note:"Feminine. Also: die Birne (pear). Both start with B!",example:"A: Eine Banane, bitte.\nB: Und eine Birne?",exampleSrc:"A: A banana, please.\nB: And a pear?",funFact:"Both feminine, both fruit, both start with B. Life is easy sometimes."},
{type:"teach",trg:"die Tomate",src:"the tomato",note:"Feminine. Also: die Kartoffel (potato).",example:"A: Die Tomaten sind frisch.\nB: Und die Kartoffeln?",exampleSrc:"A: The tomatoes are fresh.\nB: And the potatoes?",funFact:"'Kartoffel' originally meant 'truffle'! Germans renamed the potato after truffles when it arrived from the Americas."},
{type:"teach",trg:"das Gemüse",src:"the vegetables (collective)",note:"Neuter. Always singular, like Obst.",example:"A: Ich brauche Gemüse.\nB: Der Salat ist im Angebot.",exampleSrc:"A: I need vegetables.\nB: The lettuce is on sale.",funFact:"Like Obst, Gemüse is always singular. German hates pluralizing categories. Der Salat = lettuce/salad."},
{type:"teach",trg:"das Brot",src:"the bread",note:"Neuter. Also: das Brötchen (bread roll).",example:"A: Ich kaufe Brot.\nB: Und Brötchen?",exampleSrc:"A: I am buying bread.\nB: And bread rolls?",funFact:"Germany has 3,200+ bread varieties. More than any country on earth. UNESCO lists German bread culture as intangible cultural heritage."},
{type:"teach",trg:"die Butter",src:"the butter",note:"Feminine. Also: das Ei (egg), das Salz (salt), das Öl (oil).",example:"A: Butter und Eier, bitte.\nB: Und Salz?",exampleSrc:"A: Butter and eggs, please.\nB: And salt?",funFact:"Ei to Eier is one of German's weird plurals. Salz and Öl are both neuter. Liquids and powders often are."},
{type:"teach",trg:"das Fleisch",src:"the meat",note:"Neuter. Also: der Fisch (fish), das Hähnchen (chicken).",example:"A: Fleisch oder Fisch?\nB: Hähnchen, bitte.",exampleSrc:"A: Meat or fish?\nB: Chicken, please.",funFact:"Hähnchen = little rooster (Hahn + chen). The diminutive -chen makes EVERYTHING neuter. Just like Mädchen."},
{type:"teach",trg:"der Schinken",src:"the ham",note:"Masculine. Also: der Kuchen (cake), der Reis (rice).",example:"A: Zweihundert Gramm Schinken, bitte.\nB: Hier, genau zweihundert.",exampleSrc:"A: Two hundred grams of ham, please.\nB: Here, exactly two hundred.",funFact:"Germans eat ham for breakfast. On bread. With butter. Every morning. The Brotzeit (bread-time) is sacred."},
{type:"teach",trg:"die Pommes frites",src:"the fries / chips",note:"Always plural (die). Germans say 'Pommes' (POMM-ess).",example:"A: Pommes mit Mayo?\nB: Ja, immer!",exampleSrc:"A: Fries with mayo?\nB: Yes, always!",funFact:"Germans say 'Pommes' (POMM-ess), never 'frites.' And yes, they put mayo on them. Ketchup is also common, but mayo is the default."},
{type:"teach",trg:"das Wasser",src:"the water",note:"Neuter. Also: die Milch (milk), der Kaffee (coffee), der Tee (tea).",example:"A: Wasser oder Milch?\nB: Kaffee, bitte!",exampleSrc:"A: Water or milk?\nB: Coffee, please!",funFact:"German water is almost always sparkling (mit Kohlensäure). Ask for 'stilles Wasser' if you want flat. This confuses every tourist."},
{type:"teach",trg:"der Saft",src:"the juice",note:"Masculine. Also: das Bier (beer), der Wein (wine).",example:"A: Saft für die Kinder?\nB: Und Wein für uns.",exampleSrc:"A: Juice for the kids?\nB: And wine for us.",funFact:"Germans can legally drink beer and wine at 16. Spirits at 18. Saft (juice) is for the youngsters."},
{type:"teach",trg:"das Getränk",src:"the drink / beverage",note:"Neuter. Also: die Flasche (bottle), das Glas (glass).",example:"A: Ein Getränk, bitte.\nB: Flasche oder Glas?",exampleSrc:"A: A drink, please.\nB: Bottle or glass?",funFact:"'Flasche' also means 'loser' in slang. Don't call someone a Flasche."},
{type:"teach",trg:"das Lebensmittel",src:"the food / groceries",note:"Neuter. Literally: means-of-life.",example:"A: Die Lebensmittel sind frisch.\nB: Ja, sehr gut.",exampleSrc:"A: The groceries are fresh.\nB: Yes, very good.",funFact:"Leben (life) + Mittel (means) = means of life. German compound poetry at its finest."},
{type:"mc",q:"What is 'der Apfel'?",opts:["apple","bread","fish","egg"],ans:"apple",hint:"A round red fruit from the produce section."},
{type:"mc",q:"Which is neuter (das)?",opts:["der Kuchen","die Banane","das Brot","die Milch"],ans:"das Brot",hint:"Baked goods often take das in German."},
{type:"match",pairs:[{trg:"der Fisch",src:"fish"},{trg:"die Kartoffel",src:"potato"},{trg:"das Hähnchen",src:"chicken"},{trg:"die Flasche",src:"bottle"},{trg:"das Gemüse",src:"vegetables"}]},
{type:"fb",s:"Ich trinke gern {1}.",a:["Kaffee"],opts:["Kaffee","Salat","Brot","Fleisch"],hint:"Which one is a drink, not food?",sSrc:"I like to drink {1}."},
{type:"mc",q:"What does 'Lebensmittel' literally mean?",opts:["means of life","food store","daily bread","fresh items"],ans:"means of life",hint:"Translate each part of this compound noun separately."},
{type:"match",pairs:[{trg:"das Ei",src:"egg"},{trg:"die Butter",src:"butter"},{trg:"der Reis",src:"rice"},{trg:"der Schinken",src:"ham"},{trg:"das Salz",src:"salt"}]},
{type:"mc",q:"'Die Tomaten _____ frisch.'",opts:["ist","sind","hat","haben"],ans:"sind",hint:"Tomaten is plural. Plural verb form needed."}
]},

// ─── L3: Nummern, Farben, Gewichte ───
{id:"deu_r4l3",title:"Nummern, Farben, Gewichte",icon:"🔢",xp:15,board:true,steps:[
{type:"intro",title:"Nummern, Farben, Gewichte",desc:"Numbers beyond 20, all the colors, and how to weigh produce. The deli counter awaits: you MUST know your Gramm from your Kilo.",goals:["Count to 1,000+","Name all basic colors","Weights and measurements"]},
{type:"teach",trg:"dreißig / vierzig / fünfzig",src:"30 / 40 / 50",note:"Tens: add -zig to the root. dreißig is the exception (not dreizig).",example:"A: Dreißig Euro?\nB: Nein, vierzig!",exampleSrc:"A: Thirty euros?\nB: No, forty!",funFact:"German flips digit order: 43 = 'dreiundvierzig' (three-and-forty). Brain breaker for English speakers. Get used to it!"},
{type:"teach",trg:"sechzig / siebzig / achtzig / neunzig",src:"60 / 70 / 80 / 90",note:"Siebzig (not siebenzig). The 'en' gets eaten.",example:"A: Siebzig oder sechzig?\nB: Achtzig!",exampleSrc:"A: Seventy or sixty?\nB: Eighty!",funFact:"Siebzig drops the 'en': sieben to siebzig. Same thing happens with siebte (7th). German likes trimming."},
{type:"teach",trg:"hundert / tausend",src:"100 / 1,000",note:"'Ein' before them is optional: hundert = einhundert.",example:"A: Hundert Euro!\nB: Nein, tausend!",exampleSrc:"A: A hundred euros!\nB: No, a thousand!",funFact:"Both forms correct: hundert or einhundert, tausend or eintausend. Germans are flexible here."},
{type:"teach",trg:"die Farbe",src:"the color",note:"Feminine. Colors as adjectives are lowercase: rot, blau, grün.",example:"A: Welche Farbe?\nB: Rot!",exampleSrc:"A: Which color?\nB: Red!",funFact:"German color words don't capitalize unless they are nouns (das Rot). As adjectives: always lowercase."},
{type:"teach",trg:"rot / blau / grün / gelb",src:"red / blue / green / yellow",note:"Basic colors. Used as adjectives (no ending when predicative).",example:"A: Der Apfel ist rot.\nB: Die Banane ist gelb.",exampleSrc:"A: The apple is red.\nB: The banana is yellow.",funFact:"Rot, blau, grün, gelb: four primary colors every child learns first. 'Grün hinter den Ohren' (green behind the ears) = naive/inexperienced."},
{type:"teach",trg:"schwarz / weiß / braun / grau",src:"black / white / brown / grey",note:"More colors. Schwarz and weiß are common in compound nouns.",example:"A: Schwarz oder weiß?\nB: Grau!",exampleSrc:"A: Black or white?\nB: Grey!",funFact:"Schwarzbrot (black bread), Weißwurst (white sausage), Braunschweig (city name!). Colors build food compounds."},
{type:"teach",trg:"das Gramm / das Kilogramm",src:"gram / kilogram",note:"Both neuter. Stay singular with numbers: 500 Gramm, never Gramme.",example:"A: Zweihundert Gramm Schinken, bitte.\nB: Hier, genau zweihundert.",exampleSrc:"A: Two hundred grams of ham, please.\nB: Here, exactly two hundred.",funFact:"At the Fleischtheke (deli counter), you order by Gramm. '200 Gramm Schinken' is the magic phrase. Never say 'Gramme.'"},
{type:"teach",trg:"das Pfund",src:"the pound (500g in Germany!)",note:"Neuter. German Pfund = 500g, NOT 454g like English pound!",example:"A: Ein halbes Pfund Butter.\nB: Und ein Liter Milch?",exampleSrc:"A: Half a pound of butter.\nB: And a liter of milk?",funFact:"Pfund = 500g in Germany. Not 454g like the English pound. Metric country! 'Ein halbes Pfund' = 250g."},
{type:"teach",trg:"der Liter / der Meter",src:"liter / meter",note:"Both masculine. Germany went metric in 1872.",example:"A: Hundert Zentimeter sind ein Meter.\nB: Und tausend Meter sind ein Kilometer.",exampleSrc:"A: A hundred centimeters is one meter.\nB: And a thousand meters is one kilometer.",funFact:"Germany went metric in 1872. They think in meters like you think in feet. Zentimeter, Kilometer: all masculine."},
{type:"teach",trg:"die Nummer / die Größe / das Gewicht",src:"number / size / weight",note:"Three essential measurement words.",example:"A: Welche Nummer?\nB: Nummer fünfzig.",exampleSrc:"A: Which number?\nB: Number fifty.",funFact:"At the bakery counter you MUST take a number (Nummer ziehen). No number = no service. Germans queue by number, not by standing in line."},
{type:"teach",trg:"halb / das Viertel / zirka",src:"half / quarter / approximately",note:"'Halb' = half. 'Viertel' = quarter. 'Zirka' = about.",example:"A: Zirka eine Stunde.\nB: Ein Viertel ist genug.",exampleSrc:"A: About one hour.\nB: A quarter is enough.",funFact:"'Viertel nach drei' = quarter past three. 'Halb vier' = half TO four (= 3:30!). This German clock trap catches everyone."},
{type:"mc",q:"How do you say 73 in German?",opts:["dreiundsiebzig","siebzigdrei","siebendreißig","dreißigsieben"],ans:"dreiundsiebzig",hint:"German says the ones digit first, then 'und', then tens."},
{type:"mc",q:"'Zweihundertfünfundvierzig' = ?",opts:["245","254","452","542"],ans:"245",hint:"zweihundert=200, fünfundvierzig=45."},
{type:"fb",s:"Zweihundert {1} Schinken, bitte.",a:["Gramm"],opts:["Gramm","Liter","Meter","Grad"],hint:"Which unit measures weight for deli items?",sSrc:"Two hundred {1} of ham, please."},
{type:"match",pairs:[{trg:"rot",src:"red"},{trg:"blau",src:"blue"},{trg:"gelb",src:"yellow"},{trg:"grün",src:"green"},{trg:"schwarz",src:"black"}]},
{type:"mc",q:"'Zirka ein Kilo' means:",opts:["about one kilogram","exactly one kilogram","half a kilogram","two kilograms"],ans:"about one kilogram",hint:"Zirka means approximately."},
{type:"fb",s:"Ein {1} Pfund Butter, bitte.",a:["halbes"],opts:["halbes","ganzes","großes","kleines"],hint:"You want 250g, which is half of a Pfund.",sSrc:"A {1} pound of butter, please."},
{type:"mc",q:"Which color means 'grey'?",opts:["grau","grün","braun","blau"],ans:"grau",hint:"It starts with 'gr' but is NOT green."},
{type:"match",pairs:[{trg:"die Nummer",src:"number"},{trg:"das Gewicht",src:"weight"},{trg:"die Größe",src:"size"},{trg:"das Viertel",src:"quarter"},{trg:"die Stunde",src:"hour"}]},
{type:"fb",s:"Das Brot kostet drei Euro fünfzig {1}.",a:["Cent"],opts:["Cent","Euro","Prozent","Gramm"],hint:"The small coin denomination after Euro.",sSrc:"The bread costs three euros fifty {1}."}
]},

// ─── L4: Akkusativ-Alarm ───
{id:"deu_r4l4",title:"Akkusativ-Alarm",icon:"⚡",xp:20,board:true,steps:[
{type:"intro",title:"Akkusativ-Alarm",desc:"The accusative case changes ONE article: der becomes den. That's it. One gender, one change. But it changes everything about how you shop.",goals:["Accusative case (den/einen)","Negative article kein","nicht vs kein distinction"]},
{type:"teach",trg:"teuer",src:"expensive",note:"Adjective. Opposite: billig (cheap). Better word: günstig (good value).",example:"A: Das ist teuer!\nB: Nein, das ist günstig.",exampleSrc:"A: That is expensive!\nB: No, that is good value.",funFact:"'Günstig' does not mean cheap. It means good value. Germans make this distinction seriously. Billig = cheap (negative). Günstig = well-priced (positive)."},
{type:"teach",trg:"viel / wenig / mehr",src:"much / little / more",note:"Viel = much/many. Wenig = little/few. Mehr = more (comparative).",example:"A: Ich brauche mehr Milch.\nB: Wir haben nicht viel.",exampleSrc:"A: I need more milk.\nB: We don't have much.",funFact:"'Mehr' never declines. No endings, ever. 'Die meisten Leute' = most people. Meist is the superlative of viel."},
{type:"tip",title:"Accusative Case (der Akkusativ)",text:"The direct object case. What changes?\n\nder becomes den (masculine ONLY)\nein becomes einen (masculine ONLY)\ndie / das / eine / ein(neut) = NO CHANGE\n\nNominative: Der Apfel ist rot.\nAccusative: Ich kaufe den Apfel.\n\nOnly masculine changes. Everything else stays the same.\nThis is the easiest German case."},
{type:"teach",trg:"den / einen",src:"the / a (masculine accusative)",note:"Masculine accusative: der to den, ein to einen.",example:"A: Ich kaufe den Apfel.\nB: Und ich nehme einen Kuchen.",exampleSrc:"A: I am buying the apple.\nB: And I am taking a cake.",funFact:"Only ONE gender changes in accusative. Masculine gets an extra -en. Die and das? Lazy. No change."},
{type:"mc",q:"'Ich kaufe ___ Fisch.'",opts:["den","der","dem","des"],ans:"den",hint:"Fisch is masculine. Direct object = accusative case. What form?"},
{type:"fb",s:"Ich brauche {1} Apfel.",a:["einen"],opts:["einen","ein","einer","eine"],hint:"Apfel is masculine. In accusative, ein becomes...",sSrc:"I need {1} apple."},
{type:"mc",q:"'Ich esse ___ Banane.'",opts:["die","den","dem","der"],ans:"die",hint:"Banane is feminine. Feminine does NOT change in accusative."},
{type:"fb",s:"Er kauft {1} Brot.",a:["das"],opts:["das","den","der","die"],hint:"Brot is neuter. Neuter stays the same in accusative.",sSrc:"He buys {1} bread."},
{type:"tip",title:"kein: The Negative Article",text:"kein = 'not a' / 'no.' Declines like ein:\n\nNom: kein Apfel, keine Banane, kein Brot\nAcc: keinen Apfel, keine Banane, kein Brot\n\nMasculine adds -en in accusative.\nJust like ein becomes einen."},
{type:"teach",trg:"kein / keinen / keine",src:"no / not a (negative article)",note:"Follows ein-pattern. keinen for masculine accusative.",example:"A: Hast du einen Apfel?\nB: Nein, ich habe keinen Apfel.",exampleSrc:"A: Do you have an apple?\nB: No, I don't have an apple.",funFact:"Kein is ein's evil twin. Same endings, opposite meaning. Master ein-endings, and kein is free."},
{type:"mc",q:"'Ich habe ___ Geld.'",opts:["kein","keinen","keine","keiner"],ans:"kein",hint:"Geld is neuter. You are negating a noun. Which negator for neuter nouns?"},
{type:"fb",s:"Wir haben {1} Milch.",a:["keine"],opts:["keine","kein","keinen","keiner"],hint:"Milch is feminine. What form does kein take with feminine nouns?",sSrc:"We have {1} milk."},
{type:"mc",q:"'Er kauft ___ Schinken.' (none)",opts:["keinen","kein","keine","keinem"],ans:"keinen",hint:"Schinken is masculine. Accusative masculine kein gets -en."},
{type:"tip",title:"nicht vs kein",text:"When to use which?\n\nKEIN replaces ein/eine before nouns:\n'Ich habe ein Auto' to 'Ich habe kein Auto'\n\nNICHT negates verbs, adjectives, adverbs:\n'Ich kaufe nicht' / 'Das ist nicht teuer'\n\nNICHT goes before what it negates.\nKEIN goes before the noun."},
{type:"mc",q:"'Das Brot ist ___ frisch.'",opts:["nicht","kein","keinen","keine"],ans:"nicht",hint:"Is the negated word a noun or an adjective/verb? The negator depends on this."},
{type:"fb",s:"Ich kaufe {1} Fleisch.",a:["kein"],opts:["kein","nicht","keinen","keine"],hint:"Negating a neuter noun. Which negative article?",sSrc:"I am buying {1} meat."},
{type:"mc",q:"'Ich trinke ___ .'",opts:["nicht","kein","keinen","keine"],ans:"nicht",hint:"Nothing being negated is a noun. What negator works for verbs?"},
{type:"drag_fill",s:"Ich habe {1} Geld und kaufe {2} ein.",blanks:{"1":"kein","2":"nicht"},pool:["kein","nicht","keinen","keine"],hint:"Geld is neuter noun (kein). Second blank negates the verb (nicht).",sSrc:"I have {1} money and am {2} shopping."},
{type:"mc",q:"'Wir brauchen ___ Eier.'",opts:["keine","nicht","kein","keinen"],ans:"keine",hint:"Eier is plural. What ending does the noun-negator need for plural?"},
{type:"fb",s:"Die Tomaten sind {1} billig.",a:["nicht"],opts:["nicht","keine","kein","keinen"],hint:"Negating the adjective 'billig', not a noun.",sSrc:"The tomatoes are {1} cheap."},
{type:"drag_fill",s:"Ich kaufe {1} Fisch. Der Fisch ist {2} günstig.",blanks:{"1":"keinen","2":"nicht"},pool:["keinen","nicht","kein","keine"],hint:"First: masculine noun accusative. Second: negating adjective.",sSrc:"I am buying {1} fish. The fish is {2} affordable."},
{type:"mc",q:"'Er hat ___ Kreditkarte.'",opts:["keine","nicht","kein","keinen"],ans:"keine",hint:"Kreditkarte is feminine. What ending does the noun-negator need?"}
]},

// ─── L5: Für, Ohne, Gegen ───
{id:"deu_r4l5",title:"Für, Ohne, Gegen",icon:"🎯",xp:20,board:true,steps:[
{type:"intro",title:"Für, Ohne, Gegen",desc:"Five prepositions that ALWAYS take accusative. Plus demonstrative articles and the imperative. Grammar-heavy, but you already know the accusative.",goals:["5 accusative prepositions (DOGFU)","Demonstrative articles: dieser/jeder","Basic imperative commands"]},
{type:"teach",trg:"ohne",src:"without",note:"Preposition. Always takes accusative.",example:"A: Kaffee ohne Milch?\nB: Ja, ohne Milch und ohne Zucker.",exampleSrc:"A: Coffee without milk?\nB: Yes, without milk and without sugar.",funFact:"'Ohne mich!' = Count me out! Always takes accusative. Ohne einen Euro = without a euro."},
{type:"teach",trg:"bitten",src:"to ask / to request",note:"Irregular: ich bitte, du bittest. 'Bitten um' = ask for.",example:"A: Ich bitte um Hilfe.\nB: Natürlich!",exampleSrc:"A: I am asking for help.\nB: Of course!",funFact:"'Bitten um' always takes accusative. 'Bitte' (please) comes from this verb. The most polite word in German has aggressive grammar."},
{type:"teach",trg:"geben",src:"to give",note:"Irregular: ich gebe, du gibst, er gibt.",example:"A: Gibst du mir den Apfel?\nB: Ja, ich gebe dir den Apfel.",exampleSrc:"A: Are you giving me the apple?\nB: Yes, I am giving you the apple.",funFact:"'Geben' takes dative for the person and accusative for the thing. For now, focus on the accusative object: den Apfel, die Milch, das Brot."},
{type:"tip",title:"DOGFU: 5 Accusative Prepositions",text:"Five prepositions ALWAYS take accusative:\n\nDurch (through): durch den Laden\nOhne (without): ohne einen Euro\nGegen (against): gegen den Preis\nFür (for): für die Familie\nUm (around): um die Ecke\n\nMnemonic: DOGFU.\nOnly masculine changes: den/einen."},
{type:"mc",q:"'Das Geschenk ist für ___ Kundin.'",opts:["die","den","dem","der"],ans:"die",hint:"Kundin is feminine. Feminine doesn't change in accusative."},
{type:"fb",s:"Ich gehe durch {1} Laden.",a:["den"],opts:["den","der","dem","das"],hint:"'Durch' always demands the same case. Apply it to a masculine noun.",sSrc:"I walk through {1} store."},
{type:"mc",q:"Fill in: 'Kaffee ohne ___.'",opts:["Milch","die Milch","der Milch","den Milch"],ans:"Milch",hint:"After ohne, no article needed when speaking generally about a substance."},
{type:"fb",s:"Das ist für {1} Verkäufer.",a:["den"],opts:["den","der","dem","des"],hint:"Verkäufer is masculine. Für always takes accusative.",sSrc:"That is for {1} salesperson."},
{type:"tip",title:"Demonstrativartikel",text:"dieser/jeder/welcher decline like der/die/das:\n\nMasc nom: dieser, jeder, welcher\nMasc acc: diesen, jeden, welchen\nFem: diese, jede, welche (no change nom/acc)\nNeut: dieses, jedes, welches (no change nom/acc)\nPlural: diese, alle, welche"},
{type:"teach",trg:"was für ein / was für eine",src:"what kind of (a)",note:"'Was für' + ein-word. The ein-part declines normally.",example:"A: Was für einen Kuchen möchtest du?\nB: Einen Schokoladenkuchen!",exampleSrc:"A: What kind of cake would you like?\nB: A chocolate cake!",funFact:"'Was für ein' = what kind of. Masculine acc: was für einen. Feminine: was für eine. Neuter: was für ein."},
{type:"mc",q:"'___ Apfel möchtest du?'",opts:["Welchen","Welcher","Welches","Welche"],ans:"Welchen",hint:"Apfel is masculine, direct object (accusative). Welch- + masc acc = -en."},
{type:"fb",s:"Ich kaufe {1} Flasche.",a:["diese"],opts:["diese","diesen","dieser","dieses"],hint:"Flasche is feminine, accusative case. What ending for dieser-type words?",sSrc:"I am buying {1} bottle."},
{type:"mc",q:"'___ Brot schmeckt gut?'",opts:["Welches","Welcher","Welchen","Welche"],ans:"Welches",hint:"Brot is neuter, nominative. Think about the dieser-word endings chart."},
{type:"fb",s:"Ich nehme {1} Kuchen.",a:["diesen"],opts:["diesen","dieser","dieses","diese"],hint:"Kuchen is masculine, direct object (accusative). Masculine accusative ending?",sSrc:"I will take {1} cake."},
{type:"tip",title:"Imperative (Commands)",text:"Giving commands in German:\n\ndu-form: verb stem: Kauf! Nimm! Gib!\nihr-form: same as ihr-present: Kauft! Nehmt!\nSie-form: infinitive + Sie: Kaufen Sie! Nehmen Sie!\n\nSeparable verbs split: Kauf ein! Kaufen Sie ein!\nSie-form is the polite one. Always use it with strangers."},
{type:"mc",q:"'Buy!' (polite) in German:",opts:["Kaufen Sie!","Kauf!","Kauft!","Kaufe!"],ans:"Kaufen Sie!",hint:"Polite imperative uses the Sie-form: infinitive + Sie."},
{type:"fb",s:"{1} den Apfel!",a:["Nimm"],opts:["Nimm","Nehmen","Nimmst","Nimmt"],hint:"Informal du-command. What is the imperative stem of nehmen?",sSrc:"{1} the apple!"},
{type:"mc",q:"'_____ bitte hier!' (polite: pay here)",opts:["Zahlen Sie","Zahl","Zahlt","Zahlst du"],ans:"Zahlen Sie",hint:"Polite command = infinitive + Sie."},
{type:"drag_fill",s:"{1} Sie {2} den Laden!",blanks:{"1":"Gehen","2":"durch"},pool:["Gehen","durch","Geht","für"],hint:"Polite imperative of the verb meaning 'to walk' + a directional prefix.",sSrc:"{1} {2} the store!"},
{type:"mc",q:"'Für welch___ Kundin ist das?'",opts:["welche","welchen","welcher","welches"],ans:"welche",hint:"Kundin is feminine. Accusative feminine = no change."},
{type:"fb",s:"Ohne {1} Euro geht nichts.",a:["einen"],opts:["einen","ein","einer","eine"],hint:"Euro is masculine. Ohne requires accusative. How does ein change for masc acc?",sSrc:"Without {1} euro nothing works."},
{type:"drag_fill",s:"{1} Sie {2} Kreditkarte für {3} Einkauf!",blanks:{"1":"Nehmen","2":"die","3":"den"},pool:["Nehmen","die","den","Nimm","der","das"],hint:"Polite imperative. Kreditkarte is fem (die). Einkauf is masc acc (den).",sSrc:"{1} {2} credit card for {3} purchase!"},
{type:"mc",q:"'Was für ___ Brot möchtest du?'",opts:["ein","einen","eine","einer"],ans:"ein",hint:"Brot is neuter. Accusative neuter ein = no change."}
]},

// ─── L6: Nummer Ziehen! ───
{id:"deu_r4l6",title:"Nummer Ziehen!",icon:"🎫",xp:15,board:true,steps:[
{type:"intro",title:"Nummer Ziehen!",desc:"The bakery counter. You MUST take a number. The deli weighs in Gramm. And you can pay bar or mit Karte. Maybe.",goals:["bekommen vs kriegen","Payment vocabulary","Quantities in practice"]},
{type:"teach",trg:"bekommen",src:"to get / to receive",note:"FALSE FRIEND: does NOT mean 'to become'!",example:"A: Was bekommen Sie?\nB: Ich bekomme zwei Brötchen.",exampleSrc:"A: What would you like? (lit: What do you get?)\nB: I'll have two bread rolls.",funFact:"'Was bekommen Sie?' is how EVERY German shop assistant asks what you want. Bekommen does NOT mean 'become.' That trap catches every English speaker. 'Werden' = to become."},
{type:"teach",trg:"kriegen",src:"to get (casual synonym of bekommen)",note:"Casual. 'Ich kriege einen Kaffee.' Same meaning as bekommen.",example:"A: Was kriegst du?\nB: Ich kriege ein Brötchen.",exampleSrc:"A: What are you getting?\nB: I'm getting a bread roll.",funFact:"'Kriegen' also historically means 'to wage war' (der Krieg = war). But in everyday speech it just means 'to get.' Context is everything."},
{type:"teach",trg:"anbieten",src:"to offer",note:"Separable: wir bieten... an. 'Das Angebot' comes from this verb.",example:"A: Was bieten Sie an?\nB: Wir bieten frisches Brot an.",exampleSrc:"A: What do you offer?\nB: We offer fresh bread.",funFact:"Separable: an|bieten. 'Das Angebot' (the offer) is the noun form. Compound magic: verb to noun in one step."},
{type:"teach",trg:"bar",src:"cash (adjective/adverb)",note:"'Bar zahlen' = pay cash. Noun 'die Bar' = a pub/bar.",example:"A: Zahlen Sie bar?\nB: Ja, bar bitte.",exampleSrc:"A: Are you paying cash?\nB: Yes, cash please.",funFact:"'Bar' as payment = cash. 'Die Bar' as a place = pub. Same word, totally different meaning and gender!"},
{type:"teach",trg:"leicht / schwer",src:"light / heavy (also: easy / difficult)",note:"Both have double meanings: physical weight AND difficulty.",example:"A: Ist die Tasche schwer?\nB: Nein, sie ist leicht.",exampleSrc:"A: Is the bag heavy?\nB: No, it is light.",funFact:"'Schwer' also means 'difficult.' 'Leicht' also means 'easy.' 'Das war schwer!' could mean heavy OR hard. Context saves you."},
{type:"teach",trg:"überweisen",src:"to transfer (money)",note:"Inseparable: ich überweise. Also: die Bank, das Konto.",example:"A: Ich überweise das Geld.\nB: Auf welches Konto?",exampleSrc:"A: I am transferring the money.\nB: To which account?",funFact:"Germans LOVE bank transfers (Überweisungen). Many bills are paid this way, not by card. The Überweisung is a German institution."},
{type:"tip",title:"At the Bakery Counter",text:"Verumius stands at the Bäckerei counter.\nNo number. 'Wer ist dran?' calls the baker.\nThree people wave their numbers.\nVerumius stares.\n\nThe annoyed customer behind him sighs:\n'Nummer ziehen!'\nPull a number!\n\nLesson learned: always take a number at German counters."},
{type:"mc",q:"'Was bekommen Sie?' means:",opts:["What would you like?","What are you becoming?","What do you know?","Where are you going?"],ans:"What would you like?",hint:"Bekommen = to get/receive, NOT to become!"},
{type:"fb",s:"Wir {1} frischen Kuchen an.",a:["bieten"],opts:["bieten","bietet","anbieten","bitten"],hint:"Separable verb: the 'an' is at the end. The verb stem goes in the blank.",sSrc:"We {1} fresh cake."},
{type:"mc",q:"'Zahlen Sie ___?'",opts:["bar","teuer","billig","schwer"],ans:"bar",hint:"The cashier asks about your payment method. Physical money = ?"},
{type:"fb",s:"Die Tasche ist {1}. Sie hat viel Obst.",a:["schwer"],opts:["schwer","leicht","teuer","billig"],hint:"A bag full of fruit is not light.",sSrc:"The bag is {1}. It has a lot of fruit."},
{type:"drag_fill",s:"Ich {1} zweihundert Gramm Schinken und {2} Brötchen.",blanks:{"1":"bekomme","2":"drei"},pool:["bekomme","drei","kriege","ohne"],hint:"'I get' at the deli counter. Plus a number of bread rolls.",sSrc:"I {1} two hundred grams of ham and {2} bread rolls."},
{type:"mc",q:"'Ich habe ___ Bargeld. Kann ich mit Karte zahlen?'",opts:["kein","nicht","keinen","keine"],ans:"kein",hint:"Bargeld is neuter. Negating a noun. Does the negator change for neuter?"},
{type:"fb",s:"Nehmen {1} diesen Kuchen!",a:["Sie"],opts:["Sie","du","ihr","er"],hint:"Polite imperative: verb + ?",sSrc:"Take {1} this cake!"},
{type:"mc",q:"'Dieser Fisch ist ___ frisch.'",opts:["nicht","kein","keinen","keine"],ans:"nicht",hint:"You are negating an adjective, not a noun. Which negator goes with adjectives?"},
{type:"drag_fill",s:"Kaufen Sie {1} Gramm Schinken {2} den Preis von drei Euro.",blanks:{"1":"zweihundert","2":"für"},pool:["zweihundert","für","durch","dreihundert"],hint:"200g of ham at a certain price. Which DOGFU preposition means 'for the purpose of'?",sSrc:"Buy {1} grams of ham {2} the price of three euros."},
{type:"match",pairs:[{trg:"bekommen",src:"to get/receive"},{trg:"anbieten",src:"to offer"},{trg:"überweisen",src:"to transfer money"},{trg:"bar",src:"cash"},{trg:"schwer",src:"heavy/difficult"}]},
{type:"mc",q:"'Für ___ Konto ist die Überweisung?'",opts:["welches","welcher","welchen","welche"],ans:"welches",hint:"Konto is neuter. Für needs accusative. What ending for welch- with neuter acc?"}
]},

// ─── L7: Speed Checkout Terror ───
{id:"deu_r4l7",title:"Speed Checkout Terror",icon:"⚡",xp:20,board:true,steps:[
{type:"intro",title:"Speed Checkout Terror",desc:"The moment of truth. Items fly across the scanner. The cashier doesn't pause. The next customer is already loading. ALL grammar from this unit in action.",goals:["Test all 6 grammar constructs","Multi-construct combinations","Survive the Kasse"]},
{type:"tip",title:"The Speed Checkout",text:"The conveyor belt moves. Verumius places his items:\nden Fisch, die Bananen, das Brot, keine Tüte.\nThe cashier scans without looking up.\n'Dreiundvierzig Euro achtundsiebzig.'\nVerumius fumbles for his Kreditkarte.\n'Nur bar!' says the cashier.\nPanic."},
{type:"mc",q:"'Verumius kauft ___ Fisch.'",opts:["den","der","dem","des"],ans:"den",hint:"Fisch is masculine. Direct object = accusative = den."},
{type:"fb",s:"Das Hähnchen kostet {1} Euro fünfzig.",a:["neun"],opts:["neun","neunzig","neunhundert","neuntausend"],hint:"A chicken costs less than ten euros.",sSrc:"The chicken costs {1} euros fifty."},
{type:"mc",q:"'Er hat ___ Tüte.'",opts:["keine","nicht","kein","keinen"],ans:"keine",hint:"Tüte is feminine. What ending does the noun-negator need for feminine?"},
{type:"drag_fill",s:"Ich kaufe {1} Liter Milch und {2} Gramm Butter {3} die Familie.",blanks:{"1":"einen","2":"zweihundert","3":"für"},pool:["einen","zweihundert","für","ein","dreihundert","ohne"],hint:"Liter is masculine (acc: einen). 200g. DOGFU: 'for' the family.",sSrc:"I am buying {1} liter of milk and {2} grams of butter {3} the family."},
{type:"mc",q:"'___ Brot möchten Sie?'",opts:["Welches","Welcher","Welchen","Welche"],ans:"Welches",hint:"Brot is neuter, accusative. Check the demonstrative endings for neuter."},
{type:"fb",s:"Geben Sie mir {1} Rechnung!",a:["die"],opts:["die","den","der","das"],hint:"Rechnung is feminine. Acc feminine = no change from nom.",sSrc:"Please give me {1} bill!"},
{type:"mc",q:"'Der Wein ist nicht ___. Nur drei Euro.'",opts:["teuer","billig","günstig","schwer"],ans:"teuer",hint:"At 3 euros, the wine is NOT expensive."},
{type:"drag_fill",s:"Zahlen Sie {1} oder mit {2}?",blanks:{"1":"bar","2":"Karte"},pool:["bar","Karte","Geld","Bank"],hint:"Cash or with card? Two payment methods.",sSrc:"Are you paying {1} or with {2}?"},
{type:"mc",q:"'Ich gehe ___ den Supermarkt.'",opts:["durch","für","mit","bei"],ans:"durch",hint:"Movement THROUGH something. First letter of DOGFU."},
{type:"fb",s:"Ohne {1} Euro bekomme ich keinen Einkaufswagen.",a:["einen"],opts:["einen","ein","einer","eine"],hint:"Ohne requires a specific case. Think about what happens to the article.",sSrc:"Without {1} euro I cannot get a shopping cart."},
{type:"mc",q:"'Die Tomaten kosten ein Euro ___ Kilo.'",opts:["das","den","pro","für"],ans:"das",hint:"Per kilogram. 'Das Kilo' used directly."},
{type:"drag_fill",s:"{1} Sie {2} Kuchen! Er ist heute im Angebot.",blanks:{"1":"Nehmen","2":"diesen"},pool:["Nehmen","diesen","Nimm","dieser"],hint:"Polite imperative. Kuchen is masculine. What form does the demonstrative take in accusative?",sSrc:"{1} {2} cake! It is on offer today."},
{type:"fb",s:"Was für {1} Gemüse kaufst du?",a:["ein"],opts:["ein","einen","eine","einer"],hint:"Was für requires a specific article form. Think about the noun's gender.",sSrc:"What kind of {1} vegetables are you buying?"},
{type:"mc",q:"Dreihundertfünfundsechzig = ?",opts:["365","356","563","653"],ans:"365",hint:"dreihundert=300, fünfundsechzig=65."},
{type:"match",pairs:[{trg:"teuer",src:"expensive"},{trg:"günstig",src:"good value"},{trg:"schwer",src:"heavy"},{trg:"leicht",src:"light/easy"},{trg:"billig",src:"cheap"}]},
{type:"drag_fill",s:"Ich habe {1} Bargeld und {2} Kreditkarte. Ich kann {3} bezahlen.",blanks:{"1":"kein","2":"keine","3":"nicht"},pool:["kein","keine","nicht","keinen"],hint:"Bargeld=neuter (kein), Kreditkarte=fem (keine), verb negation (nicht).",sSrc:"I have {1} cash and {2} credit card. I cannot pay {3}."},
{type:"mc",q:"'Jed___ Kunde muss eine Nummer ziehen.'",opts:["jeder","jeden","jedes","jede"],ans:"jeder",hint:"Kunde is masculine. Nominative case. What form does jed- take?"},
{type:"fb",s:"Das Obst ist {1} als das Fleisch.",a:["leichter"],opts:["leichter","schwerer","teurer","billiger"],hint:"Fruit weighs less than meat. Comparative of leicht.",sSrc:"The fruit is {1} than the meat."},
{type:"mc",q:"'___ kaufen Sie ein?'",opts:["Was","Wer","Wo","Wann"],ans:"Was",hint:"Asking about WHAT you are shopping for."},
{type:"fb",s:"Der Preis {1} diesen Fisch ist sieben Euro.",a:["für"],opts:["für","ohne","gegen","durch"],hint:"The price FOR this fish. Which accusative preposition?",sSrc:"The price {1} this fish is seven euros."}
]},

// ─── L8: Küchenparade ───
{id:"deu_r4l8",title:"Küchenparade",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"Küchenparade",desc:"Verumius made it home. Bags borrowed, groceries secured. Time to review everything from the supermarket adventure. All 6 grammar constructs in multi-construct combinations.",goals:["Comprehensive Unit 4 review","Multi-construct quiz steps","Celebrate surviving German shopping"]},
{type:"tip",title:"Victory in the Kitchen",text:"Verumius stands in his kitchen. Results:\n\nNo bags (keine Tüte) = borrowed from a kind Kundin\nPfandautomat rejected his foreign bottle\nForgot to weigh his tomatoes\n\nBut: amazing bread, perfect Schinken, fresh Obst, and cheap Wein.\nVerumius: 1. German supermarket: 0."},
{type:"mc",q:"'Ich kaufe ___ Apfel und ___ Banane.'",opts:["einen ... eine","ein ... eine","einen ... einen","eine ... einen"],ans:"einen ... eine",hint:"One masculine direct object, one feminine direct object. How does ein change for each?"},
{type:"fb",s:"Zweihundert {1} Schinken, bitte.",a:["Gramm"],opts:["Gramm","Liter","Euro","Kilo"],hint:"Deli meat is weighed in this small unit.",sSrc:"Two hundred {1} of ham, please."},
{type:"drag_fill",s:"Ich gehe {1} den Supermarkt und kaufe Obst {2} die Familie, aber {3} Fleisch.",blanks:{"1":"durch","2":"für","3":"ohne"},pool:["durch","für","ohne","gegen","um"],hint:"Through the store, fruit FOR the family, but WITHOUT meat.",sSrc:"I go {1} the supermarket and buy fruit {2} the family, but {3} meat."},
{type:"mc",q:"'Welch___ Brot nehmen Sie?'",opts:["Welches","Welcher","Welchen","Welche"],ans:"Welches",hint:"Brot is neuter. What form does welcher take for neuter accusative?"},
{type:"match",pairs:[{trg:"bezahlen",src:"to pay"},{trg:"überweisen",src:"to transfer"},{trg:"anbieten",src:"to offer"},{trg:"bekommen",src:"to receive"},{trg:"einkaufen",src:"to shop"}]},
{type:"fb",s:"Die Milch kostet ein Euro {1} Cent.",a:["fünfundsiebzig"],opts:["fünfundsiebzig","siebzigfünf","fünfsiebzig","siebenfünfzig"],hint:"German numbers: ones digit first, then und, then tens. Five-and-seventy.",sSrc:"The milk costs one euro {1} cents."},
{type:"drag_fill",s:"{1} Sie {2} Fisch! Er ist heute {3}.",blanks:{"1":"Kaufen","2":"den","3":"günstig"},pool:["Kaufen","den","günstig","Kauf","der","teuer"],hint:"Polite imperative + masculine accusative + good value.",sSrc:"{1} {2} fish! It is {3} today."},
{type:"mc",q:"'Er hat ___ Geld und ___ Kreditkarte.'",opts:["kein ... keine","nicht ... nicht","keinen ... keine","kein ... nicht"],ans:"kein ... keine",hint:"Two nouns: one neuter, one feminine. The noun-negator changes with gender."},
{type:"fb",s:"Jed{1} Kundin muss eine Nummer ziehen.",a:["e"],opts:["e","er","es","en"],hint:"Kundin is feminine. Jeder declines like der. Feminine nom = jede.",sSrc:"Ever{1} customer must take a number."},
{type:"mc",q:"'Was für ___ Wein möchten Sie?'",opts:["einen","ein","eine","einer"],ans:"einen",hint:"Wein is masculine and a direct object. How does ein change in accusative?"},
{type:"drag_fill",s:"Das Hähnchen kostet {1} Euro {2} und die Kartoffeln kosten {3} Euro {4}.",blanks:{"1":"acht","2":"neunzig","3":"zwei","4":"fünfzig"},pool:["acht","neunzig","zwei","fünfzig","neun","achtzig"],hint:"Chicken: 8 Euro 90. Potatoes: 2 Euro 50.",sSrc:"The chicken costs {1} euros {2} and the potatoes cost {3} euros {4}."},
{type:"mc",q:"'Die rote Tasche ist ___. Die blaue ist günstig.'",opts:["teuer","billig","leicht","schwer"],ans:"teuer",hint:"Contrast with günstig. The red bag costs a lot."},
{type:"fb",s:"Ich brauche {1} Kilo Kartoffeln.",a:["ein"],opts:["ein","einen","eine","einer"],hint:"Kilo is neuter. Accusative neuter = no change.",sSrc:"I need {1} kilo of potatoes."},
{type:"mc",q:"'Nimm ___ Brötchen!' (informal)",opts:["das","den","der","die"],ans:"das",hint:"Brötchen is neuter. Du-imperative + neuter acc = das."},
{type:"drag_fill",s:"Verumius hat {1} Tüte und {2} Bargeld. Aber er hat {3} Obst!",blanks:{"1":"keine","2":"kein","3":"frisches"},pool:["keine","kein","frisches","keinen","keines","nicht"],hint:"No bag (fem=keine), no cash (neut=kein), but fresh fruit.",sSrc:"Verumius has {1} bag and {2} cash. But he has {3} fruit!"},
{type:"match",pairs:[{trg:"rot",src:"red"},{trg:"weiß",src:"white"},{trg:"grau",src:"grey"},{trg:"braun",src:"brown"},{trg:"gelb",src:"yellow"}]},
{type:"mc",q:"'Ohne ___ geht man nicht in den Supermarkt.'",opts:["einen Euro","ein Euro","einer Euro","einem Euro"],ans:"einen Euro",hint:"Ohne takes accusative case. What happens to ein with masculine nouns?"},
{type:"fb",s:"Die {1} Leute kaufen hier ein.",a:["meisten"],opts:["meisten","mehr","viel","wenig"],hint:"MOST people shop here. Superlative of viel.",sSrc:"The {1} people shop here."},
{type:"mc",q:"Hundertdreiundfünfzig = ?",opts:["153","135","351","315"],ans:"153",hint:"hundert=100, dreiundfünfzig=53."},
{type:"drag_fill",s:"{1} Sie bitte {2} den Laden und bezahlen Sie {3} Einkauf!",blanks:{"1":"Gehen","2":"durch","3":"den"},pool:["Gehen","durch","den","Geht","der","das"],hint:"Polite: go through the store and pay for the (masc acc) purchase!",sSrc:"{1} please {2} the store and pay for {3} purchase!"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-verumius-kitchen",trg:"Verumius steht in seiner Küche. Brot auf dem Tisch, Obst im Kühlschrank, Wein auf dem Regal. Morgen: kochen. Ohne Rezept, ohne Plan, aber mit Mut. Und mit einer Einkaufsliste. Hildi hat ihm eine geschrieben.",src:"Verumius stands in his kitchen. Bread on the table, fruit in the fridge, wine on the shelf. Tomorrow: cooking. Without a recipe, without a plan, but with courage. And with a shopping list. Hildi wrote him one."}
]},

,

{id:"deu_r4l9",title:"Essen und Trinken",icon:"🍞",xp:15,board:true,steps:[
{type:"intro",title:"Essen und Trinken",desc:"The German breakfast table, the Bäckerei, and everything you need to eat and drink your way through daily life.",goals:["Name common German foods and drinks","Use articles with food nouns","Order and shop for food items"]},
{type:"teach",trg:"der Kaffee",src:"the coffee",note:"Masculine noun. No plural in standard use. 'Zwei Kaffee, bitte!'",example:"A: Möchtest du Kaffee?\nB: Ja, einen Kaffee mit Milch, bitte.",exampleSrc:"A: Would you like coffee?\nB: Yes, a coffee with milk, please.",funFact:"Germany is the 3rd largest coffee consumer in the world, after Finland and the Netherlands. 'Kaffee und Kuchen' (coffee and cake) at 3 PM is a sacred German tradition."},
{type:"teach",trg:"die Milch",src:"the milk",note:"Feminine noun. No plural. 'Mit Milch' = with milk.",example:"A: Trinken Sie Milch?\nB: Nein, ich trinke keine Milch.",exampleSrc:"A: Do you drink milk?\nB: No, I don't drink milk.",funFact:"German distinguishes: Vollmilch (whole milk), fettarme Milch (low-fat), Magermilch (skim). At the supermarket, the cap color tells you which type."},
{type:"teach",trg:"der Tee",src:"the tea",note:"Masculine noun. Plural: die Tees. 'Schwarzer Tee' = black tea.",example:"A: Möchten Sie Tee oder Kaffee?\nB: Tee, bitte. Grünen Tee.",exampleSrc:"A: Would you like tea or coffee?\nB: Tea, please. Green tea.",funFact:"'Tee' comes from Chinese 'te' via Dutch traders. Northern Germany, especially East Frisia, has a tea culture rivaling England's. They drink more tea per capita than any other German region."},
{type:"teach",trg:"das Bier",src:"the beer",note:"Neuter noun. Plural: die Biere. Germany's national drink.",example:"A: Ein Bier, bitte!\nB: Welches Bier? Pils, Weizen oder Kölsch?",exampleSrc:"A: A beer, please!\nB: Which beer? Pilsner, wheat or Kölsch?",funFact:"Germany has the Reinheitsgebot (Purity Law) from 1516: beer may only contain water, barley, and hops. There are over 1,500 breweries and 5,000 beer brands."},
{type:"teach",trg:"der Wein",src:"the wine",note:"Masculine noun. Plural: die Weine. 'Rotwein' = red, 'Weißwein' = white.",example:"A: Trinken Sie Wein?\nB: Ja, ich mag Weißwein.",exampleSrc:"A: Do you drink wine?\nB: Yes, I like white wine.",funFact:"Germany's wine regions along the Rhine and Mosel produce excellent Riesling. Glühwein (mulled wine) is the star of every Christmas market. 'Wein' and English 'wine' come from Latin 'vinum.'"},
{type:"teach",trg:"das Brötchen",src:"the bread roll",note:"Neuter noun. Plural: die Brötchen. Diminutive of 'Brot' (bread).",example:"A: Ich möchte zwei Brötchen, bitte.\nB: Mit Butter und Käse?",exampleSrc:"A: I'd like two bread rolls, please.\nB: With butter and cheese?",funFact:"Brötchen have different names across Germany: Semmel (Bavaria), Schrippe (Berlin), Wecken (Southwest). Starting a 'what is the correct name' debate is a guaranteed conversation starter."},
{type:"teach",trg:"die Kartoffel",src:"the potato",note:"Feminine noun. Plural: die Kartoffeln.",example:"A: Magst du Kartoffeln?\nB: Ja, Bratkartoffeln sind mein Lieblingsessen!",exampleSrc:"A: Do you like potatoes?\nB: Yes, fried potatoes are my favorite food!",funFact:"Kartoffel comes from Italian 'tartufolo' (truffle), because early potatoes looked like truffles. Frederick the Great forced Prussians to eat them. Now Germany eats 60 kg per person per year."},
{type:"teach",trg:"der Reis",src:"the rice",note:"Masculine noun. No standard plural. 'Reis mit Gemüse' = rice with vegetables.",example:"A: Möchten Sie Reis oder Kartoffeln?\nB: Reis, bitte.",exampleSrc:"A: Would you like rice or potatoes?\nB: Rice, please.",funFact:"'Reis' comes from Greek 'oryza' via Latin. In a German Mensa (university cafeteria), Reis mit Sauce is the cheapest meal option. Every student knows it."},
{type:"teach",trg:"der Salat",src:"the salad",note:"Masculine noun. Plural: die Salate. Also means 'lettuce.'",example:"A: Ich nehme einen Salat.\nB: Einen großen oder kleinen Salat?",exampleSrc:"A: I'll have a salad.\nB: A large or small salad?",funFact:"'Salat' in German can mean the dish (salad) OR the plant (lettuce). 'Kopfsalat' = head lettuce. 'Kartoffelsalat' = potato salad, a German BBQ essential with as many recipes as there are grandmothers."},
{type:"teach",trg:"die Birne",src:"the pear",note:"Feminine noun. Plural: die Birnen. Also slang for 'head.'",example:"A: Möchtest du eine Birne?\nB: Ja, die Birnen sehen gut aus!",exampleSrc:"A: Would you like a pear?\nB: Yes, the pears look good!",funFact:"'Birne' also means 'light bulb' (die Glühbirne = glow-pear) because of the shape. And in slang, 'Birne' means 'head': 'Mir raucht die Birne' = my head is smoking (I'm thinking hard)."},
{type:"teach",trg:"der Kuchen",src:"the cake",note:"Masculine noun. Plural: die Kuchen. German Kuchen is a daily treat.",example:"A: Möchtest du ein Stück Kuchen?\nB: Ja, bitte! Apfelkuchen?",exampleSrc:"A: Would you like a piece of cake?\nB: Yes, please! Apple cake?",funFact:"Kaffee und Kuchen at 3 PM is Germany's unofficial fourth meal. Popular types: Schwarzwälder Kirschtorte (Black Forest cake), Apfelkuchen, Bienenstich (bee sting cake)."},
{type:"teach",trg:"der Fisch",src:"the fish",note:"Masculine noun. Plural: die Fische.",example:"A: Essen Sie gern Fisch?\nB: Ja, besonders Lachs.",exampleSrc:"A: Do you like eating fish?\nB: Yes, especially salmon.",funFact:"Fischbrötchen (fish sandwich) is THE street food of northern Germany, especially Hamburg. It is to Hamburg what the Döner is to Berlin."},
{type:"teach",trg:"das Hähnchen",src:"the chicken (cooked)",note:"Neuter noun. Plural: die Hähnchen. Diminutive of Hahn (rooster).",example:"A: Ich möchte Hähnchen, bitte.\nB: Hähnchen mit Reis oder Pommes?",exampleSrc:"A: I'd like chicken, please.\nB: Chicken with rice or fries?",funFact:"Hähnchen means the cooked dish. A living chicken is 'das Huhn.' A rooster is 'der Hahn.' Half a roasted chicken at Oktoberfest is called 'ein halbes Hendl' in Bavarian."},
{type:"teach",trg:"das Ei",src:"the egg",note:"Neuter noun. Plural: die Eier.",example:"A: Wie möchtest du dein Ei?\nB: Weich gekocht, bitte.",exampleSrc:"A: How would you like your egg?\nB: Soft-boiled, please.",funFact:"The German breakfast egg (Frühstücksei) is serious business. There is even a famous comedy sketch about couples arguing over the perfect egg-boiling time: the '4.5 Minuten Ei' debate."},
{type:"teach",trg:"das Öl",src:"the oil",note:"Neuter noun. Plural: die Öle. Used for cooking and other purposes.",example:"A: Kochst du mit Öl oder Butter?\nB: Mit Olivenöl.",exampleSrc:"A: Do you cook with oil or butter?\nB: With olive oil.",funFact:"'Öl' works in compounds: Olivenöl (olive oil), Sonnenblumenöl (sunflower oil), Motoröl (motor oil). Same word for kitchen and garage."},
{type:"teach",trg:"das Salz",src:"the salt",note:"Neuter noun. No standard plural. Essential in every kitchen.",example:"A: Kannst du mir das Salz geben?\nB: Hier, bitte.",exampleSrc:"A: Can you pass me the salt?\nB: Here you go.",funFact:"Salzburg (salt castle) and the word 'salary' both come from salt. In medieval Germany, salt was so valuable it was called 'weißes Gold' (white gold)."},
{type:"teach",trg:"das Glas",src:"the glass",note:"Neuter noun. Plural: die Gläser (with umlaut!).",example:"A: Kann ich ein Glas Wasser haben?\nB: Hier, ein Glas Wasser.",exampleSrc:"A: Can I have a glass of water?\nB: Here, a glass of water.",funFact:"'Ein Glas Wein,' 'ein Glas Bier,' 'ein Glas Wasser.' German uses 'Glas' like English uses 'glass of.' But 'Gläser' (plural) adds an umlaut. Tricky!"},
{type:"teach",trg:"die Flasche",src:"the bottle",note:"Feminine noun. Plural: die Flaschen.",example:"A: Eine Flasche Wasser, bitte.\nB: Mit oder ohne Kohlensäure?",exampleSrc:"A: A bottle of water, please.\nB: Sparkling or still?",funFact:"Germans LOVE sparkling water. If you ask for 'Wasser' in a restaurant, you will get sparkling. Say 'stilles Wasser' for still water. The Pfand (bottle deposit) system means you return bottles for 25 cents each."},
{type:"mc",q:"Which drink is Germany's most traditional?",opts:["das Bier","der Tee","die Milch","der Wein"],ans:"das Bier",hint:"Think Reinheitsgebot, Oktoberfest, and 1,500 breweries."},
{type:"fb",s:"Zwei {1}, bitte. Mit Butter und Käse.",a:["Brötchen"],opts:["Brötchen","Kuchen","Kartoffeln","Eier"],hint:"These small bread rolls are a breakfast staple at the Bäckerei.",sSrc:"Two {1}, please. With butter and cheese."},
{type:"mc",q:"'Kannst du mir das Salz geben?' What does the speaker want?",opts:["The salt","The sugar","A glass","A bottle"],ans:"The salt",hint:"This white seasoning has been called 'white gold' in history."},
{type:"match",pairs:[{trg:"der Kaffee",src:"coffee"},{trg:"die Milch",src:"milk"},{trg:"das Brötchen",src:"bread roll"},{trg:"die Kartoffel",src:"potato"},{trg:"der Fisch",src:"fish"},{trg:"das Ei",src:"egg"}]}
]},

{id:"deu_r4l10",title:"Geld und Maße",icon:"💶",xp:15,board:true,steps:[
{type:"intro",title:"Geld und Maße",desc:"Shopping means numbers. Big numbers. Learn to talk about money, measurements, and everything you need to survive a German supermarket.",goals:["Use large numbers: hundreds, thousands, millions","Name coins, currencies, and measurements","Shop for shoes, jackets, and more"]},
{type:"teach",trg:"der Euro",src:"the euro",note:"Masculine noun. Plural: die Euro (not Euros!). 'Fünf Euro, bitte.'",example:"A: Was kostet das?\nB: Das kostet drei Euro fünfzig.",exampleSrc:"A: How much does that cost?\nB: That costs three euros fifty.",funFact:"Germany switched from the Deutsche Mark to the Euro in 2002. Some older Germans still mentally convert prices to D-Mark. One Euro was 1.95583 DM."},
{type:"teach",trg:"der Cent",src:"the cent",note:"Masculine noun. Plural: die Cent. 100 Cent = 1 Euro.",example:"A: Haben Sie fünfzig Cent?\nB: Nein, nur einen Euro.",exampleSrc:"A: Do you have fifty cents?\nB: No, only a euro.",funFact:"The German 1-Cent coin shows an oak leaf, the 2-Cent shows a Brandenburg Gate. Most Germans want to abolish 1 and 2 Cent coins because they cost more to make than they are worth."},
{type:"teach",trg:"das Konto",src:"the bank account",note:"Neuter noun. Plural: die Konten. From Italian 'conto.'",example:"A: Hast du ein Konto bei der Sparkasse?\nB: Ja, mein Konto ist bei der Sparkasse.",exampleSrc:"A: Do you have an account at Sparkasse?\nB: Yes, my account is at Sparkasse.",funFact:"Germany is still a cash country. Many restaurants and shops do not accept cards. The phrase 'Nur Barzahlung' (cash only) will haunt you. Always carry cash."},
{type:"teach",trg:"einhundert",src:"one hundred (100)",note:"Number. Also simply 'hundert.' 'Einhundert Euro' = 100 euros.",example:"A: Wie viel kostet die Jacke?\nB: Einhundert Euro.",exampleSrc:"A: How much does the jacket cost?\nB: One hundred euros.",funFact:"German numbers get interesting after 20: 'einundzwanzig' (one-and-twenty = 21). The ones digit comes BEFORE the tens. This reversal confuses every English speaker."},
{type:"teach",trg:"zweihundert",src:"two hundred (200)",note:"Number. Pattern: number + hundert. Dreihundert = 300.",example:"A: Wie viel ist die Miete?\nB: Zweihundert Euro pro Zimmer.",exampleSrc:"A: How much is the rent?\nB: Two hundred euros per room.",funFact:"Large German numbers are written as one word: zweihundertfünfunddreißig = 235. This is not a typo. German really does this."},
{type:"teach",trg:"eintausend",src:"one thousand (1000)",note:"Number. Also simply 'tausend.' Pattern: number + tausend.",example:"A: Wie viele Leute wohnen hier?\nB: Eintausend in diesem Haus.",exampleSrc:"A: How many people live here?\nB: One thousand in this building.",funFact:"In German, the dot and comma are swapped: 1.000 = one thousand, 1,5 = one point five. This causes endless confusion with prices and bank transfers."},
{type:"teach",trg:"siebenzig",src:"seventy (70)",note:"Number. Not siebzig! The 'en' stays: sieben + zig = siebenzig.",example:"A: Mein Opa ist siebenzig.\nB: Siebenzig? Er sieht jung aus!",exampleSrc:"A: My grandpa is seventy.\nB: Seventy? He looks young!",funFact:"'Siebenzig' keeps the full 'sieben,' unlike 'siebzehn' (17) which shortens to 'sieb.' German numbers are not always consistent with their shortening rules."},
{type:"teach",trg:"die Million",src:"the million",note:"Feminine noun. Plural: die Millionen. 'Eine Million Euro.'",example:"A: Berlin hat drei Millionen Einwohner.\nB: Und München?",exampleSrc:"A: Berlin has three million inhabitants.\nB: And Munich?",funFact:"Unlike English, 'Million' is a noun in German, so it takes an article: 'eine Million.' After eine, it stays singular. After zwei+: 'zwei Millionen' (with -en)."},
{type:"teach",trg:"die Milliarde",src:"the billion (1,000,000,000)",note:"Feminine noun. Plural: die Milliarden. NOT 'Billion' in German!",example:"A: Die Erde hat acht Milliarden Menschen.\nB: Das sind viele Leute!",exampleSrc:"A: Earth has eight billion people.\nB: That is a lot of people!",funFact:"TRAP: German 'Billion' = English 'trillion' (1,000,000,000,000). German 'Milliarde' = English 'billion.' This causes business misunderstandings worth billions (or Milliarden)."},
{type:"teach",trg:"der Grad",src:"the degree",note:"Masculine noun. Plural: die Grade. For temperature and angles.",example:"A: Wie warm ist es?\nB: Zwanzig Grad.",exampleSrc:"A: How warm is it?\nB: Twenty degrees.",funFact:"Germany uses Celsius. 20 Grad = comfortable. 30 Grad = hot (Germans start complaining). 35 Grad = emergency (schools may close). 0 Grad = normal winter."},
{type:"teach",trg:"das Kilo",src:"the kilogram (short form)",note:"Neuter noun. Short for Kilogramm. 'Ein Kilo Äpfel, bitte.'",example:"A: Ein Kilo Kartoffeln, bitte.\nB: Hier, genau ein Kilo.",exampleSrc:"A: A kilo of potatoes, please.\nB: Here, exactly one kilo.",funFact:"At German markets, you buy by the Kilo (or Pfund = 500g). 'Ein halbes Kilo' = half a kilo = 500g. Supermarket scales at the fruit section are self-service."},
{type:"teach",trg:"der Kilometer",src:"the kilometer",note:"Masculine noun. Plural: die Kilometer. Abbreviated: km.",example:"A: Wie weit ist es bis Hamburg?\nB: Dreihundert Kilometer.",exampleSrc:"A: How far is it to Hamburg?\nB: Three hundred kilometers.",funFact:"The German Autobahn has sections with NO speed limit. The recommended speed is 130 km/h, but some drivers go 200+. 'Freie Fahrt für freie Bürger' (free driving for free citizens) is an unofficial motto."},
{type:"teach",trg:"der Zentimeter",src:"the centimeter",note:"Masculine noun. Plural: die Zentimeter. Abbreviated: cm.",example:"A: Wie groß bist du?\nB: Eins achtzig. Hundertachtzig Zentimeter.",exampleSrc:"A: How tall are you?\nB: One eighty. A hundred eighty centimeters.",funFact:"Germans say height in meters: 'eins achtzig' = 1.80m. Not in feet and inches. If someone is 'eins neunzig' (1.90m), they are considered tall."},
{type:"teach",trg:"das Prozent",src:"the percent",note:"Neuter noun. 'Zwanzig Prozent Rabatt' = 20% discount.",example:"A: Wie viel Rabatt gibt es?\nB: Zwanzig Prozent auf alles!",exampleSrc:"A: How much discount is there?\nB: Twenty percent off everything!",funFact:"German stores have two big sale seasons: Sommerschlussverkauf (summer clearance) and Winterschlussverkauf (winter clearance). Discounts of 50-70 Prozent are common."},
{type:"teach",trg:"der Teil",src:"the part / piece",note:"Masculine noun. Plural: die Teile. 'Zum Teil' = partly.",example:"A: Das ist nur ein Teil des Problems.\nB: Und der andere Teil?",exampleSrc:"A: That is only one part of the problem.\nB: And the other part?",funFact:"'Teil' builds many compounds: Stadtteil (city district), Nachteil (disadvantage, literally 'night-part'), Vorteil (advantage, 'fore-part'), Urteil (judgment)."},
{type:"teach",trg:"der Automat",src:"the vending machine / ATM",note:"Masculine noun. Plural: die Automaten. From Greek 'automatos.'",example:"A: Wo ist ein Automat?\nB: Dort drüben, neben der Tür.",exampleSrc:"A: Where is a vending machine?\nB: Over there, next to the door.",funFact:"German train stations have Fahrkartenautomaten (ticket machines) that accept coins, cards, and bills. The interface is available in 10+ languages. They replace most ticket counters."},
{type:"teach",trg:"die Jacke",src:"the jacket",note:"Feminine noun. Plural: die Jacken.",example:"A: Zieh deine Jacke an, es ist kalt!\nB: Ich brauche keine Jacke.",exampleSrc:"A: Put on your jacket, it is cold!\nB: I do not need a jacket.",funFact:"Germans have a saying: 'Es gibt kein schlechtes Wetter, nur schlechte Kleidung.' There is no bad weather, only bad clothing. A good Jacke solves everything."},
{type:"teach",trg:"der Schuh",src:"the shoe",note:"Masculine noun. Plural: die Schuhe. German shoe sizes differ from US/UK.",example:"A: Welche Schuhgröße haben Sie?\nB: Zweiundvierzig.",exampleSrc:"A: What shoe size do you have?\nB: Forty-two.",funFact:"German shoe sizes: 42 = US 9 / UK 8. The system (Pariser Stich) measures in 2/3 cm increments. If someone says 'Schuhgröße 42,' they mean European 42."},
{type:"teach",trg:"die Tasche",src:"the bag / pocket",note:"Feminine noun. Plural: die Taschen. Dual meaning!",example:"A: Hast du eine Tasche?\nB: Ja, meine Tasche ist hier.",exampleSrc:"A: Do you have a bag?\nB: Yes, my bag is here.",funFact:"Tasche = bag AND pocket. 'Hosentasche' = pants pocket. 'Handtasche' = handbag. 'Taschenlampe' = pocket lamp (flashlight). 'Taschenbuch' = pocket book (paperback)."},
{type:"teach",trg:"verkaufen",src:"to sell",note:"Inseparable prefix verb: ich verkaufe, du verkaufst. Opposite: kaufen (buy).",example:"A: Verkaufen Sie auch Briefmarken?\nB: Nein, nur am Schalter.",exampleSrc:"A: Do you also sell stamps?\nB: No, only at the counter.",funFact:"'Ver-' often adds a negative or intensive meaning: kaufen (buy) vs verkaufen (sell). 'Ver-' flips the direction. Similarly: mieten (rent) vs vermieten (rent out)."},
{type:"teach",trg:"zahlen",src:"to pay",note:"Regular verb: ich zahle, du zahlst. 'Ich möchte zahlen' = check please.",example:"A: Ich möchte zahlen, bitte.\nB: Bar oder mit Karte?",exampleSrc:"A: I would like to pay, please.\nB: Cash or card?",funFact:"'Zahlen, bitte!' is how you ask for the check in a German restaurant. The waiter brings a portable card reader or counts change from a wallet. No bill left on the table."},
{type:"teach",trg:"meist",src:"mostly / most",note:"Superlative adverb. 'Meistens' = usually/most of the time.",example:"A: Was isst du meistens zum Frühstück?\nB: Meistens Brötchen mit Käse.",exampleSrc:"A: What do you usually eat for breakfast?\nB: Mostly bread rolls with cheese.",funFact:"'Am meisten' = the most (superlative of viel). 'Meistens' = most of the time. 'Der Meister' = the master. All from the same root."},
{type:"mc",q:"A German says their height is 'eins fünfundachtzig.' How tall are they?",opts:["1.85 meters","185 pounds","1.85 feet","185 kilometers"],ans:"1.85 meters",hint:"Germans use the metric system for height, not feet or pounds."},
{type:"fb",s:"Das kostet {1} Euro fünfzig.",a:["drei"],opts:["drei","der","die","das"],hint:"A number! The price is X euros and fifty cents.",sSrc:"That costs {1} euros fifty."},
{type:"match",pairs:[{trg:"der Euro",src:"euro"},{trg:"der Cent",src:"cent"},{trg:"das Kilo",src:"kilogram"},{trg:"die Jacke",src:"jacket"},{trg:"der Schuh",src:"shoe"},{trg:"die Tasche",src:"bag"}]}
]}
]},
// ═══════════════════════════════════════════════════════════════
// UNIT 5: Hunger! -- Zusammen oder Getrennt?
// Story: Verumius at the Gasthaus, meets Lukas, modal verbs, dative preps
// CEFR: A1.1 - Restaurant, modals, dative prepositions, likes/dislikes
// ═══════════════════════════════════════════════════════════════
{n:5,lang:"de",srcLang:"en",track:"v2",title:"Hunger!",sub:"Restaurant, modal verbs & dative prepositions",icon:"🍽️",level:"A1.1",color:"#7B5EE8",lessons:[

// ─── L1: Was gibt's zum Essen? ───
{id:"deu_r5l1",title:"Was gibt's zum Essen?",icon:"🍽️",xp:15,board:true,steps:[
{type:"intro",title:"Was gibt's zum Essen?",desc:"Lerne die wichtigsten Wörter rund ums Essen und Trinken in Deutschland.",goals:["Mahlzeiten benennen","essen und trinken konjugieren","Im Restaurant bestellen"]},
{type:"teach",trg:"der Freund",src:"the friend (male)",note:"Masculine noun. Plural: die Freunde.\n'Mein Freund' can mean 'my boyfriend' or 'my male friend' depending on context.",example:"A: Wer ist Lukas?\nB: Lukas ist mein Freund. Wir essen zusammen.\nA: Ein guter Freund?",exampleSrc:"A: Who is Lukas?\nB: Lukas is my friend. We eat together.\nA: A good friend?",funFact:"'Freund' comes from the same root as English 'friend.' In Germany, being called 'ein Freund' means something deep. Germans distinguish between 'Bekannte' (acquaintances) and 'Freunde' (real friends). Making the jump takes time."},
{type:"teach",trg:"schön",src:"beautiful / nice / lovely",note:"One of the most common German adjectives.\nComparative: schöner. Superlative: am schönsten.",example:"A: Das Wetter ist heute schön!\nB: Ja, schön warm. Ein schöner Tag.\nA: Schön, dass du hier bist.",exampleSrc:"A: The weather is beautiful today!\nB: Yes, nicely warm. A beautiful day.\nA: Nice that you are here.",funFact:"Germans use 'schön' for everything: schönes Wetter (nice weather), schöne Grüße (kind regards), na schön (all right then), schön gemacht (well done). It is one of the five most common adjectives in German."},
{type:"teach",trg:"das Herz",src:"the heart",note:"Neuter noun. Plural: die Herzen.\nAlso used figuratively: 'von Herzen' = from the heart.",example:"A: Dieses Lied geht mir ans Herz.\nB: Mir auch. Es ist so schön.\nA: Von Herzen danke für den schönen Abend.",exampleSrc:"A: This song touches my heart.\nB: Mine too. It is so beautiful.\nA: Thank you from the heart for the lovely evening.",funFact:"Lebkuchenherz (gingerbread heart) is a classic German fair souvenir with icing messages like 'Ich liebe dich' or 'Schatz.' The word 'herzlich' (heartfelt, warm) comes from Herz. 'Herzlich willkommen!' = A heartfelt welcome!"},
{type:"teach",trg:"das Frühstück",src:"breakfast",note:"Neuter noun. From früh (early) + Stück (piece).",example:"A: Was gibt es zum Frühstück?\nB: Brötchen mit Käse und Marmelade.",exampleSrc:"A: What is there for breakfast?\nB: Rolls with cheese and jam.",funFact:"Germans take breakfast seriously. A typical Frühstück includes fresh rolls, cold cuts, cheese, jam, and a soft-boiled egg."},
{type:"teach",trg:"der Mittag",src:"noon, midday",note:"Masculine noun. Also used in Mittagessen (lunch).",example:"A: Wann ist Mittag?\nB: Um zwölf Uhr.",exampleSrc:"A: When is noon?\nB: At twelve o'clock.",funFact:"Mittagessen is traditionally the biggest meal of the day in Germany, though this is changing in cities."},
{type:"teach",trg:"der Abend",src:"evening",note:"Masculine noun. Abendessen means dinner or supper.",example:"A: Was machst du heute Abend?\nB: Ich koche Abendessen.",exampleSrc:"A: What are you doing this evening?\nB: I am cooking dinner.",funFact:"Abendbrot (evening bread) is a common light dinner of bread, cold cuts, and cheese."},
{type:"mc",q:"Which meal is traditionally the biggest in Germany?",opts:["das Frühstück","das Mittagessen","das Abendessen","das Abendbrot"],ans:"das Mittagessen",hint:"Think about the midday meal tradition."},
{type:"teach",trg:"das Essen",src:"food, meal",note:"Neuter noun. Also means 'the eating' as a gerund.",example:"A: Wie ist das Essen hier?\nB: Das Essen ist sehr gut!",exampleSrc:"A: How is the food here?\nB: The food is very good!",funFact:"Das Essen can mean both the food itself and the act of eating. Context tells you which."},
{type:"teach",trg:"essen",src:"to eat",note:"Irregular verb: ich esse, du isst, er/sie isst. The vowel changes in du/er forms.",example:"A: Was isst du gern?\nB: Ich esse gern Brot mit Käse.",exampleSrc:"A: What do you like to eat?\nB: I like to eat bread with cheese.",funFact:"The vowel change e to i in du isst is a classic strong verb pattern in German."},
{type:"teach",trg:"trinken",src:"to drink",note:"Regular conjugation: ich trinke, du trinkst, er/sie trinkt.",example:"A: Was trinkst du?\nB: Ich trinke Kaffee.",exampleSrc:"A: What are you drinking?\nB: I am drinking coffee.",funFact:"Germans drink more coffee per capita than beer. About 162 liters of coffee per year!"},
{type:"fb",s:"Ich {1} jeden Morgen ein Brötchen.",a:["esse"],opts:["esse","isst","essen","esst"],hint:"The vowel change only happens in du/er forms, not ich.",sSrc:"I {1} a bread roll every morning."},
{type:"teach",trg:"frühstücken",src:"to have breakfast",note:"Regular verb formed from Frühstück + -en.",example:"A: Frühstückst du zu Hause?\nB: Nein, ich frühstücke im Büro.",exampleSrc:"A: Do you have breakfast at home?\nB: No, I have breakfast at the office.",funFact:"Frühstücken is one of many German verbs made directly from a noun. Noun to verb, just add -en!"},
{type:"teach",trg:"der Appetit",src:"appetite",note:"Masculine noun. Used in the phrase Guten Appetit!",example:"A: Das Essen ist fertig!\nB: Wunderbar! Guten Appetit!",exampleSrc:"A: The food is ready!\nB: Wonderful! Enjoy your meal!",funFact:"Saying Guten Appetit before eating is essential etiquette in Germany. Not saying it is considered rude."},
{type:"teach",trg:"die Speisekarte",src:"menu",note:"Feminine noun. Speise (dish) + Karte (card).",example:"A: Kann ich bitte die Speisekarte haben?\nB: Natürlich, hier bitte.",exampleSrc:"A: Can I have the menu please?\nB: Of course, here you go.",funFact:"In Germany, you often have to ask for the menu. It is not always brought automatically."},
{type:"teach",trg:"die Speisenkarte",src:"menu (variant spelling)",note:"Feminine noun. Same meaning as Speisekarte, with an extra -n-.",example:"A: Haben Sie eine Speisenkarte?\nB: Ja, einen Moment bitte.",exampleSrc:"A: Do you have a menu?\nB: Yes, one moment please.",funFact:"Both Speisekarte and Speisenkarte are correct. You will see both in restaurants across Germany."},
{type:"mc",q:"What do Germans say before eating a meal?",opts:["Guten Appetit!","Guten Morgen!","Guten Tag!","Guten Abend!"],ans:"Guten Appetit!",hint:"It involves a word you just learned about hunger and food."},
{type:"teach",trg:"die Zigarette",src:"cigarette",note:"Feminine noun. Borrowed from French.",example:"A: Rauchst du?\nB: Nein, ich rauche keine Zigaretten.",exampleSrc:"A: Do you smoke?\nB: No, I do not smoke cigarettes.",funFact:"Smoking is banned in restaurants and bars across Germany since 2007, though rules vary by state."},
{type:"teach",trg:"rauchen",src:"to smoke",note:"Regular verb: ich rauche, du rauchst, er/sie raucht.",example:"A: Darf man hier rauchen?\nB: Nein, rauchen ist hier verboten.",exampleSrc:"A: Is smoking allowed here?\nB: No, smoking is forbidden here.",funFact:"The word Rauch also means smoke as a noun. Räucherlachs (smoked salmon) uses the same root."},
{type:"fb",s:"Kann ich bitte die {1} haben?",a:["Speisekarte"],opts:["Speisekarte","Essen","Appetit","Frühstück"],hint:"You are asking for something to read before ordering.",sSrc:"Can I please have the {1}?"},
{type:"match",pairs:[{trg:"das Frühstück",src:"breakfast"},{trg:"der Mittag",src:"noon"},{trg:"der Abend",src:"evening"},{trg:"trinken",src:"to drink"},{trg:"die Speisekarte",src:"menu"}]},
{type:"mc",q:"Ich ___ gern Brot. Which form of essen fits?",opts:["esse","isst","esst","essen"],ans:"esse",hint:"The subject is ich. What happens to the vowel?"},
{type:"fb",s:"Guten {1}! Das Essen sieht lecker aus.",a:["Appetit"],opts:["Appetit","Morgen","Abend","Tag"],hint:"A polite phrase said before meals.",sSrc:"Enjoy your {1}! The food looks delicious."},
{type:"tip",title:"Im Gasthaus",text:"A Gasthaus is a traditional German inn or restaurant. When you arrive:\n1. Wait to be seated or find a free table.\n2. Ask: Kann ich die Speisekarte haben?\n3. Say Guten Appetit before eating.\n4. To pay: Zahlen bitte! or Die Rechnung bitte!",deepDive:{title:"Restaurant culture",text:"In Germany, tipping is not as high as in the US. Rounding up or adding 5 to 10 percent is normal. You say the total amount you want to pay, including tip, when handing money to the server."}},
{type:"mc",q:"Which word means the same as Speisekarte?",opts:["Speisenkarte","Rechnung","Bestellung","Kellner"],ans:"Speisenkarte",hint:"It is a variant spelling with one extra letter."}
]},

// ─── L2: Wie schmeckt's? ───
{id:"deu_r5l2",title:"Wie schmeckt's?",icon:"😋",xp:15,board:true,steps:[
{type:"intro",title:"Wie schmeckt's?",desc:"Lerne Adjektive für Geschmack, Stimmung und Vorlieben. Drücke aus, was du magst und was dir gefällt.",goals:["Adjektive für Geschmack und Stimmung","gern/gerne benutzen","gefallen und lieben unterscheiden"]},
{type:"teach",trg:"wunderbar",src:"wonderful",note:"Adjective/adverb. Works the same way as English wonderful.",example:"A: Wie schmeckt die Suppe?\nB: Wunderbar! Wirklich lecker.",exampleSrc:"A: How does the soup taste?\nB: Wonderful! Really delicious.",funFact:"Wunderbar became internationally famous through the Kinder chocolate bar of the same name."},
{type:"teach",trg:"schlecht",src:"bad",note:"Adjective. Opposite of gut (good).",example:"A: Wie geht es dir?\nB: Mir geht es schlecht. Ich bin krank.",exampleSrc:"A: How are you?\nB: I am doing badly. I am sick.",funFact:"Schlechtes Wetter (bad weather) is a very common phrase in Germany. Germans love talking about weather."},
{type:"teach",trg:"einfach",src:"simple, easy",note:"Adjective/adverb. Also used as 'just' or 'simply'.",example:"A: Ist Deutsch schwer?\nB: Nein, es ist einfach!",exampleSrc:"A: Is German hard?\nB: No, it is easy!",funFact:"Einfach also means 'one-way' for tickets. Eine einfache Fahrkarte is a one-way ticket."},
{type:"teach",trg:"lustig",src:"funny, fun",note:"Adjective. Not to be confused with English 'lusty'.",example:"A: Der Film war sehr lustig.\nB: Ja, ich habe viel gelacht!",exampleSrc:"A: The film was very funny.\nB: Yes, I laughed a lot!",funFact:"Lustig is a false friend. It means funny, not lustful. The German word for lustful is lüstern."},
{type:"mc",q:"Das Essen ist ___! Ich liebe es! Which word fits best?",opts:["wunderbar","schlecht","bitter","laut"],ans:"wunderbar",hint:"The speaker loves the food. Pick the positive word."},
{type:"teach",trg:"laut",src:"loud",note:"Adjective. Opposite of leise.",example:"A: Die Musik ist zu laut!\nB: Entschuldigung, ich mache sie leiser.",exampleSrc:"A: The music is too loud!\nB: Sorry, I will turn it down.",funFact:"Laut also means 'according to' as a preposition: laut dem Bericht (according to the report)."},
{type:"teach",trg:"leise",src:"quiet, soft (sound)",note:"Adjective. Describes low volume, not personality.",example:"A: Kannst du bitte leise sein?\nB: Entschuldigung, ich bin schon still.",exampleSrc:"A: Can you please be quiet?\nB: Sorry, I am already silent.",funFact:"Leise Töne means subtle hints. Germans use leise figuratively for anything understated."},
{type:"teach",trg:"ruhig",src:"calm, peaceful",note:"Adjective. Describes a calm atmosphere or person.",example:"A: Wie ist das Restaurant?\nB: Sehr ruhig und gemütlich.",exampleSrc:"A: How is the restaurant?\nB: Very calm and cozy.",funFact:"Ruhig also works as a particle meaning 'go ahead': Du kannst ruhig fragen means Feel free to ask."},
{type:"fb",s:"Die Bibliothek ist sehr {1}. Man hört nichts.",a:["ruhig"],opts:["ruhig","laut","lustig","schlecht"],hint:"A library is a peaceful, quiet place.",sSrc:"The library is very {1}. You can't hear anything."},
{type:"teach",trg:"bitter",src:"bitter",note:"Adjective. Same word in English and German.",example:"A: Wie schmeckt der Kaffee?\nB: Er ist ein bisschen bitter.",exampleSrc:"A: How does the coffee taste?\nB: It is a little bitter.",funFact:"Bitterschokolade is dark chocolate in German. Literally: bitter chocolate."},
{type:"teach",trg:"zufrieden",src:"satisfied, content",note:"Adjective. Often used with mit (with).",example:"A: Bist du zufrieden mit dem Essen?\nB: Ja, sehr zufrieden!",exampleSrc:"A: Are you satisfied with the food?\nB: Yes, very satisfied!",funFact:"Zufrieden comes from zu (to) + Frieden (peace). Being satisfied literally means being at peace."},
{type:"teach",trg:"zusammen",src:"together",note:"Adverb. Also used when paying: zusammen oder getrennt?",example:"A: Zusammen oder getrennt?\nB: Zusammen bitte.",exampleSrc:"A: Together or separate?\nB: Together please.",funFact:"In Germany, waiters always ask zusammen oder getrennt? (together or separate?) when you want to pay."},
{type:"mc",q:"The waiter asks: Zusammen oder getrennt? What is being asked?",opts:["One bill or separate bills","Eat in or take away","Cash or card","Smoking or non-smoking"],ans:"One bill or separate bills",hint:"Zusammen = together. Getrennt = ___. The waiter asks about the check."},
{type:"teach",trg:"gern",src:"gladly, with pleasure",note:"Adverb. Used with verbs to express liking: Ich koche gern.",example:"A: Kochst du gern?\nB: Ja, ich koche sehr gern!",exampleSrc:"A: Do you like cooking?\nB: Yes, I really like cooking!",funFact:"Gern is the short form. Gerne means exactly the same thing. Both are equally correct."},
{type:"teach",trg:"gerne",src:"gladly, with pleasure",note:"Adverb. Longer form of gern, identical in meaning.",example:"A: Möchtest du Kaffee?\nB: Ja, gerne!",exampleSrc:"A: Would you like coffee?\nB: Yes, gladly!",funFact:"Gerne! by itself is a common reply meaning Yes please! or With pleasure!"},
{type:"teach",trg:"gefallen",src:"to please, to like (something pleases you)",note:"The thing liked is the subject: Das Buch gefällt mir (The book pleases me).",example:"A: Gefällt dir das Restaurant?\nB: Ja, es gefällt mir sehr gut!",exampleSrc:"A: Do you like the restaurant?\nB: Yes, I like it a lot!",funFact:"Gefallen flips the subject. You do not like the book. The book likes you. This confuses many learners at first."},
{type:"teach",trg:"lieben",src:"to love",note:"Regular verb: ich liebe, du liebst. Stronger than mögen or gern.",example:"A: Liebst du Schokolade?\nB: Ja, ich liebe Schokolade!",exampleSrc:"A: Do you love chocolate?\nB: Yes, I love chocolate!",funFact:"Ich liebe dich (I love you) is one of the most searched German phrases worldwide."},
{type:"fb",s:"Ich schwimme {1}. Es macht Spaß!",a:["gern"],opts:["gern","schlecht","bitter","laut"],hint:"You enjoy swimming. Which adverb expresses liking an activity?",sSrc:"I swim {1}. It is fun!"},
{type:"mc",q:"Das Buch gefällt mir. What is the subject of this sentence?",opts:["The book","Me / I","The pleasure","Nobody"],ans:"The book",hint:"In gefallen sentences, the thing that pleases is the grammatical subject."},
{type:"tip",title:"gern vs gefallen vs lieben",text:"Three ways to say you like something:\n1. gern/gerne + verb: Ich lese gern. (I like reading.)\n2. gefallen + dative: Das gefällt mir. (That pleases me.)\n3. lieben: Ich liebe Musik. (I love music.)\n\ngern is for activities, gefallen is for impressions, lieben is the strongest.",deepDive:{title:"Why gefallen flips the subject",text:"Gefallen literally means 'to please.' The thing you like is doing the pleasing, so it becomes the subject. Das Essen gefällt mir = The food pleases me. If you want to say 'I like the food,' the German structure puts the food first as the subject and you in the dative case (mir)."}},
{type:"match",pairs:[{trg:"wunderbar",src:"wonderful"},{trg:"schlecht",src:"bad"},{trg:"lustig",src:"funny"},{trg:"leise",src:"quiet"},{trg:"zufrieden",src:"satisfied"},{trg:"zusammen",src:"together"}]},
{type:"fb",s:"Der Film ist sehr {1}. Alle lachen.",a:["lustig"],opts:["lustig","leise","bitter","ruhig"],hint:"Everyone is laughing. The film must be funny.",sSrc:"The film is very {1}. Everyone is laughing."},
{type:"mc",q:"Ich koche gern. What does this sentence mean?",opts:["I like cooking.","I cook well.","I must cook.","I am cooking."],ans:"I like cooking.",hint:"Gern after a verb expresses enjoyment of that activity."}
]},

// ─── L3: Ich kann das nicht lesen! ───
{id:"deu_r5l3",title:"Ich kann das nicht lesen!",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Ich kann das nicht lesen!",desc:"Lerne die drei wichtigsten Modalverben: können, müssen, wollen. Entdecke, wie sie den Satzbau verändern.",goals:["können, müssen, wollen konjugieren","Modalverb-Satzstruktur verstehen","Wünsche und Pflichten ausdrücken"]},
{type:"teach",trg:"können",src:"can, to be able to",note:"Modal verb. Irregular: ich kann, du kannst, er kann. Infinitive goes to end.",example:"A: Kannst du Deutsch sprechen?\nB: Ja, ich kann ein bisschen Deutsch sprechen.",exampleSrc:"A: Can you speak German?\nB: Yes, I can speak a little German.",funFact:"Können changes its vowel from ö to a in singular forms. This pattern is typical for German modal verbs."},
{type:"teach",trg:"müssen",src:"must, to have to",note:"Modal verb. Irregular: ich muss, du musst, er muss. Expresses necessity.",example:"A: Musst du morgen arbeiten?\nB: Ja, ich muss um acht Uhr anfangen.",exampleSrc:"A: Do you have to work tomorrow?\nB: Yes, I have to start at eight o'clock.",funFact:"Nicht müssen means 'do not have to,' not 'must not.' This catches many English speakers off guard."},
{type:"teach",trg:"wollen",src:"to want",note:"Modal verb. Irregular: ich will, du willst, er will. Expresses desire.",example:"A: Was willst du essen?\nB: Ich will Pizza bestellen.",exampleSrc:"A: What do you want to eat?\nB: I want to order pizza.",funFact:"German ich will sounds like English 'I will,' but means 'I want.' Will for future is ich werde."},
{type:"tip",title:"Modal verb sentence structure",text:"Modal verbs change word order:\n1. The modal verb is conjugated and takes position 2.\n2. The main verb goes to the END in infinitive form.\n\nIch spreche Deutsch. (normal)\nIch kann Deutsch sprechen. (with modal)\n\nThe modal is conjugated, the main verb stays infinitive at the end.",deepDive:{title:"Why the verb goes to the end",text:"German has a verb bracket (Satzklammer). The conjugated verb stays in position 2, but any additional verb forms move to the end. This creates a bracket around the middle of the sentence. With modals: Ich [kann] heute Abend nicht [kommen]. The modal opens the bracket, the infinitive closes it."}},
{type:"verb_table",title:"können (can)",groups:[{label:"Present tense",rows:[{pronoun:"ich",form:"kann",src:"I can"},{pronoun:"du",form:"kannst",src:"you can"},{pronoun:"er/sie/es",form:"kann",src:"he/she/it can"},{pronoun:"wir",form:"können",src:"we can"},{pronoun:"ihr",form:"könnt",src:"you all can"},{pronoun:"sie/Sie",form:"können",src:"they/you (formal) can"}]}],note:"Notice: ich and er/sie/es have the same form (kann). The vowel changes from ö to a in singular."},
{type:"mc",q:"Du ___ sehr gut kochen! Which form of können fits?",opts:["kannst","kann","können","könnt"],ans:"kannst",hint:"The subject is du. Add -st to the singular stem."},
{type:"fb",s:"Ich {1} Deutsch sprechen.",a:["kann"],opts:["kann","kannst","können","könnt"],hint:"First person singular of können.",sSrc:"I {1} speak German."},
{type:"teach",trg:"verboten",src:"forbidden, prohibited",note:"Adjective/past participle. From verbieten (to forbid).",example:"A: Darf ich hier rauchen?\nB: Nein, das ist verboten!",exampleSrc:"A: May I smoke here?\nB: No, that is forbidden!",funFact:"Verboten signs are everywhere in Germany. Germans are known for following rules, and these signs are taken seriously."},
{type:"verb_table",title:"müssen (must)",groups:[{label:"Present tense",rows:[{pronoun:"ich",form:"muss",src:"I must"},{pronoun:"du",form:"musst",src:"you must"},{pronoun:"er/sie/es",form:"muss",src:"he/she/it must"},{pronoun:"wir",form:"müssen",src:"we must"},{pronoun:"ihr",form:"müsst",src:"you all must"},{pronoun:"sie/Sie",form:"müssen",src:"they/you (formal) must"}]}],note:"Same pattern: ü to u in singular. ich and er/sie/es share the same form (muss)."},
{type:"mc",q:"Wir ___ um 8 Uhr da sein. Which modal verb fits?",opts:["müssen","muss","musst","müsst"],ans:"müssen",hint:"The subject is wir. Use the plural form."},
{type:"teach",trg:"lieb",src:"dear, sweet, kind",note:"Adjective. Used for people: ein liebes Kind (a sweet child).",example:"A: Dein Sohn ist sehr lieb.\nB: Danke, das ist nett von dir!",exampleSrc:"A: Your son is very sweet.\nB: Thanks, that is nice of you!",funFact:"Lieb is related to lieben (to love). Liebling means darling or favorite."},
{type:"teach",trg:"böse",src:"angry, evil, naughty",note:"Adjective. Context determines the meaning: angry (person) or evil (character).",example:"A: Bist du böse auf mich?\nB: Nein, ich bin nicht böse.",exampleSrc:"A: Are you angry with me?\nB: No, I am not angry.",funFact:"Böse auf means angry at someone. Der Böse means the villain. The Brothers Grimm used böse for all their fairy tale villains."},
{type:"verb_table",title:"wollen (to want)",groups:[{label:"Present tense",rows:[{pronoun:"ich",form:"will",src:"I want"},{pronoun:"du",form:"willst",src:"you want"},{pronoun:"er/sie/es",form:"will",src:"he/she/it wants"},{pronoun:"wir",form:"wollen",src:"we want"},{pronoun:"ihr",form:"wollt",src:"you all want"},{pronoun:"sie/Sie",form:"wollen",src:"they/you (formal) want"}]}],note:"Vowel change o to i in singular. Remember: will means want, not future tense!"},
{type:"fb",s:"Er {1} heute Abend ins Kino gehen.",a:["will"],opts:["will","wollen","wollt","willst"],hint:"Third person singular of wollen.",sSrc:"He {1} to go to the cinema tonight."},
{type:"mc",q:"Ich kann Deutsch ___. Where does the infinitive go?",opts:["sprechen (at the end)","sprechen (after ich)","spreche (at the end)","gesprochen (at the end)"],ans:"sprechen (at the end)",hint:"With modal verbs, the main verb goes to the end in infinitive form."},
{type:"drag_fill",s:"Wir {1} heute Abend Pizza {2}.",blanks:{"1":"müssen","2":"essen"},pool:["müssen","essen","muss","isst"],hint:"We have to eat pizza tonight. Modal in position 2, main verb at end.",sSrc:"We {1} to eat pizza {2} tonight."},
{type:"mc",q:"Ich muss nicht arbeiten. What does this mean?",opts:["I do not have to work.","I must not work.","I cannot work.","I will not work."],ans:"I do not have to work.",hint:"Nicht müssen means lack of obligation, not prohibition."},
{type:"fb",s:"Ich {1} eine Bratwurst bestellen.",a:["will"],opts:["will","kann","muss","wollen"],hint:"You want to order a sausage. Which modal expresses desire?",sSrc:"I {1} to order a bratwurst."},
{type:"drag_fill",s:"Sie {1} gut Deutsch {2} und {3} mehr {4}.",blanks:{"1":"kann","2":"sprechen","3":"will","4":"lernen"},pool:["kann","sprechen","will","lernen","muss","können"],hint:"She can speak German well and wants to learn more. Two modal clauses joined.",sSrc:"She {1} speak German well {2} and {3} to learn more {4}."},
{type:"mc",q:"Kannst du das ___? I cannot read it!",opts:["verstehen","verboten","müssen","lieb"],ans:"verstehen",hint:"The speaker cannot read something and asks if you can understand it."},
{type:"tip",title:"Zusammengesetzte Wörter",text:"German is famous for compound words:\n\nSpeise + Karte = Speisekarte (menu)\nFrüh + Stück = Frühstück (breakfast)\nAbend + Essen = Abendessen (dinner)\nMittag + Essen = Mittagessen (lunch)\n\nThe last word determines the gender: die Karte, so die Speisekarte.",deepDive:{title:"The longest German words",text:"German compounds can get very long. Rindfleischetikettierungsüberwachungsaufgabenübertragungsgesetz was an actual law about beef labeling. The rule is simple: take any nouns, stick them together, and the last noun gives the gender and plural form."}}
]},

// ─── L4: Darf ich? Soll ich? Möchtest du? ───
{id:"deu_r5l4",title:"Darf ich? Soll ich? Möchtest du?",icon:"🎭",xp:20,board:true,steps:[
{type:"intro",title:"Darf ich? Soll ich? Möchtest du?",desc:"Three more modal verbs complete the set. Permission, obligation, and the politest way to order anything in Germany.",goals:["dürfen (permission), sollen (should), mögen (like)","möchten: the polite ordering form","Comparatives: besser, lieber, am besten"]},
{type:"teach",trg:"dürfen",src:"may / to be allowed to",note:"The permission modal. 'Darf ich?' = May I?",example:"A: Darf ich hier sitzen?\nB: Ja, natürlich!",exampleSrc:"A: May I sit here?\nB: Yes, of course!",funFact:"'Nicht dürfen' = must not / forbidden. 'Nicht müssen' = don't have to. Critical difference! Mixing them up causes chaos."},
{type:"teach",trg:"sollen",src:"should / to be supposed to",note:"For advice and expectations. 'Du sollst nicht stehlen.'",example:"A: Soll ich bestellen?\nB: Ja, bitte!",exampleSrc:"A: Should I order?\nB: Yes, please!",funFact:"Used for advice, expectations, and reported instructions. Less about personal desire, more about what others expect."},
{type:"teach",trg:"mögen",src:"to like (general)",note:"'Ich mag Kaffee.' Subjunctive 'möchten' = would like.",example:"A: Magst du Fisch?\nB: Ja, ich mag Fisch sehr!",exampleSrc:"A: Do you like fish?\nB: Yes, I like fish a lot!",funFact:"'Mögen' = general liking. 'Möchten' (would like) is the REAL star: the politest way to order. 'Ich möchte einen Kaffee, bitte.'"},
{type:"verb_table",title:"dürfen / sollen / mögen",groups:[{label:"dürfen (may)",rows:[{pronoun:"ich",form:"darf",src:"I may"},{pronoun:"du",form:"darfst",src:"you may"},{pronoun:"er/sie/es",form:"darf",src:"he/she/it may"},{pronoun:"wir",form:"dürfen",src:"we may"}]},{label:"sollen (should)",rows:[{pronoun:"ich",form:"soll",src:"I should"},{pronoun:"du",form:"sollst",src:"you should"},{pronoun:"er/sie/es",form:"soll",src:"he/she/it should"},{pronoun:"wir",form:"sollen",src:"we should"}]},{label:"mögen / möchten",rows:[{pronoun:"ich",form:"mag / möchte",src:"I like / I'd like"},{pronoun:"du",form:"magst / möchtest",src:"you like / you'd like"},{pronoun:"er/sie/es",form:"mag / möchte",src:"likes / would like"},{pronoun:"wir",form:"mögen / möchten",src:"we like / we'd like"}]}],note:"All three: no ending on ich/er forms. Möchten is THE polite ordering form."},
{type:"mc",q:"'Darf ich hier rauchen?' asks about:",opts:["Am I allowed to smoke here?","Must I smoke here?","Should I smoke here?","Do I want to smoke here?"],ans:"Am I allowed to smoke here?",hint:"Dürfen is about permission."},
{type:"fb",s:"Man {1} hier nicht rauchen. Es ist verboten!",a:["darf"],opts:["darf","soll","muss","kann"],hint:"Permission denied = prohibition. Not ability.",sSrc:"One {1} not smoke here. It is forbidden!"},
{type:"teach",trg:"besser",src:"better (comparative of gut)",note:"Irregular: gut, besser, am besten.",example:"A: Wie ist das Restaurant?\nB: Besser als gestern!",exampleSrc:"A: How is the restaurant?\nB: Better than yesterday!",funFact:"Gut, besser, am besten. Irregular just like English 'good, better, best.'"},
{type:"teach",trg:"lieber",src:"rather / preferably (comparative of gern)",note:"'Ich esse lieber Fisch' = I prefer eating fish.",example:"A: Trinkst du lieber Bier oder Wein?\nB: Ich trinke lieber Wein.",exampleSrc:"A: Do you prefer beer or wine?\nB: I prefer wine.",funFact:"If gern = gladly, lieber = more gladly = preferably. Express preferences effortlessly."},
{type:"teach",trg:"am besten",src:"best (superlative of gut)",note:"'Das ist das beste Restaurant!' Irregular superlative.",example:"A: Welches Essen ist am besten?\nB: Der Schweinebraten ist am besten!",exampleSrc:"A: Which food is the best?\nB: The pork roast is the best!",funFact:"'Am besten' = best of all. The superlative of the irregular gut-besser-best chain."},
{type:"mc",q:"Lukas: '___ du den Schweinebraten?'",opts:["Möchtest","Willst","Darfst","Sollst"],ans:"Möchtest",hint:"Lukas is being polite. Which modal is the politest offer?"},
{type:"tip",title:"The 6 Modal Verbs: Complete Set",text:"können: ability (I CAN swim)\nmüssen: necessity (I MUST eat)\nwollen: desire (I WANT that)\ndürfen: permission (MAY I?)\nsollen: expectation (I SHOULD help)\nmögen/möchten: liking / polite want\n\nAll follow the same pattern:\n1. Conjugated modal in position 2\n2. Main verb as infinitive at the END\n3. No ending on ich and er/sie/es forms"},
{type:"fb",s:"{1} ich Ihnen etwas empfehlen?",a:["Darf"],opts:["Darf","Muss","Wird","Hat"],hint:"The waiter is asking for permission to make a suggestion.",sSrc:"{1} I recommend something to you?"},
{type:"drag_fill",s:"Ich {1} den Fisch, aber Lukas {2} lieber den Schweinebraten {3}.",blanks:{"1":"möchte","2":"will","3":"essen"},pool:["möchte","will","essen","kann","trinken","muss"],hint:"One speaker is polite, the other is direct. Use two different modals.",sSrc:"I {1} the fish, but Lukas {2} prefer the pork roast {3}."},
{type:"mc",q:"Which expression means 'must not' (forbidden)?",opts:["nicht dürfen","nicht müssen","nicht sollen","nicht können"],ans:"nicht dürfen",hint:"To forbid something, you negate the permission modal."},
{type:"fb",s:"Du {1} mehr Wasser trinken. Das ist gesund.",a:["sollst"],opts:["sollst","darfst","willst","magst"],hint:"Friendly advice: what you SHOULD do.",sSrc:"You {1} drink more water. That is healthy."},
{type:"mc",q:"Most polite way to order:",opts:["Ich möchte einen Kaffee, bitte.","Ich will einen Kaffee.","Gib mir einen Kaffee.","Ich muss einen Kaffee haben."],ans:"Ich möchte einen Kaffee, bitte.",hint:"The subjunctive form of mögen is the most polite way to order."},
{type:"drag_fill",s:"Man {1} hier nicht rauchen, aber man {2} draußen {3}.",blanks:{"1":"darf","2":"kann","3":"rauchen"},pool:["darf","kann","rauchen","muss","soll","trinken"],hint:"MAY NOT inside, but CAN outside. Permission vs ability.",sSrc:"One {1} not smoke here, but one {2} outside {3}."},
{type:"mc",q:"'Ich esse lieber Fisch.' Lieber expresses:",opts:["preference","love","permission","ability"],ans:"preference",hint:"Lieber is comparative of gern. More gladly = preferably."},
{type:"fb",s:"Das Essen hier ist {1} als im anderen Restaurant.",a:["besser"],opts:["besser","lieber","best","wunderbar"],hint:"Comparing two things. Comparative of gut.",sSrc:"The food here is {1} than at the other restaurant."},
{type:"mc",q:"Welches Restaurant ist am ___?",opts:["besten","besser","gut","lieber"],ans:"besten",hint:"Superlative with 'am': am + ___en. Best of all."},
{type:"drag_fill",s:"Lukas {1} Bier, aber er {2} heute lieber Wasser {3}.",blanks:{"1":"mag","2":"möchte","3":"trinken"},pool:["mag","möchte","trinken","kann","will","essen"],hint:"He LIKES beer general. Today he'd LIKE to drink water.",sSrc:"Lukas {1} beer, but today he {2} prefer to drink water {3}."},
{type:"match",pairs:[{trg:"können",src:"can/able to"},{trg:"müssen",src:"must/have to"},{trg:"wollen",src:"to want"},{trg:"dürfen",src:"may/allowed"},{trg:"sollen",src:"should"},{trg:"mögen",src:"to like"}]}
]},

// ─── L5: Ich bestelle für uns beide! ───
{id:"deu_r5l5",title:"Ich bestelle für uns beide!",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"Ich bestelle für uns beide!",desc:"Lukas takes charge. Restaurant action verbs and separable verbs at the table. Time to order like a pro.",goals:["Restaurant action verbs","Separable verbs: mitbringen, mitnehmen","Order food confidently"]},
{type:"teach",trg:"bestellen",src:"to order",note:"Regular. 'Ich möchte bestellen' = I'd like to order.",example:"A: Kann ich bitte bestellen?\nB: Natürlich! Was möchten Sie?",exampleSrc:"A: Can I please order?\nB: Of course! What would you like?",funFact:"The single most important restaurant verb. Waiters ask 'Haben Sie schon bestellt?' (Have you already ordered?)."},
{type:"teach",trg:"empfehlen",src:"to recommend",note:"Irregular: ich empfehle, du empfiehlst, er empfiehlt.",example:"A: Was empfehlen Sie?\nB: Ich empfehle den Schweinebraten!",exampleSrc:"A: What do you recommend?\nB: I recommend the pork roast!",funFact:"Vowel change e to ie. 'Was empfehlen Sie?' is the perfect question when the menu is incomprehensible."},
{type:"verb_table",title:"empfehlen (to recommend)",groups:[{label:"Present tense (stem change: e → ie)",rows:[{pronoun:"ich",form:"empfehle",src:"I recommend"},{pronoun:"du",form:"empfiehlst",src:"you recommend"},{pronoun:"er/sie/es",form:"empfiehlt",src:"he/she/it recommends"},{pronoun:"wir",form:"empfehlen",src:"we recommend"},{pronoun:"ihr",form:"empfehlt",src:"you all recommend"},{pronoun:"sie/Sie",form:"empfehlen",src:"they/you (formal) recommend"}]}],note:"Same e → ie pattern as lesen (liest)."},
{type:"teach",trg:"schmecken",src:"to taste",note:"'Schmeckt's?' = Does it taste good? Highest food compliment.",example:"A: Wie schmeckt das Essen?\nB: Es schmeckt wunderbar!",exampleSrc:"A: How does the food taste?\nB: It tastes wonderful!",funFact:"'Schmeckt's?' is how every German grandma checks on you mid-meal. 'Es schmeckt!' needs no object. It just tastes good."},
{type:"mc",q:"The waiter asks: 'Was ___ Sie?' What is he asking?",opts:["möchten","schmecken","empfehlen","riechen"],ans:"möchten",hint:"He wants to know what you'd like to order."},
{type:"teach",trg:"kochen",src:"to cook",note:"Regular. Also means 'to boil': Das Wasser kocht.",example:"A: Kannst du kochen?\nB: Ja, ich koche gern!",exampleSrc:"A: Can you cook?\nB: Yes, I like cooking!",funFact:"'Kochen' also means 'to boil.' 'Das Wasser kocht' = the water is boiling. A versatile kitchen verb."},
{type:"teach",trg:"riechen",src:"to smell",note:"Irregular: riechen, roch, gerochen. Present tense is regular.",example:"A: Das Essen riecht gut!\nB: Ja, der Koch ist sehr gut.",exampleSrc:"A: The food smells good!\nB: Yes, the cook is very good.",funFact:"'Das riecht gut!' is what you say walking past a Bäckerei. German noses are well-trained."},
{type:"teach",trg:"grillen",src:"to grill / to barbecue",note:"Regular. A national summer sport in Germany.",example:"A: Wollen wir am Samstag grillen?\nB: Ja, ich bringe Würstchen mit!",exampleSrc:"A: Shall we grill on Saturday?\nB: Yes, I'll bring sausages!",funFact:"Germans LOVE grilling. Parks fill with smoke every warm Saturday. It is always charcoal, never gas. That is a rule."},
{type:"fb",s:"Das Essen {1} fantastisch! Der Koch ist toll.",a:["riecht"],opts:["riecht","schmeckt","kocht","bestellt"],hint:"You haven't eaten yet. You are using your nose.",sSrc:"The food {1} fantastic! The cook is great."},
{type:"teach",trg:"mitbringen",src:"to bring along",note:"Separable: ich bringe Wein mit. Prefix goes to the end.",example:"A: Ich bringe Kuchen mit.\nB: Super! Ich freue mich.",exampleSrc:"A: I'll bring cake.\nB: Great! I'm looking forward to it.",funFact:"'Bring bitte Brot mit!' is a common request. Separable: the 'mit' goes to the end."},
{type:"teach",trg:"mitnehmen",src:"to take along / to go",note:"Separable: ich nehme den Kaffee mit. 'Zum Mitnehmen' = to go.",example:"A: Zum Mitnehmen, bitte.\nB: Kommt sofort!",exampleSrc:"A: To go, please.\nB: Coming right up!",funFact:"'Zum Mitnehmen' is how you order food to go in Germany. Mit (along) + nehmen (take)."},
{type:"mc",q:"'Zum Mitnehmen' means:",opts:["to go / take away","for here","for two people","without tip"],ans:"to go / take away",hint:"'Mit' = along, 'nehmen' = to take. Take along."},
{type:"fb",s:"Was {1} der Kellner heute?",a:["empfiehlt"],opts:["empfiehlt","bestellt","kocht","schmeckt"],hint:"The waiter is suggesting something. Vowel change: e to ie.",sSrc:"What does the waiter {1} today?"},
{type:"tip",title:"Separable Verbs at the Restaurant",text:"Two new separable verbs:\n\nmitbringen: Ich bringe Wein mit.\nmitnehmen: Ich nehme den Kaffee mit.\n\nWith modals, the prefix stays attached:\nIch kann Wein mitbringen.\nIch will den Kaffee mitnehmen.\n\nThe modal bracket keeps separable verbs whole!"},
{type:"drag_fill",s:"Ich {1} einen Kaffee zum {2}.",blanks:{"1":"möchte","2":"Mitnehmen"},pool:["möchte","Mitnehmen","kann","Essen"],hint:"I'd like a coffee TO GO.",sSrc:"I {1} a coffee to go {2}."},
{type:"mc",q:"'Das Essen ___! Wunderbar!'",opts:["schmeckt","riecht","kocht","bestellt"],ans:"schmeckt",hint:"He is eating it now. It is about the TASTE."},
{type:"fb",s:"Am Samstag {1} wir im Garten.",a:["grillen"],opts:["grillen","kochen","bestellen","essen"],hint:"Outside, with charcoal. A German summer tradition.",sSrc:"On Saturday we {1} in the garden."},
{type:"drag_fill",s:"Lukas {1} das Schnitzel und Verumius {2} den Schweinebraten {3}.",blanks:{"1":"bestellt","2":"möchte","3":"bestellen"},pool:["bestellt","möchte","bestellen","kann","kochen","empfiehlt"],hint:"Lukas orders (conjugated). Verumius would LIKE to order (modal + infinitive).",sSrc:"Lukas {1} the schnitzel and Verumius {2} to order the pork roast {3}."},
{type:"mc",q:"'Ich bringe morgen Kuchen mit.' Where does the prefix go?",opts:["At the end of the sentence","Before the verb","After the subject","It doesn't separate"],ans:"At the end of the sentence",hint:"Separable verbs: prefix to the end."},
{type:"match",pairs:[{trg:"bestellen",src:"to order"},{trg:"empfehlen",src:"to recommend"},{trg:"schmecken",src:"to taste"},{trg:"riechen",src:"to smell"},{trg:"kochen",src:"to cook"},{trg:"grillen",src:"to grill"}]},
{type:"fb",s:"Ich {1} Bier mit. Wir trinken zusammen!",a:["bringe"],opts:["bringe","nehme","koche","bestelle"],hint:"Bringing something along to share. Separable: prefix at end.",sSrc:"I {1} beer along. We drink together!"},
{type:"mc",q:"Verumius asks the waiter: 'Was ___ Sie?'",opts:["empfehlen","bestellen","schmecken","kochen"],ans:"empfehlen",hint:"He is asking for a recommendation. Formal Sie = infinitive form."}
]},

// ─── L6: Aus der Küche, mit Liebe ───
{id:"deu_r5l6",title:"Aus der Küche, mit Liebe",icon:"🏨",xp:20,board:true,steps:[
{type:"intro",title:"Aus der Küche, mit Liebe",desc:"Seven prepositions that ALWAYS take dative. Plus hotel vocabulary. Lukas mentions he works 'bei einer Firma.' Every sentence has one of these little words.",goals:["7 dative prepositions: aus/bei/mit/nach/seit/von/zu","Hotel vocabulary","Dative article changes"]},
{type:"tip",title:"Dative Prepositions: The Magic 7",text:"Seven prepositions ALWAYS take dative:\n\naus: out of / from (origin)\nbei: at / near / with (someone's place)\nmit: with\nnach: after / to (cities, countries)\nseit: since / for (time)\nvon: from / of / by\nzu: to (people, places, events)\n\nMnemonic: 'Aus-bei-mit, nach-seit, von-zu'\nSing it like a chant. Germans learn it this way too.",deepDive:{title:"How Dative Changes Articles",text:"der becomes dem, die becomes der, das becomes dem, plural die becomes den (+n on noun). Masculine and neuter look the same in dative: dem/einem. You already know accusative (den/einen). Dative is the 'receiver' case."}},
{type:"verb_table",title:"Dative Articles After Prepositions",groups:[{label:"Definite",rows:[{pronoun:"masculine (der)",form:"dem",src:"mit dem Mann"},{pronoun:"feminine (die)",form:"der",src:"mit der Frau"},{pronoun:"neuter (das)",form:"dem",src:"mit dem Kind"},{pronoun:"plural (die)",form:"den (+n)",src:"mit den Kindern"}]},{label:"Indefinite",rows:[{pronoun:"masculine (ein)",form:"einem",src:"mit einem Mann"},{pronoun:"feminine (eine)",form:"einer",src:"mit einer Frau"},{pronoun:"neuter (ein)",form:"einem",src:"mit einem Kind"}]}],note:"Masculine and neuter look the same in dative: dem/einem."},
{type:"mc",q:"'Ich komme aus ___ Küche.' (die Küche)",opts:["der","die","dem","den"],ans:"der",hint:"Küche is feminine. After 'aus' (dative), die becomes der."},
{type:"fb",s:"Das Essen kommt aus {1} Küche.",a:["der"],opts:["der","die","dem","den"],hint:"'Aus' always demands the same case. What happens to 'die' in that case?",sSrc:"The food comes from {1} kitchen."},
{type:"mc",q:"'Ich esse mit ___ Freund.' (ein Freund)",opts:["einem","einen","einer","ein"],ans:"einem",hint:"Mit requires dative case. Masculine dative ein form?"},
{type:"fb",s:"Nach {1} Essen gehen wir spazieren.",a:["dem"],opts:["dem","das","den","der"],hint:"Neuter noun after nach. Dative case changes the article.",sSrc:"After {1} meal we go for a walk."},
{type:"teach",trg:"übernachten",src:"to stay overnight",note:"Regular. Über (over) + Nacht (night) = to overnight somewhere.",example:"A: Wo übernachtest du?\nB: Ich übernachte in einem Hotel.",exampleSrc:"A: Where are you staying overnight?\nB: I'm staying in a hotel.",funFact:"Works for hotels, hostels, friends' couches. 'Übernachtung' = overnight stay. Every booking site uses it."},
{type:"teach",trg:"das Einzelzimmer",src:"the single room",note:"Neuter. Einzel (single) + Zimmer (room).",example:"A: Haben Sie ein Einzelzimmer?\nB: Ja, für wie viele Nächte?",exampleSrc:"A: Do you have a single room?\nB: Yes, for how many nights?",funFact:"At German hotel reception: 'Ein Einzelzimmer, bitte.' Compound words are your friends now."},
{type:"teach",trg:"das Doppelzimmer",src:"the double room",note:"Neuter. Doppel (double) + Zimmer (room).",example:"A: Ich möchte ein Doppelzimmer.\nB: Mit Frühstück?",exampleSrc:"A: I would like a double room.\nB: With breakfast?",funFact:"Can mean twin beds OR a double bed. Specify 'mit Doppelbett' if you need the big bed."},
{type:"teach",trg:"die Rezeption",src:"the reception / front desk",note:"Feminine. Same word as English, German pronunciation.",example:"A: Fragen Sie an der Rezeption.\nB: Danke, ich gehe sofort hin.",exampleSrc:"A: Ask at the reception.\nB: Thanks, I'll go right away.",funFact:"The go-to place for complaints, key cards, and asking 'Wo ist das WLAN?'"},
{type:"teach",trg:"die Halbpension",src:"half board (breakfast + dinner)",note:"Feminine. Halb (half) + Pension (board).",example:"A: Ist das mit Halbpension?\nB: Ja, Frühstück und Abendessen inklusive.",exampleSrc:"A: Is that with half board?\nB: Yes, breakfast and dinner included.",funFact:"Vollpension = full board (all meals). Halbpension is the sweet spot: breakfast and dinner at the hotel, lunch on your own."},
{type:"mc",q:"Verumius braucht ein Zimmer für eine Person. Was braucht er?",opts:["ein Einzelzimmer","ein Doppelzimmer","die Halbpension","die Rezeption"],ans:"ein Einzelzimmer",hint:"Single person = single room."},
{type:"fb",s:"Ich übernachte in {1} Hotel.",a:["einem"],opts:["einem","ein","einer","einen"],hint:"Neuter noun. In + dative for location. Dative ein form?",sSrc:"I am staying overnight in {1} hotel."},
{type:"drag_fill",s:"Er wohnt seit {1} Jahr bei {2} Freund.",blanks:{"1":"einem","2":"einem"},pool:["einem","einer","einen","dem","der"],hint:"seit and bei both take dative. Jahr (neuter) and Freund (masc) both get 'einem.'",sSrc:"He has been living for {1} year with {2} friend."},
{type:"mc",q:"'Ich gehe zu ___ Rezeption.' (die Rezeption)",opts:["der","die","dem","den"],ans:"der",hint:"Rezeption is feminine. After 'zu' (dative), die becomes der."},
{type:"fb",s:"Das Brot kommt von {1} Bäckerei.",a:["der"],opts:["der","die","dem","den"],hint:"'Von' demands the same case as 'aus.' Apply it to a feminine noun.",sSrc:"The bread comes from {1} bakery."},
{type:"drag_fill",s:"Nach {1} Frühstück gehen wir zu {2} Rezeption und fragen nach {3} Einzelzimmer.",blanks:{"1":"dem","2":"der","3":"einem"},pool:["dem","der","einem","den","die","ein"],hint:"das Frühstück = dem, die Rezeption = der, ein Einzelzimmer (neut) = einem. All dative.",sSrc:"After {1} breakfast we go to {2} reception and ask about {3} single room."},
{type:"mc",q:"Which preposition means 'since' or 'for' (time)?",opts:["seit","von","aus","nach"],ans:"seit",hint:"Which dative preposition indicates duration or starting point in time?"},
{type:"match",pairs:[{trg:"aus",src:"out of / from"},{trg:"bei",src:"at / near / with"},{trg:"mit",src:"with"},{trg:"nach",src:"after / to"},{trg:"seit",src:"since / for"},{trg:"von",src:"from / of"},{trg:"zu",src:"to"}]},
{type:"fb",s:"Ich möchte ein Doppelzimmer mit {1}.",a:["Halbpension"],opts:["Halbpension","Rezeption","Einzelzimmer","Frühstück"],hint:"Breakfast AND dinner included. Half of all meals.",sSrc:"I would like a double room with {1}."},
{type:"mc",q:"'Aus-bei-mit, nach-seit, von-zu' all have in common:",opts:["They always take dative case","They always take accusative case","They are modal verbs","They are separable prefixes"],ans:"They always take dative case",hint:"The magic 7 chant. These prepositions all demand the same case."}
]},

// ─── L7: Zusammen oder Getrennt? ───
{id:"deu_r5l7",title:"Zusammen oder Getrennt?",icon:"💰",xp:20,board:true,steps:[
{type:"intro",title:"Zusammen oder Getrennt?",desc:"The big moment. Verumius must order, eat, and pay. What could go wrong? All grammar constructs in communicative action.",goals:["Order food in a restaurant","Express likes and abilities","Survive paying the bill"]},
{type:"tip",title:"Scene: Ordering",text:"Kellner: 'Was möchten Sie bestellen?'\nVerumius looks at Lukas. Lukas nods encouragingly.\nVerumius: 'Ich möchte... den... Schweine...braten?'\nKellner: 'Sehr gute Wahl! Und zu trinken?'\nVerumius: 'Ein Wasser, bitte.'\nKellner: 'Still oder mit Kohlensäure?'\nVerumius: '...'\nLukas: 'Zwei Sprudel, bitte.'"},
{type:"mc",q:"You want Schweinebraten. How do you start?",opts:["Ich möchte den Schweinebraten, bitte.","Ich will Schweinebraten!","Gib mir Schweinebraten.","Schweinebraten, schnell!"],ans:"Ich möchte den Schweinebraten, bitte.",hint:"The subjunctive form of mögen is the polite ordering formula."},
{type:"fb",s:"Und zu {1}, bitte?",a:["trinken"],opts:["trinken","essen","bestellen","kochen"],hint:"The waiter is asking about drinks. 'And to ___?'",sSrc:"And to {1}, please?"},
{type:"drag_fill",s:"Ich {1} bitte die Speisekarte {2}, und dann {3} ich {4}.",blanks:{"1":"möchte","2":"haben","3":"kann","4":"bestellen"},pool:["möchte","haben","kann","bestellen","will","essen"],hint:"I'd LIKE to HAVE the menu, then I CAN order. Two modal brackets.",sSrc:"I {1} please have the menu {2}, and then I {3} {4}."},
{type:"mc",q:"Lukas: 'Schmeckt's?' Verumius sagt:",opts:["Es schmeckt wunderbar!","Ich kann nicht schmecken.","Es riecht gut.","Ich will schmecken."],ans:"Es schmeckt wunderbar!",hint:"He is eating and it tastes great."},
{type:"fb",s:"Ich esse {1} Schweinebraten als Fisch.",a:["lieber"],opts:["lieber","besser","gern","am besten"],hint:"Expressing preference between two things. Comparative of gern.",sSrc:"I {1} eat pork roast than fish."},
{type:"tip",title:"Scene: The Bill",text:"The meal is over. Verumius is zufrieden.\nKellner: 'Zusammen oder getrennt?'\nVerumius freezes. Together or separate? The food? The table? His life?\nLukas whispers: 'Er fragt, ob wir zusammen oder getrennt bezahlen.'\nVerumius: 'Ah! Zusammen!'\nHe reaches for his card. The waiter shakes his head.\n'Nur Bargeld.'\nVerumius has no cash."},
{type:"mc",q:"'Zusammen oder getrennt?' asks about:",opts:["paying together or splitting the bill","sitting together or apart","eating here or taking away","ordering one dish or two"],ans:"paying together or splitting the bill",hint:"Zusammen = together. Getrennt = separated. Think about the check."},
{type:"mc",q:"'Nur Bargeld' means the restaurant accepts:",opts:["only cash","only cards","only euros","only coins"],ans:"only cash",hint:"Bar = ___. Geld = money. What does Bargeld mean for payment?"},
{type:"fb",s:"Verumius {1} nicht bezahlen. Er hat kein Bargeld.",a:["kann"],opts:["kann","will","muss","darf"],hint:"He is NOT ABLE to pay. An ability problem.",sSrc:"Verumius {1} not pay. He has no cash."},
{type:"drag_fill",s:"Lukas: 'Ich {1} für uns beide {2}. Du {3} mir morgen das Geld {4}.'",blanks:{"1":"kann","2":"bezahlen","3":"kannst","4":"mitbringen"},pool:["kann","bezahlen","kannst","mitbringen","muss","geben"],hint:"Lukas CAN pay for both. Verumius CAN bring the money tomorrow.",sSrc:"Lukas: 'I {1} pay for both of us {2}. You {3} bring me the money tomorrow {4}.'"},
{type:"mc",q:"How does Verumius say he LIKES the food?",opts:["Das Essen schmeckt mir!","Ich kann das Essen!","Ich muss das Essen!","Das Essen gefällt mir schlecht!"],ans:"Das Essen schmeckt mir!",hint:"Schmecken + dative = tastes good to me."},
{type:"fb",s:"Ich mag das Restaurant. Es {1} mir hier.",a:["gefällt"],opts:["gefällt","schmeckt","kann","will"],hint:"The restaurant is pleasing TO ME. Gefallen with dative.",sSrc:"I like the restaurant. It {1} me here."},
{type:"tip",title:"Scene: Walking Home",text:"Lukas and Verumius walk through the evening streets.\nLukas: 'Von wo kommst du?'\nVerumius: 'Aus den Niederlanden. Ich bin seit einer Woche hier.'\nLukas: 'Nur eine Woche? Du kannst schon gut bestellen!'\nVerumius laughs. He has a friend now. A real one.\nLukas: 'Hier, meine Nummer. Wir können zusammen Deutsch üben.'\nVerumius: 'Das ist lieb von dir.'"},
{type:"mc",q:"'Von wo kommst du?' asks about:",opts:["where you come from","where you are going","what you want","how you feel"],ans:"where you come from",hint:"Von = from. Wo = where."},
{type:"fb",s:"Ich bin seit {1} Woche in Deutschland.",a:["einer"],opts:["einer","eine","einem","ein"],hint:"Seit = dative. Woche is feminine. Dative form of eine?",sSrc:"I have been in Germany for {1} week."},
{type:"drag_fill",s:"Lukas kommt aus {1} Stadt und arbeitet bei {2} Firma.",blanks:{"1":"der","2":"einer"},pool:["der","einer","dem","die","einem","ein"],hint:"die Stadt (fem) = der in dative. eine Firma (fem) = einer in dative.",sSrc:"Lukas comes from {1} city and works at {2} company."},
{type:"mc",q:"'Ich ___ jetzt besser bestellen!'",opts:["kann","muss","darf","soll"],ans:"kann",hint:"He has improved! He is now ABLE to order."},
{type:"fb",s:"Das war das {1} Essen in Deutschland!",a:["beste"],opts:["beste","bessere","gute","wunderbare"],hint:"Superlative: gut, besser, am ___. After das, what form?",sSrc:"That was the {1} food in Germany!"},
{type:"mc",q:"Three levels of liking:",opts:["gern < gefallen < lieben","können < müssen < wollen","schmecken < riechen < kochen","bestellen < empfehlen < mitbringen"],ans:"gern < gefallen < lieben",hint:"Like < be pleased by < love."}
]},

// ─── L8: Stammtisch-Prüfung ───
{id:"deu_r5l8",title:"Stammtisch-Prüfung",icon:"🍻",xp:20,board:true,steps:[
{type:"intro",title:"Stammtisch-Prüfung",desc:"Verumius returns to the Gasthaus. This time, he is ready. Lukas saved him a seat at the Stammtisch. Full unit review.",goals:["All 6 modals in context","Dative prepositions mastery","Full restaurant communicative skills"]},
{type:"mc",q:"Der Kellner: 'Was ___ Sie trinken?'",opts:["möchten","können","müssen","sollen"],ans:"möchten",hint:"The polite way to ask what someone wants."},
{type:"fb",s:"Ich möchte die {1}, bitte.",a:["Speisekarte"],opts:["Speisekarte","Zigarette","Rezeption","Halbpension"],hint:"You need this to see what is available to eat.",sSrc:"I would like the {1}, please."},
{type:"mc",q:"'Ich kann jetzt die Speisekarte lesen!' Verumius expresses:",opts:["He is able to read the menu now.","He must read the menu.","He wants to read the menu.","He should read the menu."],ans:"He is able to read the menu now.",hint:"Können = ability. He has learned!"},
{type:"drag_fill",s:"Ich {1} den Schweinebraten {2}, und mein Freund {3} die Käsespätzle {4}.",blanks:{"1":"möchte","2":"bestellen","3":"will","4":"haben"},pool:["möchte","bestellen","will","haben","kann","essen"],hint:"One speaker is polite, the other direct. Two different modals + infinitive at end.",sSrc:"I {1} to order the pork roast {2}, and my friend {3} to have the cheese spaetzle {4}."},
{type:"fb",s:"Das Essen {1} wunderbar!",a:["schmeckt"],opts:["schmeckt","riecht","kocht","bestellt"],hint:"You are eating it. The taste is wonderful.",sSrc:"The food {1} wonderful!"},
{type:"mc",q:"'Ich trinke lieber Bier.' means:",opts:["I prefer beer.","I drink better beer.","I drink the best beer.","I can drink beer."],ans:"I prefer beer.",hint:"Lieber = preferably. Comparative of gern."},
{type:"drag_fill",s:"Das Brot kommt aus {1} Küche und das Bier kommt von {2} Brauerei.",blanks:{"1":"der","2":"der"},pool:["der","dem","die","den","einer","einem"],hint:"Both Küche and Brauerei are feminine. Dative: die becomes der.",sSrc:"The bread comes from {1} kitchen and the beer comes from {2} brewery."},
{type:"mc",q:"'Darf man hier rauchen?' 'Nein, das ist ___.'",opts:["verboten","einfach","lustig","wunderbar"],ans:"verboten",hint:"Forbidden! Not allowed."},
{type:"fb",s:"Ich wohne seit {1} Monat in Deutschland.",a:["einem"],opts:["einem","ein","einen","einer"],hint:"Seit = dative. Monat is masculine. Dative form of ein?",sSrc:"I have been living in Germany for {1} month."},
{type:"mc",q:"Which sentence uses modal + separable verb correctly?",opts:["Ich kann Wein mitbringen.","Ich kann Wein bringe mit.","Ich mitbringe kann Wein.","Ich bringe kann Wein mit."],ans:"Ich kann Wein mitbringen.",hint:"With modals, separable verbs stay as one infinitive at the end."},
{type:"drag_fill",s:"Er {1} nicht {2}, weil es {3} ist.",blanks:{"1":"darf","2":"rauchen","3":"verboten"},pool:["darf","rauchen","verboten","kann","essen","schlecht"],hint:"He is not ALLOWED to smoke because it is forbidden.",sSrc:"He {1} not {2}, because it is {3}."},
{type:"fb",s:"Die Atmosphäre {1} mir sehr gut.",a:["gefällt"],opts:["gefällt","schmeckt","mag","kann"],hint:"The atmosphere is pleasing TO ME. Subject = atmosphere.",sSrc:"The atmosphere {1} me very much."},
{type:"mc",q:"'Zusammen oder getrennt?' You want one bill:",opts:["Zusammen, bitte.","Getrennt, bitte.","Alles, bitte.","Bargeld, bitte."],ans:"Zusammen, bitte.",hint:"Together = one bill for everyone."},
{type:"match",pairs:[{trg:"können",src:"can/able to"},{trg:"müssen",src:"must/have to"},{trg:"dürfen",src:"may/allowed"},{trg:"wollen",src:"to want"},{trg:"sollen",src:"should"},{trg:"mögen",src:"to like"}]},
{type:"fb",s:"Ich übernachte in {1} Hotel mit Halbpension.",a:["einem"],opts:["einem","ein","einer","einen"],hint:"Neuter noun. In + dative for location. Dative ein form?",sSrc:"I am staying overnight in {1} hotel with half board."},
{type:"drag_fill",s:"Nach {1} Essen gehen wir zu {2} Hotel und fragen an {3} Rezeption nach {4} Einzelzimmer.",blanks:{"1":"dem","2":"dem","3":"der","4":"einem"},pool:["dem","dem","der","einem","den","einer"],hint:"Essen(neut)=dem, Hotel(neut)=dem, Rezeption(fem)=der, Einzelzimmer(neut)=einem.",sSrc:"After {1} meal we go to {2} hotel and ask at {3} reception about {4} single room."},
{type:"mc",q:"'Ich ___ jetzt gut bestellen, aber ich ___ noch besser Deutsch lernen.'",opts:["kann ... muss","muss ... kann","will ... darf","soll ... mag"],ans:"kann ... muss",hint:"He CAN order (ability), but MUST learn more (necessity)."},
{type:"fb",s:"Das ist das {1} Restaurant in der Stadt!",a:["beste"],opts:["beste","besser","gut","lieber"],hint:"The superlative form of gut. After das?",sSrc:"That is the {1} restaurant in the city!"},
{type:"mc",q:"Which preposition means 'with'?",opts:["mit","bei","von","aus"],ans:"mit",hint:"The most common dative preposition. Used constantly."},
{type:"drag_fill",s:"Lukas {1} gern zu Hause, aber heute {2} er lieber im Restaurant {3}.",blanks:{"1":"kocht","2":"möchte","3":"essen"},pool:["kocht","möchte","essen","kann","will","kochen"],hint:"Lukas likes cooking at home, but today he'd rather eat out.",sSrc:"Lukas {1} cooking at home, but today he {2} prefer to eat out {3}."},
{type:"mc",q:"'Ich esse gern Fisch, lieber Fleisch, am liebsten Schweinebraten.' shows:",opts:["gern to lieber to am liebsten (three levels)","drei Modalverben","drei Restaurants","Dativpräpositionen"],ans:"gern to lieber to am liebsten (three levels)",hint:"Three levels of preference: from basic to stronger to strongest."},
{type:"match",pairs:[{trg:"aus",src:"out of/from"},{trg:"bei",src:"at/near/with"},{trg:"nach",src:"after/to"},{trg:"seit",src:"since/for"},{trg:"von",src:"from/of"},{trg:"zu",src:"to"}]},
{type:"tip",title:"Unit 5 Complete: Zusammen!",text:"Verumius came to the Gasthaus hungry and confused.\nHe left with:\n\n1. A best friend (Lukas)\n2. Six modal verbs\n3. Seven dative prepositions\n4. The ability to order food and (almost) pay the bill\n5. A love for Schweinebraten\n\nNext: Verumius explores Berlin. What could POSSIBLY go wrong?"}
]},

]},
// ═══════════════════════════════════════════════════════════════
// UNIT 6: Alles auf Deutsch -- The Hot Water Crisis
// Story: Daily routine, appointments, bureaucracy, Hildi's tea, A1 finale
// CEFR: A1.2 - Time, health, work, hobbies, bureaucracy, war/hatte
// ═══════════════════════════════════════════════════════════════
{n:6,lang:"de",srcLang:"en",track:"v2",title:"Alles auf Deutsch",sub:"Daily life, health, work, hobbies & Hildi's tea",icon:"☕",level:"A1.2",color:"#7B5EE8",lessons:[

// ─── L1: Kaltes Wasser! ───
{id:"deu_r6l1",title:"Kaltes Wasser!",icon:"🚿",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf Deutsch",desc:"Verumius is settling into his apartment. But the hot water is gone. Time to learn daily routine, body parts, and past tense of sein/haben.",goals:["Daily routine vocabulary","Body parts","Past tense: war/hatte"]},
{type:"teach",trg:"die Dusche",src:"the shower",note:"Feminine. Also the verb: duschen (to shower).",example:"A: Die Dusche ist kalt!\nB: Oh nein! Kein heißes Wasser?",exampleSrc:"A: The shower is cold!\nB: Oh no! No hot water?",funFact:"Germans love their showers. Average shower time: 6 minutes. Hildi's Hausordnung has a section on shower times."},
{type:"teach",trg:"duschen",src:"to shower",note:"Regular. Reflexive in formal German (sich duschen).",example:"A: Ich dusche jeden Morgen.\nB: Warm oder kalt?",exampleSrc:"A: I shower every morning.\nB: Warm or cold?",funFact:"In everyday speech, Germans drop the 'sich': 'Ich dusche' instead of 'Ich dusche mich.' Both correct."},
{type:"teach",trg:"der Schlaf",src:"sleep",note:"Masculine. No plural. Verb: schlafen (irregular: schläft).",example:"A: Gute Nacht! Guter Schlaf!\nB: Danke, dir auch!",exampleSrc:"A: Good night! Good sleep!\nB: Thanks, you too!",funFact:"'Schönheitsschlaf' = beauty sleep. Germans take it seriously."},
{type:"teach",trg:"schlafen",src:"to sleep",note:"Irregular: ich schlafe, du schläfst, er schläft.",example:"A: Wie lange schläfst du?\nB: Ich schlafe acht Stunden.",exampleSrc:"A: How long do you sleep?\nB: I sleep eight hours.",funFact:"Stem vowel change: a to ä in du/er forms. One of the first strong verbs you meet."},
{type:"verb_table",title:"schlafen (to sleep)",groups:[{label:"Present tense (stem change: a → ä)",rows:[{pronoun:"ich",form:"schlafe",src:"I sleep"},{pronoun:"du",form:"schläfst",src:"you sleep"},{pronoun:"er/sie/es",form:"schläft",src:"he/she/it sleeps"},{pronoun:"wir",form:"schlafen",src:"we sleep"},{pronoun:"ihr",form:"schlaft",src:"you all sleep"},{pronoun:"sie/Sie",form:"schlafen",src:"they/you (formal) sleep"}]}],note:"Same a → ä pattern as fahren and waschen."},
{type:"teach",trg:"einschlafen",src:"to fall asleep",note:"Separable: ich schlafe ein. Irregular like schlafen.",example:"A: Wann schläfst du ein?\nB: Ich schlafe um elf ein.",exampleSrc:"A: When do you fall asleep?\nB: I fall asleep at eleven.",funFact:"Separable! 'Ich schlafe ein' = I fall asleep. The 'ein' flies to the end."},
{type:"teach",trg:"wecken",src:"to wake (someone)",note:"Regular. 'Der Wecker' = alarm clock.",example:"A: Weck mich um sieben!\nB: Okay, ich wecke dich.",exampleSrc:"A: Wake me at seven!\nB: Okay, I'll wake you.",funFact:"Not to confuse with 'Wecken' (bread roll in southern Germany). Context saves you."},
{type:"teach",trg:"der Hunger",src:"hunger",note:"Masculine. 'Ich habe Hunger' = I am hungry.",example:"A: Hast du Hunger?\nB: Ja, großen Hunger!",exampleSrc:"A: Are you hungry?\nB: Yes, very hungry!",funFact:"'Bärenhunger' = bear's hunger = starving. Germans love animal metaphors."},
{type:"teach",trg:"der Durst",src:"thirst",note:"Masculine. 'Ich habe Durst' = I am thirsty.",example:"A: Ich habe Durst.\nB: Möchtest du Wasser?",exampleSrc:"A: I'm thirsty.\nB: Would you like water?",funFact:"Used with haben, not sein. 'Ich habe Durst,' never 'Ich bin Durst.'"},
{type:"teach",trg:"spazieren gehen",src:"to go for a walk",note:"Two-verb combo. 'Ich gehe spazieren.'",example:"A: Gehst du spazieren?\nB: Ja, im Park.",exampleSrc:"A: Are you going for a walk?\nB: Yes, in the park.",funFact:"Germans walk A LOT. 'Sonntagsspaziergang' = Sunday stroll. A genuine German tradition."},
{type:"teach",trg:"früh",src:"early",note:"Adjective/adverb. Opposite: spät (late).",example:"A: Es ist zu früh!\nB: Der frühe Vogel fängt den Wurm.",exampleSrc:"A: It's too early!\nB: The early bird catches the worm.",funFact:"Same proverb! 'Der frühe Vogel fängt den Wurm.' Germans are early risers."},
{type:"teach",trg:"fertig",src:"finished / ready",note:"Means both! Context decides.",example:"A: Bist du fertig?\nB: Ja, ich bin fertig!",exampleSrc:"A: Are you done/ready?\nB: Yes, I'm done/ready!",funFact:"'Fertig' = finished AND ready. 'Das Essen ist fertig' = dinner is ready. 'Ich bin fertig' = I'm done."},
{type:"teach",trg:"der Kopf / die Hand / der Arm / der Bauch",src:"head / hand / arm / belly",note:"Body parts: der Kopf (m), die Hand (f), der Arm (m), der Bauch (m).",example:"A: Mein Kopf tut weh.\nB: Und meine Hand auch!",exampleSrc:"A: My head hurts.\nB: And my hand too!",funFact:"Hand is one of the few German body parts that is feminine. Most are masculine."},
{type:"teach",trg:"der Rücken / das Bein / der Fuß / der Finger",src:"back / leg / foot / finger",note:"More body parts. das Bein is neuter!",example:"A: Mein Rücken tut weh.\nB: Und mein Bein auch!",exampleSrc:"A: My back hurts.\nB: And my leg too!",funFact:"Fuß is cognate with English 'foot.' The ß in Fuß shows a long vowel. Plural: Füße."},
{type:"tip",title:"Past Tense: war / hatte",text:"In spoken German, ONLY sein and haben use simple past:\n\nwar (was): ich war, du warst, er war, wir waren\nhatte (had): ich hatte, du hattest, er hatte, wir hatten\n\n'Das Wasser war kalt.'\n'Ich hatte Hunger.'\n\nEverything else uses Perfekt (coming in A2)."},
{type:"mc",q:"'Das Wasser ___ kalt.'",opts:["war","hatte","ist","hat"],ans:"war",hint:"Simple past of sein. The water WAS cold."},
{type:"fb",s:"Ich {1} gestern großen Hunger.",a:["hatte"],opts:["hatte","war","habe","bin"],hint:"Past tense of haben. I HAD hunger.",sSrc:"I {1} great hunger yesterday."},
{type:"mc",q:"'Ich ___ jeden Morgen.'",opts:["frühstücke","frühstücken","schlafe","dusche"],ans:"frühstücke",hint:"What do you do with food in the morning? First person singular."},
{type:"match",pairs:[{trg:"der Kopf",src:"head"},{trg:"die Hand",src:"hand"},{trg:"der Fuß",src:"foot"},{trg:"der Bauch",src:"belly"},{trg:"das Bein",src:"leg"}]}
]},

// ─── L2: Mein Tag ───
{id:"deu_r6l2",title:"Mein Tag",icon:"⏰",xp:15,board:true,steps:[
{type:"intro",title:"Mein Tag",desc:"Time words, clock expressions, and daily scheduling. The backbone of German life: everything runs on time.",goals:["Time nouns and adverbs","Clock expressions: um + Uhr","Yesterday/today/tomorrow"]},
{type:"teach",trg:"der Tag",src:"the day",note:"Masculine. Also means 'hello' in southern Germany! 'Tag!'",example:"A: Was für ein schöner Tag!\nB: Ja, die Sonne scheint!",exampleSrc:"A: What a beautiful day!\nB: Yes, the sun is shining!",funFact:"'Tag!' is a casual greeting in southern Germany. Just the word 'day' as a hello."},
{type:"teach",trg:"der Morgen",src:"the morning / tomorrow",note:"Masculine. Morgen = morning AND tomorrow!",example:"A: Guten Morgen!\nB: Morgen habe ich frei.",exampleSrc:"A: Good morning!\nB: Tomorrow I'm off.",funFact:"'Morgen Morgen' = tomorrow morning. Germans find this funny too."},
{type:"teach",trg:"die Nacht",src:"the night",note:"Feminine. 'Gute Nacht' = good night.",example:"A: Gute Nacht!\nB: Schlaf gut!",exampleSrc:"A: Good night!\nB: Sleep well!",funFact:"Nacht is always feminine, like 'la nuit' in French. 'Heute Nacht' = tonight."},
{type:"teach",trg:"die Woche",src:"the week",note:"Feminine. Plural: die Wochen.",example:"A: Wie war deine Woche?\nB: Gut, aber stressig.",exampleSrc:"A: How was your week?\nB: Good, but stressful.",funFact:"From Old German 'wehsel' (change/turn). A week = one turn of days."},
{type:"teach",trg:"das Wochenende",src:"the weekend",note:"Neuter. Compound: Woche + Ende.",example:"A: Was machst du am Wochenende?\nB: Ich gehe spazieren.",exampleSrc:"A: What are you doing on the weekend?\nB: I'm going for a walk.",funFact:"die Woche + das Ende = das Wochenende. Gender of the LAST word wins."},
{type:"teach",trg:"die Uhr",src:"the clock / o'clock",note:"Feminine. Double meaning: clock AND o'clock.",example:"A: Wie viel Uhr ist es?\nB: Es ist drei Uhr.",exampleSrc:"A: What time is it?\nB: It is three o'clock.",funFact:"'Uhr' means both 'clock' and 'o'clock.' 'Die Uhr ist kaputt' AND 'Es ist drei Uhr.'"},
{type:"teach",trg:"die Minute / die Sekunde",src:"minute / second",note:"Both feminine. From Latin. Nearly identical to English.",example:"A: Noch eine Minute!\nB: Sekunde mal!",exampleSrc:"A: One more minute!\nB: Just a second!",funFact:"'Sekunde mal!' = Just a second! Very common in everyday speech."},
{type:"teach",trg:"das Datum / der Kalender",src:"the date / the calendar",note:"Datum is neuter. Kalender is masculine.",example:"A: Welches Datum ist heute?\nB: Schau im Kalender.",exampleSrc:"A: What date is today?\nB: Check the calendar.",funFact:"Plural of Datum is 'Daten,' which also means 'data.' Context is everything."},
{type:"teach",trg:"gestern",src:"yesterday",note:"Adverb. 'Gestern war alles besser.'",example:"A: Was hast du gestern gemacht?\nB: Gestern war ich müde.",exampleSrc:"A: What did you do yesterday?\nB: Yesterday I was tired.",funFact:"'Gestern war alles besser' = yesterday everything was better. Classic German nostalgia."},
{type:"teach",trg:"spät",src:"late",note:"Adjective/adverb. Opposite of früh. Comparative: später.",example:"A: Es ist spät!\nB: Besser spät als nie.",exampleSrc:"A: It's late!\nB: Better late than never.",funFact:"'Besser spät als nie' = better late than never. Identical proverb!"},
{type:"teach",trg:"gerade",src:"right now / straight",note:"Dual meaning: currently AND straight.",example:"A: Was machst du gerade?\nB: Ich lerne gerade Deutsch.",exampleSrc:"A: What are you doing right now?\nB: I'm learning German right now.",funFact:"'Gerade' also means 'straight.' 'Geradeaus' = straight ahead (from Unit 2!)."},
{type:"teach",trg:"danach / vorher / nachher",src:"after that / before / afterward",note:"Time sequence words. Essential for narrating.",example:"A: Zuerst dusche ich, danach frühstücke ich.\nB: Und nachher?",exampleSrc:"A: First I shower, then I have breakfast.\nB: And after that?",funFact:"Vorher = before. Nachher = afterward. Danach = after that. Three ways to sequence events."},
{type:"teach",trg:"pünktlich",src:"punctual / on time",note:"THE German virtue. Being late is a social crime.",example:"A: Bist du immer pünktlich?\nB: Natürlich! Ich bin deutsch.",exampleSrc:"A: Are you always on time?\nB: Of course! I'm German.",funFact:"Punctuality is sacred in Germany. 5 minutes early = on time. On time = late."},
{type:"tip",title:"Time Expressions",text:"um + clock time: um drei Uhr (at 3 o'clock)\nam + day: am Montag (on Monday)\ngestern / heute / morgen: standalone\ngerade = right now\nvorher / nachher / danach = before / after / then\n\n'Es ist drei Uhr.' (It is 3 o'clock.)\n'Ich komme um drei.' (I'm coming at 3.)"},
{type:"teach",trg:"der Nachmittag / der Vormittag",src:"afternoon / morning (before noon)",note:"Both masculine. Nach+Mittag / Vor+Mittag.",example:"A: Was machst du am Nachmittag?\nB: Ich lerne Deutsch.",exampleSrc:"A: What are you doing in the afternoon?\nB: I'm learning German.",funFact:"Vormittag = before noon. Nachmittag = after noon. Transparent compounds."},
{type:"teach",trg:"der Schluss",src:"the end / closing time",note:"Masculine. 'Ladenschluss' = store closing time.",example:"A: Wann ist Schluss?\nB: Um siebzehn Uhr.",exampleSrc:"A: When is closing time?\nB: At 5 PM.",funFact:"'Schluss!' as an exclamation means 'That's it! Enough!' Very final."},
{type:"mc",q:"Es ist 15:00. Es ist ___.",opts:["drei Uhr","fünfzehn","fünf Uhr","dreizehn Uhr"],ans:"drei Uhr",hint:"15:00 in 12-hour = 3 o'clock."},
{type:"fb",s:"Gestern {1} ich sehr müde.",a:["war"],opts:["war","bin","hatte","habe"],hint:"Past tense of sein, first person. I WAS tired.",sSrc:"Yesterday I {1} very tired."},
{type:"mc",q:"'Ich dusche ___ um sieben Uhr.'",opts:["morgens","gestern","danach","spät"],ans:"morgens",hint:"What time word means 'in the morning' as a habit?"},
{type:"drag_fill",s:"Ich frühstücke {1} sieben {2}.",blanks:{"1":"um","2":"Uhr"},pool:["um","am","Uhr","Morgen","Tag"],hint:"Clock time format: preposition + number + the word for o'clock.",sSrc:"I have breakfast {1} seven {2}."},
{type:"mc",q:"'___ hatte ich keinen Hunger.'",opts:["Gestern","Morgen","Endlich","Gerade"],ans:"Gestern",hint:"Which word means 'yesterday'?"}
]},

// ─── L3: Montag bis Sonntag ───
{id:"deu_r6l3",title:"Montag bis Sonntag",icon:"📅",xp:15,board:true,steps:[
{type:"intro",title:"Montag bis Sonntag",desc:"Days of the week, months, and ordinal numbers. All named after gods, planets, or Latin numbers.",goals:["7 days of the week","First 6 months","Ordinals: erste, zweite, dritte"]},
{type:"teach",trg:"der Montag",src:"Monday",note:"Masculine. All days are masculine! Mond (moon) + Tag.",example:"A: Am Montag gehe ich arbeiten.\nB: Ich auch!",exampleSrc:"A: On Monday I go to work.\nB: Me too!",funFact:"Moon-day! Same as English Monday (Moon's day). Same Germanic origin."},
{type:"teach",trg:"der Dienstag",src:"Tuesday",note:"Named after Tyr/Ziu (Norse god).",example:"A: Am Dienstag habe ich Deutsch.\nB: Viel Spaß!",exampleSrc:"A: On Tuesday I have German.\nB: Have fun!",funFact:"English Tuesday = Tyr's day. German Dienstag = Ziu's day. Same thunder god."},
{type:"teach",trg:"der Mittwoch",src:"Wednesday",note:"Literally 'mid-week.' The ONLY day not named after a god.",example:"A: Mittwoch ist die Mitte der Woche.\nB: Stimmt!",exampleSrc:"A: Wednesday is the middle of the week.\nB: That's right!",funFact:"Mitte + Woche = mid-week. English Wednesday is Woden's day. German went practical."},
{type:"teach",trg:"der Donnerstag",src:"Thursday",note:"Thunder-day! Donner (thunder) + Tag.",example:"A: Am Donnerstag gehe ich einkaufen.\nB: Ich komme mit!",exampleSrc:"A: On Thursday I go shopping.\nB: I'll come along!",funFact:"Thursday = Thor's day. Donnerstag = Thunder-day. Same thunder god, different names."},
{type:"teach",trg:"der Freitag",src:"Friday",note:"Named after Freya (goddess of love).",example:"A: Freitag ist mein Lieblingstag!\nB: Meiner auch!",exampleSrc:"A: Friday is my favorite day!\nB: Mine too!",funFact:"Friday = Freya's day. Freitag = Freya's day. Same love goddess."},
{type:"teach",trg:"der Samstag / der Sonntag",src:"Saturday / Sunday",note:"Samstag from Hebrew 'Shabbat.' Sonntag = Sun-day.",example:"A: Am Samstag grillen wir.\nB: Und am Sonntag? Ruhetag!",exampleSrc:"A: On Saturday we grill.\nB: And on Sunday? Rest day!",funFact:"Shops are CLOSED on Sundays in Germany. The 'Sonntagsruhe' (Sunday rest) is law."},
{type:"tip",title:"am + Day",text:"All days are masculine, all use 'am' (an + dem):\n\nam Montag = on Monday\nam Dienstag = on Tuesday\n\nNever 'auf Montag' or 'in Montag.'\n'Am' is the ONLY correct preposition for days."},
{type:"teach",trg:"der Januar / der Februar / der März",src:"January / February / March",note:"All months are masculine (der). Same as English roots.",example:"A: Im Januar ist es kalt.\nB: Und im März wird es wärmer.",exampleSrc:"A: In January it's cold.\nB: And in March it gets warmer.",funFact:"Januar (Janus, two-faced god), Februar (purification month), März (Mars, god of war)."},
{type:"teach",trg:"der April / der Mai / der Juni",src:"April / May / June",note:"All masculine. im + month: 'im April.'",example:"A: Im Mai blühen die Blumen.\nB: Und im Juni scheint die Sonne.",exampleSrc:"A: In May the flowers bloom.\nB: And in June the sun shines.",funFact:"April (opening/spring), Mai (Maia, goddess of growth), Juni (Juno, queen of gods)."},
{type:"teach",trg:"erste / zweite / dritte",src:"first / second / third",note:"Ordinal numbers. Irregular for 1st-3rd, regular from 4th.",example:"A: Der erste Januar ist Neujahr.\nB: Und der dritte Oktober?",exampleSrc:"A: The first of January is New Year.\nB: And the third of October?",funFact:"1st/2nd/3rd are irregular (like English). From 4th onward: add -te (vierte, fünfte, sechste)."},
{type:"teach",trg:"seit",src:"since / for (time duration)",note:"Dative preposition! 'Seit drei Wochen' = for three weeks.",example:"A: Seit wann bist du hier?\nB: Seit drei Wochen.",exampleSrc:"A: Since when have you been here?\nB: For three weeks.",funFact:"Always dative. German uses present tense with seit: 'Ich wohne seit drei Wochen hier' (I have been living here for three weeks)."},
{type:"teach",trg:"wichtig / eilig",src:"important / urgent",note:"Zwei nützliche Adjektive. Essential for office/bureaucracy.",example:"A: Es ist wichtig!\nB: Und eilig! Wir müssen jetzt gehen.",exampleSrc:"A: It's important!\nB: And urgent! We have to go now.",funFact:"'Wichtig' from 'Gewicht' (weight). Important = weighty. 'Ich habe es eilig' = I'm in a hurry."},
{type:"mc",q:"Mittwoch bedeutet:",opts:["Mitte der Woche","Tag des Mondes","Tag des Donners","Tag der Sonne"],ans:"Mitte der Woche",hint:"What does 'Mitt' + 'Woch' combine to mean?"},
{type:"fb",s:"{1} Montag habe ich einen Termin.",a:["Am"],opts:["Am","Im","Um","Seit"],hint:"Days use which preposition contraction?",sSrc:"{1} Monday I have an appointment."},
{type:"mc",q:"Der ___ Januar ist Neujahr.",opts:["erste","zweite","dritte","vierte"],ans:"erste",hint:"New Year's Day is the 1st."},
{type:"match",pairs:[{trg:"Montag",src:"Monday"},{trg:"Mittwoch",src:"Wednesday"},{trg:"Freitag",src:"Friday"},{trg:"Sonntag",src:"Sunday"},{trg:"Donnerstag",src:"Thursday"}]},
{type:"fb",s:"Ich wohne {1} drei Wochen in Berlin.",a:["seit"],opts:["seit","vor","nach","um"],hint:"Which preposition means 'for' with a continuing duration?",sSrc:"I have been living in Berlin {1} three weeks."},
{type:"mc",q:"Shops are closed on ___ in Germany.",opts:["Sonntag","Samstag","Freitag","Mittwoch"],ans:"Sonntag",hint:"The Sunday rest is law."}
]},

// ─── L4: Juli bis Dezember ───
{id:"deu_r6l4",title:"Juli bis Dezember",icon:"🌦️",xp:15,board:true,steps:[
{type:"intro",title:"Juli bis Dezember",desc:"Remaining months, all four seasons, weather vocabulary, and more ordinals. When things happen and what it is like outside.",goals:["6 remaining months","4 seasons with im + season","Weather vocabulary"]},
{type:"teach",trg:"der Juli / der August",src:"July / August",note:"Both masculine. Named after Roman emperors.",example:"A: Im Juli fahren wir nach Spanien.\nB: Und im August?",exampleSrc:"A: In July we're going to Spain.\nB: And in August?",funFact:"Juli = Julius Caesar. August = Emperor Augustus. August is Germany's main vacation month."},
{type:"teach",trg:"der September / der Oktober / der November / der Dezember",src:"Sept / Oct / Nov / Dec",note:"All masculine. Nearly identical to English.",example:"A: Im Oktober ist Oktoberfest!\nB: Und im Dezember Weihnachten.",exampleSrc:"A: In October is Oktoberfest!\nB: And in December Christmas.",funFact:"Sept=7, Okt=8, Nov=9, Dez=10 in the old Roman calendar (year started in March)."},
{type:"teach",trg:"der Frühling",src:"spring",note:"Masculine. Literally 'early-ling.' Früh + -ling.",example:"A: Im Frühling blühen die Blumen.\nB: Ja, alles wird grün!",exampleSrc:"A: In spring the flowers bloom.\nB: Yes, everything turns green!",funFact:"Früh (early) + -ling (suffix) = the early season. Spring arrives!"},
{type:"teach",trg:"der Sommer",src:"summer",note:"Masculine. Cognate with English 'summer.'",example:"A: Im Sommer grillen wir.\nB: Und im Winter?",exampleSrc:"A: In summer we grill.\nB: And in winter?",funFact:"Same Proto-Germanic root. Identical meaning for 2000+ years."},
{type:"teach",trg:"der Herbst",src:"autumn / fall",note:"Masculine. Cognate with English 'harvest.'",example:"A: Im Herbst werden die Blätter bunt.\nB: Ja, wunderschön!",exampleSrc:"A: In autumn the leaves turn colorful.\nB: Yes, beautiful!",funFact:"English shifted to 'autumn' (from French). German kept Herbst. Same original meaning: harvest time."},
{type:"teach",trg:"der Winter",src:"winter",note:"Masculine. Identical to English.",example:"A: Im Winter ist es kalt.\nB: Ja, minus zehn Grad!",exampleSrc:"A: In winter it's cold.\nB: Yes, minus ten degrees!",funFact:"German winters are serious: -10 degrees C is normal in Bavaria."},
{type:"teach",trg:"das Wetter",src:"the weather",note:"Neuter. 'Wie ist das Wetter?' = How's the weather?",example:"A: Wie ist das Wetter heute?\nB: Es regnet.",exampleSrc:"A: How is the weather today?\nB: It's raining.",funFact:"Weather is THE small-talk topic in Germany. 'Über das Wetter kann man immer reden.'"},
{type:"teach",trg:"der Regen / regnen",src:"the rain / to rain",note:"Regen is masculine. Regnen uses 'es': Es regnet.",example:"A: Es regnet schon wieder!\nB: Hast du einen Regenschirm?",exampleSrc:"A: It's raining again!\nB: Do you have an umbrella?",funFact:"Impersonal verb: 'Es regnet.' Only 'es' can rain. You can't say 'Ich regne.'"},
{type:"teach",trg:"der Schnee / die Temperatur",src:"snow / temperature",note:"Schnee is masculine. Temperatur is feminine.",example:"A: Es schneit! Schnee!\nB: Die Temperatur ist minus fünf.",exampleSrc:"A: It's snowing! Snow!\nB: The temperature is minus five.",funFact:"'Schnee' is cognate with English 'snow.' Germany uses Celsius: 20°C = comfortable."},
{type:"teach",trg:"leider",src:"unfortunately",note:"Adverb. Softens bad news. Germans use it A LOT.",example:"A: Kommst du morgen?\nB: Leider nicht. Ich muss arbeiten.",exampleSrc:"A: Are you coming tomorrow?\nB: Unfortunately not. I have to work.",funFact:"From 'Leid' (suffering). Leider politely softens any disappointment."},
{type:"teach",trg:"scheinen",src:"to shine / to seem",note:"Dual meaning! 'Die Sonne scheint' AND 'Es scheint gut.'",example:"A: Die Sonne scheint heute.\nB: Endlich!",exampleSrc:"A: The sun is shining today.\nB: Finally!",funFact:"Two completely different meanings: to shine (sun) AND to seem/appear."},
{type:"teach",trg:"vierte / fünfte / sechste",src:"fourth / fifth / sixth",note:"Regular from 4th: add -te. Vierte, fünfte, sechste.",example:"A: Der vierte Juli.\nB: Amerikanischer Nationalfeiertag!",exampleSrc:"A: The fourth of July.\nB: American Independence Day!",funFact:"From 4th onward, just add -te to the number. Easy pattern!"},
{type:"tip",title:"im + Month / Season",text:"'Im Januar' (in January)\n'Im Sommer' (in summer)\n\nim = in + dem (dative contraction)\nAll months and seasons are masculine (der).\n\n'Im Winter war es kalt.'\n'Im Mai blühen die Blumen.'"},
{type:"mc",q:"'Wir fahren ___ Sommer nach Spanien.'",opts:["im","am","um","seit"],ans:"im",hint:"Seasons use im (in + dem)."},
{type:"fb",s:"Es {1} seit drei Tagen.",a:["regnet"],opts:["regnet","schneit","Regen","Wetter"],hint:"The verb for rain, with 'es' as subject.",sSrc:"It {1} for three days."},
{type:"mc",q:"Der vierte ___ ist der amerikanische Nationalfeiertag.",opts:["Juli","Juni","August","Mai"],ans:"Juli",hint:"Independence Day: July 4th."},
{type:"drag_fill",s:"Gestern {1} es kalt und ich {2} keinen Regenschirm.",blanks:{"1":"war","2":"hatte"},pool:["war","hatte","ist","habe","bin"],hint:"Past tense of the two most important auxiliary verbs. Think about existence vs. possession.",sSrc:"Yesterday it {1} cold and I {2} no umbrella."},
{type:"match",pairs:[{trg:"der Frühling",src:"spring"},{trg:"der Sommer",src:"summer"},{trg:"der Herbst",src:"autumn"},{trg:"der Winter",src:"winter"},{trg:"das Wetter",src:"weather"}]},
{type:"mc",q:"'Leider' means:",opts:["unfortunately","luckily","always","never"],ans:"unfortunately",hint:"From 'Leid' (suffering). Softens bad news."}
]},

// ─── L5: Der Anruf ───
{id:"deu_r6l5",title:"Der Anruf",icon:"📞",xp:15,board:true,steps:[
{type:"intro",title:"Der Anruf",desc:"Verumius calls the Hausverwaltung about the hot water. Automated menus, hold music, and body parts for the doctor visit.",goals:["Phone and communication vocabulary","More body parts","Imperative in phone context"]},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-verumius-phone",trg:"Kein warmes Wasser seit zwei Tagen. Verumius nimmt sein Handy und ruft die Hausverwaltung an. 'Willkommen bei der Hausverwaltung Berlin-Mitte. Für Deutsch, drücken Sie die Eins.'",src:"No hot water for two days. Verumius picks up his phone and calls the property management. 'Welcome to the Berlin-Mitte property management. For German, press one.'"},
{type:"teach",trg:"der Anruf / anrufen",src:"the call / to call",note:"Anruf is masculine. Anrufen is separable: ich rufe an.",example:"A: Ich rufe die Hausverwaltung an.\nB: Gute Idee!",exampleSrc:"A: I'm calling the property management.\nB: Good idea!",funFact:"Separable: 'Ich rufe an.' The 'an' goes to the end. 'Der Anruf' = the call (noun form)."},
{type:"teach",trg:"das Handy",src:"the mobile phone",note:"Neuter. FALSE FRIEND: not related to English 'handy'!",example:"A: Wo ist mein Handy?\nB: Auf dem Tisch.",exampleSrc:"A: Where is my phone?\nB: On the table.",funFact:"Germans use the English word 'handy' for mobile phones, but English speakers never call phones 'handys.' A Denglisch classic."},
{type:"teach",trg:"das Telefon / telefonieren",src:"telephone / to call",note:"Telefon is neuter. Telefonieren is NOT separable.",example:"A: Telefonierst du gerade?\nB: Ja, einen Moment bitte.",exampleSrc:"A: Are you on the phone?\nB: Yes, one moment please.",funFact:"'Telefonieren' is inseparable. 'Anrufen' is separable. Both mean 'to call.' Telefonieren is more formal."},
{type:"teach",trg:"die Nachricht / der Brief",src:"message / letter",note:"Nachricht is feminine. Brief is masculine.",example:"A: Ich habe eine Nachricht bekommen.\nB: Einen Brief oder eine E-Mail?",exampleSrc:"A: I received a message.\nB: A letter or an email?",funFact:"'Nachricht' = message (any kind). 'Brief' = physical letter. 'Die Nachrichten' = the news (always plural)."},
{type:"teach",trg:"die E-Mail / klingeln",src:"the email / to ring",note:"E-Mail is feminine. Klingeln: das Telefon klingelt.",example:"A: Das Telefon klingelt!\nB: Ich gehe ran.",exampleSrc:"A: The phone is ringing!\nB: I'll answer.",funFact:"'Klingeln' also means doorbell ringing. 'Es klingelt!' = the bell is ringing (phone or door)."},
{type:"teach",trg:"das Auge / das Ohr / die Nase",src:"eye / ear / nose",note:"Auge and Ohr are neuter. Nase is feminine.",example:"A: Ich sehe mit den Augen.\nB: Und ich höre mit den Ohren.",exampleSrc:"A: I see with my eyes.\nB: And I hear with my ears.",funFact:"'Auge' plural is 'Augen.' 'Ohr' plural is 'Ohren.' Both add -en. Easy pattern!"},
{type:"teach",trg:"der Mund / der Zahn / das Haar",src:"mouth / tooth / hair",note:"Mund and Zahn are masculine. Haar is neuter.",example:"A: Mach den Mund auf!\nB: Der Zahn tut weh.",exampleSrc:"A: Open your mouth!\nB: The tooth hurts.",funFact:"Plural of Zahn: Zähne (umlaut!). 'Zahnarzt' = tooth-doctor = dentist."},
{type:"teach",trg:"das Gesicht / der Zeh",src:"face / toe",note:"Gesicht is neuter. Zeh is masculine.",example:"A: Mein Gesicht ist rot.\nB: Und mein Zeh tut weh.",exampleSrc:"A: My face is red.\nB: And my toe hurts.",funFact:"Gesicht literally: 'the seen thing.' From 'sehen' (to see). Your face is what people see."},
{type:"mc",q:"'Das Telefon klingelt!' means:",opts:["The phone is ringing!","The phone is broken!","The phone is new!","The phone is expensive!"],ans:"The phone is ringing!",hint:"Klingeln = to ring. Think of the sound: kling-kling!"},
{type:"fb",s:"Ich {1} die Hausverwaltung {1}.",a:["rufe"],opts:["rufe","anrufe","telefoniere","klingele"],hint:"Separable verb: prefix is at the end. Fill in the conjugated stem for ich.",sSrc:"I {1} the property management {1}."},
{type:"mc",q:"'Handy' in German means:",opts:["mobile phone","useful","handbag","hand cream"],ans:"mobile phone",hint:"A German false friend. Nothing to do with the English word 'handy.'"},
{type:"match",pairs:[{trg:"das Auge",src:"eye"},{trg:"das Ohr",src:"ear"},{trg:"die Nase",src:"nose"},{trg:"der Mund",src:"mouth"},{trg:"der Zahn",src:"tooth"}]},
{type:"fb",s:"Ich habe eine {1} von der Hausverwaltung bekommen.",a:["Nachricht"],opts:["Nachricht","Brief","Anruf","Handy"],hint:"A message. Could be email, text, or voicemail.",sSrc:"I received a {1} from the property management."},
{type:"mc",q:"'Drücken Sie die Eins!' is an example of:",opts:["imperative","past tense","modal verb","reflexive verb"],ans:"imperative",hint:"A formal command form. What grammar structure is this?"},
{type:"story",speaker:"narrator",mood:"frustrated",art:"de-hold-music",trg:"Wartemusik. Fünf Minuten. Zehn Minuten. Eine Stimme: 'Ihr Anruf ist uns wichtig. Bitte warten Sie.' Verumius wartet. Und wartet. Kaltes Wasser, warme Geduld.",src:"Hold music. Five minutes. Ten minutes. A voice: 'Your call is important to us. Please wait.' Verumius waits. And waits. Cold water, warm patience."},
{type:"drag_fill",s:"Mein {1} tut weh und meine {2} sind rot.",blanks:{"1":"Kopf","2":"Augen"},pool:["Kopf","Augen","Hand","Fuß","Ohr"],hint:"Head hurts and eyes are red. Body parts from L1 + this lesson.",sSrc:"My {1} hurts and my {2} are red."},
{type:"mc",q:"Plural of 'der Zahn':",opts:["die Zähne","die Zahne","die Zähnen","die Zahns"],ans:"die Zähne",hint:"Umlaut + -e pattern. Like Stuhl to Stühle."}
]},

// ─── L6: Beim Arzt ───
{id:"deu_r6l6",title:"Beim Arzt",icon:"🏥",xp:15,board:true,steps:[
{type:"intro",title:"Beim Arzt",desc:"Verumius visits the doctor. Health vocabulary, describing symptoms, and modal verbs in medical context.",goals:["Health and illness vocabulary","Describe symptoms","Modal verbs: müssen/sollen at the doctor"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-arzt-wartezimmer",trg:"Arztpraxis. Wartezimmer. Zwanzig Menschen, eine Zeitschrift von 2019, und ein Fernseher ohne Ton. Verumius hat seine Versicherungskarte. Er wartet.",src:"Doctor's office. Waiting room. Twenty people, a magazine from 2019, and a TV with no sound. Verumius has his insurance card. He waits."},
{type:"teach",trg:"der Arzt / die Ärztin",src:"the doctor (m/f)",note:"Masculine/feminine. Plural: die Ärzte.",example:"A: Ich muss zum Arzt.\nB: Was ist los?",exampleSrc:"A: I have to go to the doctor.\nB: What's wrong?",funFact:"'Zum Arzt gehen' is the standard phrase. 'Hausarzt' = family doctor. You need one in Germany."},
{type:"teach",trg:"krank / gesund",src:"sick / healthy",note:"Opposites. 'Ich bin krank' = I am sick.",example:"A: Bist du krank?\nB: Nein, ich bin gesund.",exampleSrc:"A: Are you sick?\nB: No, I'm healthy.",funFact:"'Krankenwagen' = sick-wagon = ambulance. 'Krankenhaus' = sick-house = hospital. German compound logic."},
{type:"teach",trg:"die Krankheit / die Gesundheit",src:"illness / health",note:"Both feminine. Gesundheit! = the sneeze response.",example:"A: Gesundheit!\nB: Danke!",exampleSrc:"A: Bless you!\nB: Thanks!",funFact:"Germans say 'Gesundheit!' when someone sneezes. It literally means 'Health!' English borrowed it directly."},
{type:"teach",trg:"das Medikament / die Tablette",src:"medicine / pill",note:"Medikament is neuter. Tablette is feminine.",example:"A: Nehmen Sie dieses Medikament.\nB: Wie oft?",exampleSrc:"A: Take this medicine.\nB: How often?",funFact:"'Rezept' in German means BOTH 'recipe' (cooking) AND 'prescription' (medical). Context!"},
{type:"teach",trg:"der Schmerz / die Erkältung",src:"pain / cold (illness)",note:"Schmerz is masculine. Erkältung is feminine.",example:"A: Ich habe Schmerzen.\nB: Wo genau?",exampleSrc:"A: I'm in pain.\nB: Where exactly?",funFact:"Plural 'Schmerzen' is more common. 'Kopfschmerzen' = headache. 'Bauchschmerzen' = stomachache."},
{type:"teach",trg:"das Fieber / der Husten",src:"fever / cough",note:"Fieber is neuter. Husten is masculine.",example:"A: Ich habe Fieber und Husten.\nB: Gehen Sie zum Arzt!",exampleSrc:"A: I have a fever and cough.\nB: Go to the doctor!",funFact:"'Fieber messen' = to take temperature. Germans use ear thermometers mostly."},
{type:"teach",trg:"weh tun",src:"to hurt",note:"Separable-ish: 'Mein Kopf tut weh.' The weh goes to the end.",example:"A: Was tut weh?\nB: Mein Rücken tut weh.",exampleSrc:"A: What hurts?\nB: My back hurts.",funFact:"Body part + tut weh. 'Mein Arm tut weh. Meine Augen tun weh.' Plural uses 'tun.'"},
{type:"teach",trg:"die Apotheke / das Rezept",src:"pharmacy / prescription (or recipe!)",note:"Apotheke is feminine. Rezept is neuter.",example:"A: Hier ist das Rezept.\nB: Danke, ich gehe zur Apotheke.",exampleSrc:"A: Here is the prescription.\nB: Thanks, I'll go to the pharmacy.",funFact:"German pharmacies (Apotheke) sell prescription AND non-prescription medicine. No medicine at supermarkets!"},
{type:"mc",q:"'Mein Kopf tut weh' means:",opts:["My head hurts","My head is big","My head is cold","My head is turning"],ans:"My head hurts",hint:"'Weh tun' = to hurt. Which body part is mentioned?"},
{type:"fb",s:"Ich habe {1} und Husten.",a:["Fieber"],opts:["Fieber","Hunger","Durst","Schlaf"],hint:"Fever. A medical symptom, not a daily need.",sSrc:"I have a {1} and a cough."},
{type:"mc",q:"'Gesundheit!' is said when someone:",opts:["sneezes","coughs","laughs","sleeps"],ans:"sneezes",hint:"The universal German sneeze response."},
{type:"drag_fill",s:"Sie {1} dieses Medikament drei Mal am Tag {2}.",blanks:{"1":"müssen","2":"nehmen"},pool:["müssen","nehmen","können","trinken","sollen","essen"],hint:"You MUST take this medicine. Modal + infinitive at end.",sSrc:"You {1} take this medicine three times a day {2}."},
{type:"fb",s:"Ich gehe zur {1}. Ich brauche Medikamente.",a:["Apotheke"],opts:["Apotheke","Kasse","Rezeption","Küche"],hint:"The place that sells medicine.",sSrc:"I am going to the {1}. I need medicine."},
{type:"mc",q:"'Krankenhaus' literally means:",opts:["sick-house","care-house","doctor-house","medicine-house"],ans:"sick-house",hint:"Krank (sick) + Haus (house). German compound logic."},
{type:"match",pairs:[{trg:"der Arzt",src:"doctor"},{trg:"krank",src:"sick"},{trg:"der Schmerz",src:"pain"},{trg:"das Fieber",src:"fever"},{trg:"die Apotheke",src:"pharmacy"}]},
{type:"fb",s:"Der Arzt sagt: 'Sie {1} mehr schlafen.'",a:["sollen"],opts:["sollen","müssen","können","dürfen"],hint:"The doctor gives advice. You SHOULD sleep more.",sSrc:"The doctor says: 'You {1} sleep more.'"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-apotheke",trg:"Verumius verlässt die Praxis mit einem Rezept. Zur Apotheke. Die Apothekerin lächelt: 'Drei Mal am Tag, nach dem Essen.' Er nickt. In Deutschland funktioniert alles. Auch krank sein.",src:"Verumius leaves the practice with a prescription. To the pharmacy. The pharmacist smiles: 'Three times a day, after eating.' He nods. In Germany, everything works. Even being sick."},
{type:"mc",q:"'Rezept' in German means BOTH:",opts:["prescription AND recipe","poison AND medicine","doctor AND nurse","pharmacy AND hospital"],ans:"prescription AND recipe",hint:"Same word, two completely different contexts!"}
]},

// ─── L7: Am Bürgeramt ───
{id:"deu_r6l7",title:"Am Bürgeramt",icon:"🏛️",xp:15,board:true,steps:[
{type:"intro",title:"Am Bürgeramt",desc:"German bureaucracy. Verumius must register at the Bürgeramt. Forms, queue numbers, and the word 'Formular.'",goals:["Office and bureaucracy vocabulary","Fill in forms","Registration process"]},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-buergeramt",trg:"Bürgeramt. Nummer 347. Bildschirm zeigt: 289. Verumius hat alle Dokumente: Reisepass, Mietvertrag, Anmeldeformular. Er wartet. Und wartet.",src:"Registration office. Number 347. Screen shows: 289. Verumius has all documents: passport, rental contract, registration form. He waits. And waits."},
{type:"teach",trg:"das Formular / das Dokument",src:"form / document",note:"Both neuter. Essential for German bureaucracy.",example:"A: Bitte füllen Sie das Formular aus.\nB: Welches Dokument brauchen Sie?",exampleSrc:"A: Please fill out the form.\nB: Which document do you need?",funFact:"'Formular ausfüllen' = to fill out a form. Germans love forms. For everything. Every. Single. Thing."},
{type:"teach",trg:"der Termin / der Ausweis",src:"appointment / ID card",note:"Both masculine. Without a Termin, nothing happens.",example:"A: Haben Sie einen Termin?\nB: Ja, um 14 Uhr. Hier ist mein Ausweis.",exampleSrc:"A: Do you have an appointment?\nB: Yes, at 2 PM. Here is my ID.",funFact:"Many German offices require a Termin booked weeks in advance. Walk-ins? Rarely accepted."},
{type:"teach",trg:"die Anmeldung / die Unterschrift",src:"registration / signature",note:"Both feminine. You must anmelden (register) when you move.",example:"A: Die Anmeldung ist fertig.\nB: Bitte Ihre Unterschrift hier.",exampleSrc:"A: The registration is done.\nB: Your signature here, please.",funFact:"'Anmeldung' is MANDATORY. You must register your address within 14 days of moving. Fines apply!"},
{type:"teach",trg:"der Vertrag / die Gebühr",src:"contract / fee",note:"Vertrag is masculine. Gebühr is feminine.",example:"A: Der Vertrag ist unterschrieben.\nB: Und die Gebühr?",exampleSrc:"A: The contract is signed.\nB: And the fee?",funFact:"Germans sign contracts for EVERYTHING: phone, gym, internet. Kündigungsfrist (cancellation period) is real."},
{type:"teach",trg:"die Versicherung",src:"insurance",note:"Feminine. Health insurance is MANDATORY in Germany.",example:"A: Haben Sie eine Versicherung?\nB: Ja, Krankenversicherung.",exampleSrc:"A: Do you have insurance?\nB: Yes, health insurance.",funFact:"Krankenversicherung (health insurance) is mandatory. Without it, no doctor visit, no registration, no life."},
{type:"teach",trg:"die Verwaltung / der Beamte",src:"administration / official",note:"Verwaltung is fem. Beamte is masc (adj-noun).",example:"A: Die Verwaltung ist zuständig.\nB: Der Beamte hilft Ihnen.",exampleSrc:"A: The administration is responsible.\nB: The official will help you.",funFact:"German 'Beamte' (civil servants) have legendary job security. Unkündbar (cannot be fired)."},
{type:"mc",q:"'Bitte füllen Sie das Formular aus.' An example of:",opts:["polite imperative","past tense","modal verb","reflexive verb"],ans:"polite imperative",hint:"Füllen Sie... aus! A polite command with a separable verb."},
{type:"fb",s:"Haben Sie einen {1}?",a:["Termin"],opts:["Termin","Formular","Vertrag","Ausweis"],hint:"The first question at any German office: do you have an appointment?",sSrc:"Do you have an {1}?"},
{type:"mc",q:"'Anmeldung' is mandatory within ___ days of moving.",opts:["14","30","7","90"],ans:"14",hint:"Two weeks! German bureaucracy waits for no one."},
{type:"match",pairs:[{trg:"das Formular",src:"the form"},{trg:"der Termin",src:"appointment"},{trg:"die Unterschrift",src:"signature"},{trg:"der Vertrag",src:"contract"},{trg:"die Versicherung",src:"insurance"}]},
{type:"drag_fill",s:"Ich {1} das Formular {2} und gebe meine {3}.",blanks:{"1":"fülle","2":"aus","3":"Unterschrift"},pool:["fülle","aus","Unterschrift","Termin","habe","ein"],hint:"Fill out the form (separable: ausfüllen) and give my signature.",sSrc:"I {1} the form {2} and give my {3}."},
{type:"fb",s:"Die {1} kostet zwanzig Euro.",a:["Gebühr"],opts:["Gebühr","Versicherung","Anmeldung","Verwaltung"],hint:"The fee. A charge for the service.",sSrc:"The {1} costs twenty euros."},
{type:"mc",q:"German civil servants are famous for:",opts:["legendary job security","low salaries","working weekends","being very fast"],ans:"legendary job security",hint:"Unkündbar = cannot be fired. A German institution."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-anmeldung-done",trg:"Nummer 347. Verumius geht zum Schalter. Formulare, Unterschrift, Gebühr. Fertig. Er hat seine Anmeldung. Er existiert offiziell in Deutschland. Der Beamte sagt: 'Nächster!'",src:"Number 347. Verumius goes to the counter. Forms, signature, fee. Done. He has his registration. He officially exists in Germany. The official says: 'Next!'"},
{type:"fb",s:"Ohne {1} kann ich nicht zum Arzt gehen.",a:["Versicherung"],opts:["Versicherung","Formular","Termin","Gebühr"],hint:"Without this, no doctor visit in Germany.",sSrc:"Without {1} I cannot go to the doctor."},
{type:"mc",q:"'Hausverwaltung' is a compound of:",opts:["Haus + Verwaltung","Haus + Waltung","Hauser + Verwaltung","Haus + Verwalter"],ans:"Haus + Verwaltung",hint:"House + administration. Property management."}
]},

// ─── L8: Arbeit und Studium ───
{id:"deu_r6l8",title:"Arbeit und Studium",icon:"💼",xp:15,board:true,steps:[
{type:"intro",title:"Arbeit und Studium",desc:"Work, education, and professions. What do you do? How do you describe your job? The most common small-talk topic after weather.",goals:["Work and job vocabulary","Education terms","Describe your profession"]},
{type:"teach",trg:"die Arbeit / arbeiten",src:"work / to work",note:"Arbeit is feminine. Arbeiten is regular.",example:"A: Wo arbeitest du?\nB: Ich arbeite in einem Büro.",exampleSrc:"A: Where do you work?\nB: I work in an office.",funFact:"'Arbeit macht frei' is a dark phrase from history. In everyday use, 'Arbeit' is neutral: 'Ich gehe zur Arbeit.'"},
{type:"teach",trg:"der Beruf / der Job",src:"profession / job",note:"Beruf is formal (profession). Job is casual.",example:"A: Was ist dein Beruf?\nB: Ich bin Lehrer.",exampleSrc:"A: What is your profession?\nB: I am a teacher.",funFact:"German drops the article for professions: 'Ich bin Lehrer' (not 'Ich bin EIN Lehrer'). Unique grammar rule."},
{type:"teach",trg:"das Büro / die Firma",src:"office / company",note:"Büro is neuter. Firma is feminine.",example:"A: Mein Büro ist klein.\nB: Meine Firma ist groß.",exampleSrc:"A: My office is small.\nB: My company is big.",funFact:"'Büro' from French 'bureau.' Germans pronounce it 'bü-ROH.' Many German office words are French loans."},
{type:"teach",trg:"der Lehrer / die Lehrerin",src:"teacher (m/f)",note:"Always give both forms in German.",example:"A: Mein Lehrer ist streng.\nB: Meine Lehrerin ist nett.",exampleSrc:"A: My teacher (m) is strict.\nB: My teacher (f) is nice.",funFact:"'Lehren' = to teach. 'Lernen' = to learn. Don't mix them up! Lehrer teaches, Lerner learns."},
{type:"teach",trg:"die Schule / die Universität",src:"school / university",note:"Both feminine. 'Uni' is the casual short form.",example:"A: Gehst du noch zur Schule?\nB: Nein, ich studiere an der Uni.",exampleSrc:"A: Are you still in school?\nB: No, I study at university.",funFact:"'Studieren' in German means studying at university specifically. 'Lernen' is for school or self-study."},
{type:"teach",trg:"studieren / lernen",src:"to study (at uni) / to learn",note:"Studieren = university. Lernen = general learning.",example:"A: Was studierst du?\nB: Ich studiere Medizin.",exampleSrc:"A: What are you studying?\nB: I'm studying medicine.",funFact:"A German 'Student' is ALWAYS a university student. School pupils are 'Schüler.'"},
{type:"teach",trg:"der Chef / die Chefin",src:"boss (m/f)",note:"From French. Masculine/feminine forms.",example:"A: Mein Chef ist streng.\nB: Meine Chefin ist fair.",exampleSrc:"A: My boss (m) is strict.\nB: My boss (f) is fair.",funFact:"Germans use 'Chef' for boss in everyday speech. In a restaurant, 'der Küchenchef' = head chef."},
{type:"teach",trg:"das Gehalt / der Urlaub",src:"salary / vacation",note:"Gehalt is neuter. Urlaub is masculine.",example:"A: Wie ist das Gehalt?\nB: Gut. Und 30 Tage Urlaub!",exampleSrc:"A: How is the salary?\nB: Good. And 30 days vacation!",funFact:"Germany mandates minimum 20 vacation days. Most jobs give 25-30. Plus public holidays. Work-life balance!"},
{type:"mc",q:"'Was ist dein Beruf?' You answer 'I am a teacher':",opts:["Ich bin Lehrer.","Ich bin ein Lehrer.","Ich bin der Lehrer.","Ich habe Lehrer."],ans:"Ich bin Lehrer.",hint:"German drops the article for professions."},
{type:"fb",s:"Ich {1} an der Universität.",a:["studiere"],opts:["studiere","lerne","arbeite","lehre"],hint:"At university, Germans use a different verb than lernen.",sSrc:"I {1} at the university."},
{type:"mc",q:"Germany mandates a minimum of ___ vacation days.",opts:["20","10","15","5"],ans:"20",hint:"Most jobs give 25-30, but the legal minimum is 20."},
{type:"match",pairs:[{trg:"die Arbeit",src:"work"},{trg:"der Beruf",src:"profession"},{trg:"das Büro",src:"office"},{trg:"die Firma",src:"company"},{trg:"der Urlaub",src:"vacation"}]},
{type:"drag_fill",s:"Mein {1} arbeitet bei einer großen {2} in Berlin.",blanks:{"1":"Chef","2":"Firma"},pool:["Chef","Firma","Büro","Schule","Lehrer","Universität"],hint:"My boss works at a big company in Berlin.",sSrc:"My {1} works at a large {2} in Berlin."},
{type:"fb",s:"Ich bin {1}. Ich lehre Deutsch.",a:["Lehrerin"],opts:["Lehrerin","Schülerin","Studentin","Chefin"],hint:"A teacher (female). Add the feminine suffix to the masculine form.",sSrc:"I am a {1}. I teach German."},
{type:"mc",q:"'Studieren' vs 'lernen':",opts:["studieren = at university, lernen = general learning","studieren = general, lernen = university","both mean the same","studieren = reading, lernen = writing"],ans:"studieren = at university, lernen = general learning",hint:"A German 'Student' is always at a specific institution of higher education."},
{type:"fb",s:"Das {1} ist gut. Dreißig Tage Urlaub!",a:["Gehalt"],opts:["Gehalt","Urlaub","Büro","Beruf"],hint:"The salary. Your monthly payment for work.",sSrc:"The {1} is good. Thirty days of vacation!"},
{type:"mc",q:"A German Schüler is:",opts:["a school pupil","a university student","a teacher","a professor"],ans:"a school pupil",hint:"In German, the word depends on the learner's level of education."}
]},

// ─── L9: Freizeit und Hobbys ───
{id:"deu_r6l9",title:"Freizeit und Hobbys",icon:"🎨",xp:15,board:true,steps:[
{type:"intro",title:"Freizeit und Hobbys",desc:"What do you do in your free time? Sports, music, travel, and the verb 'gern.' Express what you enjoy.",goals:["Hobby and leisure vocabulary","Sports and activities","Express interests with gern/lieber"]},
{type:"teach",trg:"die Freizeit / das Hobby",src:"free time / hobby",note:"Freizeit is feminine. Hobby is neuter (borrowed from English).",example:"A: Was machst du in deiner Freizeit?\nB: Mein Hobby ist Schwimmen.",exampleSrc:"A: What do you do in your free time?\nB: My hobby is swimming.",funFact:"'Freizeit' = free + time. A compound noun. Germans take Freizeit seriously: it's when the rules relax."},
{type:"teach",trg:"der Sport / schwimmen",src:"sport / to swim",note:"Sport is masculine. Schwimmen is irregular (past: schwamm).",example:"A: Treibst du Sport?\nB: Ja, ich schwimme gern.",exampleSrc:"A: Do you do sports?\nB: Yes, I like swimming.",funFact:"'Sport treiben' = to do sports. Treiben literally = to drive/push. Germans push themselves."},
{type:"teach",trg:"laufen / Fahrrad fahren",src:"to run / to ride a bicycle",note:"Laufen: irregular (läuft). Fahrrad fahren: two-word verb.",example:"A: Ich laufe jeden Morgen.\nB: Und ich fahre Fahrrad.",exampleSrc:"A: I run every morning.\nB: And I ride my bicycle.",funFact:"Germany is a cycling nation. Fahrrad = travel-wheel. Dedicated bike lanes everywhere."},
{type:"teach",trg:"spielen / tanzen",src:"to play / to dance",note:"Both regular. Spielen works for sports, instruments, and games.",example:"A: Spielst du Fußball?\nB: Nein, ich tanze lieber.",exampleSrc:"A: Do you play soccer?\nB: No, I prefer dancing.",funFact:"'Spielen' covers everything: Fußball spielen, Gitarre spielen, Karten spielen. One verb for all play."},
{type:"teach",trg:"lesen / singen",src:"to read / to sing",note:"Lesen: irregular (liest). Singen: irregular (sang).",example:"A: Ich lese gern Bücher.\nB: Und ich singe gern.",exampleSrc:"A: I like reading books.\nB: And I like singing.",funFact:"'Lesen' has a vowel change: du liest, er liest. Same pattern as essen (isst)."},
{type:"teach",trg:"reisen / das Reisen",src:"to travel / travel",note:"Regular verb. 'Das Reisen' = travel as noun.",example:"A: Ich reise gern.\nB: Wohin reist du?",exampleSrc:"A: I like traveling.\nB: Where do you travel?",funFact:"Germans are the world's biggest travelers. 'Fernweh' = far-sickness = wanderlust. The opposite of Heimweh (homesickness)."},
{type:"teach",trg:"die Musik / das Konzert",src:"music / concert",note:"Musik is feminine. Konzert is neuter.",example:"A: Ich höre gern Musik.\nB: Gehen wir ins Konzert?",exampleSrc:"A: I like listening to music.\nB: Shall we go to the concert?",funFact:"Germany has more orchestras than any other country. Classical music is serious business."},
{type:"teach",trg:"das Kino / das Theater",src:"cinema / theater",note:"Both neuter. 'Ins Kino gehen' = to go to the movies.",example:"A: Gehen wir ins Kino?\nB: Oder ins Theater?",exampleSrc:"A: Shall we go to the cinema?\nB: Or to the theater?",funFact:"German cinemas often show films in original language with subtitles (OmU = Original mit Untertiteln)."},
{type:"teach",trg:"malen / fotografieren",src:"to paint / to photograph",note:"Both regular. Creative hobbies.",example:"A: Ich male gern.\nB: Und ich fotografiere gern.",exampleSrc:"A: I like painting.\nB: And I like photographing.",funFact:"'Malen' = to paint (art). 'Streichen' = to paint (walls). Different verbs for different painting!"},
{type:"mc",q:"'Treibst du Sport?' means:",opts:["Do you do sports?","Do you drive sports?","Do you push sports?","Do you like sports?"],ans:"Do you do sports?",hint:"This is a fixed verb-noun collocation. 'Treiben' pairs with a physical activity noun."},
{type:"fb",s:"Ich {1} gern Bücher.",a:["lese"],opts:["lese","singe","spiele","tanze"],hint:"What do you do with books? Read them.",sSrc:"I {1} books with pleasure."},
{type:"mc",q:"'Fernweh' means:",opts:["wanderlust / longing for far places","homesickness","fear of travel","jet lag"],ans:"wanderlust / longing for far places",hint:"Fern (far) + Weh (ache). The opposite of Heimweh."},
{type:"match",pairs:[{trg:"schwimmen",src:"to swim"},{trg:"laufen",src:"to run"},{trg:"spielen",src:"to play"},{trg:"lesen",src:"to read"},{trg:"reisen",src:"to travel"}]},
{type:"drag_fill",s:"Ich {1} gern Fußball, aber ich {2} lieber Fahrrad.",blanks:{"1":"spiele","2":"fahre"},pool:["spiele","fahre","laufe","schwimme","tanze","singe"],hint:"I like playing soccer, but I prefer cycling.",sSrc:"I {1} soccer with pleasure, but I prefer {2} bicycle."},
{type:"fb",s:"Gehen wir heute Abend ins {1}?",a:["Kino"],opts:["Kino","Büro","Krankenhaus","Bürgeramt"],hint:"The place where you watch films.",sSrc:"Shall we go to the {1} tonight?"},
{type:"mc",q:"'Spielen' can be used for:",opts:["sports, instruments, and games","only sports","only music","only children's games"],ans:"sports, instruments, and games",hint:"Fußball spielen, Gitarre spielen, Karten spielen. Universal play verb."},
{type:"fb",s:"Mein Hobby ist {1}. Ich reise jedes Jahr.",a:["Reisen"],opts:["Reisen","Lesen","Kochen","Tanzen"],hint:"Travel as a hobby. The noun form.",sSrc:"My hobby is {1}. I travel every year."}
]},

// ─── L10: Ein Fest planen ───
{id:"deu_r6l10",title:"Ein Fest planen",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"Ein Fest planen",desc:"Verumius plans a small party. Invitations, food, drinks, and putting all vocabulary together. Cultural event: the German Einweihungsfeier (housewarming).",goals:["Party and event vocabulary","Combine food, time, and place words","Plan and describe an event"]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-party-planning",trg:"Lena ruft an: 'Du wohnst seit einem Monat in Berlin und hast noch keine Einweihungsfeier gemacht? Das geht nicht! Samstag. Einladungen. Sofort.' Verumius sieht sich in der leeren Wohnung um. Er hat einen Tisch. Und zwei Stühle.",src:"Lena calls: 'You've been living in Berlin for a month and haven't had a housewarming yet? That won't do! Saturday. Invitations. Now.' Verumius looks around the empty apartment. He has a table. And two chairs."},
{type:"teach",trg:"die Feier / die Party",src:"celebration / party",note:"Feier is formal, Party is casual. Both feminine.",example:"A: Wir machen eine Feier!\nB: Eine Party? Super!",exampleSrc:"A: We're having a celebration!\nB: A party? Great!",funFact:"'Einweihungsfeier' = housewarming party. Germans bring bread and salt as traditional gifts."},
{type:"teach",trg:"die Einladung / einladen",src:"invitation / to invite",note:"Einladung is feminine. Einladen is separable: ich lade ein.",example:"A: Ich lade Lukas ein.\nB: Und Hildi?",exampleSrc:"A: I'm inviting Lukas.\nB: And Hildi?",funFact:"Separable: 'Ich lade dich ein!' The 'ein' goes to the end. With modals: 'Ich möchte dich einladen.'"},
{type:"teach",trg:"das Geschenk / schenken",src:"gift / to give (as gift)",note:"Geschenk is neuter. Schenken is regular.",example:"A: Was schenkst du?\nB: Ich schenke Wein.",exampleSrc:"A: What are you giving?\nB: I'm giving wine.",funFact:"'Schenken' = to give as a gift. 'Geben' = to give in general. Gifts are serious in Germany."},
{type:"teach",trg:"feiern / sich freuen",src:"to celebrate / to be happy/look forward to",note:"Feiern is regular. Sich freuen auf = look forward to.",example:"A: Wir feiern am Samstag!\nB: Ich freue mich!",exampleSrc:"A: We're celebrating on Saturday!\nB: I'm looking forward to it!",funFact:"'Sich freuen auf' = look forward to (future). 'Sich freuen über' = be happy about (present). Preposition matters!"},
{type:"teach",trg:"der Gast / die Gäste",src:"guest / guests",note:"Masculine. Plural: Gäste (umlaut!).",example:"A: Wie viele Gäste kommen?\nB: Zehn Gäste.",exampleSrc:"A: How many guests are coming?\nB: Ten guests.",funFact:"'Gastfreundschaft' = guest-friendship = hospitality. A German virtue. Guests get the best treatment."},
{type:"teach",trg:"bringen / holen",src:"to bring / to fetch",note:"Bringen: irregular. Holen: regular.",example:"A: Ich bringe Kuchen.\nB: Und ich hole Getränke.",exampleSrc:"A: I'll bring cake.\nB: And I'll get drinks.",funFact:"'Bringen' = bring (towards here). 'Holen' = fetch/go get (away and back). Direction matters."},
{type:"mc",q:"'Einweihungsfeier' is a:",opts:["housewarming party","birthday party","wedding","office party"],ans:"housewarming party",hint:"Ein+weih+ung = dedication/consecration. Feier = celebration. For a new home."},
{type:"fb",s:"Ich {1} Lukas zur Party {1}.",a:["lade"],opts:["lade","einlade","bringe","hole"],hint:"Separable verb splits. Prefix at end. Fill in the ich-form of the stem.",sSrc:"I {1} Lukas to the party {1}."},
{type:"mc",q:"Traditional German housewarming gifts are:",opts:["bread and salt","flowers and wine","money and cards","books and music"],ans:"bread and salt",hint:"Brot und Salz. So the house never lacks food."},
{type:"drag_fill",s:"Wir {1} am Samstag und ich {2} mich sehr!",blanks:{"1":"feiern","2":"freue"},pool:["feiern","freue","bringe","lade","hole","schenke"],hint:"We celebrate on Saturday and I'm looking forward to it!",sSrc:"We {1} on Saturday and I am very {2}!"},
{type:"fb",s:"Wie viele {1} kommen zur Party?",a:["Gäste"],opts:["Gäste","Geschenke","Einladungen","Feiern"],hint:"How many people are invited? The guests.",sSrc:"How many {1} are coming to the party?"},
{type:"mc",q:"'Sich freuen auf' means:",opts:["to look forward to","to be afraid of","to run away from","to argue about"],ans:"to look forward to",hint:"Freuen = to be happy. Auf = towards (future). Happy about something coming."},
{type:"match",pairs:[{trg:"die Feier",src:"celebration"},{trg:"die Einladung",src:"invitation"},{trg:"das Geschenk",src:"gift"},{trg:"der Gast",src:"guest"},{trg:"feiern",src:"to celebrate"}]},
{type:"drag_fill",s:"Ich {1} Kuchen und Lukas {2} Getränke.",blanks:{"1":"bringe","2":"holt"},pool:["bringe","holt","lade","schenke","feiere","hole"],hint:"I bring cake (towards here). Lukas fetches drinks (goes to get them).",sSrc:"I {1} cake and Lukas {2} drinks."},
{type:"fb",s:"Was {1} du Verumius zur Einweihungsfeier?",a:["schenkst"],opts:["schenkst","bringst","holst","kaufst"],hint:"What do you GIVE as a gift?",sSrc:"What do you {1} Verumius for the housewarming?"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-einweihung",trg:"Samstag Abend. Zehn Gäste, ein Tisch, zwei Stühle. Alle sitzen auf dem Boden. Lukas bringt Bier, Hildi bringt Brot und Salz ('Tradition!'), Lena schickt eine Videobotschaft. Verumius hat sein erstes Fest in Deutschland. Die Wohnung fühlt sich zum ersten Mal wie zu Hause an.",src:"Saturday evening. Ten guests, one table, two chairs. Everyone sits on the floor. Lukas brings beer, Hildi brings bread and salt ('Tradition!'), Lena sends a video message. Verumius has his first party in Germany. The apartment feels like home for the first time."}
]},

// ─── L11: Hildis Tee ───
{id:"deu_r6l11",title:"Hildis Tee",icon:"🍵",xp:15,board:true,steps:[
{type:"intro",title:"Hildis Tee",desc:"Story climax. Verumius is invited to Hildi's apartment for the first time. Hot water is back. Hildi makes tea. A real conversation happens.",goals:["Review all Unit 6 vocabulary in story context","Emotional vocabulary","Hildi's character revelation"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-apartment",trg:"Dienstagabend. Hildi klopft an die Tür. 'Das heiße Wasser funktioniert wieder. Ich habe die Reparatur selbst gemacht.' Pause. 'Möchten Sie... einen Tee? Bei mir?'",src:"Tuesday evening. Hildi knocks on the door. 'The hot water works again. I did the repair myself.' Pause. 'Would you like... a tea? At my place?'"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-hildi-wohnzimmer",trg:"Hildis Wohnung. Alles perfekt. Blumen auf jedem Fensterbrett. Fotos an der Wand: ein Mann mit freundlichen Augen. 'Mein Mann Werner,' sagt Hildi leise. 'Seit fünf Jahren...' Sie macht den Tee fertig.",src:"Hildi's apartment. Everything perfect. Flowers on every windowsill. Photos on the wall: a man with kind eyes. 'My husband Werner,' says Hildi quietly. 'For five years...' She finishes making the tea."},
{type:"mc",q:"'Das heiße Wasser funktioniert wieder.' Hildi fixed:",opts:["the hot water","the cold water","the shower","the toilet"],ans:"the hot water",hint:"'Heiß' is the opposite of 'kalt.' Something Hildi finally fixed."},
{type:"fb",s:"Möchten Sie einen Tee {1} mir?",a:["bei"],opts:["bei","mit","von","zu"],hint:"At my place. Which dative preposition means 'at someone's place'?",sSrc:"Would you like a tea {1} my place?"},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-tea",trg:"Sie sitzen am Tisch. Hildi gießt Tee ein. 'Seit wann sind Sie in Deutschland?' 'Seit einem Monat.' 'Und? Gefällt es Ihnen?' Verumius denkt nach. 'Ja. Es ist... anders. Aber gut.' Hildi nickt. 'Am Anfang ist alles schwer. Auch für mich war es schwer. Damals.'",src:"They sit at the table. Hildi pours tea. 'Since when have you been in Germany?' 'For a month.' 'And? Do you like it?' Verumius thinks. 'Yes. It's... different. But good.' Hildi nods. 'In the beginning, everything is hard. For me too it was hard. Back then.'"},
{type:"mc",q:"'Seit einem Monat' uses which case after seit?",opts:["dative","accusative","nominative","genitive"],ans:"dative",hint:"The magic 7 prepositions (aus, bei, mit, nach, seit, von, zu) all require which case?"},
{type:"fb",s:"Am Anfang {1} alles schwer.",a:["ist"],opts:["ist","war","hat","wird"],hint:"In the beginning, everything IS hard. Present tense statement.",sSrc:"In the beginning, everything {1} hard."},
{type:"story",speaker:"narrator",mood:"happy",art:"de-hildi-smile",trg:"Hildi zeigt auf die Hausordnung an der Wand. 'Die habe ich selbst geschrieben. Vierzehn Seiten. Werner hat gelacht.' Zum ersten Mal lächelt sie richtig. 'Er hat gesagt: Hildi, du kannst ein Buch schreiben. Über Mülltrennung.'",src:"Hildi points at the Hausordnung on the wall. 'I wrote it myself. Fourteen pages. Werner laughed.' For the first time, she smiles properly. 'He said: Hildi, you could write a book. About waste separation.'"},
{type:"mc",q:"The Hausordnung has:",opts:["14 pages","7 pages","20 pages","3 pages"],ans:"14 pages",hint:"Vierzehn Seiten. Hildi wrote it all herself."},
{type:"fb",s:"Werner hat {1}: 'Du kannst ein Buch schreiben.'",a:["gesagt"],opts:["gesagt","gemacht","geschrieben","gelacht"],hint:"Werner SAID something. Past tense of sagen.",sSrc:"Werner {1}: 'You can write a book.'"},
{type:"story",speaker:"narrator",mood:"happy",art:"de-hildi-door",trg:"An der Tür. Hildi: 'Die Ruhezeit beginnt um 22 Uhr. Sie wissen das.' Verumius: 'Ja, Frau Schreiber.' Hildi: 'Hildi. Sie können Hildi sagen.' Die Tür schließt sich. Verumius steht im Flur und lächelt. Hildi. Nicht Frau Schreiber. Ein Durchbruch.",src:"At the door. Hildi: 'Quiet hours begin at 10 PM. You know that.' Verumius: 'Yes, Mrs. Schreiber.' Hildi: 'Hildi. You can say Hildi.' The door closes. Verumius stands in the hallway and smiles. Hildi. Not Mrs. Schreiber. A breakthrough."},
{type:"mc",q:"What does Hildi offer Verumius?",opts:["Permission to use her first name","A key to her apartment","A copy of the Hausordnung","A job at the Hausverwaltung"],ans:"Permission to use her first name",hint:"'Sie können Hildi sagen.' From formal to personal. A breakthrough."},
{type:"drag_fill",s:"Hildi wohnt {1} fünf Jahren alleine. Ihr Mann Werner ist {2} fünf Jahren nicht mehr da.",blanks:{"1":"seit","2":"seit"},pool:["seit","vor","nach","bis","um"],hint:"For five years. Both blanks use the same dative preposition for duration.",sSrc:"Hildi has lived alone for {1} five years. Her husband Werner has {2} been gone for five years."},
{type:"match",pairs:[{trg:"die Ruhezeit",src:"quiet hours"},{trg:"der Durchbruch",src:"breakthrough"},{trg:"der Tee",src:"tea"},{trg:"die Reparatur",src:"repair"},{trg:"der Anfang",src:"beginning"}]},
{type:"fb",s:"Es {1} mir hier in Deutschland.",a:["gefällt"],opts:["gefällt","schmeckt","ist","hat"],hint:"I like it here. The thing pleases ME. Dative verb.",sSrc:"It {1} me here in Germany."},
{type:"mc",q:"This lesson's emotional arc shows Hildi as:",opts:["strict but caring, with hidden vulnerability","cold and distant always","only interested in rules","angry about the hot water"],ans:"strict but caring, with hidden vulnerability",hint:"The Hausordnung, the tea, the first-name offer. Layers."},
{type:"tip",title:"A1 Complete: Verumius Has a Home",text:"Unit 6 is the end of A1.\n\nVerumius now has:\n1. An apartment (with a 14-page Hausordnung)\n2. A friend (Lukas)\n3. A landlady who is becoming a friend (Hildi)\n4. Hot water (finally)\n5. All the German he needs to survive\n\nBut A1 is just survival.\nA2 is where real communication begins."}
]},

// ─── L12: Alles auf Deutsch ───
{id:"deu_r6l12",title:"Alles auf Deutsch",icon:"🏆",xp:25,board:true,steps:[
{type:"intro",title:"Alles auf Deutsch",desc:"Comprehensive Unit 6 review. All vocabulary domains, all grammar, all communicative functions. Prove you can handle daily life in Germany.",goals:["Full Unit 6 vocabulary review","All grammar constructs tested","A1 mastery demonstrated"]},
{type:"mc",q:"'Ich ___ jeden Morgen um sieben Uhr.'",opts:["dusche","schlafe","einschlafe","wecke"],ans:"dusche",hint:"Morning hygiene routine. What do you do at 7 AM?"},
{type:"fb",s:"Gestern {1} das Wasser kalt.",a:["war"],opts:["war","ist","hatte","hat"],hint:"Past tense of sein. Yesterday the water WAS cold.",sSrc:"Yesterday the water {1} cold."},
{type:"mc",q:"'Am ___ gehe ich zum Arzt.'",opts:["Montag","Januar","Sommer","Uhr"],ans:"Montag",hint:"am + day of the week. Not month, season, or time."},
{type:"drag_fill",s:"Ich habe {1} acht Uhr einen {2} beim Arzt.",blanks:{"1":"um","2":"Termin"},pool:["um","am","Termin","Formular","im","Vertrag"],hint:"AT 8 o'clock (um + time). An appointment.",sSrc:"I have {1} eight o'clock an {2} at the doctor."},
{type:"fb",s:"Im {1} blühen die Blumen.",a:["Frühling"],opts:["Frühling","Winter","Herbst","Dezember"],hint:"Which season brings flowers?",sSrc:"In {1} the flowers bloom."},
{type:"mc",q:"'Mein Kopf tut weh' means:",opts:["My head hurts","My head is big","My head is cold","My head is turning"],ans:"My head hurts",hint:"Weh tun = to hurt."},
{type:"drag_fill",s:"Ich {1} die Hausverwaltung {2} und sage: 'Kein heißes Wasser {3} zwei Tagen!'",blanks:{"1":"rufe","2":"an","3":"seit"},pool:["rufe","an","seit","habe","ein","vor"],hint:"Call (separable: anrufen). A preposition expressing duration from a starting point.",sSrc:"I {1} the property management {2} and say: 'No hot water for {3} two days!'"},
{type:"fb",s:"Bitte füllen Sie das {1} aus.",a:["Formular"],opts:["Formular","Dokument","Vertrag","Ausweis"],hint:"The form. You fill it out at every German office.",sSrc:"Please fill out the {1}."},
{type:"mc",q:"Was ist dein Beruf? 'Ich bin ___.'",opts:["Lehrerin","eine Lehrerin","die Lehrerin","Lehrerinnen"],ans:"Lehrerin",hint:"German drops the article for professions!"},
{type:"drag_fill",s:"Ich {1} gern Fußball und {2} gern Bücher.",blanks:{"1":"spiele","2":"lese"},pool:["spiele","lese","tanze","schwimme","singe","male"],hint:"Play soccer and read books. Two hobbies.",sSrc:"I {1} soccer with pleasure and {2} books with pleasure."},
{type:"fb",s:"Ich {1} Lukas zur Einweihungsfeier {1}.",a:["lade"],opts:["lade","bringe","hole","schenke"],hint:"Separable verb. The prefix is already at the end. What goes in position 2?",sSrc:"I {1} Lukas to the housewarming party {1}."},
{type:"mc",q:"Traditional German housewarming gifts:",opts:["bread and salt","flowers and wine","money and cards","books and music"],ans:"bread and salt",hint:"So the house never lacks food."},
{type:"match",pairs:[{trg:"der Arzt",src:"doctor"},{trg:"das Formular",src:"form"},{trg:"die Versicherung",src:"insurance"},{trg:"der Termin",src:"appointment"},{trg:"die Feier",src:"celebration"}]},
{type:"drag_fill",s:"Seit {1} Monat wohne ich in Berlin und arbeite bei {2} Firma.",blanks:{"1":"einem","2":"einer"},pool:["einem","einer","einen","ein","eine","dem"],hint:"Seit + dative. Bei + dative.",sSrc:"For {1} month I have been living in Berlin and working at {2} company."},
{type:"mc",q:"Hildi says 'Sie können Hildi sagen.' This means:",opts:["Use my first name","Say hello to Hildi","Read the Hausordnung","Call me tomorrow"],ans:"Use my first name",hint:"A shift from formal to personal. She invites informality by sharing something."},
{type:"fb",s:"Es {1} mir sehr gut in Deutschland.",a:["gefällt"],opts:["gefällt","schmeckt","ist","hat"],hint:"I like it here. Gefallen + dative.",sSrc:"It {1} me very well in Germany."},
{type:"drag_fill",s:"Am {1} gehe ich zum Arzt, im {2} fahre ich nach Spanien, und um {3} Uhr fange ich an.",blanks:{"1":"Montag","2":"Sommer","3":"neun"},pool:["Montag","Sommer","neun","Januar","Winter","drei"],hint:"am + day, im + season, um + time. Three time expressions.",sSrc:"On {1} I go to the doctor, in {2} I travel to Spain, and at {3} o'clock I start."},
{type:"mc",q:"A1 is complete. Verumius can now:",opts:["Survive daily life in Germany","Discuss philosophy in German","Write academic papers","Translate poetry"],ans:"Survive daily life in Germany",hint:"A1 = survival level. Real communication starts at A2."}
]},

{id:"deu_r6l13",title:"Arbeit und Bildung",icon:"🎓",xp:15,board:true,steps:[
{type:"intro",title:"Arbeit und Bildung",desc:"Work and education vocabulary: jobs, studies, and the workplace.",goals:["Learn 20 words about work and education","Practice using job and study vocabulary in context"]},
{type:"teach",trg:"der Arbeitsplatz",src:"the workplace",note:"Masculine noun. Plural: die Arbeitsplätze. Compound: Arbeit (work) + Platz (place).",example:"A: Wie ist dein Arbeitsplatz?\nB: Mein Arbeitsplatz ist sehr modern.",exampleSrc:"A: How is your workplace?\nB: My workplace is very modern.",funFact:"Germans value a tidy Arbeitsplatz. Many offices have rules about keeping desks clean before going home."},
{type:"teach",trg:"die Klasse",src:"the class/classroom",note:"Feminine noun. Plural: die Klassen.",example:"A: In welcher Klasse ist dein Kind?\nB: Mein Kind ist in der dritten Klasse.",exampleSrc:"A: What class is your child in?\nB: My child is in third grade.",funFact:"In Germany, Klasse also means grade level. Erste Klasse on a train means first class."},
{type:"teach",trg:"der Kollege",src:"the colleague (male)",note:"Masculine noun. Plural: die Kollegen. Female form: die Kollegin.",example:"A: Kennst du meinen Kollegen?\nB: Ja, er arbeitet im zweiten Stock.",exampleSrc:"A: Do you know my colleague?\nB: Yes, he works on the second floor.",funFact:"Germans often say Liebe Kolleginnen und Kollegen to address all colleagues in a meeting."},
{type:"teach",trg:"der Kurs",src:"the course",note:"Masculine noun. Plural: die Kurse.",example:"A: Welchen Kurs besuchst du?\nB: Ich besuche einen Deutschkurs.",exampleSrc:"A: Which course are you attending?\nB: I am attending a German course.",funFact:"Integrationskurs is the official German integration course for immigrants, covering language and civic knowledge."},
{type:"teach",trg:"die Maschine",src:"the machine",note:"Feminine noun. Plural: die Maschinen.",example:"A: Was macht diese Maschine?\nB: Diese Maschine druckt Etiketten.",exampleSrc:"A: What does this machine do?\nB: This machine prints labels.",funFact:"Waschmaschine (washing machine) is one of the first compound words German learners encounter."},
{type:"teach",trg:"das Praktikum",src:"the internship",note:"Neuter noun. Plural: die Praktika. From Latin practicum.",example:"A: Machst du ein Praktikum?\nB: Ja, ich mache ein Praktikum bei Siemens.",exampleSrc:"A: Are you doing an internship?\nB: Yes, I am doing an internship at Siemens.",funFact:"Praktika are very common in Germany. Many university programs require at least one before graduation."},
{type:"teach",trg:"die Prüfung",src:"the exam",note:"Feminine noun. Plural: die Prüfungen.",example:"A: Wann ist die Prüfung?\nB: Die Prüfung ist am Freitag.",exampleSrc:"A: When is the exam?\nB: The exam is on Friday.",funFact:"The Goethe-Prüfung is Germany's most recognized language certification, offered worldwide."},
{type:"teach",trg:"der Schüler",src:"the student/pupil (male)",note:"Masculine noun. Plural: die Schüler. Female form: die Schülerin. Used for school students, not university.",example:"A: Ist er Schüler?\nB: Ja, er ist Schüler am Gymnasium.",exampleSrc:"A: Is he a student?\nB: Yes, he is a student at the Gymnasium.",funFact:"Schüler is only for school pupils. University students are called Studenten."},
{type:"teach",trg:"die Stelle",src:"the position/job",note:"Feminine noun. Plural: die Stellen. Also means spot or place.",example:"A: Hast du eine neue Stelle?\nB: Ja, ich habe eine Stelle als Lehrer.",exampleSrc:"A: Do you have a new job?\nB: Yes, I have a position as a teacher.",funFact:"Stellenanzeige means job advertisement. Germans often search on portals like StepStone or Indeed."},
{type:"teach",trg:"der Student",src:"the university student (male)",note:"Masculine noun. Plural: die Studenten. Female form: die Studentin. Only for university level.",example:"A: Bist du Student?\nB: Ja, ich bin Student an der Universität Berlin.",exampleSrc:"A: Are you a university student?\nB: Yes, I am a student at the University of Berlin.",funFact:"German students pay very low tuition fees compared to the US or UK. Many public universities charge under 300 euros per semester."},
{type:"teach",trg:"das Studium",src:"the studies/degree program",note:"Neuter noun. No common plural. Refers to university studies as a whole.",example:"A: Wie lange dauert dein Studium?\nB: Mein Studium dauert drei Jahre.",exampleSrc:"A: How long does your degree take?\nB: My degree takes three years.",funFact:"A typical Bachelor Studium in Germany is 6 semesters (3 years), shorter than in many other countries."},
{type:"teach",trg:"der Test",src:"the test",note:"Masculine noun. Plural: die Tests.",example:"A: Wie war der Test?\nB: Der Test war nicht so schwer.",exampleSrc:"A: How was the test?\nB: The test was not so hard.",funFact:"Germans borrowed Test directly from English. The older German word is Prüfung, which sounds more formal."},
{type:"teach",trg:"der Unterricht",src:"the lesson/instruction",note:"Masculine noun. Usually no plural. Refers to teaching sessions.",example:"A: Wann beginnt der Unterricht?\nB: Der Unterricht beginnt um acht Uhr.",exampleSrc:"A: When does the lesson start?\nB: The lesson starts at eight o'clock.",funFact:"German school Unterricht typically starts at 7:45 or 8:00, earlier than in many countries."},
{type:"teach",trg:"verdienen",src:"to earn",note:"Regular verb. Ich verdiene, du verdienst, er/sie verdient.",example:"A: Wie viel verdienst du?\nB: Ich verdiene genug.",exampleSrc:"A: How much do you earn?\nB: I earn enough.",funFact:"Asking about salary is considered quite private in Germany. Many people avoid the topic."},
{type:"teach",trg:"werden",src:"to become",note:"Irregular verb. Ich werde, du wirst, er/sie wird. Also used as future auxiliary.",example:"A: Was willst du werden?\nB: Ich will Arzt werden.",exampleSrc:"A: What do you want to become?\nB: I want to become a doctor.",funFact:"Werden is one of the most important German verbs. It forms the future tense and the passive voice."},
{type:"teach",trg:"arbeitslos",src:"unemployed",note:"Adjective. Compound: Arbeit (work) + los (without).",example:"A: Ist er noch arbeitslos?\nB: Nein, er hat jetzt eine Stelle.",exampleSrc:"A: Is he still unemployed?\nB: No, he has a job now.",funFact:"The suffix -los means without, like English -less. Arbeitslos, hoffnungslos (hopeless), kostenlos (free of charge)."},
{type:"teach",trg:"selbständig",src:"self-employed/independent",note:"Adjective. Also spelled selbstständig (both accepted).",example:"A: Arbeitest du in einer Firma?\nB: Nein, ich bin selbständig.",exampleSrc:"A: Do you work at a company?\nB: No, I am self-employed.",funFact:"Germany has over 4 million self-employed people. The word comes from selbst (self) + ständig (standing)."},
{type:"teach",trg:"kulturell",src:"cultural",note:"Adjective. Related to die Kultur (culture).",example:"A: Gibt es kulturelle Angebote hier?\nB: Ja, es gibt viele Museen und Theater.",exampleSrc:"A: Are there cultural offerings here?\nB: Yes, there are many museums and theaters.",funFact:"Germany has over 6,000 museums, making it one of the most culturally rich countries in Europe."},
{type:"teach",trg:"normal",src:"normal",note:"Adjective. Same word in English and German, but pronounced with stress on the second syllable: nor-MAL.",example:"A: Ist das normal hier?\nB: Ja, das ist ganz normal.",exampleSrc:"A: Is that normal here?\nB: Yes, that is completely normal.",funFact:"German borrowed normal from Latin normalis. The pronunciation differs: Germans stress the second syllable."},
{type:"teach",trg:"der Doktor",src:"the doctor/PhD",note:"Masculine noun. Plural: die Doktoren. Academic title and medical professional.",example:"A: Ist sie Doktor?\nB: Ja, sie hat einen Doktor in Physik.",exampleSrc:"A: Is she a doctor?\nB: Yes, she has a PhD in physics.",funFact:"Germans take the Doktor title very seriously. It appears on official IDs and people expect to be addressed as Herr/Frau Doktor."},
{type:"mc",q:"How do you say 'workplace' in German?",opts:["der Arbeitsplatz","die Arbeit","der Platz","das Arbeiten"],ans:"der Arbeitsplatz",hint:"It is a compound noun combining work and place."},
{type:"fb",s:"Ich mache ein {1} bei Siemens.",a:"Praktikum",opts:["Praktikum","Prüfung","Studium","Unterricht"],hint:"This is the German word for an internship.",sSrc:"I am doing an {1} at Siemens."},
{type:"mc",q:"Which word means 'to become'?",opts:["werden","verdienen","arbeiten","lernen"],ans:"werden",hint:"This irregular verb also helps form the future tense."},
{type:"match",pairs:[{trg:"die Prüfung",src:"the exam"},{trg:"der Schüler",src:"the pupil"},{trg:"die Stelle",src:"the position/job"},{trg:"arbeitslos",src:"unemployed"},{trg:"der Kurs",src:"the course"}]}
]},

{id:"deu_r6l14",title:"Stift und Papier",icon:"✏️",xp:15,board:true,steps:[
{type:"intro",title:"Stift und Papier",desc:"Writing, media, and learning materials. From pencils to newspapers.",goals:["Learn 20 words about writing and media","Practice using these words in everyday contexts"]},
{type:"teach",trg:"die Antwort",src:"the answer",note:"Feminine noun. Plural: die Antworten. Verb: antworten (to answer).",example:"A: Weißt du die Antwort?\nB: Ja, die Antwort ist Berlin.",exampleSrc:"A: Do you know the answer?\nB: Yes, the answer is Berlin.",funFact:"Antwort comes from Old High German antwurti, meaning a response given face to face."},
{type:"teach",trg:"die Anzeige",src:"the advertisement/display",note:"Feminine noun. Plural: die Anzeigen. Can mean ad, display, or police report.",example:"A: Hast du die Anzeige gelesen?\nB: Ja, sie suchen einen Koch.",exampleSrc:"A: Did you read the advertisement?\nB: Yes, they are looking for a cook.",funFact:"Anzeige can also mean filing a police report. Ich erstatte Anzeige means I am pressing charges."},
{type:"teach",trg:"die Aufgabe",src:"the task/assignment",note:"Feminine noun. Plural: die Aufgaben. Compound: auf (up) + Gabe (giving).",example:"A: Was ist deine Aufgabe?\nB: Meine Aufgabe ist die Planung.",exampleSrc:"A: What is your task?\nB: My task is the planning.",funFact:"Hausaufgabe means homework, literally home task. German students get plenty of Hausaufgaben."},
{type:"teach",trg:"die Aussage",src:"the statement",note:"Feminine noun. Plural: die Aussagen. From aus (out) + sagen (to say).",example:"A: Was ist die Aussage des Textes?\nB: Die Aussage ist klar.",exampleSrc:"A: What is the statement of the text?\nB: The statement is clear.",funFact:"In legal contexts, Aussage means testimony. Eine Aussage machen means to make a statement to police."},
{type:"teach",trg:"das Ergebnis",src:"the result",note:"Neuter noun. Plural: die Ergebnisse.",example:"A: Wie ist das Ergebnis?\nB: Das Ergebnis ist sehr gut.",exampleSrc:"A: How is the result?\nB: The result is very good.",funFact:"Germans love checking Ergebnisse for soccer matches. The Bundesliga results page is one of the most visited sites."},
{type:"teach",trg:"der Fehler",src:"the mistake/error",note:"Masculine noun. Plural: die Fehler.",example:"A: Habe ich einen Fehler gemacht?\nB: Nein, alles ist richtig.",exampleSrc:"A: Did I make a mistake?\nB: No, everything is correct.",funFact:"Fehler machen means to make mistakes. Germans say Aus Fehlern lernt man: you learn from mistakes."},
{type:"teach",trg:"die Lösung",src:"the solution",note:"Feminine noun. Plural: die Lösungen. From lösen (to solve).",example:"A: Gibt es eine Lösung?\nB: Ja, ich habe eine Lösung gefunden.",exampleSrc:"A: Is there a solution?\nB: Yes, I found a solution.",funFact:"Lösung also means dissolving in chemistry. Context tells you whether it is a solution to a problem or a liquid solution."},
{type:"teach",trg:"das Bild",src:"the picture/image",note:"Neuter noun. Plural: die Bilder.",example:"A: Wer hat dieses Bild gemalt?\nB: Das hat mein Sohn gemalt.",exampleSrc:"A: Who painted this picture?\nB: My son painted it.",funFact:"Bildung means education in German, literally forming or building. Same root as Bild (image, formation)."},
{type:"teach",trg:"der Bleistift",src:"the pencil",note:"Masculine noun. Plural: die Bleistifte. Compound: Blei (lead) + Stift (pen).",example:"A: Hast du einen Bleistift?\nB: Ja, hier ist ein Bleistift.",exampleSrc:"A: Do you have a pencil?\nB: Yes, here is a pencil.",funFact:"Bleistift literally means lead pen, though modern pencils use graphite, not lead."},
{type:"teach",trg:"der Bogen",src:"the sheet (of paper)/form",note:"Masculine noun. Plural: die Bögen or die Bogen.",example:"A: Ich brauche einen Bogen Papier.\nB: Hier, nimm diesen Bogen.",exampleSrc:"A: I need a sheet of paper.\nB: Here, take this sheet.",funFact:"Bogen also means bow or arch. The Regenbogen (rainbow) is literally a rain arch."},
{type:"teach",trg:"das Buch",src:"the book",note:"Neuter noun. Plural: die Bücher.",example:"A: Liest du gern Bücher?\nB: Ja, ich lese jeden Abend ein Buch.",exampleSrc:"A: Do you like reading books?\nB: Yes, I read a book every evening.",funFact:"The Frankfurt Book Fair (Frankfurter Buchmesse) is the world's largest book trade fair, held since the 15th century."},
{type:"teach",trg:"der Buchstabe",src:"the letter (of the alphabet)",note:"Masculine noun. Plural: die Buchstaben. Weak noun: den/dem Buchstaben.",example:"A: Wie viele Buchstaben hat das Alphabet?\nB: Das deutsche Alphabet hat 26 Buchstaben plus Umlaute.",exampleSrc:"A: How many letters does the alphabet have?\nB: The German alphabet has 26 letters plus umlauts.",funFact:"Buchstabe literally comes from Buche (beech tree) + Stab (staff), referring to ancient runes carved into beech wood."},
{type:"teach",trg:"der Kugelschreiber",src:"the ballpoint pen",note:"Masculine noun. Plural: die Kugelschreiber. Often shortened to Kuli.",example:"A: Kann ich deinen Kugelschreiber haben?\nB: Klar, hier ist mein Kuli.",exampleSrc:"A: Can I have your ballpoint pen?\nB: Sure, here is my pen.",funFact:"Kugelschreiber literally means ball writer. Almost everyone shortens it to Kuli in everyday speech."},
{type:"teach",trg:"das Papier",src:"the paper",note:"Neuter noun. Plural: die Papiere. Papiere also means documents or ID papers.",example:"A: Haben Sie Ihre Papiere dabei?\nB: Ja, hier ist mein Ausweis.",exampleSrc:"A: Do you have your papers with you?\nB: Yes, here is my ID.",funFact:"Papiere in plural often means identity documents. Ihre Papiere, bitte is what police say when checking IDs."},
{type:"teach",trg:"der Satz",src:"the sentence",note:"Masculine noun. Plural: die Sätze.",example:"A: Kannst du den Satz wiederholen?\nB: Ja: Ich lerne Deutsch.",exampleSrc:"A: Can you repeat the sentence?\nB: Yes: I am learning German.",funFact:"Satz has many meanings: sentence, set (in tennis), movement (in music), and rate (Zinssatz = interest rate)."},
{type:"teach",trg:"der Text",src:"the text",note:"Masculine noun. Plural: die Texte.",example:"A: Hast du den Text gelesen?\nB: Ja, der Text war interessant.",exampleSrc:"A: Did you read the text?\nB: Yes, the text was interesting.",funFact:"Text comes from Latin textus meaning woven. A text is a weaving of words."},
{type:"teach",trg:"das Thema",src:"the topic/theme",note:"Neuter noun. Plural: die Themen. From Greek thema.",example:"A: Was ist das Thema heute?\nB: Das Thema ist Umweltschutz.",exampleSrc:"A: What is the topic today?\nB: The topic is environmental protection.",funFact:"Kein Thema is a casual German way of saying no problem or do not mention it."},
{type:"teach",trg:"das Wort",src:"the word",note:"Neuter noun. Two plurals: die Wörter (individual words), die Worte (connected speech/sayings).",example:"A: Was bedeutet dieses Wort?\nB: Dieses Wort bedeutet Freundschaft.",exampleSrc:"A: What does this word mean?\nB: This word means friendship.",funFact:"German distinguishes Wörter (individual dictionary words) from Worte (meaningful words in context, like famous last Worte)."},
{type:"teach",trg:"die Zeitung",src:"the newspaper",note:"Feminine noun. Plural: die Zeitungen. From Zeit (time) + -ung.",example:"A: Liest du die Zeitung?\nB: Ja, ich lese die Zeitung am Morgen.",exampleSrc:"A: Do you read the newspaper?\nB: Yes, I read the newspaper in the morning.",funFact:"Bild-Zeitung (Bild) is Germany's most-read newspaper, known for its bold headlines and tabloid style."},
{type:"teach",trg:"der Film",src:"the film/movie",note:"Masculine noun. Plural: die Filme.",example:"A: Welchen Film möchtest du sehen?\nB: Ich möchte einen deutschen Film sehen.",exampleSrc:"A: Which movie would you like to see?\nB: I would like to see a German movie.",funFact:"Germany has a strong film industry. The Berlin International Film Festival (Berlinale) is one of the world's top three."},
{type:"mc",q:"What does 'der Fehler' mean?",opts:["the mistake","the solution","the result","the task"],ans:"the mistake",hint:"Think of something you want to correct."},
{type:"fb",s:"Ich brauche einen {1} und Papier.",a:"Bleistift",opts:["Bleistift","Buchstabe","Bogen","Buch"],hint:"A writing tool made of wood with graphite inside.",sSrc:"I need a {1} and paper."},
{type:"mc",q:"Which word means 'the topic'?",opts:["das Thema","der Text","der Satz","das Wort"],ans:"das Thema",hint:"This neuter noun comes from Greek and means subject of discussion."},
{type:"match",pairs:[{trg:"die Zeitung",src:"the newspaper"},{trg:"das Buch",src:"the book"},{trg:"die Lösung",src:"the solution"},{trg:"die Aufgabe",src:"the task"},{trg:"der Film",src:"the film"}]}
]},

{id:"deu_r6l15",title:"Am Telefon",icon:"📱",xp:15,board:true,steps:[
{type:"intro",title:"Am Telefon",desc:"Communication, phone, mail, and technology vocabulary for everyday life.",goals:["Learn 18 words about phones, mail, and technology","Practice using communication vocabulary in context"]},
{type:"teach",trg:"der Absender",src:"the sender",note:"Masculine noun. Plural: die Absender. From ab (away) + senden (to send).",example:"A: Wer ist der Absender?\nB: Der Absender ist mein Bruder.",exampleSrc:"A: Who is the sender?\nB: The sender is my brother.",funFact:"On German letters, the Absender goes in the top left corner, not on the back of the envelope."},
{type:"teach",trg:"der Anrufbeantworter",src:"the answering machine",note:"Masculine noun. Plural: die Anrufbeantworter. Compound: Anruf (call) + Beantworter (answerer).",example:"A: Hast du meine Nachricht gehört?\nB: Nein, mein Anrufbeantworter war voll.",exampleSrc:"A: Did you hear my message?\nB: No, my answering machine was full.",funFact:"At 19 letters, Anrufbeantworter is a classic example of German compound words. Most people just say AB."},
{type:"teach",trg:"die Briefmarke",src:"the postage stamp",note:"Feminine noun. Plural: die Briefmarken. Compound: Brief (letter) + Marke (mark/stamp).",example:"A: Ich brauche eine Briefmarke.\nB: Briefmarken gibt es an der Post.",exampleSrc:"A: I need a postage stamp.\nB: You can get stamps at the post office.",funFact:"Collecting Briefmarken (philately) is a beloved hobby in Germany. The first German stamp was the Schwarzer Einser from 1849."},
{type:"teach",trg:"der Empfänger",src:"the recipient",note:"Masculine noun. Plural: die Empfänger. From empfangen (to receive).",example:"A: Wer ist der Empfänger?\nB: Der Empfänger ist Frau Müller.",exampleSrc:"A: Who is the recipient?\nB: The recipient is Mrs. Müller.",funFact:"On a German envelope, der Empfänger goes in the center. The address format is: name, street + number, postal code + city."},
{type:"teach",trg:"das Fax",src:"the fax",note:"Neuter noun. Plural: die Faxe. Short for Faksimile.",example:"A: Können Sie mir ein Fax schicken?\nB: Ja, ich schicke das Fax sofort.",exampleSrc:"A: Can you send me a fax?\nB: Yes, I will send the fax right away.",funFact:"Germany still uses fax machines more than most countries. Many offices and government agencies prefer fax over email."},
{type:"teach",trg:"die Postleitzahl",src:"the postal code",note:"Feminine noun. Plural: die Postleitzahlen. Abbreviated PLZ.",example:"A: Was ist die Postleitzahl?\nB: Die Postleitzahl ist 10115.",exampleSrc:"A: What is the postal code?\nB: The postal code is 10115.",funFact:"German postal codes have 5 digits. Berlin codes start with 10, Munich with 80, Hamburg with 20."},
{type:"teach",trg:"die Vorwahl",src:"the area code",note:"Feminine noun. Plural: die Vorwahlen. Compound: vor (before) + Wahl (dialing).",example:"A: Was ist die Vorwahl von Berlin?\nB: Die Vorwahl ist 030.",exampleSrc:"A: What is the area code for Berlin?\nB: The area code is 030.",funFact:"Germany's country code is +49. When calling from abroad, you drop the leading 0 from the Vorwahl."},
{type:"teach",trg:"das Wiederhören",src:"the hearing again",note:"Neuter noun. Used in Auf Wiederhören (goodbye on the phone).",example:"A: Dann bis morgen. Auf Wiederhören!\nB: Auf Wiederhören!",exampleSrc:"A: Then until tomorrow. Goodbye!\nB: Goodbye!",funFact:"Auf Wiederhören is for phone calls (hearing again). Auf Wiedersehen is for in-person goodbyes (seeing again)."},
{type:"teach",trg:"die CD",src:"the CD",note:"Feminine noun. Plural: die CDs. Pronounced tsee-dee.",example:"A: Hast du noch CDs?\nB: Ja, ich habe viele alte CDs.",exampleSrc:"A: Do you still have CDs?\nB: Yes, I have many old CDs.",funFact:"Germans pronounce CD as tsee-dee, not see-dee. The letters follow German pronunciation rules."},
{type:"teach",trg:"der Drucker",src:"the printer",note:"Masculine noun. Plural: die Drucker. From drucken (to print).",example:"A: Funktioniert der Drucker?\nB: Nein, der Drucker ist kaputt.",exampleSrc:"A: Does the printer work?\nB: No, the printer is broken.",funFact:"Drucker also means printer as a profession. Johannes Gutenberg was the most famous Drucker in history."},
{type:"teach",trg:"das Internet",src:"the internet",note:"Neuter noun. No plural. Always with article: das Internet.",example:"A: Hast du Internet zu Hause?\nB: Ja, aber es ist langsam.",exampleSrc:"A: Do you have internet at home?\nB: Yes, but it is slow.",funFact:"Germany is often teased for slow Internet. The country has been working to expand fiber optic networks."},
{type:"teach",trg:"das Lieblingslied",src:"the favorite song",note:"Neuter noun. Plural: die Lieblingslieder. Compound: Liebling (favorite) + Lied (song).",example:"A: Was ist dein Lieblingslied?\nB: Mein Lieblingslied ist von den Beatles.",exampleSrc:"A: What is your favorite song?\nB: My favorite song is by the Beatles.",funFact:"Lieblings- is a productive prefix. You can make Lieblingsfilm, Lieblingsbuch, Lieblingsessen for any favorite thing."},
{type:"teach",trg:"das Lied",src:"the song",note:"Neuter noun. Plural: die Lieder.",example:"A: Kennst du dieses Lied?\nB: Ja, das ist ein altes Volkslied.",exampleSrc:"A: Do you know this song?\nB: Yes, that is an old folk song.",funFact:"Volkslied means folk song. Germany has a rich tradition of Volkslieder, many dating back centuries."},
{type:"teach",trg:"das Gespräch",src:"the conversation",note:"Neuter noun. Plural: die Gespräche. From sprechen (to speak).",example:"A: Wie war das Gespräch?\nB: Das Gespräch war sehr nett.",exampleSrc:"A: How was the conversation?\nB: The conversation was very nice.",funFact:"Vorstellungsgespräch means job interview, literally an introduction conversation."},
{type:"teach",trg:"automatisch",src:"automatic",note:"Adjective. Same root as English automatic, from Greek automatos.",example:"A: Ist die Tür automatisch?\nB: Ja, die Tür öffnet sich automatisch.",exampleSrc:"A: Is the door automatic?\nB: Yes, the door opens automatically.",funFact:"German adds -isch to many international words: automatisch, romantisch, fantastisch."},
{type:"teach",trg:"drucken",src:"to print",note:"Regular verb. Ich drucke, du druckst, er/sie druckt. Do not confuse with drücken (to press).",example:"A: Kannst du das drucken?\nB: Ja, ich drucke es sofort.",exampleSrc:"A: Can you print that?\nB: Yes, I will print it right away.",funFact:"Drucken and drücken look alike but differ: drucken = to print, drücken = to press or push."},
{type:"teach",trg:"drücken",src:"to press/push",note:"Regular verb. Ich drücke, du drückst, er/sie drückt. The umlaut distinguishes it from drucken.",example:"A: Welchen Knopf soll ich drücken?\nB: Drück den grünen Knopf.",exampleSrc:"A: Which button should I press?\nB: Press the green button.",funFact:"Ich drücke dir die Daumen means I press my thumbs for you, the German way of saying I am keeping my fingers crossed."},
{type:"teach",trg:"benutzen",src:"to use",note:"Regular verb. Ich benutze, du benutzt, er/sie benutzt. Synonym: verwenden.",example:"A: Kann ich dein Telefon benutzen?\nB: Ja, du kannst es benutzen.",exampleSrc:"A: Can I use your phone?\nB: Yes, you can use it.",funFact:"Benutzen and verwenden both mean to use. Benutzen is more casual, verwenden more formal."},
{type:"mc",q:"What is the German phrase for 'goodbye' on the phone?",opts:["Auf Wiederhören","Auf Wiedersehen","Tschüss","Bis bald"],ans:"Auf Wiederhören",hint:"This phrase uses the word for hearing, not seeing."},
{type:"fb",s:"Kannst du das bitte {1}? Ich brauche eine Kopie.",a:"drucken",opts:["drucken","drücken","benutzen","schicken"],hint:"This verb means making a paper copy with a machine.",sSrc:"Can you please {1} that? I need a copy."},
{type:"mc",q:"What does 'der Empfänger' mean?",opts:["the recipient","the sender","the stamp","the area code"],ans:"the recipient",hint:"This person is on the other end of mail delivery."},
{type:"match",pairs:[{trg:"der Absender",src:"the sender"},{trg:"die Briefmarke",src:"the stamp"},{trg:"das Gespräch",src:"the conversation"},{trg:"der Drucker",src:"the printer"},{trg:"das Lied",src:"the song"}]}
]},

{id:"deu_r6l16",title:"Was machst du so?",icon:"🎬",xp:15,board:true,steps:[
{type:"intro",title:"Was machst du so?",desc:"Daily activities, hobbies, and action verbs for everyday German life.",goals:["Learn 18 essential activity and hobby verbs","Practice separable prefix verbs","Use verbs in everyday conversation"]},
{type:"teach",trg:"anmelden",src:"to register / sign up",note:"Separable: Ich melde mich an. Reflexive with sich.",example:"A: Hast du dich schon angemeldet?\nB: Nein, ich melde mich morgen an.",exampleSrc:"A: Have you already registered?\nB: No, I'll register tomorrow.",funFact:"Germans register for everything: gym, courses, even moving to a new city (Anmeldung)."},
{type:"teach",trg:"ausfüllen",src:"to fill out",note:"Separable: Ich fülle das Formular aus.",example:"A: Kannst du das Formular ausfüllen?\nB: Ja, ich fülle es jetzt aus.",exampleSrc:"A: Can you fill out the form?\nB: Yes, I'll fill it out now.",funFact:"German bureaucracy loves forms. You will ausfüllen many Formulare in your life in Germany."},
{type:"teach",trg:"erlauben",src:"to allow / permit",note:"Not separable. Erlauben Sie? is a polite way to ask permission.",example:"A: Ist Rauchen hier erlaubt?\nB: Nein, das ist nicht erlaubt.",exampleSrc:"A: Is smoking allowed here?\nB: No, that is not allowed.",funFact:"Erlaubnis (permission) comes from erlauben. German laws love the word 'nicht erlaubt'."},
{type:"teach",trg:"erzählen",src:"to tell / narrate",note:"Not separable. Erzähl mir! means Tell me!",example:"A: Erzähl mir von deinem Urlaub!\nB: Es war wunderbar. Ich erzähle dir alles.",exampleSrc:"A: Tell me about your vacation!\nB: It was wonderful. I'll tell you everything.",funFact:"Eine Erzählung is a narrative or story. Germany has a rich tradition of Erzählkunst (narrative art)."},
{type:"teach",trg:"vorstellen",src:"to introduce / imagine",note:"Separable: Ich stelle mich vor (introduce). Ich stelle mir vor (imagine).",example:"A: Kannst du dich bitte vorstellen?\nB: Ja, ich heiße Anna und komme aus Berlin.",exampleSrc:"A: Can you please introduce yourself?\nB: Yes, my name is Anna and I'm from Berlin.",funFact:"Vorstellung means both introduction AND imagination. Also a theater performance!"},
{type:"teach",trg:"abgeben",src:"to hand in / submit",note:"Separable: Ich gebe die Arbeit ab.",example:"A: Wann gibst du die Hausaufgabe ab?\nB: Ich gebe sie morgen ab.",exampleSrc:"A: When do you hand in the homework?\nB: I'll hand it in tomorrow.",funFact:"At German universities, you abgeben your thesis at a specific office with a timestamp."},
{type:"teach",trg:"anklicken",src:"to click on",note:"Separable: Klick den Link an! Used for computer/phone actions.",example:"A: Was soll ich machen?\nB: Klick einfach den Button an.",exampleSrc:"A: What should I do?\nB: Just click on the button.",funFact:"German tech vocabulary mixes English loans with German prefixes: anklicken, downloaden, uploaden."},
{type:"teach",trg:"ankreuzen",src:"to check / mark with X",note:"Separable: Kreuz die richtige Antwort an.",example:"A: Was muss ich hier machen?\nB: Kreuz bitte die richtige Antwort an.",exampleSrc:"A: What do I have to do here?\nB: Please check the correct answer.",funFact:"In Germany, you mark answers with an X (Kreuz), not a checkmark. The opposite of many countries!"},
{type:"teach",trg:"fehlen",src:"to be missing / absent",note:"Works like gefallen: the missing thing is the subject. Du fehlst mir = I miss you.",example:"A: Wer fehlt heute?\nB: Lisa fehlt. Sie ist krank.",exampleSrc:"A: Who is absent today?\nB: Lisa is absent. She is sick.",funFact:"Du fehlst mir literally means 'You are missing to me.' German expresses missing someone from the other direction."},
{type:"teach",trg:"fernsehen",src:"to watch TV",note:"Separable: Ich sehe fern. Das Fernsehen = television (noun).",example:"A: Was machst du heute Abend?\nB: Ich sehe ein bisschen fern.",exampleSrc:"A: What are you doing tonight?\nB: I'm watching a bit of TV.",funFact:"Fernsehen literally means 'far-seeing.' Germans watch about 3.5 hours of TV per day on average."},
{type:"teach",trg:"gewinnen",src:"to win",note:"Irregular past: gewann, hat gewonnen.",example:"A: Wer hat das Spiel gewonnen?\nB: Deutschland hat drei zu eins gewonnen!",exampleSrc:"A: Who won the game?\nB: Germany won three to one!",funFact:"Der Gewinner (winner) and der Gewinn (prize/profit) both come from gewinnen."},
{type:"teach",trg:"glauben",src:"to believe",note:"Regular verb. Ich glaube (nicht) = I (don't) think so.",example:"A: Kommt er heute?\nB: Ich glaube nicht. Er ist krank.",exampleSrc:"A: Is he coming today?\nB: I don't think so. He is sick.",funFact:"Ich glaube schon (I think so) and Ich glaube nicht (I don't think so) are among the most common German phrases."},
{type:"teach",trg:"kümmern",src:"to care / take care of",note:"Reflexive: sich kümmern um + accusative. Ich kümmere mich darum.",example:"A: Wer kümmert sich um die Kinder?\nB: Ich kümmere mich heute um sie.",exampleSrc:"A: Who takes care of the children?\nB: I'll take care of them today.",funFact:"Kummer means grief or sorrow. Sich kümmern originally meant to worry about something, now it means to take care of it."},
{type:"teach",trg:"lachen",src:"to laugh",note:"Regular verb. Lach nicht! = Don't laugh!",example:"A: Warum lachst du?\nB: Der Film ist so lustig!",exampleSrc:"A: Why are you laughing?\nB: The movie is so funny!",funFact:"Das Lachen is contagious in any language. Germans even have Lachyoga (laughter yoga) classes."},
{type:"teach",trg:"leben",src:"to live",note:"Regular verb. Means to be alive / to reside. Das Leben = life.",example:"A: Wo lebst du?\nB: Ich lebe in Hamburg.",exampleSrc:"A: Where do you live?\nB: I live in Hamburg.",funFact:"Leben and wohnen both mean 'to live,' but leben is broader (to be alive, to exist) while wohnen is specifically about where you reside."},
{type:"teach",trg:"mitmachen",src:"to participate / join in",note:"Separable: Machst du mit? = Will you join in?",example:"A: Wir spielen Fußball. Machst du mit?\nB: Ja, ich mache gerne mit!",exampleSrc:"A: We're playing football. Will you join in?\nB: Yes, I'd love to join in!",funFact:"Mitmachen is the friendliest invitation word in German. Machst du mit? is how most activities start."},
{type:"teach",trg:"treffen",src:"to meet",note:"Irregular: du triffst, er trifft. Sich treffen = to meet up (reflexive).",example:"A: Wann treffen wir uns?\nB: Lass uns um drei Uhr treffen.",exampleSrc:"A: When are we meeting?\nB: Let's meet at three o'clock.",funFact:"Treffen also means to hit a target. Ein Treffer is a hit or a goal in football."},
{type:"teach",trg:"tun",src:"to do",note:"Irregular: ich tue, du tust, er tut. Very common in spoken German.",example:"A: Was tust du gerade?\nB: Ich tue nichts. Ich bin müde.",exampleSrc:"A: What are you doing right now?\nB: I'm doing nothing. I'm tired.",funFact:"Tun is slightly more informal than machen. Was tun? (What to do?) is a classic German phrase of indecision."},
{type:"mc",q:"Which verb means 'to register or sign up'?",opts:["anmelden","ausfüllen","abgeben","ankreuzen"],ans:"anmelden",hint:"Think of putting your name on a list."},
{type:"fb",s:"Ich {1} heute Abend ein bisschen fern.",a:"sehe",opts:["sehe","mache","gebe","fülle"],hint:"This separable verb is about watching from far away.",sSrc:"I watch a bit of TV tonight {1}."},
{type:"mc",q:"'Du fehlst mir' means...",opts:["I miss you","You are wrong","You are late","I need you"],ans:"I miss you",hint:"The subject is the person who is absent, not the speaker."},
{type:"fb",s:"Wir {1} uns morgen um zehn Uhr.",a:"treffen",opts:["treffen","machen","leben","glauben"],hint:"This irregular verb means to meet up with someone.",sSrc:"We {1} tomorrow at ten o'clock."}
]},

{id:"deu_r6l17",title:"Zeit und Feste",icon:"🎊",xp:15,board:true,steps:[
{type:"intro",title:"Zeit und Feste",desc:"Time expressions, holidays, and celebrations in German culture.",goals:["Learn 20 words for time, holidays, and celebrations","Practice using time-related nouns with articles","Talk about events and special occasions"]},
{type:"teach",trg:"das Ende",src:"the end",note:"Neuter noun. Plural: die Enden. Am Ende = in the end.",example:"A: Wann ist das Ende vom Film?\nB: Um zehn Uhr. Es dauert noch eine Stunde.",exampleSrc:"A: When is the end of the movie?\nB: At ten o'clock. It lasts another hour.",funFact:"Ende gut, alles gut (all's well that ends well) is a beloved German proverb borrowed from Shakespeare."},
{type:"teach",trg:"das Jahr",src:"the year",note:"Neuter noun. Plural: die Jahre. Dieses Jahr = this year.",example:"A: Wie viele Jahre lebst du schon in Berlin?\nB: Ich lebe seit drei Jahren hier.",exampleSrc:"A: How many years have you lived in Berlin?\nB: I've lived here for three years.",funFact:"Jahrgang means both a year's vintage of wine and the year someone was born. Germans ask Welcher Jahrgang bist du?"},
{type:"teach",trg:"der Moment",src:"the moment",note:"Masculine noun. Plural: die Momente. Einen Moment bitte! = One moment please!",example:"A: Hast du kurz Zeit?\nB: Einen Moment bitte, ich bin gleich fertig.",exampleSrc:"A: Do you have a moment?\nB: One moment please, I'll be done shortly.",funFact:"Im Moment means 'at the moment.' Germans also say Momentmal! as a quick 'hold on!'"},
{type:"teach",trg:"die Zeit",src:"the time",note:"Feminine noun. Plural: die Zeiten. Es ist Zeit = It is time.",example:"A: Hast du Zeit am Samstag?\nB: Ja, ich habe den ganzen Tag Zeit.",exampleSrc:"A: Do you have time on Saturday?\nB: Yes, I have time all day.",funFact:"Zeit ist Geld (time is money) is used as often in German as in English. Germans take punctuality very seriously."},
{type:"teach",trg:"der Sonnabend",src:"Saturday (northern German)",note:"Masculine noun. Used in northern and eastern Germany instead of Samstag.",example:"A: Arbeitest du am Sonnabend?\nB: Nein, am Sonnabend habe ich frei.",exampleSrc:"A: Do you work on Saturday?\nB: No, I have Saturday off.",funFact:"Northern Germans say Sonnabend (sun evening), southern Germans say Samstag (from Sabbath). Both are correct!"},
{type:"teach",trg:"der Wochentag",src:"the weekday",note:"Masculine noun. Plural: die Wochentage. Compound: Woche + Tag.",example:"A: An welchem Wochentag hast du frei?\nB: Am Mittwoch habe ich immer frei.",exampleSrc:"A: On which weekday do you have off?\nB: I always have Wednesdays off.",funFact:"German weekdays are named after Norse gods and celestial bodies: Montag (moon), Dienstag (Tyr), Mittwoch (midweek)."},
{type:"teach",trg:"der Feierabend",src:"the end of the work day",note:"Masculine noun. Feierabend machen = to call it a day.",example:"A: Wann machst du Feierabend?\nB: Um fünf Uhr. Dann gehe ich nach Hause.",exampleSrc:"A: When do you finish work?\nB: At five o'clock. Then I go home.",funFact:"Feierabend literally means 'celebration evening.' Germans take their after-work time very seriously. It is sacred rest time."},
{type:"teach",trg:"der Feiertag",src:"the public holiday",note:"Masculine noun. Plural: die Feiertage. Germany has many regional holidays.",example:"A: Ist morgen ein Feiertag?\nB: Ja, morgen ist alles geschlossen.",exampleSrc:"A: Is tomorrow a public holiday?\nB: Yes, everything is closed tomorrow.",funFact:"Germany has between 9 and 13 public holidays depending on the state. Bavaria has the most!"},
{type:"teach",trg:"die Pause",src:"the break / pause",note:"Feminine noun. Plural: die Pausen. Eine Pause machen = to take a break.",example:"A: Ich bin so müde.\nB: Mach doch eine Pause!",exampleSrc:"A: I'm so tired.\nB: Take a break!",funFact:"German schools have die große Pause (big break, 15-20 min) where kids play outside, rain or shine."},
{type:"teach",trg:"das Glück",src:"luck / happiness",note:"Neuter noun. No plural in this meaning. Viel Glück! = Good luck!",example:"A: Morgen habe ich meine Prüfung.\nB: Viel Glück! Du schaffst das!",exampleSrc:"A: Tomorrow I have my exam.\nB: Good luck! You can do it!",funFact:"Glück means both luck AND happiness in German. A Glückspilz (lucky mushroom) is a lucky person."},
{type:"teach",trg:"der Glückwunsch",src:"the congratulations",note:"Masculine noun. Plural: die Glückwünsche. Herzlichen Glückwunsch! = Congratulations!",example:"A: Ich habe die Prüfung bestanden!\nB: Herzlichen Glückwunsch!",exampleSrc:"A: I passed the exam!\nB: Congratulations!",funFact:"Herzlichen Glückwunsch zum Geburtstag is the full way to say Happy Birthday. Literally: heartfelt luck-wish for the birthday."},
{type:"teach",trg:"die Hochzeit",src:"the wedding",note:"Feminine noun. Plural: die Hochzeiten. Literally: high time.",example:"A: Wann ist die Hochzeit?\nB: Im Juni. Die Feier ist im Garten.",exampleSrc:"A: When is the wedding?\nB: In June. The celebration is in the garden.",funFact:"Hochzeit literally means 'high time' or 'best time.' A Hochzeitstorte (wedding cake) is often multi-layered."},
{type:"teach",trg:"der Verein",src:"the club / association",note:"Masculine noun. Plural: die Vereine. Central to German social life.",example:"A: Bist du in einem Verein?\nB: Ja, ich bin im Sportverein.",exampleSrc:"A: Are you in a club?\nB: Yes, I'm in the sports club.",funFact:"Germany has over 600,000 Vereine. There is a saying: Drei Deutsche, ein Verein (three Germans, one club)."},
{type:"teach",trg:"die Gruppe",src:"the group",note:"Feminine noun. Plural: die Gruppen. Gruppenarbeit = group work.",example:"A: Wie groß ist deine Gruppe?\nB: Wir sind fünf Personen in der Gruppe.",exampleSrc:"A: How big is your group?\nB: We are five people in the group.",funFact:"Gruppenarbeit (group work) is extremely common in German schools and universities. Teamwork is highly valued."},
{type:"teach",trg:"das Frühjahr",src:"spring (formal)",note:"Neuter noun. More formal than Frühling. Früh = early + Jahr = year.",example:"A: Wann blühen die Blumen?\nB: Im Frühjahr, meistens im April.",exampleSrc:"A: When do the flowers bloom?\nB: In spring, mostly in April.",funFact:"Frühjahr is used more in writing and news. Frühling is the everyday word. Both mean the early part of the year."},
{type:"teach",trg:"der Wind",src:"the wind",note:"Masculine noun. Plural: die Winde. Es ist windig = It is windy.",example:"A: Warum ist es so kalt?\nB: Der Wind ist heute sehr stark.",exampleSrc:"A: Why is it so cold?\nB: The wind is very strong today.",funFact:"Germany's North Sea coast is famous for strong winds. Windenergie (wind energy) provides over 25% of Germany's electricity."},
{type:"teach",trg:"beginnen",src:"to begin",note:"Irregular past: begann, hat begonnen. Formal alternative to anfangen.",example:"A: Wann beginnt der Kurs?\nB: Er beginnt um neun Uhr.",exampleSrc:"A: When does the course begin?\nB: It begins at nine o'clock.",funFact:"Beginnen is slightly more formal than anfangen. In writing, beginnen is preferred. In speech, both work."},
{type:"teach",trg:"enden",src:"to end",note:"Regular verb. Das Ende = the end (noun). Enden can also mean to finish.",example:"A: Wann endet das Konzert?\nB: Es endet um elf Uhr.",exampleSrc:"A: When does the concert end?\nB: It ends at eleven o'clock.",funFact:"Endlich! means 'finally!' in German. It comes from Ende and expresses relief that something is over."},
{type:"teach",trg:"gratulieren",src:"to congratulate",note:"Regular verb. Ich gratuliere dir! = I congratulate you!",example:"A: Ich habe einen neuen Job!\nB: Toll! Ich gratuliere dir!",exampleSrc:"A: I got a new job!\nB: Great! I congratulate you!",funFact:"Germans gratulieren for birthdays, exams, weddings, and new jobs. It is always followed by the dative (dir, Ihnen)."},
{type:"teach",trg:"heiraten",src:"to marry",note:"Regular verb. Die Heirat = marriage (noun). Wir heiraten! = We're getting married!",example:"A: Wann heiratet ihr?\nB: Wir heiraten im September.",exampleSrc:"A: When are you getting married?\nB: We're getting married in September.",funFact:"In Germany, you must have a civil ceremony at the Standesamt (registry office). A church wedding alone is not legally binding."},
{type:"mc",q:"What does 'der Feierabend' mean?",opts:["the public holiday","the end of the work day","the celebration","the weekend"],ans:"the end of the work day",hint:"After finishing your professional obligations, this is the moment of freedom."},
{type:"fb",s:"Herzlichen {1} zum Geburtstag!",a:"Glückwunsch",opts:["Glückwunsch","Glück","Hochzeit","Feiertag"],hint:"This compound noun combines luck and wish.",sSrc:"Happy {1} for your birthday!"},
{type:"mc",q:"Which word is the formal way to say 'spring'?",opts:["das Frühjahr","der Frühling","die Frühzeit","der Frühstart"],ans:"das Frühjahr",hint:"This compound combines 'early' with 'year.'"},
{type:"fb",s:"Wann {1} der Kurs? Um neun Uhr.",a:"beginnt",opts:["beginnt","endet","macht","geht"],hint:"This is the formal verb for starting something.",sSrc:"When does the course {1}? At nine o'clock."}
]},

{id:"deu_r6l18",title:"Noch mehr Verben",icon:"💪",xp:15,board:true,steps:[
{type:"intro",title:"Noch mehr Verben",desc:"Essential remaining verbs, adjectives, and time expressions to round out your A1 vocabulary.",goals:["Learn 18 remaining essential words","Master time adverbs and adjectives","Use common verb phrases in context"]},
{type:"teach",trg:"wehtun",src:"to hurt / ache",note:"Separable: Es tut weh = It hurts. Mir tut der Kopf weh = My head hurts.",example:"A: Was ist los?\nB: Mein Bauch tut weh. Ich brauche eine Pause.",exampleSrc:"A: What's wrong?\nB: My stomach hurts. I need a break.",funFact:"Germans point to the body part and say Es tut weh. Weh is an old word for pain, related to English 'woe.'"},
{type:"teach",trg:"warten",src:"to wait",note:"Regular verb. Warten auf + accusative = to wait for.",example:"A: Worauf wartest du?\nB: Ich warte auf den Bus. Er kommt in fünf Minuten.",exampleSrc:"A: What are you waiting for?\nB: I'm waiting for the bus. It comes in five minutes.",funFact:"Warten auf has a fixed preposition (auf). Der Warteraum (waiting room) is found in every German doctor's office."},
{type:"teach",trg:"Rad fahren",src:"to ride a bicycle",note:"Written separately in infinitive. Ich fahre Rad. Das Fahrrad = bicycle.",example:"A: Wie kommst du zur Arbeit?\nB: Ich fahre jeden Tag Rad.",exampleSrc:"A: How do you get to work?\nB: I ride my bicycle every day.",funFact:"Germany has over 75,000 km of bike paths. Rad fahren is the main transport for many Germans, especially in cities like Munster."},
{type:"teach",trg:"aus sein",src:"to be off / finished",note:"Phrase with sein. Das Licht ist aus = The light is off. Die Schule ist aus = School is over.",example:"A: Ist die Schule schon aus?\nB: Ja, seit einer Stunde.",exampleSrc:"A: Is school already over?\nB: Yes, since an hour ago.",funFact:"Aus sein is incredibly versatile. Es ist aus (it's over) can refer to lights, relationships, school, or events."},
{type:"teach",trg:"weg sein",src:"to be gone / away",note:"Phrase with sein. Er ist weg = He is gone. Weg! = Go away!",example:"A: Wo ist mein Handy?\nB: Es ist weg! Hast du es verloren?",exampleSrc:"A: Where is my phone?\nB: It's gone! Did you lose it?",funFact:"Weg as a noun means path (der Weg). As a particle it means away/gone. Two completely different meanings!"},
{type:"teach",trg:"zu sein",src:"to be closed",note:"Phrase with sein. Der Laden ist zu = The shop is closed. Opposite: auf sein.",example:"A: Gehen wir zum Supermarkt?\nB: Er ist schon zu. Es ist nach acht.",exampleSrc:"A: Shall we go to the supermarket?\nB: It's already closed. It's past eight.",funFact:"German shops close earlier than in many countries. Zu sein after 8 PM is normal. On Sundays, almost everything ist zu."},
{type:"teach",trg:"wiederholen",src:"to repeat / review",note:"Not separable in this meaning. Können Sie das bitte wiederholen? = Can you repeat that?",example:"A: Ich habe das nicht verstanden.\nB: Kein Problem, ich wiederhole es gerne.",exampleSrc:"A: I didn't understand that.\nB: No problem, I'll gladly repeat it.",funFact:"Wiederholen literally means to fetch again (wieder + holen). In language class, you will hear Bitte wiederholen! constantly."},
{type:"teach",trg:"das Leben",src:"the life",note:"Neuter noun. No plural in this meaning. Das ist das Leben! = That's life!",example:"A: Wie ist das Leben in Deutschland?\nB: Es ist gut, aber manchmal stressig.",exampleSrc:"A: How is life in Germany?\nB: It's good, but sometimes stressful.",funFact:"Lebensqualität (quality of life) is something Germans take very seriously. German cities regularly rank in top global livability lists."},
{type:"teach",trg:"der Plan",src:"the plan",note:"Masculine noun. Plural: die Pläne. Note the umlaut in plural!",example:"A: Was sind deine Pläne für das Wochenende?\nB: Ich habe noch keine Pläne.",exampleSrc:"A: What are your plans for the weekend?\nB: I don't have any plans yet.",funFact:"Germans love planning. Der Fahrplan (schedule), der Stadtplan (city map), der Lehrplan (curriculum) all have Plan in them."},
{type:"teach",trg:"der Fußball",src:"football / soccer",note:"Masculine noun. Literally: foot + ball. Die Bundesliga is the top league.",example:"A: Spielst du gerne Fußball?\nB: Ja, jeden Samstag im Verein!",exampleSrc:"A: Do you like playing football?\nB: Yes, every Saturday at the club!",funFact:"Fußball is practically a religion in Germany. The Bundesliga is one of the most-watched leagues in the world."},
{type:"teach",trg:"glücklich",src:"happy",note:"Adjective. Opposite: unglücklich (unhappy). From Glück (luck/happiness).",example:"A: Bist du glücklich hier?\nB: Ja, ich bin sehr glücklich in dieser Stadt.",exampleSrc:"A: Are you happy here?\nB: Yes, I am very happy in this city.",funFact:"Glücklich combines luck and happiness. Germans might say Ich bin glücklich for deep contentment, froh for momentary gladness."},
{type:"teach",trg:"tot",src:"dead",note:"Adjective. Der Tod = death (noun). Totmüde = dead tired (colloquial).",example:"A: Lebt der Fisch noch?\nB: Nein, er ist leider tot.",exampleSrc:"A: Is the fish still alive?\nB: No, it's unfortunately dead.",funFact:"Totmüde (dead tired), totlachen (to die laughing), totschweigen (to kill with silence): German loves tot- as an intensifier."},
{type:"teach",trg:"früher",src:"earlier / in the past",note:"Comparative of früh (early). Also means 'back then, in the old days.'",example:"A: Wie war das Leben früher?\nB: Früher war alles anders.",exampleSrc:"A: How was life in the past?\nB: Everything was different back then.",funFact:"Früher war alles besser (everything was better in the past) is a classic German phrase, usually said with a sigh."},
{type:"teach",trg:"letzt",src:"last (previous)",note:"Adjective. Always with ending: letzte Woche, letztes Jahr, letzten Montag.",example:"A: Wann warst du im Kino?\nB: Letzte Woche. Der Film war toll.",exampleSrc:"A: When were you at the cinema?\nB: Last week. The movie was great.",funFact:"Letzt always needs an adjective ending in German. You cannot say just letzt. It is always letzte/letztes/letzten depending on the noun."},
{type:"teach",trg:"nächst",src:"next",note:"Adjective. Always with ending: nächste Woche, nächstes Jahr, nächsten Montag.",example:"A: Wann fährst du in den Urlaub?\nB: Nächste Woche. Ich freue mich!",exampleSrc:"A: When are you going on vacation?\nB: Next week. I'm looking forward to it!",funFact:"Nächst also means nearest: die nächste Haltestelle (the next/nearest stop). Context tells you which meaning."},
{type:"teach",trg:"später",src:"later",note:"Comparative of spät (late). Bis später! = See you later!",example:"A: Kommst du jetzt?\nB: Nein, ich komme später. Bis später!",exampleSrc:"A: Are you coming now?\nB: No, I'll come later. See you later!",funFact:"Bis später is one of the most common German goodbyes. Spätestens means 'at the latest.'"},
{type:"teach",trg:"heute",src:"today",note:"Adverb. Heute Morgen = this morning. Heute Abend = tonight.",example:"A: Was machst du heute?\nB: Heute gehe ich einkaufen und dann ins Kino.",exampleSrc:"A: What are you doing today?\nB: Today I'm going shopping and then to the cinema.",funFact:"Heutzutage means 'nowadays.' Heute is related to English 'today' through the Germanic root for 'this day.'"},
{type:"teach",trg:"bis",src:"until / by",note:"Preposition. Bis morgen! = See you tomorrow! Bis wann? = Until when?",example:"A: Bis wann bist du im Büro?\nB: Bis fünf Uhr. Dann mache ich Feierabend.",exampleSrc:"A: Until when are you at the office?\nB: Until five o'clock. Then I finish work.",funFact:"Bis is one of the most useful small words. Bis bald (see you soon), bis gleich (see you in a moment), bis dann (see you then)."},
{type:"mc",q:"What does 'wehtun' mean?",opts:["to hurt / ache","to wait","to repeat","to be gone"],ans:"to hurt / ache",hint:"Think of something causing pain in your body."},
{type:"fb",s:"Ich {1} auf den Bus. Er kommt bald.",a:"warte",opts:["warte","fahre","bin","mache"],hint:"This regular verb takes the preposition 'auf' for what you expect.",sSrc:"I {1} for the bus. It is coming soon."},
{type:"mc",q:"'Bis später' means...",opts:["See you later","Good morning","Goodbye forever","Until tomorrow"],ans:"See you later",hint:"Bis means until. Später means at a following time."},
{type:"fb",s:"Letzte {1} war ich im Kino.",a:"Woche",opts:["Woche","Tag","Jahr","Monat"],hint:"Seven days make up this time period.",sSrc:"Last {1} I was at the cinema."}
]}

]}
,

// ═══════════════════════════════════════════════════════════════
// UNIT 7: Der Arztbesuch
// Story: First German cold. Apotheke, 4-minute Hausarzt, Beipackzettel comedy
// CEFR: A2.1 - Perfekt haben, dative full, Präteritum modals, verbs+dative
// ═══════════════════════════════════════════════════════════════
{n:7,lang:"de",srcLang:"en",track:"v2",title:"Der Arztbesuch",sub:"First cold, pharmacy visit, four-minute doctor, Beipackzettel",icon:"🤧",level:"A2.1",color:"#7B5EE8",lessons:[
{id:"deu_r7l1",title:"Die Apotheke",icon:"🤧",xp:15,board:true,steps:[
{type:"intro",title:"Die Apotheke",desc:"Verumius wacht krank auf. Kopfschmerzen, Husten, Schnupfen. Er braucht Hilfe, aber wohin? Zeit, die deutsche Apotheke zu entdecken.",goals:["Lerne 8 wichtige Wörter rund um Gesundheit und Krankheit","Verstehe den Unterschied zwischen Apotheke, Arzt und Krankenhaus","Begleite Verumius bei seinem ersten Apothekenbesuch in Berlin"]},
{type:"story",speaker:"narrator",mood:"miserable",art:"berlin_apartment_rain",trg:"Es ist Montagmorgen in Berlin. Der Regen trommelt gegen das Fenster. Verumius liegt im Bett. Sein Kopf tut weh, seine Nase läuft, und er hustet seit zwei Stunden. Er greift nach seinem Handy und tippt: 'Apotheke in der Nähe'. Ein rotes A leuchtet auf der Karte. Fünfhundert Meter. Er zieht seine Jacke an und geht raus in den Regen.",src:"It's Monday morning in Berlin. The rain drums against the window. Verumius is lying in bed. His head hurts, his nose is running, and he's been coughing for two hours. He reaches for his phone and types: 'Pharmacy nearby'. A red A lights up on the map. Five hundred meters. He puts on his jacket and goes out into the rain."},
{type:"teach",trg:"die Apotheke",src:"the pharmacy",note:"Feminine noun. Look for the red A sign on German streets.\nNot a drugstore: only medicines, no groceries.",example:"A: Entschuldigung, wo ist die nächste Apotheke?\nB: Gleich um die Ecke, neben dem Supermarkt.\nA: Ist sie jetzt geöffnet?\nB: Ja, bis achtzehn Uhr.",exampleSrc:"A: Excuse me, where is the nearest pharmacy?\nB: Right around the corner, next to the supermarket.\nA: Is it open now?\nB: Yes, until six o'clock.",funFact:"The word Apotheke comes from ancient Greek 'apotheke' (storage room). German pharmacies display a red gothic A and are strictly regulated. You cannot buy aspirin at a supermarket in Germany."},
{type:"teach",trg:"die Grippe",src:"the flu, the cold",note:"Feminine noun. Eine Grippe haben = to have the flu.\nErkältung is a milder cold, Grippe is more serious.",example:"A: Du siehst nicht gut aus. Was ist los?\nB: Ich habe eine Grippe. Seit drei Tagen.\nA: Warst du schon beim Arzt?\nB: Nein, ich gehe erst mal in die Apotheke.",exampleSrc:"A: You don't look well. What's wrong?\nB: I have the flu. For three days.\nA: Have you been to the doctor yet?\nB: No, I'll go to the pharmacy first.",funFact:"Germans take Grippe seriously. The Grippewelle (flu wave) is a national news topic every winter. Companies track sick days from flu, and doctors hand out Krankschreibungen (sick notes) generously."},
{type:"teach",trg:"der Schmerz",src:"the pain",note:"Masculine noun. Plural: die Schmerzen.\nCompounds: Kopfschmerzen (headache), Bauchschmerzen (stomachache), Halsschmerzen (sore throat).",example:"A: Wo haben Sie Schmerzen?\nB: Ich habe starke Kopfschmerzen.\nA: Seit wann?\nB: Seit gestern Abend. Und auch Halsschmerzen.",exampleSrc:"A: Where do you have pain?\nB: I have a strong headache.\nA: Since when?\nB: Since yesterday evening. And also a sore throat.",funFact:"German builds body pain words like LEGO: body part + Schmerzen. Kopf (head) + Schmerzen = Kopfschmerzen. Zahn (tooth) + Schmerzen = Zahnschmerzen. Once you know Schmerzen, you can describe pain anywhere."},
{type:"mc",q:"Verumius hat Kopfschmerzen und Husten. Wohin geht er zuerst?",opts:["In die Apotheke","In den Supermarkt","In die Schule","In das Kino"],ans:"In die Apotheke",hint:"Look for the red A on German streets. It's where you buy medicine."},
{type:"teach",trg:"husten",src:"to cough",note:"Regular verb. Ich huste, du hustest, er hustet.\nDer Husten (noun) = the cough.\nHustensaft = cough syrup.",example:"A: Sie husten ja ganz schrecklich!\nB: Ja, ich huste seit zwei Tagen.\nA: Hier, nehmen Sie diesen Hustensaft.\nB: Danke, wie oft muss ich ihn nehmen?",exampleSrc:"A: You're coughing terribly!\nB: Yes, I've been coughing for two days.\nA: Here, take this cough syrup.\nB: Thanks, how often do I need to take it?",funFact:"Hustensaft (cough syrup) is one of Germany's favorite pharmacy purchases. Germans also love Hustenbonbons (cough drops). The brand Ricola, though Swiss, is everywhere in German pharmacies."},
{type:"teach",trg:"die Gesundheit",src:"health",note:"Feminine noun. Also what Germans say when someone sneezes!\nGesund = healthy. Gesundheit = health/healthiness.",example:"A: Hatschiii!\nB: Gesundheit!\nA: Danke. Meine Gesundheit ist gerade nicht so gut.\nB: Gute Besserung! Trink viel Tee.",exampleSrc:"A: Achoo!\nB: Bless you! (lit: Health!)\nA: Thanks. My health isn't so great right now.\nB: Get well soon! Drink lots of tea.",funFact:"Gesundheit! after a sneeze is used worldwide, even in English. It literally means 'health!' as a wish. Germans also say 'Gute Besserung' (good improvement) when someone is sick, similar to 'get well soon'."},
{type:"fb",s:"Meine {1} ist nicht gut. Ich habe Kopfschmerzen und Husten.",a:["Gesundheit"],opts:["Gesundheit","Apotheke","Grippe","Schmerz"],hint:"This word means health. Germans also say it when you sneeze.",sSrc:"My {1} is not good. I have a headache and a cough."},
{type:"story",speaker:"narrator",mood:"anxious",art:"berlin_apotheke_counter",trg:"Verumius steht in der Apotheke. Alles ist weiß und sauber. Hinter dem Tresen steht eine Frau im weißen Kittel. Sie lächelt freundlich. 'Guten Tag, wie kann ich Ihnen helfen?' Verumius öffnet den Mund, aber die Worte kommen langsam. Er ist nervös. Was, wenn sie ihn nicht versteht?",src:"Verumius stands in the pharmacy. Everything is white and clean. Behind the counter stands a woman in a white coat. She smiles warmly. 'Good day, how can I help you?' Verumius opens his mouth, but the words come slowly. He's nervous. What if she doesn't understand him?"},
{type:"teach",trg:"das Krankenhaus",src:"the hospital",note:"Neuter noun. Literally: krank (sick) + Haus (house) = sick house.\nIns Krankenhaus gehen = to go to the hospital.",example:"A: Soll ich ins Krankenhaus gehen?\nB: Nein, das ist nur eine Grippe.\nA: Wann muss man ins Krankenhaus?\nB: Nur bei einem Notfall. Gehen Sie erst zum Arzt.",exampleSrc:"A: Should I go to the hospital?\nB: No, it's just a flu.\nA: When do you have to go to the hospital?\nB: Only in an emergency. Go to the doctor first.",funFact:"Krankenhaus is a beautiful German compound: kranken (sick) + Haus (house). German loves building words this way. A Krankenwagen (sick wagon) is an ambulance. A Krankenschwester (sick sister) is a nurse."},
{type:"teach",trg:"nervös",src:"nervous",note:"Adjective. Same form for all genders.\nIch bin nervös = I am nervous.\nCognate with English 'nervous' and French 'nerveux'.",example:"A: Du siehst nervös aus. Alles okay?\nB: Ja, ich bin nur nervös. Mein Deutsch ist nicht so gut.\nA: Keine Sorge! Ich verstehe Sie sehr gut.\nB: Wirklich? Das freut mich!",exampleSrc:"A: You look nervous. Everything okay?\nB: Yes, I'm just nervous. My German isn't so good.\nA: Don't worry! I understand you very well.\nB: Really? That makes me happy!",funFact:"Nervös is a cognate, almost identical to English 'nervous'. It entered German from French 'nerveux' in the 18th century. When in doubt in German, try the English word with a German accent. It works more often than you think."},
{type:"mc",q:"Wo kaufst du Medizin, wenn du krank bist?",opts:["In der Apotheke","Im Krankenhaus","Im Supermarkt","In der Schule"],ans:"In der Apotheke",hint:"It has a red A sign and a pharmacist in a white coat."},
{type:"teach",trg:"schlimm",src:"bad, severe, serious",note:"Adjective. Schlimmer (worse), am schlimmsten (worst).\nNicht so schlimm = not so bad.\nDas ist schlimm = that's bad/serious.",example:"A: Wie geht es Ihnen? Ist es schlimm?\nB: Nein, nicht so schlimm. Nur Husten und Schnupfen.\nA: Gut. Hier ist ein Tee und Hustensaft.\nB: Danke! Wird es schlimmer ohne Medizin?",exampleSrc:"A: How are you? Is it bad?\nB: No, not so bad. Just cough and a runny nose.\nA: Good. Here is a tea and cough syrup.\nB: Thanks! Does it get worse without medicine?",funFact:"'Nicht so schlimm' (not so bad) is one of the most useful German phrases. Germans use it to downplay almost anything. Spilled coffee? Nicht so schlimm. Missed the bus? Nicht so schlimm. It's the German equivalent of 'no worries'."},
{type:"fb",s:"Verumius ist {1}, weil er zum ersten Mal in einer deutschen Apotheke ist.",a:["nervös"],opts:["nervös","schlimm","krank","husten"],hint:"This feeling comes when you do something for the first time.",sSrc:"Verumius is {1} because it is his first time in a German pharmacy."},
{type:"tip",title:"Apotheke, Arzt oder Krankenhaus?",text:"Germany has a clear system for health care:\n\n1. Die Apotheke (pharmacy): For mild problems. Cough, cold, headache. No appointment needed. The pharmacist gives advice and medicine.\n\n2. Der Arzt (doctor): For anything that lasts more than a few days or feels serious. You need a Termin (appointment) or go to the Notaufnahme (emergency room) of a practice.\n\n3. Das Krankenhaus (hospital): Only for emergencies or when a doctor sends you. Broken bones, surgery, severe illness.\n\nMost Germans go to the Apotheke first. The pharmacist often solves the problem without a doctor visit.",deepDive:"German pharmacists (Apotheker) study for 4 years at university. They are highly trained and can recommend specific medicines. Unlike many countries, you cannot buy painkillers like ibuprofen at a supermarket in Germany. Even aspirin requires a pharmacy visit. This makes the Apotheke the first stop for most health issues."},
{type:"mc",q:"Du hast seit einer Woche starke Kopfschmerzen. Sie werden schlimmer. Wohin gehst du?",opts:["Zum Arzt","In die Apotheke","Ins Krankenhaus","In den Supermarkt"],ans:"Zum Arzt",hint:"A week of worsening pain needs more than pharmacy advice."},
{type:"drag_fill",s:"Ich habe eine {1} und muss {2}. Es ist nicht so {3}.",blanks:{"1":"Grippe","2":"husten","3":"schlimm"},pool:["Grippe","husten","schlimm","Apotheke","nervös","Schmerz"],hint:"I have a flu, I must cough, and it's not so bad.",sSrc:"I have a {1} and must {2}. It is not so {3}."},
{type:"match",pairs:[{trg:"die Apotheke",src:"the pharmacy"},{trg:"die Grippe",src:"the flu"},{trg:"der Schmerz",src:"the pain"},{trg:"husten",src:"to cough"},{trg:"die Gesundheit",src:"health"},{trg:"das Krankenhaus",src:"the hospital"},{trg:"nervös",src:"nervous"},{trg:"schlimm",src:"bad, severe"}]},
{type:"mc",q:"Was passiert in der Geschichte? Verumius wacht auf und ...",opts:["Er ist krank und geht in die Apotheke","Er geht ins Krankenhaus mit dem Krankenwagen","Er bleibt im Bett und schläft den ganzen Tag","Er geht zum Arzt und bekommt eine Spritze"],ans:"Er ist krank und geht in die Apotheke",hint:"Remember the red A on his phone map and the rainy walk."}
]},

{id:"deu_r7l2",title:"Mein Körper tut weh",icon:"🏥",xp:15,board:true,steps:[
{type:"intro",title:"Mein Körper tut weh",desc:"Verumius ist in der Apotheke. Er muss erklären, was ihm wehtut. Lerne Körperteile und Apothekenvokabular.",goals:["Körperteile benennen","Apothekenprodukte kennen","Schmerzen ausdrücken mit 'mir tut ... weh'"]},
{type:"teach",trg:"der Körper",src:"the body",note:"Masculine. Related to English 'corpse' and 'corps'.",example:"A: Geht es Ihnen gut?\nB: Nein, mein ganzer Körper tut weh.\nA: Oh nein. Was haben Sie gemacht?\nB: Ich war gestern im Fitnessstudio.",exampleSrc:"A: Are you alright?\nB: No, my whole body hurts.\nA: Oh no. What did you do?\nB: I was at the gym yesterday.",funFact:"Körper comes from Latin 'corpus'. The same root gives us 'corporation' in English, a 'body' of people working together."},
{type:"teach",trg:"der Hals",src:"the throat / neck",note:"Masculine. Covers both throat and neck in German.",example:"A: Was fehlt Ihnen?\nB: Mir tut der Hals weh.\nA: Seit wann?\nB: Seit zwei Tagen. Ich kann kaum schlucken.",exampleSrc:"A: What's wrong?\nB: My throat hurts.\nA: Since when?\nB: For two days. I can barely swallow.",funFact:"Germans say 'Hals- und Beinbruch!' (break your neck and leg) to wish someone good luck. It comes from a Yiddish expression meaning 'success and blessing'."},
{type:"teach",trg:"der Magen",src:"the stomach",note:"Masculine. Used for the organ, not the belly area (that's 'der Bauch').",example:"A: Möchten Sie etwas essen?\nB: Nein danke, mein Magen tut weh.\nA: Haben Sie etwas Schlechtes gegessen?\nB: Vielleicht. Das Sushi gestern war komisch.",exampleSrc:"A: Would you like to eat something?\nB: No thanks, my stomach hurts.\nA: Did you eat something bad?\nB: Maybe. The sushi yesterday was strange.",funFact:"'Magengrummeln' is the German word for stomach rumbling. Germans love compound nouns for very specific body sounds."},
{type:"mc",q:"Welches Wort bedeutet 'throat'?",opts:["der Magen","der Hals","der Körper","der Schmerz"],ans:"der Hals",hint:"This body part connects your head to your shoulders and helps you swallow."},
{type:"teach",trg:"das Ohr",src:"the ear",note:"Neuter. Plural: die Ohren. One of the few body parts that changes in plural.",example:"A: Mein Ohr tut so weh!\nB: Das linke oder das rechte?\nA: Das linke. Ich höre schlecht.\nB: Gehen Sie zum Arzt. Das klingt nach einer Entzündung.",exampleSrc:"A: My ear hurts so much!\nB: The left one or the right one?\nA: The left one. I can't hear well.\nB: Go to the doctor. That sounds like an infection.",funFact:"'Ohrwurm' (ear worm) is the German word for a catchy song stuck in your head. English borrowed this word directly from German!"},
{type:"teach",trg:"der Rücken",src:"the back",note:"Masculine. Very common complaint. 'Rückenschmerzen' means back pain.",example:"A: Können Sie mir helfen? Mein Rücken tut weh.\nB: Sitzen Sie viel am Schreibtisch?\nA: Ja, den ganzen Tag.\nB: Ich empfehle Ihnen diese Creme.",exampleSrc:"A: Can you help me? My back hurts.\nB: Do you sit at a desk a lot?\nA: Yes, all day long.\nB: I recommend this cream to you.",funFact:"Back pain (Rückenschmerzen) is the number one reason Germans visit a doctor. Germany even has a special 'Rückenschule' (back school) for prevention."},
{type:"teach",trg:"der Zahn",src:"the tooth",note:"Masculine. Plural: die Zähne. Notice the umlaut change in plural!",example:"A: Au! Mein Zahn tut weh!\nB: Welcher Zahn?\nA: Hier hinten. Seit drei Tagen.\nB: Sie brauchen einen Zahnarzt, keine Apotheke.",exampleSrc:"A: Ow! My tooth hurts!\nB: Which tooth?\nA: Back here. For three days.\nB: You need a dentist, not a pharmacy.",funFact:"The German word for dentist is 'Zahnarzt', literally 'tooth doctor'. Germans are famous for their dental care. Children get a 'Zahnfee' (tooth fairy) just like in English."},
{type:"fb",s:"Mir tut der {1} weh. Ich kann kaum schlucken.",a:["Hals"],opts:["Hals","Magen","Rücken","Zahn"],hint:"Which body part makes it hard to swallow.",sSrc:"My {1} hurts. I can barely swallow."},
{type:"tip",title:"Mir tut ... weh / Mir tun ... weh",text:"To say something hurts, use this pattern:\n\nSingular: Mir tut der Hals weh.\nPlural: Mir tun die Ohren weh.\n\n'Mir' = to me (dative)\n'tut/tun' = does/do\n'weh' = sore/painful\n\nThe body part is the subject, so the verb matches IT:\n- der Zahn tut weh (one tooth)\n- die Zähne tun weh (multiple teeth)\n\nCompound pain words: Kopfschmerzen, Halsschmerzen, Bauchschmerzen, Rückenschmerzen."},
{type:"mc",q:"Verumius sagt: 'Mir tun die ___ weh.' Was passt, wenn er nichts hören kann?",opts:["Ohr","Ohren","Ohrs","Ohre"],ans:"Ohren",hint:"Plural form needed after 'die'. This word adds -en in plural."},
{type:"teach",trg:"die Tablette",src:"the tablet / pill",note:"Feminine. Plural: die Tabletten. Take with water!",example:"A: Ich habe Kopfschmerzen.\nB: Nehmen Sie diese Tabletten.\nA: Wie viele pro Tag?\nB: Zwei Tabletten, morgens und abends.",exampleSrc:"A: I have a headache.\nB: Take these tablets.\nA: How many per day?\nB: Two tablets, morning and evening.",funFact:"Germans are Europe's biggest consumers of herbal medicine. Many prefer 'pflanzliche Tabletten' (herbal tablets) over synthetic pills."},
{type:"teach",trg:"das Medikament",src:"the medication / medicine",note:"Neuter. More formal than 'Medizin'. Used for specific prescribed drugs.",example:"A: Brauche ich ein Medikament?\nB: Ja, ich verschreibe Ihnen etwas.\nA: Ist das Medikament stark?\nB: Nein, nehmen Sie es dreimal am Tag.",exampleSrc:"A: Do I need medication?\nB: Yes, I'll prescribe you something.\nA: Is the medication strong?\nB: No, take it three times a day.",funFact:"Germany has over 18,000 pharmacies (Apotheken). By law, most medications can only be sold in pharmacies, not in supermarkets like in other countries."},
{type:"teach",trg:"das Rezept",src:"the prescription",note:"Neuter. Same word also means 'recipe' for cooking!",example:"A: Ich brauche ein Medikament gegen Halsschmerzen.\nB: Haben Sie ein Rezept vom Arzt?\nA: Nein, leider nicht.\nB: Dann kann ich Ihnen nur diese Tabletten geben.",exampleSrc:"A: I need medication for a sore throat.\nB: Do you have a prescription from the doctor?\nA: No, unfortunately not.\nB: Then I can only give you these tablets.",funFact:"In German, 'Rezept' means both 'prescription' and 'recipe'. Context tells you which one. 'Ein Rezept vom Arzt' = prescription. 'Ein Rezept für Kuchen' = recipe."},
{type:"mc",q:"Verumius fragt in der Apotheke nach Medizin. Die Apothekerin fragt: 'Haben Sie ein ___ vom Arzt?'",opts:["Medikament","Tablette","Rezept","Creme"],ans:"Rezept",hint:"The pharmacist wants to know if a doctor authorized this."},
{type:"teach",trg:"die Creme",src:"the cream / ointment",note:"Feminine. Pronounced like 'Krehm'. Used for skin and pain relief.",example:"A: Mein Rücken tut so weh.\nB: Versuchen Sie diese Creme.\nA: Hilft die Creme schnell?\nB: Ja, reiben Sie sie zweimal am Tag ein.",exampleSrc:"A: My back hurts so much.\nB: Try this cream.\nA: Does the cream work quickly?\nB: Yes, rub it in twice a day.",funFact:"Nivea, one of the world's most famous cream brands, was invented in Hamburg in 1911. The name comes from Latin 'niveus' meaning 'snow-white'."},
{type:"teach",trg:"der Patient",src:"the patient (male)",note:"Masculine noun. Plural: die Patienten.\nFeminine form: die Patientin.",example:"A: Der Patient wartet schon eine Stunde.\nB: Ja, der Arzt hat heute viele Patienten.\nA: Wie heißt der Patient?\nB: Verumius. Er hat die Grippe.",exampleSrc:"A: The patient has been waiting for an hour.\nB: Yes, the doctor has many patients today.\nA: What is the patient's name?\nB: Verumius. He has the flu.",funFact:"In Germany, patients get a yellow Krankschreibung (sick note) from the doctor. One copy goes to the employer, one to the insurance company, and one is for the patient. The system is paper-based to this day."},
{type:"teach",trg:"die Krankschreibung",src:"the sick note",note:"Feminine noun. Compound: krank (sick) + Schreibung (writing).\nOfficially: Arbeitsunfähigkeitsbescheinigung (28 letters!).",example:"A: Ich bin seit drei Tagen krank.\nB: Hast du eine Krankschreibung?\nA: Ja, der Arzt hat mir eine gegeben.\nB: Gut, schick sie an deinen Chef.",exampleSrc:"A: I have been sick for three days.\nB: Do you have a sick note?\nA: Yes, the doctor gave me one.\nB: Good, send it to your boss.",funFact:"The official German term is 'Arbeitsunfähigkeitsbescheinigung' (certificate of inability to work), often abbreviated AU. It is one of the longest commonly used German words. Everyone just says Krankschreibung instead."},
{type:"teach",trg:"der Krankenwagen",src:"the ambulance",note:"Masculine noun. Compound: Kranken (sick people) + Wagen (vehicle).\nLiterally: the sick-wagon.",example:"A: Ruf den Krankenwagen!\nB: Ist es so schlimm?\nA: Ja, der Patient kann nicht stehen.\nB: Okay, ich rufe sofort an: 112.",exampleSrc:"A: Call the ambulance!\nB: Is it that bad?\nA: Yes, the patient cannot stand.\nB: Okay, I will call right away: 112.",funFact:"112 is the emergency number for ambulance and fire in Germany (and all of Europe). Police is 110. German ambulances are staffed with Rettungssanitäter (paramedics) and often an emergency doctor (Notarzt) as well."},
{type:"teach",trg:"stark",src:"strong",note:"Adjective. Comparative: stärker. Superlative: am stärksten.\nNote the umlaut in comparative and superlative!",example:"A: Ich habe starke Kopfschmerzen.\nB: Seit wann? Sind die Schmerzen sehr stark?\nA: Ja, ziemlich stark. Seit gestern.",exampleSrc:"A: I have a strong headache.\nB: Since when? Is the pain very strong?\nA: Yes, pretty strong. Since yesterday.",funFact:"'Stark' also means 'great' or 'awesome' in slang: 'Das war echt stark!' = That was really awesome! Like English 'strong move.' In grammar, 'starke Verben' (strong verbs) are irregular verbs that change their vowel."},
{type:"fb",s:"Der Arzt gibt Verumius ein {1} für die Apotheke.",a:["Rezept"],opts:["Rezept","Medikament","Tablette","Creme"],hint:"A piece of paper from the doctor that the pharmacy needs to see.",sSrc:"The doctor gives Verumius a {1} for the pharmacy."},
{type:"drag_fill",s:"Mir {1} der Rücken {2}. Ich brauche eine Creme.",blanks:{"1":"tut","2":"weh"},pool:["tut","weh","tun","ist","gut","hat"],hint:"Singular body part uses the singular verb form. The pain word goes at the end.",sSrc:"My back {1} {2}. I need a cream."},
{type:"match",pairs:[{trg:"der Körper",src:"body"},{trg:"der Hals",src:"throat/neck"},{trg:"der Magen",src:"stomach"},{trg:"das Ohr",src:"ear"},{trg:"der Rücken",src:"back"},{trg:"der Zahn",src:"tooth"},{trg:"die Tablette",src:"tablet/pill"},{trg:"das Medikament",src:"medication"},{trg:"das Rezept",src:"prescription"},{trg:"die Creme",src:"cream"}]},
{type:"mc",q:"Verumius hat Rückenschmerzen und geht in die Apotheke. Was braucht er?",opts:["eine Creme","einen Zahn","ein Ohr","einen Hals"],ans:"eine Creme",hint:"For back pain, you apply something to the skin."}
]}
,

// Unit 7, Lesson 3: Beim Hausarzt
// Story: Verumius visits the Hausarzt. 4-minute appointment. Doctor speaks fast.
// Grammar: Perfekt with haben (formal intro), Dative case full paradigm
{id:"deu_r7l3",title:"Beim Hausarzt",icon:"\uD83D\uDC68\u200D\u2695\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Beim Hausarzt",desc:"Verumius finally has his doctor's appointment. But German doctors are fast. Very fast. Four minutes fast.",goals:["Learn 8 new medical vocabulary words","Understand Perfekt with haben (past tense)","Learn the full dative case paradigm"]},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-arztpraxis",trg:"Verumius sitzt im Wartezimmer. Endlich ruft die Sprechstundenhilfe seinen Namen. Er geht in das Behandlungszimmer. Der Arzt tippt schon auf seinem Computer.",src:"Verumius sits in the waiting room. Finally the receptionist calls his name. He goes into the treatment room. The doctor is already typing on his computer."},
{type:"story",speaker:"doctor",trg:"Guten Tag. Setzen Sie sich. Krankenkassenkarte bitte. Was fehlt Ihnen?",src:"Good day. Sit down. Insurance card please. What's the matter with you?"},
{type:"story",speaker:"verumius",mood:"confused",trg:"Ich... ich f\u00fchle mich nicht gut. Ich habe Halsschmerzen und...",src:"I... I don't feel well. I have a sore throat and..."},
{type:"story",speaker:"doctor",trg:"Mund auf. Hmm. Haben Sie Fieber gehabt? Husten? Seit wann?",src:"Open your mouth. Hmm. Have you had a fever? Cough? Since when?"},
{type:"teach",trg:"der Besuch",src:"the visit",note:"Masculine noun. Plural: die Besuche. Also means 'visitor.'",example:"A: Wie war der Besuch beim Arzt?\nB: Der Besuch war sehr kurz.\nA: Wie kurz?\nB: Vier Minuten!",exampleSrc:"A: How was the visit to the doctor?\nB: The visit was very short.\nA: How short?\nB: Four minutes!",funFact:"'Besuch' comes from 'besuchen' (to visit). Germans use it for both the act of visiting AND the person visiting. 'Wir haben Besuch' means 'We have visitors.'"},
{type:"teach",trg:"die Sprechstunde",src:"consultation hours",note:"Feminine noun. Compound: Sprech (speaking) + Stunde (hour).",example:"A: Wann hat der Arzt Sprechstunde?\nB: Die Sprechstunde ist von 8 bis 12.\nA: Und am Nachmittag?\nB: Nur mit Termin.",exampleSrc:"A: When does the doctor have consultation hours?\nB: Consultation hours are from 8 to 12.\nA: And in the afternoon?\nB: Only with an appointment.",funFact:"German doctors have fixed Sprechstunden. You show up, take a number, and wait. No appointment needed for the morning slot. This surprises many foreigners!"},
{type:"teach",trg:"die Krankenkasse",src:"the health insurance",note:"Feminine. Compound: Krank (sick) + Kasse (cash register/fund).",example:"A: Haben Sie eine Krankenkasse?\nB: Ja, ich bin bei der AOK.\nA: Gut. Krankenkassenkarte bitte.\nB: Hier, bitte.",exampleSrc:"A: Do you have health insurance?\nB: Yes, I'm with the AOK.\nA: Good. Insurance card please.\nB: Here you go.",funFact:"In Germany, health insurance is mandatory. The word literally means 'sick-cash-register.' About 90% of Germans are in the public system. The card is the first thing the receptionist asks for."},
{type:"teach",trg:"die Krankheit",src:"the illness / disease",note:"Feminine. From 'krank' (sick) + '-heit' (suffix like English '-ness').",example:"A: Was ist die Krankheit?\nB: Ich habe eine Erk\u00e4ltung.\nA: Das ist nicht schlimm.\nB: Aber ich f\u00fchle mich sehr schlecht!",exampleSrc:"A: What is the illness?\nB: I have a cold.\nA: That's not serious.\nB: But I feel very bad!",funFact:"The suffix '-heit' turns adjectives into nouns, just like English '-ness.' Krank to Krankheit, gesund to Gesundheit, sch\u00f6n to Sch\u00f6nheit (beauty). Once you know this trick, you can build dozens of nouns."},
{type:"teach",trg:"untersuchen",src:"to examine",note:"Inseparable verb: ich untersuche, er untersucht. Prefix 'unter-' stays attached.",example:"A: Der Arzt untersucht mich jetzt.\nB: Was untersucht er?\nA: Meinen Hals und meine Ohren.\nB: Das geht schnell.",exampleSrc:"A: The doctor is examining me now.\nB: What is he examining?\nA: My throat and my ears.\nB: That goes quickly.",funFact:"'Unter' means 'under,' so 'untersuchen' literally means 'to look under.' Like a detective investigating. The past participle has NO ge-: 'untersucht,' not 'geuntersucht.' Inseparable prefixes block 'ge-.'"},
{type:"teach",trg:"sich f\u00fchlen",src:"to feel (reflexive)",note:"Reflexive verb: ich f\u00fchle mich, du f\u00fchlst dich, er f\u00fchlt sich.",example:"A: Wie f\u00fchlen Sie sich?\nB: Ich f\u00fchle mich nicht gut.\nA: Seit wann?\nB: Seit drei Tagen.",exampleSrc:"A: How do you feel?\nB: I don't feel well.\nA: Since when?\nB: For three days.",funFact:"German uses 'sich' (myself/yourself) where English just says 'feel.' You don't just feel bad, you feel YOURSELF bad. 'Ich f\u00fchle mich krank' means I feel myself sick. Many body and emotion verbs are reflexive in German."},
{type:"teach",trg:"fallen",src:"to fall",note:"Irregular: ich falle, du f\u00e4llst, er f\u00e4llt. Stem change a to \u00e4.",example:"A: Ich bin gestern gefallen.\nB: Oh nein! Wo bist du gefallen?\nA: Auf der Treppe.\nB: Hast du dich verletzt?",exampleSrc:"A: I fell yesterday.\nB: Oh no! Where did you fall?\nA: On the stairs.\nB: Did you hurt yourself?",funFact:"'Fallen' uses 'sein' in the Perfekt (ich BIN gefallen), not 'haben.' Why? Because it is a movement verb. Movement verbs like gehen, kommen, fallen, fahren always use 'sein.' You will learn this distinction soon."},
{type:"teach",trg:"endlich",src:"finally / at last",note:"Adverb expressing relief that something happened after a long wait.",example:"A: Endlich bin ich dran!\nB: Wie lange hast du gewartet?\nA: Zwei Stunden!\nB: Das ist normal beim Hausarzt.",exampleSrc:"A: Finally it's my turn!\nB: How long did you wait?\nA: Two hours!\nB: That's normal at the GP.",funFact:"'Endlich' comes from 'Ende' (end). It carries emotional relief, not just sequence. 'Endlich!' by itself is an exclamation: 'At last!' Germans also say 'Na endlich!' for a stronger 'About time!'"},
{type:"tip",title:"Perfekt with haben: Talking About the Past",text:"German has a past tense called Perfekt. It uses TWO parts:\n\nhaben (conjugated) + Partizip II (at the end)\n\nRegular verbs: ge- + stem + -t\nmachen \u2192 gemacht, kaufen \u2192 gekauft, h\u00f6ren \u2192 geh\u00f6rt\n\nIrregular verbs: ge- + stem + -en (often with vowel change)\nnehmen \u2192 genommen, sprechen \u2192 gesprochen, trinken \u2192 getrunken\n\nExamples:\nIch habe Medikamente gekauft. (I bought medicine.)\nEr hat den Hals untersucht. (He examined the throat.)\n\nThe Partizip II always goes to the END of the sentence.",deepDive:"Inseparable prefix verbs (be-, er-, ver-, ent-, unter-) do NOT get ge-:\nbesuchen \u2192 besucht, untersuchen \u2192 untersucht, verstehen \u2192 verstanden.\n\nSeparable prefix verbs put ge- in the MIDDLE:\neinkaufen \u2192 eingekauft, aufmachen \u2192 aufgemacht.\n\nSome verbs use 'sein' instead of 'haben' for movement and state-change verbs like gehen, fallen, kommen. You will learn those in the next lesson."},
{type:"verb_table",title:"Perfekt with haben",groups:[{label:"haben conjugation",rows:[{pronoun:"ich",form:"habe",src:"I have"},{pronoun:"du",form:"hast",src:"you have"},{pronoun:"er/sie/es",form:"hat",src:"he/she/it has"},{pronoun:"wir",form:"haben",src:"we have"},{pronoun:"ihr",form:"habt",src:"you all have"},{pronoun:"sie/Sie",form:"haben",src:"they/you formal have"}]},{label:"Partizip II examples",rows:[{pronoun:"machen",form:"gemacht",src:"made/done"},{pronoun:"kaufen",form:"gekauft",src:"bought"},{pronoun:"h\u00f6ren",form:"geh\u00f6rt",src:"heard"},{pronoun:"nehmen",form:"genommen",src:"taken"},{pronoun:"sprechen",form:"gesprochen",src:"spoken"},{pronoun:"trinken",form:"getrunken",src:"drunk"}]}],note:"Regular: ge- + stem + -t. Irregular: ge- + changed stem + -en. Partizip II goes to the END."},
{type:"mc",q:"'Ich habe Tabletten gekauft.' What does this sentence mean?",opts:["I am buying tablets.","I bought tablets.","I will buy tablets.","I want to buy tablets."],ans:"I bought tablets.",hint:"The sentence uses haben + Partizip II, which describes a completed action."},
{type:"fb",s:"Er hat den Arzt {1}.",a:["besucht"],opts:["besucht","gebesucht","besuchen","besuchte"],hint:"Inseparable prefix verbs form their Partizip II without ge-.",sSrc:"He {1} the doctor."},
{type:"mc",q:"Which is the correct Partizip II of 'machen'?",opts:["gemacht","gemachen","gegemacht","macht"],ans:"gemacht",hint:"Regular verbs follow the pattern ge- + stem + -t."},
{type:"tip",title:"The Dative Case: Giving, Showing, Telling",text:"German has four cases. You know Nominativ (subject) and Akkusativ (direct object). Now: Dativ.\n\nDativ answers: to whom? for whom?\n\nThe articles change:\nder \u2192 dem (masculine)\ndie \u2192 der (feminine)\ndas \u2192 dem (neuter)\ndie (plural) \u2192 den + -n on noun\n\nExamples:\nDer Arzt gibt dem Mann ein Rezept. (The doctor gives the man a prescription.)\nIch sage der Frau meinen Namen. (I tell the woman my name.)\nEr hilft dem Kind. (He helps the child.)",deepDive:"Common verbs that ALWAYS take dative:\nhelfen (to help): Ich helfe dem Arzt.\ngeben (to give): Er gibt dem Patienten Tabletten.\nzeigen (to show): Sie zeigt dem Kind das Buch.\nsagen (to say to): Ich sage der Frau die Adresse.\ngefallen (to please): Das gef\u00e4llt dem Mann.\n\nAlso after these prepositions: mit (with), bei (at/near), von (from), zu (to), nach (after), seit (since), aus (out of)."},
{type:"mc",q:"'Der Arzt gibt ___ Mann ein Rezept.' Which article fills the blank?",opts:["dem","den","der","das"],ans:"dem",hint:"The man receives the prescription. This is the to-whom case for a masculine noun."},
{type:"fb",s:"Ich erkl\u00e4re {1} \u00c4rztin die Krankheit.",a:["der"],opts:["der","die","dem","den"],hint:"\u00c4rztin is feminine. Think about what 'die' becomes in the dative case.",sSrc:"I explain the illness to the {1} doctor."},
{type:"mc",q:"Verumius says: 'Ich habe endlich die Sprechstunde gefunden!' What does 'endlich' express?",opts:["All of a sudden","With deep regret","Finally, relieved","Probably not yet"],ans:"Finally, relieved",hint:"This word comes from 'Ende' and expresses that something took a long time."},
{type:"fb",s:"Wie {1} Sie sich heute?",a:["f\u00fchlen"],opts:["f\u00fchlen","fallen","finden","fahren"],hint:"Which reflexive verb asks about someone's physical state.",sSrc:"How do you {1} today?"},
{type:"match",pairs:[{trg:"der Besuch",src:"the visit"},{trg:"die Krankenkasse",src:"health insurance"},{trg:"untersuchen",src:"to examine"},{trg:"sich f\u00fchlen",src:"to feel"},{trg:"endlich",src:"finally"},{trg:"die Krankheit",src:"illness"}]},
{type:"drag_fill",s:"Verumius {1} dem Arzt die Krankenkassenkarte {2}.",blanks:{"1":"hat","2":"gegeben"},pool:["hat","gegeben","ist","geben","dem","den"],hint:"Past tense with haben: conjugated haben + Partizip II at the end.",sSrc:"Verumius {1} the insurance card to the doctor {2}."}
]}
,

// ─── L4: Was hat der Arzt gesagt? (Grammar) ───
{id:"deu_r7l4",title:"Was hat der Arzt gesagt?",icon:"📋",xp:20,board:true,steps:[
{type:"intro",title:"Was hat der Arzt gesagt?",desc:"Verumius tries to remember what the doctor said. Conjunctions, modal verbs in past tense, and dative verbs. Plus: the world's longest Beipackzettel.",goals:["Use dass, weil, wenn, and als in sentences","Conjugate modal verbs in Präteritum","Recognize verbs that take dative objects"]},
{type:"teach",trg:"dass",src:"that (conjunction)",note:"Sends the verb to the END of the clause.\ndass + subject + ... + verb (last).",example:"A: Was hat der Arzt gesagt?\nB: Er hat gesagt, dass du mehr schlafen musst.\nA: Mehr schlafen? Das ist das beste Rezept!\nB: Ja, und weniger Kaffee trinken.",exampleSrc:"A: What did the doctor say?\nB: He said that you need to sleep more.\nA: More sleep? That's the best prescription!\nB: Yes, and drink less coffee.",funFact:"In a dass-clause, the conjugated verb jumps to the very end. Germans hear the verb last and still understand everything. Their brains are wired for suspense."},
{type:"teach",trg:"weil",src:"because",note:"Also sends the verb to the END.\nweil + subject + ... + verb (last).",example:"A: Warum bist du beim Arzt?\nB: Weil ich starke Kopfschmerzen habe.\nA: Seit wann?\nB: Seit drei Tagen. Es wird nicht besser.",exampleSrc:"A: Why are you at the doctor's?\nB: Because I have strong headaches.\nA: Since when?\nB: For three days. It's not getting better.",funFact:"'Weil' and 'denn' both mean 'because,' but 'weil' kicks the verb to the end while 'denn' keeps normal word order. Two words, same meaning, different grammar."},
{type:"teach",trg:"wenn",src:"when / if (repeated or hypothetical)",note:"For repeated events or conditions.\nwenn + subject + ... + verb (last).",example:"A: Wann nimmst du die Tabletten?\nB: Wenn ich Kopfschmerzen habe.\nA: Und wenn du keine hast?\nB: Dann bin ich froh!",exampleSrc:"A: When do you take the tablets?\nB: When I have headaches.\nA: And when you don't?\nB: Then I'm happy!",funFact:"'Wenn' does double duty: 'when' for repeated events and 'if' for conditions. 'Wenn es regnet, bleibe ich zu Hause' can mean both 'When it rains' and 'If it rains.' Context decides."},
{type:"teach",trg:"als",src:"when (past, single event)",note:"Only for ONE specific moment in the past.\nals + subject + ... + verb (last).",example:"A: Was ist passiert?\nB: Als ich beim Arzt war, hat er mich untersucht.\nA: Und was hat er gefunden?\nB: Er hat gesagt, es ist nur eine Erkältung.",exampleSrc:"A: What happened?\nB: When I was at the doctor's, he examined me.\nA: And what did he find?\nB: He said it's just a cold.",funFact:"The wenn/als distinction trips up every learner. Simple rule: one specific past moment = als. Everything else (repeated past, present, future, hypothetical) = wenn. 'Als ich Kind war' = When I was a child (one era)."},
{type:"mc",q:"Verumius says: 'Ich bin müde, ___ ich nicht gut geschlafen habe.' Which conjunction means 'because'?",opts:["dass","weil","wenn","als"],ans:"weil",hint:"He is giving a reason for being tired."},
{type:"fb",s:"Er hat gesagt, {1} ich mehr Wasser trinken soll.",a:["dass"],opts:["dass","weil","wenn","als"],hint:"The doctor reported something. Which conjunction introduces reported speech.",sSrc:"He said {1} I should drink more water."},
{type:"mc",q:"'Als ich beim Arzt war, hat er mich untersucht.' Why is 'als' correct here?",opts:["It describes a repeated habit","It describes a single past event","It introduces a condition","It gives a reason"],ans:"It describes a single past event",hint:"The doctor visit happened once, at a specific earlier time."},
{type:"verb_table",title:"Modal Verbs: Präteritum (Simple Past)",groups:[{label:"können (could)",rows:[{pronoun:"ich",form:"konnte",src:"I could"},{pronoun:"du",form:"konntest",src:"you could"},{pronoun:"er/sie/es",form:"konnte",src:"he/she/it could"},{pronoun:"wir",form:"konnten",src:"we could"},{pronoun:"ihr",form:"konntet",src:"you all could"},{pronoun:"sie/Sie",form:"konnten",src:"they/you (formal) could"}]},{label:"müssen (had to)",rows:[{pronoun:"ich",form:"musste",src:"I had to"},{pronoun:"du",form:"musstest",src:"you had to"},{pronoun:"er/sie/es",form:"musste",src:"he/she/it had to"},{pronoun:"wir",form:"mussten",src:"we had to"},{pronoun:"ihr",form:"musstet",src:"you all had to"},{pronoun:"sie/Sie",form:"mussten",src:"they/you (formal) had to"}]},{label:"wollen (wanted to)",rows:[{pronoun:"ich",form:"wollte",src:"I wanted to"},{pronoun:"du",form:"wolltest",src:"you wanted to"},{pronoun:"er/sie/es",form:"wollte",src:"he/she/it wanted to"},{pronoun:"wir",form:"wollten",src:"we wanted to"},{pronoun:"ihr",form:"wolltet",src:"you all wanted to"},{pronoun:"sie/Sie",form:"wollten",src:"they/you (formal) wanted to"}]},{label:"dürfen (was allowed to)",rows:[{pronoun:"ich",form:"durfte",src:"I was allowed to"},{pronoun:"du",form:"durftest",src:"you were allowed to"},{pronoun:"er/sie/es",form:"durfte",src:"he/she/it was allowed to"},{pronoun:"wir",form:"durften",src:"we were allowed to"},{pronoun:"ihr",form:"durftet",src:"you all were allowed to"},{pronoun:"sie/Sie",form:"durften",src:"they/you (formal) were allowed to"}]},{label:"sollen (was supposed to)",rows:[{pronoun:"ich",form:"sollte",src:"I was supposed to"},{pronoun:"du",form:"solltest",src:"you were supposed to"},{pronoun:"er/sie/es",form:"sollte",src:"he/she/it was supposed to"},{pronoun:"wir",form:"sollten",src:"we were supposed to"},{pronoun:"ihr",form:"solltet",src:"you all were supposed to"},{pronoun:"sie/Sie",form:"sollten",src:"they/you (formal) were supposed to"}]}],note:"Pattern: drop umlaut, add -te. konnte/musste/wollte/durfte/sollte. ich and er/sie/es forms are identical (no -st, no -t)."},
{type:"tip",title:"Why Modals Prefer Präteritum",text:"In spoken German, most verbs use Perfekt for the past:\n'Ich habe gegessen.' (I ate.)\n\nBut modal verbs almost always use Präteritum:\n'Ich konnte nicht schlafen.' (I couldn't sleep.)\nNOT: 'Ich habe nicht schlafen können.'\n\nWhy? The Perfekt of modals is clumsy: double infinitives at the end.\nPräteritum is shorter and cleaner. Germans just prefer it.",deepDive:"The technical term is Ersatzinfinitiv. When a modal has a dependent infinitive, Perfekt requires a double infinitive construction: 'Ich habe schlafen können.' This sounds overly formal and bookish. In everyday speech, 'Ich konnte schlafen' wins every time. The same applies to werden, lassen, sehen, hören, and helfen with infinitives."},
{type:"mc",q:"'Ich ___ gestern nicht schlafen.' Which Präteritum form of 'können' fits?",opts:["konnte","gekonnt","kann","könnte"],ans:"konnte",hint:"Simple past of 'können' for ich. No umlaut in past tense."},
{type:"fb",s:"Er {1} zum Arzt gehen, weil er krank war.",a:["musste"],opts:["musste","muss","gemusst","müsste"],hint:"Simple past of 'müssen' for er. The umlaut disappears in past tense.",sSrc:"He {1} go to the doctor because he was sick."},
{type:"mc",q:"'Wir ___ am Wochenende nicht arbeiten.' Which is the Präteritum of 'dürfen' for wir?",opts:["durften","dürfen","gedurft","dürften"],ans:"durften",hint:"Simple past of dürfen, plural form. Ends in -ten."},
{type:"tip",title:"Verbs with Dative: Who Benefits?",text:"Some German verbs take a DATIVE object instead of accusative.\nThink of them as 'benefit/affect' verbs:\n\nhelfen + dative: Ich helfe DIR. (I help you.)\ngefallen + dative: Das gefällt MIR. (I like that.)\ngehören + dative: Das gehört IHM. (That belongs to him.)\nschmecken + dative: Das schmeckt UNS. (That tastes good to us.)\nfehlen + dative: Du fehlst MIR. (I miss you.)\nwehtun + dative: Der Kopf tut MIR weh. (My head hurts.)\n\nAll these describe something happening TO someone.",deepDive:"The pattern: these verbs describe an experience or benefit directed at a person, not an action performed on an object. 'Helfen' does not change the person, it benefits them. 'Gefallen' describes the experience OF someone. English hides this, but German marks it with dative case: mir, dir, ihm, ihr, uns, euch, ihnen."},
{type:"mc",q:"'Der Arzt hilft ___.' Which pronoun completes this correctly?",opts:["mir","mich","ich","mein"],ans:"mir",hint:"Helfen takes a dative object. What is the dative form of 'ich'?"},
{type:"fb",s:"Das Medikament schmeckt {1} nicht.",a:["mir"],opts:["mir","mich","ich","mein"],hint:"Schmecken takes dative. First person singular dative pronoun.",sSrc:"The medication does not taste good to {1}."},
{type:"teach",trg:"dringend",src:"urgent / urgently",note:"Used as adjective or adverb.\ndringend = urgent(ly).",example:"A: Ist es dringend?\nB: Ja, sehr dringend! Ich brauche sofort einen Arzt.\nA: Okay, kommen Sie mit!\nB: Danke, das ist sehr nett.",exampleSrc:"A: Is it urgent?\nB: Yes, very urgent! I need a doctor immediately.\nA: Okay, come with me!\nB: Thanks, that's very kind.",funFact:"'Dringend' comes from 'dringen' (to press/penetrate). Something urgent is literally 'pressing' on you. English 'urgent' comes from Latin urgere (to press). Same metaphor, different language family."},
{type:"teach",trg:"selbst",src:"self / oneself",note:"Adds emphasis: 'ich selbst' = I myself.\nAlso means 'even': 'Selbst der Arzt war krank.'",example:"A: Wer hat das Rezept gelesen?\nB: Ich selbst! Es war zehn Seiten lang.\nA: Zehn Seiten? Das ist ja ein Roman!\nB: Selbst die Apothekerin hat gelacht.",exampleSrc:"A: Who read the prescription?\nB: I myself! It was ten pages long.\nA: Ten pages? That's a novel!\nB: Even the pharmacist laughed.",funFact:"'Selbst' at the start of a sentence means 'even.' 'Selbst Verumius hat das verstanden' = Even Verumius understood that. After a pronoun it means 'oneself': 'Er hat es selbst gemacht' = He did it himself."},
{type:"teach",trg:"dabei",src:"with it / at the same time / present",note:"da + bei. 'Ich war dabei' = I was there/present.\n'Er hat dabei gelacht' = He laughed while doing it.",example:"A: Hattest du den Beipackzettel dabei?\nB: Ja, ich hatte ihn dabei.\nA: Und? Hast du alles gelesen?\nB: Nein, ich bin dabei eingeschlafen!",exampleSrc:"A: Did you have the medication insert with you?\nB: Yes, I had it with me.\nA: And? Did you read everything?\nB: No, I fell asleep while doing it!",funFact:"German has dozens of 'da-words': dabei, dafür, damit, darauf, darin, darüber, darunter. They replace 'preposition + es/das' for things (not people). 'Dabei' = 'bei dem' compressed."},
{type:"teach",trg:"darauf",src:"on it / thereupon / after that",note:"da + auf. 'Darauf steht eine Warnung' = There is a warning on it.\n'Ich freue mich darauf' = I'm looking forward to it.",example:"A: Was steht auf dem Beipackzettel?\nB: Darauf steht: nicht mit Kaffee einnehmen.\nA: Kein Kaffee?! Das ist schlimmer als die Krankheit!\nB: Darauf habe ich gewartet. Dein Gesicht!",exampleSrc:"A: What does the medication insert say?\nB: On it says: do not take with coffee.\nA: No coffee?! That's worse than the illness!\nB: I was waiting for that. Your face!",funFact:"'Darauf' is used with verbs that take 'auf': warten auf (wait for), sich freuen auf (look forward to), achten auf (pay attention to). 'Ich warte darauf' = I'm waiting for it. You cannot say 'Ich warte auf es.'"},
{type:"mc",q:"'Verumius konnte den Beipackzettel nicht lesen, ___ er zu lang war.' Which conjunction fits?",opts:["dass","weil","als","wenn"],ans:"weil",hint:"He is giving the reason he could not read it."},
{type:"drag_fill",s:"Der Arzt sagte, {1} Verumius mehr Wasser trinken {2}.",blanks:{"1":"dass","2":"sollte"},pool:["dass","weil","sollte","konnte","wenn","musste"],hint:"Reported speech uses a conjunction that sends the verb to the end.",sSrc:"The doctor said {1} Verumius should drink more water {2}."},
{type:"fb",s:"Als ich beim Arzt war, {1} ich lange warten.",a:["musste"],opts:["musste","muss","konnte","sollte"],hint:"Past tense of 'have to.' He had no choice but to wait.",sSrc:"When I was at the doctor's, I {1} wait a long time."},
{type:"match",pairs:[{trg:"dass",src:"that (conjunction)"},{trg:"weil",src:"because"},{trg:"wenn",src:"when / if"},{trg:"als",src:"when (past, single)"},{trg:"dringend",src:"urgent"},{trg:"selbst",src:"self / even"},{trg:"dabei",src:"with it / present"},{trg:"darauf",src:"on it / thereupon"}]}
]}
,

{id:"deu_r7l5",title:"Vorsicht ist besser",icon:"💊",xp:15,board:true,steps:[
{type:"intro",title:"Vorsicht ist besser",desc:"Neue Wörter rund um Vorsicht, Unfälle und Selbstfürsorge. Wiederholung: Perfekt, Dativ und Präteritum der Modalverben.",goals:["9 neue Wörter lernen","Perfekt mit haben wiederholen","Dativ und modale Präteritumformen üben"]},
{type:"teach",trg:"der Unfall",src:"the accident",note:"Plural: die Unfälle.\nUnfall = un (bad) + Fall (fall/case).",example:"A: Was ist gestern passiert?\nB: Mein Nachbar hatte einen Unfall.\nA: Oh nein! Ist er verletzt?\nB: Nein, zum Glück nicht schlimm.",exampleSrc:"A: What happened yesterday?\nB: My neighbor had an accident.\nA: Oh no! Is he hurt?\nB: No, luckily not bad.",funFact:"Germans are legally required to carry a first-aid kit (Verbandskasten) in their car at all times."},
{type:"teach",trg:"die Angst",src:"the fear, anxiety",note:"Angst haben vor + Dativ = to be afraid of.\nNo plural in everyday use.",example:"A: Hast du Angst vor dem Zahnarzt?\nB: Ja, ein bisschen.\nA: Ich auch! Aber der Arzt ist sehr nett.\nB: Das stimmt, er erklärt alles gut.",exampleSrc:"A: Are you afraid of the dentist?\nB: Yes, a little.\nA: Me too! But the doctor is very nice.\nB: That's true, he explains everything well.",funFact:"The word Angst was borrowed directly into English and is used in psychology worldwide."},
{type:"teach",trg:"die Ahnung",src:"the idea, clue",note:"keine Ahnung = no idea (very common phrase).\nAhnung haben von + Dativ = to know about.",example:"A: Weißt du, wo die Apotheke ist?\nB: Keine Ahnung, sorry.\nA: Ich frage mal den Mann dort.\nB: Gute Idee, der wohnt hier bestimmt.",exampleSrc:"A: Do you know where the pharmacy is?\nB: No idea, sorry.\nA: I'll ask that man over there.\nB: Good idea, he probably lives here.",funFact:"Keine Ahnung is one of the top 10 most-used phrases in casual German conversation."},
{type:"teach",trg:"der Apparat",src:"the device, apparatus",note:"Also used for phone: am Apparat = on the line.\nPlural: die Apparate.",example:"A: Was ist das für ein Apparat?\nB: Damit misst der Arzt den Blutdruck.\nA: Ah, das kenne ich vom Krankenhaus.\nB: Genau, der ist ganz normal.",exampleSrc:"A: What kind of device is that?\nB: The doctor measures blood pressure with it.\nA: Ah, I know that from the hospital.\nB: Exactly, it's completely normal.",funFact:"When answering the phone in Germany, people traditionally say their last name, not Hallo."},
{type:"teach",trg:"sich ausruhen",src:"to rest (oneself)",note:"Reflexive: Ich ruhe mich aus.\nSeparable prefix: aus + ruhen.",example:"A: Du siehst müde aus.\nB: Ja, ich muss mich ausruhen.\nA: Leg dich auf das Sofa.\nB: Danke, das mache ich.",exampleSrc:"A: You look tired.\nB: Yes, I need to rest.\nA: Lie down on the sofa.\nB: Thanks, I'll do that.",funFact:"German doctors can write you a Krankschreibung (sick note) that legally excuses you from work, even for minor illnesses."},
{type:"teach",trg:"sich verletzen",src:"to injure (oneself)",note:"Reflexive: Ich habe mich verletzt.\nPerfekt: hat sich verletzt (haben).",example:"A: Warum hast du einen Verband?\nB: Ich habe mich beim Sport verletzt.\nA: Das tut mir leid. Warst du beim Arzt?\nB: Ja, es ist nicht so schlimm.",exampleSrc:"A: Why do you have a bandage?\nB: I injured myself during sports.\nA: I'm sorry. Did you go to the doctor?\nB: Yes, it's not that bad.",funFact:"Germany has over 27,000 sports clubs, and sports injuries are one of the most common reasons for doctor visits."},
{type:"teach",trg:"aufpassen",src:"to watch out, to be careful",note:"Separable: Pass auf!\nAufpassen auf + Akkusativ = to look after.",example:"A: Die Straße ist glatt heute.\nB: Danke, ich passe auf.\nA: Gestern ist dort jemand gefallen.\nB: Oh, dann gehe ich ganz langsam.",exampleSrc:"A: The street is slippery today.\nB: Thanks, I'll be careful.\nA: Someone fell there yesterday.\nB: Oh, then I'll walk very slowly.",funFact:"Pass auf! is one of the first warning phrases German children learn, often shouted by parents near roads."},
{type:"teach",trg:"sich beeilen",src:"to hurry (oneself)",note:"Reflexive: Beeil dich! = Hurry up!\nPerfekt: hat sich beeilt.",example:"A: Die Sprechstunde endet um vier!\nB: Dann müssen wir uns beeilen.\nA: Hast du die Krankenkarte dabei?\nB: Ja, die ist in meiner Tasche.",exampleSrc:"A: Office hours end at four!\nB: Then we need to hurry.\nA: Do you have the insurance card with you?\nB: Yes, it's in my bag.",funFact:"Being late to a doctor's appointment in Germany can mean losing your slot entirely, so Beeilen is taken seriously."},
{type:"teach",trg:"manchmal",src:"sometimes",note:"Position: manchmal can start or follow the verb.\nManchmal gehe ich ... / Ich gehe manchmal ...",example:"A: Gehst du oft zum Arzt?\nB: Nein, nur manchmal.\nA: Ich gehe manchmal wegen Rückenschmerzen.\nB: Das kenne ich, das ist nicht schön.",exampleSrc:"A: Do you go to the doctor often?\nB: No, only sometimes.\nA: I sometimes go because of back pain.\nB: I know that, it's not nice.",funFact:"Germans visit the doctor an average of 10 times per year, one of the highest rates in Europe."},
{type:"tip",title:"Reflexive Verben im Perfekt",text:"Reflexive verbs use haben in the Perfekt.\nThe reflexive pronoun stays:\n\nIch habe mich ausgeruht.\nEr hat sich verletzt.\nWir haben uns beeilt.\n\nWord order: subject + haben + reflexive pronoun + ... + Partizip II."},
{type:"mc",q:"Ich habe ___ beim Kochen verletzt.",opts:["mich","mir","sich","uns"],ans:"mich",hint:"First person singular reflexive in accusative case."},
{type:"fb",s:"Gestern {1} ich einen Unfall.",a:"hatte",opts:["hatte","habe","bin","war"],hint:"Präteritum of haben, first person singular.",sSrc:"Yesterday I {1} an accident."},
{type:"mc",q:"Er musste sich ___.",opts:["beeilen","beeilt","zu beeilen","beeilte"],ans:"beeilen",hint:"After a modal verb, use the infinitive form."},
{type:"fb",s:"Pass {1}! Die Straße ist nass.",a:"auf",opts:["auf","an","aus","ab"],hint:"Which separable prefix means to watch out.",sSrc:"Watch {1}! The road is wet."},
{type:"mc",q:"Hast du Angst ___ dem Krankenhaus?",opts:["vor","für","mit","bei"],ans:"vor",hint:"Angst haben requires a specific dative preposition."},
{type:"fb",s:"Ich habe keine {1}, wo die Apotheke ist.",a:"Ahnung",opts:["Ahnung","Angst","Idee","Apparat"],hint:"Common phrase meaning you have no clue at all.",sSrc:"I have no {1} where the pharmacy is."},
{type:"drag_fill",s:"Sie {1} sich gestern beim Sport {2}.",blanks:{"1":"hat","2":"verletzt"},pool:["hat","sich","verletzt","ist","verletzen"],hint:"Perfekt of sich verletzen uses haben.",sSrc:"She {1} herself during sports yesterday {2}."},
{type:"mc",q:"Manchmal ___ ich mich nach der Arbeit aus.",opts:["ruhe","ruhen","ausruhe","ruht"],ans:"ruhe",hint:"Separable verb: the prefix goes to the end in main clauses."},
{type:"teach",trg:"schwanger",src:"pregnant",note:"Adjective. Sie ist schwanger = She is pregnant. No comparative form used.",example:"A: Hast du gehört? Lisa ist schwanger!\nB: Wirklich? Das ist wunderbar!\nA: Ja, sie bekommt das Baby im Sommer.\nB: Herzlichen Glückwunsch an sie!",exampleSrc:"A: Did you hear? Lisa is pregnant!\nB: Really? That is wonderful!\nA: Yes, she is having the baby in the summer.\nB: Congratulations to her!",funFact:"In Germany, pregnant women get a Mutterpass (maternity record book) from their doctor. They carry it everywhere. Employers must provide 14 weeks of paid maternity leave (Mutterschutz), and firing a pregnant employee is illegal."},
{type:"match",pairs:[{trg:"der Unfall",src:"the accident"},{trg:"die Angst",src:"the fear"},{trg:"aufpassen",src:"to watch out"},{trg:"sich beeilen",src:"to hurry"},{trg:"manchmal",src:"sometimes"}]},
{type:"fb",s:"Der Arzt hat einen neuen {1} für den Blutdruck.",a:"Apparat",opts:["Apparat","Rezept","Tablette","Besuch"],hint:"A device used for measuring something medical.",sSrc:"The doctor has a new {1} for blood pressure."},
{type:"teach",trg:"bleiben",src:"to stay / to remain",note:"Irregular: ich bleibe, du bleibst. Perfekt: ist geblieben (with sein!).",example:"A: Wie lange bleibst du in Berlin?\nB: Ich weiß noch nicht. Vielleicht für immer.\nA: Das wäre schön!",exampleSrc:"A: How long are you staying in Berlin?\nB: I don't know yet. Maybe forever.\nA: That would be nice!",funFact:"Bleiben uses sein in Perfekt because staying is a state change: you were elsewhere, now you remain. 'Ich bin geblieben' not 'Ich habe geblieben.'"}
]},

// ─── L6: Der Beipackzettel (Story Climax) ───
{id:"deu_r7l6",title:"Der Beipackzettel",icon:"\uD83D\uDCDC",xp:20,board:true,steps:[
{type:"intro",title:"Der Beipackzettel",desc:"Verumius unfolds the medication insert. And unfolds it. And keeps unfolding it. German compound nouns have never been scarier.",goals:["Read a Beipackzettel (medication insert)","Combine Perfekt, dative, and modal Präteritum in sentences","Use weil and dass clauses with complex grammar"]},
{type:"story",speaker:"narrator",mood:"comedic",art:"de-beipackzettel",trg:"Verumius nimmt die Tabletten aus der Tüte. Er sieht den Beipackzettel. Er faltet ihn auf. Und faltet. Und faltet. Das Papier ist jetzt größer als der Tisch.",src:"Verumius takes the tablets out of the bag. He sees the medication insert. He unfolds it. And unfolds. And unfolds. The paper is now bigger than the table."},
{type:"story",speaker:"verumius",mood:"panic",trg:"Was?! Nebenwirkungen: Kopfschmerzen, Bauchschmerzen, Müdigkeit, Schwindel, Übelkeit... Das sind mehr Wörter als in meinem ganzen Deutschkurs!",src:"What?! Side effects: headaches, stomach aches, tiredness, dizziness, nausea... That's more words than in my entire German course!"},
{type:"story",speaker:"hildi",mood:"laughing",trg:"Verumius, du musst nicht alles lesen! Nimm einfach die Tablette und ruf mich an, wenn etwas passiert.",src:"Verumius, you don't have to read everything! Just take the tablet and call me if something happens."},
{type:"teach",trg:"passieren",src:"to happen",note:"Regular verb. Perfekt: ist passiert (uses sein!).",example:"A: Was ist passiert?\nB: Ich bin hingefallen und habe mir den Arm wehgetan.",exampleSrc:"A: What happened?\nB: I fell and hurt my arm.",funFact:"'Passieren' comes from French 'passer.' In German it only means 'to happen,' never 'to pass by.' For passing, Germans say 'vorbeigehen.'"},
{type:"teach",trg:"rufen",src:"to call (out) / to shout",note:"Irregular: ruft, rief, hat gerufen. Not for phone calls (that is 'anrufen').",example:"A: Wer hat meinen Namen gerufen?\nB: Das war der Arzt. Er hat dich gerufen.",exampleSrc:"A: Who called my name?\nB: That was the doctor. He called you.",funFact:"'Rufen' is calling OUT, like shouting across a room. For phone calls, Germans add 'an': 'anrufen.' Hildi says 'ruf mich an' because she means by phone."},
{type:"teach",trg:"sich setzen",src:"to sit down (reflexive)",note:"Reflexive: Ich setze mich. Perfekt: hat sich gesetzt. Dative with location: auf den Stuhl.",example:"A: Bitte setzen Sie sich!\nB: Danke, ich habe mich schon gesetzt.",exampleSrc:"A: Please sit down!\nB: Thanks, I already sat down.",funFact:"German distinguishes sitting DOWN (sich setzen, movement) from sitting (sitzen, position). 'Setz dich!' means get into the chair. 'Sitz!' is what you say to a dog already in place."},
{type:"teach",trg:"weinen",src:"to cry",note:"Regular verb. Perfekt: hat geweint.",example:"A: Warum hast du geweint?\nB: Weil der Film so traurig war.",exampleSrc:"A: Why did you cry?\nB: Because the film was so sad.",funFact:"'Weinen' is related to English 'whine,' but in German it means full crying with tears, not complaining. For complaining, Germans say 'jammern.'"},
{type:"teach",trg:"sich aufregen",src:"to get upset / to get worked up",note:"Separable + reflexive: Ich rege mich auf. Perfekt: hat sich aufgeregt.",example:"A: Reg dich nicht auf!\nB: Ich kann mich nicht beruhigen, weil ich den Beipackzettel gelesen habe!",exampleSrc:"A: Don't get upset!\nB: I can't calm down because I read the medication insert!",funFact:"'Auf' (up) + 'regen' (to stir). Getting upset literally means stirring yourself UP. 'Aufregen' is one of the most common reflexive verbs in everyday German."},
{type:"teach",trg:"sogar",src:"even (adverb)",note:"Adds emphasis or surprise. Placed before the word it emphasizes.",example:"A: Kannst du den Beipackzettel lesen?\nB: Sogar mein Arzt versteht ihn nicht!",exampleSrc:"A: Can you read the medication insert?\nB: Even my doctor doesn't understand it!",funFact:"'Sogar' comes from 'so' + 'gar' (completely). It is the standard word for 'even' in surprising contexts. Sogar Hildi hat gelacht. Even Hildi laughed."},
{type:"mc",q:"Hildi sagt: 'Ruf mich an, wenn etwas passiert.' Was bedeutet 'passiert'?",opts:["happens","passes by","calls","hurts"],ans:"happens",hint:"Think about unexpected events, not physical movement."},
{type:"fb",s:"Was ist gestern {1}?",a:["passiert"],opts:["passiert","gerufen","gesetzt","geweint"],hint:"Which Perfekt participle uses sein, not haben.",sSrc:"What {1} yesterday?"},
{type:"mc",q:"Verumius hat sich aufgeregt, weil er den Beipackzettel gelesen hat. What was Verumius?",opts:["tired","upset","hungry","happy"],ans:"upset",hint:"Reading a comically long medical insert stirred him up."},
{type:"drag_fill",s:"Verumius {1} sich auf den Stuhl {2}, weil er müde {3}.",blanks:{"1":"hat","2":"gesetzt","3":"war"},pool:["hat","gesetzt","war","ist","gerufen","hatte"],hint:"Perfekt of sich setzen (hat + past participle) plus Präteritum of sein.",sSrc:"Verumius {1} down on the chair {2} because he was tired {3}."},
{type:"fb",s:"Der Arzt hat den Patienten {1}.",a:["gerufen"],opts:["gerufen","geweint","passiert","gesetzt"],hint:"Which participle means 'called out for someone'.",sSrc:"The doctor {1} the patient."},
{type:"mc",q:"'Sogar der Apotheker konnte den Beipackzettel nicht verstehen.' Was bedeutet 'sogar'?",opts:["always","never","even","almost"],ans:"even",hint:"This word adds surprise, emphasizing how unexpected it is."},
{type:"drag_fill",s:"Ich habe {1}, weil der Arzt mir {2} hat, dass ich {3} musste.",blanks:{"1":"geweint","2":"gesagt","3":"warten"},pool:["geweint","gesagt","warten","gerufen","passiert","konnte"],hint:"Perfekt of weinen, then Perfekt of sagen, then a modal infinitive at the end.",sSrc:"I {1} because the doctor told {2} me that I had to {3}."},
{type:"mc",q:"Verumius konnte den Beipackzettel nicht lesen, weil die Wörter zu lang waren. Why couldn't he read it?",opts:["Because the words were too long","Because he lost his glasses","Because it was in English","Because the doctor took it away"],ans:"Because the words were too long",hint:"The weil clause explains the reason with an adjective about length."},
{type:"fb",s:"Sie hat sich so {1}, dass sie sogar geweint hat.",a:["aufgeregt"],opts:["aufgeregt","gesetzt","passiert","gerufen"],hint:"Which separable verb participle means 'got worked up'.",sSrc:"She got so {1} that she even cried."},
{type:"drag_fill",s:"Hildi {1} Verumius {2}, weil er sich nicht {3} {4}.",blanks:{"1":"hat","2":"gerufen","3":"beruhigen","4":"konnte"},pool:["hat","gerufen","beruhigen","konnte","ist","passiert"],hint:"Perfekt of rufen in the main clause, then weil sends the modal to the end.",sSrc:"Hildi {1} Verumius {2} because he could not {3} calm {4} himself."},
{type:"match",pairs:[{trg:"passieren",src:"to happen"},{trg:"rufen",src:"to call out"},{trg:"sich setzen",src:"to sit down"},{trg:"weinen",src:"to cry"},{trg:"sich aufregen",src:"to get upset"},{trg:"sogar",src:"even"}]}
]}
,

{id:"deu_r7l7",title:"Alles klar?",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Alles klar?",desc:"Zeit für den großen Test! Alles aus Lektion 1 bis 6 kommt jetzt zusammen: Körperteile, Arztbesuch, Perfekt, Modalverben im Präteritum, Dativ und Nebensätze.",goals:["Vokabeln aus L1-L6 wiederholen","Grammatik kombinieren","Alles zusammen anwenden"]},
{type:"mc",q:"Ich habe gestern eine Tablette ___.",opts:["genommen","nehmen","genommt","genahmt"],ans:"genommen",hint:"Nehmen ist ein starkes Verb mit unregelmäßigem Partizip."},
{type:"fb",s:"Er {1} nicht zum Arzt gehen.",a:"konnte",opts:["konnte","kann","gekonnt","könnte"],hint:"Modalverb in der Vergangenheit, Präteritum.",sSrc:"He {1} not go to the doctor."},
{type:"mc",q:"Was bedeutet 'die Sprechstunde'?",opts:["Office hours","Emergency room","Pharmacy aisle","Waiting room"],ans:"Office hours",hint:"Der Arzt hat bestimmte Zeiten für Patienten."},
{type:"drag_fill",s:"Ich habe {1} Arzt gesagt, {2} mein Hals wehtut.",blanks:{1:"dem",2:"dass"},pool:["dem","der","dass","weil","den"],hint:"Dativ nach sagen + Nebensatz mit Verb am Ende.",sSrc:"I told the {1} doctor {2} my throat hurts."},
{type:"fb",s:"Die Ärztin hat mich gründlich {1}.",a:"untersucht",opts:["untersucht","untersuchen","untersuchte","unterforscht"],hint:"Perfekt von untersuchen: hat ge...t? Nein, un- ist untrennbar!",sSrc:"The doctor {1} me thoroughly."},
{type:"mc",q:"Welcher Satz ist richtig?",opts:["Ich musste im Krankenhaus bleiben, weil ich Grippe hatte.","Ich musste im Krankenhaus bleiben, weil ich hatte Grippe.","Ich musste im Krankenhaus bleiben, weil ich Grippe gehabt.","Ich musste im Krankenhaus bleiben, weil hatte ich Grippe."],ans:"Ich musste im Krankenhaus bleiben, weil ich Grippe hatte.",hint:"Nach weil steht das konjugierte Verb am Satzende."},
{type:"fb",s:"Der Schmerz im Rücken tut {1} sehr weh.",a:"mir",opts:["mir","mich","ich","mein"],hint:"Wehtun braucht den Dativ der Person.",sSrc:"The pain in my back hurts {1} a lot."},
{type:"mc",q:"Er ___ sich gestern beim Sport verletzt.",opts:["hat","ist","wird","hatte"],ans:"hat",hint:"Reflexive Verben bilden das Perfekt immer mit haben."},
{type:"drag_fill",s:"Sie {1} gestern in der Apotheke eine Creme {2}.",blanks:{1:"hat",2:"gekauft"},pool:["hat","ist","gekauft","kaufen","gekaufen"],hint:"Perfekt mit haben. Kaufen ist regelmäßig: ge...t.",sSrc:"She {1} a cream at the pharmacy yesterday {2}."},
{type:"mc",q:"Mein Magen tut weh. Ich glaube, ich habe etwas Schlechtes ___.",opts:["gegessen","gegesst","geessen","essen"],ans:"gegessen",hint:"Starkes Verb! Denk an die dritte Stammform."},
{type:"fb",s:"Sie {1} als Kind keine Medikamente nehmen.",a:"durfte",opts:["durfte","darf","gedurft","dürfte"],hint:"Dürfen in der Vergangenheit, einfache Erzählung.",sSrc:"As a child, she {1} not take medication."},
{type:"drag_fill",s:"Der Arzt hat {1} Patientin erklärt, {2} sie sich ausruhen {3}.",blanks:{1:"der",2:"dass",3:"soll"},pool:["der","dem","dass","weil","soll","muss"],hint:"Dativ feminin + dass-Nebensatz mit Verb am Ende.",sSrc:"The doctor explained to the {1} patient that she should {2} rest {3}."},
{type:"mc",q:"Wähle die richtige Kombination: Er ist nervös, ___ er keine Ahnung hat, ___ passiert ist.",opts:["weil ... was","dass ... was","weil ... dass","wenn ... weil"],ans:"weil ... was",hint:"Grund mit weil, dann eine indirekte Frage."},
{type:"fb",s:"Ich sollte mich nicht so {1}.",a:"aufregen",opts:["aufregen","aufgeregt","aufregt","aufzuregen"],hint:"Nach Modalverben steht der Infinitiv.",sSrc:"I should not get so {1}."},
{type:"mc",q:"Er hat dem Kind geholfen, weil es ___ hat.",opts:["geweint","weinen","geweinen","geweaint"],ans:"geweint",hint:"Weinen ist regelmäßig: ge...t."},
{type:"drag_fill",s:"Wir {1} den Krankenwagen rufen, {2} der Unfall sehr schlimm {3}.",blanks:{1:"mussten",2:"weil",3:"war"},pool:["mussten","müssen","weil","dass","war","ist"],hint:"Präteritum von müssen + weil mit Verb am Ende.",sSrc:"We {1} call the ambulance {2} the accident was very bad {3}."},
{type:"fb",s:"Pass auf dich {1}!",a:"auf",opts:["auf","an","aus","um"],hint:"Trennbares Verb! Welches Präfix gehört hierher.",sSrc:"Take care of yourself {1}!"},
{type:"mc",q:"Die Gesundheit ___ den Menschen am wichtigsten.",opts:["ist","hat","wird","macht"],ans:"ist",hint:"Welches Verb passt zu einem Zustand wie Gesundheit?"},
{type:"drag_fill",s:"Er {1} sich endlich {2}, weil er manchmal zu viel {3} hat.",blanks:{1:"hat",2:"ausgeruht",3:"gearbeitet"},pool:["hat","ist","ausgeruht","ausruhen","gearbeitet","arbeiten"],hint:"Reflexive verb: which auxiliary? Then past participle forms for resting and working.",sSrc:"He {1} finally {2} because he had sometimes worked too much {3}."},
{type:"mc",q:"Der Zahnarzt hat ___ Mädchen gesagt, dass es keine Angst haben soll.",opts:["dem","das","der","den"],ans:"dem",hint:"Sagen braucht den Dativ. Mädchen ist Neutrum."},
{type:"fb",s:"Sie wollte sich {1}, aber sie konnte den Arzt nicht erreichen.",a:"beeilen",opts:["beeilen","beeilt","beeilte","beeilen sich"],hint:"Nach Modalverben kommt der Infinitiv ohne sich davor.",sSrc:"She wanted to {1} herself, but she could not reach the doctor."},
{type:"match",pairs:[{trg:"die Krankenkasse",src:"health insurance"},{trg:"das Rezept",src:"prescription"},{trg:"die Grippe",src:"the flu"},{trg:"der Besuch",src:"the visit"},{trg:"dringend",src:"urgent"},{trg:"sogar",src:"even"}]}
]},

{id:"deu_r7l8",title:"Gute Besserung",icon:"🍵",xp:15,board:true,steps:[
{type:"intro",title:"Gute Besserung",desc:"Verumius wakes up feeling better. Hildi left chicken soup at his door with a note. Time to recover, reflect on German healthcare, and learn a few last words.",goals:["Learn adjectives for health and state","Discover German healthcare culture","Review the full unit vocabulary"]},
{type:"teach",trg:"gesund",src:"healthy",note:"The opposite of krank. Germans say 'Bleib gesund!' as a farewell wish.",example:"A: Bist du wieder gesund?\nB: Ja, ich bin wieder gesund. Die Suppe hat geholfen.\nA: Das freut mich! Bleib gesund!\nB: Danke, du auch!",exampleSrc:"A: Are you healthy again?\nB: Yes, I'm healthy again. The soup helped.\nA: I'm glad! Stay healthy!\nB: Thanks, you too!",funFact:"'Gesundheit!' is what Germans say when someone sneezes. It literally means 'health!' and is used worldwide."},
{type:"teach",trg:"fit",src:"fit",note:"Same word as English. Used for physical fitness and general well-being.",example:"A: Ich fühle mich wieder fit.\nB: Wirklich? Gestern warst du noch so krank.\nA: Die frische Luft hilft sehr.\nB: Typisch deutsch! Frische Luft heilt alles.",exampleSrc:"A: I feel fit again.\nB: Really? Yesterday you were still so sick.\nA: The fresh air helps a lot.\nB: Typical German! Fresh air heals everything.",funFact:"Germans genuinely believe fresh air (frische Luft) cures almost anything. Open windows in winter are completely normal, even in hospitals."},
{type:"teach",trg:"wach",src:"awake",note:"From the verb 'wachen' (to be awake). Wach werden means to wake up.",example:"A: Bist du schon wach?\nB: Ja, ich bin seit sechs Uhr wach.\nA: So früh? Du warst doch krank!\nB: Ich konnte nicht mehr schlafen.",exampleSrc:"A: Are you already awake?\nB: Yes, I've been awake since six o'clock.\nA: So early? You were sick!\nB: I couldn't sleep anymore.",funFact:"Germany runs on early mornings. Many bakeries open at 5:30 AM, and construction noise is legally allowed from 7 AM."},
{type:"teach",trg:"schwach",src:"weak",note:"The opposite of stark (strong). Describes physical weakness or a faint feeling.",example:"A: Ich fühle mich noch etwas schwach.\nB: Das ist normal nach einer Erkältung.\nA: Wann werde ich wieder stark?\nB: Ruh dich aus und iss die Suppe!",exampleSrc:"A: I still feel a bit weak.\nB: That's normal after a cold.\nA: When will I be strong again?\nB: Rest and eat the soup!",funFact:"The German word for weakness, 'Schwäche,' also means a soft spot. 'Schokolade ist meine Schwäche' means chocolate is my weakness."},
{type:"teach",trg:"gefährlich",src:"dangerous",note:"From Gefahr (danger). Very common in warnings and safety signs across Germany.",example:"A: Ist es gefährlich, mit Fieber zu arbeiten?\nB: Ja, das ist sehr gefährlich!\nA: Mein Chef sagt, ich soll kommen.\nB: Dein Arzt sagt nein. Der Arzt gewinnt.",exampleSrc:"A: Is it dangerous to work with a fever?\nB: Yes, that's very dangerous!\nA: My boss says I should come.\nB: Your doctor says no. The doctor wins.",funFact:"In Germany, if your doctor writes you a Krankschreibung (sick note), your employer cannot force you to work. Sick leave is a protected right."},
{type:"teach",trg:"furchtbar",src:"terrible",note:"From Furcht (fear). Used for something truly awful, stronger than schlecht.",example:"A: Wie war die Nacht?\nB: Furchtbar. Ich hatte Kopfschmerzen und Fieber.\nA: Das klingt wirklich schlimm.\nB: Aber heute geht es mir besser.",exampleSrc:"A: How was the night?\nB: Terrible. I had a headache and fever.\nA: That sounds really bad.\nB: But today I feel better.",funFact:"Germans love intensifiers. 'Furchtbar' (terrible) is often used positively too: 'furchtbar nett' means terribly nice, like 'awfully kind' in English."},
{type:"teach",trg:"plötzlich",src:"suddenly",note:"An adverb describing something unexpected. Very common in storytelling.",example:"A: Was ist passiert?\nB: Ich war im Büro und plötzlich war mir schwindelig.\nA: Plötzlich? Einfach so?\nB: Ja, von einer Sekunde auf die andere.",exampleSrc:"A: What happened?\nB: I was at the office and suddenly I felt dizzy.\nA: Suddenly? Just like that?\nB: Yes, from one second to the next.",funFact:"German has wonderful adverbs for time: plötzlich (suddenly), allmählich (gradually), gelegentlich (occasionally), and augenblicklich (instantaneously, literally 'in the blink of an eye')."},
{type:"teach",trg:"hoffentlich",src:"hopefully",note:"From Hoffnung (hope). Always placed at the start or middle of a sentence.",example:"A: Hoffentlich geht es dir bald besser.\nB: Danke! Hoffentlich kann ich morgen arbeiten.\nA: Nicht zu schnell! Erst gesund werden.\nB: Du klingst wie meine Mutter!",exampleSrc:"A: Hopefully you'll feel better soon.\nB: Thanks! Hopefully I can work tomorrow.\nA: Not too fast! Get healthy first.\nB: You sound like my mother!",funFact:"Hoffentlich is one of those German words that packs a whole English phrase into one word. Another example: Fingerspitzengefühl means intuitive sensitivity (literally: fingertip feeling)."},
{type:"teach",trg:"niemand",src:"nobody",note:"The opposite of jemand (somebody). Used as a pronoun in the subject or object position.",example:"A: War jemand an der Tür?\nB: Niemand. Aber da steht eine Suppe!\nA: Von wem ist die?\nB: Da liegt ein Zettel: 'Gute Besserung. Frau Schreiber.'",exampleSrc:"A: Was somebody at the door?\nB: Nobody. But there's a soup!\nA: Who is it from?\nB: There's a note: 'Get well soon. Frau Schreiber.'",funFact:"Hildi Schreiber left soup without knocking. In Germany, neighbours often help quietly without making a fuss. It is considered polite not to make someone feel indebted."},
{type:"tip",title:"Deutsche Gesundheitskultur",text:"German healthcare culture has a few surprises:\n\n\u2022 Krankschreibung: Your doctor gives you a sick note and you stay home. No guilt.\n\u2022 Kur: A multi-week health retreat at a spa town, sometimes covered by insurance.\n\u2022 Frische Luft: Germans open windows year-round. Fresh air is considered medicine.\n\u2022 Hühnersuppe: Chicken soup is the universal German home remedy, just like everywhere else.\n\u2022 Apotheke vs. Drogerie: Prescription medicine only at the Apotheke (pharmacy). Shampoo and vitamins at the Drogerie (drugstore).",deepDive:"Germany has universal healthcare through the Gesetzliche Krankenversicherung (statutory health insurance). About 90% of the population is covered. Employees and employers split the cost. Doctor visits have no co-pay. The system dates back to 1883 under Otto von Bismarck, making it one of the oldest national healthcare systems in the world."},
{type:"mc",q:"Hildi hat Suppe vor die Tür gestellt. Was steht auf dem Zettel?",opts:["Gute Besserung","Guten Appetit","Viel Glück","Herzlichen Glückwunsch"],ans:"Gute Besserung",hint:"This is what Germans say to someone who is sick."},
{type:"fb",s:"Ich fühle mich heute wieder {1}.",a:"gesund",opts:["gesund","krank","schwach","gefährlich"],hint:"The opposite of sick, the goal of recovery.",sSrc:"I feel {1} again today."},
{type:"mc",q:"Was bedeutet 'furchtbar'?",opts:["terrible","dangerous","suddenly","hopefully"],ans:"terrible",hint:"Think of the root word Furcht, which means fear."},
{type:"fb",s:"Hoffentlich kann ich morgen wieder {1}.",a:"arbeiten",opts:["arbeiten","schlafen","husten","niesen"],hint:"What you do at the office or workplace.",sSrc:"Hopefully I can {1} again tomorrow."},
{type:"mc",q:"Verumius öffnet das Fenster. Warum?",opts:["Frische Luft hilft bei Krankheit","Er hat Besuch","Das Fenster ist kaputt","Er will rausgehen"],ans:"Frische Luft hilft bei Krankheit",hint:"A very German belief about recovery and health."},
{type:"fb",s:"{1} hat an der Tür geklopft.",a:"Niemand",opts:["Niemand","Jemand","Hildi","Der Arzt"],hint:"The soup appeared with no one knocking.",sSrc:"{1} knocked on the door."},
{type:"mc",q:"Plötzlich war mir schwindelig. Was bedeutet 'plötzlich'?",opts:["suddenly","slowly","hopefully","always"],ans:"suddenly",hint:"It describes something happening without warning."},
{type:"drag_fill",s:"Gestern war ich {1}, aber heute bin ich wieder {2}.",blanks:{"1":"krank","2":"fit"},pool:["krank","fit","schwach","wach","gefährlich"],hint:"From illness yesterday to feeling good today.",sSrc:"Yesterday I was {1}, but today I am {2} again."},
{type:"match",pairs:[{trg:"gesund",src:"healthy"},{trg:"schwach",src:"weak"},{trg:"gefährlich",src:"dangerous"},{trg:"furchtbar",src:"terrible"},{trg:"plötzlich",src:"suddenly"},{trg:"hoffentlich",src:"hopefully"}]},
{type:"mc",q:"Was ist eine Krankschreibung?",opts:["Ein Dokument vom Arzt für den Chef","Ein Rezept für Medizin","Eine Rechnung vom Krankenhaus","Ein Brief an die Familie"],ans:"Ein Dokument vom Arzt für den Chef",hint:"It tells your employer why you cannot come to work."}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 8: Müllprofessor
// Story: Wrong bin, recycling lecture, Abendbrot discovery, Mia intro
// CEFR: A2.1 - Wechselpräpositionen, weil-clause, comparatives, superlatives
// ═══════════════════════════════════════════════════════════════
{n:8,lang:"de",srcLang:"en",track:"v2",title:"Müllprofessor",sub:"Recycling lecture, Abendbrot discovery, meeting Mia",icon:"♻️",level:"A2.1",color:"#7B5EE8",lessons:[
{id:"deu_r8l1",title:"Der falsche Eimer",icon:"♻️",xp:15,board:true,steps:[
{type:"intro",title:"Der falsche Eimer",desc:"Verumius steht im Hinterhof vor sechs bunten Mülltonnen. Er hat einen Joghurtbecher in der Hand. Hildi kommt um die Ecke und ihr Gesicht wird blass.",goals:["10 neue Wörter rund um Müll, Natur und Nachbarschaft","Deutsche Mülltrennung verstehen","Adjektive: sauber, schmutzig, schädlich, nützlich"]},
{type:"teach",trg:"der Müll",src:"waste, trash",note:"Uncountable noun. Used without article in general statements:\nMüll trennen = to separate waste.",example:"A: Was machst du da mit dem Joghurtbecher?\nB: Ich werfe ihn in den Müll.\nA: In welchen Müll? Das ist der falsche Eimer!\nB: Es gibt mehr als einen Eimer?",exampleSrc:"A: What are you doing with that yogurt cup?\nB: I'm throwing it in the trash.\nA: In which trash? That's the wrong bin!\nB: There's more than one bin?",funFact:"Germany recycles about 67% of its waste, making it one of the top recyclers in the world. The word Müll comes from Middle High German mul (dust, rubble)."},
{type:"teach",trg:"der Nachbar",src:"neighbor (male)",note:"Plural: die Nachbarn.\nWeak noun (n-Deklination): den Nachbarn, dem Nachbarn.",example:"A: Wer ist der Mann im dritten Stock?\nB: Das ist unser Nachbar, Herr Fischer.\nA: Er sieht streng aus.\nB: Er kontrolliert die Mülltonnen jeden Morgen.",exampleSrc:"A: Who is the man on the third floor?\nB: That's our neighbor, Herr Fischer.\nA: He looks strict.\nB: He checks the trash bins every morning.",funFact:"In Germany, neighbors often share a Hausordnung (house rules) that includes quiet hours and cleaning schedules for shared spaces."},
{type:"teach",trg:"die Nachbarin",src:"neighbor (female)",note:"Plural: die Nachbarinnen.\nFeminine form of der Nachbar. Add -in for feminine.",example:"A: Kennst du die Nachbarin im Erdgeschoss?\nB: Ja, das ist Frau Braun. Sie ist sehr nett.\nA: Sie hat mir gestern Kuchen gebracht.\nB: Sie bringt allen neuen Bewohnern Kuchen!",exampleSrc:"A: Do you know the neighbor on the ground floor?\nB: Yes, that's Frau Braun. She's very nice.\nA: She brought me cake yesterday.\nB: She brings cake to all new residents!",funFact:"The suffix -in turns masculine job titles and roles into feminine ones: der Lehrer becomes die Lehrerin, der Arzt becomes die Ärztin."},
{type:"teach",trg:"die Natur",src:"nature",note:"No plural in this meaning.\nCommon compound: der Naturschutz (nature protection).",example:"A: Warum trennst du den Müll so genau?\nB: Es ist gut für die Natur.\nA: Stimmt. Plastik im Wald ist schlimm.\nB: Genau! Die Natur braucht unsere Hilfe.",exampleSrc:"A: Why do you separate the trash so carefully?\nB: It's good for nature.\nA: True. Plastic in the forest is terrible.\nB: Exactly! Nature needs our help.",funFact:"Germany has over 100 Naturschutzgebiete (nature reserves). The Pfand system returns deposits on bottles to reduce waste in nature."},
{type:"teach",trg:"die Pflanze",src:"plant",note:"Plural: die Pflanzen.\nRelated verb: pflanzen = to plant.",example:"A: Was ist das auf deinem Balkon?\nB: Das sind meine Pflanzen. Tomaten und Kräuter.\nA: Die sehen toll aus!\nB: Danke! Pflanzen machen mich glücklich.",exampleSrc:"A: What's that on your balcony?\nB: Those are my plants. Tomatoes and herbs.\nA: They look great!\nB: Thanks! Plants make me happy.",funFact:"Germans love their Balkonpflanzen (balcony plants). The most popular is the Geranie (geranium), seen on balconies across Bavaria and beyond."},
{type:"teach",trg:"sauber",src:"clean",note:"Adjective. Opposite: schmutzig.\nDie Wohnung ist sauber = The apartment is clean.",example:"A: Ist die Küche sauber?\nB: Ja, ich habe gerade geputzt.\nA: Und der Hinterhof?\nB: Der Hinterhof ist auch sauber. Alles in Ordnung!",exampleSrc:"A: Is the kitchen clean?\nB: Yes, I just cleaned.\nA: And the courtyard?\nB: The courtyard is also clean. Everything's fine!",funFact:"Kehrwoche is a tradition in southwestern Germany where neighbors take turns cleaning shared spaces like stairwells and sidewalks on a weekly rotation."},
{type:"teach",trg:"schmutzig",src:"dirty",note:"Adjective. Opposite: sauber.\nDie Schuhe sind schmutzig = The shoes are dirty.",example:"A: Warum sind deine Hände so schmutzig?\nB: Ich habe im Garten gearbeitet.\nA: Du musst sie waschen vor dem Essen!\nB: Ja, ja, ich gehe schon ins Bad.",exampleSrc:"A: Why are your hands so dirty?\nB: I worked in the garden.\nA: You need to wash them before eating!\nB: Yeah, yeah, I'm heading to the bathroom.",funFact:"The German word Schmutzfink (literally dirty finch) is a playful insult for someone who is messy or untidy. Parents often use it with children."},
{type:"teach",trg:"schädlich",src:"harmful",note:"Adjective with umlaut from Schaden (damage).\nPlastik ist schädlich für die Umwelt.",example:"A: Ist Plastik wirklich so schlimm?\nB: Ja, Plastik ist sehr schädlich für die Natur.\nA: Was kann ich besser machen?\nB: Nimm eine Stofftasche zum Einkaufen!",exampleSrc:"A: Is plastic really that bad?\nB: Yes, plastic is very harmful to nature.\nA: What can I do better?\nB: Take a cloth bag for shopping!",funFact:"Since 2022, Germany has banned single-use plastic items like straws, plates, and cutlery. Shops charge for plastic bags to reduce schädlich waste."},
{type:"teach",trg:"nützlich",src:"useful",note:"Adjective from Nutzen (use, benefit).\nOpposite: nutzlos (useless).",example:"A: Mülltrennung ist so kompliziert!\nB: Aber es ist sehr nützlich für die Umwelt.\nA: Welche Tonne ist für Glas?\nB: Die grüne. Komm, ich zeige es dir!",exampleSrc:"A: Recycling is so complicated!\nB: But it's very useful for the environment.\nA: Which bin is for glass?\nB: The green one. Come, I'll show you!",funFact:"The word nützlich comes from the Middle High German nuz (useful). German has many adjective pairs: nützlich/nutzlos, schädlich/harmlos, sauber/schmutzig."},
{type:"teach",trg:"die Tür",src:"door",note:"Plural: die Türen.\nRelated: die Haustür (front door), die Autotür (car door).",example:"A: Wo ist die Tür zum Hinterhof?\nB: Geh durch die Küche, dann links.\nA: Die Tür klemmt ein bisschen.\nB: Ja, drück etwas fester. Sie ist alt.",exampleSrc:"A: Where is the door to the courtyard?\nB: Go through the kitchen, then left.\nA: The door is stuck a bit.\nB: Yes, push a little harder. It's old.",funFact:"In Germany, front doors often lock automatically when closed. Forgetting your keys means calling a Schlüsseldienst (locksmith), which can cost 100 euros or more at night!"},
{type:"tip",title:"Willkommen im Mülltrennung-Land!",text:"Germany takes recycling very seriously. Most buildings have color-coded bins:\n\n- Gelbe Tonne: packaging (plastic, metal, cartons)\n- Blaue Tonne: paper and cardboard\n- Braune/Grüne Tonne: organic waste (Biomüll)\n- Schwarze/Graue Tonne: non-recyclable waste (Restmüll)\n- Glascontainer: glass (sorted by color!)\n- Pfandflaschen: bottles with deposit (return to the shop)\n\nPutting waste in the wrong bin can upset your Nachbarn. Hildi is not the only one watching!",deepDive:"The Pfand (deposit) system is uniquely German. You pay 8-25 cents extra on bottles and cans, then return them to machines in supermarkets. Some people collect Pfandflaschen from public bins as income. Mülltrennung is taught in schools and taken very seriously by most Germans."},
{type:"mc",q:"Verumius steht im Hinterhof. Was hat er in der Hand?",opts:["Einen Joghurtbecher","Eine Zeitung","Ein Glas Wasser","Einen Apfel"],ans:"Einen Joghurtbecher",hint:"Denk an die Szene am Anfang der Lektion."},
{type:"mc",q:"Wie sagt man 'neighbor (female)' auf Deutsch?",opts:["die Nachbarin","der Nachbar","die Nachbarschaft","die Nachbarn"],ans:"die Nachbarin",hint:"Weibliche Formen enden oft mit einer bestimmten Silbe."},
{type:"fb",s:"Plastik ist sehr {1} für die Natur.",a:"schädlich",opts:["schädlich","nützlich","sauber","schmutzig"],hint:"Das Gegenteil von harmlos oder hilfreich.",sSrc:"Plastic is very {1} for nature."},
{type:"fb",s:"Die Küche ist {1}. Ich habe gerade geputzt.",a:"sauber",opts:["sauber","schmutzig","schädlich","nützlich"],hint:"Das Gegenteil von schmutzig beschreibt diesen Zustand.",sSrc:"The kitchen is {1}. I just cleaned."},
{type:"mc",q:"Was gehört in die gelbe Tonne?",opts:["Plastik und Metall","Papier und Kartons","Glas und Flaschen","Obst und Gemüse"],ans:"Plastik und Metall",hint:"Diese Tonne ist für Material, das man im Supermarkt als Verpackung findet."},
{type:"fb",s:"Geh durch die {1} zum Hinterhof.",a:"Tür",opts:["Tür","Pflanze","Natur","Nachbarin"],hint:"Man öffnet und schließt sie, um einen Raum zu betreten.",sSrc:"Go through the {1} to the courtyard."},
{type:"match",pairs:[{trg:"der Müll",src:"waste/trash"},{trg:"die Pflanze",src:"plant"},{trg:"sauber",src:"clean"},{trg:"schmutzig",src:"dirty"},{trg:"nützlich",src:"useful"}]},
{type:"teach",trg:"die Mülltrennung",src:"waste separation / recycling",note:"Feminine. Compound: Müll (waste) + Trennung (separation). The cornerstone of German environmental culture.",example:"A: Was ist Mülltrennung?\nB: Man sortiert den Müll in verschiedene Tonnen.\nA: Ist das wirklich so wichtig?\nB: In Deutschland ist es Pflicht!",exampleSrc:"A: What is waste separation?\nB: You sort waste into different bins.\nA: Is that really so important?\nB: In Germany it is mandatory!",funFact:"Germany introduced the Grüner Punkt (Green Dot) system in 1991, making it one of the first countries to require manufacturers to pay for packaging recycling. Mülltrennung is taught in schools from age six."},
{type:"mc",q:"Hildi sagt: 'Mülltrennung ist sehr ... für die Umwelt.'",opts:["nützlich","schmutzig","schädlich","sauber"],ans:"nützlich",hint:"Ein positives Adjektiv, das Vorteil oder Nutzen beschreibt."},
{type:"fb",s:"Mein {1} kontrolliert die Mülltonnen jeden Morgen.",a:"Nachbar",opts:["Nachbar","Nachbarin","Natur","Müll"],hint:"Ein Mann, der im selben Gebäude wohnt wie du.",sSrc:"My {1} checks the trash bins every morning."},
{type:"drag_fill",s:"Die {1} im Garten sind {2}, aber die Schuhe sind {3}.",blanks:{"1":"Pflanzen","2":"sauber","3":"schmutzig"},pool:["Pflanzen","sauber","schmutzig","schädlich","Müll"],hint:"Erst die grünen Dinge im Boden, dann zwei gegensätzliche Adjektive.",sSrc:"The {1} in the garden are {2}, but the shoes are {3}."},
{type:"mc",q:"Verumius wirft den Joghurtbecher in den falschen Eimer. Hildi wird blass. Warum?",opts:["Recycling ist hier sehr wichtig","Der Becher ist viel zu groß","Hildi mag diesen Joghurt nicht","Es gibt nur einen einzigen Eimer"],ans:"Recycling ist hier sehr wichtig",hint:"Deutsche nehmen die Mülltrennung sehr ernst."}
]},

{id:"deu_r8l2",title:"In der Küche",icon:"🍽️",xp:15,board:true,steps:[
{type:"intro",title:"In der Küche",desc:"Hildi shows you around her kitchen and apartment. Learn the words for cutlery, dishes, and parts of the home.",goals:["12 kitchen and home vocabulary words","Articles: der, die, das with every noun","Talk about rooms and objects in a German home"]},
{type:"teach",trg:"die Gabel",src:"the fork",note:"die Gabel (feminine). Plural: die Gabeln.",example:"A: Wo ist die Gabel?\nB: Die Gabel liegt neben dem Teller.\nA: Danke! Ich brauche sie für den Salat.\nB: Hier, nimm diese Gabel.",exampleSrc:"A: Where is the fork?\nB: The fork is next to the plate.\nA: Thanks! I need it for the salad.\nB: Here, take this fork.",funFact:"The word Gabel comes from Old High German 'gabala' meaning a forked stick. Forks only became common table utensils in Germany in the 17th century."},
{type:"teach",trg:"der Löffel",src:"the spoon",note:"der Löffel (masculine). Plural: die Löffel.",example:"A: Hast du einen Löffel für mich?\nB: Ja, hier ist ein Löffel.\nA: Der ist aber groß!\nB: Das ist ein Suppenlöffel.",exampleSrc:"A: Do you have a spoon for me?\nB: Yes, here is a spoon.\nA: That one is big though!\nB: That is a soup spoon.",funFact:"Germans distinguish between Teelöffel (teaspoon), Esslöffel (tablespoon), and Suppenlöffel (soup spoon). Recipes always specify which Löffel to use."},
{type:"teach",trg:"das Messer",src:"the knife",note:"das Messer (neuter). Plural: die Messer.",example:"A: Dieses Messer ist sehr scharf.\nB: Ja, pass auf! Es ist neu.\nA: Wo hast du es gekauft?\nB: Im Geschäft am Marktplatz.",exampleSrc:"A: This knife is very sharp.\nB: Yes, be careful! It is new.\nA: Where did you buy it?\nB: At the shop on the market square.",funFact:"Solingen, a city in western Germany, is called the 'City of Blades' and has been the world capital of knife and blade production since medieval times."},
{type:"teach",trg:"der Teller",src:"the plate",note:"der Teller (masculine). Plural: die Teller.",example:"A: Kannst du die Teller auf den Tisch stellen?\nB: Wie viele Teller brauchen wir?\nA: Vier Teller, bitte.\nB: Gut, ich hole sie aus dem Schrank.",exampleSrc:"A: Can you put the plates on the table?\nB: How many plates do we need?\nA: Four plates, please.\nB: Good, I will get them from the cupboard.",funFact:"In many German households, each family member has their own designated Teller, Tasse, and Glas. Using someone else's is a minor social faux pas."},
{type:"mc",q:"Was ist 'die Gabel' auf Englisch?",opts:["the fork","the spoon","the knife","the plate"],ans:"the fork",hint:"Think of the utensil with prongs"},
{type:"fb",s:"Der {1} liegt neben dem Messer.",a:"Löffel",opts:["Löffel","Gabel","Fenster","Keller"],hint:"The rounded utensil for soup.",sSrc:"The {1} is next to the knife."},
{type:"teach",trg:"der Topf",src:"the pot",note:"der Topf (masculine). Plural: die Töpfe. Note the umlaut in plural.",example:"A: Was kochst du in dem Topf?\nB: Ich mache eine Suppe.\nA: Der Topf ist sehr groß!\nB: Ja, es gibt Suppe für alle.",exampleSrc:"A: What are you cooking in the pot?\nB: I am making a soup.\nA: The pot is very big!\nB: Yes, there is soup for everyone.",funFact:"Germans often say 'Jeder Topf findet seinen Deckel' (every pot finds its lid), meaning there is a perfect match for everyone. It is the German equivalent of 'there is someone for everyone.'"},
{type:"teach",trg:"das Geschirr",src:"the dishes",note:"das Geschirr (neuter). Used as a collective noun. No common plural form.",example:"A: Wer spült heute das Geschirr?\nB: Du bist dran! Ich habe gestern gespült.\nA: Okay, aber die Spülmaschine ist voll.\nB: Dann spül bitte mit der Hand.",exampleSrc:"A: Who is washing the dishes today?\nB: It is your turn! I washed yesterday.\nA: Okay, but the dishwasher is full.\nB: Then please wash by hand.",funFact:"'Geschirr' originally meant equipment or harness (for horses). The meaning narrowed over centuries to specifically mean tableware. Horse harness is still called 'Pferdegeschirr.'"},
{type:"teach",trg:"die Lampe",src:"the lamp",note:"die Lampe (feminine). Plural: die Lampen.",example:"A: Die Lampe in der Küche ist kaputt.\nB: Schon wieder? Ich kaufe eine neue.\nA: Nimm eine LED-Lampe.\nB: Gute Idee, die sind besser für die Umwelt.",exampleSrc:"A: The lamp in the kitchen is broken.\nB: Again? I will buy a new one.\nA: Get an LED lamp.\nB: Good idea, they are better for the environment.",funFact:"Germans are serious about lighting. Many apartments come without ceiling lamps. New tenants must buy and install their own. Moving often means packing your Lampen."},
{type:"mc",q:"Hildi kocht Suppe. Was braucht sie?",opts:["einen Topf","einen Teller","eine Gabel","ein Messer"],ans:"einen Topf",hint:"Think about what you cook soup inside"},
{type:"teach",trg:"der Stuhl",src:"the chair",note:"der Stuhl (masculine). Plural: die Stühle. Note the umlaut.",example:"A: Ist dieser Stuhl frei?\nB: Ja, setz dich! Der Stuhl ist bequem.\nA: Oh ja, sehr bequem.\nB: Den habe ich vom Flohmarkt.",exampleSrc:"A: Is this chair free?\nB: Yes, sit down! The chair is comfortable.\nA: Oh yes, very comfortable.\nB: I got it from the flea market.",funFact:"Germans love their flea markets (Flohmärkte). Buying second-hand furniture, especially Stühle and Tische, is extremely common and not considered cheap but rather environmentally conscious."},
{type:"teach",trg:"das Fenster",src:"the window",note:"das Fenster (neuter). Plural: die Fenster.",example:"A: Kannst du das Fenster öffnen?\nB: Ja, es ist warm hier drin.\nA: Frische Luft tut gut.\nB: In fünf Minuten mache ich es wieder zu.",exampleSrc:"A: Can you open the window?\nB: Yes, it is warm in here.\nA: Fresh air feels good.\nB: In five minutes I will close it again.",funFact:"Germans practice 'Stoßlüften': opening windows wide for 5 to 10 minutes to exchange all the air, then closing them. Leaving windows cracked (gekippt) all day is considered wasteful and bad for heating."},
{type:"teach",trg:"der Keller",src:"the basement",note:"der Keller (masculine). Plural: die Keller.",example:"A: Wo sind die alten Bücher?\nB: Die sind im Keller.\nA: Ist der Keller groß?\nB: Ja, jeder Mieter hat seinen eigenen Keller.",exampleSrc:"A: Where are the old books?\nB: They are in the basement.\nA: Is the basement big?\nB: Yes, every tenant has their own basement.",funFact:"In German apartment buildings, each tenant typically gets their own locked Kellerabteil (basement compartment) for storage. It is included in the rent and is standard in almost all buildings."},
{type:"fb",s:"Mach bitte das {1} auf, es ist warm.",a:"Fenster",opts:["Fenster","Geschirr","Keller","Stuhl"],hint:"You open this to let fresh air in.",sSrc:"Please open the {1}, it is warm."},
{type:"teach",trg:"das Erdgeschoss",src:"the ground floor",note:"das Erdgeschoss (neuter). Literally: earth + floor. Abbreviated EG.",example:"A: In welchem Stockwerk wohnst du?\nB: Ich wohne im Erdgeschoss.\nA: Oh, das ist praktisch.\nB: Ja, keine Treppen!",exampleSrc:"A: On which floor do you live?\nB: I live on the ground floor.\nA: Oh, that is practical.\nB: Yes, no stairs!",funFact:"In Germany the Erdgeschoss is floor 0, not floor 1. The first floor above ground is called 'erstes Obergeschoss' (1. OG). This confuses many English speakers in elevators."},
{type:"teach",trg:"das Stockwerk",src:"the floor / story (of a building)",note:"das Stockwerk (neuter). Plural: die Stockwerke. Synonym: die Etage.",example:"A: Wie viele Stockwerke hat das Haus?\nB: Es hat vier Stockwerke.\nA: Und Hildi wohnt im dritten?\nB: Genau, im dritten Stockwerk.",exampleSrc:"A: How many floors does the building have?\nB: It has four floors.\nA: And Hildi lives on the third?\nB: Exactly, on the third floor.",funFact:"The word Stockwerk comes from 'Stock' (stick/staff). Medieval builders marked each floor level with a staff during construction. The marks became the name for the floors themselves."},
{type:"teach",trg:"die Etage",src:"the floor / story (of a building)",note:"Feminine noun. Plural: die Etagen. Borrowed from French.\nSynonym of Stockwerk but more common in everyday speech.",example:"A: Auf welcher Etage wohnst du?\nB: Auf der zweiten Etage.\nA: Gibt es einen Aufzug?\nB: Nein, leider nur Treppen.",exampleSrc:"A: On which floor do you live?\nB: On the second floor.\nA: Is there an elevator?\nB: No, unfortunately only stairs.",funFact:"Etage comes from French 'etage.' In everyday German, Etage and Stockwerk are interchangeable, but Etage sounds slightly more elegant. Department stores use Etage: 'Damenabteilung, dritte Etage.'"},
{type:"teach",trg:"der Flur",src:"the hallway / corridor",note:"Masculine noun. Plural: die Flure.\nThe space inside an apartment connecting rooms.",example:"A: Wo hängt die Jacke?\nB: Im Flur, neben der Tür.\nA: Der Flur ist aber dunkel.\nB: Ja, die Lampe ist kaputt.",exampleSrc:"A: Where is the jacket hanging?\nB: In the hallway, next to the door.\nA: The hallway is quite dark.\nB: Yes, the lamp is broken.",funFact:"In traditional German apartments, the Flur is the first room you enter. Germans always take off their shoes in the Flur. Keeping outdoor shoes on inside is a social faux pas in most German homes."},
{type:"teach",trg:"das Brett",src:"the board / plank / shelf",note:"Neuter noun. Plural: die Bretter.\nUsed in many compounds: Schneidebrett (cutting board), Schwarzes Brett (notice board).",example:"A: Wo ist das Schneidebrett?\nB: Das Brett liegt auf dem Tisch.\nA: Ah, danke. Ich schneide das Brot.\nB: Pass auf, das Brett rutscht leicht.",exampleSrc:"A: Where is the cutting board?\nB: The board is on the table.\nA: Ah, thanks. I will cut the bread.\nB: Be careful, the board slides easily.",funFact:"'Schwarzes Brett' (black board) is the German term for a notice board or bulletin board. Every university, office, and apartment building has one. 'Brettspiel' means board game."},
{type:"teach",trg:"stellen",src:"to put / to place (upright)",note:"Regular: ich stelle, du stellst. Always implies standing position.\nLegen = put down flat. Stellen = put upright.",example:"A: Wo soll ich die Teller stellen?\nB: Stell sie bitte in den Schrank.\nA: Und die Gläser?\nB: Die auch. Stell alles in den Schrank.",exampleSrc:"A: Where should I put the plates?\nB: Put them in the cupboard, please.\nA: And the glasses?\nB: Those too. Put everything in the cupboard.",funFact:"German has different verbs for putting things: stellen (put upright, like a bottle), legen (put flat, like a book), setzen (put sitting), hängen (put hanging). English just uses 'put' for all of them!"},
{type:"teach",trg:"fernsehen",src:"to watch TV",note:"Separable verb: ich sehe fern, du siehst fern.\nFrom fern (far) + sehen (to see) = 'far-seeing'.\nder Fernseher = the TV set.",example:"A: Was machst du heute Abend?\nB: Ich sehe fern. Es gibt einen guten Film.\nA: Welchen Fernseher hast du?\nB: Einen alten, aber er funktioniert gut.",exampleSrc:"A: What are you doing tonight?\nB: I am watching TV. There is a good movie on.\nA: Which TV do you have?\nB: An old one, but it works well.",funFact:"'Fernsehen' literally means 'far-seeing.' The first German TV broadcast was in 1935. Today, ARD and ZDF are public channels funded by the Rundfunkbeitrag (broadcasting fee) that every household pays: 18.36 euros per month."},
{type:"tip",title:"Abendbrot: Die deutsche Küchentradition",text:"Germans traditionally eat a cold dinner called Abendbrot (evening bread). The family gathers in the kitchen, sets out bread, cheese, cold cuts, and pickles.\n\nNo cooking needed. Everything goes on a Teller with a Messer and Gabel.\n\nThis tradition is why German kitchens often have a small Tisch with Stühle for casual family meals, separate from a formal Esszimmer (dining room)."},
{type:"mc",q:"Was ist das Erdgeschoss?",opts:["The ground floor","The basement","The attic","The second floor"],ans:"The ground floor",hint:"Think about the literal meaning: Erd = earth"},
{type:"mc",q:"Hildi sagt: 'Das Geschirr ist schmutzig.' Was meint sie?",opts:["The dishes are dirty","The kitchen is dirty","The glass is broken","The spoon is missing"],ans:"The dishes are dirty",hint:"Geschirr is the collective word for plates, cups, bowls"},
{type:"fb",s:"Jeder Mieter hat seinen eigenen {1}.",a:"Keller",opts:["Keller","Stuhl","Löffel","Teller"],hint:"The storage space below the building.",sSrc:"Every tenant has their own {1}."},
{type:"mc",q:"Hildis Haus hat vier Etagen. Was ist ein anderes Wort dafür?",opts:["Stockwerke","Fenster","Keller","Stühle"],ans:"Stockwerke",hint:"Each level of a building from ground to roof."},
{type:"match",pairs:[{trg:"die Gabel",src:"the fork"},{trg:"der Löffel",src:"the spoon"},{trg:"das Messer",src:"the knife"},{trg:"der Teller",src:"the plate"},{trg:"der Topf",src:"the pot"},{trg:"das Geschirr",src:"the dishes"}]},
{type:"match",pairs:[{trg:"die Lampe",src:"the lamp"},{trg:"der Stuhl",src:"the chair"},{trg:"das Fenster",src:"the window"},{trg:"der Keller",src:"the basement"},{trg:"das Erdgeschoss",src:"the ground floor"},{trg:"das Stockwerk",src:"the floor/story"}]},
{type:"mc",q:"Du brauchst etwas zum Schneiden. Was nimmst du?",opts:["das Messer","die Gabel","den Löffel","den Teller"],ans:"das Messer",hint:"The sharp tool used for cutting food"},
{type:"fb",s:"Setz dich auf den {1}, er ist sehr bequem.",a:"Stuhl",opts:["Stuhl","Teller","Topf","Keller"],hint:"The piece of furniture you sit on.",sSrc:"Sit down on the {1}, it is very comfortable."},
{type:"drag_fill",s:"In der Küche stehen ein {1}, vier {2} und eine {3}.",blanks:{"1":"Topf","2":"Teller","3":"Lampe"},pool:["Topf","Teller","Lampe","Keller","Messer"],hint:"Think about what belongs in a kitchen.",sSrc:"In the kitchen there is a {1}, four {2}, and a {3}."},
{type:"teach",trg:"sortieren",src:"to sort",note:"Regular: ich sortiere. Müll sortieren = to sort trash.",example:"A: Wie sortiert man den Müll richtig?\nB: Plastik in den gelben Sack, Papier in die blaue Tonne.\nA: Und Glas?",exampleSrc:"A: How do you sort the trash correctly?\nB: Plastic in the yellow bag, paper in the blue bin.\nA: And glass?",funFact:"Germans sort trash into up to 6 categories. Getting it wrong can earn you a stern look from your neighbors."},
{type:"teach",trg:"niedrig",src:"low",note:"Opposite of hoch (high). Niedrige Preise = low prices.",example:"A: Ist die Miete hier niedrig?\nB: Nein, Berlin wird immer teurer.\nA: Das stimmt leider.",exampleSrc:"A: Is the rent low here?\nB: No, Berlin is getting more expensive.\nA: That is unfortunately true.",funFact:"Niedrig comes from Old German 'nidar' (down). Related to English 'nether' as in Netherlands (low lands)."}
]}
,

{id:"deu_r8l3",title:"Mülltrennung",icon:"📊",xp:15,board:true,steps:[
{type:"intro",title:"Mülltrennung",desc:"Hildi pulls out her recycling chart and gives a full lecture on household waste sorting. Mia arrives mid-lesson. Learn household chore words, and get your first formal look at Wechselpräpositionen and comparatives.",goals:["10 household vocabulary words","Wechselpräpositionen: accusative vs. dative","Comparatives with -er + als"]},
{type:"teach",trg:"der Haushalt",src:"the household",note:"der Haushalt (masculine). Plural: die Haushalte.",example:"A: Wer macht den Haushalt bei euch?\nB: Hildi und ich teilen alles.\nA: Das ist gut so.\nB: Ja, ein guter Haushalt braucht Teamarbeit.",exampleSrc:"A: Who does the housework at your place?\nB: Hildi and I share everything.\nA: That is good.\nB: Yes, a good household needs teamwork.",funFact:"Haushalt also means 'budget' in politics. The Bundeshaushalt is Germany's federal budget. Same word, very different context."},
{type:"teach",trg:"die Heizung",src:"the heating",note:"die Heizung (feminine). Plural: die Heizungen.",example:"A: Ist dir kalt? Ich mache die Heizung an.\nB: Ja bitte, es ist so kalt heute.\nA: Die Heizung braucht ein paar Minuten.\nB: Kein Problem, ich warte.",exampleSrc:"A: Are you cold? I will turn on the heating.\nB: Yes please, it is so cold today.\nA: The heating needs a few minutes.\nB: No problem, I will wait.",funFact:"German tenants must pay a yearly Heizkostenabrechnung (heating cost bill). Landlords are required by law to provide heating from October 1 to April 30."},
{type:"teach",trg:"die Reinigung",src:"the cleaning",note:"die Reinigung (feminine). Also means 'dry cleaner' (die chemische Reinigung).",example:"A: Heute ist Reinigung dran.\nB: Die ganze Wohnung?\nA: Ja, Küche und Bad zuerst.\nB: Dann fange ich mit dem Bad an.",exampleSrc:"A: Today it is time for cleaning.\nB: The whole apartment?\nA: Yes, kitchen and bathroom first.\nB: Then I will start with the bathroom.",funFact:"Many German apartment buildings have a Putzplan (cleaning schedule) in the hallway. Tenants take turns cleaning the shared staircase. Missing your turn is a serious social offense."},
{type:"teach",trg:"die Wäsche",src:"the laundry",note:"die Wäsche (feminine). No common plural. Covers both dirty and clean laundry.",example:"A: Wo ist mein blaues Hemd?\nB: Das ist noch in der Wäsche.\nA: Kannst du die Wäsche heute waschen?\nB: Ja, ich hänge sie dann auf den Balkon.",exampleSrc:"A: Where is my blue shirt?\nB: It is still in the laundry.\nA: Can you wash the laundry today?\nB: Yes, I will hang it on the balcony then.",funFact:"Most German apartments do not have dryers. Hanging laundry on a Wäscheständer (drying rack) or the balcony is standard. Some buildings ban hanging laundry on balconies facing the street."},
{type:"mc",q:"Die Wohnung ist schmutzig. Was brauchen wir?",opts:["eine Reinigung","eine Heizung","eine Wäsche","einen Haushalt"],ans:"eine Reinigung",hint:"The word for the act of making things clean"},
{type:"teach",trg:"aufräumen",src:"to tidy up",note:"aufräumen (separable). Ich räume auf. Past: aufgeräumt.",example:"A: Hildi, dein Zimmer ist so unordentlich!\nB: Ich weiß. Ich räume später auf.\nA: Das sagst du immer!\nB: Okay, okay, ich räume jetzt auf.",exampleSrc:"A: Hildi, your room is so messy!\nB: I know. I will tidy up later.\nA: You always say that!\nB: Okay, okay, I will tidy up now.",funFact:"Aufräumen is one of the first verbs German children learn. 'Aufräumen!' (Tidy up!) is a one-word command heard in every German household with kids."},
{type:"teach",trg:"putzen",src:"to clean",note:"putzen (regular). Ich putze. Past: geputzt. Stronger than aufräumen: scrubbing, not just tidying.",example:"A: Wer putzt heute das Bad?\nB: Ich putze das Bad, du putzt die Küche.\nA: Das ist fair.\nB: Hildi putzt nie. Das stört mich.",exampleSrc:"A: Who is cleaning the bathroom today?\nB: I clean the bathroom, you clean the kitchen.\nA: That is fair.\nB: Hildi never cleans. That bothers me.",funFact:"Kehrwoche (sweeping week) is a tradition in Swabia where residents must sweep the sidewalk and staircase on their assigned week. Neglecting it can lead to actual complaints from neighbors."},
{type:"teach",trg:"aufmachen",src:"to open",note:"aufmachen (separable). Ich mache auf. Past: aufgemacht. Casual synonym of öffnen.",example:"A: Mach bitte die Tür auf!\nB: Moment, ich komme.\nA: Mia steht draußen.\nB: Oh, ich mache sofort auf!",exampleSrc:"A: Please open the door!\nB: One moment, I am coming.\nA: Mia is standing outside.\nB: Oh, I will open right away!",funFact:"Aufmachen is the everyday word. Öffnen sounds more formal. A shop sign says 'Geöffnet' (open), never 'Aufgemacht.' But at home you always say 'Mach die Tür auf.'"},
{type:"teach",trg:"zumachen",src:"to close",note:"zumachen (separable). Ich mache zu. Past: zugemacht. Casual synonym of schließen.",example:"A: Mach bitte das Fenster zu.\nB: Warum? Es ist so warm.\nA: Hildi sagt, die Heizung läuft.\nB: Ach so. Ich mache es zu.",exampleSrc:"A: Please close the window.\nB: Why? It is so warm.\nA: Hildi says the heating is running.\nB: Oh I see. I will close it.",funFact:"Zumachen literally means 'to make shut.' Germans pair auf/zu for open/close in casual speech: aufmachen/zumachen, aufdrehen/zudrehen (twist open/shut for taps and bottles)."},
{type:"fb",s:"Ich {1} heute die ganze Wohnung auf.",a:"räume",opts:["räume","putze","mache","hänge"],hint:"The separable verb for tidying, minus its prefix.",sSrc:"I {1} the whole apartment up today."},
{type:"tip",title:"Wechselpräpositionen: Richtung oder Ort?",text:"Nine prepositions change case depending on meaning:\nan, auf, hinter, in, neben, über, unter, vor, zwischen\n\nAkkusativ = direction (Wohin? Where to?)\nIch stelle den Eimer IN DEN Flur. (into the hallway)\n\nDativ = location (Wo? Where?)\nDer Eimer steht IM Flur. (in the hallway)\n\nKey contractions:\nin + dem = im (location)\nin + das = ins (direction)\nan + dem = am (location)\nan + das = ans (direction)",deepDive:"Think of it this way: if something is MOVING to a new position, use accusative. If something is STAYING in one position, use dative.\n\nVerbs that signal direction (accusative): stellen, legen, hängen, setzen, stecken\nVerbs that signal location (dative): stehen, liegen, hängen, sitzen, stecken\n\nNotice hängen and stecken appear in both lists. Context determines the case:\nIch hänge das Bild an die Wand. (I hang the picture onto the wall. Direction.)\nDas Bild hängt an der Wand. (The picture hangs on the wall. Location.)"},
{type:"teach",trg:"hängen",src:"to hang",note:"hängen (mixed). Direction: Ich hänge (acc). Location: Es hängt (dat). Past: gehängt (active) / gehangen (state).",example:"A: Wo soll ich die Wäsche hängen?\nB: Häng sie auf den Balkon.\nA: Die Wäsche hängt schon auf dem Balkon.\nB: Dann häng sie ins Bad.",exampleSrc:"A: Where should I hang the laundry?\nB: Hang it onto the balcony.\nA: The laundry is already hanging on the balcony.\nB: Then hang it in the bathroom.",funFact:"Hängen is the textbook example of Wechselpräpositionen. It even changes its past participle: gehängt when YOU hang something, gehangen when something just hangs there."},
{type:"teach",trg:"stören",src:"to disturb",note:"stören (regular). Ich störe. Past: gestört. 'Das stört mich' = that bothers me.",example:"A: Störe ich gerade?\nB: Nein, komm rein, Mia!\nA: Hildi gibt eine Müllvorlesung.\nB: Ha! Das stört mich nicht, ich höre gerne zu.",exampleSrc:"A: Am I disturbing right now?\nB: No, come in, Mia!\nA: Hildi is giving a trash lecture.\nB: Ha! That does not bother me, I like to listen.",funFact:"'Bitte nicht stören' (please do not disturb) appears on hotel doors across Germany. Stören is also used in electronics: Störung means interference or malfunction. 'Wir bitten um Entschuldigung für die Störung' is the classic German train delay announcement."},
{type:"mc",q:"Hildi hängt die Wäsche auf den Balkon. Warum Akkusativ?",opts:["Die Wäsche bewegt sich dorthin","Die Wäsche ist schon dort","Der Balkon ist maskulin","Hängen braucht immer Akkusativ"],ans:"Die Wäsche bewegt sich dorthin",hint:"Think about movement versus staying put"},
{type:"fb",s:"Die Wäsche hängt schon auf {1} Balkon.",a:"dem",opts:["dem","den","der","das"],hint:"Location, not direction: which case.",sSrc:"The laundry is already hanging on {1} balcony."},
{type:"mc",q:"Ich stelle den Eimer ... Flur. (direction)",opts:["in den","im","in der","ins"],ans:"in den",hint:"Direction needs accusative: der Flur becomes ..."},
{type:"tip",title:"Komparativ: Vergleichen mit -er + als",text:"To compare two things in German, add -er to the adjective:\nschnell (fast) becomes schneller (faster)\nklein (small) becomes kleiner (smaller)\n\nMany short adjectives add an umlaut:\ngroß becomes größer\nalt becomes älter\nkalt becomes kälter\nwarm becomes wärmer\n\nIrregular forms (memorize these):\ngut becomes besser\nviel becomes mehr\ngern becomes lieber\nhoch becomes höher\n\nUse 'als' for 'than':\nHildi ist ordentlicher als Mia.",deepDive:"The comparative form works like English '-er than' but is more consistent. Almost every German adjective uses the -er ending, whereas English switches between '-er' and 'more' depending on syllable count.\n\nComparatives can also be used as adjectives before nouns. Then they take normal adjective endings too:\nein größerer Mülleimer (a bigger trash can)\neine bessere Idee (a better idea)\n\nThe umlaut rule applies to most one-syllable adjectives with a, o, or u. But not all: toll stays toller, bunt stays bunter."},
{type:"mc",q:"Mia ist schnell. Hildi ist ... als Mia.",opts:["schneller","schnell","am schnellsten","mehr schnell"],ans:"schneller",hint:"Add the comparative ending to the adjective"},
{type:"fb",s:"Diese Wohnung ist {1} als meine alte Wohnung.",a:"größer",opts:["größer","groß","am größten","mehr groß"],hint:"The comparative of groß, with umlaut.",sSrc:"This apartment is {1} than my old apartment."},
{type:"mc",q:"Aufräumen ist gut, aber putzen ist ...",opts:["besser","guter","mehr gut","am besten"],ans:"besser",hint:"The irregular comparative of 'gut'"},
{type:"drag_fill",s:"Stell den Müll {1} die Tonne. Der Müll steht jetzt {2} der Tonne.",blanks:{"1":"in","2":"in"},pool:["in","auf","an","neben","unter"],hint:"Same preposition, but the case changes: direction first, then location.",sSrc:"Put the rubbish {1} the bin. The rubbish is now {2} the bin."},
{type:"mc",q:"Die Heizung läuft. Mach bitte das Fenster ...",opts:["zu","auf","an","ab"],ans:"zu",hint:"The opposite of aufmachen"},
{type:"match",pairs:[{trg:"der Haushalt",src:"the household"},{trg:"die Heizung",src:"the heating"},{trg:"die Reinigung",src:"the cleaning"},{trg:"die Wäsche",src:"the laundry"},{trg:"aufräumen",src:"to tidy up"},{trg:"putzen",src:"to clean"}]},
{type:"match",pairs:[{trg:"aufmachen",src:"to open"},{trg:"zumachen",src:"to close"},{trg:"hängen",src:"to hang"},{trg:"stören",src:"to disturb"},{trg:"der Haushalt",src:"the household"},{trg:"die Wäsche",src:"the laundry"}]},
{type:"drag_fill",s:"Hildi {1} die Küche, und ich {2} das Wohnzimmer {3}.",blanks:{"1":"putzt","2":"räume","3":"auf"},pool:["putzt","räume","auf","mache","zu"],hint:"Two different cleaning verbs: scrubbing vs. tidying. One is separable.",sSrc:"Hildi {1} the kitchen, and I {2} the living room {3}."},
{type:"fb",s:"Mia sagt: 'Störe ich?' Hildi antwortet: 'Nein, du {1} nicht.'",a:"störst",opts:["störst","störe","stört","gestört"],hint:"Second person singular present of stören.",sSrc:"Mia says: 'Am I disturbing?' Hildi answers: 'No, you {1} not.'"}
]}
,

// U8 L4: Besser als vorher (Grammar lesson)
// Grammar: #18 Superlative, #8 Nebensatz weil, #11 Subordinate word order
// Reinforces: #7 Wechselpräp, #17 Comparative from L3
// 8 new adjectives + 3 grammar tip cards + verb_table + 6+ combo quizzes
{id:"deu_r8l4",title:"Besser als vorher",icon:"\uD83D\uDCD0",xp:20,board:true,steps:[
{type:"intro",title:"Besser als vorher",desc:"Hildi's recycling lecture continues. Today she explains WHY things matter, compares everything to everything, and declares the best and worst habits. Time to learn superlatives, weil-clauses, and subordinate word order.",goals:["Form superlatives (am besten, der beste)","Build weil-clauses with verb-final word order","Combine comparatives and superlatives in real sentences"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-kitchen",trg:"Hildi steht in der Küche. Auf dem Tisch liegt eine Liste: 'Regeln für den Müll.' Verumius liest die erste Regel und schluckt.",src:"Hildi stands in the kitchen. On the table lies a list: 'Rules for the rubbish.' Verumius reads the first rule and gulps."},
{type:"story",speaker:"hildi",mood:"passionate",trg:"Recycling ist wichtiger als du denkst, Verumius. Und frisches Essen ist am besten, weil es weniger Verpackung hat.",src:"Recycling is more important than you think, Verumius. And fresh food is the best, because it has less packaging."},
{type:"teach",trg:"hart",src:"hard",note:"Comparative: härter. Superlative: am härtesten.",example:"A: Ist Glas hart?\nB: Ja, Glas ist härter als Plastik.",exampleSrc:"A: Is glass hard?\nB: Yes, glass is harder than plastic.",funFact:"'Hart' and English 'hard' are the same word. Both come from Proto-Germanic 'harduz.' Over 1,000 years apart and still twins."},
{type:"teach",trg:"schwierig",src:"difficult",note:"No umlaut in comparative: schwieriger, am schwierigsten.",example:"A: Ist Mülltrennung schwierig?\nB: Am Anfang ist es schwierig, aber dann wird es leichter.",exampleSrc:"A: Is waste separation difficult?\nB: At the beginning it is difficult, but then it gets easier.",funFact:"Germans rarely say 'schwer' for tasks. 'Schwierig' is for mental difficulty. 'Schwer' is for physical weight. A box is schwer. A grammar rule is schwierig."},
{type:"teach",trg:"stark",src:"strong",note:"Comparative: stärker. Superlative: am stärksten. Umlaut!",example:"A: Ist der Müllgeruch stark?\nB: Ja, heute ist er stärker als gestern.",exampleSrc:"A: Is the rubbish smell strong?\nB: Yes, today it is stronger than yesterday.",funFact:"'Stark' also means 'great/awesome' in slang. 'Das war echt stark!' = That was really awesome! Like English 'strong move.'"},
{type:"teach",trg:"weich",src:"soft",note:"Comparative: weicher. Superlative: am weichsten.",example:"A: Ist das Brot noch weich?\nB: Nein, es ist hart. Wir brauchen frisches.",exampleSrc:"A: Is the bread still soft?\nB: No, it is hard. We need fresh bread.",funFact:"'Weich' comes from the same root as English 'weak.' The original meaning was 'yielding.' Over time English shifted to 'lacking strength' while German kept 'soft to the touch.'"},
{type:"mc",q:"Hildi says the bread is not 'weich' anymore. What does she mean?",opts:["It is not soft anymore","It is not warm anymore","It is not sweet anymore","It is not fresh anymore"],ans:"It is not soft anymore",hint:"This adjective describes texture, not temperature or taste."},
{type:"teach",trg:"scharf",src:"sharp / spicy",note:"Two meanings! Comparative: schärfer. Umlaut in comparative.",example:"A: Ist die Soße scharf?\nB: Ja, sie ist schärfer als gestern.",exampleSrc:"A: Is the sauce spicy?\nB: Yes, it is spicier than yesterday.",funFact:"A knife is 'scharf' (sharp). Chili is 'scharf' (spicy). A photo is 'scharf' (in focus). And a person can be 'scharf' (attractive). One word, four jobs."},
{type:"teach",trg:"frisch",src:"fresh",note:"Comparative: frischer. Superlative: am frischesten.",example:"A: Kaufst du frisches Gemüse?\nB: Ja, frisches Gemüse ist am besten.",exampleSrc:"A: Do you buy fresh vegetables?\nB: Yes, fresh vegetables are the best.",funFact:"'Frisch' and English 'fresh' are the same word. German kept the original spelling. English added an 'e' and softened the 'sch' to 'sh.'"},
{type:"teach",trg:"süß",src:"sweet",note:"Comparative: süßer. Superlative: am süßesten.",example:"A: Ist der Kuchen süß?\nB: Ja, er ist süßer als die Schokolade!",exampleSrc:"A: Is the cake sweet?\nB: Yes, it is sweeter than the chocolate!",funFact:"Germans call cute things 'süß' too. A baby is süß. A puppy is süß. Even a good idea can be 'süß.' Exactly like English 'sweet!'"},
{type:"teach",trg:"sauer",src:"sour",note:"Comparative: saurer. Superlative: am sauersten.",example:"A: Ist die Zitrone sauer?\nB: Ja, sie ist am sauersten von allen Früchten.",exampleSrc:"A: Is the lemon sour?\nB: Yes, it is the sourest of all fruits.",funFact:"'Sauer' also means 'angry' in German. 'Er ist sauer auf mich' = He is angry at me. And 'Sauerbraten' is a famous pot roast marinated in vinegar. Sour meat!"},
{type:"mc",q:"Which word describes both a knife and a chili pepper?",opts:["hart","scharf","stark","frisch"],ans:"scharf",hint:"Think of the word that means both 'sharp' and 'spicy.'"},
{type:"tip",title:"Superlative: am ...sten",text:"To say something is THE MOST or THE BEST:\n\nam + STEM + sten\n\nschnell: am schnellsten (the fastest)\nhart: am härtesten (the hardest)\nfrisch: am frischesten (the freshest)\n\nWith articles (before a noun):\nder/die/das + STEM + ste\n\nder schnellste Zug (the fastest train)\ndie frischeste Orange (the freshest orange)\n\nIrregulars you must memorize:\ngut: am besten (the best)\nviel: am meisten (the most)\ngern: am liebsten (most gladly)",deepDive:"When the stem ends in -t, -d, -s, -ß, -z, add an extra -e- before -sten for pronunciation:\nhärt-esten, süß-esten, frisch-esten.\n\nWith articles, the adjective takes declension endings:\nder beste Müll (nom masc)\ndie beste Idee (nom fem)\ndas beste Essen (nom neut)\nden besten Kuchen (acc masc)"},
{type:"verb_table",title:"Irregular Comparatives and Superlatives",groups:[{label:"Must-know irregulars",rows:[{pronoun:"gut",form:"besser",src:"am besten"},{pronoun:"viel",form:"mehr",src:"am meisten"},{pronoun:"gern",form:"lieber",src:"am liebsten"},{pronoun:"hoch",form:"höher",src:"am höchsten"},{pronoun:"nah",form:"näher",src:"am nächsten"},{pronoun:"groß",form:"größer",src:"am größten"}]},{label:"Umlaut comparatives (a/o/u get ä/ö/ü)",rows:[{pronoun:"alt",form:"älter",src:"am ältesten"},{pronoun:"stark",form:"stärker",src:"am stärksten"},{pronoun:"hart",form:"härter",src:"am härtesten"},{pronoun:"scharf",form:"schärfer",src:"am schärfsten"},{pronoun:"kalt",form:"kälter",src:"am kältesten"},{pronoun:"warm",form:"wärmer",src:"am wärmsten"}]}],note:"Many one-syllable adjectives with a/o/u take umlaut in comparative AND superlative. The irregulars (gut/viel/gern) must simply be memorized."},
{type:"mc",q:"What is the superlative of 'gut'?",opts:["am gusten","am bessten","am besten","am gutsten"],ans:"am besten",hint:"This is completely irregular. Think of English 'good, better, best.'"},
{type:"fb",s:"Frisches Gemüse ist {1} als Dosengemüse.",a:["besser"],opts:["besser","bester","am besten","gut"],hint:"You need the comparative form here because 'als' follows.",sSrc:"Fresh vegetables are {1} than tinned vegetables."},
{type:"fb",s:"Die Zitrone ist {1} von allen Früchten.",a:["am sauersten"],opts:["am sauersten","saurer","sauer","am saueren"],hint:"You need the superlative form with 'am ... sten.'",sSrc:"The lemon is {1} of all fruits."},
{type:"tip",title:"weil: Because + Verb to the End",text:"In German, 'weil' (because) sends the verb to the END of the clause.\n\nMain clause: Das Essen ist frisch.\nWith weil: ..., weil das Essen frisch ist.\n\nThe verb 'ist' jumps to the end!\n\nMore examples:\nIch trenne den Müll, weil es wichtig ist.\nHildi ist sauer, weil Verumius falsch sortiert.\nDas Brot ist hart, weil es alt ist.",deepDive:"What happens with separable verbs?\nThe prefix stays attached in weil-clauses:\n\nMain: Verumius räumt auf.\nWith weil: ..., weil Verumius aufräumt.\n\nThe separable verb reunites at the end! This is true for ALL subordinate clauses (weil, dass, wenn, ob)."},
{type:"mc",q:"'Ich kaufe frisches Brot, weil ...' Which ending is correct?",opts:["weil das alte Brot ist hart","weil das alte Brot hart ist","weil hart ist das alte Brot","weil ist das alte Brot hart"],ans:"weil das alte Brot hart ist",hint:"After 'weil,' the conjugated verb moves to the very end."},
{type:"fb",s:"Hildi ist sauer, weil Verumius den Müll falsch {1}.",a:["sortiert"],opts:["sortiert","sortieren","sortiert hat","hat sortiert"],hint:"The verb goes to the end of the weil-clause in present tense.",sSrc:"Hildi is annoyed because Verumius {1} the rubbish incorrectly."},
{type:"tip",title:"Subordinate Clause Word Order",text:"After conjunctions like weil, dass, wenn, ob:\n\nConjunction + Subject + ... + VERB (at the end)\n\nNormal: Plastik gehört nicht in den Biomüll.\nSubordinate: ..., weil Plastik nicht in den Biomüll gehört.\n\nNormal: Er räumt die Küche auf.\nSubordinate: ..., weil er die Küche aufräumt.\n\nThe verb always sits at the very end. Separable prefixes rejoin their verb.",deepDive:"When the subordinate clause comes FIRST, the main clause verb comes immediately after:\n\nWeil es regnet, bleibe ich zu Hause.\n(Because it is raining, I stay at home.)\n\nThe pattern: Subordinate clause (verb-final), VERB (main clause), rest.\nThis is called 'Verb-Zweit' (verb-second): the main verb is always in position 2."},
{type:"drag_fill",s:"Hildi sagt, dass frisches Gemüse {1} als {2} ist.",blanks:{"1":"besser","2":"Dosengemüse"},pool:["besser","Dosengemüse","ist","gut","als"],hint:"After 'dass,' build the comparison and put the verb at the end.",sSrc:"Hildi says that fresh vegetables are {1} than {2}."},
{type:"mc",q:"'Weil Plastik nicht in den Biomüll gehört, ...' What is happening with 'gehört' here?",opts:["It is at the start of the clause","It is in the normal second position","It is at the very end of the weil-clause","It has been removed"],ans:"It is at the very end of the weil-clause",hint:"In subordinate clauses, the verb always moves to one specific position."},
{type:"fb",s:"Das ist der {1} Müll in der ganzen Stadt.",a:["schlimmste"],opts:["schlimmste","schlimmer","am schlimmsten","schlimm"],hint:"Before a noun with 'der,' you need the superlative adjective with an -ste ending.",sSrc:"That is the {1} rubbish in the whole city."},
{type:"mc",q:"Verumius asks: 'Warum trennst du den Müll?' Hildi answers: 'Weil es ...'",opts:["Weil es ist wichtig für die Natur","Weil es wichtig für die Natur ist","Weil wichtig es für die Natur ist","Weil für die Natur es wichtig ist"],ans:"Weil es wichtig für die Natur ist",hint:"After weil, subject first, then everything else, verb at the very end."},
{type:"drag_fill",s:"Mülltrennung ist am {1}, weil die Umwelt am {2} ist.",blanks:{"1":"wichtigsten","2":"wichtigsten"},pool:["wichtigsten","wichtiger","wichtig","am"],hint:"Both blanks need the same superlative form. Think: 'the most important.'",sSrc:"Waste separation is the {1} important, because the environment is the {2} important."},
{type:"mc",q:"Which sentence correctly combines a comparative with a weil-clause?",opts:["Frisches Brot ist besser, weil es weicher ist.","Frisches Brot ist besser, weil es ist weicher.","Frisches Brot besser ist, weil es weicher ist.","Frisches Brot ist besser, weil weicher es ist."],ans:"Frisches Brot ist besser, weil es weicher ist.",hint:"Main clause has normal word order. The weil-clause puts the verb at the end."},
{type:"fb",s:"Die Soße ist heute {1} als gestern.",a:["schärfer"],opts:["schärfer","scharf","am schärfsten","scharfer"],hint:"You need the comparative with umlaut because 'als' follows.",sSrc:"The sauce is {1} today than yesterday."},
{type:"mc",q:"Hildi says: 'Glas gehört in den Glascontainer, weil ...' How does this clause end?",opts:["...weil man es recyceln kann.","...weil man kann es recyceln.","...weil kann man es recyceln.","...weil es recyceln man kann."],ans:"...weil man es recyceln kann.",hint:"In the weil-clause, the modal verb goes to the very end, after the infinitive."},
{type:"match",pairs:[{trg:"am besten",src:"the best"},{trg:"am härtesten",src:"the hardest"},{trg:"am süßesten",src:"the sweetest"},{trg:"am schärfsten",src:"the sharpest/spiciest"},{trg:"am stärksten",src:"the strongest"},{trg:"am sauersten",src:"the sourest"}]},
{type:"drag_fill",s:"Verumius stellt die Flasche {1} den Glascontainer, weil Glas {2} als Plastik {3}.",blanks:{"1":"in","2":"besser","3":"ist"},pool:["in","auf","besser","gut","ist","hat"],hint:"Direction into a container (Wechselpräp with accusative), then comparative, then verb-final in the weil-clause.",sSrc:"Verumius puts the bottle {1} the glass container because glass is {2} than plastic {3}."}
]}
,

// U8 L5: Abendbrot - Vocab + review
{id:"deu_r8l5",title:"Abendbrot",icon:"\uD83E\uDDC0",xp:15,board:true,steps:[
{type:"intro",title:"Abendbrot",desc:"Hildi invites Verumius over for Abendbrot. He expects a hot dinner. What he gets is... very German.",goals:["Learn 12 food and drink words with articles","Discover the Abendbrot tradition","Review Wechselpräpositionen, weil-clauses, and comparatives"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-hildi-kitchen",trg:"Abend bei Hildi. Verumius hat Hunger. Den ganzen Tag hat er nur einen Kaffee getrunken. Jetzt riecht es nach... nichts. Kein Braten, keine Soße. Nur ein Holzbrett auf dem Tisch.",src:"Evening at Hildi's. Verumius is hungry. All day he only had a coffee. Now it smells like... nothing. No roast, no sauce. Just a wooden board on the table."},
{type:"story",speaker:"Hildi",trg:"So! Abendbrot ist fertig. Setz dich!",src:"So! Abendbrot is ready. Sit down!"},
{type:"story",speaker:"Verumius",trg:"Das ist... Brot? Und Käse? Wo ist das warme Essen?",src:"That's... bread? And cheese? Where is the hot food?"},
{type:"story",speaker:"Hildi",trg:"Warmes Essen? Zum Abendbrot? Du bist lustig, Verumius. In Deutschland essen wir abends kalt. Brot, Käse, Wurst. Fertig.",src:"Hot food? For Abendbrot? You're funny, Verumius. In Germany we eat cold in the evening. Bread, cheese, sausage. Done."},
{type:"teach",trg:"der Käse",src:"the cheese",note:"Masculine. No plural form commonly used.",example:"A: Magst du Käse?\nB: Ja, ich liebe Käse! Besonders Gouda.",exampleSrc:"A: Do you like cheese?\nB: Yes, I love cheese! Especially Gouda.",funFact:"Germany produces over 1,500 varieties of cheese. But at Abendbrot, you'll mostly see sliced Gouda, Emmentaler, and Butterkäse on the board."},
{type:"teach",trg:"die Wurst",src:"the sausage",note:"Feminine. Plural: die Würste.",example:"A: Welche Wurst möchtest du?\nB: Die Salami, bitte.",exampleSrc:"A: Which sausage would you like?\nB: The salami, please.",funFact:"Germany has over 1,500 types of Wurst. The saying 'Das ist mir Wurst' (That is sausage to me) means 'I don't care.' Sausage is so common it became a synonym for indifference."},
{type:"teach",trg:"die Bohne",src:"the bean",note:"Feminine. Plural: die Bohnen.",example:"A: Was kochst du?\nB: Ich koche eine Bohnensuppe.",exampleSrc:"A: What are you cooking?\nB: I'm cooking a bean soup.",funFact:"'Bohnenkaffee' (bean coffee) was how Germans distinguished real coffee from the grain substitutes used during wartime. If someone offers you Bohnenkaffee, it means the real stuff."},
{type:"teach",trg:"die Nudel",src:"the noodle",note:"Feminine. Plural: die Nudeln. Used for all pasta.",example:"A: Was gibt es zum Mittagessen?\nB: Nudeln mit Tomatensoße!",exampleSrc:"A: What's for lunch?\nB: Noodles with tomato sauce!",funFact:"Spätzle, Maultaschen, Schupfnudeln: southern Germany has its own noodle tradition older than Italian pasta in Germany. Schwaben (Swabians) take their Nudeln very seriously."},
{type:"teach",trg:"die Orange",src:"the orange",note:"Feminine. Plural: die Orangen. Pronounced with French stress: oh-RAHN-zhuh.",example:"A: Möchtest du eine Orange?\nB: Ja, gerne! Orangen sind gesund.",exampleSrc:"A: Would you like an orange?\nB: Yes, please! Oranges are healthy.",funFact:"In northern Germany you might hear 'Apfelsine' instead of 'Orange.' It means 'apple from China' (Apfel + Sine/China). Two words for the same fruit, split by geography."},
{type:"teach",trg:"die Pizza",src:"the pizza",note:"Feminine. Plural: die Pizzen (or Pizzas).",example:"A: Lass uns Pizza bestellen!\nB: Gute Idee! Ich nehme eine Margherita.",exampleSrc:"A: Let's order pizza!\nB: Good idea! I'll have a Margherita.",funFact:"Germany eats more frozen pizza per capita than any other European country. The brand Dr. Oetker sells over 350 million frozen pizzas per year in Germany alone."},
{type:"mc",q:"Which article goes with 'Käse'?",opts:["der","die","das","ein"],ans:"der",hint:"This dairy product is masculine in German."},
{type:"fb",s:"Ich esse {1} Wurst zum Abendbrot.",a:["die"],opts:["die","der","das","den"],hint:"Wurst is feminine. What is the feminine accusative article.",sSrc:"I eat {1} sausage for Abendbrot."},
{type:"teach",trg:"das Mineralwasser",src:"the mineral water",note:"Neuter. Compound: Mineral + Wasser.",example:"A: Was trinkst du?\nB: Ein Mineralwasser, bitte.",exampleSrc:"A: What are you drinking?\nB: A mineral water, please.",funFact:"Germans drink more sparkling water than almost anyone. If you order 'Wasser' in a restaurant, you'll get sparkling (mit Kohlensäure). Want still? Say 'stilles Wasser.'"},
{type:"teach",trg:"das Mittagessen",src:"the lunch",note:"Neuter. Compound: Mittag (midday) + Essen (food).",example:"A: Was hast du zum Mittagessen gegessen?\nB: Ich hatte Nudeln mit Gemüse.",exampleSrc:"A: What did you eat for lunch?\nB: I had noodles with vegetables.",funFact:"Mittagessen is the main hot meal in Germany, traditionally eaten between 12:00 and 13:00. That is why Abendbrot (evening bread) is cold. The hot meal already happened at midday."},
{type:"teach",trg:"die Portion",src:"the portion",note:"Feminine. Plural: die Portionen.",example:"A: Die Portionen hier sind riesig!\nB: Ja, das ist typisch deutsch.",exampleSrc:"A: The portions here are huge!\nB: Yes, that's typically German.",funFact:"German restaurant portions tend to be generous. Asking for a 'kleine Portion' (small portion) is perfectly acceptable and common, especially for Kinder (children)."},
{type:"teach",trg:"der Zucker",src:"the sugar",note:"Masculine. No common plural.",example:"A: Nimmst du Zucker in den Kaffee?\nB: Nein, ohne Zucker bitte.",exampleSrc:"A: Do you take sugar in your coffee?\nB: No, without sugar please.",funFact:"The word 'Zucker' traveled from Sanskrit (sharkara) through Arabic (sukkar) to German. The same root gave English 'sugar', French 'sucre', and Spanish 'azucar.'"},
{type:"teach",trg:"die Suppe",src:"the soup",note:"Feminine. Plural: die Suppen.",example:"A: Im Winter esse ich gern Suppe.\nB: Ich auch! Kartoffelsuppe ist mein Favorit.",exampleSrc:"A: In winter I like eating soup.\nB: Me too! Potato soup is my favorite.",funFact:"Eintopf (one-pot) is Germany's comfort soup: a thick stew of meat, potatoes, and vegetables. During both World Wars, the government promoted 'Eintopfsonntag' (one-pot Sunday) to save resources."},
{type:"teach",trg:"das Eis",src:"the ice cream",note:"Neuter. Also means 'ice.' Context tells you which.",example:"A: Möchtest du ein Eis?\nB: Ja, Schokolade bitte!",exampleSrc:"A: Would you like an ice cream?\nB: Yes, chocolate please!",funFact:"German Eisdielen (ice cream parlors) are often run by Italian families who came to Germany in the 1920s. The tradition is so strong that 'Italian ice cream' is considered a German cultural staple."},
{type:"tip",title:"Abendbrot: The Cold Supper",text:"Germans traditionally eat their warm meal at midday (Mittagessen).\n\nAbendbrot (evening bread) is a cold meal:\n\n\u2022 Bread (often dark rye or sourdough)\n\u2022 Sliced cheese and cold cuts\n\u2022 Maybe pickles, tomatoes, or radishes\n\u2022 Butter and mustard\n\nIt is simple, practical, and very German.\nVisitors expecting a hot dinner are often surprised."},
{type:"mc",q:"Hildi sagt: 'In Deutschland essen wir abends kalt.' Was bedeutet das?",opts:["Germans eat cold food in the evening","Germans eat outside in the evening","Germans skip dinner","Germans eat early in the morning"],ans:"Germans eat cold food in the evening",hint:"Translate the two key words: 'kalt' and 'abends' to understand the custom."},
{type:"fb",s:"Nimmst du {1} in den Kaffee?",a:["Zucker"],opts:["Zucker","Käse","Wurst","Nudel"],hint:"Which of these is a sweet white powder.",sSrc:"Do you take {1} in your coffee?"},
{type:"mc",q:"Verumius legt die Wurst auf das Brett. What does 'auf das Brett' tell us?",opts:["The sausage is already on the board","The sausage is moving onto the board","The sausage is under the board","The sausage is next to the board"],ans:"The sausage is moving onto the board",hint:"'Auf das' (accusative) signals movement to a new position."},
{type:"fb",s:"Der Käse liegt {1} dem Tisch.",a:["auf"],opts:["auf","in","über","unter"],hint:"The cheese is resting on a flat surface. Which Wechselpräposition.",sSrc:"The cheese is lying {1} the table."},
{type:"mc",q:"Verumius sagt: 'Ich esse Suppe, weil ich Hunger habe.' Where is the verb in the weil-clause?",opts:["Second position","Right after weil","At the very end","Before the subject"],ans:"At the very end",hint:"Weil is a subordinating conjunction. It sends the verb somewhere special."},
{type:"drag_fill",s:"Ich trinke Mineralwasser, {1} es {2} als Cola {3}.",blanks:{"1":"weil","2":"gesünder","3":"ist"},pool:["weil","gesünder","ist","denn","gut","hat"],hint:"A weil-clause needs verb-final. The comparative of 'gesund' is irregular.",sSrc:"I drink mineral water {1} it {2} than cola {3}."},
{type:"mc",q:"'Die Pizza ist größer als die Portion Nudeln.' What does 'größer als' express?",opts:["The pizza is the same size","The pizza is smaller","The pizza is larger","The pizza is cheaper"],ans:"The pizza is larger",hint:"'Größer' is the comparative form of 'groß' (big)."},
{type:"fb",s:"Abendbrot ist {1} als Mittagessen.",a:["einfacher"],opts:["einfacher","einfach","am einfachsten","einfache"],hint:"You need the comparative form to compare two meals.",sSrc:"Abendbrot is {1} than lunch."},
{type:"teach",trg:"backen",src:"to bake",note:"Irregular: ich backe, du bäckst/backst, er bäckt/backt. Past: gebacken.",example:"A: Was bäckst du da?\nB: Einen Apfelkuchen für die Nachbarn.\nA: Das riecht wunderbar!\nB: Danke, das Rezept ist von meiner Oma.",exampleSrc:"A: What are you baking?\nB: An apple cake for the neighbors.\nA: That smells wonderful!\nB: Thanks, the recipe is from my grandma.",funFact:"German Brotkultur (bread culture) is UNESCO-listed. Over 3,200 registered bread varieties. Every village has a Bäckerei (bakery). Backen is one of the first verbs German children learn."},
{type:"teach",trg:"braten",src:"to fry / to roast",note:"Irregular: ich brate, du brätst, er brät. Past: gebraten.",example:"A: Wie bereitest du das Schnitzel zu?\nB: Ich brate es in der Pfanne.\nA: Mit viel Butter?\nB: Natürlich! So macht man es in Deutschland.",exampleSrc:"A: How do you prepare the schnitzel?\nB: I fry it in the pan.\nA: With lots of butter?\nB: Of course! That is how you do it in Germany.",funFact:"A Braten (roast) is the centerpiece of a German Sunday dinner. Schweinebraten, Rinderbraten, and Gänsebraten are classics."},
{type:"teach",trg:"schneiden",src:"to cut",note:"Irregular: ich schneide, du schneidest. Past: geschnitten. Strong verb!",example:"A: Kannst du das Brot schneiden?\nB: Ja, wo ist das Messer?\nA: In der Schublade links.\nB: Danke. Wie dick soll ich schneiden?",exampleSrc:"A: Can you cut the bread?\nB: Yes, where is the knife?\nA: In the left drawer.\nB: Thanks. How thick should I cut?",funFact:"Der Schneider means tailor (one who cuts fabric). Many German family names come from trades: Schneider, Bäcker, Fischer."},
{type:"match",pairs:[{trg:"der Käse",src:"the cheese"},{trg:"die Wurst",src:"the sausage"},{trg:"die Bohne",src:"the bean"},{trg:"die Nudel",src:"the noodle"},{trg:"das Mineralwasser",src:"the mineral water"},{trg:"das Eis",src:"the ice cream"},{trg:"die Suppe",src:"the soup"},{trg:"der Zucker",src:"the sugar"}]},
{type:"mc",q:"Verumius stellt das Mineralwasser neben den Käse. Why is it 'neben den Käse' and not 'neben dem Käse'?",opts:["Because Käse is masculine","Because the water is already there","Because it describes movement to a new spot","Because neben always takes accusative"],ans:"Because it describes movement to a new spot",hint:"Wechselpräpositionen use accusative for direction and dative for location."},
{type:"fb",s:"Die Suppe steht {1} dem Herd.",a:["auf"],opts:["auf","in","an","neben"],hint:"The soup is sitting on a flat cooking surface.",sSrc:"The soup is standing {1} the stove."}
]}
,

// U8 L6: Kommst du mit? (Story climax, Mia introduction in stairwell)
{id:"deu_r8l6",title:"Kommst du mit?",icon:"\uD83C\uDFC3\u200D\u2640\uFE0F",xp:20,board:true,steps:[
{type:"intro",title:"Kommst du mit?",desc:"In the stairwell, Verumius meets Mia for the first time. She is athletic, direct, and already uses du. Will he survive her invitation?",goals:["Learn vocabulary for food, home, and daily life","Review Wechselpräpositionen, weil, comparatives, and superlatives","Combine multiple grammar constructs in one sentence"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-altbau-stairwell",trg:"Im Treppenhaus. Verumius kommt von Hildis Wohnung. Er ist noch satt vom Abendbrot. Die Haustür unten geht auf. Schnelle Schritte auf der Treppe. Eine junge Frau mit Lauftasche und Pferdeschwanz steht plötzlich vor ihm.",src:"In the stairwell. Verumius is coming from Hildi's apartment. He is still full from dinner. The front door opens below. Quick steps on the stairs. A young woman with a running bag and ponytail suddenly stands in front of him."},
{type:"story",speaker:"Mia",trg:"Hey! Du bist der Neue, oder? Ich bin Mia. Lukas hat mir von dir erzählt. Ich wohne im dritten Stock.",src:"Hey! You're the new guy, right? I'm Mia. Lukas told me about you. I live on the third floor."},
{type:"story",speaker:"Verumius",trg:"Oh, hallo! Ich bin Verumius. Freut mich. Lukas hat auch von dir erzählt.",src:"Oh, hello! I'm Verumius. Nice to meet you. Lukas also told me about you."},
{type:"story",speaker:"Mia",trg:"Hör mal. Ich organisiere einen Lauftreff im Park. Jeden Samstag um acht. Kommst du mit?",src:"Listen. I organize a running group in the park. Every Saturday at eight. Are you coming?"},
{type:"teach",trg:"der Hamburger",src:"the hamburger",note:"Masculine noun. Plural: die Hamburger. The same word in German!",example:"A: Ich hätte gern einen Hamburger, bitte.\nB: Mit Käse oder ohne?",exampleSrc:"A: I'd like a hamburger, please.\nB: With cheese or without?",funFact:"Germans call it 'der Hamburger' because it comes from Hamburg, where the original Frikadelle (meat patty) was invented. Hamburger in Hamburg actually refers to a person FROM Hamburg."},
{type:"teach",trg:"die Süßigkeit",src:"the sweet / candy",note:"Feminine noun. Plural: die Süßigkeiten. From 'süß' (sweet) + '-igkeit' (noun suffix).",example:"A: Willst du eine Süßigkeit?\nB: Nein danke, ich esse keine Süßigkeiten mehr.",exampleSrc:"A: Do you want a sweet?\nB: No thanks, I don't eat sweets anymore.",funFact:"The suffix '-igkeit' turns adjectives into nouns: süß becomes Süßigkeit, schwierig becomes Schwierigkeit. German word building at its finest."},
{type:"teach",trg:"das Handtuch",src:"the towel",note:"Neuter noun. Plural: die Handtücher. Compound: Hand (hand) + Tuch (cloth).",example:"A: Wo hängt das Handtuch?\nB: Das Handtuch hängt an der Tür.",exampleSrc:"A: Where is the towel hanging?\nB: The towel is hanging on the door.",funFact:"Hand + Tuch = hand cloth. Germans also have Badetuch (bath towel), Geschirrtuch (dish towel), and Staubtuch (dust cloth). Always a Tuch for the job!"},
{type:"teach",trg:"die Seife",src:"the soap",note:"Feminine noun. Plural: die Seifen.",example:"A: Hast du Seife im Badezimmer?\nB: Ja, die Seife liegt neben dem Waschbecken.",exampleSrc:"A: Do you have soap in the bathroom?\nB: Yes, the soap is next to the sink.",funFact:"The word 'Seife' comes from the same ancient root as English 'soap.' Germanic tribes taught the Romans about soap. Pliny the Elder wrote about it!"},
{type:"teach",trg:"streiten",src:"to argue / to quarrel",note:"Irregular: ich streite, du streitest, er streitet. Past: gestritten.",example:"A: Warum streiten die Nachbarn?\nB: Weil der Müll im Treppenhaus steht.",exampleSrc:"A: Why are the neighbors arguing?\nB: Because the trash is in the stairwell.",funFact:"'Sich streiten' (reflexive) means to argue with each other. 'Darüber lässt sich streiten' is a common idiom meaning 'that is debatable.'"},
{type:"teach",trg:"renovieren",src:"to renovate",note:"Regular: ich renoviere, du renovierst. Past: renoviert (no ge- prefix, because of the -ieren ending).",example:"A: Was macht der Nachbar im Erdgeschoss?\nB: Er renoviert seine Wohnung.",exampleSrc:"A: What is the neighbor doing on the ground floor?\nB: He is renovating his apartment.",funFact:"Verbs ending in '-ieren' (renovieren, telefonieren, organisieren) never get the 'ge-' prefix in past tense. 'Renoviert,' not 'gerenoviert.' These are all borrowed from French or Latin."},
{type:"teach",trg:"einziehen",src:"to move in",note:"Separable verb: ich ziehe ein, du ziehst ein. Past: eingezogen (sein).",example:"A: Wann bist du eingezogen?\nB: Ich bin letzte Woche eingezogen.",exampleSrc:"A: When did you move in?\nB: I moved in last week.",funFact:"Ein + ziehen = to pull in. Ausziehen = to move out (to pull out). Also: ausziehen = to undress. Context matters. 'Ich ziehe aus' at a party means something very different than at a Wohnungsbesichtigung."},
{type:"mc",q:"Mia sagt: 'Ich lege das Handtuch auf den Stuhl.' Where is the towel going?",opts:["onto the chair","under the chair","behind the chair","next to the chair"],ans:"onto the chair",hint:"'Auf den Stuhl' uses accusative, showing direction of movement."},
{type:"fb",s:"Die Seife liegt neben {1} Waschbecken.",a:["dem"],opts:["dem","den","das","der"],hint:"Location (no movement) after 'neben' requires dative. Waschbecken is neuter.",sSrc:"The soap is lying next to {1} sink."},
{type:"mc",q:"Die Nachbarn sind laut und böse. Was machen sie?",opts:["streiten","stören","streichen","stellen"],ans:"streiten",hint:"When two people disagree loudly and with anger."},
{type:"fb",s:"Er hat seine Wohnung {1}.",a:["renoviert"],opts:["renoviert","gerenoviert","renovieren","renovierte"],hint:"Verbs ending in -ieren form past tense without ge-. Think of the rule.",sSrc:"He {1} his apartment."},
{type:"drag_fill",s:"Mia legt die Lauftasche {1} den Boden und hängt das Handtuch {2} die Tür.",blanks:{"1":"auf","2":"an"},pool:["auf","an","in","unter","neben","vor"],hint:"Both show direction (accusative). The bag goes onto the floor, the towel goes onto the door.",sSrc:"Mia puts the running bag {1} the floor and hangs the towel {2} the door."},
{type:"mc",q:"'Ich bin letzte Woche eingezogen.' Why does this use 'bin' instead of 'habe'?",opts:["Movement verb, so uses sein","It is a reflexive verb here","The subject ich requires sein","Past time phrases force sein"],ans:"Movement verb, so uses sein",hint:"Moving in is a change of location. Think about which helper verb location-change verbs need."},
{type:"fb",s:"Süßigkeiten sind süßer {1} Obst.",a:["als"],opts:["als","wie","von","mit"],hint:"Which word means 'than' when comparing two things in German.",sSrc:"Sweets are sweeter {1} fruit."},
{type:"drag_fill",s:"Das Handtuch hängt {1} der Tür, weil Mia es {2} die Tür gehängt hat.",blanks:{"1":"an","2":"an"},pool:["an","auf","in","an","unter","neben"],hint:"First blank: location (dative, it is hanging THERE). Second blank: direction (accusative, she PUT it there). Same preposition, different case!",sSrc:"The towel is hanging {1} the door because Mia hung it {2} the door."},
{type:"mc",q:"Verumius findet Hildis Abendbrot besser als Pizza, weil es frischer ist. Which two grammar patterns are combined here?",opts:["Comparative + weil-clause","Superlative + dass-clause","Comparative + wenn-clause","Superlative + weil-clause"],ans:"Comparative + weil-clause",hint:"'Besser als' compares two things. 'Weil' explains the reason with verb at the end."},
{type:"fb",s:"Mia ist die {1} Läuferin im Lauftreff.",a:["schnellste"],opts:["schnellste","schneller","schnellere","am schnellsten"],hint:"After a definite article (die), superlatives use the '-ste' ending, not 'am ...sten.'",sSrc:"Mia is the {1} runner in the running group."},
{type:"drag_fill",s:"Mia stellt die Schuhe {1} die Tür, weil es {2} der Wohnung sauberer ist {3} im Treppenhaus.",blanks:{"1":"vor","2":"in","3":"als"},pool:["vor","in","als","an","auf","wie"],hint:"Shoes go in front of the door (direction). Cleaner inside (location) the apartment than in the stairwell (comparison).",sSrc:"Mia puts the shoes {1} the door because it is {2} the apartment cleaner {3} in the stairwell."},
{type:"mc",q:"'Im dritten Stock wohnt die netteste Nachbarin.' What grammar is used here?",opts:["Superlative with adjective ending","Comparative with als","Wechselpräposition with dative","Subordinate clause with weil"],ans:"Superlative with adjective ending",hint:"'Die netteste' shows the highest degree of 'nett' with a grammatical suffix after the article."},
{type:"fb",s:"Verumius zieht {1} die Wohnung im zweiten Stock ein.",a:["in"],opts:["in","an","auf","vor"],hint:"Which Wechselpräposition means 'into' when moving into a place.",sSrc:"Verumius moves {1} the apartment on the second floor."},
{type:"drag_fill",s:"Mia sagt, dass der Lauftreff {1} wichtigsten Termin der Woche ist, weil Laufen {2} als Fernsehen ist.",blanks:{"1":"am","2":"besser"},pool:["am","besser","als","der","im","gut"],hint:"First blank: superlative form uses 'am ...sten.' Second blank: an irregular form meaning 'more good' for the comparison.",sSrc:"Mia says that the running group is the {1} most important appointment of the week because running is {2} than watching TV."},
{type:"mc",q:"'Weil Mia jeden Samstag im Park läuft, ist sie stärker als Verumius.' Why is 'läuft' at the end of the weil-clause?",opts:["In weil-clauses, the verb moves to the final position","Läuft is always last in German","Mia is the subject so the verb follows","Im Park requires the verb at the end"],ans:"In weil-clauses, the verb moves to the final position",hint:"Remember the subordinate clause word order rule from earlier this unit."},
{type:"match",pairs:[{trg:"der Hamburger",src:"the hamburger"},{trg:"die Süßigkeit",src:"the sweet/candy"},{trg:"das Handtuch",src:"the towel"},{trg:"die Seife",src:"the soap"},{trg:"streiten",src:"to argue"},{trg:"renovieren",src:"to renovate"},{trg:"einziehen",src:"to move in"}]}
]}
,

{id:"deu_r8l7",title:"Müllprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Müllprüfung",desc:"Alles aus Unit 8 auf dem Prüfstand. Keine neuen Wörter, nur dein Wissen.",goals:["Wechselpräpositionen anwenden","weil-Sätze bilden","Komparativ und Superlativ verwenden","Wortschatz aus L1-L6 beherrschen"]},
{type:"mc",q:"Ich stelle den Topf ___ den Herd.",opts:["auf","im","am","ans"],ans:"auf",hint:"Wohin? Akkusativ mit Richtung nach oben."},
{type:"fb",s:"Die Gabel liegt {1} dem Teller.",a:"auf",opts:["auf","in","an","unter"],hint:"The fork is resting on top of something. Which two-way preposition describes this position.",sSrc:"The fork is lying {1} the plate."},
{type:"mc",q:"Welches Wort bedeutet das Gegenteil von 'sauber'?",opts:["schmutzig","schädlich","scharf","schwierig"],ans:"schmutzig",hint:"Denk an dreckige Kleidung nach der Gartenarbeit."},
{type:"fb",s:"Er hängt das Handtuch {1} die Tür.",a:"an",opts:["an","auf","in","neben"],hint:"Wohin? Akkusativ, das Handtuch kommt zur Tür.",sSrc:"He hangs the towel {1} the door."},
{type:"mc",q:"Warum putzt Hildi die Küche? Weil die Küche ___ ist.",opts:["schmutzig","sauber","frisch","nützlich"],ans:"schmutzig",hint:"Putzen macht man, wenn etwas nicht sauber ist."},
{type:"drag_fill",s:"Ich räume auf, weil der {1} so {2} ist.",blanks:{1:"Keller",2:"schmutzig"},pool:["Keller","schmutzig","Stockwerk","sauber","frisch"],hint:"weil schickt das Verb ans Ende. Was ist unten und dreckig.",sSrc:"I tidy up because the {1} is so {2}."},
{type:"mc",q:"Pizza ist ___ als Suppe. (lecker)",opts:["leckerer","am leckersten","lecker","das leckerste"],ans:"leckerer",hint:"Vergleich mit 'als' braucht die Komparativform."},
{type:"fb",s:"Das Messer ist {1} als die Gabel. (scharf)",a:"schärfer",opts:["schärfer","am schärfsten","scharf","scharfer"],hint:"Komparativ von scharf: Umlaut nicht vergessen.",sSrc:"The knife is {1} than the fork."},
{type:"match",pairs:[{trg:"die Bohne",src:"bean"},{trg:"der Zucker",src:"sugar"},{trg:"die Wurst",src:"sausage"},{trg:"das Eis",src:"ice cream"},{trg:"die Nudel",src:"noodle"}]},
{type:"mc",q:"Welches Essen ist am süßesten?",opts:["Eis","Käse","Wurst","Suppe"],ans:"Eis",hint:"Superlativ: welches ist wirklich am süßesten?"},
{type:"drag_fill",s:"Sie stellt die {1} in den {2}, weil sie {3} kochen will.",blanks:{1:"Nudel",2:"Topf",3:"Mittagessen"},pool:["Nudel","Topf","Mittagessen","Teller","Gabel","Suppe"],hint:"Pasta goes into a round cooking vessel. The midday meal needs preparing.",sSrc:"She puts the {1} in the {2} because she wants to cook {3}."},
{type:"fb",s:"Das Erdgeschoss ist {1} als das dritte Stockwerk. (niedrig)",a:"niedriger",opts:["niedriger","am niedrigsten","niedrig","niedrigere"],hint:"Komparativ: Erdgeschoss liegt tiefer als Stockwerk 3.",sSrc:"The ground floor is {1} than the third story."},
{type:"mc",q:"Er macht das Fenster zu, weil es draußen kalt ___.",opts:["ist","sein","hat","wird"],ans:"ist",hint:"weil-Satz: das konjugierte Verb steht ganz am Ende."},
{type:"drag_fill",s:"Die {1} ist nützlich, weil sie die {2} sauber {3}.",blanks:{1:"Seife",2:"Hände",3:"macht"},pool:["Seife","Hände","macht","Lampe","Wäsche","stört"],hint:"Was reinigt? Nebensatzstellung: Verb am Ende.",sSrc:"The {1} is useful because it {3} the {2} clean."},
{type:"mc",q:"Mineralwasser ist ___ als Orangensaft. (gesund)",opts:["gesünder","am gesündesten","gesund","gesunder"],ans:"gesünder",hint:"Vergleich mit 'als': Komparativform mit Umlaut."},
{type:"fb",s:"Die Nachbarin legt die Seife {1} das Waschbecken.",a:"neben",opts:["neben","zwischen","\u00fcber","hinter"],hint:"Wohin? Die Seife kommt zur Seite des Waschbeckens, Akkusativ.",sSrc:"The neighbor puts the soap {1} the sink."},
{type:"match",pairs:[{trg:"aufräumen",src:"to tidy up"},{trg:"putzen",src:"to clean"},{trg:"aufmachen",src:"to open"},{trg:"zumachen",src:"to close"},{trg:"stören",src:"to disturb"}]},
{type:"mc",q:"Welcher Satz hat die richtige Wortstellung?",opts:["Ich putze, weil die Küche schmutzig ist.","Ich putze, weil die Küche ist schmutzig.","Ich putze, weil ist die Küche schmutzig.","Ich putze, weil schmutzig die Küche ist."],ans:"Ich putze, weil die Küche schmutzig ist.",hint:"Nach weil geht das konjugierte Verb ans Satzende."},
{type:"drag_fill",s:"Der {1} streitet mit der {2}, weil die Musik zu {3} ist.",blanks:{1:"Nachbar",2:"Nachbarin",3:"hart"},pool:["Nachbar","Nachbarin","hart","weich","Pflanze","Lampe"],hint:"Wer streitet mit wem? Warum? Nebensatz: Verb am Ende.",sSrc:"The {1} argues with the {2} because the music is too {3}."},
{type:"fb",s:"Die Reinigung ist am {1}. (schwierig)",a:"schwierigsten",opts:["schwierigsten","schwieriger","schwierig","schwierigste"],hint:"Superlativ mit 'am': am ...sten.",sSrc:"Cleaning is the {1}."},
{type:"mc",q:"Er stellt die Lampe ___ den Stuhl.",opts:["neben","im","am","beim"],ans:"neben",hint:"Wohin? Akkusativ: die Lampe bewegt sich zum Stuhl."},
{type:"drag_fill",s:"Die {1} im Keller ist {2} als die im {3}.",blanks:{1:"Heizung",2:"stärker",3:"Erdgeschoss"},pool:["Heizung","stärker","Erdgeschoss","Wäsche","schwieriger","Stockwerk"],hint:"Was heizt? Komparativ von stark. Welches Geschoss.",sSrc:"The {1} in the basement is {2} than the one on the {3}."},
{type:"mc",q:"Ich renoviere die Wohnung, weil wir bald ___.",opts:["einziehen","einziehe","ziehen ein","ein ziehen"],ans:"einziehen",hint:"Nach weil bleibt das trennbare Verb zusammen am Ende."},
{type:"match",pairs:[{trg:"schädlich",src:"harmful"},{trg:"nützlich",src:"useful"},{trg:"frisch",src:"fresh"},{trg:"sauer",src:"sour"},{trg:"weich",src:"soft"}]},
{type:"drag_fill",s:"Eine {1} Portion Käse ist {2} als eine große Portion {3}.",blanks:{1:"kleine",2:"gesünder",3:"Süßigkeit"},pool:["kleine","gesünder","Süßigkeit","große","schärfer","Hamburger"],hint:"Komparativ: gesund mit Umlaut. Was ist ungesund und süß.",sSrc:"A {1} portion of cheese is {2} than a large portion of {3}."}
]}
,

// U8 L8: Neue Nachbarn - Story resolution + remaining vocab
{id:"deu_r8l8",title:"Neue Nachbarn",icon:"\uD83C\uDFE0",xp:15,board:true,steps:[
{type:"intro",title:"Neue Nachbarn",desc:"Verumius finally knows his neighbors, can separate trash like a pro, and Hildi is impressed. Time to settle into the building and learn the last words you need for daily life in Germany.",goals:["Learn vocabulary for places, devices, and animals","Use spatial adverbs: drinnen, nebenan, rein, raus","Master useful expressions: auf jeden Fall, daf\u00fcr, dagegen"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-building-courtyard",trg:"Freitagabend. Verumius steht im Hof und liest die Recycling-Regeln auf seinem Zettel. Hildi kommt mit einer Tasse Kaffee vorbei.",src:"Friday evening. Verumius stands in the courtyard and reads the recycling rules on his sheet. Hildi comes by with a cup of coffee."},
{type:"story",speaker:"hildi",trg:"Na, Verumius? Du sortierst jetzt besser als die meisten Deutschen! Ich bin stolz auf dich. Mia hat \u00fcbrigens gefragt, ob du zum Lauftreff kommst.",src:"Well, Verumius? You sort better than most Germans now! I am proud of you. Mia asked, by the way, whether you are coming to the running club."},
{type:"story",speaker:"verumius",trg:"Auf jeden Fall! Ich kenne jetzt die Nachbarn, die M\u00fclltonne und den Supermarkt. Ich glaube, ich wohne gern hier.",src:"Absolutely! I now know the neighbors, the trash bins, and the supermarket. I think I like living here."},
{type:"teach",trg:"die Vermieterin",src:"the landlady",note:"Feminine. Der Vermieter = landlord. From 'vermieten' (to rent out).",example:"A: Wer ist deine Vermieterin?\nB: Frau Klein. Sie wohnt nebenan.",exampleSrc:"A: Who is your landlady?\nB: Mrs. Klein. She lives next door.",funFact:"German landlords have a reputation for strict house rules. The 'Hausordnung' (house rules) can regulate quiet hours, stairwell cleaning schedules, and even how you hang laundry."},
{type:"teach",trg:"das Wohnzimmer",src:"the living room",note:"Neuter. Compound: Wohn (living) + Zimmer (room).",example:"A: Wo ist der Fernseher?\nB: Im Wohnzimmer, neben dem Sofa.",exampleSrc:"A: Where is the TV?\nB: In the living room, next to the sofa.",funFact:"German has a room for everything: Wohnzimmer (living), Schlafzimmer (sleeping), Esszimmer (eating), Arbeitszimmer (working), Badezimmer (bathing). The system is beautifully logical."},
{type:"teach",trg:"die Garage",src:"the garage",note:"Feminine. Borrowed from French. Plural: die Garagen.",example:"A: Wo ist dein Auto?\nB: In der Garage.",exampleSrc:"A: Where is your car?\nB: In the garage.",funFact:"Many Germans pronounce this the French way: ga-RAH-zhuh. Others say ga-RAH-guh. Both are correct, but the French pronunciation sounds fancier."},
{type:"mc",q:"Verumius asks 'Wo ist das Sofa?' Hildi says 'Im Wohnzimmer.' What is a Wohnzimmer?",opts:["A bedroom","A bathroom","A living room","A kitchen"],ans:"A living room",hint:"'Wohnen' means to live or to dwell in German."},
{type:"teach",trg:"die Baustelle",src:"the construction site",note:"Feminine. Compound: Bau (construction) + Stelle (place/site).",example:"A: Warum ist die Stra\u00dfe gesperrt?\nB: Es gibt eine Baustelle nebenan.",exampleSrc:"A: Why is the street blocked?\nB: There is a construction site next door.",funFact:"Germany is famous for its Baustellen. The Berlin airport BER took 14 years to build. Germans joke that Baustellen are permanent landmarks."},
{type:"teach",trg:"die Cafeteria",src:"the cafeteria",note:"Feminine. Same word in many languages. Plural: die Cafeterien.",example:"A: Wo essen die Studenten?\nB: In der Cafeteria. Das Essen ist g\u00fcnstig.",exampleSrc:"A: Where do the students eat?\nB: In the cafeteria. The food is affordable.",funFact:"German universities have a 'Mensa' (from Latin for table), which is the student cafeteria. A 'Cafeteria' usually refers to one in an office or hospital."},
{type:"teach",trg:"das Ger\u00e4t",src:"the device / appliance",note:"Neuter. Plural: die Ger\u00e4te. From 'Rat' (advice, counsel).",example:"A: Was ist das f\u00fcr ein Ger\u00e4t?\nB: Das ist ein Staubsauger.",exampleSrc:"A: What kind of device is that?\nB: That is a vacuum cleaner.",funFact:"'Ger\u00e4t' originally meant 'equipment' or 'tool.' Today it covers everything from kitchen appliances (Haushaltsger\u00e4te) to smartphones (mobile Ger\u00e4te). Turnger\u00e4t means gymnastics apparatus!"},
{type:"fb",s:"Hildi hat ein neues {1} f\u00fcr die K\u00fcche gekauft.",a:["Ger\u00e4t"],opts:["Ger\u00e4t","Gericht","Garage","Garten"],hint:"Which neuter noun means a device or appliance.",sSrc:"Hildi bought a new {1} for the kitchen."},
{type:"teach",trg:"das Gericht",src:"the dish / the court",note:"Neuter. Two meanings: a meal dish, or a court of law.",example:"A: Was ist dein Lieblingsgericht?\nB: Schnitzel mit Kartoffelsalat!",exampleSrc:"A: What is your favorite dish?\nB: Schnitzel with potato salad!",funFact:"Same word, two meanings. 'Das Gericht' can be dinner (Hauptgericht = main course) or the law court (Amtsgericht = local court). Context always makes it clear."},
{type:"teach",trg:"die Schere",src:"the scissors",note:"Feminine. Always singular in German, unlike English.",example:"A: Hast du eine Schere?\nB: Ja, sie liegt in der Schublade.",exampleSrc:"A: Do you have scissors?\nB: Yes, they are in the drawer.",funFact:"In German, 'die Schere' is singular. You cut with ONE Schere, not 'a pair of scissors.' English treats scissors as plural, German treats them as one tool."},
{type:"teach",trg:"das Schwein",src:"the pig",note:"Neuter. Plural: die Schweine. Also means 'luck' in slang!",example:"A: Was ist das auf dem Bauernhof?\nB: Das ist ein Schwein.",exampleSrc:"A: What is that on the farm?\nB: That is a pig.",funFact:"'Schwein haben' (to have pig) means 'to be lucky' in German! At New Year, Germans give each other marzipan pigs (Glücksschweine) for good luck. Pigs = prosperity in German culture."},
{type:"teach",trg:"das Glück",src:"luck / happiness",note:"Neuter. No plural. Glück haben = to be lucky. Glücklich = happy.",example:"A: Ich habe die Prüfung bestanden!\nB: Herzlichen Glückwunsch! Du hattest Glück.\nA: Nein, ich habe viel gelernt!\nB: Na gut, dann hast du es verdient.",exampleSrc:"A: I passed the exam!\nB: Congratulations! You were lucky.\nA: No, I studied a lot!\nB: Alright, then you earned it.",funFact:"German distinguishes Glück (luck/happiness) from Pech (bad luck). 'Glück im Unglück' means luck in misfortune, finding a silver lining. New Year symbols: four-leaf clover, chimney sweeps, horseshoes, and marzipan pigs."},
{type:"teach",trg:"das Rind",src:"the beef / cattle",note:"Neuter. Rindfleisch = beef (the meat). Plural: die Rinder.",example:"A: Was möchtest du essen?\nB: Ich nehme das Rind mit Gemüse.",exampleSrc:"A: What would you like to eat?\nB: I'll have the beef with vegetables.",funFact:"Germans distinguish carefully: das Rind (the animal/cattle), das Rindfleisch (beef as meat), die Kuh (cow specifically). Rinderbraten (roast beef) is a classic Sunday dish."},
{type:"mc",q:"Verumius sees a 'Glücksschwein' at New Year. What animal is it?",opts:["A cat","A pig","A cow","A horse"],ans:"A pig",hint:"This neuter noun also has a slang meaning related to luck."},
{type:"tip",title:"Deutsche Nachbarschaft",text:"In Germany, knowing your neighbors matters more than you think.\n\n\u2022 Gr\u00fc\u00dfen ist Pflicht: Always greet neighbors in the stairwell. Not greeting is considered rude.\n\u2022 Hausordnung: Most buildings have written house rules on quiet hours, cleaning schedules, and trash sorting.\n\u2022 Kehrwoche: In S\u00fcddeutschland, tenants take turns sweeping the stairwell and sidewalk. Skipping your turn is a social crime.\n\u2022 Nachbarschaftshilfe: Neighbors help each other with packages, watering plants, and lending tools.\n\u2022 Lauftreff/Stammtisch: Community running groups and regular pub meetups build real friendships.",deepDive:"The concept of 'Nachbarschaft' goes beyond proximity. In smaller cities, neighbors exchange house keys, watch each other's children, and celebrate together. The 'Nachbarschaftsfest' (neighborhood party) is a tradition where the whole street sets up tables outside and shares food. Moving into a new building? Introduce yourself with a small gift or a note in the mailbox. First impressions matter."},
{type:"teach",trg:"drinnen",src:"inside",note:"Opposite of 'drau\u00dfen' (outside). Refers to being indoors.",example:"A: Wo sind die Kinder?\nB: Sie spielen drinnen. Es regnet.",exampleSrc:"A: Where are the children?\nB: They are playing inside. It is raining.",funFact:"'Drinnen' vs 'drin': both mean inside, but 'drin' is more casual. 'Was ist da drin?' (What's in there?) vs 'Drinnen ist es warm' (Inside it is warm)."},
{type:"teach",trg:"nebenan",src:"next door",note:"Adverb. 'Der Nachbar nebenan' = the neighbor next door.",example:"A: Wo wohnt Frau Klein?\nB: Sie wohnt nebenan.",exampleSrc:"A: Where does Mrs. Klein live?\nB: She lives next door.",funFact:"'Nebenan' comes from 'neben' (next to) + 'an' (at). Germans love stacking prepositions to create precise spatial adverbs: nebenan, nebendran, nebenher."},
{type:"teach",trg:"rein",src:"in (colloquial for hinein)",note:"Short for 'herein/hinein.' Very common in spoken German.",example:"A: Komm rein! Es ist kalt drau\u00dfen.\nB: Danke! Hier ist es gem\u00fctlich.",exampleSrc:"A: Come in! It is cold outside.\nB: Thanks! It is cozy in here.",funFact:"'Rein' is the casual version of 'hinein' (into). Similarly, 'raus' = 'hinaus' (out of), 'r\u00fcber' = 'hin\u00fcber' (over). Spoken German loves these short forms."},
{type:"teach",trg:"raus",src:"out (colloquial for hinaus)",note:"Short for 'heraus/hinaus.' 'Geh raus!' = Go outside!",example:"A: Das Wetter ist sch\u00f6n!\nB: Dann lass uns rausgehen!",exampleSrc:"A: The weather is nice!\nB: Then let us go outside!",funFact:"'Raus' appears in many expressions: 'rausfinden' (to find out), 'rauskommen' (to come out), 'rauswerfen' (to throw out/fire someone). The prefix completely changes the verb's meaning."},
{type:"fb",s:"Komm {1}! Wir essen gleich.",a:["rein"],opts:["rein","raus","nebenan","drinnen"],hint:"Which colloquial adverb means 'in' when inviting someone inside.",sSrc:"Come {1}! We are eating soon."},
{type:"teach",trg:"gegen\u00fcber",src:"opposite / across from",note:"Preposition + adverb. Takes dative: gegen\u00fcber dem Haus.",example:"A: Wo ist die Apotheke?\nB: Gegen\u00fcber dem Supermarkt.",exampleSrc:"A: Where is the pharmacy?\nB: Opposite the supermarket.",funFact:"'Gegen\u00fcber' can also be a noun: 'mein Gegen\u00fcber' means 'the person opposite me.' At dinner, your Gegen\u00fcber is whoever sits across from you."},
{type:"teach",trg:"daf\u00fcr",src:"for it / in favor of it",note:"Da + f\u00fcr. Replaces 'f\u00fcr + noun' when the noun is already known.",example:"A: Bist du daf\u00fcr?\nB: Ja, ich bin daf\u00fcr!",exampleSrc:"A: Are you in favor of it?\nB: Yes, I am for it!",funFact:"German 'da-words' replace prepositional phrases: daf\u00fcr (for it), damit (with it), dar\u00fcber (about it), daran (on it). They avoid repeating the noun. Very efficient!"},
{type:"teach",trg:"dagegen",src:"against it / opposed to it",note:"Da + gegen. Opposite of 'daf\u00fcr.'",example:"A: Alle wollen ein Nachbarschaftsfest. Bist du dagegen?\nB: Nein, ich bin daf\u00fcr!",exampleSrc:"A: Everyone wants a neighborhood party. Are you against it?\nB: No, I am for it!",funFact:"In German parliament, votes are counted as 'daf\u00fcr' (in favor), 'dagegen' (against), and 'Enthaltung' (abstention). You hear these words in every political debate."},
{type:"mc",q:"Hildi asks 'Bist du daf\u00fcr oder dagegen?' What is she asking?",opts:["Are you inside or outside?","Are you coming or staying?","Are you for it or against it?","Are you hungry or full?"],ans:"Are you for it or against it?",hint:"These two da-words express opposite opinions about something."},
{type:"teach",trg:"auf jeden Fall",src:"in any case / absolutely",note:"Strong agreement. 'Auf jeden Fall komme ich!' = I am definitely coming!",example:"A: Kommst du zum Lauftreff?\nB: Auf jeden Fall!",exampleSrc:"A: Are you coming to the running club?\nB: Absolutely!",funFact:"The opposite is 'auf keinen Fall' (no way / under no circumstances). 'Jeden' = every, 'keinen' = no. Same structure, opposite meaning."},
{type:"teach",trg:"auf keinen Fall",src:"no way / under no circumstances",note:"Strong disagreement. 'Auf keinen Fall!' = Absolutely not!",example:"A: Soll ich den Biomüll in den Restm\u00fcll werfen?\nB: Auf keinen Fall! Hildi sieht alles.",exampleSrc:"A: Should I throw the organic waste in the general trash?\nB: No way! Hildi sees everything.",funFact:"Germans use this phrase with conviction. It leaves zero room for doubt. If Hildi says 'auf keinen Fall,' you do NOT put plastic in the Biotonne."},
{type:"fb",s:"Kommst du morgen? {1}!",a:["Auf jeden Fall"],opts:["Auf jeden Fall","Auf keinen Fall","Dagegen","Nebenan"],hint:"Which expression means 'absolutely' or 'definitely'.",sSrc:"Are you coming tomorrow? {1}!"},
{type:"drag_fill",s:"Die Apotheke ist {1} dem Supermarkt. Frau Klein wohnt {2}.",blanks:{"1":"gegen\u00fcber","2":"nebenan"},pool:["gegen\u00fcber","nebenan","drinnen","raus","dagegen"],hint:"One means 'opposite/across from,' the other means 'next door.'",sSrc:"The pharmacy is {1} the supermarket. Mrs. Klein lives {2}."},
{type:"mc",q:"Verumius says 'Die Kinder spielen drinnen.' Where are the children?",opts:["Outside in the garden","Inside the building","Next door","At the construction site"],ans:"Inside the building",hint:"This adverb is the opposite of 'drau\u00dfen' (outside)."},
{type:"mc",q:"Which word means 'the construction site'?",opts:["die Baustelle","die Cafeteria","die Garage","die Vermieterin"],ans:"die Baustelle",hint:"Compound word: Bau (building/construction) + Stelle (place)."},
{type:"fb",s:"Zum Neujahr verschenkt man Marzipanschweine. Schwein haben bedeutet '{1} haben.'",a:["Gl\u00fcck"],opts:["Gl\u00fcck","Geld","Essen","Angst"],hint:"The opposite of Pech. Something positive that happens by chance.",sSrc:"At New Year, people give marzipan pigs. Having pig means having '{1}'."},
{type:"teach",trg:"leer",src:"empty",note:"Adjective. Opposite: voll (full). Die Flasche ist leer.",example:"A: Ist noch Milch da?\nB: Nein, die Flasche ist leer.\nA: Schon wieder? Wer trinkt so viel Milch?\nB: Verumius. Er macht jeden Morgen Müsli.",exampleSrc:"A: Is there still milk?\nB: No, the bottle is empty.\nA: Again? Who drinks so much milk?\nB: Verumius. He makes muesli every morning.",funFact:"Leergut means empty containers eligible for the Pfand (deposit) return. Supermarkets have Leergutautomaten where you feed in bottles and cans for money back."},
{type:"teach",trg:"notwendig",src:"necessary",note:"Adjective. Stronger than nötig. Es ist notwendig = It is necessary.",example:"A: Ist eine Krankenversicherung notwendig?\nB: Ja, in Deutschland ist sie Pflicht.\nA: Auch für Studenten?\nB: Ja, für alle. Ohne geht es nicht.",exampleSrc:"A: Is health insurance necessary?\nB: Yes, in Germany it is mandatory.\nA: Even for students?\nB: Yes, for everyone. You cannot do without it.",funFact:"Notwendig literally means 'turning away need' (Not = need, wenden = to turn). German loves building words that explain their own meaning."},
{type:"teach",trg:"praktisch",src:"practical",note:"Adjective. Also used as an adverb meaning 'practically' or 'virtually.'",example:"A: Die Wohnung hat einen Balkon.\nB: Oh, das ist sehr praktisch!\nA: Ja, ich trockne dort meine Wäsche.\nB: Praktisch! Kein Trockner nötig.",exampleSrc:"A: The apartment has a balcony.\nB: Oh, that is very practical!\nA: Yes, I dry my laundry there.\nB: Practical! No dryer needed.",funFact:"Germans highly value being practical. A practical gift is better than an expensive one. Practical shoes beat fashionable ones. Functionality is a cultural value."},
{type:"teach",trg:"bauen",src:"to build",note:"Regular: ich baue, du baust, er baut. Past: gebaut.",example:"A: Was bauen sie nebenan?\nB: Eine neue Schule.\nA: Wie lange dauert das?\nB: Mindestens zwei Jahre. Das ist eine große Baustelle.",exampleSrc:"A: What are they building next door?\nB: A new school.\nA: How long will that take?\nB: At least two years. That is a big construction site.",funFact:"Berlin's BER airport took 14 years to build. The Cologne Cathedral took 632 years (started 1248, finished 1880). Germans joke that building is a test of patience."},
{type:"teach",trg:"herstellen",src:"to produce / to manufacture",note:"Separable: ich stelle her. Past: hergestellt. Used for factory production.",example:"A: Wo wird dieses Auto hergestellt?\nB: In Wolfsburg, bei Volkswagen.\nA: Made in Germany!\nB: Genau. Deutsche Qualität.",exampleSrc:"A: Where is this car manufactured?\nB: In Wolfsburg, at Volkswagen.\nA: Made in Germany!\nB: Exactly. German quality.",funFact:"'Made in Germany' was originally a British warning label in 1887 to mark inferior German imports. Germans turned it into a badge of quality worldwide."},
{type:"match",pairs:[{trg:"die Vermieterin",src:"the landlady"},{trg:"das Wohnzimmer",src:"the living room"},{trg:"die Baustelle",src:"the construction site"},{trg:"nebenan",src:"next door"},{trg:"dafür",src:"for it"},{trg:"auf jeden Fall",src:"absolutely"},{trg:"die Schere",src:"the scissors"},{trg:"das Gerät",src:"the device"}]}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 9: Freizeit und Vereine
// Story: Lauftreff, Vereinskultur, Satzung comedy, Yilmaz's text
// CEFR: A2.2 - dass/ob clauses, reflexive verbs/pronouns, coord conjunctions
// ═══════════════════════════════════════════════════════════════
{n:9,lang:"de",srcLang:"en",track:"v2",title:"Freizeit und Vereine",sub:"Running club, Vereinskultur, hobbies, and German social life",icon:"🏃",level:"A2.2",color:"#7B5EE8",lessons:[
// ─── L1: Der Lauftreff ───
{id:"deu_r9l1",title:"Der Lauftreff",icon:"🏃",xp:15,board:true,steps:[
{type:"intro",title:"Der Lauftreff",desc:"Mia drags Verumius to her running club in Volkspark Friedrichshain. It's 6:30 AM, the autumn air bites, and Verumius is already regretting this.",goals:["Learn 12 sports and leisure words","Discover German Vereinskultur","Survive your first Lauftreff"]},
{type:"story",speaker:"narrator",mood:"tired",art:"de-volkspark-dawn",trg:"Volkspark Friedrichshain. 6:30 Uhr. Die Bäume sind orange und rot. Kalte Luft, Atem wie kleine Wolken. Mia steht am Eingang und dehnt sich. Verumius steht daneben und gähnt.",src:"Volkspark Friedrichshain. 6:30 AM. The trees are orange and red. Cold air, breath like little clouds. Mia stands at the entrance stretching. Verumius stands next to her and yawns."},
{type:"story",speaker:"Mia",trg:"Guten Morgen! Bist du bereit? Wir treffen uns hier jeden Samstag. Das ist unser Lauftreff!",src:"Good morning! Are you ready? We meet here every Saturday. This is our running club!"},
{type:"story",speaker:"Verumius",trg:"Jeden Samstag? Um halb sieben? Ihr seid alle verrückt.",src:"Every Saturday? At half past six? You're all crazy."},
{type:"teach",trg:"der Ball",src:"the ball",note:"Masculine noun. Plural: die Bälle.",example:"A: Hast du einen Ball?\nB: Ja, der Ball ist im Auto.\nA: Dann hol ihn schnell!",exampleSrc:"A: Do you have a ball?\nB: Yes, the ball is in the car.\nA: Then go get it quickly!",funFact:"'Ball' is identical in English and German. It comes from Old High German 'bal.' Germans host over 400 'Bälle' (formal dance balls) each year, most famously the Vienna Opera Ball."},
{type:"teach",trg:"der Fan",src:"the fan (supporter)",note:"Masculine noun. Plural: die Fans. Borrowed from English.",example:"A: Bist du ein Fan von Bayern München?\nB: Nein! Ich bin ein Fan von Dortmund!\nA: Oh, dann können wir nicht Freunde sein.",exampleSrc:"A: Are you a fan of Bayern Munich?\nB: No! I'm a fan of Dortmund!\nA: Oh, then we can't be friends.",funFact:"Germany's Bundesliga has the highest average stadium attendance in the world. Borussia Dortmund's 'Gelbe Wand' (Yellow Wall) holds 25,000 standing fans in one section alone."},
{type:"teach",trg:"die Mannschaft",src:"the team",note:"Feminine noun. Plural: die Mannschaften.",example:"A: Welche Mannschaft spielt heute?\nB: Die Mannschaft aus Berlin spielt gegen Hamburg.\nA: Das wird ein gutes Spiel!",exampleSrc:"A: Which team is playing today?\nB: The team from Berlin is playing against Hamburg.\nA: That will be a good game!",funFact:"The German national football team is simply called 'die Mannschaft' (the team). The word comes from 'Mann' (man) + '-schaft' (collective suffix), like English '-ship' in 'fellowship.'"},
{type:"teach",trg:"der Sportplatz",src:"the sports field",note:"Masculine compound noun: Sport + Platz (place).",example:"A: Wo ist der Sportplatz?\nB: Der Sportplatz ist hinter der Schule.\nA: Danke! Wir trainieren dort um vier.",exampleSrc:"A: Where is the sports field?\nB: The sports field is behind the school.\nA: Thanks! We train there at four.",funFact:"Every German neighborhood has a Sportplatz. There are over 90,000 sports facilities in Germany. Even tiny villages have their own football field with a clubhouse."},
{type:"mc",q:"Mia says 'Die Mannschaft trainiert auf dem Sportplatz.' Where does the team train?",opts:["At the train station","On the sports field","In the swimming pool","At the supermarket"],ans:"On the sports field",hint:"'Sportplatz' is a compound of Sport and a word meaning 'place.'"},
{type:"fb",s:"Bist du ein {1} von Dortmund?",a:["Fan"],opts:["Fan","Ball","Spiel","Mannschaft"],hint:"Which borrowed English word means a supporter of a team?",sSrc:"Are you a {1} of Dortmund?"},
{type:"teach",trg:"das Training",src:"the training / practice",note:"Neuter noun. No common plural form in everyday use.",example:"A: Wann ist das Training?\nB: Das Training ist um sechs Uhr.\nA: So früh? Das ist hart!",exampleSrc:"A: When is the training?\nB: The training is at six o'clock.\nA: So early? That's tough!",funFact:"Germans take training schedules seriously. Club training sessions run year-round, rain or shine. The phrase 'Übung macht den Meister' (practice makes the master) is a national motto."},
{type:"teach",trg:"das Spiel",src:"the game / match",note:"Neuter noun. Plural: die Spiele.",example:"A: Wie war das Spiel?\nB: Das Spiel war fantastisch! 3:1 für uns.\nA: Toll! Wer hat die Tore geschossen?",exampleSrc:"A: How was the game?\nB: The game was fantastic! 3-1 for us.\nA: Great! Who scored the goals?",funFact:"'Spiel' gives us 'Spielplatz' (playground), 'Spielzeug' (toy, literally play-stuff), and the verb 'spielen.' Steven Spielberg's surname literally means 'play mountain.'"},
{type:"teach",trg:"der Spaziergang",src:"the walk / stroll",note:"Masculine compound: spazieren (to stroll) + Gang (way/path).",example:"A: Machen wir einen Spaziergang?\nB: Ja, gerne! Im Park?\nA: Perfekt. Die Sonne scheint.",exampleSrc:"A: Shall we go for a walk?\nB: Yes, I'd love to! In the park?\nA: Perfect. The sun is shining.",funFact:"The Sunday 'Spaziergang' is a sacred German tradition. After lunch, families walk through parks or forests. It is considered healthy, social, and deeply German. Some call it 'Verdauungsspaziergang' (digestion walk)."},
{type:"mc",q:"Verumius says 'Machen wir einen Spaziergang im Park?' What is he suggesting?",opts:["Let's eat in the park","Let's play a game in the park","Let's go for a walk in the park","Let's train in the park"],ans:"Let's go for a walk in the park",hint:"A 'Spaziergang' is a relaxed, leisurely outdoor activity."},
{type:"story",speaker:"narrator",mood:"struggling",art:"de-volkspark-running",trg:"Die Gruppe läuft los. Mia ist vorne, schnell und leicht. Verumius ist hinten. Seine Beine sind schwer. Sein Atem ist laut. Ein älterer Mann überholt ihn. Eine Frau mit Kinderwagen überholt ihn.",src:"The group starts running. Mia is at the front, fast and light. Verumius is at the back. His legs are heavy. His breathing is loud. An older man passes him. A woman with a stroller passes him."},
{type:"teach",trg:"joggen",src:"to jog",note:"Borrowed from English. Regular: ich jogge, du joggst.",example:"A: Gehst du gerne joggen?\nB: Ja, ich jogge jeden Morgen im Park.\nA: Alleine oder mit Freunden?",exampleSrc:"A: Do you like jogging?\nB: Yes, I jog every morning in the park.\nA: Alone or with friends?",funFact:"Germans borrowed 'joggen' in the 1970s running boom. They even created 'der Jogger' and 'die Joggerin.' English sports words flood German: 'der Sprint,' 'das Workout,' 'das Stretching.'"},
{type:"teach",trg:"trainieren",src:"to train / to work out",note:"Regular: ich trainiere, du trainierst, er trainiert.",example:"A: Wie oft trainierst du?\nB: Ich trainiere dreimal pro Woche.\nA: Das ist beeindruckend!",exampleSrc:"A: How often do you train?\nB: I train three times per week.\nA: That's impressive!",funFact:"From Latin 'trahere' (to pull/drag), through French 'trainer.' The same root gave English 'train' (the vehicle literally pulls carriages). In German, 'trainieren' is ONLY for exercise, never for vehicles."},
{type:"teach",trg:"spazieren",src:"to walk / to stroll",note:"Regular: ich spaziere, du spazierst. Often used with 'gehen.'",example:"A: Was machst du am Sonntag?\nB: Ich gehe spazieren. Kommst du mit?\nA: Klar! Wohin gehen wir?",exampleSrc:"A: What are you doing on Sunday?\nB: I'm going for a walk. Do you want to come?\nA: Sure! Where are we going?",funFact:"'Spazieren' comes from Italian 'spaziare' (to wander). It arrived in German during the Renaissance when Italian culture was fashionable. A walk borrowed from Italy!"},
{type:"fb",s:"Ich {1} jeden Morgen im Park.",a:["jogge"],opts:["jogge","spaziere","trainiere","spiele"],hint:"Which verb specifically means running at a moderate pace?",sSrc:"I {1} every morning in the park."},
{type:"teach",trg:"aktiv",src:"active",note:"Same spelling as English. Used with sein: 'Ich bin aktiv.'",example:"A: Bist du sportlich?\nB: Ja, ich bin sehr aktiv. Ich jogge und schwimme.\nA: Respekt!",exampleSrc:"A: Are you sporty?\nB: Yes, I'm very active. I jog and swim.\nA: Respect!",funFact:"Germany ranks among the most physically active countries in Europe. Over 27 million Germans are members of a sports club. That is one in three people!"},
{type:"teach",trg:"sportlich",src:"sporty / athletic",note:"From 'Sport' + '-lich' (similar to English '-ly'). Used for people AND things.",example:"A: Mia ist wirklich sportlich!\nB: Ja, sie trainiert jeden Tag.\nA: Ich bin leider nicht so sportlich.",exampleSrc:"A: Mia is really sporty!\nB: Yes, she trains every day.\nA: Unfortunately I'm not that sporty.",funFact:"The suffix '-lich' turns nouns into adjectives: Sport to sportlich, Freund to freundlich, Herz to herzlich. Once you know this trick, you can decode hundreds of German adjectives."},
{type:"mc",q:"Verumius says 'Mia ist sportlich, ich bin es nicht.' What does 'sportlich' mean?",opts:["Tired","Sporty","Hungry","Late"],ans:"Sporty",hint:"This adjective is built from a word you already know plus '-lich.'"},
{type:"tip",title:"Vereinskultur: The Heart of German Community",text:"Germany has over 600,000 registered Vereine (clubs).\n\nFootball clubs, hiking clubs, running clubs, singing clubs, rabbit-breeding clubs.\n\n'Sich treffen' (to meet up) and 'sich anmelden' (to register) are key verbs for club life. You will learn these soon!\n\nJoining a Verein is how Germans build community. Mia's Lauftreff is a perfect example: same people, same time, same park, every week.",deepDive:"The first German Verein was founded in 1791. Today, about 44% of all Germans belong to at least one club. The concept is so central to German identity that 'Vereinsmeier' (someone obsessed with club rules) is a well-known word. Many clubs have a 'Stammtisch' (regulars' table) at a local pub where members meet after activities."},
{type:"mc",q:"How many registered Vereine (clubs) does Germany have?",opts:["About 6,000","About 60,000","About 600,000","About 6,000,000"],ans:"About 600,000",hint:"Think about the tip card. It is a six-figure number."},
{type:"fb",s:"Mia ist sehr {1}. Sie trainiert jeden Tag.",a:["sportlich"],opts:["sportlich","aktiv","müde","hungrig"],hint:"Which adjective describes someone who is athletic?",sSrc:"Mia is very {1}. She trains every day."},
{type:"match",pairs:[{trg:"der Ball",src:"the ball"},{trg:"die Mannschaft",src:"the team"},{trg:"das Spiel",src:"the game"},{trg:"joggen",src:"to jog"},{trg:"trainieren",src:"to train"},{trg:"spazieren",src:"to stroll"},{trg:"aktiv",src:"active"},{trg:"sportlich",src:"sporty"}]},
{type:"story",speaker:"Mia",trg:"Nicht schlecht für dein erstes Mal! Nächste Woche wird es einfacher. Das Training macht dich fit!",src:"Not bad for your first time! Next week it will be easier. The training will get you fit!"},
{type:"story",speaker:"Verumius",trg:"Nächste Woche? Ich kann meine Beine nicht mehr fühlen!",src:"Next week? I can't feel my legs anymore!"},
{type:"mc",q:"'Das Training macht dich fit.' What does 'das Training' mean?",opts:["The game","The walk","The training","The team"],ans:"The training",hint:"This neuter noun describes the activity of practicing a sport."},
{type:"drag_fill",s:"Mia ist {1} und {2}. Sie geht jeden Samstag zum {3}.",blanks:{"1":"aktiv","2":"sportlich","3":"Lauftreff"},pool:["aktiv","sportlich","Lauftreff","müde","Spiel"],hint:"Describe Mia's character and her Saturday activity.",sSrc:"Mia is {1} and {2}. She goes every Saturday to the {3}."}
]}
,

{id:"deu_r9l2",title:"Was machst du gern?",icon:"🎨",xp:15,board:true,steps:[
{type:"intro",title:"Was machst du gern?",desc:"Lerne Wörter für Hobbys, Kunst und Kultur.",goals:["14 neue Wörter für Freizeit und Kultur","Über Hobbys und Interessen sprechen","Kulturelle Orte und Aktivitäten beschreiben"]},
{type:"teach",trg:"die Musik",src:"music",note:"Feminine. Die Musik spielt eine große Rolle in Deutschland.",funFact:"Deutschland hat über 130 professionelle Orchester. Mehr als jedes andere Land der Welt.",example:"A: Hörst du gern Musik?\nB: Ja, ich höre jeden Tag Musik.",exampleSrc:"A: Do you like listening to music?\nB: Yes, I listen to music every day."},
{type:"teach",trg:"das Instrument",src:"instrument",note:"Neuter. Plural: die Instrumente.",funFact:"Etwa 18% der Deutschen spielen ein Instrument. Klavier und Gitarre sind am beliebtesten.",example:"A: Spielst du ein Instrument?\nB: Ja, ich spiele seit drei Jahren.",exampleSrc:"A: Do you play an instrument?\nB: Yes, I have been playing for three years."},
{type:"teach",trg:"die Gitarre",src:"guitar",note:"Feminine. Plural: die Gitarren.",funFact:"Die klassische Gitarre kam im 19. Jahrhundert nach Deutschland und wurde schnell populär in Wandervogel-Gruppen.",example:"A: Kannst du Gitarre spielen?\nB: Ein bisschen. Ich lerne noch.",exampleSrc:"A: Can you play guitar?\nB: A little. I am still learning."},
{type:"teach",trg:"das Klavier",src:"piano",note:"Neuter. Plural: die Klaviere. Das Wort kommt vom lateinischen clavis (Taste).",funFact:"Beethoven, Bach, Brahms. Deutschland hat mehr berühmte Klavierkomponisten als fast jedes andere Land.",example:"A: Mein Sohn spielt Klavier.\nB: Toll! Seit wann?\nA: Seit September.",exampleSrc:"A: My son plays piano.\nB: Great! Since when?\nA: Since September."},
{type:"mc",q:"Wie sagt man 'guitar' auf Deutsch?",opts:["die Gitarre","das Klavier","die Musik","das Instrument"],ans:"die Gitarre",hint:"Ein Saiteninstrument mit sechs Saiten."},
{type:"teach",trg:"die Kunst",src:"art",note:"Feminine. Kein Plural in dieser Bedeutung.",funFact:"Die documenta in Kassel ist eine der wichtigsten Kunstausstellungen der Welt. Sie findet alle fünf Jahre statt.",example:"A: Interessierst du dich für Kunst?\nB: Ja, besonders für moderne Kunst.",exampleSrc:"A: Are you interested in art?\nB: Yes, especially modern art."},
{type:"teach",trg:"die Kultur",src:"culture",note:"Feminine. Kulturell ist das Adjektiv.",funFact:"In vielen deutschen Städten gibt es eine Kulturkarte. Damit bekommt man Rabatt für Museen, Theater und Konzerte.",example:"A: Die Kultur hier ist sehr interessant.\nB: Ja, es gibt so viel zu sehen!",exampleSrc:"A: The culture here is very interesting.\nB: Yes, there is so much to see!"},
{type:"teach",trg:"das Museum",src:"museum",note:"Neuter. Plural: die Museen (nicht Museums!).",funFact:"Berlin hat die Museumsinsel mit fünf Museen. Sie gehört zum UNESCO-Weltkulturerbe.",example:"A: Warst du schon im Museum?\nB: Ja, das Pergamonmuseum ist fantastisch.",exampleSrc:"A: Have you been to the museum?\nB: Yes, the Pergamon Museum is fantastic."},
{type:"teach",trg:"die Ausstellung",src:"exhibition",note:"Feminine. Plural: die Ausstellungen. Aus + Stellung = etwas wird ausgestellt.",funFact:"Viele deutsche Museen haben am ersten Sonntag im Monat freien Eintritt.",example:"A: Gehst du in die Ausstellung?\nB: Ja, sie ist nur noch bis Freitag.",exampleSrc:"A: Are you going to the exhibition?\nB: Yes, it is only open until Friday."},
{type:"fb",s:"Ich möchte ins {1} gehen. Die Ausstellung über Picasso beginnt heute.",a:["Museum"],opts:["Museum","Theater","Konzert","Bibliothek"],hint:"Ein Ort, wo man Ausstellungen besucht.",sSrc:"I would like to go to the {1}. The Picasso exhibition starts today."},
{type:"teach",trg:"das Theater",src:"theater",note:"Neuter. Plural: die Theater. Ins Theater gehen = to go to the theater.",funFact:"Deutschland hat über 800 Theater. Pro Kopf mehr als jedes andere Land.",example:"A: Gehen wir am Samstag ins Theater?\nB: Gute Idee! Was wird gespielt?",exampleSrc:"A: Shall we go to the theater on Saturday?\nB: Good idea! What is playing?"},
{type:"teach",trg:"das Konzert",src:"concert",note:"Neuter. Plural: die Konzerte. Ins Konzert gehen.",funFact:"Die Elbphilharmonie in Hamburg hat eine der besten Akustiken der Welt. Karten sind oft Monate im Voraus ausverkauft.",example:"A: Das Konzert war wunderbar!\nB: Ja, die Musik war so schön.",exampleSrc:"A: The concert was wonderful!\nB: Yes, the music was so beautiful."},
{type:"teach",trg:"die Bibliothek",src:"library",note:"Feminine. Plural: die Bibliotheken. Nicht verwechseln mit Buchhandlung (bookshop).",funFact:"Die Deutsche Nationalbibliothek in Leipzig und Frankfurt sammelt jedes Buch, das auf Deutsch erscheint.",example:"A: Wo ist die Bibliothek?\nB: Gleich neben dem Museum.",exampleSrc:"A: Where is the library?\nB: Right next to the museum."},
{type:"mc",q:"Wo kann man Bücher lesen und ausleihen?",opts:["in der Bibliothek","im großen Museum","im alten Rathaus","im neuen Zentrum"],ans:"in der Bibliothek",hint:"Dieser Ort ist voll mit Büchern und Regalen."},
{type:"teach",trg:"malen",src:"to paint",note:"Regular: ich male, du malst, er malt.",funFact:"Gerhard Richter ist einer der teuersten lebenden Maler der Welt. Er kommt aus Dresden.",example:"A: Was machst du am Wochenende?\nB: Ich male ein Bild für meine Mutter.",exampleSrc:"A: What are you doing on the weekend?\nB: I am painting a picture for my mother."},
{type:"teach",trg:"zeichnen",src:"to draw",note:"Regular: ich zeichne, du zeichnest, er zeichnet. Mit Bleistift oder Kohle.",funFact:"Albrecht Dürer aus Nürnberg war einer der größten Zeichner aller Zeiten. Sein Hase ist weltberühmt.",example:"A: Kannst du gut zeichnen?\nB: Es geht. Ich zeichne gern Tiere.",exampleSrc:"A: Can you draw well?\nB: So-so. I like drawing animals."},
{type:"teach",trg:"basteln",src:"to do crafts",note:"Regular: ich bastle, du bastelst. Basteln = mit den Händen etwas kreativ machen.",funFact:"Basteln ist in Deutschland ein echtes Hobby. Es gibt ganze Bastelgeschäfte nur für Materialien.",example:"A: Die Kinder basteln Laternen für Sankt Martin.\nB: Oh, wie schön! Aus Papier?",exampleSrc:"A: The children are making lanterns for St. Martin's Day.\nB: Oh, how nice! Out of paper?"},
{type:"tip",title:"Musikvereine und Kulturvereine",text:"In Deutschland gibt es tausende Vereine für Musik und Kultur.\n\n- Musikverein: Man spielt zusammen in einem Orchester oder einer Band.\n- Kulturverein: Man organisiert Ausstellungen, Lesungen oder Theaterabende.\n- Volkshochschule (VHS): Hier kann man malen, zeichnen oder basteln lernen.\n\nEin Verein kostet oft nur 5 bis 15 Euro im Monat. Fast jedes Dorf hat einen Musikverein!",deepDive:"Das deutsche Vereinswesen hat Tradition seit dem 19. Jahrhundert. Heute gibt es etwa 600.000 eingetragene Vereine (e.V.) in Deutschland. Viele Kinder lernen ihr erstes Instrument im Musikverein."},
{type:"mc",q:"Lena spielt gern Klavier und Gitarre. Was spielt sie?",opts:["Instrumente","Ausstellungen","Theater","Kultur"],ans:"Instrumente",hint:"Ein Wort für Dinge, die Musik machen."},
{type:"fb",s:"Am Samstag gehen wir ins {1}. Wir sehen ein Stück von Schiller.",a:["Theater"],opts:["Theater","Museum","Konzert","Bibliothek"],hint:"Ein Ort, wo Schauspieler auf der Bühne stehen.",sSrc:"On Saturday we are going to the {1}. We are seeing a play by Schiller."},
{type:"drag_fill",s:"Mein Bruder {1} gern und meine Schwester {2} gern. Beide lieben {3}.",blanks:{"1":"malt","2":"zeichnet","3":"Kunst"},pool:["malt","zeichnet","Kunst","bastelt","Musik","Kultur"],hint:"Er benutzt Farben, sie benutzt Bleistift, beide lieben es.",sSrc:"My brother {1} and my sister {2}. Both love {3}."},
{type:"match",pairs:[{trg:"die Ausstellung",src:"exhibition"},{trg:"das Konzert",src:"concert"},{trg:"die Bibliothek",src:"library"},{trg:"basteln",src:"to do crafts"},{trg:"zeichnen",src:"to draw"},{trg:"die Gitarre",src:"guitar"}]},
{type:"mc",q:"Was macht man in einer Bibliothek?",opts:["Bücher lesen und ausleihen","Konzerte besuchen","Bilder malen","Instrumente spielen"],ans:"Bücher lesen und ausleihen",hint:"Denk an Regale, Stille und einen Ausweis zum Mitnehmen."},
{type:"fb",s:"Ich gehe heute Abend ins {1}. Die Band spielt meine Lieblingsmusik!",a:["Konzert"],opts:["Konzert","Museum","Theater","Bibliothek"],hint:"Ein Ereignis, wo eine Band live Musik spielt.",sSrc:"I am going to the {1} tonight. The band is playing my favorite music!"}
]},

// ─── L3: Die Vereinssitzung ───
{id:"deu_r9l3",title:"Die Vereinssitzung",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"Die Vereinssitzung",desc:"Verumius attends his first Verein meeting. Folding chairs, a whiteboard, and a binder labeled SATZUNG. Mia runs a surprisingly formal meeting for a running club.",goals:["Learn reflexive verbs with accusative pronouns","Understand dass-clauses with verb-final word order","Talk about events, fun, and participation"]},
{type:"story",speaker:"narrator",mood:"curious",art:"de-verein-meeting",trg:"Dienstagabend. Ein Kirchenkeller mit Klappstühlen und einer alten Tafel. Mia steht vorne mit einem dicken Ordner. Auf dem Ordner steht: SATZUNG.",src:"Tuesday evening. A church basement with folding chairs and an old whiteboard. Mia stands at the front with a thick binder. On the binder it says: CONSTITUTION."},
{type:"story",speaker:"verumius",mood:"shocked",trg:"Ein Laufverein hat eine Satzung?! In Italien treffen wir uns einfach im Park und laufen los.",src:"A running club has a constitution?! In Italy we just meet in the park and start running."},
{type:"story",speaker:"mia",mood:"cheerful",trg:"Willkommen zur Vereinssitzung! Ich freue mich, dass so viele da sind. Wir haben heute viel zu besprechen.",src:"Welcome to the club meeting! I am happy that so many people are here. We have a lot to discuss today."},
{type:"teach",trg:"das Interesse",src:"the interest",note:"Neuter noun. Plural: die Interessen. 'Interesse an + Dativ.'",example:"A: Hast du Interesse an dem Laufverein?\nB: Ja, ich habe großes Interesse!",exampleSrc:"A: Are you interested in the running club?\nB: Yes, I have great interest!",funFact:"Borrowed directly from Latin 'interesse' (to be between). German, French, English, and Italian all use the same word. A true European traveler."},
{type:"teach",trg:"die Lust",src:"the desire / mood (to do something)",note:"Feminine noun. 'Hast du Lust?' = Do you feel like it?",example:"A: Hast du Lust auf ein Bier nach dem Training?\nB: Ja, ich habe total Lust!",exampleSrc:"A: Do you feel like a beer after training?\nB: Yes, I totally feel like it!",funFact:"'Hast du Lust?' is how Germans casually invite people to do things. It is warmer than 'Möchtest du?' and more natural in everyday speech. You will hear it constantly."},
{type:"teach",trg:"der Spaß",src:"the fun",note:"Masculine noun. 'Das macht Spaß!' = That is fun!",example:"A: Macht Laufen Spaß?\nB: Ja, das macht total Spaß!",exampleSrc:"A: Is running fun?\nB: Yes, it is totally fun!",funFact:"Germans say 'Spaß machen' (to make fun), not 'Spaß haben' (to have fun). Fun is something you create, not something you possess. A very German way to think about enjoyment."},
{type:"teach",trg:"das Fest",src:"the celebration / festival",note:"Neuter noun. Plural: die Feste. Think: Oktoberfest!",example:"A: Wann ist das Sommerfest?\nB: Das Fest ist im Juli.",exampleSrc:"A: When is the summer festival?\nB: The festival is in July.",funFact:"'Fest' gives us Oktoberfest, Weinfest, Schützenfest, Volksfest. Germany has over 10,000 festivals per year. If there is a reason to celebrate, there is a Fest for it."},
{type:"teach",trg:"die Feier",src:"the party / celebration",note:"Feminine noun. Plural: die Feiern. More personal than Fest.",example:"A: Kommst du zur Feier am Samstag?\nB: Ja, ich komme gerne zur Feier!",exampleSrc:"A: Are you coming to the party on Saturday?\nB: Yes, I'd love to come to the party!",funFact:"'Feier' is for personal celebrations (birthdays, weddings). 'Fest' is for public ones (festivals, fairs). A birthday is a Feier, not a Fest. Oktoberfest is a Fest, not a Feier."},
{type:"teach",trg:"die Veranstaltung",src:"the event / organized occasion",note:"Feminine noun. Plural: die Veranstaltungen. Formal word.",example:"A: Welche Veranstaltungen gibt es im Mai?\nB: Es gibt drei Veranstaltungen im Mai.",exampleSrc:"A: Which events are there in May?\nB: There are three events in May.",funFact:"16 letters! One of those long German words that sounds scary but breaks down simply: ver + an + stalt + ung. 'Anstalt' means institution, 'ver-' makes it into an action. An organized occasion."},
{type:"mc",q:"Mia says 'Hast du Lust auf eine Feier?' What is she asking?",opts:["Do you have time for a party?","Do you feel like a party?","Do you need a party?","Do you know about a party?"],ans:"Do you feel like a party?",hint:"'Lust haben auf' expresses wanting or feeling like doing something."},
{type:"fb",s:"Das Training macht {1}!",a:["Spaß"],opts:["Spaß","Lust","Fest","Interesse"],hint:"Which masculine noun means 'fun' and pairs with 'machen'?",sSrc:"Training is {1}!"},
{type:"teach",trg:"der Wettbewerb",src:"the competition",note:"Masculine noun. Plural: die Wettbewerbe. Compound: Wette + Bewerb.",example:"A: Gibt es einen Wettbewerb im Oktober?\nB: Ja, der Wettbewerb ist am 15. Oktober.",exampleSrc:"A: Is there a competition in October?\nB: Yes, the competition is on October 15th.",funFact:"'Wette' means bet, 'Bewerb' comes from 'bewerben' (to apply/compete). A competition is literally a 'bet-application.' Germans once settled disputes by betting on athletic contests."},
{type:"teach",trg:"sich freuen",src:"to be happy / to look forward to",note:"Reflexive verb. 'Ich freue mich.' 'sich freuen auf' = look forward to.",example:"A: Ich freue mich auf das Fest!\nB: Ich freue mich auch!",exampleSrc:"A: I'm looking forward to the festival!\nB: I'm looking forward to it too!",funFact:"'Sich freuen' needs a reflexive pronoun. Without it, 'freuen' alone sounds wrong. The 'sich' is like saying 'to glad oneself.' German emotions often work this way: you do the feeling TO yourself."},
{type:"teach",trg:"sich treffen",src:"to meet up",note:"Reflexive + irregular: ich treffe mich, du triffst dich, er trifft sich.",example:"A: Wann treffen wir uns?\nB: Wir treffen uns um 18 Uhr.",exampleSrc:"A: When do we meet up?\nB: We meet up at 6 PM.",funFact:"'Treffen' alone means 'to hit' (a target). Add 'sich' and it becomes 'to meet.' The reflexive changes the entire meaning. You are not hitting anyone, you are meeting each other!"},
{type:"tip",title:"Reflexive Verbs: The 'sich' System",text:"Some German verbs need a reflexive pronoun. The pronoun refers back to the subject.\n\nKey pattern: subject + reflexive pronoun + verb\n\nIch freue mich. (I am happy.)\nDu freust dich. (You are happy.)\nWir treffen uns. (We meet up.)\n\nThe reflexive pronoun changes with the subject. Next, you will see the full table."},
{type:"verb_table",title:"Accusative Reflexive Pronouns",groups:[{label:"Subject + reflexive pronoun",rows:[{pronoun:"ich",form:"mich",src:"myself"},{pronoun:"du",form:"dich",src:"yourself"},{pronoun:"er/sie/es",form:"sich",src:"himself/herself/itself"},{pronoun:"wir",form:"uns",src:"ourselves"},{pronoun:"ihr",form:"euch",src:"yourselves"},{pronoun:"sie/Sie",form:"sich",src:"themselves/yourself (formal)"}]},{label:"sich freuen (to be happy)",rows:[{pronoun:"ich",form:"freue mich",src:"I am happy"},{pronoun:"du",form:"freust dich",src:"you are happy"},{pronoun:"er/sie/es",form:"freut sich",src:"he/she/it is happy"},{pronoun:"wir",form:"freuen uns",src:"we are happy"},{pronoun:"ihr",form:"freut euch",src:"you all are happy"},{pronoun:"sie/Sie",form:"freuen sich",src:"they are / you (formal) are happy"}]}],note:"The reflexive pronoun sits right after the conjugated verb. In questions: 'Freust du dich?' Common reflexive verbs: sich freuen, sich treffen, sich anmelden, sich fühlen."},
{type:"mc",q:"'Ich freue mich auf das Fest.' What does 'mich' do in this sentence?",opts:["It means 'me' as a direct object","It is a reflexive pronoun referring back to 'ich'","It means 'my' as a possessive","It replaces a noun that was mentioned before"],ans:"It is a reflexive pronoun referring back to 'ich'",hint:"The verb 'sich freuen' always needs a word that refers back to the subject."},
{type:"fb",s:"Wir treffen {1} um 18 Uhr im Park.",a:["uns"],opts:["uns","sich","mich","euch"],hint:"Which reflexive pronoun matches the subject 'wir'?",sSrc:"We meet {1} at 6 PM in the park."},
{type:"mc",q:"'Er freut sich auf den Wettbewerb.' Which reflexive pronoun is correct for 'er'?",opts:["mich","dich","sich","uns"],ans:"sich",hint:"Third person (er, sie, es) always uses the same reflexive pronoun."},
{type:"fb",s:"Freust du {1} auf die Feier?",a:["dich"],opts:["dich","mich","sich","uns"],hint:"Which reflexive pronoun matches the subject 'du'?",sSrc:"Are you looking forward {1} to the party?"},
{type:"teach",trg:"teilnehmen",src:"to participate / to take part",note:"Separable: ich nehme teil. 'An + Dativ' follows: 'am Wettbewerb teilnehmen.'",example:"A: Nimmst du am Wettbewerb teil?\nB: Ja, ich nehme teil!",exampleSrc:"A: Are you participating in the competition?\nB: Yes, I'm participating!",funFact:"'Teil' (part) + 'nehmen' (to take). Literally 'to take part.' English and German use the exact same logic here, word for word. Separable verbs split apart in main clauses: 'Ich nehme teil.'"},
{type:"teach",trg:"stattfinden",src:"to take place / to happen",note:"Separable: es findet statt. 'Das Fest findet am Samstag statt.'",example:"A: Wann findet das Fest statt?\nB: Es findet am Samstag statt.",exampleSrc:"A: When does the festival take place?\nB: It takes place on Saturday.",funFact:"'Statt' (place/instead) + 'finden' (to find). An event 'finds its place.' This verb is almost always used with events and is very common in formal announcements and newspapers."},
{type:"teach",trg:"organisieren",src:"to organize",note:"Regular verb: ich organisiere, du organisierst, er organisiert.",example:"A: Wer organisiert das Sommerfest?\nB: Mia organisiert alles!",exampleSrc:"A: Who is organizing the summer festival?\nB: Mia organizes everything!",funFact:"Borrowed from French 'organiser.' German happily borrows words from French for anything cultural, administrative, or fashionable. Organisieren, reservieren, telefonieren: the -ieren ending is always French-origin."},
{type:"story",speaker:"mia",mood:"formal",trg:"Punkt eins: Ich glaube, dass wir ein Sommerfest organisieren sollten. Wer nimmt teil?",src:"Point one: I believe that we should organize a summer festival. Who is participating?"},
{type:"tip",title:"dass-Clauses: Verb Goes to the End",text:"After 'dass' (that), the conjugated verb moves to the END of the clause.\n\nMain clause: Ich glaube + dass-clause: dass wir ein Fest organisieren.\n\nIch glaube, dass wir ein Fest organisieren.\nEr sagt, dass das Fest am Samstag stattfindet.\nWir wissen, dass Mia alles organisiert.\n\nCommon starters: glauben (believe), sagen (say), wissen (know), denken (think), hoffen (hope).\n\nThe comma before 'dass' is mandatory in German."},
{type:"mc",q:"'Ich glaube, dass das Fest am Samstag stattfindet.' Where is the verb in the dass-clause?",opts:["Right after the word dass","In the second position","At the end of the clause","Before the comma itself"],ans:"At the end of the clause",hint:"In dass-clauses, the conjugated verb always travels to one specific position."},
{type:"fb",s:"Er sagt, dass er sich auf die Veranstaltung {1}.",a:["freut"],opts:["freut","freuen","freue","freust"],hint:"The verb must agree with 'er' and must go at the end of the dass-clause.",sSrc:"He says that he is {1} about the event."},
{type:"mc",q:"Which sentence correctly uses a dass-clause?",opts:["Ich denke, dass Mia das Fest organisiert.","Ich denke, dass organisiert Mia das Fest.","Ich denke, Mia dass das Fest organisiert.","Ich denke dass, Mia das Fest organisiert."],ans:"Ich denke, dass Mia das Fest organisiert.",hint:"After 'dass,' the verb must go to the very end. Check each option for verb position."},
{type:"drag_fill",s:"Wir wissen, {1} die Feier am Samstag {2}.",blanks:{"1":"dass","2":"stattfindet"},pool:["dass","stattfindet","findet","weil","statt"],hint:"The first blank needs the conjunction. The second needs the separable verb reunited at the end.",sSrc:"We know {1} the party {2} on Saturday."},
{type:"mc",q:"Mia says 'Ich hoffe, dass alle teilnehmen.' What does she hope?",opts:["That everyone organizes something","That everyone participates","That everyone leaves early","That everyone pays a fee"],ans:"That everyone participates",hint:"'Teilnehmen' means to take part in something."},
{type:"fb",s:"Hast du {1} auf den Wettbewerb?",a:["Lust"],opts:["Lust","Spaß","Fest","Interesse"],hint:"Which feminine noun means 'desire/mood' and pairs with 'haben auf'?",sSrc:"Do you feel like {1} for the competition?"},
{type:"drag_fill",s:"Ich {1} mich, dass du am Wettbewerb {2}.",blanks:{"1":"freue","2":"teilnimmst"},pool:["freue","teilnimmst","nimmst","freuen","teil"],hint:"The main clause needs the reflexive verb for 'ich.' The dass-clause needs the verb for 'du' at the end.",sSrc:"I am {1} that you are {2} in the competition."},
{type:"match",pairs:[{trg:"sich freuen",src:"to be happy"},{trg:"sich treffen",src:"to meet up"},{trg:"teilnehmen",src:"to participate"},{trg:"stattfinden",src:"to take place"},{trg:"organisieren",src:"to organize"},{trg:"die Veranstaltung",src:"the event"}]},
{type:"story",speaker:"verumius",mood:"amused",trg:"Okay, ich glaube, dass deutsche Vereine ernster sind als italienische. Aber ich freue mich, dass ich dabei bin!",src:"Okay, I believe that German clubs are more serious than Italian ones. But I'm happy that I'm part of it!"}
]}
,

{id:"deu_r9l4",title:"Ob oder dass?",icon:"📐",xp:20,board:true,steps:[
{type:"intro",title:"Ob oder dass?",desc:"Two powerful conjunctions unlock indirect speech: dass (that) introduces facts, ob (whether) introduces yes/no questions. Plus reflexive pronouns get their own dative forms, and you meet the ADUSO gang: five conjunctions that keep word order normal.",goals:["Reflexive pronouns: accusative vs dative","ob: indirect yes/no questions with verb-final","Coordinating conjunctions: und/oder/aber/denn/sondern (ADUSO)"]},
{type:"teach",trg:"sich verabreden",src:"to make a date / to arrange to meet",note:"Reflexive + separable. Ich verabrede mich mit Freunden.",example:"A: Verabredest du dich heute Abend?\nB: Ja, ich verabrede mich mit Lukas.",exampleSrc:"A: Are you meeting up tonight?\nB: Yes, I'm meeting up with Lukas.",funFact:"From 'Abrede' (agreement). Germans don't 'make plans,' they 'agree themselves.' The reflexive pronoun is essential: without 'sich,' it sounds like a legal contract."},
{type:"teach",trg:"sich unterhalten",src:"to chat / to converse",note:"Reflexive. Irregular: du unterhältst dich, er unterhält sich.",example:"A: Worüber unterhaltet ihr euch?\nB: Wir unterhalten uns über den Film.",exampleSrc:"A: What are you chatting about?\nB: We're chatting about the film.",funFact:"Literally 'to hold oneself under.' Also means 'to entertain.' 'Die Unterhaltung' = conversation OR entertainment. German efficiency: one word, two meanings."},
{type:"teach",trg:"diskutieren",src:"to discuss",note:"Regular, not reflexive. Diskutieren über + accusative.",example:"A: Wir diskutieren über das Spiel.\nB: Wer hat gewonnen?",exampleSrc:"A: We're discussing the game.\nB: Who won?",funFact:"Borrowed from Latin 'discutere' (to shake apart). Germans kept the Latin structure but gave it German endings. Easy cognate from English 'discuss.'"},
{type:"teach",trg:"vergessen",src:"to forget",note:"Irregular: du vergisst, er vergisst. Stem change e to i.",example:"A: Vergiss den Schlüssel nicht!\nB: Ich vergesse ihn nie!",exampleSrc:"A: Don't forget the key!\nB: I never forget it!",funFact:"The 'ver-' prefix often means 'wrongly' or 'away': verlaufen (get lost), versprechen (misspeak/promise). Vergessen = to 'get' something wrong in your memory."},
{type:"teach",trg:"verlieren",src:"to lose",note:"Irregular past, but regular present: ich verliere, du verlierst.",example:"A: Ich verliere immer meinen Schlüssel.\nB: Kauf dir eine Schlüsselbox!",exampleSrc:"A: I always lose my key.\nB: Buy yourself a key box!",funFact:"'Ver-' again! 'Verlieren' literally suggests something going astray. The opposite 'gewinnen' (to win) has no 'ver-' because winning is the normal state. Very German."},
{type:"teach",trg:"sich verlieben",src:"to fall in love",note:"Reflexive: ich verliebe mich in + accusative.",example:"A: Hast du dich schon mal verliebt?\nB: Ja, in meinen Hund!",exampleSrc:"A: Have you ever fallen in love?\nB: Yes, with my dog!",funFact:"Liebe = love. Sich verlieben = to love-ify yourself. The 'ver-' here means 'into a state.' You don't just love, you enter the STATE of loving. Very philosophical."},
{type:"teach",trg:"träumen",src:"to dream",note:"Regular: ich träume, du träumst. Träumen von + dative.",example:"A: Wovon träumst du?\nB: Ich träume von einer Reise nach Japan.",exampleSrc:"A: What do you dream about?\nB: I dream about a trip to Japan.",funFact:"'Der Traum' (the dream) shares a root with English 'dream.' In German you dream OF something (von), not ABOUT something. Preposition difference!"},
{type:"teach",trg:"sich ärgern",src:"to get annoyed / to be upset",note:"Reflexive: ich ärgere mich über + accusative (about).",example:"A: Warum ärgerst du dich?\nB: Ich ärgere mich über den Regen.",exampleSrc:"A: Why are you annoyed?\nB: I'm annoyed about the rain.",funFact:"'Ärger' = annoyance/trouble. Without 'sich,' ärgern means to annoy SOMEONE ELSE: 'Du ärgerst mich!' = You're annoying me! The reflexive flips the direction."},
{type:"tip",title:"Reflexive Pronouns: Accusative vs Dative",text:"Most reflexive verbs use ACCUSATIVE reflexive pronouns:\nich: mich, du: dich, er/sie/es: sich\nwir: uns, ihr: euch, sie/Sie: sich\n\nBut when there is ALSO a direct object, the reflexive switches to DATIVE:\nich: mir, du: dir, er/sie/es: sich\nwir: uns, ihr: euch, sie/Sie: sich\n\nCompare:\nIch wasche mich. (I wash myself. No other object.)\nIch wasche mir die Hände. (I wash my hands. Hände = acc object, so mir = dat.)\n\nOnly ich and du change: mich/mir, dich/dir. All others stay the same.",deepDive:{title:"When Does the Switch Happen?",text:"The rule is simple: a sentence can only have ONE accusative object. If the verb already has a direct object (die Hände, die Haare, die Zähne), the reflexive pronoun must step down to dative. This mostly matters with body parts and clothing:\nIch putze mir die Zähne. (I brush my teeth.)\nIch ziehe mir die Jacke an. (I put on my jacket.)\nIch kämme mir die Haare. (I comb my hair.)"}},
{type:"mc",q:"'Ich wasche ___ die Hände.' Which reflexive pronoun fits?",opts:["mir","mich","sich","dir"],ans:"mir",hint:"The hands are the accusative object. The reflexive must be dative."},
{type:"fb",s:"Ärgerst du {1} über das Wetter?",a:["dich"],opts:["dich","dir","mich","sich"],hint:"No other object here. The reflexive is accusative for du.",sSrc:"Are you annoyed {1} about the weather?"},
{type:"tip",title:"ob: Indirect Yes/No Questions",text:"'Ob' means 'whether' and turns a yes/no question into an indirect one.\nThe verb goes to the END after ob.\n\nDirect: Kommt er morgen?\nIndirect: Ich weiß nicht, ob er morgen kommt.\n\nCommon triggers for ob:\nfragen (to ask), wissen (to know), sicher sein (to be sure)\n\nCompare with dass (that), which states FACTS:\nIch weiß, dass er morgen kommt. (I know THAT he comes.)\nIch weiß nicht, ob er morgen kommt. (I don't know WHETHER he comes.)\n\ndass = certainty. ob = uncertainty.",deepDive:{title:"Dass vs Ob: The Quick Test",text:"Ask yourself: 'Can I answer this with yes or no?'\nIf YES: use ob.\nIch frage, ob du kommst. (Will you come? Yes/no.)\nIf NO: use dass.\nIch weiß, dass du kommst. (You're coming. Fact.)\n\nBoth send the verb to the end. The difference is certainty vs uncertainty."}},
{type:"mc",q:"'Ich frage mich, ___ er heute kommt.' Which conjunction fits?",opts:["ob","dass","weil","denn"],ans:"ob",hint:"He might come, he might not. You are uncertain."},
{type:"fb",s:"Weißt du, {1} das Kino heute offen ist?",a:["ob"],opts:["ob","dass","weil","und"],hint:"You genuinely don't know. Yes or no question hidden inside.",sSrc:"Do you know {1} the cinema is open today?"},
{type:"tip",title:"Coordinating Conjunctions: ADUSO",text:"Five conjunctions that keep NORMAL word order (verb stays in position 2):\n\nA: aber (but)\nD: denn (because, in main clauses)\nU: und (and)\nS: sondern (but rather, after a negative)\nO: oder (or)\n\nThese connect two main clauses. The verb does NOT move.\nIch spiele Tennis, und er spielt Fußball.\nSie kommt nicht, sondern sie bleibt zu Hause.\n\nContrast with dass/ob/weil: those are SUBORDINATING and push the verb to the end.",deepDive:{title:"Aber vs Sondern",text:"Both mean 'but,' with different uses:\n\nAber = general contrast:\nIch bin müde, aber ich gehe ins Kino.\n\nSondern = correction after a negative:\nIch trinke nicht Kaffee, sondern Tee.\n(Not coffee, but RATHER tea.)\n\nSondern always follows 'nicht' or 'kein.' If there is no negation, use aber."}},
{type:"mc",q:"'Er kommt nicht aus Berlin, ___ aus Hamburg.' Which word corrects the false statement?",opts:["sondern","aber","denn","oder"],ans:"sondern",hint:"After 'nicht,' this conjunction replaces a wrong idea with the correct one."},
{type:"fb",s:"Ich möchte mitkommen, {1} ich habe keine Zeit.",a:["aber"],opts:["aber","sondern","denn","ob"],hint:"A general contrast. No negation before this conjunction.",sSrc:"I would like to come along, {1} I have no time."},
{type:"mc",q:"'Ich weiß, dass er sich verliebt hat.' What does 'dass' introduce here?",opts:["A fact he knows","A yes/no question","A reason","A time clause"],ans:"A fact he knows",hint:"There is certainty here. Dass introduces certainties, ob introduces doubt."},
{type:"drag_fill",s:"Ich frage mich, {1} sie {2} heute {3}.",blanks:{"1":"ob","2":"sich","3":"verabredet"},pool:["ob","sich","verabredet","dass","mich","verliebt"],hint:"Uncertain question: WHETHER she arranges to meet today. Verb to end.",sSrc:"I wonder {1} she is meeting up today."},
{type:"mc",q:"'Ich putze mir die Zähne.' Why is it 'mir' and not 'mich'?",opts:["Zähne takes the accusative","Putzen always needs dative","Mir sounds more polite here","There is no real reason"],ans:"Zähne takes the accusative",hint:"A sentence can only have one direct object. The body part fills that role."},
{type:"fb",s:"Wir unterhalten {1} über den neuen Film.",a:["uns"],opts:["uns","euch","sich","mich"],hint:"Wir = we. The reflexive pronoun for wir is the same in acc and dat.",sSrc:"We are chatting {1} about the new film."},
{type:"drag_fill",s:"Er weiß nicht, {1} sie ihn {2}, {3} er fragt sie.",blanks:{"1":"ob","2":"liebt","3":"denn"},pool:["ob","liebt","denn","dass","verliebt","aber"],hint:"He doesn't know WHETHER she loves him, BECAUSE (main clause reason) he asks her.",sSrc:"He doesn't know {1} she {2} him, {3} he asks her."},
{type:"mc",q:"Which conjunction keeps normal V2 word order?",opts:["und","dass","ob","weil"],ans:"und",hint:"ADUSO conjunctions: aber, denn, und, sondern, oder. All keep V2."},
{type:"fb",s:"Ich vergesse nie, {1} du mir geholfen hast.",a:["dass"],opts:["dass","ob","denn","und"],hint:"You know for certain she helped. This is a stated fact.",sSrc:"I never forget {1} you helped me."},
{type:"drag_fill",s:"Sie {1} sich, {2} sie morgen frei {3}.",blanks:{"1":"fragt","2":"ob","3":"hat"},pool:["fragt","ob","hat","weiß","dass","ist"],hint:"She asks herself WHETHER she has tomorrow off. Verb to end after ob.",sSrc:"She asks herself {1} she has {3} off tomorrow."},
{type:"mc",q:"'Ich ärgere mich, denn er vergisst alles.' What does 'denn' mean here?",opts:["because (reason)","but (contrast)","whether (doubt)","that (fact)"],ans:"because (reason)",hint:"Denn explains the cause while keeping main clause word order."},
{type:"match",pairs:[{trg:"sich verabreden",src:"to arrange to meet"},{trg:"sich unterhalten",src:"to chat"},{trg:"vergessen",src:"to forget"},{trg:"sich verlieben",src:"to fall in love"},{trg:"ob",src:"whether"},{trg:"sondern",src:"but rather"}]}
]}
,

{id:"deu_r9l5",title:"Digital und analog",icon:"📱",xp:15,board:true,steps:[
{type:"intro",title:"Digital und analog",desc:"Verumius discovers German media culture: from blogs and podcasts to paper magazines and comic books. The old and the new, side by side.",goals:["Learn 14 words for media and digital life","Review reflexive verbs with sich","Practice dass and ob subordinate clauses"]},
{type:"teach",trg:"der Blog",src:"the blog",note:"Masculine noun. Plural: die Blogs. Borrowed from English.",example:"A: Liest du einen Blog über Kochen?\nB: Ja, ich lese jeden Tag einen neuen Blog.",exampleSrc:"A: Do you read a blog about cooking?\nB: Yes, I read a new blog every day.",funFact:"Germans adopted 'Blog' directly from English but gave it a masculine article. Some Germans say 'das Blog' (neuter), which causes fierce grammar debates online."},
{type:"teach",trg:"das E-Book",src:"the e-book",note:"Neuter noun. Plural: die E-Books. Pronounced like English.",example:"A: Liest du lieber E-Books oder Bücher?\nB: Ich lese lieber E-Books, weil sie leichter sind.",exampleSrc:"A: Do you prefer reading e-books or books?\nB: I prefer e-books because they are lighter.",funFact:"Germany has a fixed book price law (Buchpreisbildung). Every bookstore must sell the same book at the same price. E-Books are included since 2016."},
{type:"teach",trg:"der Comic",src:"the comic",note:"Masculine noun. Plural: die Comics.",example:"A: Hast du als Kind Comics gelesen?\nB: Ja, ich habe viele Comics gesammelt.",exampleSrc:"A: Did you read comics as a child?\nB: Yes, I collected many comics.",funFact:"Germany's most famous comic is 'Werner,' about a plumber and his motorcycle. Asterix is also hugely popular in German translation, with brilliant wordplay."},
{type:"teach",trg:"die Sendung",src:"the TV show / broadcast",note:"Feminine noun. Plural: die Sendungen. From 'senden' (to send/broadcast).",example:"A: Welche Sendung schaust du heute Abend?\nB: Ich schaue eine Sendung über Natur.",exampleSrc:"A: Which show are you watching tonight?\nB: I'm watching a show about nature.",funFact:"'Sendung mit der Maus' is Germany's most beloved children's show, running since 1971. The orange mouse explains how things work. Even adults watch it."},
{type:"teach",trg:"die Zeitschrift",src:"the magazine",note:"Feminine noun. Plural: die Zeitschriften. Compound: Zeit (time) + Schrift (writing).",example:"A: Kaufst du noch Zeitschriften?\nB: Nein, ich lese alles online.",exampleSrc:"A: Do you still buy magazines?\nB: No, I read everything online.",funFact:"Zeit + Schrift = time-writing. A magazine captures a moment in time. Der Spiegel and Stern are Germany's most famous magazines, read in every doctor's waiting room."},
{type:"teach",trg:"das Programm",src:"the program / schedule",note:"Neuter noun. Plural: die Programme. Also means TV schedule.",example:"A: Was kommt heute im Programm?\nB: Um acht kommt eine neue Sendung.",exampleSrc:"A: What is on the schedule today?\nB: At eight there is a new show.",funFact:"Germans still say 'Was kommt im Programm?' when asking what is on TV. The word covers software, TV listings, theater schedules, and political platforms."},
{type:"mc",q:"Verumius fragt: 'Was kommt heute im Programm?' What is he asking about?",opts:["What is on TV tonight","What software to install","What is for dinner","When the train leaves"],ans:"What is on TV tonight",hint:"'Programm' here refers to the broadcast schedule."},
{type:"fb",s:"Ich lese eine {1} über Reisen.",a:["Zeitschrift"],opts:["Zeitschrift","Sendung","Blog","Programm"],hint:"Which feminine noun means a printed magazine you can hold?",sSrc:"I read a {1} about travel."},
{type:"teach",trg:"das Radio",src:"the radio",note:"Neuter noun. Plural: die Radios.",example:"A: Hörst du Radio im Auto?\nB: Ja, ich höre immer Radio beim Fahren.",exampleSrc:"A: Do you listen to the radio in the car?\nB: Yes, I always listen to the radio while driving.",funFact:"German public radio is funded by the Rundfunkbeitrag, a monthly fee every household pays (about 18 euros). Germans debate this fee as passionately as the weather."},
{type:"teach",trg:"der Tipp",src:"the tip / piece of advice",note:"Masculine noun. Plural: die Tipps. Borrowed from English.",example:"A: Hast du einen Tipp für mich?\nB: Ja, informiere dich vorher im Internet.",exampleSrc:"A: Do you have a tip for me?\nB: Yes, inform yourself beforehand on the internet.",funFact:"Germans spell it with double 'p' unlike English 'tip.' The word entered German in the 19th century from English horse racing jargon."},
{type:"teach",trg:"das Heft",src:"the notebook / issue (of a magazine)",note:"Neuter noun. Plural: die Hefte. Two meanings depending on context.",example:"A: Hast du das neue Heft gekauft?\nB: Nein, ich kaufe keine Hefte mehr.",exampleSrc:"A: Did you buy the new issue?\nB: No, I don't buy issues anymore.",funFact:"Every German schoolchild has a Heft for each subject: Matheheft, Deutschheft, Englischheft. The word originally meant a handle (what you 'hold'), then shifted to a bound booklet."},
{type:"mc",q:"'Das Heft' can mean two things. Which pair is correct?",opts:["Notebook and issue","Book and a letter","Blog and an email","Radio and a show"],ans:"Notebook and issue",hint:"Think about what you write in at school and what you buy at a newsstand."},
{type:"teach",trg:"fotografieren",src:"to photograph",note:"Regular: ich fotografiere, du fotografierst. Past: fotografiert (no ge- prefix).",example:"A: Fotografierst du gern?\nB: Ja, ich fotografiere am liebsten Landschaften.",exampleSrc:"A: Do you like photographing?\nB: Yes, I like photographing landscapes the most.",funFact:"Like all -ieren verbs (studieren, telefonieren, informieren), fotografieren skips the ge- prefix in past tense: 'Ich habe fotografiert,' never 'gefotografiert.'"},
{type:"teach",trg:"chatten",src:"to chat (online)",note:"Regular: ich chatte, du chattest. Past: gechattet.",example:"A: Mit wem chattest du?\nB: Ich chatte mit meiner Schwester.",exampleSrc:"A: Who are you chatting with?\nB: I'm chatting with my sister.",funFact:"Unlike -ieren verbs, 'chatten' DOES get the ge- prefix: gechattet. Why? Because it was borrowed recently and conjugated like a regular German verb, not through French/Latin."},
{type:"teach",trg:"surfen",src:"to surf (the internet)",note:"Regular: ich surfe, du surfst. 'Im Internet surfen' = to browse the web.",example:"A: Was machst du gerade?\nB: Ich surfe im Internet.",exampleSrc:"A: What are you doing right now?\nB: I'm surfing the internet.",funFact:"Germans say 'im Internet surfen' like riding waves of information. The verb keeps its English pronunciation but gets German endings: surfe, surfst, surft."},
{type:"teach",trg:"sammeln",src:"to collect",note:"Regular: ich sammle, du sammelst. Past: gesammelt.",example:"A: Was sammelst du?\nB: Ich sammle alte Comics und Briefmarken.",exampleSrc:"A: What do you collect?\nB: I collect old comics and stamps.",funFact:"Germans are serious collectors. Briefmarkensammler (stamp collectors), Münzsammler (coin collectors), and Bierdeckelsammler (beer coaster collectors) all have dedicated clubs and meetups."},
{type:"teach",trg:"informieren",src:"to inform",note:"Regular: ich informiere. Reflexive: sich informieren = to find out, to inform oneself.",example:"A: Wo informierst du dich über Nachrichten?\nB: Ich informiere mich online.",exampleSrc:"A: Where do you get your news?\nB: I inform myself online.",funFact:"'Sich informieren' is reflexive: you inform YOURSELF. Germans love reflexive verbs for actions you do for your own benefit: sich erinnern, sich freuen, sich informieren."},
{type:"mc",q:"'Ich informiere mich im Internet.' Why is 'mich' in this sentence?",opts:["Because informieren is used reflexively here","Because the internet requires accusative","Because ich always needs mich","Because it is a question"],ans:"Because informieren is used reflexively here",hint:"The action of informing loops back to the subject. Think: I inform MYSELF."},
{type:"fb",s:"Er {1} sich über das Programm.",a:["informiert"],opts:["informiert","informieren","informiere","informierst"],hint:"Third person singular: er + verb. Which ending fits?",sSrc:"He {1} about the program."},
{type:"mc",q:"Mia sagt, dass sie jeden Tag einen Blog ___.",opts:["liest","lesen","lese","lest"],ans:"liest",hint:"In a dass-clause the verb goes to the end. Mia is 'sie,' so the verb needs the third person form."},
{type:"fb",s:"Ich weiß nicht, ob er gern {1}.",a:["chattet"],opts:["chattet","chatten","chatte","chattest"],hint:"After 'ob' the verb moves to the end. The subject is 'er.'",sSrc:"I don't know if he likes to {1}."},
{type:"drag_fill",s:"Sie fragt, ob Verumius {1} gern {2} und ob er Zeitschriften {3}.",blanks:{"1":"sich","2":"informiert","3":"sammelt"},pool:["sich","informiert","sammelt","mich","surft","chatten"],hint:"First clause: reflexive 'sich informieren' with verb at end. Second clause: 'sammeln' with er-form at end.",sSrc:"She asks whether Verumius likes to {2} {1} and whether he {3} magazines."},
{type:"mc",q:"How do you form the Partizip II of verbs ending in -ieren?",opts:["No ge- prefix: just stem + t","Normal ge- prefix: ge + stem + t","Double ge-: gege + stem + t","No change at all"],ans:"No ge- prefix: just stem + t",hint:"Think about studieren, telefonieren, informieren. They all follow the same pattern."},
{type:"fb",s:"Er sagt, dass er alte Comics {1}.",a:["sammelt"],opts:["sammelt","sammeln","sammle","gesammelt"],hint:"In a dass-clause the conjugated verb goes to the end. Subject is 'er.'",sSrc:"He says that he {1} old comics."},
{type:"mc",q:"Verumius surft im Internet. Er findet einen Blog. Was macht er?",opts:["He browses online and finds a blog","He goes surfing at the beach","He collects magazines","He listens to the radio"],ans:"He browses online and finds a blog",hint:"'Im Internet surfen' means browsing, not ocean waves."},
{type:"drag_fill",s:"Lukas erzählt, dass er {1} für Sendungen über Natur {2} und dass er Tipps im {3} gehört hat.",blanks:{"1":"sich","2":"interessiert","3":"Radio"},pool:["sich","interessiert","Radio","mich","informiert","Blog"],hint:"Reflexive 'sich interessieren' in the first dass-clause. He heard tips on which device?",sSrc:"Lukas tells us that he is {2} {1} in shows about nature and that he heard tips on the {3}."},
{type:"match",pairs:[{trg:"der Blog",src:"the blog"},{trg:"die Sendung",src:"the TV show"},{trg:"das Radio",src:"the radio"},{trg:"fotografieren",src:"to photograph"},{trg:"chatten",src:"to chat online"},{trg:"sammeln",src:"to collect"},{trg:"die Zeitschrift",src:"the magazine"}]},
{type:"teach",trg:"der Fotoapparat",src:"the camera (old style)",note:"Masculine compound: Foto + Apparat. Plural: die Fotoapparate.",example:"A: Hast du deinen Fotoapparat dabei?\nB: Nein, ich fotografiere nur mit dem Handy.\nA: Mein Opa hat noch einen alten Fotoapparat.",exampleSrc:"A: Do you have your camera with you?\nB: No, I only take photos with my phone.\nA: My grandpa still has an old camera.",funFact:"Before digital cameras, every German family had a Fotoapparat for vacations. Leica, a German brand, invented the 35mm camera in 1925."},
{type:"teach",trg:"die Kamera",src:"the camera",note:"Feminine. Plural: die Kameras. Modern, general word for camera.",example:"A: Welche Kamera benutzt du?\nB: Eine kleine Digitalkamera.\nA: Die Fotos sind wirklich gut!",exampleSrc:"A: Which camera do you use?\nB: A small digital camera.\nA: The photos are really good!",funFact:"Germany's camera industry shaped photography worldwide. Zeiss lenses, Leica cameras, and Rollei twin-lens reflexes were all born in Germany."},
{type:"teach",trg:"online",src:"online",note:"Adverb and adjective. Pronounced like English. Online sein = to be online.",example:"A: Bist du gerade online?\nB: Ja, ich surfe im Internet.\nA: Schick mir den Link!",exampleSrc:"A: Are you online right now?\nB: Yes, I'm surfing the internet.\nA: Send me the link!",funFact:"Germans adopted 'online' wholesale from English. The phrase 'online gehen' (to go online) is used by all generations."},
{type:"teach",trg:"das Buch",src:"the book",note:"Neuter. Plural: die Bücher (with Umlaut!).",example:"A: Was liest du gerade?\nB: Ein Buch über deutsche Geschichte.\nA: Klingt interessant! Leihst du es mir?",exampleSrc:"A: What are you reading?\nB: A book about German history.\nA: Sounds interesting! Will you lend it to me?",funFact:"Germany publishes about 70,000 new books per year, making it the third largest book market in the world after the US and China."},
{type:"teach",trg:"ausleihen",src:"to borrow / to lend out",note:"Separable: ich leihe aus. Perfekt: hat ausgeliehen. In der Bibliothek Bücher ausleihen.",example:"A: Kann ich das Buch ausleihen?\nB: Ja, du kannst es zwei Wochen behalten.\nA: Danke! Ich bringe es pünktlich zurück.",exampleSrc:"A: Can I borrow the book?\nB: Yes, you can keep it for two weeks.\nA: Thanks! I'll bring it back on time.",funFact:"German libraries are very popular. Over 200 million items are borrowed per year. Many now also lend e-books, video games, and even kitchen appliances."}
]}
,

// U9 L6: Nach dem Lauf - Story climax (post-run park scene)
{id:"deu_r9l6",title:"Nach dem Lauf",icon:"☕",xp:20,board:true,steps:[
{type:"intro",title:"Nach dem Lauf",desc:"The run is over. Verumius stretches in the park while Lukas arrives with coffees on his cargo bike. A text from Dr. Yilmaz reminds everyone why community matters.",goals:["Learn animal and leisure vocabulary","Review reflexive verbs, dass, ob, and conjunctions","Combine multiple grammar patterns in real conversation"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-park-stretching",trg:"Sonntagmorgen im Park. Verumius dehnt sich auf einer Bank. Die Luft riecht nach Gras und Kaffee. Ein Vogel singt in der Eiche über ihm.",src:"Sunday morning in the park. Verumius stretches on a bench. The air smells of grass and coffee. A bird sings in the oak above him."},
{type:"story",speaker:"verumius",trg:"Ich fühle mich großartig! Aber meine Beine tun weh. Ich muss mich mehr dehnen.",src:"I feel great! But my legs hurt. I need to stretch more."},
{type:"story",speaker:"lukas",trg:"Hey, Verumius! Ich habe Kaffee mitgebracht. Setz dich hin und trink! Ich glaube, dass du den verdient hast.",src:"Hey, Verumius! I brought coffee. Sit down and drink! I think that you earned it."},
{type:"teach",trg:"die Katze",src:"the cat",note:"Feminine. Plural: die Katzen.",example:"A: Hast du ein Haustier?\nB: Ja, ich habe eine Katze. Sie heißt Mimi.",exampleSrc:"A: Do you have a pet?\nB: Yes, I have a cat. Her name is Mimi.",funFact:"Germany has about 15 million pet cats, making them the most popular pet. The idiom 'die Katze im Sack kaufen' (to buy the cat in the bag) means to buy something sight unseen."},
{type:"teach",trg:"der Vogel",src:"the bird",note:"Masculine. Plural: die Vögel (with Umlaut!).",example:"A: Hörst du den Vogel?\nB: Ja, er singt wunderschön!",exampleSrc:"A: Do you hear the bird?\nB: Yes, it sings beautifully!",funFact:"'Einen Vogel haben' (to have a bird) means to be crazy in German. People tap their forehead to show someone 'hat einen Vogel.' Careful with this gesture!"},
{type:"teach",trg:"das Pferd",src:"the horse",note:"Neuter. Plural: die Pferde.",example:"A: Warst du schon mal auf einem Pferd?\nB: Nein, aber ich möchte es versuchen.",exampleSrc:"A: Have you ever been on a horse?\nB: No, but I would like to try.",funFact:"German has a great expression: 'Das beste Pferd im Stall' (the best horse in the stable) means the top performer. Germany's equestrian tradition runs deep."},
{type:"teach",trg:"das Tier",src:"the animal",note:"Neuter. Plural: die Tiere. From Old High German 'tior.'",example:"A: Was ist dein Lieblingstier?\nB: Ich mag Hunde, aber auch Katzen.",exampleSrc:"A: What is your favorite animal?\nB: I like dogs, but also cats.",funFact:"The German word 'Tierarzt' (animal doctor) is wonderfully literal. 'Tierschutz' (animal protection) is taken very seriously in Germany, with animal welfare written into the constitution since 2002."},
{type:"mc",q:"Lukas fragt: 'Hast du ein Haustier?' Verumius sagt: 'Ja, eine Katze.' Was ist eine Katze?",opts:["a dog","a bird","a cat","a horse"],ans:"a cat",hint:"This feminine noun names a popular pet that purrs."},
{type:"fb",s:"Im Park singt ein {1} im Baum.",a:"Vogel",opts:["Vogel","Pferd","Katze","Tier"],hint:"Which masculine animal is known for singing from branches?",sSrc:"In the park a {1} sings in the tree."},
{type:"teach",trg:"der Park",src:"the park",note:"Masculine. Plural: die Parks. Borrowed from English/French.",example:"A: Wo treffen wir uns?\nB: Im Park, neben der großen Eiche.",exampleSrc:"A: Where do we meet?\nB: In the park, next to the big oak.",funFact:"Berlin alone has over 2,500 public parks. The Tiergarten (animal garden) in Berlin was originally a royal hunting ground. Now it is the city's green lung."},
{type:"teach",trg:"die Tour",src:"the tour",note:"Feminine. Plural: die Touren. Also means 'a trip' or 'a route.'",example:"A: Machen wir am Samstag eine Radtour?\nB: Gute Idee! Ich freue mich darauf.",exampleSrc:"A: Shall we do a bike tour on Saturday?\nB: Good idea! I look forward to it.",funFact:"'Radtour' (bike tour), 'Wandertour' (hiking tour), 'Stadttour' (city tour). Germans love compound nouns, and they love organized outings even more."},
{type:"teach",trg:"der Workshop",src:"the workshop",note:"Masculine. Plural: die Workshops. Anglicism used in German.",example:"A: Ich besuche einen Workshop über Fotografie.\nB: Das klingt interessant!",exampleSrc:"A: I am attending a workshop on photography.\nB: That sounds interesting!",funFact:"Germans borrow many English words but pronounce them differently. 'Workshop' becomes 'VORK-shop' with a German W. The original German word is 'Werkstatt,' but Workshop sounds trendier."},
{type:"teach",trg:"der Zirkus",src:"the circus",note:"Masculine. Plural: die Zirkusse.",example:"A: Warst du schon im Zirkus?\nB: Ja, als Kind. Ich fand die Tiere toll.",exampleSrc:"A: Have you been to the circus?\nB: Yes, as a child. I loved the animals.",funFact:"The famous Circus Roncalli in Germany stopped using real animals in 2018 and replaced them with holograms. Technology meets tradition!"},
{type:"teach",trg:"der Zoo",src:"the zoo",note:"Masculine. Short for 'der Zoologische Garten.'",example:"A: Gehen wir morgen in den Zoo?\nB: Ja, ich möchte die Elefanten sehen.",exampleSrc:"A: Shall we go to the zoo tomorrow?\nB: Yes, I want to see the elephants.",funFact:"The Berlin Zoo, opened in 1844, is the oldest zoo in Germany and one of the most species-rich in the world, with over 20,000 animals."},
{type:"teach",trg:"der Krimi",src:"the crime novel / thriller",note:"Masculine. Short for 'der Kriminalroman.' Plural: die Krimis.",example:"A: Was liest du gerade?\nB: Einen Krimi von Sebastian Fitzek. Sehr spannend!",exampleSrc:"A: What are you reading right now?\nB: A thriller by Sebastian Fitzek. Very exciting!",funFact:"Germans love their Krimis. The TV show 'Tatort' (crime scene) has been running since 1970 and is a Sunday night ritual. Bars even host Tatort viewing parties."},
{type:"story",speaker:"verumius",trg:"Lukas, ich habe eine Nachricht von Dr. Yilmaz bekommen. Sie schreibt, dass Gemeinschaft das Wichtigste ist. Ob wir nächste Woche zusammen eine Tour machen?",src:"Lukas, I got a message from Dr. Yilmaz. She writes that community is the most important thing. Whether we should do a tour together next week?"},
{type:"story",speaker:"lukas",trg:"Natürlich! Und ich bringe Kaffee mit, denn ohne Kaffee läuft bei mir nichts.",src:"Of course! And I will bring coffee, because without coffee nothing works for me."},
{type:"mc",q:"Verumius sagt, dass Dr. Yilmaz über Gemeinschaft schreibt. Welcher Nebensatz ist richtig?",opts:["Sie schreibt, dass Gemeinschaft wichtig ist.","Sie schreibt, dass ist Gemeinschaft wichtig.","Sie schreibt, dass wichtig Gemeinschaft ist.","Sie schreibt, ist dass Gemeinschaft wichtig."],ans:"Sie schreibt, dass Gemeinschaft wichtig ist.",hint:"In a dass clause, the conjugated verb moves to the very end."},
{type:"fb",s:"Ich frage mich, {1} der Zoo am Sonntag offen ist.",a:"ob",opts:["ob","dass","weil","denn"],hint:"Which conjunction introduces an indirect yes/no question?",sSrc:"I wonder {1} the zoo is open on Sunday."},
{type:"drag_fill",s:"Lukas sagt, {1} er {2} auf die Tour {3}.",blanks:{1:"dass",2:"sich",3:"freut"},pool:["dass","sich","freut","ob","mich","lacht"],hint:"'Sich freuen' is reflexive. In a dass clause, the verb goes to the end.",sSrc:"Lukas says {1} he is looking forward {2} the tour."},
{type:"mc",q:"'Ich interessiere mich für Krimis, und Lukas interessiert sich für Sport.' What connects these two clauses?",opts:["und","aber","denn","oder"],ans:"und",hint:"Both facts are true and simply added together without contrast."},
{type:"fb",s:"Die Katze schläft, {1} sie müde ist.",a:"weil",opts:["weil","und","oder","denn"],hint:"This subordinating conjunction means 'because' and sends the verb to the end.",sSrc:"The cat is sleeping {1} it is tired."},
{type:"drag_fill",s:"Er fragt, {1} sie {2} für Pferde {3}.",blanks:{1:"ob",2:"sich",3:"interessiert"},pool:["ob","sich","interessiert","dass","mich","fragt"],hint:"Indirect yes/no question with a reflexive verb. Verb goes last.",sSrc:"He asks {1} she is interested in horses."},
{type:"mc",q:"Welcher Satz kombiniert 'sich fühlen' und 'denn' korrekt?",opts:["Ich fühle mich gut, denn ich habe Sport gemacht.","Ich mich fühle gut, denn ich habe Sport gemacht.","Ich fühle mich gut, denn ich Sport gemacht habe.","Ich fühle gut mich, denn ich habe Sport gemacht."],ans:"Ich fühle mich gut, denn ich habe Sport gemacht.",hint:"'Denn' is a coordinating conjunction, so the word order after it stays normal (verb second)."},
{type:"fb",s:"Sie ärgert {1} über den Lärm im Park.",a:"sich",opts:["sich","mich","dich","uns"],hint:"Third person reflexive pronoun for 'she' in a reflexive verb.",sSrc:"She is annoyed {1} about the noise in the park."},
{type:"mc",q:"'Verumius weiß nicht, ob er morgen eine Radtour macht oder ob er in den Zoo geht.' How many ob clauses are in this sentence?",opts:["One","Two","Three","None"],ans:"Two",hint:"Count the word 'ob.' Each one opens a new indirect question."},
{type:"drag_fill",s:"Er {1} sich, {2} der Krimi spannend ist, {3} er ihn lesen will.",blanks:{1:"fragt",2:"ob",3:"denn"},pool:["fragt","ob","denn","dass","freut","weil"],hint:"He asks himself (reflexive), whether... because... Two different conjunctions needed.",sSrc:"He asks himself {1} {2} the thriller is exciting, {3} he wants to read it."},
{type:"match",pairs:[{trg:"die Katze",src:"the cat"},{trg:"der Vogel",src:"the bird"},{trg:"das Pferd",src:"the horse"},{trg:"das Tier",src:"the animal"},{trg:"der Park",src:"the park"},{trg:"der Krimi",src:"the thriller"}]},
{type:"teach",trg:"die Gemeinschaft",src:"the community",note:"Feminine. From gemein (common) + -schaft (collective suffix). Plural: die Gemeinschaften.",example:"A: Die Gemeinschaft im Verein ist toll.\nB: Ja, alle helfen sich gegenseitig.\nA: Das ist das Beste am Vereinsleben.",exampleSrc:"A: The community in the club is great.\nB: Yes, everyone helps each other.\nA: That's the best thing about club life.",funFact:"Gemeinschaft vs. Gesellschaft is a famous sociological contrast coined by Ferdinand Tonnies in 1887. Gemeinschaft is warm personal bonds, Gesellschaft is formal society."},
{type:"teach",trg:"interessieren (sich)",src:"to be interested (in)",note:"Reflexive: sich interessieren für + accusative. Ich interessiere mich für Musik.",example:"A: Wofür interessierst du dich?\nB: Ich interessiere mich für Fotografie.\nA: Dann musst du die Ausstellung sehen!",exampleSrc:"A: What are you interested in?\nB: I'm interested in photography.\nA: Then you have to see the exhibition!",funFact:"Like many German reflexive verbs, the meaning changes with 'sich.' Without it, 'interessieren' means to interest someone else: Das interessiert mich (That interests me)."},
{type:"teach",trg:"leihen",src:"to lend / to borrow",note:"Irregular: ich leihe, du leihst. Past: geliehen. Not separable (unlike ausleihen).",example:"A: Kannst du mir zehn Euro leihen?\nB: Klar, hier bitte.\nA: Danke! Ich gebe es dir morgen zurück.",exampleSrc:"A: Can you lend me ten euros?\nB: Sure, here you go.\nA: Thanks! I'll give it back tomorrow.",funFact:"Leihen is the base verb. Add prefixes for nuance: ausleihen (borrow from a library), verleihen (to award/bestow), entleihen (formal borrowing)."},
{type:"teach",trg:"komisch",src:"funny / weird",note:"Adjective. Can mean 'funny' (humor) or 'strange' (suspicious). Context decides.",example:"A: Der Film war sehr komisch.\nB: Lustig komisch oder seltsam komisch?\nA: Beides!",exampleSrc:"A: The film was very funny/weird.\nB: Funny-funny or strange-funny?\nA: Both!",funFact:"Komisch comes from Greek 'komikos' (of comedy). In German it drifted to also mean 'strange.' If someone says 'Das ist komisch,' check their face to know which meaning."},
{type:"teach",trg:"sympathisch",src:"likeable / nice (personality)",note:"Adjective. Er ist sehr sympathisch = He is very likeable. Not 'sympathetic' (=mitfühlend)!",example:"A: Wie findest du den neuen Trainer?\nB: Er ist sehr sympathisch!\nA: Ja, er lacht viel.",exampleSrc:"A: What do you think of the new trainer?\nB: He is very likeable!\nA: Yes, he laughs a lot.",funFact:"False friend alert! German 'sympathisch' means likeable, not sympathetic. If you want to say sympathetic, use 'mitfühlend' or 'verständnisvoll.'"}
]},

{id:"deu_r9l7",title:"Vereinsprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"mc",q:"Ich freue mich, ___ das Konzert heute Abend stattfindet.",opts:["dass","ob","weil","denn"],ans:"dass",hint:"You know for certain it's happening."},
{type:"mc",q:"Er fragt sich, ___ das Training heute ausfällt.",opts:["ob","dass","weil","aber"],ans:"ob",hint:"He's uncertain and wants to find out."},
{type:"fb",s:"Sie {1} sich jeden Samstag im Park zum Joggen.",a:"treffen",opts:["treffen","freuen","ärgern","unterhalten"],hint:"They come together at a location.",sSrc:"They {1} every Saturday in the park for jogging."},
{type:"mc",q:"Wir ___ uns über die Ausstellung im Museum.",opts:["unterhalten","verlieren","vergessen","trainieren"],ans:"unterhalten",hint:"Think about having a conversation."},
{type:"fb",s:"Er hat Lust, Gitarre zu spielen, {1} er hat kein Instrument.",a:"aber",opts:["aber","dass","ob","denn"],hint:"A contrast between wanting and not having.",sSrc:"He feels like playing guitar, {1} he has no instrument."},
{type:"drag_fill",s:"Ich weiß, {1} sie {2} für Kunst interessiert.",blanks:{"1":"dass","2":"sich"},pool:["dass","ob","sich","mich","denn"],hint:"She has interest in art. Which conjunction for a known fact?",sSrc:"I know {1} she is {2} in art."},
{type:"mc",q:"___ du dich für den Wettbewerb anmelden möchtest, musst du morgen kommen.",opts:["Ob","Dass","Falls","Denn"],ans:"Falls",hint:"This is a conditional: if you want to sign up..."},
{type:"match",pairs:[{trg:"sich freuen",src:"to be happy/excited"},{trg:"sich treffen",src:"to meet up"},{trg:"sich ärgern",src:"to be annoyed"},{trg:"sich verlieben",src:"to fall in love"},{trg:"sich verabreden",src:"to make plans to meet"}]},
{type:"fb",s:"Hast du {1}, das Heft mitzubringen?",a:"vergessen",opts:["vergessen","verloren","geträumt","organisiert"],hint:"You were supposed to bring it but didn't remember.",sSrc:"Did you {1} to bring the notebook?"},
{type:"mc",q:"Sie träumt davon, in einem Zirkus zu arbeiten, ___ sie liebt Tiere.",opts:["denn","dass","ob","sich"],ans:"denn",hint:"This gives the reason. A coordinating conjunction."},
{type:"drag_fill",s:"Er fragt, {1} wir {2} am Samstag im Theater treffen.",blanks:{"1":"ob","2":"uns"},pool:["ob","dass","uns","sich","euch"],hint:"He's unsure about the plan. Which pronoun for 'wir'?",sSrc:"He asks {1} we meet {2} at the theater on Saturday."},
{type:"fb",s:"Die Veranstaltung {1} nächsten Freitag im Museum statt.",a:"findet",opts:["findet","nimmt","macht","gibt"],hint:"A separable verb meaning 'to take place'.",sSrc:"The event {1} next Friday at the museum."},
{type:"mc",q:"Ich interessiere ___ für Musik und Kultur.",opts:["mich","sich","dich","uns"],ans:"mich",hint:"The reflexive pronoun must match 'ich'."},
{type:"mc",q:"Er sagt, dass er gern Comics ___ und im Internet surft.",opts:["sammelt","sammeln","gesammelt","sammelst"],ans:"sammelt",hint:"After 'dass', the verb goes to the end, conjugated."},
{type:"drag_fill",s:"Wir nehmen an der Tour teil {1} fotografieren die Vögel im Park, {2} das Wetter schön ist.",blanks:{"1":"und","2":"denn"},pool:["und","aber","denn","dass","ob"],hint:"Two coordinating conjunctions: one connects actions, one gives a reason.",sSrc:"We do the tour {1} photograph the birds in the park, {2} the weather is nice."},
{type:"fb",s:"Sie ärgert {1} über die Sendung im Radio.",a:"sich",opts:["sich","mich","dich","euch"],hint:"The reflexive pronoun matches 'sie' (she).",sSrc:"She is annoyed {1} about the show on the radio."},
{type:"mc",q:"Weißt du, ___ der Workshop morgen stattfindet ___ am Wochenende?",opts:["ob ... oder","dass ... und","ob ... denn","dass ... aber"],ans:"ob ... oder",hint:"Asking between two possibilities you're unsure about."},
{type:"match",pairs:[{trg:"das Konzert",src:"the concert"},{trg:"die Zeitschrift",src:"the magazine"},{trg:"der Wettbewerb",src:"the competition"},{trg:"die Bibliothek",src:"the library"},{trg:"die Mannschaft",src:"the team"}]},
{type:"drag_fill",s:"Sie informiert {1}, {2} der Krimi heute Abend im Programm ist.",blanks:{"1":"sich","2":"ob"},pool:["sich","mich","ob","dass","denn"],hint:"She checks for herself whether something is on tonight.",sSrc:"She checks {1} {2} the thriller is on tonight."},
{type:"fb",s:"Ich weiß, {1} er jeden Tag auf dem Sportplatz trainiert.",a:"dass",opts:["dass","ob","denn","aber"],hint:"You're stating a fact you're certain about.",sSrc:"I know {1} he trains on the sports field every day."},
{type:"mc",q:"Er bastelt gern, ___ er malt nicht so oft.",opts:["aber","denn","dass","ob"],ans:"aber",hint:"A contrast between two hobbies."},
{type:"drag_fill",s:"Wir verabreden {1} für die Feier {2} treffen {3} vor dem Zoo.",blanks:{"1":"uns","2":"und","3":"uns"},pool:["uns","sich","und","aber","euch"],hint:"'Wir' reflexive appears twice: making plans AND meeting up.",sSrc:"We arrange {1} for the party {2} meet {3} in front of the zoo."},
{type:"mc",q:"Er hat viel Spaß, ___ er aktiv und sportlich ist.",opts:["denn","aber","ob","dass"],ans:"denn",hint:"Gives the reason why he has fun."},
{type:"fb",s:"Sie zeichnet gern Katzen {1} Pferde.",a:"und",opts:["und","aber","dass","ob"],hint:"Connecting two things she likes to draw.",sSrc:"She likes drawing cats {1} horses."},
{type:"drag_fill",s:"Ich glaube, {1} sie {2} auf das Fest freut, {3} sie hat schon ein Kleid gekauft.",blanks:{"1":"dass","2":"sich","3":"denn"},pool:["dass","ob","sich","mich","denn","aber"],hint:"A known belief, a reflexive verb, and a reason.",sSrc:"I believe {1} she is {2} about the festival, {3} she has already bought a dress."}
]},

{id:"deu_r9l8",title:"Der Mitgliedsausweis",icon:"🎫",xp:15,board:true,steps:[
{type:"intro",title:"Der Mitgliedsausweis",desc:"Verumius pins his Lauftreff membership card to the corkboard. His German life is growing. Time to learn the rest of the Freizeit vocabulary.",goals:["Sports and entertainment vocabulary","Personality adjectives","Everyday verbs for social life"]},
{type:"story",speaker:"narrator",mood:"proud",art:"de-corkboard",trg:"Verumius hängt den Mitgliedsausweis an die Pinnwand. Neben dem Mietvertrag, der Anmeldung und der Krankenkassenkarte. Vier Dokumente. Vier Schritte in Deutschland. Er lächelt.",src:"Verumius pins the membership card to the corkboard. Next to the lease, the registration, and the health insurance card. Four documents. Four steps in Germany. He smiles."},
{type:"teach",trg:"das Tennis",src:"tennis",note:"Neuter. Tennis spielen = to play tennis.",example:"A: Spielst du Tennis?\nB: Ja, jeden Samstag im Verein.\nA: Toll! Ich möchte auch anfangen.",exampleSrc:"A: Do you play tennis?\nB: Yes, every Saturday at the club.\nA: Great! I want to start too.",funFact:"Boris Becker won Wimbledon at 17. Germany went tennis-crazy in the 1980s. Every town built courts."},
{type:"teach",trg:"der Basketball",src:"basketball",note:"Masculine. Basketball spielen.",example:"A: Wer spielt heute Basketball?\nB: Die Mannschaft aus Hamburg.\nA: Ich bin Fan!",exampleSrc:"A: Who is playing basketball today?\nB: The team from Hamburg.\nA: I am a fan!",funFact:"Dirk Nowitzki made basketball huge in Germany. The BBL (Basketball Bundesliga) now has 18 teams."},
{type:"teach",trg:"der Volleyball",src:"volleyball",note:"Masculine. Beach-Volleyball is also popular in Germany.",example:"A: Wollen wir Volleyball spielen?\nB: Gern! Am Strand oder in der Halle?",exampleSrc:"A: Do you want to play volleyball?\nB: Sure! At the beach or in the hall?",funFact:"Germany's beach volleyball duo won Olympic gold in 2012 in London. Beach volleyball is huge at German lakes."},
{type:"mc",q:"Which sport uses a net and you hit the ball over it with your hands?",opts:["Volleyball","Basketball","Tennis","Fußball"],ans:"Volleyball",hint:"Teams of six stand on either side of a net."},
{type:"teach",trg:"das Rad",src:"wheel / bicycle",note:"Neuter. Rad fahren = to cycle. Plural: Räder.",example:"A: Fährst du mit dem Rad zur Arbeit?\nB: Ja, jeden Tag. Es ist gesünder.",exampleSrc:"A: Do you cycle to work?\nB: Yes, every day. It is healthier.",funFact:"Germans cycle about 1,000 km per person per year. Many cities have more bike paths than car lanes."},
{type:"teach",trg:"reiten",src:"to ride (horse)",note:"Irregular: ich reite, du reitest. Past: geritten (with sein!).",example:"A: Kannst du reiten?\nB: Ein bisschen. Als Kind habe ich geritten.",exampleSrc:"A: Can you ride?\nB: A little. I rode as a child.",funFact:"Germany is one of Europe's top equestrian nations. The German Riding Federation has over 660,000 members."},
{type:"teach",trg:"singen",src:"to sing",note:"Irregular: ich singe, du singst. Past: gesungen.",example:"A: Singst du gern?\nB: Ja, ich bin im Chor!\nA: Wirklich? Das ist toll!",exampleSrc:"A: Do you like singing?\nB: Yes, I am in a choir!\nA: Really? That is great!",funFact:"Germany has more amateur choirs than any country in Europe. About 3 million Germans sing in a choir."},
{type:"fb",s:"Mia {1} jeden Morgen im Park.",a:["joggt"],opts:["joggt","singt","reitet","malt"],hint:"What does Mia do at the Lauftreff? Running activity.",sSrc:"Mia {1} every morning in the park."},
{type:"teach",trg:"unternehmen",src:"to undertake / to do (an activity)",note:"Irregular: ich unternehme, du unternimmst. Separable: NOT (inseparable un-).",example:"A: Was wollen wir heute unternehmen?\nB: Wir könnten ins Museum gehen.",exampleSrc:"A: What shall we do today?\nB: We could go to the museum.",funFact:"Despite looking like a separable verb, unternehmen is inseparable. The 'unter' is a prefix, not a particle."},
{type:"teach",trg:"ausgehen",src:"to go out",note:"Separable: ich gehe aus, du gehst aus. Past: ausgegangen (sein).",example:"A: Gehst du heute Abend aus?\nB: Ja, wir gehen in die Disco.",exampleSrc:"A: Are you going out tonight?\nB: Yes, we are going to the disco.",funFact:"Germans go out later than many Europeans. Dinner at 8, clubs after midnight. Berlin clubs famously open at 1 AM."},
{type:"teach",trg:"probieren",src:"to try / to taste",note:"Regular: ich probiere, du probierst. Probieren geht über Studieren!",example:"A: Möchtest du den Kuchen probieren?\nB: Ja, gern! Er sieht lecker aus.",exampleSrc:"A: Would you like to try the cake?\nB: Yes, please! It looks delicious.",funFact:"The German proverb 'Probieren geht über Studieren' means 'trying beats studying.' Learning by doing!"},
{type:"mc",q:"'Was wollen wir heute unternehmen?' means:",opts:["What shall we do today?","What are you studying?","Where are you going?","Who is coming along?"],ans:"What shall we do today?",hint:"Planning an activity together. What should we DO?"},
{type:"teach",trg:"tauschen",src:"to swap / to exchange",note:"Regular: ich tausche. Tauschbörse = swap market.",example:"A: Wollen wir die Plätze tauschen?\nB: Ja, klar! Ich sitze gern am Fenster.",exampleSrc:"A: Do you want to swap seats?\nB: Yes, sure! I like sitting by the window.",funFact:"Germany has a strong Tauschkultur. Swap parties for clothes, books, and toys are common, especially in Berlin."},
{type:"teach",trg:"teilen",src:"to share / to divide",note:"Regular: ich teile. Teilen ist leben! (Sharing is living.)",example:"A: Sollen wir die Pizza teilen?\nB: Gute Idee! Eine ganze Pizza ist zu viel.",exampleSrc:"A: Should we share the pizza?\nB: Good idea! A whole pizza is too much.",funFact:"In German restaurants, 'getrennt' means separate bills and 'zusammen' means one bill. Germans often split."},
{type:"teach",trg:"schimpfen",src:"to scold / to complain",note:"Regular: ich schimpfe. Schimpfwort = swear word.",example:"A: Warum schimpft Hildi?\nB: Weil jemand den Müll falsch sortiert hat!",exampleSrc:"A: Why is Hildi scolding?\nB: Because someone sorted the trash wrong!",funFact:"Germans are known for Beschwerdekultur (complaint culture). If the rules are broken, someone WILL say something."},
{type:"fb",s:"Sollen wir die Rechnung {1}?",a:["teilen"],opts:["teilen","tauschen","schimpfen","probieren"],hint:"To split the bill between two people.",sSrc:"Should we {1} the bill?"},
{type:"teach",trg:"fantastisch",src:"fantastic",note:"Same in English! Easily recognizable.",example:"A: Wie war das Konzert?\nB: Fantastisch! Die Band war super.",exampleSrc:"A: How was the concert?\nB: Fantastic! The band was great.",funFact:"Many German adjectives for positive emotions are borrowed from French or Latin: fantastisch, romantisch, sympathisch."},
{type:"teach",trg:"langweilig",src:"boring",note:"Lang (long) + weilig (time-related). Literally: making time feel long.",example:"A: Wie findest du den Film?\nB: Langweilig. Lass uns gehen.",exampleSrc:"A: How do you find the movie?\nB: Boring. Let us leave.",funFact:"The word structure tells you the meaning: lang (long) + Weile (while). Something that makes time stretch."},
{type:"teach",trg:"nett",src:"nice / kind",note:"Common everyday compliment. 'Das ist nett von dir.'",example:"A: Dein Nachbar ist sehr nett.\nB: Ja, er hilft mir oft mit dem Müll.",exampleSrc:"A: Your neighbor is very nice.\nB: Yes, he often helps me with the trash.",funFact:"In German culture, 'nett' can also be faint praise. 'Nett ist die kleine Schwester von...' means nett is the lesser version of truly good."},
{type:"teach",trg:"toll",src:"great / awesome",note:"Very common positive adjective. Informal but widely used.",example:"A: Ich habe den Job bekommen!\nB: Toll! Herzlichen Glückwunsch!",exampleSrc:"A: I got the job!\nB: Great! Congratulations!",funFact:"'Toll' originally meant 'crazy/mad' in Old German. Over centuries it shifted to mean 'amazing.' Similar to English 'terrific.'"},
{type:"teach",trg:"witzig",src:"witty / funny",note:"From Witz (joke). Ein witziger Mensch = a funny person.",example:"A: Der Film war sehr witzig.\nB: Ja, ich habe so viel gelacht!",exampleSrc:"A: The movie was very funny.\nB: Yes, I laughed so much!",funFact:"German humor exists! Loriot, a legendary German comedian, proved that dry observational humor is universal."},
{type:"mc",q:"The opposite of 'langweilig' (boring) would be:",opts:["spannend","nett","toll","witzig"],ans:"spannend",hint:"Something that keeps you on the edge of your seat. Exciting."},
{type:"teach",trg:"spannend",src:"exciting / thrilling",note:"From spannen (to stretch/tighten). Like a taut bowstring.",example:"A: Das Buch ist sehr spannend!\nB: Wirklich? Worum geht es?",exampleSrc:"A: The book is very exciting!\nB: Really? What is it about?",funFact:"Spannend comes from the same root as English 'suspense.' A Spannungsroman is a thriller novel."},
{type:"teach",trg:"beliebt",src:"popular / well-liked",note:"From belieben (to please). Ein beliebtes Restaurant.",example:"A: Diese Sendung ist sehr beliebt.\nB: Ja, alle schauen sie!",exampleSrc:"A: This show is very popular.\nB: Yes, everyone watches it!",funFact:"Beliebt is a participial adjective. 'Es beliebt mir' (it pleases me) is the archaic origin."},
{type:"teach",trg:"berühmt",src:"famous",note:"From Ruhm (fame). Ein berühmter Musiker.",example:"A: Kennst du diesen berühmten Musiker?\nB: Ja, er ist überall bekannt!",exampleSrc:"A: Do you know this famous musician?\nB: Yes, he is known everywhere!",funFact:"Be-rühm-t: the prefix be- + Ruhm (glory) + -t ending. 'Touched by glory.' German word building at its finest."},
{type:"teach",trg:"besonders",src:"especially / particularly",note:"Adverb. Besonders gut = especially good.",example:"A: Was gefällt dir an Berlin?\nB: Besonders die Kultur und die Musik.",exampleSrc:"A: What do you like about Berlin?\nB: Especially the culture and the music.",funFact:"Besonders comes from 'besonder' (special/separate). Something that stands apart from the rest."},
{type:"teach",trg:"meistens",src:"mostly / usually",note:"Adverb. Meistens + verb = what you usually do.",example:"A: Was machst du am Wochenende?\nB: Meistens gehe ich spazieren.",exampleSrc:"A: What do you do on weekends?\nB: I usually go for a walk.",funFact:"Meistens comes from 'meist' (most). The -ens ending turns it into 'for the most part.'"},
{type:"drag_fill",s:"Der Film war {1} und {2}. Ich habe so viel gelacht!",blanks:{"1":"witzig","2":"toll"},pool:["witzig","toll","langweilig","schlimm","nett","traurig"],hint:"A funny and great movie. Two positive adjectives.",sSrc:"The film was {1} and {2}. I laughed so much!"},
{type:"match",pairs:[{trg:"fantastisch",src:"fantastic"},{trg:"langweilig",src:"boring"},{trg:"spannend",src:"exciting"},{trg:"beliebt",src:"popular"},{trg:"berühmt",src:"famous"},{trg:"witzig",src:"funny"},{trg:"nett",src:"nice"},{trg:"toll",src:"great"}]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-corkboard",trg:"Lukas schreibt in den Gruppenchat: 'Wer will nächste Woche mit dem ICE nach München fahren? Ich habe günstige Tickets gefunden!' Verumius hat noch nie allein den ICE genommen. Aber jetzt hat er einen Mitgliedsausweis. Er kann alles.",src:"Lukas writes in the group chat: 'Who wants to take the ICE to Munich next week? I found cheap tickets!' Verumius has never taken the ICE alone. But now he has a membership card. He can do anything."},
{type:"mc",q:"What is Lukas proposing in the group chat?",opts:["A train trip to Munich","A running competition","A museum visit","A concert in Berlin"],ans:"A train trip to Munich",hint:"He found cheap ICE tickets. Where does he want to go?"},
{type:"teach",trg:"die Band",src:"the band (music group)",note:"Feminine. Plural: die Bands. Borrowed from English.",example:"A: Welche Band spielte auf dem Festival?\nB: Eine Indie-Band aus Berlin.\nA: Waren sie gut?",exampleSrc:"A: Which band played at the festival?\nB: An indie band from Berlin.\nA: Were they good?",funFact:"Germany has a huge live music scene. Rock am Ring, Wacken Open Air, and Splash! are among Europe's biggest festivals."},
{type:"teach",trg:"die Disco",src:"the disco / nightclub",note:"Feminine. Also: die Disko. Plural: die Discos.",example:"A: Gehen wir heute Abend in die Disco?\nB: Ja, die Musik dort ist super!\nA: Um wie viel Uhr?",exampleSrc:"A: Shall we go to the club tonight?\nB: Yes, the music there is great!\nA: What time?",funFact:"Germans still say 'Disco' for nightclub, though younger people also say 'Club.' Berlin is considered the techno capital of the world."},
{type:"teach",trg:"das Festival",src:"the festival",note:"Neuter. Plural: die Festivals. From English.",example:"A: Warst du schon auf einem Festival?\nB: Ja, letztes Jahr auf dem Wacken Open Air.\nA: Drei Tage Musik und Camping!",exampleSrc:"A: Have you been to a festival?\nB: Yes, last year at Wacken Open Air.\nA: Three days of music and camping!",funFact:"Wacken Open Air is the world's largest heavy metal festival, held in a tiny village with just 2,000 residents but 85,000 visitors."},
{type:"teach",trg:"der Klub",src:"the club",note:"Masculine. Plural: die Klubs. Also spelled Club.",example:"A: Bist du Mitglied in einem Klub?\nB: Ja, in einem Leseclub.\nA: Was lest ihr gerade?",exampleSrc:"A: Are you a member of a club?\nB: Yes, in a book club.\nA: What are you reading now?",funFact:"The Berghain in Berlin is often called the world's most exclusive nightclub. The doormen decide who enters based on criteria nobody fully understands."},
{type:"teach",trg:"das Plakat",src:"the poster (public)",note:"Neuter. Plural: die Plakate. For advertising posters, event announcements.",example:"A: Hast du das Plakat für das Konzert gesehen?\nB: Ja, es hängt am Bahnhof.\nA: Die Farben sind toll!",exampleSrc:"A: Have you seen the poster for the concert?\nB: Yes, it hangs at the train station.\nA: The colors are great!",funFact:"Germany has Litfaßsäulen (advertising columns) on streets since 1855, invented by Ernst Litfaß to reduce wild poster chaos."},
{type:"teach",trg:"das Poster",src:"the poster (decorative)",note:"Neuter. Plural: die Poster. Borrowed from English. More personal than Plakat.",example:"A: Ich habe ein neues Poster für mein Zimmer.\nB: Was ist darauf?\nA: Ein Foto von den Alpen.",exampleSrc:"A: I have a new poster for my room.\nB: What's on it?\nA: A photo of the Alps.",funFact:"Plakat is for public/commercial posters. Poster is for decorative ones at home. Germans keep both words with different meanings."},
{type:"teach",trg:"das Quiz",src:"the quiz",note:"Neuter. Plural: die Quiz or Quizze. Borrowed from English.",example:"A: Machen wir ein Quiz über Deutschland?\nB: Gute Idee! Wer weiß mehr?\nA: Ich bin bereit!",exampleSrc:"A: Shall we do a quiz about Germany?\nB: Good idea! Who knows more?\nA: I'm ready!",funFact:"'Wer wird Millionär?' (Who Wants to Be a Millionaire?) has been running since 1999 with host Günther Jauch."},
{type:"teach",trg:"das Rätsel",src:"the puzzle / riddle",note:"Neuter. Plural: die Rätsel. Ein Kreuzworträtsel = crossword puzzle.",example:"A: Ich liebe Rätsel!\nB: Dann mach das Kreuzworträtsel in der Zeitung.\nA: Gute Idee!",exampleSrc:"A: I love puzzles!\nB: Then do the crossword in the newspaper.\nA: Good idea!",funFact:"The Brothers Grimm filled their fairy tales with riddles. Rumpelstiltskin is basically one giant name-guessing puzzle."},
{type:"teach",trg:"das Team",src:"the team",note:"Neuter. Plural: die Teams. Synonym: die Mannschaft (more traditional).",example:"A: Unser Team hat gewonnen!\nB: Fantastisch! Wie war das Spiel?\nA: Drei zu eins!",exampleSrc:"A: Our team won!\nB: Fantastic! How was the game?\nA: Three to one!",funFact:"Germans use both 'Team' (modern, borrowed) and 'Mannschaft' (traditional). In business, Team is preferred. In football, Mannschaft rules."},
{type:"teach",trg:"vereinbaren",src:"to arrange / to agree upon",note:"Inseparable: ich vereinbare. Perfekt: hat vereinbart.",example:"A: Wollen wir einen Termin vereinbaren?\nB: Ja, passt dir Dienstag?\nA: Perfekt, Dienstag um zehn.",exampleSrc:"A: Shall we arrange an appointment?\nB: Yes, does Tuesday work for you?\nA: Perfect, Tuesday at ten.",funFact:"From Verein (club). Vereinbaren means to come to an agreement. Very German: even scheduling is an act of unification."},
{type:"teach",trg:"auspacken",src:"to unpack",note:"Separable: ich packe aus. Opposite of einpacken.",example:"A: Hast du den Koffer schon ausgepackt?\nB: Nein, ich bin zu müde.\nA: Das mache ich morgen.",exampleSrc:"A: Have you unpacked the suitcase yet?\nB: No, I'm too tired.\nA: I'll do it tomorrow.",funFact:"In colloquial German, 'auspacken' also means to reveal secrets. A witness who 'auspackt' is spilling everything."},
{type:"teach",trg:"austauschen",src:"to exchange / to swap",note:"Separable: ich tausche aus. Emphasizes mutual exchange.",example:"A: Wollen wir Telefonnummern austauschen?\nB: Ja, gerne! Hier ist meine.\nA: Danke! Ich schreibe dir.",exampleSrc:"A: Shall we exchange phone numbers?\nB: Yes, gladly! Here is mine.\nA: Thanks! I'll text you.",funFact:"Schüleraustausch (student exchange) is very popular. About 20,000 German students go abroad each year."},
{type:"teach",trg:"romantisch",src:"romantic",note:"Adjective. Same root as English. Ein romantischer Abend.",example:"A: Der Film war sehr romantisch.\nB: Ja, aber auch ein bisschen kitschig.\nA: Das ist doch das Beste daran!",exampleSrc:"A: The film was very romantic.\nB: Yes, but also a bit cheesy.\nA: That's the best part!",funFact:"The Rhine Valley inspired the German Romantic movement in the 19th century. Romantisch comes from this era."}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 10: Deutsche Bahn
// Story: 47 min delay, seat conflict, sprint for Anschluss, Bordbistro
// CEFR: A2.2 - Perfekt sein, Partizip II, wenn-clause, subordinate word order
// ═══════════════════════════════════════════════════════════════
{n:10,lang:"de",srcLang:"en",track:"v2",title:"Deutsche Bahn",sub:"Train delays, seat conflicts, sprinting for connections",icon:"🚂",level:"A2.2",color:"#7B5EE8",lessons:[
{id:"deu_r10l1",title:"47 Minuten Verspätung",icon:"🚂",xp:15,board:true,steps:[
{type:"intro",title:"47 Minuten Verspätung",desc:"Berlin Hauptbahnhof. Der ICE hat 47 Minuten Verspätung. Die Anzeigetafel leuchtet rot. Erfahrene Reisende trinken Kaffee. Verumius starrt auf die Tafel.",goals:["Learn 10 travel and transport words","Understand train delay culture in Germany","See your first Perfekt sentences with sein"]},
{type:"teach",trg:"der Fahrplan",src:"the timetable",note:"der Fahrplan (masculine). Literally: drive-plan.\nCompound: fahren (to drive) + Plan (plan).",example:"A: Hast du den Fahrplan gesehen?\nB: Ja, der Zug kommt um 14:30.\nA: Dann haben wir noch Zeit.\nB: Lass uns einen Kaffee trinken.",exampleSrc:"A: Have you seen the timetable?\nB: Yes, the train comes at 14:30.\nA: Then we still have time.\nB: Let's grab a coffee.",funFact:"Deutsche Bahn prints pocket timetables (Taschenfahrplan) that some collectors treasure. The tradition goes back to the 1800s."},
{type:"teach",trg:"die Verspätung",src:"the delay",note:"die Verspätung (feminine). From: spät (late).\nverspäten = to be late, die Verspätung = the delay.",example:"A: Der ICE hat 47 Minuten Verspätung.\nB: Schon wieder?\nA: Ja, das ist leider normal.\nB: Dann verpasse ich meinen Anschluss.",exampleSrc:"A: The ICE has a 47-minute delay.\nB: Again?\nA: Yes, unfortunately that's normal.\nB: Then I'll miss my connection.",funFact:"In 2024, only about 64% of Deutsche Bahn long-distance trains arrived on time. Germans joke that delays are the only reliable thing about DB."},
{type:"teach",trg:"der Verkehr",src:"the traffic",note:"der Verkehr (masculine). Used for all traffic:\nStraßenverkehr (road), Zugverkehr (rail), Flugverkehr (air).",example:"A: Wie ist der Verkehr heute?\nB: Auf der Autobahn ist Stau.\nA: Dann nehme ich den Zug.\nB: Gute Idee, der fährt bald.",exampleSrc:"A: How is the traffic today?\nB: There's a traffic jam on the highway.\nA: Then I'll take the train.\nB: Good idea, it leaves soon.",funFact:"Germany's Autobahn has sections with no speed limit, yet traffic jams (Stau) cause roughly 450,000 hours of delays per year."},
{type:"teach",trg:"das Verkehrsmittel",src:"the means of transport",note:"das Verkehrsmittel (neuter). Compound:\nVerkehr (traffic) + Mittel (means/tool).\nPlural: die Verkehrsmittel.",example:"A: Welches Verkehrsmittel nimmst du?\nB: Ich fahre mit dem Zug.\nA: Ich nehme lieber das Fahrrad.\nB: Bei Regen? Du bist mutig!",exampleSrc:"A: Which means of transport do you take?\nB: I go by train.\nA: I prefer the bicycle.\nB: In rain? You're brave!",funFact:"Germans use over 30 billion trips per year on public transport. The Deutschlandticket (49-euro ticket) made buses and trains across the country accessible with one pass."},
{type:"teach",trg:"der Weg",src:"the way / path",note:"der Weg (masculine). Both literal path and figurative way.\nauf dem Weg = on the way.\nPlural: die Wege.",example:"A: Kennst du den Weg zum Bahnhof?\nB: Ja, immer geradeaus und dann links.\nA: Ist es weit?\nB: Nein, nur zehn Minuten zu Fuß.",exampleSrc:"A: Do you know the way to the station?\nB: Yes, straight ahead and then left.\nA: Is it far?\nB: No, only ten minutes on foot.",funFact:"The word Weg appears in hundreds of German compounds: Gehweg (sidewalk), Radweg (bike path), Umweg (detour), Ausweg (way out)."},
{type:"teach",trg:"die Nähe",src:"the vicinity / nearness",note:"die Nähe (feminine). From: nah (near/close).\nin der Nähe von = in the vicinity of, near.",example:"A: Gibt es ein Hotel in der Nähe?\nB: Ja, direkt am Bahnhof.\nA: Ist es teuer?\nB: Nein, es ist ganz günstig.",exampleSrc:"A: Is there a hotel nearby?\nB: Yes, right at the train station.\nA: Is it expensive?\nB: No, it's quite affordable.",funFact:"In der Nähe is one of the most useful travel phrases in German. You can combine it with von + dative to say near anything: in der Nähe vom Flughafen."},
{type:"tip",title:"Deutsche Bahn Kultur",text:"\"Wenige Minuten\" on the display board?\nThat means 5 to 60 minutes. Nobody knows.\n\nKey vocabulary for the Anzeigetafel:\n. pünktlich = on time\n. ca. 15 Min. später = approx. 15 min late\n. Zug fällt aus = train cancelled\n\nAnschluss = connecting train. Missing yours because of a delay? Deutsche Bahn must rebook you for free.\n\nThe Bordbistro sells coffee and pretzels on ICE trains. Many travelers treat delays as bonus reading time."},
{type:"mc",q:"Verumius steht am Hauptbahnhof. Der ICE hat 47 Minuten ___.",opts:["Verspätung","Verkehr","Fahrplan","Nähe"],ans:"Verspätung",hint:"Think about what happens when a train is late."},
{type:"fb",s:"Kennst du den {1} zum Bahnhof?",a:"Weg",opts:["Weg","Verkehr","Flug","Nähe"],hint:"Which word means way or path?",sSrc:"Do you know the {1} to the train station?"},
{type:"teach",trg:"der Flug",src:"the flight",note:"der Flug (masculine). From: fliegen (to fly).\nder Flughafen = the airport (flight harbor).\nPlural: die Flüge (note the umlaut).",example:"A: Wann geht dein Flug?\nB: Um halb acht morgen früh.\nA: Das ist aber früh!\nB: Ja, ich muss um fünf aufstehen.",exampleSrc:"A: When does your flight leave?\nB: At half past seven tomorrow morning.\nA: That's really early!\nB: Yes, I have to get up at five.",funFact:"Frankfurt Airport (Flughafen Frankfurt) is the busiest in Germany and the fourth busiest in Europe, handling over 59 million passengers a year."},
{type:"teach",trg:"buchen",src:"to book / to reserve",note:"buchen (regular verb). ich buche, du buchst, er bucht.\neine Reise buchen = to book a trip.\nein Hotel buchen = to book a hotel.",example:"A: Hast du das Hotel schon gebucht?\nB: Nein, ich mache das heute Abend.\nA: Buch lieber jetzt, es wird teurer!\nB: Okay, ich buche sofort online.",exampleSrc:"A: Have you already booked the hotel?\nB: No, I'll do it tonight.\nA: Better book now, it gets more expensive!\nB: Okay, I'll book online right away.",funFact:"The DB Navigator app lets you book train tickets, check live delays, and find your platform. Over 20 million Germans use it regularly."},
{type:"teach",trg:"umsteigen",src:"to transfer / to change (trains)",note:"umsteigen (separable verb). ich steige um.\nPerfekt: Ich bin umgestiegen (uses sein!).\num = around/change + steigen = to climb.",example:"A: Muss ich in Hannover umsteigen?\nB: Ja, auf Gleis 7.\nA: Wie viel Zeit habe ich?\nB: Nur acht Minuten. Beeil dich!",exampleSrc:"A: Do I have to transfer in Hannover?\nB: Yes, at platform 7.\nA: How much time do I have?\nB: Only eight minutes. Hurry!",funFact:"Umsteigen is a separable verb: the um splits off. Ich steige in Hamburg um. But in subordinate clauses it stays together: weil ich in Hamburg umsteige."},
{type:"teach",trg:"verpassen",src:"to miss (a train, bus, flight)",note:"verpassen (inseparable verb). ich verpasse.\nver- does NOT separate. ich verpasse den Zug.\nAlso used for missing events or deadlines.",example:"A: Ich habe den Zug verpasst!\nB: Wann fährt der nächste?\nA: In 45 Minuten.\nB: Dann hol dir einen Kaffee am Kiosk.",exampleSrc:"A: I missed the train!\nB: When does the next one leave?\nA: In 45 minutes.\nB: Then grab a coffee at the kiosk.",funFact:"Verpassen is inseparable (the ver- stays attached), while umsteigen is separable (the um detaches). Learning which prefixes separate is a key German skill."},
{type:"mc",q:"Verumius will nach München fliegen. Er braucht einen ___.",opts:["Flug","Weg","Fahrplan","Verkehr"],ans:"Flug",hint:"What do you need when you want to fly somewhere?"},
{type:"fb",s:"Ich muss in Hannover {1}.",a:"umsteigen",opts:["umsteigen","verpassen","buchen","fahren"],hint:"Which verb means to change trains?",sSrc:"I have to {1} in Hannover."},
{type:"mc",q:"Verumius hat den ICE verpasst. Was bedeutet verpassen?",opts:["to miss","to book","to transfer","to arrive"],ans:"to miss",hint:"The train left without him."},
{type:"tip",title:"Perfekt mit sein: Bewegung!",text:"Most German verbs form Perfekt with haben.\nBut verbs of MOVEMENT use sein:\n\nIch bin nach München gefahren.\n(I drove/went to Munich.)\n\nEr ist umgestiegen.\n(He transferred.)\n\nWir sind angekommen.\n(We arrived.)\n\nKey idea: if you physically move from A to B, use sein.\nYou will practice this more in the coming lessons."},
{type:"mc",q:"Ich ___ nach Berlin gefahren. (Perfekt with movement verb)",opts:["bin","habe","ist","hat"],ans:"bin",hint:"Movement verbs use a form of sein, not haben."},
{type:"fb",s:"Gibt es ein Hotel in der {1}?",a:"Nähe",opts:["Nähe","Weg","Verspätung","Verkehr"],hint:"Which word means vicinity or nearness?",sSrc:"Is there a hotel in the {1}?"},
{type:"mc",q:"Verumius will ein Ticket kaufen. Er muss das Ticket online ___.",opts:["buchen","umsteigen","verpassen","fahren"],ans:"buchen",hint:"Which verb means to book or reserve?"},
{type:"match",pairs:[{trg:"der Fahrplan",src:"the timetable"},{trg:"die Verspätung",src:"the delay"},{trg:"umsteigen",src:"to transfer"},{trg:"verpassen",src:"to miss"},{trg:"die Nähe",src:"the vicinity"}]},
{type:"mc",q:"Der ___ auf der Autobahn ist heute sehr schlecht.",opts:["Verkehr","Fahrplan","Flug","Weg"],ans:"Verkehr",hint:"Which word describes cars, buses, and trucks on the road?"},
{type:"fb",s:"Welches {1} nimmst du? Den Zug oder das Flugzeug?",a:"Verkehrsmittel",opts:["Verkehrsmittel","Verkehr","Fahrplan","Weg"],hint:"Which compound word means means of transport?",sSrc:"Which {1} do you take? The train or the airplane?"}
]}
,

{id:"deu_r10l2",title:"Unterwegs",icon:"🗺️",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs",desc:"Lerne wichtige Orte und Landschaften auf Deutsch kennen.",goals:["12 Orte und Landschaftswörter lernen","Artikel (der/die/das) mit neuen Nomen üben","Über deutsche Geografie sprechen"]},
{type:"teach",trg:"die Ampel",src:"traffic light",gender:"f",article:"die",note:"Feminine. Plural: die Ampeln.",funFact:"Deutsche Ampelmännchen sind Kultsymbole. Das Ost-Ampelmännchen mit Hut ist weltberühmt.",example:"A: Ist die Ampel grün?\nB: Nein, sie ist noch rot. Wir müssen warten.",exampleSrc:"A: Is the traffic light green?\nB: No, it's still red. We have to wait."},
{type:"teach",trg:"der Berg",src:"mountain",gender:"m",article:"der",note:"Masculine. Plural: die Berge.",funFact:"Die Zugspitze ist mit 2.962 Metern der höchste Berg Deutschlands.",example:"A: Siehst du den Berg dort?\nB: Ja, er ist sehr hoch. Können wir wandern gehen?",exampleSrc:"A: Do you see the mountain there?\nB: Yes, it's very high. Can we go hiking?"},
{type:"teach",trg:"die Brücke",src:"bridge",gender:"f",article:"die",note:"Feminine. Plural: die Brücken.",funFact:"Die Basteibrücke in Sachsen ist eine der meistfotografierten Brücken Europas.",example:"A: Gehen wir über die Brücke?\nB: Ja, auf der anderen Seite ist der Markt.",exampleSrc:"A: Shall we walk over the bridge?\nB: Yes, on the other side is the market."},
{type:"teach",trg:"der Fluss",src:"river",gender:"m",article:"der",note:"Masculine. Plural: die Flüsse. Beachte den Umlaut!",funFact:"Der Rhein ist 1.230 km lang und fließt durch sechs Länder.",example:"A: Welcher Fluss ist das?\nB: Das ist die Spree. Sie fließt durch Berlin.",exampleSrc:"A: Which river is that?\nB: That's the Spree. It flows through Berlin."},
{type:"teach",trg:"die Insel",src:"island",gender:"f",article:"die",note:"Feminine. Plural: die Inseln.",funFact:"Rügen ist die größte deutsche Insel mit berühmten weißen Kreidefelsen.",example:"A: Warst du schon mal auf einer Insel?\nB: Ja, ich war letzten Sommer auf Sylt.",exampleSrc:"A: Have you ever been to an island?\nB: Yes, I was on Sylt last summer."},
{type:"teach",trg:"die Landschaft",src:"landscape",gender:"f",article:"die",note:"Feminine. Plural: die Landschaften.",funFact:"Deutschland hat alles: Alpen im Süden, Nordsee im Norden, Wälder in der Mitte.",example:"A: Wie ist die Landschaft in Bayern?\nB: Sehr schön! Berge, Seen und grüne Wiesen.",exampleSrc:"A: What's the landscape like in Bavaria?\nB: Very beautiful! Mountains, lakes, and green meadows."},
{type:"teach",trg:"das Flugzeug",src:"the airplane",note:"Neuter noun. Plural: die Flugzeuge.\nCompound: Flug (flight) + Zeug (stuff/thing).",example:"A: Nimmst du den Zug oder das Flugzeug?\nB: Das Flugzeug. Es ist schneller.\nA: Aber der Zug ist umweltfreundlicher.\nB: Stimmt. Nächstes Mal nehme ich den Zug.",exampleSrc:"A: Are you taking the train or the plane?\nB: The plane. It is faster.\nA: But the train is more environmentally friendly.\nB: True. Next time I will take the train.",funFact:"'Flugzeug' literally means 'flying thing.' German compounds are wonderfully literal: Feuerzeug (fire-thing = lighter), Fahrzeug (driving-thing = vehicle), Werkzeug (work-thing = tool). The suffix '-zeug' is one of German's most productive."},
{type:"teach",trg:"der Norden",src:"the north",note:"Masculine noun. No common plural.\nAdjective: nördlich (northern).",example:"A: Wo liegt Hamburg?\nB: Hamburg liegt im Norden von Deutschland.\nA: Und München?\nB: München liegt im Süden.",exampleSrc:"A: Where is Hamburg?\nB: Hamburg is in the north of Germany.\nA: And Munich?\nB: Munich is in the south.",funFact:"Norddeutschland (Northern Germany) has a completely different culture from the south. The north is flatter, cooler, and more reserved. People say 'Moin' instead of 'Hallo.' The food is heavier on fish and potatoes."},
{type:"teach",trg:"der Süden",src:"the south",note:"Masculine noun. No common plural.\nAdjective: südlich (southern).",example:"A: Im Süden gibt es Berge.\nB: Ja, die Alpen sind wunderschön!\nA: Ich möchte im Süden wandern gehen.",exampleSrc:"A: In the south there are mountains.\nB: Yes, the Alps are beautiful!\nA: I would like to go hiking in the south.",funFact:"Southern Germany (Bayern and Baden-Württemberg) is economically the strongest region. The cultural divide between north and south is real: different dialects, different food, different beer. Northerners drink Pils, southerners drink Weizen."},
{type:"teach",trg:"das Fundbüro",src:"the lost and found office",note:"Neuter noun. Compound: Fund (find) + Büro (office).\nEvery train station and airport has one.",example:"A: Ich habe meinen Koffer verloren!\nB: Geh zum Fundbüro am Hauptbahnhof.\nA: Wo ist das Fundbüro?\nB: Im Erdgeschoss, neben dem Ausgang.",exampleSrc:"A: I lost my suitcase!\nB: Go to the lost and found office at the main station.\nA: Where is the lost and found?\nB: On the ground floor, next to the exit.",funFact:"German Fundbüros are remarkably efficient. The Deutsche Bahn central lost-and-found service handles over 250,000 items per year. You can search for lost items online at fundservice.bahn.de."},
{type:"teach",trg:"die Rolltreppe",src:"the escalator",note:"Feminine noun. Compound: Roll (roll) + Treppe (stairs).\nLiterally: rolling stairs.",example:"A: Wo ist die Rolltreppe?\nB: Dort drüben, neben dem Aufzug.\nA: Danke! Ich muss schnell zum Gleis 14.\nB: Dann lauf auf der Rolltreppe!",exampleSrc:"A: Where is the escalator?\nB: Over there, next to the elevator.\nA: Thanks! I need to get to platform 14 quickly.\nB: Then run on the escalator!",funFact:"On German escalators, stand on the RIGHT and walk on the LEFT. Breaking this rule in a busy train station will earn you angry looks and muttered 'Entschuldigung!' from rushing commuters."},
{type:"mc",q:"Wie sagt man 'traffic light' auf Deutsch?",opts:["die Ampel","der Berg","die Brücke","der Fluss"],ans:"die Ampel",hint:"Denk an die roten, gelben und grünen Lichter."},
{type:"teach",trg:"der Markt",src:"market",gender:"m",article:"der",note:"Masculine. Plural: die Märkte. Beachte den Umlaut!",funFact:"Deutsche Weihnachtsmärkte sind weltweit bekannt. Der Nürnberger Christkindlesmarkt ist über 400 Jahre alt.",example:"A: Gehen wir heute auf den Markt?\nB: Gute Idee! Ich brauche frisches Obst.",exampleSrc:"A: Shall we go to the market today?\nB: Good idea! I need fresh fruit."},
{type:"teach",trg:"das Rathaus",src:"town hall",gender:"n",article:"das",note:"Neuter. Plural: die Rathäuser. Rat (council) + Haus (house).",funFact:"Das Hamburger Rathaus hat 647 Zimmer, mehr als der Buckingham Palace.",example:"A: Wo ist das Rathaus?\nB: Direkt am Marktplatz, das große Gebäude.",exampleSrc:"A: Where is the town hall?\nB: Right at the market square, the big building."},
{type:"teach",trg:"die Kirche",src:"church",gender:"f",article:"die",note:"Feminine. Plural: die Kirchen.",funFact:"Der Kölner Dom brauchte über 600 Jahre bis zur Fertigstellung.",example:"A: Ist die Kirche alt?\nB: Ja, sie ist aus dem 14. Jahrhundert.",exampleSrc:"A: Is the church old?\nB: Yes, it's from the 14th century."},
{type:"teach",trg:"das Zentrum",src:"center",gender:"n",article:"das",note:"Neuter. Auch: die Mitte, die Innenstadt (city center).",funFact:"Viele deutsche Innenstädte haben Fußgängerzonen ohne Autos.",example:"A: Wie komme ich ins Zentrum?\nB: Nimm die U-Bahn bis Hauptbahnhof.",exampleSrc:"A: How do I get to the center?\nB: Take the subway to the main station."},
{type:"teach",trg:"der Strand",src:"beach",gender:"m",article:"der",note:"Masculine. Plural: die Strände. Beachte den Umlaut!",funFact:"Deutsche Nordseestrände haben Strandkörbe: überdachte Sitze gegen den Wind.",example:"A: Gibt es hier einen Strand?\nB: Ja, der Strand ist nur zehn Minuten zu Fuß.",exampleSrc:"A: Is there a beach here?\nB: Yes, the beach is only ten minutes on foot."},
{type:"teach",trg:"der Wald",src:"forest",gender:"m",article:"der",note:"Masculine. Plural: die Wälder. Beachte den Umlaut!",funFact:"Ein Drittel Deutschlands ist Wald. Der Schwarzwald inspirierte viele Märchen der Brüder Grimm.",example:"A: Gehen wir im Wald spazieren?\nB: Ja, die Luft dort ist wunderbar frisch.",exampleSrc:"A: Shall we go for a walk in the forest?\nB: Yes, the air there is wonderfully fresh."},
{type:"mc",q:"Welchen Artikel hat das Wort für 'town hall'?",opts:["das","der","die","den"],ans:"das",hint:"Es ist ein zusammengesetztes Wort mit Haus. Haus ist sächlich."},
{type:"fb",s:"Wir gehen über die {1} zum Markt.",a:"Brücke",opts:["Brücke","Berg","Strand","Wald"],hint:"Man geht darüber, um einen Fluss zu überqueren.",sSrc:"We walk over the {1} to the market."},
{type:"mc",q:"Der Rhein, die Donau und die Elbe sind deutsche ...",opts:["Flüsse","Berge","Inseln","Wälder"],ans:"Flüsse",hint:"Wasser fließt durch diese Landschaftsform."},
{type:"fb",s:"Im Dezember besuchen viele Menschen den Weihnachts{1}.",a:"markt",opts:["markt","berg","wald","strand"],hint:"Dort kann man Geschenke und Glühwein kaufen.",sSrc:"In December many people visit the Christmas {1}."},
{type:"tip",title:"Deutsche Geografie: 16 Bundesländer",text:"Deutschland hat 16 Bundesländer mit sehr unterschiedlichen Landschaften:\n\n- Norden: Nordsee, Ostsee, flaches Land, Inseln (Sylt, Rügen)\n- Mitte: Wälder (Schwarzwald, Thüringer Wald), Flüsse (Rhein, Elbe)\n- Süden: Alpen, Seen (Bodensee, Chiemsee), Berge\n- Osten: Seenplatte, historische Städte\n- Westen: Industriegebiete, Weinregionen am Rhein",deepDive:"Die 16 Bundesländer sind: Baden-Württemberg, Bayern, Berlin, Brandenburg, Bremen, Hamburg, Hessen, Mecklenburg-Vorpommern, Niedersachsen, Nordrhein-Westfalen, Rheinland-Pfalz, Saarland, Sachsen, Sachsen-Anhalt, Schleswig-Holstein und Thüringen. Jedes hat eine eigene Hauptstadt und Kultur."},
{type:"mc",q:"Welches Wort passt? 'Die Zugspitze ist der höchste ... Deutschlands.'",opts:["Berg","Fluss","Strand","Wald"],ans:"Berg",hint:"Die Zugspitze ist fast 3.000 Meter hoch."},
{type:"match",pairs:[{trg:"die Ampel",src:"traffic light"},{trg:"der Fluss",src:"river"},{trg:"die Insel",src:"island"},{trg:"der Wald",src:"forest"},{trg:"die Kirche",src:"church"},{trg:"das Zentrum",src:"center"}]},
{type:"fb",s:"Rügen ist die größte deutsche {1}.",a:"Insel",opts:["Insel","Brücke","Ampel","Kirche"],hint:"Ein Stück Land, umgeben von Wasser.",sSrc:"Rügen is the largest German {1}."},
{type:"mc",q:"Wo kann man im Sommer in der Sonne liegen?",opts:["am Strand","im Rathaus","an der Ampel","auf der Brücke"],ans:"am Strand",hint:"Sand, Wasser und Sonnenschirme sind dort."},
{type:"drag_fill",s:"Die {1} in Deutschland ist sehr vielfältig: {2} im Süden, {3} in der Mitte und {4} im Norden.",blanks:{"1":"Landschaft","2":"Berge","3":"Wälder","4":"Strände"},pool:["Landschaft","Berge","Wälder","Strände","Kirchen","Ampeln"],hint:"Denk an die Geografie: Alpen, Schwarzwald, Nordsee.",sSrc:"The {1} in Germany is very diverse: {2} in the south, {3} in the middle and {4} in the north."},
{type:"mc",q:"Was ist das Hamburger Rathaus?",opts:["Ein Gebäude für den Stadtrat","Ein Berg in Hamburg","Ein Fluss in Hamburg","Ein Markt in Hamburg"],ans:"Ein Gebäude für den Stadtrat",hint:"Rat bedeutet council, Haus bedeutet house."}
]}
,

{id:"deu_r10l3",title:"Mein Platz!",icon:"💺",xp:15,board:true,steps:[
{type:"intro",title:"Mein Platz!",desc:"Verumius findet seinen reservierten Platz im ICE besetzt. Zeit für eine höfliche Konfrontation.",goals:["Perfekt mit sein lernen","Partizip II bilden","Reisevokabeln üben"]},
{type:"teach",trg:"der Rucksack",src:"backpack",phonetic:"ROOK-zahk",example:"A: Ist das dein Rucksack auf dem Sitz?\nB: Oh, Entschuldigung! Ich nehme ihn weg.",exampleSrc:"A: Is that your backpack on the seat?\nB: Oh, sorry! I'll take it away.",note:"der Rucksack: literally 'back sack'. From Rücken (back) + Sack (sack).",funFact:"The word Rucksack was borrowed into English directly from German. Soldiers brought it back from WWI."},
{type:"teach",trg:"reservieren",src:"to reserve",phonetic:"reh-zer-VEER-en",example:"A: Haben Sie einen Platz reserviert?\nB: Ja, ich habe Platz 47 reserviert.",exampleSrc:"A: Did you reserve a seat?\nB: Yes, I reserved seat 47.",note:"Inseparable verb: no ge- in Partizip II. Reserviert, not gereserviert.",funFact:"Deutsche Bahn lets you reserve specific seats for just 4.50 EUR. Window or aisle, quiet zone or family area."},
{type:"teach",trg:"das Schiff",src:"ship",phonetic:"SHIF",example:"A: Bist du mit dem Schiff gefahren?\nB: Nein, ich bin mit dem Zug gefahren.",exampleSrc:"A: Did you travel by ship?\nB: No, I traveled by train.",note:"das Schiff, Plural: die Schiffe. Neuter noun.",funFact:"Germany has over 7,300 km of inland waterways. River cruises on the Rhine are world famous."},
{type:"teach",trg:"der Stadtplan",src:"city map",phonetic:"SHTAT-plahn",example:"A: Hast du einen Stadtplan?\nB: Nein, ich benutze mein Handy.",exampleSrc:"A: Do you have a city map?\nB: No, I use my phone.",note:"Compound: Stadt (city) + Plan (plan/map).",funFact:"Before smartphones, every German train station had a big Stadtplan on the wall outside. Some still do."},
{type:"teach",trg:"der Tourist / die Touristin",src:"tourist (m/f)",phonetic:"too-RIST / too-RIS-tin",example:"A: Bist du ein Tourist?\nB: Ja, ich bin zum ersten Mal in Deutschland.",exampleSrc:"A: Are you a tourist?\nB: Yes, it's my first time in Germany.",note:"der Tourist (male), die Touristin (female). Plural: die Touristen / die Touristinnen.",funFact:"Germany is the 7th most visited country in the world with over 30 million international visitors per year."},
{type:"teach",trg:"der Reifen",src:"tire",phonetic:"RYE-fen",example:"A: Der Reifen ist kaputt!\nB: Wir brauchen einen neuen Reifen.",exampleSrc:"A: The tire is broken!\nB: We need a new tire.",note:"der Reifen: also means 'hoop'. Don't confuse with reifen (to ripen).",funFact:"Germany has no general speed limit on many Autobahn sections. Good tires are essential."},
{type:"teach",trg:"der Motor",src:"motor, engine",phonetic:"MOH-tor",example:"A: Der Motor macht ein komisches Geräusch.\nB: Wir sollten zur Werkstatt fahren.",exampleSrc:"A: The engine is making a strange noise.\nB: We should drive to the workshop.",note:"der Motor, Plural: die Motoren. Stress on first syllable in German.",funFact:"Germany is home to BMW, Mercedes, Audi, Porsche, and VW. The car engine is practically a national symbol."},
{type:"teach",trg:"der Motorroller",src:"scooter",phonetic:"MOH-tor-rol-er",example:"A: Fährst du mit dem Motorroller zur Arbeit?\nB: Ja, das ist schneller als der Bus.",exampleSrc:"A: Do you ride the scooter to work?\nB: Yes, it's faster than the bus.",note:"Compound: Motor + Roller (roller). Also called just Roller.",funFact:"In German cities, e-scooters (E-Roller) are everywhere. You need to be at least 14 to ride one."},
{type:"tip",title:"Perfekt mit sein: Bewegung und Veränderung",text:"Most verbs use haben for Perfekt.\nBut verbs of MOTION or CHANGE OF STATE use sein:\n\nIch bin gefahren. (I drove/traveled)\nEr ist gegangen. (He went/walked)\nSie ist gekommen. (She came)\nWir sind angekommen. (We arrived)\n\nThink: if the subject MOVES somewhere or CHANGES state, use sein.\nStay, happen, be = also sein: Ich bin geblieben, es ist passiert.",deepDive:"The sein verbs are a closed group. The most common ones:\n\nMotion: gehen, kommen, fahren, fliegen, laufen, reisen, schwimmen\nArrival/departure: ankommen, abfahren, einsteigen, aussteigen\nChange of state: werden (become), sterben (die), einschlafen (fall asleep), aufwachen (wake up)\nExceptions: sein (to be) and bleiben (to stay) also use sein.\n\nIch bin gewesen. (I was/have been)\nEr ist geblieben. (He stayed)"},
{type:"verb_table",title:"Perfekt mit sein",label:"sein + Partizip II",groups:[{header:"Bewegungsverben (motion verbs)",rows:[{pronoun:"ich",form:"bin gefahren",src:"drove/traveled"},{pronoun:"du",form:"bist gegangen",src:"went/walked"},{pronoun:"er/sie/es",form:"ist gekommen",src:"came"},{pronoun:"wir",form:"sind angekommen",src:"arrived"},{pronoun:"ihr",form:"seid geflogen",src:"flew"},{pronoun:"sie/Sie",form:"sind gelaufen",src:"ran/walked"}]}],note:"All these verbs describe movement from A to B. That's why they use sein."},
{type:"tip",title:"Partizip II: So bildest du es",text:"Regular verbs: ge + Stamm + t\nmachen -> gemacht, kaufen -> gekauft\n\nIrregular verbs: ge + Stamm + en (often with vowel change)\nfahren -> gefahren, gehen -> gegangen\n\nSeparable verbs: Präfix + ge + Stamm + t/en\nankommen -> angekommen, einkaufen -> eingekauft\n\nInseparable verbs (be-, er-, ver-, ent-, ge-, zer-): NO ge-\nreservieren -> reserviert, besuchen -> besucht",deepDive:"The inseparable prefixes are: be-, emp-, ent-, er-, ge-, miss-, ver-, zer-.\nAlso: verbs ending in -ieren never get ge-: telefonieren -> telefoniert, reservieren -> reserviert.\n\nSeparable prefix verbs split the ge- inside:\nein|kaufen -> ein-ge-kauft\nan|kommen -> an-ge-kommen\nab|fahren -> ab-ge-fahren\n\nIrregular Partizip II forms must be memorized. Common ones:\ngehen -> gegangen, kommen -> gekommen, fahren -> gefahren, fliegen -> geflogen, nehmen -> genommen, essen -> gegessen, trinken -> getrunken, schreiben -> geschrieben, lesen -> gelesen."},
{type:"mc",q:"Verumius sagt: 'Ich ___ mit dem ICE gefahren.' Welches Hilfsverb passt?",opts:["bin","habe","ist","hat"],ans:"bin",hint:"Fahren is a motion verb. First person singular of sein?"},
{type:"mc",q:"Welcher Satz ist richtig?",opts:["Sie ist nach Berlin geflogen.","Sie hat nach Berlin geflogen.","Sie ist nach Berlin gefliegen.","Sie hat nach Berlin gefliegen."],ans:"Sie ist nach Berlin geflogen.",hint:"Fliegen uses sein for Perfekt. The Partizip II is unregelmäßig."},
{type:"fb",s:"Der Zug {1} um 10 Uhr angekommen.",a:"ist",opts:["ist","hat","bin","sind"],hint:"Ankommen is arrival. Third person singular of sein.",sSrc:"The train {1} arrived at 10 o'clock."},
{type:"fb",s:"Wir {1} gestern nach Hamburg gefahren.",a:"sind",opts:["sind","haben","ist","bin"],hint:"Wir uses the plural form of sein in Perfekt.",sSrc:"We {1} driven to Hamburg yesterday."},
{type:"mc",q:"Was ist das Partizip II von 'reservieren'?",opts:["reserviert","gereserviert","reservieren","gereservieren"],ans:"reserviert",hint:"Verbs ending in -ieren are inseparable. No ge- prefix needed."},
{type:"fb",s:"Er hat einen Platz {1}.",a:"reserviert",opts:["reserviert","gereserviert","reservieren","reserve"],hint:"Inseparable verb: no ge- prefix. Past participle ends in -t.",sSrc:"He has {1} a seat."},
{type:"mc",q:"'ankommen' -> Partizip II?",opts:["angekommen","geankommen","ankommen","angekommt"],ans:"angekommen",hint:"Separable verb: the ge- goes between prefix and stem."},
{type:"drag_fill",s:"Verumius {1} zum Platz {2} und hat seinen Rucksack {3}.",blanks:{1:"ist",2:"gegangen",3:"genommen"},pool:["ist","hat","gegangen","genommen","gefahren","gemacht"],hint:"Walking to a seat uses sein. Taking a backpack uses haben.",sSrc:"Verumius {1} {2} to the seat and has taken his backpack."},
{type:"mc",q:"Ein Mann sitzt auf Platz 47. Verumius sagt: 'Entschuldigung, ich habe diesen Platz ___.' Was fehlt?",opts:["reserviert","gereserviert","reservieren","reserve"],ans:"reserviert",hint:"Reservieren keeps no ge- prefix. Think about the -ieren rule."},
{type:"fb",s:"Die Touristin {1} mit dem Schiff nach Norwegen gefahren.",a:"ist",opts:["ist","hat","bin","sind"],hint:"Fahren means motion from A to B. She is one person.",sSrc:"The tourist {1} traveled by ship to Norway."},
{type:"drag_fill",s:"Verumius {1} mit dem ICE {2} und {3} in Frankfurt {4}.",blanks:{1:"ist",2:"gefahren",3:"ist",4:"angekommen"},pool:["ist","ist","hat","hat","gefahren","angekommen","gefahrt","ankommt"],hint:"Both fahren and ankommen are motion verbs. Both need sein.",sSrc:"Verumius {1} {2} by ICE and {3} {4} in Frankfurt."},
{type:"match",pairs:[{trg:"gefahren",src:"driven/traveled"},{trg:"gegangen",src:"went/walked"},{trg:"angekommen",src:"arrived"},{trg:"geflogen",src:"flew"},{trg:"reserviert",src:"reserved"}]},
{type:"mc",q:"Verumius zeigt seine Reservierung. Der Mann sagt: 'Oh! Ich ___ im falschen Wagen gesessen.' Welches Hilfsverb?",opts:["habe","bin","ist","hat"],ans:"habe",hint:"Sitzen is NOT motion. You stay in one place. Think about haben."},
{type:"fb",s:"Mein Motorroller {1} letzte Woche kaputt gegangen.",a:"ist",opts:["ist","hat","bin","sind"],hint:"Kaputt gehen means to break. It is a change of state.",sSrc:"My scooter {1} broken down last week."}
]},

{id:"deu_r10l4",title:"Wenn der Zug Verspätung hat",icon:"📐",xp:20,board:true,steps:[
{type:"intro",title:"Wenn der Zug Verspätung hat",desc:"Nebensätze mit wenn, Wortstellung in Nebensätzen und Reisevokabular.",goals:["wenn + verb-final word order","Subordinate clause consolidation (weil/dass/wenn/ob)","Präteritum modals in travel context","8 new travel words"]},
{type:"teach",trg:"packen",src:"to pack",phonetic:"PAH-ken",example:"A: Hast du schon gepackt?\nB: Nein, ich packe immer am letzten Tag.",exampleSrc:"A: Have you packed already?\nB: No, I always pack on the last day.",note:"Regular verb. Also used figuratively: Das packe ich! (I can handle it!)",funFact:"Germans are famous for packing efficiently. There is even a verb 'zusammenpacken' for packing things together."},
{type:"teach",trg:"einpacken",src:"to pack (in), to wrap up",phonetic:"AIN-pah-ken",example:"A: Soll ich die Geschenke einpacken?\nB: Ja, bitte pack sie in Papier ein.",exampleSrc:"A: Should I wrap the gifts?\nB: Yes, please wrap them in paper.",note:"Separable verb: ein|packen. Ich packe den Koffer ein.",funFact:"At German stores, cashiers rarely bag your items. You einpacken your own groceries."},
{type:"teach",trg:"parken",src:"to park",phonetic:"PAR-ken",example:"A: Wo hast du geparkt?\nB: Ich habe direkt am Bahnhof geparkt.",exampleSrc:"A: Where did you park?\nB: I parked right at the train station.",note:"Regular verb. Partizip II: geparkt. Uses haben.",funFact:"Parking at German train stations can cost 5 to 15 Euro per day. Many commuters use Park-and-Ride lots instead."},
{type:"teach",trg:"verreisen",src:"to go on a trip, to travel away",phonetic:"fair-RYE-zen",example:"A: Verreist ihr diesen Sommer?\nB: Ja, wir sind letztes Jahr nach Italien verreist.",exampleSrc:"A: Are you going on a trip this summer?\nB: Yes, we traveled to Italy last year.",note:"Inseparable prefix ver-. Uses sein in Perfekt: Ich bin verreist.",funFact:"Germans have on average 30 vacation days per year. Verreisen is practically a national hobby."},
{type:"teach",trg:"ziehen",src:"to pull, to move (residence)",phonetic:"TSEE-en",example:"A: Zieh bitte die Tür zu!\nB: Okay, ich ziehe sie zu.",exampleSrc:"A: Please pull the door shut!\nB: Okay, I am pulling it shut.",note:"Irregular: ziehen, zog, gezogen. With sein when meaning 'to move': Ich bin nach Berlin gezogen.",funFact:"Ziehen has over 20 compound forms in German, from anziehen (to dress) to umziehen (to move house)."},
{type:"teach",trg:"liefern",src:"to deliver",phonetic:"LEE-fern",example:"A: Wann wird das Paket geliefert?\nB: Der Bote liefert es morgen.",exampleSrc:"A: When will the package be delivered?\nB: The courier delivers it tomorrow.",note:"Regular verb. Die Lieferung = the delivery.",funFact:"Deutsche Post delivers around 1.6 billion parcels per year in Germany alone."},
{type:"teach",trg:"direkt",src:"direct, directly",phonetic:"dee-REKT",example:"A: Gibt es einen direkten Zug nach Hamburg?\nB: Ja, der ICE fährt direkt ohne Umsteigen.",exampleSrc:"A: Is there a direct train to Hamburg?\nB: Yes, the ICE goes directly without changing.",note:"Adjective and adverb. Direkt am Bahnhof = right at the station.",funFact:"A direkter Zug means no transfers. Germans strongly prefer these, because Umsteigen (changing trains) risks missing connections."},
{type:"teach",trg:"offen",src:"open, honest",phonetic:"OH-fen",example:"A: Ist das Fenster offen?\nB: Ja, ich habe es offen gelassen.",exampleSrc:"A: Is the window open?\nB: Yes, I left it open.",note:"Adjective. Not the same as öffnen (to open, verb). Die Tür ist offen = The door is open.",funFact:"Offene Türen (open doors) is a common metaphor in German. Tag der offenen Tür is an open house event at schools and businesses."},
{type:"tip",title:"Nebensatz mit wenn",text:"wenn (if/when) sends the conjugated verb to the END of the clause.\n\nMain clause: Der Zug hat Verspätung.\nNebensatz: Wenn der Zug Verspätung hat, ...\n\nNotice: hat moves to the end after wenn.\n\nWenn can mean 'if' (conditional) or 'when/whenever' (temporal):\n. Wenn es regnet, bleibe ich zu Hause. (If/When it rains...)\n. Wenn ich nach Berlin fahre, nehme ich den ICE. (When I go to Berlin...)\n\nThe main clause after a wenn-clause starts with the verb (verb-second rule):\nWenn ich packe, vergesse ich immer etwas.",deepDive:"The conjugated verb always goes to the final position in a wenn-clause. If the sentence starts with the wenn-clause, the main clause begins with the verb: Wenn ..., VERB subject ... This is called 'inversion' and happens after all subordinate clauses."},
{type:"tip",title:"Nebensatz-Wortstellung: weil, dass, wenn, ob",text:"Four conjunctions you know all share the same rule: the verb goes to the END.\n\n. weil (because): Ich bin müde, weil ich früh aufgestanden bin.\n. dass (that): Ich weiß, dass der Zug um 9 fährt.\n. wenn (if/when): Wenn du kommst, bringe ich Kaffee mit.\n. ob (whether): Ich frage, ob der Zug pünktlich ist.\n\nAll four: conjunction + subject + ... + VERB (at the end).\nWith Perfekt, the helping verb goes last: ... weil ich den Zug verpasst habe.",deepDive:"These are called subordinating conjunctions (Subjunktionen). They create dependent clauses that cannot stand alone. The verb-final rule applies to ALL subordinating conjunctions in German, not just these four."},
{type:"mc",q:"Which word order is correct after 'wenn'?",opts:["Wenn ich den Koffer packe, ...","Wenn ich packe den Koffer, ...","Wenn packe ich den Koffer, ...","Wenn den Koffer ich packe, ..."],ans:"Wenn ich den Koffer packe, ...",hint:"The verb moves to the final position in the clause."},
{type:"fb",s:"Wenn der Zug Verspätung {1}, verpasse ich den Anschluss.",a:"hat",opts:["hat","haben","habe","ist"],hint:"The subject is 'der Zug', so which form fits?",sSrc:"If the train {1} a delay, I will miss the connection."},
{type:"mc",q:"'Wenn ich nach München verreist bin, habe ich immer den ICE genommen.' What does 'wenn' mean here?",opts:["Whenever (temporal, repeated action)","If (conditional, hypothetical)","Because (causal)","That (declarative)"],ans:"Whenever (temporal, repeated action)",hint:"The sentence describes something that happened multiple times."},
{type:"fb",s:"Ich frage, ob der Zug pünktlich {1}.",a:"ist",opts:["ist","sein","bist","hat"],hint:"The subject is 'der Zug', third person singular.",sSrc:"I ask whether the train {1} on time."},
{type:"drag_fill",s:"Wenn ich früh {1}, {2} ich alles in den Koffer {3}.",blanks:{"1":"aufstehe","2":"packe","3":"ein"},pool:["aufstehe","packe","ein","stehe","packen","aus"],hint:"First blank: getting up early (separable verb). Main clause: a separable verb that means putting things into something.",sSrc:"When I {1} early, I {2} everything into the suitcase {3}."},
{type:"mc",q:"Wir konnten nicht verreisen, ... der Zug Verspätung hatte.",opts:["weil","wenn","und","aber"],ans:"weil",hint:"This gives a reason for not traveling."},
{type:"fb",s:"Er {1} gestern nicht parken, weil der Parkplatz voll war.",a:"konnte",opts:["konnte","kann","konnten","gekonnt"],hint:"Präteritum modal, third person singular, past tense.",sSrc:"He {1} not park yesterday because the parking lot was full."},
{type:"drag_fill",s:"Wenn ich nach Berlin {1}, {2} ich immer direkt am Bahnhof {3}.",blanks:{"1":"fahre","2":"parke","3":""},pool:["fahre","parke","fährt","parken"],hint:"Wenn-clause: verb final. Main clause: verb second after comma.",sSrc:"When I {1} to Berlin, I always {2} right at the train station."},
{type:"mc",q:"Sie wollte den Koffer einpacken, aber sie ... keine Zeit.",opts:["hatte","hat","haben","hatten"],ans:"hatte",hint:"Präteritum of haben, third person singular."},
{type:"fb",s:"Wenn das Paket {1} wird, bin ich nicht zu Hause.",a:"geliefert",opts:["geliefert","liefern","liefert","geliefern"],hint:"Partizip II of a regular verb in a passive construction.",sSrc:"When the package {1}, I will not be at home."},
{type:"match",pairs:[{trg:"Wenn es regnet, ...",src:"verb-final: regnet at end"},{trg:"..., weil er müde war.",src:"verb-final: war at end"},{trg:"Ich weiß, dass er kommt.",src:"verb-final: kommt at end"},{trg:"Ich frage, ob sie parkt.",src:"verb-final: parkt at end"}]},
{type:"mc",q:"Wenn ich letztes Jahr verreist ..., habe ich den Koffer immer selbst gepackt.",opts:["bin","habe","war","hatte"],ans:"bin",hint:"Verreisen uses sein in Perfekt, not haben."},
{type:"drag_fill",s:"Ich musste den Koffer {1}, weil ich morgen {2}.",blanks:{"1":"packen","2":"verreise"},pool:["packen","verreise","gepackt","verreist","packe","reise"],hint:"After a modal verb, use the infinitive. Weil-clause: verb final.",sSrc:"I had to {1} the suitcase because I am {2} tomorrow."},
{type:"fb",s:"Wenn der Zug direkt {1}, muss man nicht umsteigen.",a:"fährt",opts:["fährt","fahren","gefahren","fuhr"],hint:"Present tense, third person singular of fahren.",sSrc:"If the train {1} directly, one does not have to transfer."},
{type:"mc",q:"Wir sind nach Hamburg gezogen, weil mein Vater dort eine Stelle ... .",opts:["hatte","hat","haben","gehabt"],ans:"hatte",hint:"Präteritum of haben. The reason is in the past."},
{type:"drag_fill",s:"Wenn ich {1} habe, {2} ich immer die Tür {3}.",blanks:{"1":"gepackt","2":"ziehe","3":"zu"},pool:["gepackt","ziehe","zu","packe","gezogen","auf"],hint:"Perfekt in wenn-clause (habe at end). Main clause: a separable verb meaning to close by pulling.",sSrc:"When I have {1}, I always {2} the door {3}."},
{type:"mc",q:"Which sentence has correct word order?",opts:["Ich weiß, dass er den Koffer gepackt hat.","Ich weiß, dass er hat den Koffer gepackt.","Ich weiß, dass er gepackt den Koffer hat.","Ich weiß, dass gepackt er den Koffer hat."],ans:"Ich weiß, dass er den Koffer gepackt hat.",hint:"In Perfekt inside a dass-clause, the helping verb goes last."},
{type:"fb",s:"Wenn die Tür {1} ist, kommt kalte Luft herein.",a:"offen",opts:["offen","öffnen","geöffnet","offene"],hint:"An adjective describing the state of the door.",sSrc:"If the door is {1}, cold air comes in."},
{type:"mc",q:"Er konnte nicht einpacken, weil der Koffer zu klein ... .",opts:["war","ist","sein","gewesen"],ans:"war",hint:"Präteritum of sein. The sentence is about a past situation."},
{type:"drag_fill",s:"Wenn ich {1} bin, {2} ich immer viel {3}.",blanks:{"1":"verreist","2":"habe","3":"erlebt"},pool:["verreist","habe","erlebt","verreise","bin","erleben"],hint:"Wenn-clause uses Perfekt with sein (verreisen). Main clause also Perfekt with haben (erleben).",sSrc:"When I have {1}, I have always {2} a lot."}
]},

{id:"deu_r10l5",title:"Hin und her",icon:"↔️",xp:15,board:true,steps:[
{type:"intro",title:"Hin und her",desc:"Wohin geht die Reise? Lerne Richtungswörter mit hin, her und zurück.",goals:["Directional words with hin/her/zurück","Review Perfekt with sein","Combine with wenn-clauses"]},
{type:"teach",trg:"zurückfahren",src:"to drive back",phonetic:"tsoo-RÜCK-fah-ren",example:"A: Wann fährst du zurück?\nB: Ich fahre morgen Abend zurück.",exampleSrc:"A: When are you driving back?\nB: I'm driving back tomorrow evening.",note:"Separable: fährt ... zurück. Perfekt: ist zurückgefahren (sein, because movement).",funFact:"Germans say 'Ich fahre zurück' even for train travel. Fahren covers all vehicle transport."},
{type:"teach",trg:"zurückgeben",src:"to give back",phonetic:"tsoo-RÜCK-gay-ben",example:"A: Kannst du mir das Buch zurückgeben?\nB: Ja, ich gebe es dir morgen zurück.",exampleSrc:"A: Can you give the book back to me?\nB: Yes, I'll give it back to you tomorrow.",note:"Separable: gibt ... zurück. Perfekt: hat zurückgegeben (haben, no movement).",funFact:"At German libraries you 'geben zurück' your books. Late fees are called Mahngebühren."},
{type:"teach",trg:"zurückgehen",src:"to go back",phonetic:"tsoo-RÜCK-gay-en",example:"A: Gehen wir zurück zum Bahnhof?\nB: Ja, wir müssen zurückgehen.",exampleSrc:"A: Shall we go back to the station?\nB: Yes, we have to go back.",note:"Separable: geht ... zurück. Perfekt: ist zurückgegangen (sein).",funFact:"Zurückgehen also means 'to decrease.' Prices can zurückgehen too."},
{type:"teach",trg:"zurückkommen",src:"to come back",phonetic:"tsoo-RÜCK-koh-men",example:"A: Wann kommst du zurück?\nB: Ich komme in einer Stunde zurück.",exampleSrc:"A: When are you coming back?\nB: I'm coming back in an hour.",note:"Separable: kommt ... zurück. Perfekt: ist zurückgekommen (sein).",funFact:"Komm zurück! is what you shout when someone leaves and you want them back."},
{type:"teach",trg:"zurücklaufen",src:"to run back",phonetic:"tsoo-RÜCK-lau-fen",example:"A: Der Zug fährt gleich!\nB: Dann müssen wir zurücklaufen!",exampleSrc:"A: The train is leaving soon!\nB: Then we have to run back!",note:"Separable: läuft ... zurück. Perfekt: ist zurückgelaufen (sein).",funFact:"Laufen means both 'to walk' and 'to run' in German. Context decides the speed."},
{type:"teach",trg:"hin",src:"away from speaker",phonetic:"hin",example:"A: Wo gehst du hin?\nB: Ich gehe zum Bahnhof hin.",exampleSrc:"A: Where are you going (to)?\nB: I'm going to the station.",note:"Hin shows movement AWAY from the speaker. Often at the end: Wo gehst du hin?",funFact:"Wohin (where to) is literally wo + hin. Germans split it in speech: Wo gehst du hin?"},
{type:"teach",trg:"her",src:"toward speaker",phonetic:"hehr",example:"A: Komm mal her!\nB: Ich komme schon her.",exampleSrc:"A: Come here!\nB: I'm already coming.",note:"Her shows movement TOWARD the speaker. Opposite of hin.",funFact:"Woher (where from) is wo + her. Germans ask 'Wo kommst du her?' to learn your origin."},
{type:"tip",title:"Das Hin-und-her-System",text:"German has a directional pair system:\n\n. hin = away from speaker (Wo gehst du hin?)\n. her = toward speaker (Komm her!)\n\nThey attach to verbs as prefixes:\n. hingehen = to go there\n. herkommen = to come here\n. hinfahren = to drive there\n. herfahren = to drive here\n\nWith zurück, the movement reverses:\n. zurückfahren = to drive back\n. zurückgehen = to go back",deepDive:"Hin and her also combine with prepositions: hinaus (out, away), herein (in, toward), hinauf (up, away), herunter (down, toward). In casual speech, many Germans shorten these: raus, rein, rauf, runter."},
{type:"teach",trg:"drüben",src:"over there",phonetic:"DRÜ-ben",example:"A: Wo ist der Kiosk?\nB: Der Kiosk ist drüben, auf der anderen Seite.",exampleSrc:"A: Where is the kiosk?\nB: The kiosk is over there, on the other side.",note:"Points to the other side of something (street, room, border).",funFact:"During the Cold War, drüben meant 'the other Germany.' West Germans said die drüben for East Germans and vice versa."},
{type:"teach",trg:"unterwegs",src:"on the way",phonetic:"un-ter-VEGS",example:"A: Wo bist du?\nB: Ich bin unterwegs zum Hauptbahnhof.",exampleSrc:"A: Where are you?\nB: I'm on the way to the main station.",note:"Used with sein: Ich bin unterwegs. No separable parts.",funFact:"Unterwegs sein is the German version of 'I'm on my way.' You'll hear it in every phone call about delays."},
{type:"teach",trg:"vorbei",src:"past/over",phonetic:"for-BYE",example:"A: Ist der Zug schon vorbei?\nB: Ja, er ist vor fünf Minuten vorbeigefahren.",exampleSrc:"A: Has the train already passed?\nB: Yes, it drove past five minutes ago.",note:"Two meanings: (1) physically past (vorbeifahren), (2) finished/over (Die Party ist vorbei).",funFact:"Vorbei ist vorbei is a common German saying meaning 'what's done is done.'"},
{type:"teach",trg:"vorher",src:"before (temporal)",phonetic:"FOR-hehr",example:"A: Hast du vorher gefrühstückt?\nB: Nein, ich hatte vorher keine Zeit.",exampleSrc:"A: Did you eat breakfast before?\nB: No, I didn't have time before.",note:"Temporal only. For 'in front of' use vor.",funFact:"Germans love temporal precision. Vorher, nachher, davor, danach: four ways to say before and after."},
{type:"teach",trg:"vorwärts",src:"forward",phonetic:"FOR-verts",example:"A: Gehen wir vorwärts oder rückwärts?\nB: Immer vorwärts!",exampleSrc:"A: Are we going forward or backward?\nB: Always forward!",note:"Opposite: rückwärts (backward). Used for physical and abstract progress.",funFact:"Vorwärts was the name of the German Social Democrats' newspaper since 1876."},
{type:"teach",trg:"weg",src:"away/gone",phonetic:"vek",example:"A: Wo ist mein Koffer?\nB: Er ist weg! Jemand hat ihn genommen!",exampleSrc:"A: Where is my suitcase?\nB: It's gone! Someone took it!",note:"Short and blunt. Weg! alone means 'Go away!' As a noun, der Weg means 'the path.'",funFact:"Geh weg! (Go away!) is one of the first phrases German children learn to yell at siblings."},
{type:"mc",q:"'Hin' zeigt Bewegung ...",opts:["vom Sprecher weg","zum Sprecher","nach oben","nach unten"],ans:"vom Sprecher weg",hint:"Think about the direction: toward or away?"},
{type:"fb",s:"Wann kommst du {1}?",a:"zurück",opts:["zurück","weg","hin","vorbei"],hint:"You want to know when someone returns.",sSrc:"When are you coming {1}?"},
{type:"mc",q:"Welches Wort bedeutet 'on the way'?",opts:["unterwegs","vorwärts","drüben","vorher"],ans:"unterwegs",hint:"You're not there yet, but you're traveling."},
{type:"fb",s:"Der Zug ist schon {1}. Wir haben ihn verpasst.",a:"vorbei",opts:["vorbei","weg","hin","unterwegs"],hint:"The train already passed. It's over.",sSrc:"The train is already {1}. We missed it."},
{type:"mc",q:"'Ich bin gestern zurückgefahren.' Welches Hilfsverb braucht zurückfahren im Perfekt?",opts:["sein","haben","werden","können"],ans:"sein",hint:"Driving back involves a change of location."},
{type:"fb",s:"Wenn du morgen {1}, bringe bitte Brot mit.",a:"zurückkommst",opts:["zurückkommst","zurückgeben","vorwärts","unterwegs"],hint:"Fill in: when you come back tomorrow ...",sSrc:"When you {1} tomorrow, please bring bread."},
{type:"drag_fill",s:"Ich bin vorher zum Gleis {1}, aber der Zug war schon {2}.",blanks:{"1":"hingegangen","2":"weg"},pool:["hingegangen","weg","zurück","her","vorbei"],hint:"First blank: went there (away from speaker). Second: gone.",sSrc:"I had previously gone {1} to the platform, but the train was already {2}."},
{type:"mc",q:"Was sagt man, wenn jemand auf der anderen Straßenseite steht?",opts:["Er steht drüben.","Er ist unterwegs.","Er geht vorwärts.","Er kommt her."],ans:"Er steht drüben.",hint:"The person is on the other side, across from you."},
{type:"match",pairs:[{trg:"zurückgeben",src:"to give back"},{trg:"vorher",src:"before (temporal)"},{trg:"vorwärts",src:"forward"},{trg:"weg",src:"away/gone"},{trg:"drüben",src:"over there"}]},
{type:"fb",s:"Komm bitte {1}! Ich brauche deine Hilfe.",a:"her",opts:["her","hin","weg","zurück"],hint:"You want the person to come toward you.",sSrc:"Please come {1}! I need your help."},
{type:"mc",q:"Wenn ich den Koffer nicht finde, muss ich zum Fundbüro ...",opts:["hingehen","herkommen","zurückgeben","vorbeifahren"],ans:"hingehen",hint:"You need to go there, away from where you are now."},
{type:"drag_fill",s:"Wenn der Zug {1} ist, müssen wir zu Fuß {2}.",blanks:{"1":"vorbei","2":"zurücklaufen"},pool:["vorbei","zurücklaufen","unterwegs","hingehen","vorher"],hint:"First: the train has passed. Second: run back on foot.",sSrc:"If the train is {1}, we have to {2} on foot."}
]},

// ─── L6: Der Anschluss ───
{id:"deu_r10l6",title:"Der Anschluss",icon:"🏃‍♂️",xp:20,board:true,steps:[
{type:"intro",title:"Der Anschluss",desc:"Munich Hauptbahnhof. Verumius has exactly 4 minutes to catch his connection train. Escalators, crowds, the smell of fresh Brezeln. Can he make it?",goals:["Review Perfekt with sein and haben","Combine wenn + subordinate word order","Use Präteritum modals in past narratives","Multi-construct sentences with 2-3 grammar points"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-munich-hbf",trg:"München Hauptbahnhof. Die Durchsage: 'ICE 517 nach Hamburg fährt in vier Minuten ab, Gleis 14.' Verumius steht auf Gleis 3. Elf Gleise Unterschied. Er rennt.",src:"Munich Central Station. The announcement: 'ICE 517 to Hamburg departs in four minutes, platform 14.' Verumius is on platform 3. Eleven platforms apart. He runs."},
{type:"story",speaker:"narrator",mood:"tense",art:"de-munich-sprint",trg:"Er springt auf die Rolltreppe, drückt sich an einer Frau mit einem Kinderwagen vorbei. 'Entschuldigung!' Der Geruch von frischen Brezeln aus einer Bäckerei. Sein Magen knurrt, aber der Zug wartet nicht.",src:"He jumps on the escalator, squeezes past a woman with a stroller. 'Excuse me!' The smell of fresh pretzels from a bakery. His stomach growls, but the train won't wait."},
{type:"teach",trg:"das Kaufhaus",src:"the department store",note:"Neuter. Compound: Kauf (purchase) + Haus (house).",example:"A: Wo hast du die Jacke gekauft?\nB: Im Kaufhaus am Marienplatz.",exampleSrc:"A: Where did you buy the jacket?\nB: At the department store on Marienplatz.",funFact:"KaDeWe in Berlin (Kaufhaus des Westens) is the largest department store in continental Europe. Six floors, 60,000 square meters, and an entire floor just for food."},
{type:"teach",trg:"das Einkaufszentrum",src:"the shopping center",note:"Neuter. Compound: Einkauf (shopping) + Zentrum (center).",example:"A: Gibt es ein Einkaufszentrum in der Nähe?\nB: Ja, wenn du die Kreuzung überquerst, ist es auf der rechten Seite.",exampleSrc:"A: Is there a shopping center nearby?\nB: Yes, if you cross the intersection, it's on the right side.",funFact:"German compound nouns can get famously long. Einkaufszentrum is 16 letters, but that is short by German standards. The linking 's' in Einkauf-s-zentrum is called a Fugen-s."},
{type:"teach",trg:"die Kreuzung",src:"the intersection",note:"Feminine. From kreuzen (to cross). Plural: die Kreuzungen.",example:"A: An der Kreuzung musste ich warten.\nB: Ja, die Ampel war rot.",exampleSrc:"A: At the intersection I had to wait.\nB: Yes, the traffic light was red.",funFact:"German intersections are strictly regulated. Jaywalking (bei Rot gehen) can earn you a fine of 5 to 10 euros. Germans really do wait for the green light, even at 3 AM with no cars in sight."},
{type:"teach",trg:"der Rundgang",src:"the tour / round",note:"Masculine. Compound: rund (round) + Gang (walk).",example:"A: Wir haben einen Rundgang durch die Altstadt gemacht.\nB: Das klingt toll! Was habt ihr gesehen?",exampleSrc:"A: We did a tour through the old town.\nB: That sounds great! What did you see?",funFact:"A Rundgang is literally a 'round walk,' a circular tour that ends where it started. German city guides love offering Rundgänge through historic neighborhoods."},
{type:"teach",trg:"die Messe",src:"the trade fair",note:"Feminine. Also means 'mass' (church service). Context decides.",example:"A: Bist du zur Messe gefahren?\nB: Ja, ich bin mit dem Zug hingefahren.",exampleSrc:"A: Did you go to the trade fair?\nB: Yes, I went there by train.",funFact:"Germany hosts some of the world's biggest trade fairs. The Hannover Messe attracts over 200,000 visitors. Frankfurt's Buchmesse (book fair) is the world's largest book event."},
{type:"teach",trg:"das Zelt",src:"the tent",note:"Neuter. Plural: die Zelte.",example:"A: Wenn es regnet, gehen wir ins Zelt.\nB: Gute Idee! Es ist warm und trocken.",exampleSrc:"A: If it rains, we'll go into the tent.\nB: Good idea! It's warm and dry.",funFact:"At Oktoberfest, the Bierzelte (beer tents) are massive. The largest, the Hofbräu-Festzelt, seats 10,000 people. They are really more like temporary buildings than tents."},
{type:"teach",trg:"rund",src:"round",note:"Adjective. Also used as 'approximately': rund 100 Leute (around 100 people).",example:"A: Der Tisch ist rund.\nB: Ja, und rund 20 Leute sitzen daran.",exampleSrc:"A: The table is round.\nB: Yes, and around 20 people are sitting at it.",funFact:"'Rund' does double duty in German. Shape: ein runder Tisch (a round table). Approximation: rund 50 Euro (about 50 euros). Both meanings come from the idea of completeness."},
{type:"mc",q:"'Verumius ist durch das Kaufhaus gerannt.' Which auxiliary verb forms the Perfekt here?",opts:["ist (movement verb)","hat (action verb)","war (past tense)","wurde (passive)"],ans:"ist (movement verb)",hint:"Rennen involves a change of location. Motion verbs use sein."},
{type:"fb",s:"An der {1} musste ich fünf Minuten warten.",a:["Kreuzung"],opts:["Kreuzung","Messe","Rolltreppe","Bäckerei"],hint:"Where two streets meet and traffic lights control the flow.",sSrc:"At the {1} I had to wait five minutes."},
{type:"mc",q:"'Wenn der Zug abfährt, muss ich am Gleis sein.' What happens to the verb in the wenn-clause?",opts:["The conjugated verb goes to the end","The verb stays in second position","The verb is dropped","The verb becomes an infinitive"],ans:"The conjugated verb goes to the end",hint:"Subordinate clauses in German send the verb to the final position."},
{type:"drag_fill",s:"Verumius {1} durch das Einkaufszentrum {2}, weil er seinen Anschluss nicht {3} wollte.",blanks:{"1":"ist","2":"gerannt","3":"verpassen"},pool:["ist","gerannt","verpassen","hat","gelaufen","verpasst"],hint:"Rennen uses sein in Perfekt. Wollen + infinitive in the subordinate clause.",sSrc:"Verumius {1} {2} through the shopping center because he did not want to {3} his connection."},
{type:"fb",s:"Wir haben einen {1} durch die Altstadt gemacht.",a:["Rundgang"],opts:["Rundgang","Kreuzung","Zelt","Kaufhaus"],hint:"A circular walking tour. Compound of rund + Gang.",sSrc:"We did a {1} through the old town."},
{type:"mc",q:"'Er konnte den Zug nicht sehen, weil das Kaufhaus im Weg war.' Which grammar points combine here?",opts:["Präteritum modal + weil-clause","Perfekt + wenn-clause here","Imperativ + Partizip II","Futur + Relativsatz combo"],ans:"Präteritum modal + weil-clause",hint:"Konnte is past tense of können. Weil sends the verb to the end."},
{type:"drag_fill",s:"Wenn es {1}, gehen wir ins {2}. Dort {3} wir gestern auch {4}.",blanks:{"1":"regnet","2":"Zelt","3":"sind","4":"gewesen"},pool:["regnet","Zelt","sind","gewesen","hat","geregnet"],hint:"Wenn-clause with present tense. Second sentence: Perfekt of the verb 'to be' in past.",sSrc:"If it {1}, we go into the {2}. We were also there yesterday."},
{type:"mc",q:"'___ 200 Leute waren auf der Messe.' Which word fits for 'approximately'?",opts:["Rund","Leute","Messe","Waren"],ans:"Rund",hint:"This word also means 'round' as a shape, but here it modifies a number."},
{type:"fb",s:"Er {1} den Zug nehmen, aber er konnte das Gleis nicht finden.",a:["wollte"],opts:["wollte","konnte","musste","durfte"],hint:"He WANTED to take the train. Past tense of wollen.",sSrc:"He {1} to take the train, but he could not find the platform."},
{type:"drag_fill",s:"Wenn Verumius das {1} {2} hat, ist er zum {3} {4}.",blanks:{"1":"Kaufhaus","2":"gesehen","3":"Gleis","4":"gerannt"},pool:["Kaufhaus","gesehen","Gleis","gerannt","Messe","gefahren"],hint:"When he SAW the department store, he RAN to the platform. Wenn + Perfekt, main clause Perfekt with sein.",sSrc:"When Verumius {2} the {1}, he {4} to the {3}."},
{type:"story",speaker:"narrator",mood:"triumphant",art:"de-train-doors",trg:"Gleis 14. Die Türen piepen. Verumius springt hinein. Die Türen schließen sich hinter ihm. Er hat es geschafft! Im Bordbistro bestellt er eine Currywurst. Er hat sie verdient.",src:"Platform 14. The doors beep. Verumius jumps in. The doors close behind him. He made it! In the onboard bistro he orders a Currywurst. He's earned it."},
{type:"mc",q:"'Er hat es geschafft, weil er schnell genug gerannt ist.' How many grammar constructs combine here?",opts:["Three: Perfekt haben + weil-clause + Perfekt sein","Two: Perfekt haben + Perfekt sein","One: just Perfekt","Four: Perfekt + weil + modal + sein"],ans:"Three: Perfekt haben + weil-clause + Perfekt sein",hint:"Hat geschafft (Perfekt with haben), weil sends verb to end, gerannt ist (Perfekt with sein)."},
{type:"fb",s:"Wenn ich am Bahnhof {1}, kaufe ich eine Brezel.",a:["ankomme"],opts:["ankomme","ankommen","angekommen","ankam"],hint:"Wenn-clause needs present tense, first person singular. In subordinate clauses, separable verbs reunite at the end.",sSrc:"When I {1} at the station, I buy a pretzel."},
{type:"drag_fill",s:"Gestern {1} ich zur Messe {2}, und danach {3} ich ein Zelt auf dem Marktplatz {4}.",blanks:{"1":"bin","2":"gefahren","3":"habe","4":"gesehen"},pool:["bin","gefahren","habe","gesehen","ist","gekauft"],hint:"Fahren uses sein in Perfekt. Sehen uses haben. Two different auxiliaries in one sentence.",sSrc:"Yesterday I {1} {2} to the trade fair, and afterwards I {3} a tent at the market square {4}."},
{type:"match",pairs:[{trg:"das Kaufhaus",src:"department store"},{trg:"das Einkaufszentrum",src:"shopping center"},{trg:"die Kreuzung",src:"intersection"},{trg:"der Rundgang",src:"tour / round"},{trg:"die Messe",src:"trade fair"},{trg:"das Zelt",src:"tent"},{trg:"rund",src:"round / approximately"}]},
{type:"tip",title:"Sprint geschafft!",text:"Verumius made his connection by 12 seconds.\nHe combined everything from Unit 10:\n\n1. Perfekt with sein (ist gerannt, ist gefahren)\n2. Perfekt with haben (hat geschafft, hat gesehen)\n3. Wenn-clauses with verb at the end\n4. Weil-clauses with verb at the end\n5. Präteritum modals (konnte, wollte, musste)\n\nThe Currywurst? Totally earned."}
]}
,

{id:"deu_r10l7",title:"Fahrkartenkontrolle",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Fahrkartenkontrolle!",desc:"The ticket inspector is here. Time to prove you know your way around Deutsche Bahn, German geography, and travel vocabulary. Everything from Unit 10 is fair game.",goals:["Test all U10 travel and geography vocabulary","Combine Perfekt, wenn-clauses, and subordinate word order","Show you can handle real travel situations"]},
{type:"mc",q:"Verumius ist mit dem Zug nach München gefahren. Which tense is this sentence in?",opts:["Präsens","Perfekt with sein","Perfekt with haben","Präteritum"],ans:"Perfekt with sein",hint:"'Gefahren' is a movement verb. Think about which auxiliary it needs."},
{type:"fb",s:"Wir haben den Flug nach Berlin {1}.",a:["gebucht"],opts:["gebucht","buchen","gebuchen","buchte"],hint:"You need the Partizip II of 'buchen' after 'haben.'",sSrc:"We have {1} the flight to Berlin."},
{type:"mc",q:"'Wenn der Zug Verspätung hat, verpasse ich meinen Flug.' What does 'Verspätung' mean?",opts:["ticket","platform","delay","departure"],ans:"delay",hint:"This noun describes when something arrives later than planned."},
{type:"drag_fill",s:"Ich {1} gestern am Markt {2}.",blanks:{"1":"bin","2":"umgestiegen"},pool:["bin","habe","umgestiegen","umsteigen","hat"],hint:"'Umsteigen' is a movement action. Which auxiliary does it take?",sSrc:"I {1} {2} at the market yesterday."},
{type:"fb",s:"Wenn es regnet, nehme ich den {1} statt das Fahrrad.",a:["Bus"],opts:["Bus","Strand","Wald","Berg"],hint:"Which Verkehrsmittel keeps you dry when it rains?",sSrc:"When it rains, I take the {1} instead of the bicycle."},
{type:"match",pairs:[{trg:"der Fahrplan",src:"timetable / schedule"},{trg:"die Verspätung",src:"delay"},{trg:"das Verkehrsmittel",src:"means of transport"},{trg:"umsteigen",src:"to change / transfer"},{trg:"verpassen",src:"to miss"},{trg:"buchen",src:"to book"}]},
{type:"mc",q:"'Der Tourist hat seinen Rucksack im Zug vergessen.' What happened?",opts:["The tourist packed his backpack","The tourist bought a new backpack","The tourist forgot his backpack on the train","The tourist found his backpack at the station"],ans:"The tourist forgot his backpack on the train",hint:"'Vergessen' means to forget. Where did it happen?"},
{type:"drag_fill",s:"Wenn ich {1}, muss ich am Rathaus {2}.",blanks:{"1":"verreise","2":"umsteigen"},pool:["verreise","umsteigen","verreisen","umgestiegen","packen"],hint:"Fill in the present tense verb in the wenn-clause and the infinitive after 'muss.'",sSrc:"When I {1}, I have to {2} at the town hall."},
{type:"fb",s:"Das Schiff fährt über den {1} zur Insel.",a:["Fluss"],opts:["Fluss","Berg","Wald","Markt"],hint:"Ships travel over water. Which word means 'river'?",sSrc:"The ship travels over the {1} to the island."},
{type:"mc",q:"'Wir konnten nicht parken, weil der Markt offen war.' Which grammar features appear here?",opts:["Perfekt + wenn-clause","Präteritum + weil-clause","Präsens + dass-clause","Perfekt + ob-clause"],ans:"Präteritum + weil-clause",hint:"Look at 'konnten' and the word order after 'weil.'"},
{type:"drag_fill",s:"Wenn du den {1} liest, findest du den {2} zum Zentrum.",blanks:{"1":"Stadtplan","2":"Weg"},pool:["Stadtplan","Weg","Strand","Flug","Rucksack"],hint:"A map helps you find the route to the city center.",sSrc:"If you read the {1}, you will find the {2} to the center."},
{type:"fb",s:"Er ist gestern mit dem Motorroller zur {1} gefahren.",a:["Brücke"],opts:["Brücke","Verspätung","Ampel","Verkehr"],hint:"This is a structure built over water to cross from one side to the other.",sSrc:"He drove to the {1} by scooter yesterday."},
{type:"mc",q:"Which sentence has correct subordinate word order?",opts:["Wenn ich den Zug verpasse, muss ich warten.","Wenn ich verpasse den Zug, muss ich warten.","Wenn verpasse ich den Zug, muss ich warten.","Wenn ich den Zug verpasse, ich muss warten."],ans:"Wenn ich den Zug verpasse, muss ich warten.",hint:"In a wenn-clause the verb goes to the end. In the main clause after a wenn-clause, the verb comes first."},
{type:"match",pairs:[{trg:"die Brücke",src:"bridge"},{trg:"die Insel",src:"island"},{trg:"die Landschaft",src:"landscape"},{trg:"der Strand",src:"beach"},{trg:"der Wald",src:"forest"},{trg:"der Berg",src:"mountain"}]},
{type:"fb",s:"Die Touristen {1} ihre Koffer schon eingepackt.",a:["haben"],opts:["haben","sind","hat","ist"],hint:"Which auxiliary does a non-motion verb use in the Perfekt?",sSrc:"The tourists {1} already packed their suitcases."},
{type:"mc",q:"Verumius fragt: 'Ist die Kirche in der Nähe?' What is he asking about?",opts:["Whether the church is nearby","Whether the church is open","When the church was built","How old the church is"],ans:"Whether the church is nearby",hint:"'In der Nähe' describes physical proximity, not time or age."},
{type:"drag_fill",s:"Ich {1} vorher den Reifen {2}, weil er kaputt {3}.",blanks:{"1":"musste","2":"wechseln","3":"war"},pool:["musste","wechseln","war","konnte","gewechselt","ist"],hint:"Präteritum modal + infinitive in the main clause, verb-final in the weil-clause.",sSrc:"I {1} {2} the tire beforehand because it {3} broken."},
{type:"fb",s:"Wenn du an der Kreuzung rechts gehst, siehst du das {1}.",a:["Kaufhaus"],opts:["Kaufhaus","Reifen","Motor","Zelt"],hint:"This is a large building where you can buy many things.",sSrc:"If you turn right at the intersection, you will see the {1}."},
{type:"mc",q:"'Sie sind direkt zum Einkaufszentrum gefahren.' Why is 'sind' used here instead of 'haben'?",opts:["Because 'fahren' is a reflexive verb","Because the subject is plural","Because 'fahren' expresses movement from A to B","Because it is a question"],ans:"Because 'fahren' expresses movement from A to B",hint:"Verbs expressing a change of location take a specific auxiliary in the Perfekt."},
{type:"drag_fill",s:"Wenn wir den {1} nicht {2}, können wir den nächsten {3} nehmen.",blanks:{"1":"Zug","2":"verpassen","3":"Flug"},pool:["Zug","verpassen","Flug","Verspätung","gefahren","buchen"],hint:"If we do not miss the train, we can catch the next flight.",sSrc:"If we do not {2} the {1}, we can take the next {3}."},
{type:"mc",q:"'Wir ___ auf der Messe zelten, aber es gab kein Zelt.' Which Präteritum modal expresses a past wish?",opts:["mussten","konnten","wollten","durften"],ans:"wollten",hint:"This modal expresses a desire or intention in the past."},
{type:"fb",s:"Die Fahrt zum Flughafen dauert {1} zwei Stunden.",a:["rund"],opts:["rund","weg","hin","her"],hint:"This word means 'approximately' and sounds like a shape.",sSrc:"The trip to the airport takes {1} two hours."},
{type:"match",pairs:[{trg:"vorwärts",src:"forward"},{trg:"zurückfahren",src:"to drive back"},{trg:"unterwegs",src:"on the way"},{trg:"drüben",src:"over there"},{trg:"vorbei",src:"past / over"},{trg:"hin",src:"there (away from speaker)"}]},
{type:"drag_fill",s:"Wenn das Wetter {1} ist, {2} wir an den {3} gefahren.",blanks:{"1":"offen","2":"sind","3":"Strand"},pool:["offen","sind","Strand","haben","Berg","geschlossen"],hint:"When the weather was nice (open/clear), we drove to the beach using sein-Perfekt.",sSrc:"When the weather was {1}, we {2} to the {3}."},
{type:"mc",q:"Verumius hat seinen Stadtplan verloren. Er konnte den Weg zum Rathaus nicht finden. Wenn er vorher reserviert hätte, wäre er nicht unterwegs gewesen. How many U10 vocabulary words appear in this passage?",opts:["Three: Stadtplan, Weg, Rathaus","Five: Stadtplan, Weg, Rathaus, reserviert, unterwegs","Four: Stadtplan, Rathaus, reserviert, unterwegs","Six: Stadtplan, Weg, Rathaus, reserviert, unterwegs, verloren"],ans:"Five: Stadtplan, Weg, Rathaus, reserviert, unterwegs",hint:"Count carefully. Some words look familiar but are not from the U10 vocabulary list."}
]}
,

{id:"deu_r10l8",title:"Im Bordbistro",icon:"\u{1F35B}",xp:15,board:true,steps:[
{type:"intro",title:"Im Bordbistro",desc:"Verumius hat den Anschluss geschafft! Jetzt sitzt er im Bordbistro, isst Currywurst und schaut aus dem Fenster. Bayern ist wundersch\u00f6n.",goals:["Reisevokabular abschlie\u00dfen","Neue Adverbien und Pr\u00e4positionen lernen","\u00dcber Reisepl\u00e4ne sprechen"]},
{type:"teach",trg:"der F\u00fchrerschein",src:"driver's license",phonetic:"FYOO-rer-shyne",example:"A: Hast du einen F\u00fchrerschein?\nB: Ja, aber ich fahre lieber mit dem Zug.\nA: Das verstehe ich. Z\u00fcge sind bequemer.",exampleSrc:"A: Do you have a driver's license?\nB: Yes, but I prefer to travel by train.\nA: I understand that. Trains are more comfortable.",note:"F\u00fchren (to lead) + Schein (certificate). You lead a vehicle.",funFact:"In Germany you can get your F\u00fchrerschein at 18. Driving lessons cost 2,000 to 3,500 euros on average."},
{type:"teach",trg:"die Hauptstadt",src:"capital city",phonetic:"HOWPT-shtat",example:"A: Was ist die Hauptstadt von Bayern?\nB: M\u00fcnchen! Wir fahren gerade dorthin.\nA: Stimmt, ich sehe schon die Berge.",exampleSrc:"A: What is the capital of Bavaria?\nB: Munich! We are heading there right now.\nA: Right, I can already see the mountains.",note:"Haupt (main) + Stadt (city). Simple compound.",funFact:"Berlin became Germany's capital again in 1990 after reunification. Before that, Bonn was the capital of West Germany."},
{type:"teach",trg:"die Jugendherberge",src:"youth hostel",phonetic:"YOO-gent-hair-bair-guh",example:"A: Wo \u00fcbernachtest du in M\u00fcnchen?\nB: In einer Jugendherberge. Das ist g\u00fcnstig.\nA: Gute Idee! Die sind oft sehr sch\u00f6n.",exampleSrc:"A: Where are you staying overnight in Munich?\nB: In a youth hostel. That is affordable.\nA: Good idea! They are often very nice.",note:"Jugend (youth) + Herberge (shelter). Three parts, one word.",funFact:"Germany invented the youth hostel. The first one opened in 1912 in Altena Castle. Today there are over 400 across the country."},
{type:"teach",trg:"das Paket",src:"package",phonetic:"pa-KETT",example:"A: Ich muss ein Paket nach Berlin schicken.\nB: Es gibt einen Paketshop im Bahnhof.\nA: Perfekt, dann gehe ich vor der Abfahrt dorthin.",exampleSrc:"A: I need to send a package to Berlin.\nB: There is a parcel shop in the station.\nA: Perfect, then I will go there before departure.",note:"From French paquet. Plural: Pakete.",funFact:"DHL delivers over 1.8 billion parcels per year in Germany. Germans love online shopping."},
{type:"teach",trg:"der Umzug",src:"move (relocation)",phonetic:"OOM-tsook",example:"A: Wann ist dein Umzug nach M\u00fcnchen?\nB: N\u00e4chsten Monat. Ich brauche noch Kartons.\nA: Ich kann dir helfen!",exampleSrc:"A: When is your move to Munich?\nB: Next month. I still need boxes.\nA: I can help you!",note:"Um (around) + Zug (pull). You pull your things to a new place.",funFact:"In Germany, friends help with Umz\u00fcge and get paid in pizza and beer. It is a tradition."},
{type:"teach",trg:"die Unterkunft",src:"accommodation",phonetic:"OON-ter-koonft",example:"A: Hast du schon eine Unterkunft in M\u00fcnchen?\nB: Noch nicht. Ich suche ein Zimmer.\nA: Schau mal im Internet. Es gibt viele Angebote.",exampleSrc:"A: Do you already have accommodation in Munich?\nB: Not yet. I am looking for a room.\nA: Check online. There are many offers.",note:"Unter (under) + Kunft (from kommen, to come). Where you come to stay.",funFact:"Finding a Wohnung in Munich is notoriously difficult. People bring full application folders to apartment viewings."},
{type:"teach",trg:"fast",src:"almost",phonetic:"fasst",example:"A: Sind wir fast da?\nB: Ja, noch zehn Minuten bis M\u00fcnchen.\nA: Endlich! Die Reise war lang.",exampleSrc:"A: Are we almost there?\nB: Yes, ten more minutes to Munich.\nA: Finally! The trip was long.",note:"Be careful: fast means almost, NOT fast. Schnell means fast.",funFact:"This is a classic false friend for English speakers. Fast alle means almost everyone, not fast everyone."},
{type:"teach",trg:"zuerst",src:"first (of all)",phonetic:"tsoo-AIRST",example:"A: Was machst du zuerst in M\u00fcnchen?\nB: Zuerst gehe ich ins Hotel. Dann esse ich.\nA: Guter Plan!",exampleSrc:"A: What will you do first in Munich?\nB: First I will go to the hotel. Then I will eat.\nA: Good plan!",note:"Zu (to) + erst (first). Literally: to first.",funFact:"Germans love planning their day in order: zuerst, dann, danach, zum Schluss. Structure is everything."},
{type:"teach",trg:"zuletzt",src:"last, finally",phonetic:"tsoo-LETST",example:"A: Und was machst du zuletzt?\nB: Zuletzt besuche ich den Marienplatz.\nA: Das Glockenspiel ist wundersch\u00f6n!",exampleSrc:"A: And what will you do last?\nB: Last I will visit Marienplatz.\nA: The Glockenspiel is wonderful!",note:"Zu (to) + letzt (last). The opposite of zuerst.",funFact:"The Glockenspiel at Marienplatz plays every day at 11:00, 12:00, and 17:00. Tourists gather to watch the mechanical figures dance."},
{type:"teach",trg:"dorthin",src:"to there",phonetic:"DORT-hin",example:"A: Ich m\u00f6chte nach M\u00fcnchen.\nB: Ich fahre auch dorthin!\nA: Super, dann fahren wir zusammen.",exampleSrc:"A: I would like to go to Munich.\nB: I am also going there!\nA: Great, then we will travel together.",note:"Dort (there) + hin (towards). Hin always means motion away from speaker.",funFact:"German is very precise about direction. Dorthin is to there, dorther is from there. English uses just there for both."},
{type:"teach",trg:"wegen",src:"because of",phonetic:"VAY-gen",example:"A: Warum f\u00e4hrst du mit dem Zug?\nB: Wegen der Umwelt. Z\u00fcge sind gr\u00fcner.\nA: Das stimmt. Und es ist auch gem\u00fctlich.",exampleSrc:"A: Why are you traveling by train?\nB: Because of the environment. Trains are greener.\nA: That is true. And it is also comfortable.",note:"Wegen takes the genitive case: wegen des Wetters, wegen der Arbeit.",funFact:"Deutsche Bahn advertises itself as the green alternative. One train trip produces 80% less CO2 than the same trip by car."},
{type:"teach",trg:"hinter",src:"behind",phonetic:"HIN-ter",example:"A: Wo ist das Bordbistro?\nB: Hinter dem Wagen sechs.\nA: Danke! Ich habe Hunger.",exampleSrc:"A: Where is the onboard bistro?\nB: Behind car six.\nA: Thanks! I am hungry.",note:"Hinter + dative (no motion) or accusative (motion). Hinter dem Haus = behind the house.",funFact:"German has nine two-way prepositions that switch between dative and accusative. Hinter is one of them."},
{type:"teach",trg:"pro",src:"per",phonetic:"proh",example:"A: Was kostet die Currywurst?\nB: F\u00fcnf Euro pro St\u00fcck.\nA: Nicht schlecht! Eine bitte.",exampleSrc:"A: How much is the Currywurst?\nB: Five euros per piece.\nA: Not bad! One please.",note:"Same as English per. Used with prices, rates, and quantities.",funFact:"Currywurst im Bordbistro costs about 5 to 7 euros. On the platform it is cheaper, but the view is not as good."},
{type:"teach",trg:"vorn, vorne",src:"in front, at the front",phonetic:"forn, FOR-nuh",example:"A: Wo sitzt du im Zug?\nB: Ganz vorne, im ersten Wagen.\nA: Ich sitze hinten. Wir treffen uns in der Mitte!",exampleSrc:"A: Where are you sitting on the train?\nB: Right at the front, in the first car.\nA: I am sitting at the back. We will meet in the middle!",note:"Vorne is the longer, more common form. Vorn is shorter, same meaning. Opposite: hinten.",funFact:"In German ICE trains, first class is usually vorne. Some passengers pay extra just for the quiet at the front."},
{type:"teach",trg:"austragen",src:"to deliver, to carry out",phonetic:"OWS-trah-gen",example:"A: Mein Bruder tr\u00e4gt Zeitungen aus.\nB: Wirklich? Das ist ein guter Nebenjob.\nA: Ja, er macht das jeden Morgen vor der Schule.",exampleSrc:"A: My brother delivers newspapers.\nB: Really? That is a good side job.\nA: Yes, he does it every morning before school.",note:"Separable verb: aus + tragen. Er tr\u00e4gt Pakete aus. Past: hat ausgetragen.",funFact:"Zeitungsaustragen (newspaper delivery) is the classic first job for German teenagers, just like a paper route in America."},
{type:"tip",title:"Zugkultur: Das Bordbistro",text:"Every ICE has a Bordbistro (onboard bistro car) serving hot meals, snacks, and drinks.\n\nPopular items:\n\u2022 Currywurst mit Pommes (the classic)\n\u2022 Brezel mit Butter\n\u2022 Radler (beer mixed with lemon soda)\n\u2022 Kaffee und Kuchen\n\nThe Bordbistro is a social space. Strangers share tables and chat. It is one of the few places in Germany where talking to strangers is completely normal.",deepDive:"DB also offers an app called Komfort Check-in where you can order food to your seat in first class. The Bordbistro staff are famous for their dry humor. If the train is late, they sometimes announce: Wir bitten um Entschuldigung. Unser Zug hat sich verlaufen. (We apologize. Our train got lost.)"},
{type:"mc",q:"Verumius bestellt eine Currywurst. Was kostet sie pro St\u00fcck?",opts:["F\u00fcnf Euro","Zehn Euro","Drei Euro","Sieben Euro"],ans:"F\u00fcnf Euro",hint:"Think about what the teach card said about Bordbistro prices."},
{type:"fb",s:"Wir sind {1} da. Noch f\u00fcnf Minuten!",a:"fast",opts:["fast","zuerst","zuletzt","dorthin"],hint:"Which word means almost in German?",sSrc:"We are {1} there. Just five more minutes!"},
{type:"mc",q:"Was bedeutet 'zuerst'?",opts:["first of all","at the end","almost done","right behind"],ans:"first of all",hint:"It starts with zu and relates to ordering events."},
{type:"fb",s:"{1} gehe ich ins Hotel, dann esse ich.",a:"Zuerst",opts:["Zuerst","Zuletzt","Fast","Wegen"],hint:"Which adverb introduces the first action in a sequence?",sSrc:"{1} I go to the hotel, then I eat."},
{type:"mc",q:"Wo ist das Bordbistro? Es ist {blank} dem Wagen sechs.",opts:["hinter","vorne","wegen","pro"],ans:"hinter",hint:"The bistro is located at the back of car six."},
{type:"fb",s:"Ich fahre auch nach M\u00fcnchen. Ich fahre {1}.",a:"dorthin",opts:["dorthin","vorne","zuletzt","hinter"],hint:"Which word means to there, showing direction?",sSrc:"I am also going to Munich. I am going {1}."},
{type:"mc",q:"Was ist eine Jugendherberge?",opts:["A youth hostel","A train station","A restaurant","A school"],ans:"A youth hostel",hint:"Think about the compound: Jugend + Herberge."},
{type:"drag_fill",s:"{1} des Wetters fahre ich mit dem Zug. {2} kaufe ich ein Ticket, {3} steige ich ein.",blanks:{"1":"Wegen","2":"Zuerst","3":"dann"},pool:["Wegen","Zuerst","dann","fast","pro"],hint:"Because of the weather, first I buy a ticket, then I board.",sSrc:"{1} of the weather I travel by train. {2} I buy a ticket, {3} I board."},
{type:"match",pairs:[{trg:"der F\u00fchrerschein",src:"driver's license"},{trg:"die Hauptstadt",src:"capital city"},{trg:"die Unterkunft",src:"accommodation"},{trg:"das Paket",src:"package"},{trg:"der Umzug",src:"move (relocation)"},{trg:"vorne",src:"at the front"}]},
{type:"teach",trg:"warten",src:"to wait",note:"Regular: ich warte, du wartest. Warten auf + accusative = to wait for.",example:"A: Wie lange wartest du schon?\nB: Schon zwanzig Minuten!\nA: Der Zug hat Versp\u00e4tung. Typisch.",exampleSrc:"A: How long have you been waiting?\nB: Already twenty minutes!\nA: The train is delayed. Typical.",funFact:"Warten has a second meaning: to maintain/service. 'Das Auto warten' means to service the car. Context decides."},
{type:"teach",trg:"der Euro",src:"the euro",note:"Masculine. Plural after numbers: Euro (no change). F\u00fcnf Euro, nicht f\u00fcnf Euros.",example:"A: Was kostet das Ticket?\nB: Neunundvierzig Euro.\nA: Das ist g\u00fcnstig f\u00fcr ganz Deutschland!",exampleSrc:"A: How much does the ticket cost?\nB: Forty-nine euros.\nA: That's cheap for all of Germany!",funFact:"Germany adopted the Euro in 2002, replacing the Deutsche Mark. German Euro coins show the Brandenburg Gate, the German eagle, or an oak leaf."},
{type:"teach",trg:"das Geb\u00e4ude",src:"the building",note:"Neuter. Plural: die Geb\u00e4ude. From bauen (to build).",example:"A: Was ist das gro\u00dfe Geb\u00e4ude dort?\nB: Das ist der Hauptbahnhof.\nA: Er ist wirklich beeindruckend!",exampleSrc:"A: What is that big building there?\nB: That's the main train station.\nA: It's really impressive!",funFact:"Berlin Hauptbahnhof is the largest crossing station in Europe. The glass and steel building has five levels and opened in 2006."},
{type:"teach",trg:"der Stadtrat",src:"the city council",note:"Masculine. Compound: Stadt (city) + Rat (council/advice).",example:"A: Wer entscheidet \u00fcber neue Stra\u00dfen?\nB: Der Stadtrat trifft diese Entscheidungen.\nA: Wie oft trifft sich der Stadtrat?",exampleSrc:"A: Who decides about new streets?\nB: The city council makes those decisions.\nA: How often does the city council meet?",funFact:"Every German city and town has a Stadtrat or Gemeinderat. Members are elected locally. Town hall meetings are open to the public."},
{type:"teach",trg:"dorther",src:"from there",note:"Adverb. Dort (there) + her (toward speaker). Opposite of dorthin.",example:"A: Woher kommt der Zug?\nB: Er kommt dorther, aus Hamburg.\nA: Ah, dann ist er bald hier.",exampleSrc:"A: Where does the train come from?\nB: It comes from there, from Hamburg.\nA: Ah, then it will be here soon.",funFact:"German is very precise about direction. Dorthin = to there (away). Dorther = from there (toward). English uses just 'there' for both."}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 11: Auf dem Weihnachtsmarkt
// Story: Gendarmenmarkt magic, Opa Heinrich, Glühwein, snow walk home
// CEFR: A2.3 - Adj declension (nom/acc/dat), possessives, temporal preps, Konj II
// ═══════════════════════════════════════════════════════════════
{n:11,lang:"de",srcLang:"en",track:"v2",title:"Auf dem Weihnachtsmarkt",sub:"Christmas market, Opa Heinrich, Glühwein, adjective declension",icon:"🎄",level:"A2.3",color:"#7B5EE8",lessons:[
{id:"deu_r11l1",title:"Gendarmenmarkt",icon:"🎄",xp:15,board:true,steps:[
{type:"intro",title:"Gendarmenmarkt",desc:"Dusk falls over Berlin's most beautiful Christmas market. Golden lights, wooden stalls, the smell of Glühwein and roasted almonds. Hildi pulls Verumius into the crowd.",goals:["Learn 10 winter and Christmas market words","See adjective endings in real sentences","Discover German Weihnachtsmarkt culture"]},
{type:"teach",trg:"das Weihnachten",src:"Christmas",phonetic:"VYE-nakh-ten",gender:"n",example:"A: Was machst du an Weihnachten?\nB: Ich besuche meine Familie.\nA: Das klingt schon!",exampleSrc:"A: What are you doing at Christmas?\nB: I am visiting my family.\nA: That sounds lovely!",note:"das Weihnachten (neuter). Often used without article: 'an Weihnachten' or 'zu Weihnachten.' Compound: Weih (holy) + Nachten (nights).",funFact:"Germany celebrates on Heiligabend (Christmas Eve, Dec 24), not Dec 25. Gifts are opened in the evening, often after church. The 25th and 26th are quiet family days."},
{type:"teach",trg:"der Schnee",src:"the snow",phonetic:"shnay",gender:"m",example:"A: Schau mal, der Schnee!\nB: Ja, alles ist weiß. Wie im Märchen!",exampleSrc:"A: Look, the snow!\nB: Yes, everything is white. Like in a fairy tale!",note:"der Schnee (masculine, no plural). Related: schneien (to snow), Schneemann (snowman).",funFact:"Germans have a saying: 'Weiße Weihnachten' (white Christmas). Statistically, Berlin gets snow on Christmas Day only about once every 10 years."},
{type:"teach",trg:"schneien",src:"to snow",example:"A: Es schneit! Hast du einen Schirm?\nB: Nein, aber ich habe eine Mütze.",exampleSrc:"A: It's snowing! Do you have an umbrella?\nB: No, but I have a hat.",note:"Impersonal verb: always 'es schneit' (it snows). Past: es hat geschneit.",funFact:"The word 'schneien' comes from Old High German 'snīwan'. In Bavaria, heavy snow is called 'Schneegestöber' (snow flurry)."},
{type:"teach",trg:"die Wolke",src:"the cloud",gender:"f",example:"A: Siehst du die dunklen Wolken?\nB: Ja, es schneit bestimmt bald.",exampleSrc:"A: Do you see the dark clouds?\nB: Yes, it will definitely snow soon.",note:"die Wolke, plural: die Wolken. 'Wolkenkratzer' means skyscraper (cloud scratcher).",funFact:"The German word 'Wolkenkuckucksheim' (cloud cuckoo land) means a fantasy world. It comes from an ancient Greek comedy by Aristophanes."},
{type:"teach",trg:"der Himmel",src:"the sky / heaven",gender:"m",example:"A: Der Himmel ist so schön heute Abend.\nB: Ja, die Sterne leuchten über dem Markt.",exampleSrc:"A: The sky is so beautiful this evening.\nB: Yes, the stars shine above the market.",note:"der Himmel = sky AND heaven. 'Himmelblau' = sky blue. Plural: die Himmel (rare).",funFact:"'Himmel und Hölle' (heaven and hell) is the German name for hopscotch. Kids still play it in schoolyards across Germany."},
{type:"teach",trg:"der Kalender",src:"the calendar",gender:"m",example:"A: Hast du einen Adventskalender?\nB: Ja, mit Schokolade! Heute ist Türchen Nummer zwölf.",exampleSrc:"A: Do you have an Advent calendar?\nB: Yes, with chocolate! Today is door number twelve.",note:"der Kalender, plural: die Kalender. Adventskalender = Advent calendar (24 little doors, one per day until Christmas).",funFact:"The first printed Advent calendar was made in Germany in 1902. Today, Germans spend over 60 million euros on them every year."},
{type:"teach",trg:"die Postkarte",src:"the postcard",gender:"f",example:"A: Ich schreibe eine Postkarte an meine Eltern.\nB: Gute Idee! Der Weihnachtsmarkt ist ein tolles Motiv.",exampleSrc:"A: I'm writing a postcard to my parents.\nB: Good idea! The Christmas market is a great motif.",note:"die Postkarte, plural: die Postkarten. Compound: Post (mail) + Karte (card).",funFact:"Germany's postal service delivers around 200 million Christmas cards every December. The town of 'Himmelpfort' (Heaven's Gate) has a special Santa Claus post office."},
{type:"mc",q:"Hildi says: 'Schau, es ___!' What is happening?",opts:["Es schneit","Es regnet","Es ist warm","Es ist dunkel"],ans:"Es schneit",hint:"Think of what falls from winter clouds"},
{type:"fb",s:"Der {1} ist heute Abend wunderschön.",a:"Himmel",opts:["Himmel","Schnee","Wolke","Kalender"],hint:"Look up above the market stalls",sSrc:"The {1} is beautiful tonight."},
{type:"teach",trg:"die Schokolade",src:"the chocolate",gender:"f",example:"A: Möchtest du heiße Schokolade?\nB: Oh ja, bitte! Mit Sahne?",exampleSrc:"A: Would you like hot chocolate?\nB: Oh yes, please! With cream?",note:"die Schokolade (no common plural). Heiße Schokolade = hot chocolate. Short form: Schoki.",funFact:"Germany is the largest chocolate consumer in Europe, averaging 11 kg per person per year. Ritter Sport and Milka are iconic German brands."},
{type:"teach",trg:"die Torte",src:"the cake / tart",gender:"f",example:"A: Diese Torte sieht lecker aus!\nB: Das ist Schwarzwälder Kirschtorte. Sehr berühmt!",exampleSrc:"A: This cake looks delicious!\nB: That is Black Forest cherry cake. Very famous!",note:"die Torte, plural: die Torten. Different from 'der Kuchen' (simpler cake). Torte = layered, fancy.",funFact:"Schwarzwälder Kirschtorte (Black Forest cake) must legally contain Kirschwasser (cherry brandy) to carry the name. It was invented around 1915."},
{type:"teach",trg:"die Rose",src:"the rose",gender:"f",example:"A: Rosen im Winter?\nB: Ja, rote Rosen für den Weihnachtstisch!",exampleSrc:"A: Roses in winter?\nB: Yes, red roses for the Christmas table!",note:"die Rose, plural: die Rosen. Same word as English, from Latin 'rosa'.",funFact:"Germany grows over 80 million roses per year, mostly in greenhouses. The city of Bad Langensalza is called the 'Rosenstadt' (Rose City)."},
{type:"teach",trg:"der Ring",src:"the ring",gender:"m",example:"A: Schau mal, der goldene Ring am Stand!\nB: Sehr schön. Ist das ein Geschenk?",exampleSrc:"A: Look, the golden ring at the stall!\nB: Very nice. Is that a gift?",note:"der Ring, plural: die Ringe. Also means circle or arena (Boxring).",funFact:"The 'Ringstraße' tradition in German cities dates back to medieval times, when ring roads replaced old city walls. Vienna's famous Ringstraße is the most well known."},
{type:"tip",title:"Weihnachtsmarkt: A German Tradition",text:"Christmas markets (Weihnachtsmärkte) open across Germany from late November until Christmas Eve. Every city has its own.\n\nBerlin alone has over 60 markets. The Gendarmenmarkt is considered the most beautiful, framed by two cathedrals and the Konzerthaus.\n\nTypical treats: Glühwein (mulled wine), gebrannte Mandeln (roasted almonds), Lebkuchen (gingerbread), Bratwurst, Stollen (fruit bread).\n\nThe tradition dates back to the 1300s. Dresden's Striezelmarkt (founded 1434) is the oldest.",deepDive:"Markets are called 'Weihnachtsmarkt' or 'Christkindlmarkt' (especially in southern Germany). Each region has specialties: Nuremberg is famous for its tiny Lebkuchen, Aachen for Printen cookies, and Dresden for Christstollen."},
{type:"mc",q:"What is 'die Schokolade'?",opts:["chocolate","calendar","postcard","cake"],ans:"chocolate",hint:"A sweet treat, often served hot in winter"},
{type:"mc",q:"Verumius wants to write home. Which does he need?",opts:["die Postkarte","der Kalender","die Torte","der Ring"],ans:"die Postkarte",hint:"Something you write on and send by mail"},
{type:"fb",s:"Es gibt dunkle {1} am Himmel.",a:"Wolken",opts:["Wolken","Schnee","Ringe","Rosen"],hint:"These float in the sky before snow falls",sSrc:"There are dark {1} in the sky."},
{type:"mc",q:"'Die Torte' is different from 'der Kuchen' because a Torte is...",opts:["layered and fancy","simple and plain","always chocolate","served cold"],ans:"layered and fancy",hint:"Think of a decorated multi-layer dessert"},
{type:"fb",s:"Hildi kauft eine {1} am Weihnachtsmarkt.",a:"Rose",opts:["Rose","Wolke","Schnee","Himmel"],hint:"A beautiful flower, often red",sSrc:"Hildi buys a {1} at the Christmas market."},
{type:"mc",q:"Which word means 'ring'?",opts:["der Ring","die Rose","der Schnee","die Torte"],ans:"der Ring",hint:"A small circle you wear on your finger"},
{type:"match",pairs:[{trg:"der Schnee",src:"the snow"},{trg:"die Wolke",src:"the cloud"},{trg:"der Himmel",src:"the sky"},{trg:"die Postkarte",src:"the postcard"},{trg:"die Schokolade",src:"the chocolate"},{trg:"die Rose",src:"the rose"}]},
{type:"tip",title:"Sneak Peek: Adjective Endings",text:"You saw phrases like 'der warme Glühwein', 'die dunklen Wolken', 'der goldene Ring'.\n\nNotice the endings on the adjectives: warm-E, dunkel-N, golden-E.\n\nGerman adjectives change their endings depending on gender, case, and article. This is called adjective declension.\n\nDo not memorize rules yet. Just notice the patterns. You will learn the system step by step in coming lessons.",deepDive:"Adjective declension is one of German's trickiest grammar topics. There are three declension patterns (strong, weak, mixed) depending on what comes before the adjective. For now, just get used to hearing 'der warme', 'die schöne', 'das frische' as natural chunks."},
{type:"mc",q:"Hildi sagt: 'Der Gendarmenmarkt hat den schönsten Weihnachtsmarkt in Berlin.' What does she mean?",opts:["Gendarmenmarkt has the most beautiful Christmas market in Berlin","Gendarmenmarkt has the biggest Christmas market in Berlin","Gendarmenmarkt has the oldest Christmas market in Berlin","Gendarmenmarkt has the cheapest Christmas market in Berlin"],ans:"Gendarmenmarkt has the most beautiful Christmas market in Berlin",hint:"'schön' is an adjective in its highest form (superlative) here."}
]},

{id:"deu_r11l2",title:"Was ziehe ich an?",icon:"🧣",xp:15,board:true,steps:[
{type:"intro",title:"Was ziehe ich an?",desc:"Es ist kalt auf dem Weihnachtsmarkt! Lerne die wichtigsten Kleidungsstücke für den Winter.",goals:["14 Kleidungswörter mit Artikel","Über Kleidung sprechen","Sich für kaltes Wetter anziehen"]},
{type:"teach",trg:"der Mantel",src:"the coat",gender:"m",phonetic:"MAN-tel",example:"A: Es ist so kalt draußen!\nB: Zieh deinen Mantel an!",exampleSrc:"A: It's so cold outside!\nB: Put your coat on!",note:"der Mantel, masculine. Plural: die Mäntel.",funFact:"German Christmas markets run from late November to December 23rd, so a warm Mantel is essential."},
{type:"teach",trg:"die Mütze",src:"the hat/beanie",gender:"f",phonetic:"MÜT-tse",example:"A: Hast du eine Mütze?\nB: Ja, ich trage immer meine rote Mütze.",exampleSrc:"A: Do you have a beanie?\nB: Yes, I always wear my red beanie.",note:"die Mütze, feminine. For formal hats, use der Hut.",funFact:"In Bavaria, the traditional Filzhut (felt hat) is still worn at festivals, but a Mütze keeps your ears warm."},
{type:"teach",trg:"der Stiefel",src:"the boot",gender:"m",phonetic:"SHTEE-fel",example:"A: Welche Schuhe trägst du heute?\nB: Meine schwarzen Stiefel, es schneit!",exampleSrc:"A: Which shoes are you wearing today?\nB: My black boots, it's snowing!",note:"der Stiefel, masculine. Plural: die Stiefel (same form).",funFact:"The word Stiefel also means a large beer glass shaped like a boot, popular at Oktoberfest."},
{type:"teach",trg:"der Pullover",src:"the sweater",gender:"m",phonetic:"pul-OH-ver",example:"A: Der Pullover sieht warm aus.\nB: Ja, er ist aus Wolle.",exampleSrc:"A: That sweater looks warm.\nB: Yes, it's made of wool.",note:"der Pullover, masculine. Often shortened to Pulli in everyday speech.",funFact:"Pullover comes from English 'pull over'. Germans borrowed the word but gave it a masculine article."},
{type:"teach",trg:"die Hose",src:"the pants",gender:"f",phonetic:"HO-ze",example:"A: Die Hose passt dir gut!\nB: Danke, sie ist neu.",exampleSrc:"A: The pants fit you well!\nB: Thanks, they're new.",note:"die Hose, feminine. Always singular in German, unlike English 'pants'.",funFact:"Lederhosen literally means 'leather pants'. die Hose is singular even though pants come in pairs."},
{type:"teach",trg:"das Hemd",src:"the shirt",gender:"n",phonetic:"HEMT",example:"A: Trägst du ein Hemd zur Arbeit?\nB: Ja, ein weißes Hemd.",exampleSrc:"A: Do you wear a shirt to work?\nB: Yes, a white shirt.",note:"das Hemd, neuter. Refers to a button-up shirt specifically.",funFact:"Das Hemd is related to the old German word for 'cover'. A T-Shirt is a separate word in German."},
{type:"teach",trg:"das Kleid",src:"the dress",gender:"n",phonetic:"KLITE",example:"A: Das Kleid ist wunderschön!\nB: Danke, ich trage es gern.",exampleSrc:"A: The dress is beautiful!\nB: Thanks, I like wearing it.",note:"das Kleid, neuter. Plural: die Kleider. Also means 'clothes' in plural.",funFact:"Kleider machen Leute is a famous German proverb: 'Clothes make the person.'"},
{type:"mc",q:"Wie sagt man 'coat' auf Deutsch?",opts:["der Mantel","die Mütze","der Pullover","das Hemd"],ans:"der Mantel",hint:"Think of something long that keeps you warm outside."},
{type:"fb",s:"Im Winter trage ich immer meine {1}.",a:"Mütze",opts:["Mütze","Mantel","Hemd","Kleid"],hint:"It keeps your ears warm on cold days.",sSrc:"In winter I always wear my {1}."},
{type:"teach",trg:"die Bluse",src:"the blouse",gender:"f",phonetic:"BLUE-ze",example:"A: Die Bluse passt gut zum Rock.\nB: Findest du? Ich bin nicht sicher.",exampleSrc:"A: The blouse goes well with the skirt.\nB: You think so? I'm not sure.",note:"die Bluse, feminine. Similar to Hemd but typically for women.",funFact:"German fashion vocabulary often borrows from French. Bluse came via French from medieval Latin."},
{type:"teach",trg:"der Rock",src:"the skirt",gender:"m",phonetic:"ROK",example:"A: Der Rock ist zu kurz für den Winter.\nB: Dann ziehe ich eine Hose an.",exampleSrc:"A: The skirt is too short for winter.\nB: Then I'll put on pants.",note:"der Rock, masculine. Be careful: Rock also means 'rock music' in German.",funFact:"Der Rock is masculine even though it refers to a garment traditionally worn by women. German grammar does not follow logic."},
{type:"teach",trg:"die Jeans",src:"the jeans",gender:"f",phonetic:"JEENS",example:"A: Ich trage am liebsten Jeans.\nB: Ich auch, sie sind so bequem!",exampleSrc:"A: I prefer wearing jeans.\nB: Me too, they're so comfortable!",note:"die Jeans, feminine. Pronounced like in English. Singular in German.",funFact:"Jeans were invented by Levi Strauss, a German immigrant from Bavaria who moved to San Francisco."},
{type:"teach",trg:"der Schirm",src:"the umbrella",gender:"m",phonetic:"SHIRM",example:"A: Hast du einen Schirm dabei?\nB: Nein, aber es regnet!",exampleSrc:"A: Do you have an umbrella with you?\nB: No, but it's raining!",note:"der Schirm, masculine. Short for der Regenschirm (rain umbrella).",funFact:"Schirm literally means 'shield'. A Bildschirm is a 'picture shield', the German word for screen or monitor."},
{type:"teach",trg:"der Anzug",src:"the suit",gender:"m",phonetic:"AN-tsook",example:"A: Wann trägst du einen Anzug?\nB: Nur bei der Arbeit.",exampleSrc:"A: When do you wear a suit?\nB: Only at work.",note:"der Anzug, masculine. Literally 'something you pull on' (anziehen).",funFact:"Anzug comes from anziehen (to put on). German builds many clothing words from the verb 'to dress'."},
{type:"teach",trg:"die Brille",src:"the glasses",gender:"f",phonetic:"BRIL-le",example:"A: Ohne meine Brille sehe ich nichts.\nB: Dann vergiss sie nicht!",exampleSrc:"A: Without my glasses I can't see anything.\nB: Then don't forget them!",note:"die Brille, feminine. Always singular in German, even though you wear two lenses.",funFact:"Brille comes from Beryll, a gemstone once used to make lenses in the Middle Ages."},
{type:"teach",trg:"das T-Shirt",src:"the t-shirt",gender:"n",phonetic:"TEE-shört",example:"A: Im Sommer trage ich nur ein T-Shirt.\nB: Im Winter brauchst du mehr!",exampleSrc:"A: In summer I only wear a t-shirt.\nB: In winter you need more!",note:"das T-Shirt, neuter. Borrowed from English. Always capitalized in German.",funFact:"German capitalizes all nouns, so even borrowed words like T-Shirt get a capital letter and an article."},
{type:"tip",title:"Sich anziehen: Dressing for the Weihnachtsmarkt",text:"Germans layer up for winter markets:\n\n1. das Unterhemd (undershirt)\n2. das Hemd oder der Pullover\n3. der Mantel\n4. die Mütze, der Schal, die Handschuhe\n\nUseful verb: anziehen (to put on)\nIch ziehe meinen Mantel an.\nZieh dich warm an! (Dress warmly!)",deepDive:"anziehen is a separable verb: the an- goes to the end.\n\nIch ziehe einen Pullover an.\nSie zieht ihre Stiefel an.\n\nThe opposite is ausziehen (to take off):\nEr zieht seinen Mantel aus."},
{type:"mc",q:"Welches Wort bedeutet 'glasses'?",opts:["die Brille","die Bluse","die Hose","die Jeans"],ans:"die Brille",hint:"This word comes from a gemstone name."},
{type:"fb",s:"Levi Strauss war Deutscher. Er hat die {1} erfunden.",a:"Jeans",opts:["Jeans","Brille","Mütze","Bluse"],hint:"A famous type of pants from Bavaria.",sSrc:"Levi Strauss was German. He invented {1}."},
{type:"mc",q:"Was trägst du bei Regen?",opts:["einen Schirm","eine Mütze","einen Anzug","ein Kleid"],ans:"einen Schirm",hint:"Think of what keeps you dry when water falls from the sky."},
{type:"fb",s:"Für die Arbeit brauche ich einen {1} und ein Hemd.",a:"Anzug",opts:["Anzug","Rock","Pullover","Stiefel"],hint:"A formal outfit that you 'pull on' (anziehen).",sSrc:"For work I need a {1} and a shirt."},
{type:"mc",q:"Was ist 'der Rock' auf Englisch?",opts:["skirt","rock music","coat","dress"],ans:"skirt",hint:"A piece of clothing, not a music genre."},
{type:"drag_fill",s:"Im Winter ziehe ich {1}, {2} und {3} an.",blanks:{"1":"Stiefel","2":"einen Mantel","3":"eine Mütze"},pool:["Stiefel","einen Mantel","eine Mütze","ein T-Shirt","einen Rock"],hint:"Think about what keeps you warm from head to toe.",sSrc:"In winter I put on {1}, {2} and {3}."},
{type:"match",pairs:[{trg:"der Mantel",src:"the coat"},{trg:"die Mütze",src:"the beanie"},{trg:"der Stiefel",src:"the boot"},{trg:"die Hose",src:"the pants"},{trg:"das Kleid",src:"the dress"},{trg:"die Brille",src:"the glasses"}]},
{type:"mc",q:"Welches Kleidungsstück ist immer Neutrum (das)?",opts:["das Hemd und das Kleid","der Mantel und der Rock","die Hose und die Jeans","die Bluse und die Mütze"],ans:"das Hemd und das Kleid",hint:"Look for the neuter articles among the clothing words you learned."},
{type:"fb",s:"Kleider machen {1}.",a:"Leute",opts:["Leute","Kleider","Schuhe","Sachen"],hint:"A famous proverb about how clothes affect perception of people.",sSrc:"Clothes make {1}."}
]}
,

// Unit 11, Lesson 3: Opa Heinrichs Brötchen
// Story dev + grammar intro: adjective declension (nominative) + temporal prepositions
// 8 vocab teach cards + verb_table + tip + 8 quiz steps = 24 steps total

{id:"deu_r11l3",title:"Opa Heinrichs Brötchen",icon:"🍞",xp:15,board:true,steps:[
{type:"intro",title:"Opa Heinrichs Brötchen",desc:"A man in a wool coat and flat cap appears at the Weihnachtsmarkt. He has bread from this morning and opinions about everything. Meet Opa Heinrich.",goals:["Learn 8 new words for gifts and shopping","Understand adjective endings in nominative case","Use temporal prepositions to talk about time"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-weihnachtsmarkt-opa",trg:"Ein alter Mann kommt langsam durch die Menge. Wollmantel, Schiebermütze, eine Tüte Brötchen unter dem Arm. Er sieht Hildi und winkt. 'Von heute Morgen,' sagt er und hält die Tüte hoch. 'Noch frisch!'",src:"An old man comes slowly through the crowd. Wool coat, flat cap, a bag of bread rolls under his arm. He sees Hildi and waves. 'From this morning,' he says, holding up the bag. 'Still fresh!'"},
{type:"story",speaker:"hildi",trg:"Verumius, das ist mein Opa Heinrich. Opa, das ist Verumius. Er lernt Deutsch.",src:"Verumius, this is my grandpa Heinrich. Grandpa, this is Verumius. He is learning German."},
{type:"story",speaker:"opa",trg:"Ah, der neue Freund! Hier, nimm ein frisches Brötchen. Nach dem Frühstück habe ich noch zehn übrig. Vor einer Stunde waren es zwölf.",src:"Ah, the new friend! Here, take a fresh bread roll. After breakfast I still had ten left. An hour ago there were twelve."},
{type:"teach",trg:"die Kette",src:"the necklace / the chain",note:"Feminine noun. Plural: die Ketten.",example:"A: Die goldene Kette ist schön!\nB: Ja, die ist seit gestern im Angebot.",exampleSrc:"A: The golden necklace is beautiful!\nB: Yes, it has been on sale since yesterday.",funFact:"'Kette' means both 'necklace' and 'chain.' A bicycle chain is also 'eine Kette.' Context tells you if it is jewelry or hardware."},
{type:"teach",trg:"das Parfüm",src:"the perfume",note:"Neuter noun. Plural: die Parfüms. Borrowed from French.",example:"A: Das teure Parfüm riecht toll!\nB: Ich schenke es meiner Mutter nach Weihnachten.",exampleSrc:"A: The expensive perfume smells great!\nB: I'll give it to my mother after Christmas.",funFact:"Germans borrowed 'Parfüm' straight from French 'parfum.' The umlaut ü was added to match German pronunciation. Many luxury words in German are French imports."},
{type:"teach",trg:"die Kosmetik",src:"the cosmetics",note:"Feminine noun. Used as singular for the category.",example:"A: Wo finde ich gute Kosmetik?\nB: Seit letztem Jahr gibt es einen neuen Stand hier.",exampleSrc:"A: Where can I find good cosmetics?\nB: Since last year there has been a new stall here.",funFact:"From Greek 'kosmetikos' meaning 'skilled in decorating.' The same root gives us 'cosmos,' because the Greeks thought the universe was beautifully ordered."},
{type:"teach",trg:"die Mode",src:"the fashion",note:"Feminine noun. From French 'mode.'",example:"A: Ist diese Mode noch modern?\nB: Ja, vor zwei Wochen war sie auf Instagram!",exampleSrc:"A: Is this fashion still modern?\nB: Yes, two weeks ago it was on Instagram!",funFact:"'Mode' and 'modern' share the same Latin root 'modus' (way, style). In German, 'altmodisch' (old-fashioned) literally means 'old-mode-ish.'"},
{type:"mc",q:"Opa Heinrich says 'Von heute Morgen, noch frisch!' What is he talking about?",opts:["His wool coat","His flat cap","His bread rolls","His necklace"],ans:"His bread rolls",hint:"He is carrying a bag of something baked under his arm."},
{type:"teach",trg:"die Ferien",src:"the holidays / the vacation",note:"Always plural in German. No singular form.",example:"A: Was machst du in den Ferien?\nB: Während der Ferien fahre ich nach Spanien.",exampleSrc:"A: What are you doing during the holidays?\nB: During the holidays I'm going to Spain.",funFact:"'Ferien' is always plural. For a single day off, Germans say 'Feiertag' (celebration-day). School holidays are 'Schulferien,' and summer break is 'Sommerferien.'"},
{type:"teach",trg:"der Flohmarkt",src:"the flea market",note:"Masculine noun. Compound: Floh (flea) + Markt (market).",example:"A: Auf dem alten Flohmarkt gibt es schöne Ketten.\nB: Stimmt, seit letztem Monat ist er noch größer.",exampleSrc:"A: At the old flea market there are beautiful necklaces.\nB: True, since last month it is even bigger.",funFact:"'Flohmarkt' is a direct loan-translation from French 'marché aux puces.' The story goes that old clothes sold at these markets often had fleas in them!"},
{type:"teach",trg:"schenken",src:"to give (as a gift)",note:"Regular verb. Different from 'geben' (to give). Schenken = always a gift.",example:"A: Was schenkst du ihr?\nB: Ich schenke ihr eine neue Kette vor ihrem Geburtstag.",exampleSrc:"A: What are you giving her?\nB: I'm giving her a new necklace before her birthday.",funFact:"'Schenken' comes from 'einschenken' (to pour a drink). Originally, offering someone a drink was the act of giving. The meaning broadened to any gift."},
{type:"teach",trg:"wünschen",src:"to wish",note:"Regular verb. 'Ich wünsche dir alles Gute!' = I wish you all the best!",example:"A: Was wünschst du dir zu Weihnachten?\nB: Ich wünsche mir ein gutes Parfüm.",exampleSrc:"A: What do you wish for for Christmas?\nB: I wish for a nice perfume.",funFact:"The reflexive 'sich wünschen' means 'to wish for oneself.' A Wunschzettel is a 'wish-list' that German children write for Weihnachten."},
{type:"teach",trg:"der Schal",src:"the scarf",gender:"m",phonetic:"SHAHL",example:"A: Dein Schal ist wirklich schon!\nB: Danke, ich habe ihn auf dem Weihnachtsmarkt gekauft.\nA: Die Farbe passt perfekt zu deinem Mantel.",exampleSrc:"A: Your scarf is really beautiful!\nB: Thanks, I bought it at the Christmas market.\nA: The color matches your coat perfectly.",note:"der Schal, masculine. Plural: die Schals. A winter essential on the Weihnachtsmarkt.",funFact:"The German word 'Schal' comes from Persian via French. Cashmere scarves from Kashmir were luxury items in 18th century Europe."},
{type:"mc",q:"'Ich schenke dir eine Kette.' What is the speaker doing?",opts:["Buying a necklace for themselves","Giving a necklace as a gift","Borrowing a necklace","Returning a necklace"],ans:"Giving a necklace as a gift",hint:"This verb means presenting something as a gift, permanently."},
{type:"verb_table",title:"Adjective Endings: Nominative Case",groups:[{label:"After der/die/das (definite article): always -e",rows:[{pronoun:"der",form:"-e",src:"der alte Mann (the old man)"},{pronoun:"die",form:"-e",src:"die goldene Kette (the golden necklace)"},{pronoun:"das",form:"-e",src:"das teure Parfüm (the expensive perfume)"},{pronoun:"die (pl.)",form:"-en",src:"die frischen Brötchen (the fresh rolls)"}]},{label:"After ein/eine/ein (indefinite article)",rows:[{pronoun:"ein (masc.)",form:"-er",src:"ein alter Mann (an old man)"},{pronoun:"eine (fem.)",form:"-e",src:"eine goldene Kette (a golden necklace)"},{pronoun:"ein (neut.)",form:"-es",src:"ein teures Parfüm (an expensive perfume)"}]},{label:"No article (strong endings)",rows:[{pronoun:"masc.",form:"-er",src:"frischer Kaffee (fresh coffee)"},{pronoun:"fem.",form:"-e",src:"gute Kosmetik (good cosmetics)"},{pronoun:"neut.",form:"-es",src:"kaltes Wasser (cold water)"},{pronoun:"plural",form:"-e",src:"frische Brötchen (fresh rolls)"}]}],note:"After definite articles, adjectives are 'weak' and almost always end in -e (except plural: -en). After indefinite articles, the adjective shows the gender."},
{type:"tip",title:"Temporal Prepositions: When Did It Happen?",text:"German uses specific prepositions for time expressions:\n\nvor + dative: ago, before\n'Vor einer Stunde' = an hour ago\n'Vor dem Frühstück' = before breakfast\n\nnach + dative: after\n'Nach dem Essen' = after the meal\n'Nach Weihnachten' = after Christmas\n\nwährend + genitive: during\n'Während der Ferien' = during the holidays\n\nbis: until\n'Bis morgen!' = Until tomorrow!\n\nseit + dative: since, for (ongoing)\n'Seit gestern' = since yesterday\n'Seit zwei Wochen' = for two weeks\n\nab + dative: from (a point in time)\n'Ab morgen' = from tomorrow on",deepDive:"'Vor' and 'nach' are the most common pair. Think of them as opposites on a timeline: vor = to the left (earlier), nach = to the right (later). 'Seit' describes something that STARTED in the past and CONTINUES now. 'Bis' marks where something ENDS."},
{type:"mc",q:"Opa Heinrich says 'Vor einer Stunde waren es zwölf.' What does 'vor einer Stunde' mean?",opts:["In one hour","For one hour","An hour ago","Before one hour"],ans:"An hour ago",hint:"'Vor' with a time expression looks backward on the timeline."},
{type:"fb",s:"{1} dem Frühstück habe ich noch zehn übrig.",a:["Nach"],opts:["Nach","Vor","Seit","Bis"],hint:"Which preposition means 'after' with a past event?",sSrc:"{1} breakfast I have ten left."},
{type:"mc",q:"'Die goldene Kette ist schön.' Why does the adjective end in -e?",opts:["Because 'Kette' is feminine","Because it follows 'die' (definite article)","Because 'golden' always ends in -e","Because the sentence is about beauty"],ans:"Because it follows 'die' (definite article)",hint:"After 'die' in nominative, the suffix on the descriptor is nearly always the same."},
{type:"fb",s:"Ein alt{1} Mann kommt durch die Menge.",a:["er"],opts:["er","e","es","en"],hint:"After 'ein' in nominative, what ending does the adjective need for a masculine noun?",sSrc:"An old{1} man comes through the crowd."},
{type:"drag_fill",s:"Ich wünsche mir {1} Parfüm {2} Weihnachten.",blanks:{"1":"ein gutes","2":"vor"},pool:["ein gutes","eine gute","ein guter","vor","nach","seit"],hint:"A neuter noun after 'ein' needs which ending? And which preposition means 'before'?",sSrc:"I wish for {1} perfume {2} Christmas."},
{type:"mc",q:"'Seit letztem Jahr gibt es einen neuen Stand.' What does 'seit' tell you?",opts:["It happened once last year","It started last year and continues now","It will happen next year","It ended last year"],ans:"It started last year and continues now",hint:"This preposition describes something ongoing from a past starting point."},
{type:"fb",s:"{1} der Ferien fahre ich nach Spanien.",a:["Während"],opts:["Während","Seit","Vor","Ab"],hint:"Which preposition means 'during' and takes the genitive case?",sSrc:"{1} the holidays I am travelling to Spain."},
{type:"drag_fill",s:"{1} Brötchen sind {2} heute Morgen.",blanks:{"1":"Die frischen","2":"von"},pool:["Die frischen","Das frische","Der frischer","von","vor","nach"],hint:"Definite article + plural adjective ending? And 'from' this morning?",sSrc:"{1} rolls are {2} this morning."},
{type:"match",pairs:[{trg:"die Kette",src:"the necklace"},{trg:"schenken",src:"to give (as gift)"},{trg:"wünschen",src:"to wish"},{trg:"die Ferien",src:"the holidays"},{trg:"vor",src:"ago / before"},{trg:"seit",src:"since / for"}]},
{type:"story",speaker:"opa",trg:"Hier, frische Brötchen für alle! Seit fünfzig Jahren kaufe ich beim gleichen Bäcker. Vor dem Krieg war der Laden noch klein. Während der Ferien backt er sogar Stollen!",src:"Here, fresh rolls for everyone! For fifty years I have been buying from the same baker. Before the war the shop was still small. During the holidays he even bakes Stollen!"},
{type:"mc",q:"Opa Heinrich says 'Seit fünfzig Jahren kaufe ich beim gleichen Bäcker.' How long has he been going to the same baker?",opts:["For five years","For fifteen years","For fifty years","Since his birthday"],ans:"For fifty years",hint:"'Fünfzig' is the German word for a number between 49 and 51."}
]},
,

// U11 L4: Der rote Schal - Grammar: Adjective declension (acc/dat), possessives, Konjunktiv II
{id:"deu_r11l4",title:"Der rote Schal",icon:"\uD83D\uDCD0",xp:20,board:true,steps:[
{type:"intro",title:"Der rote Schal",desc:"Verumius spots a beautiful red scarf at the Weihnachtsmarkt. But describing it means mastering adjective endings in accusative and dative. Plus: how to say 'I would like...'",goals:["Decline adjectives in accusative and dative","Use possessive articles across cases","Express wishes with w\u00fcrde + infinitive"]},
{type:"story",speaker:"narrator",mood:"curious",art:"de-xmas-market-scarves",trg:"Am Schalstand. Bunte Schals h\u00e4ngen \u00fcberall. Verumius sieht einen roten Schal und greift danach. Hildi lacht.",src:"At the scarf stand. Colorful scarves hang everywhere. Verumius sees a red scarf and reaches for it. Hildi laughs."},
{type:"story",speaker:"Hildi",trg:"Du willst den roten Schal? Der passt zu deinem blauen Mantel. Aber ich w\u00fcrde den gr\u00fcnen nehmen!",src:"You want the red scarf? It goes with your blue coat. But I would take the green one!"},
{type:"teach",trg:"beschreiben",src:"to describe",note:"Regular: ich beschreibe, du beschreibst, er beschreibt.",example:"A: Kannst du den Schal beschreiben?\nB: Er ist lang, rot und sehr weich.",exampleSrc:"A: Can you describe the scarf?\nB: It is long, red, and very soft.",funFact:"'Beschreiben' literally means 'to write upon.' You 'write upon' something with words to paint a picture. The same 'schreiben' root appears in 'Schreibtisch' (writing desk)."},
{type:"teach",trg:"passen",src:"to fit / to suit",note:"Regular: ich passe, du passt, er passt. Often used with 'zu' (to/with).",example:"A: Passt der Schal zu meinem Mantel?\nB: Ja, die Farben passen perfekt zusammen!",exampleSrc:"A: Does the scarf go with my coat?\nB: Yes, the colors match perfectly!",funFact:"'Das passt!' is how Germans say 'That works!' In restaurants, 'Passt so' after paying means 'keep the change.' One little verb, many daily uses."},
{type:"teach",trg:"tragen",src:"to wear / to carry",note:"Irregular: ich trage, du tr\u00e4gst, er tr\u00e4gt. Stem change a \u2192 \u00e4.",example:"A: Was tr\u00e4gst du heute?\nB: Ich trage einen warmen Pullover.",exampleSrc:"A: What are you wearing today?\nB: I'm wearing a warm sweater.",funFact:"'Tragen' means both 'to wear' and 'to carry.' A 'Gep\u00e4cktr\u00e4ger' is a luggage carrier. Context decides whether clothes or cargo are involved."},
{type:"teach",trg:"vergleichen",src:"to compare",note:"Irregular past, but regular present: ich vergleiche, du vergleichst.",example:"A: Lass uns die zwei Schals vergleichen.\nB: Der rote ist weicher als der blaue.",exampleSrc:"A: Let's compare the two scarves.\nB: The red one is softer than the blue one.",funFact:"'Vergleichen' contains 'gleich' (same/equal). To compare is literally to 'check for sameness.' 'Gleich' also means 'soon' in casual speech: 'Ich komme gleich!'"},
{type:"teach",trg:"wechseln",src:"to change / to exchange",note:"Regular: ich wechsle, du wechselst. Used for money, clothes, or topics.",example:"A: Kann ich den Schal wechseln?\nB: Nat\u00fcrlich, gegen welche Farbe?",exampleSrc:"A: Can I exchange the scarf?\nB: Of course, for which color?",funFact:"A 'Wechselstube' is a currency exchange booth. 'Geld wechseln' = to exchange money. At the Weihnachtsmarkt, you might need to 'wechseln' big bills for small coins."},
{type:"teach",trg:"ansehen",src:"to look at",note:"Separable: ich sehe ... an, du siehst ... an. Stem change e \u2192 ie.",example:"A: Sieh dir den Schal an!\nB: Oh, der ist wirklich sch\u00f6n!",exampleSrc:"A: Look at the scarf!\nB: Oh, it is really beautiful!",funFact:"'Ansehen' is separable: the 'an' jumps to the end of the clause. 'Ich sehe den Schal an.' But in a subordinate clause it reunites: 'weil ich den Schal ansehe.' German word Tetris!"},
{type:"mc",q:"Which verb means 'to wear' or 'to carry' in German?",opts:["tragen","passen","wechseln","beschreiben"],ans:"tragen",hint:"This irregular verb has a stem change from a to \u00e4 in the du/er forms."},
{type:"tip",title:"Adjective Endings: The Big Picture",text:"German adjectives change their ending based on THREE things:\n\n1. Case: nominative, accusative, or dative?\n2. Gender: der, die, or das?\n3. Article type: definite (der/die/das) or indefinite (ein/eine/ein)?\n\nYou already know nominative from L3.\nNow we add accusative (direct object) and dative (indirect object).\n\nGood news: there are PATTERNS that simplify everything.",deepDive:"Why does German do this? Because adjective endings carry grammatical information. In 'Ich sehe den roten Schal,' the '-en' on 'roten' confirms this is accusative masculine. Even if you missed 'den,' the adjective ending tells you the case. It is a backup system built into the language."},
{type:"verb_table",title:"Adjective Declension: Accusative Case",groups:[{label:"With definite article (den/die/das)",rows:[{pronoun:"Masculine",form:"den rot-en Schal",src:"the red scarf (-en)"},{pronoun:"Feminine",form:"die rot-e M\u00fctze",src:"the red hat (-e)"},{pronoun:"Neuter",form:"das rot-e Kleid",src:"the red dress (-e)"}]},{label:"With indefinite article (einen/eine/ein)",rows:[{pronoun:"Masculine",form:"einen rot-en Schal",src:"a red scarf (-en)"},{pronoun:"Feminine",form:"eine rot-e M\u00fctze",src:"a red hat (-e)"},{pronoun:"Neuter",form:"ein rot-es Kleid",src:"a red dress (-es)"}]}],note:"Accusative masculine always gets -en. Feminine stays -e. Neuter: -e with definite, -es with indefinite (because 'ein' has no ending to show gender)."},
{type:"mc",q:"'Ich kaufe _____ warmen Schal.' Which article completes this accusative masculine phrase?",opts:["den","die","das","dem"],ans:"den",hint:"Accusative changes only the masculine article from 'der' to something else."},
{type:"fb",s:"Verumius tr\u00e4gt einen rot{1} Schal.",a:["en"],opts:["en","e","es","em"],hint:"After 'einen' (accusative masc. indefinite), what ending does the adjective take?",sSrc:"Verumius wears a red{1} scarf."},
{type:"mc",q:"'Hildi sieht die sch\u00f6n___ Lampe an.' Which ending fits this accusative feminine phrase?",opts:["-e","-en","-es","-em"],ans:"-e",hint:"Accusative feminine with 'die' keeps the same ending as nominative feminine."},
{type:"fb",s:"Ich m\u00f6chte ein warm{1} Kleid kaufen.",a:["es"],opts:["es","e","en","em"],hint:"Accusative neuter with 'ein' needs an ending that shows neuter gender.",sSrc:"I would like to buy a warm{1} dress."},
{type:"verb_table",title:"Adjective Declension: Dative Case",groups:[{label:"With definite article (dem/der/dem)",rows:[{pronoun:"Masculine",form:"dem rot-en Schal",src:"the red scarf (-en)"},{pronoun:"Feminine",form:"der rot-en M\u00fctze",src:"the red hat (-en)"},{pronoun:"Neuter",form:"dem rot-en Kleid",src:"the red dress (-en)"}]},{label:"With indefinite article (einem/einer/einem)",rows:[{pronoun:"Masculine",form:"einem rot-en Schal",src:"a red scarf (-en)"},{pronoun:"Feminine",form:"einer rot-en M\u00fctze",src:"a red hat (-en)"},{pronoun:"Neuter",form:"einem rot-en Kleid",src:"a red dress (-en)"}]}],note:"Dative is the EASY case for adjectives: EVERY ending is -en. Always. No exceptions. Masculine, feminine, neuter, definite, indefinite: always -en."},
{type:"tip",title:"Dative Shortcut: Always -en!",text:"Dative adjective endings are the simplest in German:\n\ndem kalten Wind = -en\nder warmen Suppe = -en\ndem alten Haus = -en\neinem neuen Freund = -en\n\nAll genders. All article types. Always -en.\nThis is the one case you can learn in five seconds.",deepDive:"Why always -en? In dative, the article itself already shows the gender clearly (dem = masc/neut, der = fem). The adjective does not need to carry extra gender information, so it relaxes to the default -en ending. Less work for the adjective when the article is already doing the job."},
{type:"fb",s:"Ich gebe es dem klein{1} Kind.",a:["en"],opts:["en","e","es","em"],hint:"In dative, adjective endings follow one universal rule for all genders.",sSrc:"I give it to the small{1} child."},
{type:"teach",trg:"die Tasse",src:"the cup",gender:"f",phonetic:"TA-suh",example:"A: Mochtest du eine Tasse Tee?\nB: Ja, gerne! Mit Zucker, bitte.\nA: Hier, eine warme Tasse fur dich.",exampleSrc:"A: Would you like a cup of tea?\nB: Yes, please! With sugar.\nA: Here, a warm cup for you.",note:"die Tasse, feminine. Plural: die Tassen. Used for cups with handles, including mugs.",funFact:"Germans drink about 164 litres of coffee per person per year. On the Weihnachtsmarkt, Gluhwein comes in collectible Tassen you can keep."},
{type:"mc",q:"'Mit einer warm___ Tasse Tee.' Which ending completes this dative phrase?",opts:["-en","-e","-es","-er"],ans:"-en",hint:"Dative adjectives follow one universal rule regardless of gender or article type."},
{type:"drag_fill",s:"Verumius gibt {1} Frau {2} Schal.",blanks:{"1":"der netten","2":"den roten"},pool:["der netten","den roten","die nette","das rote","dem netten"],hint:"'Der Frau' is dative feminine. 'Den Schal' is accusative masculine. Pick the matching adjective forms.",sSrc:"Verumius gives {1} woman {2} scarf."},
{type:"verb_table",title:"Possessive Articles: mein/dein/sein/ihr",groups:[{label:"Nominative",rows:[{pronoun:"Masculine",form:"mein roter Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meine rote M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"mein rotes Kleid",src:"my red dress"}]},{label:"Accusative",rows:[{pronoun:"Masculine",form:"meinen roten Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meine rote M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"mein rotes Kleid",src:"my red dress"}]},{label:"Dative",rows:[{pronoun:"Masculine",form:"meinem roten Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meiner roten M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"meinem roten Kleid",src:"my red dress"}]}],note:"Possessives (mein/dein/sein/ihr/unser/euer/ihr) follow the SAME pattern as ein/eine/ein. Just swap 'ein' for 'mein' and adjective endings stay identical."},
{type:"tip",title:"Possessives = ein-Words",text:"Great news: mein, dein, sein, ihr, unser, euer, ihr, and kein all follow the EXACT same pattern as ein/eine/ein.\n\nIf you know 'einen roten Schal,' you know:\nmeinen roten Schal\ndeinen roten Schal\nseinen roten Schal\nihren roten Schal\n\nOne pattern, eight words. Learn it once, use it everywhere.",deepDive:"The possessives are called 'ein-words' because they take the same endings as 'ein.' The definite article words (dieser, jeder, welcher) are called 'der-words' and follow 'der/die/das' endings. Knowing which group a word belongs to tells you all its endings automatically."},
{type:"fb",s:"Hildi tr\u00e4gt {1} neuen Schal.",a:["ihren"],opts:["ihren","ihre","ihr","ihrem"],hint:"Accusative masculine with a possessive follows the same pattern as 'einen.'",sSrc:"Hildi wears {1} new scarf."},
{type:"mc",q:"'Ich gebe es meinem alten Freund.' What case is 'meinem alten' in?",opts:["Dative","Accusative","Nominative","Genitive"],ans:"Dative",hint:"'Meinem' with -em ending signals the case used for giving things TO someone."},
{type:"tip",title:"Konjunktiv II: Wishes and Polite Requests",text:"To say 'I would...' in German, use:\nw\u00fcrde + infinitive (at the end)\n\nIch w\u00fcrde den Schal kaufen. = I would buy the scarf.\nW\u00fcrdest du mir helfen? = Would you help me?\n\nFour common verbs have their OWN Konjunktiv II forms:\nw\u00e4re (would be), h\u00e4tte (would have),\nk\u00f6nnte (could), m\u00fcsste (would have to).",deepDive:"Konjunktiv II comes from the simple past (Pr\u00e4teritum) form with an umlaut added. 'War' becomes 'w\u00e4re,' 'hatte' becomes 'h\u00e4tte,' 'konnte' becomes 'k\u00f6nnte.' For most verbs, this old form sounds archaic, so modern German uses 'w\u00fcrde + infinitive' instead. But the four common ones (w\u00e4re, h\u00e4tte, k\u00f6nnte, m\u00fcsste) are used daily."},
{type:"verb_table",title:"Konjunktiv II: w\u00fcrde + Infinitive",groups:[{label:"w\u00fcrde (would)",rows:[{pronoun:"ich",form:"w\u00fcrde",src:"I would"},{pronoun:"du",form:"w\u00fcrdest",src:"you would"},{pronoun:"er/sie/es",form:"w\u00fcrde",src:"he/she/it would"},{pronoun:"wir",form:"w\u00fcrden",src:"we would"},{pronoun:"ihr",form:"w\u00fcrdet",src:"you all would"},{pronoun:"sie/Sie",form:"w\u00fcrden",src:"they/you (formal) would"}]},{label:"Common irregular forms",rows:[{pronoun:"sein",form:"w\u00e4re",src:"would be"},{pronoun:"haben",form:"h\u00e4tte",src:"would have"},{pronoun:"k\u00f6nnen",form:"k\u00f6nnte",src:"could"},{pronoun:"m\u00fcssen",form:"m\u00fcsste",src:"would have to"}]}],note:"Use w\u00fcrde + infinitive for most verbs. Use w\u00e4re/h\u00e4tte/k\u00f6nnte/m\u00fcsste directly (no w\u00fcrde needed). 'Ich w\u00fcrde kaufen' but 'Ich h\u00e4tte gern...'"},
{type:"mc",q:"Hildi says 'Ich w\u00fcrde den gr\u00fcnen nehmen!' What does 'w\u00fcrde ... nehmen' mean?",opts:["would take","must take","will take","should take"],ans:"would take",hint:"This construction expresses a hypothetical wish, not certainty or obligation."},
{type:"fb",s:"Ich {1} gern einen Gl\u00fchwein trinken.",a:["w\u00fcrde"],opts:["w\u00fcrde","w\u00e4re","h\u00e4tte","k\u00f6nnte"],hint:"Which word means 'would' and combines with an infinitive at the end?",sSrc:"I {1} like to drink a mulled wine."},
{type:"mc",q:"'Das w\u00e4re sehr nett!' What does 'w\u00e4re' mean?",opts:["would be","would have","could","would have to"],ans:"would be",hint:"This irregular Konjunktiv II form comes from 'sein' (to be)."},
{type:"drag_fill",s:"Ich {1} gern {2} roten Schal f\u00fcr {3} Freundin kaufen.",blanks:{"1":"w\u00fcrde","2":"den","3":"meine"},pool:["w\u00fcrde","den","meine","w\u00e4re","dem","meiner"],hint:"Express a wish (would), then accusative masc. article, then accusative fem. possessive.",sSrc:"I {1} like to buy {2} red scarf for {3} girlfriend."},
{type:"mc",q:"'Wenn ich reich ___, ___ ich alles kaufen.' Which pair completes this?",opts:["w\u00e4re ... w\u00fcrde","w\u00fcrde ... w\u00e4re","h\u00e4tte ... w\u00e4re","k\u00f6nnte ... h\u00e4tte"],ans:"w\u00e4re ... w\u00fcrde",hint:"First blank needs the Konjunktiv II of 'sein,' second needs 'would' with an infinitive."},
{type:"match",pairs:[{trg:"den roten Schal",src:"the red scarf (acc.)"},{trg:"dem kalten Wind",src:"the cold wind (dat.)"},{trg:"meinen neuen Mantel",src:"my new coat (acc.)"},{trg:"einer warmen Tasse",src:"a warm cup (dat.)"},{trg:"w\u00fcrde kaufen",src:"would buy"},{trg:"w\u00e4re",src:"would be"}]}
]}
,

{id:"deu_r11l5",title:"Wie ist das Wetter?",icon:"🌨️",xp:15,board:true,steps:[
{type:"intro",title:"Wie ist das Wetter?",desc:"Wetter und Adjektive auf dem Weihnachtsmarkt. Beschreibe, was du siehst und fühlst.",goals:["20 Wetter- und Beschreibungswörter lernen","Adjektivendungen in Sätzen üben","Über das Wetter sprechen"]},
{type:"teach",trg:"kalt",src:"cold",phonetic:"kahlt",example:"A: Ist es draußen kalt?\nB: Ja, es ist sehr kalt heute.",exampleSrc:"A: Is it cold outside?\nB: Yes, it is very cold today.",note:"Das klassische Winterwort. Kälte = the cold (noun).",funFact:"Deutsche reden ständig übers Wetter. 'Kalt, oder?' ist ein vollwertiger Gesprächseinstieg."},
{type:"teach",trg:"kühl",src:"cool",phonetic:"küül",example:"A: Wie ist es abends auf dem Markt?\nB: Es wird kühl nach sechs Uhr.",exampleSrc:"A: How is it in the evening at the market?\nB: It gets cool after six o'clock.",note:"Milder als kalt. Frische Luft = cool air.",funFact:"Kühl beschreibt auch Personen: 'Sie war sehr kühl zu mir' bedeutet distanziert."},
{type:"teach",trg:"warm",src:"warm",phonetic:"varm",example:"A: Der Glühwein ist schön warm.\nB: Ja, perfekt für kalte Hände!",exampleSrc:"A: The mulled wine is nicely warm.\nB: Yes, perfect for cold hands!",note:"Cognate mit Englisch. Wärme = warmth.",funFact:"Glühwein auf dem Weihnachtsmarkt wird in Tassen serviert, die man als Souvenir behalten darf."},
{type:"teach",trg:"heiß",src:"hot",phonetic:"haiß",example:"A: Vorsicht, die Suppe ist heiß!\nB: Danke, ich warte kurz.",exampleSrc:"A: Careful, the soup is hot!\nB: Thanks, I'll wait a moment.",note:"Auch für Wetter: Es ist heiß draußen.",funFact:"'Heißhunger' bedeutet plötzlichen, starken Hunger. Wörtlich: heißer Hunger."},
{type:"teach",trg:"nass",src:"wet",phonetic:"nass",example:"A: Meine Schuhe sind ganz nass.\nB: Es hat den ganzen Tag geregnet.",exampleSrc:"A: My shoes are completely wet.\nB: It has rained all day.",note:"Auch: patschnass = soaking wet.",funFact:"Deutsche haben viele Wörter für nass: feucht, klamm, durchnässt, patschnass."},
{type:"teach",trg:"trocken",src:"dry",phonetic:"trokken",example:"A: Bleibt es heute trocken?\nB: Ja, kein Regen bis Freitag.",exampleSrc:"A: Will it stay dry today?\nB: Yes, no rain until Friday.",note:"Gegenteil von nass. Auch für Humor: trockener Witz.",funFact:"'Trockener Humor' ist typisch norddeutsch, besonders in Hamburg."},
{type:"teach",trg:"sonnig",src:"sunny",phonetic:"zonnich",example:"A: Wie wird das Wetter morgen?\nB: Sonnig und warm, sagt die App.",exampleSrc:"A: How will the weather be tomorrow?\nB: Sunny and warm, the app says.",note:"Von die Sonne. Suffix -ig macht Adjektive.",funFact:"Berlin hat im Durchschnitt mehr Sonnenstunden als London, aber weniger als Madrid."},
{type:"teach",trg:"windig",src:"windy",phonetic:"vindich",example:"A: Warum trägst du eine Mütze?\nB: Es ist sehr windig draußen.",exampleSrc:"A: Why are you wearing a hat?\nB: It is very windy outside.",note:"Von der Wind. Gleiche -ig Endung wie sonnig.",funFact:"An der Nordsee ist es fast immer windig. Die Friesen sagen: 'Wind ist hier Luft.'"},
{type:"teach",trg:"der Wind",src:"the wind",gender:"m",phonetic:"VINT",example:"A: Spurst du den kalten Wind?\nB: Ja, er kommt vom Fluss.\nA: Lass uns in die Hutte gehen.",exampleSrc:"A: Do you feel the cold wind?\nB: Yes, it is coming from the river.\nA: Let us go into the hut.",note:"der Wind, masculine. Plural: die Winde. Related adjective: windig (windy).",funFact:"Germany gets strong winds from the North Sea coast. The Beaufort scale is used in German weather reports: Windstarke 8 means gale force."},
{type:"teach",trg:"nebelig",src:"foggy",phonetic:"nebelich",example:"A: Ich sehe die Kirche nicht.\nB: Normal, es ist heute sehr nebelig.",exampleSrc:"A: I can't see the church.\nB: Normal, it is very foggy today.",note:"Von der Nebel (fog). Nebelig = foggy.",funFact:"Novembernebel in deutschen Flusstälern kann tagelang bleiben. Man nennt das Inversionswetterlage."},
{type:"teach",trg:"bewölkt",src:"cloudy",phonetic:"bevölkt",example:"A: Scheint die Sonne?\nB: Nein, es ist leider bewölkt.",exampleSrc:"A: Is the sun shining?\nB: No, it's unfortunately cloudy.",note:"Von die Wolke (cloud). Be- Präfix + -t Endung.",funFact:"Der deutsche Wetterbericht unterscheidet zwischen bewölkt, stark bewölkt und bedeckt."},
{type:"tip",title:"Deutsche und das Wetter",text:"Deutsche reden gern und oft übers Wetter. Es ist ein perfekter Gesprächseinstieg.\n\nTypische Fragen:\n\n'Wie ist das Wetter?' (allgemein)\n'Wie wird es morgen?' (Vorhersage)\n'Schönes Wetter heute, oder?' (Small Talk)\n\nAntworten mit 'Es ist...' + Adjektiv:\nEs ist kalt. Es ist sonnig. Es ist bewölkt.",deepDive:"Das Wort 'Wetter' kommt in vielen Zusammensetzungen vor: Wetterbericht (weather report), Wetterdienst (weather service), Wettervorhersage (forecast), wetterbeständig (weatherproof). Die Frage 'Na, wie ist das Wetter bei euch?' ist ein Standardeinstieg für Telefonate."},
{type:"mc",q:"Verumius sagt: 'Brr! Es ist heute wirklich ___.' Was fehlt?",opts:["kalt","sonnig","trocken","warm"],ans:"kalt",hint:"Brr drückt aus, dass jemandem nicht warm ist."},
{type:"fb",s:"Meine Jacke ist ganz {1} vom Regen.",a:"nass",opts:["nass","trocken","warm","heiß"],hint:"Regen macht Kleidung nicht trocken.",sSrc:"My jacket is completely {1} from the rain."},
{type:"teach",trg:"dunkel",src:"dark",phonetic:"dunkel",example:"A: Es wird schon um vier Uhr dunkel.\nB: Ja, typisch für Dezember in Deutschland.",exampleSrc:"A: It already gets dark at four o'clock.\nB: Yes, typical for December in Germany.",note:"Gegenteil: hell (bright). Die Dunkelheit = darkness.",funFact:"Im Dezember wird es in Norddeutschland schon gegen 16 Uhr dunkel."},
{type:"teach",trg:"bunt",src:"colorful",phonetic:"bunt",example:"A: Schau mal, die bunten Lichter!\nB: Der Weihnachtsmarkt sieht toll aus.",exampleSrc:"A: Look, the colorful lights!\nB: The Christmas market looks great.",note:"Bunt = viele Farben zusammen. Kunterbunt = very colorful.",funFact:"'Bunter Abend' ist ein deutscher Ausdruck für einen Abend mit verschiedenem Programm."},
{type:"teach",trg:"dick",src:"thick/fat",phonetic:"dik",example:"A: Ich brauche einen dicken Schal.\nB: Ja, am besten Wolle.",exampleSrc:"A: I need a thick scarf.\nB: Yes, wool is best.",note:"Dick = thick (für Sachen), fat (für Personen). Vorsicht beim Kontext.",funFact:"'Dicke Freunde' bedeutet sehr gute Freunde, nicht dass sie dick sind."},
{type:"teach",trg:"dünn",src:"thin",phonetic:"dünn",example:"A: Die Jacke ist zu dünn für Dezember.\nB: Du brauchst einen Wintermantel.",exampleSrc:"A: The jacket is too thin for December.\nB: You need a winter coat.",note:"Gegenteil von dick. Für Kleidung, Papier, Personen.",funFact:"'Dünnhäutig' (thin-skinned) bedeutet im Deutschen wie im Englischen: empfindlich."},
{type:"teach",trg:"eng",src:"tight/narrow",phonetic:"eng",example:"A: Die Gassen auf dem Markt sind eng.\nB: Ja, aber das macht es gemütlich.",exampleSrc:"A: The lanes at the market are narrow.\nB: Yes, but it makes it cozy.",note:"Eng = räumlich schmal oder Kleidung zu klein.",funFact:"'Enge' Beziehung ist positiv und bedeutet: eine nahe, vertraute Beziehung."},
{type:"teach",trg:"modern",src:"modern",phonetic:"modärn",example:"A: Der neue Weihnachtsmarkt ist sehr modern.\nB: Ich mag die traditionellen Märkte lieber.",exampleSrc:"A: The new Christmas market is very modern.\nB: I prefer the traditional markets.",note:"Cognate. Betont auf der zweiten Silbe: moˈdern.",funFact:"Viele Deutsche bevorzugen 'traditionell' gegenüber 'modern' beim Weihnachtsmarkt."},
{type:"teach",trg:"früh",src:"early",phonetic:"frü",example:"A: Wir müssen früh losgehen.\nB: Warum? Wann öffnet der Markt?\nA: Um elf, aber es wird schnell voll.",exampleSrc:"A: We have to leave early.\nB: Why? When does the market open?\nA: At eleven, but it gets crowded quickly.",note:"Gegenteil: spät (late). Früher = earlier / in the past.",funFact:"'Der frühe Vogel fängt den Wurm' ist das deutsche Äquivalent zu 'the early bird catches the worm.'"},
{type:"teach",trg:"einzeln",src:"individual/single",phonetic:"aintseln",example:"A: Kann ich einzelne Pralinen kaufen?\nB: Ja, fünfzig Cent pro Stück.",exampleSrc:"A: Can I buy individual chocolates?\nB: Yes, fifty cents each.",note:"Auch: ein einzelner Mensch = a single person.",funFact:"'Einzelkind' (only child) ist im Deutschen ein normales Wort, nicht negativ."},
{type:"teach",trg:"fleißig",src:"hardworking",phonetic:"flaißich",example:"A: Die Verkäufer auf dem Markt sind sehr fleißig.\nB: Ja, sie arbeiten von morgens bis abends.",exampleSrc:"A: The vendors at the market are very hardworking.\nB: Yes, they work from morning to evening.",note:"Ein typisch deutsches Kompliment. Fleiß = diligence.",funFact:"'Fleiß' ist eine der klassischen deutschen Tugenden neben Pünktlichkeit und Ordnung."},
{type:"teach",trg:"typisch",src:"typical",phonetic:"tüpisch",example:"A: Glühwein und Lebkuchen auf dem Markt.\nB: Das ist typisch deutsch!",exampleSrc:"A: Mulled wine and gingerbread at the market.\nB: That's typically German!",note:"Cognate. Typisch + für: typisch für Deutschland.",funFact:"'Typisch!' als Ausruf bedeutet oft: Das war zu erwarten. Leicht genervt."},
{type:"teach",trg:"der Enkel",src:"the grandson / grandchild",note:"Masculine noun. Plural: die Enkel.\nFeminine: die Enkelin (granddaughter). Plural: die Enkelinnen.",example:"A: Wie viele Enkel hast du, Heinrich?\nB: Drei Enkel! Hildi, Thomas und die kleine Lena.\nA: Hildi ist deine Enkelin?\nB: Ja, meine älteste Enkelin.",exampleSrc:"A: How many grandchildren do you have, Heinrich?\nB: Three grandchildren! Hildi, Thomas, and little Lena.\nA: Hildi is your granddaughter?\nB: Yes, my oldest granddaughter.",funFact:"In Germany, grandparents often live close to their grandchildren. The word 'Enkel' comes from Old High German 'eninchili' meaning 'little ancestor.' Grandchildren were seen as small versions of their grandparents."},
{type:"teach",trg:"das Feuer",src:"the fire",note:"Neuter noun. Plural: die Feuer.\nRelated: Feuerwehr (fire department), Feuerzeug (lighter).",example:"A: Schau, ein Feuer auf dem Markt!\nB: Das ist eine Feuerschale. Zum Wärmen.\nA: Stell dich ans Feuer, es ist warm.\nB: Gute Idee, meine Hände sind eiskalt.",exampleSrc:"A: Look, a fire at the market!\nB: That is a fire bowl. For warming up.\nA: Stand by the fire, it is warm.\nB: Good idea, my hands are ice cold.",funFact:"At German Christmas markets, Feuerschalen (fire bowls) are gathering spots where strangers warm their hands and chat. The Feuerwehr (fire department) literally means 'fire defense.' Feuerzeug (lighter) means 'fire thing.'"},
{type:"teach",trg:"die Decke",src:"the blanket / ceiling",note:"Feminine noun. Plural: die Decken.\nTwo meanings: (1) blanket/cover, (2) ceiling.",example:"A: Mir ist kalt.\nB: Hier, nimm eine Decke!\nA: Danke, die Decke ist so weich.\nB: Ja, das ist reine Wolle.",exampleSrc:"A: I am cold.\nB: Here, take a blanket!\nA: Thanks, the blanket is so soft.\nB: Yes, that is pure wool.",funFact:"'Decke' means both 'blanket' and 'ceiling.' 'Mir fällt die Decke auf den Kopf' (the ceiling falls on my head) is an idiom meaning 'I am going stir-crazy' from being indoors too long. 'Bettdecke' specifically means the bed blanket."},
{type:"teach",trg:"der Nebel",src:"the fog / mist",note:"Masculine noun. Plural: die Nebel.\nAdjective: nebelig (foggy).",example:"A: Ich sehe den Weihnachtsmarkt nicht.\nB: Der Nebel ist heute sehr dicht.\nA: Kann man bei Nebel laufen?\nB: Ja, aber langsam und vorsichtig.",exampleSrc:"A: I cannot see the Christmas market.\nB: The fog is very dense today.\nA: Can you walk in the fog?\nB: Yes, but slowly and carefully.",funFact:"German November is famous for 'Novembernebel' (November fog). In river valleys like the Rhine, fog can last for days. The word 'Nebel' is related to Latin 'nebula' (cloud). Astronomy borrowed it back as 'nebula.'"},
{type:"teach",trg:"das Weihnachtslied",src:"the Christmas carol",note:"Neuter noun. Compound: Weihnacht (Christmas) + Lied (song).\nPlural: die Weihnachtslieder.",example:"A: Kennst du ein deutsches Weihnachtslied?\nB: Ja! 'Stille Nacht, heilige Nacht.'\nA: Das ist ein typisches deutsches Weihnachtslied?\nB: Es kommt eigentlich aus Österreich!",exampleSrc:"A: Do you know a German Christmas carol?\nB: Yes! 'Silent Night, Holy Night.'\nA: Is that a typical German Christmas carol?\nB: It actually comes from Austria!",funFact:"'Stille Nacht' was first performed in 1818 in a church in Austria. 'O Tannenbaum' (O Christmas Tree) is probably the most famous German Weihnachtslied worldwide. German Weihnachtslieder are often played by live brass bands at Christmas markets."},
{type:"teach",trg:"die Fähigkeit",src:"the ability / skill",note:"Feminine noun. Plural: die Fähigkeiten.\nFrom 'fähig' (capable) + '-keit' (noun suffix).",example:"A: Verumius hat die Fähigkeit, schnell zu lernen.\nB: Ja, sein Deutsch wird jeden Tag besser.\nA: Sprachen lernen ist eine wichtige Fähigkeit.",exampleSrc:"A: Verumius has the ability to learn quickly.\nB: Yes, his German gets better every day.\nA: Learning languages is an important ability.",funFact:"The suffix '-keit' turns adjectives into nouns: fähig to Fähigkeit, möglich to Möglichkeit, freundlich to Freundlichkeit. Once you see this pattern, you unlock hundreds of abstract nouns in German."},
{type:"teach",trg:"trotz",src:"despite / in spite of",note:"Preposition. Takes the GENITIVE case.\ntrotz + genitive: trotz des Regens = despite the rain.",example:"A: Trotz des Schnees gehen wir auf den Markt.\nB: Natürlich! Ein bisschen Schnee stoppt uns nicht.\nA: Trotz der Kälte trinken alle Glühwein draußen.",exampleSrc:"A: Despite the snow, we are going to the market.\nB: Of course! A little snow does not stop us.\nA: Despite the cold, everyone drinks mulled wine outside.",funFact:"'Trotz' takes the genitive, which makes it a favorite word for testing German grammar. 'Trotzdem' (nevertheless) is the adverb form and extremely common in everyday speech. 'Es regnet? Ich gehe trotzdem!' (It is raining? I am going anyway!)"},
{type:"mc",q:"Es regnet seit drei Tagen. Die Straßen sind ___.",opts:["nass","trocken","sonnig","dunkel"],ans:"nass",hint:"Regen bringt Wasser auf die Straßen."},
{type:"fb",s:"Im Dezember wird es in Deutschland sehr {1}.",a:"dunkel",opts:["dunkel","sonnig","heiß","bunt"],hint:"Die Sonne geht früh unter im Winter.",sSrc:"In December it gets very {1} in Germany."},
{type:"mc",q:"'Die bunten Lichter auf dem Weihnachtsmarkt.' Was bedeutet 'bunt'?",opts:["colorful","bright","dark","single"],ans:"colorful",hint:"Denk an viele verschiedene Farben zusammen."},
{type:"fb",s:"Der Schal ist zu {1} für den Winter. Ich brauche einen dickeren.",a:"dünn",opts:["dünn","eng","modern","früh"],hint:"Das Gegenteil von dick beschreibt zu wenig Stoff.",sSrc:"The scarf is too {1} for winter. I need a thicker one."},
{type:"mc",q:"Verumius fragt: 'Wie ist das Wetter heute?' Hildi antwortet: 'Es ist ___ und kalt.'",opts:["windig","fleißig","einzeln","typisch"],ans:"windig",hint:"Welches Wort beschreibt das Wetter, nicht eine Person?"},
{type:"drag_fill",s:"Es ist {1} und {2} auf dem Weihnachtsmarkt. Ich trinke einen {3} Glühwein.",blanks:{"1":"kalt","2":"dunkel","3":"warmen"},pool:["kalt","dunkel","warmen","sonnig","dicken"],hint:"Winter, Abend, und ein Getränk gegen die Kälte.",sSrc:"It is {1} and {2} at the Christmas market. I am drinking a {3} mulled wine."},
{type:"mc",q:"'Die fleißigen Verkäufer arbeiten den ganzen Tag.' Was ist die Endung von 'fleißig' hier?",opts:["-en (Nom. Plural)","-e (keine Endung)","-es (Nom. Neutrum)","-er (Nom. Maskulin)"],ans:"-en (Nom. Plural)",hint:"Welcher Kasus und Numerus passt zu 'die Verkäufer'?"},
{type:"fb",s:"Das ist {1} für einen deutschen Weihnachtsmarkt: Glühwein, Bratwurst und Lebkuchen.",a:"typisch",opts:["typisch","einzeln","modern","eng"],hint:"Es ist normal und erwartet, also...",sSrc:"That is {1} for a German Christmas market: mulled wine, bratwurst and gingerbread."},
{type:"mc",q:"Verumius will um 9 Uhr auf den Markt. Hildi sagt: 'Das ist zu ___! Der Markt öffnet erst um 11.'",opts:["früh","spät","dunkel","kühl"],ans:"früh",hint:"9 Uhr ist vor der Öffnungszeit um 11 Uhr."},
{type:"drag_fill",s:"Im November ist es oft {1} und {2}. Man sieht die Sonne nicht durch den {3} Nebel.",blanks:{"1":"bewölkt","2":"nebelig","3":"dicken"},pool:["bewölkt","nebelig","dicken","sonnig","dünnen"],hint:"Typisches Novemberwetter: grau, feucht, und dichter Dunst.",sSrc:"In November it is often {1} and {2}. You cannot see the sun through the {3} fog."},
{type:"match",pairs:[{trg:"kalt",src:"cold"},{trg:"heiß",src:"hot"},{trg:"nass",src:"wet"},{trg:"trocken",src:"dry"},{trg:"sonnig",src:"sunny"},{trg:"windig",src:"windy"}]},
{type:"fb",s:"Die Gasse zum Weihnachtsmarkt ist sehr {1}. Wir müssen hintereinander gehen.",a:"eng",opts:["eng","dick","bunt","warm"],hint:"Es ist nicht genug Platz nebeneinander.",sSrc:"The alley to the Christmas market is very {1}. We have to walk in single file."},
{type:"mc",q:"Hildi kauft eine Praline. Sie will keine ganze Schachtel, nur eine ___.",opts:["einzelne","dicke","frühe","dunkle"],ans:"einzelne",hint:"Nur ein Stück, nicht die ganze Packung."},
{type:"drag_fill",s:"Der {1} Markt gefällt mir nicht. Ich mag die {2} Weihnachtsmärkte mit {3} Holzbuden.",blanks:{"1":"moderne","2":"traditionellen","3":"bunten"},pool:["moderne","traditionellen","bunten","einzelnen","dunklen"],hint:"Neu vs. alt, und die Hütten haben viele Farben.",sSrc:"The {1} market does not appeal to me. I prefer the {2} Christmas markets with {3} wooden stalls."}
]},

{id:"deu_r11l6",title:"Glühwein",icon:"\ud83c\udf77",xp:20,board:true,steps:[
{type:"intro",title:"Glühwein",desc:"Drei Tassen Glühwein, Dampf steigt auf, Lichterketten spiegeln sich im Wein. Heinrich erzählt Geschichten, Hildi verdreht liebevoll die Augen. Verumius ist warm und angekommen.",goals:["8 neue Adjektive und Nomen lernen","Adjektivdeklination in allen drei Fällen üben","Temporale Präpositionen, Possessive und Konjunktiv II wiederholen"]},
{type:"teach",trg:"der Gewitter",src:"thunderstorm",example:"A: Kommt heute Abend ein Gewitter?\nB: Nein, der Himmel ist klar. Perfekt für den Weihnachtsmarkt!",exampleSrc:"A: Is there a thunderstorm coming tonight?\nB: No, the sky is clear. Perfect for the Christmas market!",note:"das Gewitter (neuter). Despite der in some dialects, standard German uses das.",funFact:"German Christmas markets stay open even in light rain. Only a real Gewitter closes the stalls."},
{type:"teach",trg:"tief",src:"deep",example:"A: Der Glühwein hat einen tiefen Geschmack.\nB: Ja, mit Zimt und Nelken. Sehr lecker!",exampleSrc:"A: The mulled wine has a deep flavor.\nB: Yes, with cinnamon and cloves. Very tasty!",note:"tief: deep, low, profound. Opposite of hoch (high).",funFact:"Germans say 'tief in der Nacht' (deep in the night) for the late hours when Christmas markets finally close."},
{type:"teach",trg:"reich",src:"rich",example:"A: Heinrich kennt so viele reiche Geschichten!\nB: Ja, er hat ein reiches Leben geführt.",exampleSrc:"A: Heinrich knows so many rich stories!\nB: Yes, he has led a rich life.",note:"reich: rich (money or experience). Ein reiches Land, eine reiche Geschichte.",funFact:"The word 'Reich' originally just meant 'realm' or 'kingdom.' Frankreich (France) literally means 'realm of the Franks.'"},
{type:"teach",trg:"arm",src:"poor",example:"A: Als Kind war Heinrich arm.\nB: Aber jetzt ist er reich an Freunden.",exampleSrc:"A: As a child, Heinrich was poor.\nB: But now he is rich in friends.",note:"arm: poor. Opposite of reich. Also: der Arm (noun) = the arm (body part).",funFact:"The phrase 'arm aber glücklich' (poor but happy) is a common German saying, especially around Christmas."},
{type:"teach",trg:"bequem",src:"comfortable",example:"A: Ist dein Platz bequem?\nB: Ja, sehr! Und der Glühwein wärmt meine Hände.",exampleSrc:"A: Is your seat comfortable?\nB: Yes, very! And the mulled wine warms my hands.",note:"bequem: comfortable (seats, shoes, life). For temperature comfort, use gemütlich.",funFact:"Germans distinguish bequem (physically comfortable) from gemütlich (cozy atmosphere). A Weihnachtsmarkt is gemütlich, a chair is bequem."},
{type:"teach",trg:"hässlich",src:"ugly",example:"A: Hildi findet Heinrichs Weihnachtspullover hässlich.\nB: Aber Heinrich trägt ihn trotzdem jeden Winter!",exampleSrc:"A: Hildi finds Heinrich's Christmas sweater ugly.\nB: But Heinrich wears it every winter anyway!",note:"hässlich: ugly. Strong word. For 'not pretty,' Germans often soften with nicht so schön.",funFact:"Ugly Christmas sweaters (hässliche Weihnachtspullover) are a growing trend in Germany, borrowed from American culture."},
{type:"teach",trg:"intelligent",src:"intelligent",example:"A: Verumius ist ein intelligenter Kerl.\nB: Stimmt! Er lernt so schnell Deutsch.",exampleSrc:"A: Verumius is an intelligent guy.\nB: True! He learns German so quickly.",note:"intelligent: same as English. Note the ending changes: ein intelligenter Mann, eine intelligente Frau.",funFact:"German borrows 'intelligent' from Latin via French. The native German equivalent is klug, which feels warmer and less academic."},
{type:"teach",trg:"klug",src:"clever, smart",example:"A: Das war eine kluge Entscheidung, hierher zu kommen.\nB: Ja, der Glühwein allein war es wert!",exampleSrc:"A: That was a clever decision to come here.\nB: Yes, the mulled wine alone was worth it!",note:"klug: clever, smart, wise. More everyday than intelligent. Ein kluger Kopf = a smart cookie.",funFact:"The Brothers Grimm used 'klug' constantly in their fairy tales. Das kluge Gretel, Die kluge Else. Cleverness was the ultimate survival trait."},
{type:"tip",title:"Glühwein und Freundschaft",text:"Heinrich hebt seine Tasse: 'Auf uns drei!' Hildi lächelt. Verumius spürt etwas Warmes, und es ist nicht nur der Glühwein. Er hat eine Familie gefunden, auf seine eigene Art.\n\nTonight we review everything from this unit: adjective endings across all three cases, temporal prepositions, possessives, and Konjunktiv II. The Glühwein scene brings it all together."},
{type:"mc",q:"Heinrich erzählt eine ___ Geschichte. (reich, nominative feminine)",opts:["reiche","reicher","reiches","reichen"],ans:"reiche",hint:"Feminine nominative: eine ___e Geschichte."},
{type:"fb",s:"Der Glühwein hat einen {1} Geschmack.",a:"tiefen",opts:["tiefen","tiefer","tiefes","tiefe"],hint:"Accusative masculine: einen ___en.",sSrc:"The mulled wine has a {1} taste."},
{type:"mc",q:"Hildi sitzt auf einem ___ Stuhl. (bequem, dative masculine)",opts:["bequemen","bequemer","bequemes","bequem"],ans:"bequemen",hint:"Dative masculine after auf (location): einem ___en."},
{type:"drag_fill",s:"Heinrich war {1} Kind ein {2} Junge, aber er hatte {3} Freunde.",blanks:{"1":"als","2":"armer","3":"kluge"},pool:["als","armer","kluge","reiches","während","hässlicher"],hint:"Temporal prep + nom masc adj + acc plural adj.",sSrc:"Heinrich was {1} child a {2} boy, but he had {3} friends."},
{type:"fb",s:"Wenn ich reich {1}, würde ich jeden Tag Glühwein trinken.",a:"wäre",opts:["wäre","bin","war","sei"],hint:"Konjunktiv II of sein for unreal wishes.",sSrc:"If I {1} rich, I would drink mulled wine every day."},
{type:"mc",q:"Das ist ___ Pullover! Niemand will ihn tragen. (nominative masculine, ein-word)",opts:["ein hässlicher","einen hässlichen","einem hässlichem","einer hässlicher"],ans:"ein hässlicher",hint:"Nominative masculine with ein: ein ___er."},
{type:"drag_fill",s:"Verumius trinkt {1} Glühwein mit {2} klugen Freunden {3} dem Weihnachtsmarkt.",blanks:{"1":"seinen","2":"seinen","3":"auf"},pool:["seinen","seinen","auf","sein","seine","in"],hint:"Possessive accusative + possessive dative + location preposition.",sSrc:"Verumius drinks {1} mulled wine with {2} clever friends {3} the Christmas market."},
{type:"fb",s:"Wenn das Wetter {1} wäre, könnten wir nicht draußen sitzen.",a:"hässlich",opts:["hässlich","hässliches","hässlichen","hässlicher"],hint:"Predicate adjective after sein: no ending needed.",sSrc:"If the weather {1}, we would not be able to sit outside."},
{type:"mc",q:"Heinrich hat eine ___ Stimme. Er erzählt gern Geschichten. (tief, accusative feminine)",opts:["tiefe","tiefer","tiefes","tiefen"],ans:"tiefe",hint:"Accusative feminine: eine ___e Stimme."},
{type:"drag_fill",s:"{1} des Gewitters {2} sie gemütlich {3} dem Markt.",blanks:{"1":"Trotz","2":"saßen","3":"auf"},pool:["Trotz","saßen","auf","Wegen","standen","in"],hint:"'Despite' + genitive, then past tense of sitzen + location.",sSrc:"{1} the thunderstorm they {2} cosily {3} the market."},
{type:"fb",s:"Hätte ich {1} intelligenten Freund wie Verumius!",a:"einen",opts:["einen","einem","einer","ein"],hint:"Accusative masculine: hätte ich ___en ___en Freund.",sSrc:"If only I {1} intelligent friend like Verumius!"},
{type:"mc",q:"Die drei Freunde sitzen mit ___ warmen Tassen am Tisch. (possessive, dative plural)",opts:["ihren","ihre","ihrer","ihrem"],ans:"ihren",hint:"Dative plural possessive: mit ___en warmen Tassen."},
{type:"match",pairs:[{trg:"tief",src:"deep"},{trg:"reich",src:"rich"},{trg:"arm",src:"poor"},{trg:"bequem",src:"comfortable"},{trg:"hässlich",src:"ugly"},{trg:"klug",src:"clever"}]}
]},

{id:"deu_r11l7",title:"Weihnachtsprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Weihnachtsprüfung",desc:"Der Glühwein ist leer, die Lichter blinken, und Opa Heinrich wartet auf Antworten. Zeig, was du auf dem Weihnachtsmarkt gelernt hast. Keine neuen Wörter. Nur du und die Grammatik.",goals:["Adjektivdeklination in Nominativ, Akkusativ und Dativ","Possessivartikel in allen Fällen","Temporale Präpositionen korrekt verwenden","Konjunktiv II für Wünsche und Hypothesen"]},
{type:"mc",q:"'Der warme Glühwein schmeckt gut.' Warum endet das Adjektiv auf -e?",opts:["Nach bestimmtem Artikel im Nominativ: immer -e","Das Adjektiv zeigt das Genus mit -e","Warm ist unregelmäßig","Glühwein ist feminin"],ans:"Nach bestimmtem Artikel im Nominativ: immer -e",hint:"Definite articles in nominative make adjective endings predictable."},
{type:"fb",s:"Ein kalt{1} Wind weht über den Markt.",a:"er",opts:["er","e","es","en"],hint:"After 'ein' in nominative, what ending does the adjective need for a masculine noun?",sSrc:"A cold{1} wind blows over the market."},
{type:"mc",q:"Hildi sagt: 'Ich trage meinen dicken Mantel.' Welcher Fall ist 'meinen dicken Mantel'?",opts:["Nominativ","Akkusativ","Dativ","Genitiv"],ans:"Akkusativ",hint:"Tragen takes a direct object. Think about what case marks that."},
{type:"drag_fill",s:"Heinrich schenkt {1} Enkelin {2} goldenen Ring.",blanks:{"1":"seiner","2":"einen"},pool:["seiner","seine","seinem","einen","ein","einem"],hint:"Schenken: dative (to whom?) + accusative (what?). Enkelin is feminine, Ring is masculine.",sSrc:"Heinrich gives {1} granddaughter {2} golden ring."},
{type:"fb",s:"Verumius trinkt {1} heißen Glühwein auf dem Markt.",a:"einen",opts:["einen","ein","einem","einer"],hint:"Glühwein is masculine. Direct object means accusative case.",sSrc:"Verumius drinks {1} hot mulled wine at the market."},
{type:"mc",q:"Welches Wort zeigt den Dativ in: 'Er sitzt mit ___ warmen Pullover am Feuer'?",opts:["einem","einen","ein","einer"],ans:"einem",hint:"'Mit' always governs one specific case. Look at the article form."},
{type:"drag_fill",s:"{1} dem Essen gehen wir {2} den bunten Weihnachtsmarkt.",blanks:{"1":"Nach","2":"auf"},pool:["Nach","Vor","Seit","auf","in","an"],hint:"First eat, then go. Which temporal preposition means 'after'? And which preposition with accusative for destination?",sSrc:"{1} the meal we go {2} the colourful Christmas market."},
{type:"fb",s:"{1} drei Wochen ist der Weihnachtsmarkt geöffnet.",a:"Seit",opts:["Seit","Vor","Nach","Bis"],hint:"The market opened three weeks ago and is still open now.",sSrc:"{1} three weeks the Christmas market has been open."},
{type:"mc",q:"'Wenn ich reich wäre, würde ich jeden Tag Torte essen.' Was drückt dieser Satz aus?",opts:["Einen hypothetischen Wunsch","Eine echte Absicht","Eine Erinnerung","Einen Befehl"],ans:"Einen hypothetischen Wunsch",hint:"The speaker imagines something that is not real. Which grammatical mood fits?"},
{type:"fb",s:"Ich {1} gern eine Reise nach Wien machen.",a:"würde",opts:["würde","werde","wurde","wollte"],hint:"For polite hypothetical wishes, use Konjunktiv II of werden + infinitive.",sSrc:"I {1} like to take a trip to Vienna."},
{type:"drag_fill",s:"Hildi gibt {1} alten Mann {2} warme Decke {3} dem Fest.",blanks:{"1":"dem","2":"eine","3":"nach"},pool:["dem","den","der","eine","einen","einem","nach","vor","seit"],hint:"Dative recipient (masc.) + accusative object (fem.) + temporal preposition meaning 'after'.",sSrc:"Hildi gives {1} old man {2} warm blanket {3} the celebration."},
{type:"mc",q:"'In meinem bequemen Bett schlafe ich gut.' Welchen Fall regiert 'in' hier?",opts:["Akkusativ","Dativ","Nominativ","Genitiv"],ans:"Dativ",hint:"'In' with location (where something happens) takes a specific case. No movement involved."},
{type:"fb",s:"Die fleißig{1} Verkäufer arbeiten den ganzen Tag.",a:"en",opts:["en","e","er","es"],hint:"Nominative plural after 'die': weak declension applies.",sSrc:"The hardworking{1} vendors work all day."},
{type:"drag_fill",s:"Heinrich erzählt von {1} Kindheit {2} dem Krieg.",blanks:{"1":"seiner","2":"vor"},pool:["seiner","seinem","seine","vor","nach","seit"],hint:"'Von' takes dative. Kindheit is feminine. And which temporal preposition means 'before'?",sSrc:"Heinrich tells of {1} childhood {2} the war."},
{type:"mc",q:"'Verumius hätte gern ein warmes Bett.' Was bedeutet 'hätte'?",opts:["would have","has","had","will have"],ans:"would have",hint:"This is an irregular Konjunktiv II form derived from 'haben.'"},
{type:"fb",s:"Mit {1} neuen Mütze sieht Hildi toll aus.",a:"ihrer",opts:["ihrer","ihrem","ihren","ihre"],hint:"'Mit' takes dative. Mütze is feminine. What is the dative feminine possessive for 'her'?",sSrc:"With {1} new hat Hildi looks great."},
{type:"drag_fill",s:"Verumius {1} gern {2} roten Schal kaufen, aber er {3} nicht genug Geld.",blanks:{"1":"würde","2":"den","3":"hätte"},pool:["würde","wäre","den","dem","einen","hätte","könnte"],hint:"Konjunktiv II wish + accusative masculine definite + irregular Konjunktiv II of haben.",sSrc:"Verumius {1} like to buy {2} red scarf, but he {3} enough money."},
{type:"mc",q:"'Während des Gewitters bleiben alle in der warmen Hütte.' Was regiert 'während'?",opts:["Akkusativ","Dativ","Genitiv","Nominativ"],ans:"Genitiv",hint:"This temporal preposition is one of the few that governs a case you rarely see elsewhere."},
{type:"fb",s:"Das ist ein typisch{1} deutsches Weihnachtslied.",a:"es",opts:["es","er","e","en"],hint:"Lied is neuter. After 'ein' in nominative neuter, the adjective shows the gender.",sSrc:"That is a typical{1} German Christmas carol."},
{type:"drag_fill",s:"{1} der Ferien {2} ich gern auf {3} schönen Markt gehen.",blanks:{"1":"Während","2":"würde","3":"den"},pool:["Während","Seit","Vor","würde","werde","wurde","den","dem","der"],hint:"Temporal prep + genitive, Konjunktiv II, accusative masculine (direction).",sSrc:"{1} the holidays I {2} like to go to {3} beautiful market."},
{type:"match",pairs:[{trg:"vor dem Essen",src:"before the meal"},{trg:"nach Weihnachten",src:"after Christmas"},{trg:"seit einer Woche",src:"for a week"},{trg:"während des Fests",src:"during the festival"},{trg:"bis Freitag",src:"until Friday"},{trg:"ab morgen",src:"starting tomorrow"}]},
{type:"mc",q:"'Wenn es nicht so kalt wäre, könnten wir draußen sitzen.' Was drückt 'könnten' aus?",opts:["Eine tatsächliche Fähigkeit","Eine hypothetische Möglichkeit","Eine vergangene Fähigkeit","Einen Zukunftsplan"],ans:"Eine hypothetische Möglichkeit",hint:"The whole sentence describes an unreal condition. The verb form matches."},
{type:"drag_fill",s:"Heinrich schenkt {1} Enkelin {2} bequemen Schal und erzählt von {3} Kindheit.",blanks:{"1":"seiner","2":"einen","3":"seiner"},pool:["seiner","seiner","einen","eine","seinem","ihren"],hint:"Dative fem. possessive (to whom?) + accusative masc. (what?) + dative fem. possessive after 'von.'",sSrc:"Heinrich gives {1} granddaughter {2} comfortable scarf and tells of {3} childhood."},
{type:"fb",s:"Wenn ich Deutsch perfekt sprechen {1}, wäre das wunderbar.",a:"könnte",opts:["könnte","kann","konnte","können"],hint:"Irregular Konjunktiv II of 'können' for a hypothetical ability.",sSrc:"If I {1} speak German perfectly, that would be wonderful."},
{type:"match",pairs:[{trg:"der rote Schal",src:"the red scarf (nom.)"},{trg:"den roten Schal",src:"the red scarf (acc.)"},{trg:"dem roten Schal",src:"the red scarf (dat.)"},{trg:"ein roter Schal",src:"a red scarf (nom.)"},{trg:"einen roten Schal",src:"a red scarf (acc.)"},{trg:"einem roten Schal",src:"a red scarf (dat.)"}]}
]}
,

{id:"deu_r11l8",title:"Durch den Schnee",icon:"❄️",xp:15,board:true,steps:[
{type:"intro",title:"Durch den Schnee",desc:"Walking home through snowy Berlin after the Weihnachtsmarkt. Heinrich's bread in the bag, warmth in the heart.",goals:["Personality and character adjectives","Time expressions beyond today","Everyday verbs for learning"]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-snowy-street",trg:"Schnee auf den Straßenlaternen. Schnee auf den parkenden Autos. Schnee auf Verumius' Schultern. In der Tasche: Heinrichs Brötchen. Im Herzen: Wärme. Er geht langsam nach Hause.",src:"Snow on the streetlamps. Snow on the parked cars. Snow on Verumius's shoulders. In the bag: Heinrich's bread rolls. In the heart: warmth. He walks slowly home."},
{type:"teach",trg:"egal",src:"doesn't matter / irrelevant",note:"Das ist mir egal = I don't care. Very common.",example:"A: Willst du Tee oder Kaffee?\nB: Das ist mir egal. Beides ist gut.\nA: Dann mache ich Tee.",exampleSrc:"A: Do you want tea or coffee?\nB: I don't care. Both are fine.\nA: Then I'll make tea.",funFact:"From Latin 'aequalis' (equal). If two things are equal, neither matters more."},
{type:"teach",trg:"freiwillig",src:"voluntary",note:"Frei (free) + willig (willing). Freiwillige Feuerwehr = volunteer fire dept.",example:"A: Ist die Teilnahme freiwillig?\nB: Ja, niemand muss kommen.\nA: Gut, dann komme ich gern!",exampleSrc:"A: Is participation voluntary?\nB: Yes, nobody has to come.\nA: Good, then I'll gladly come!",funFact:"Germany has 22,000 volunteer fire departments vs only 100 professional ones."},
{type:"teach",trg:"verschieden",src:"different / various",note:"Verschiedene Leute = various people.",example:"A: Die Glühweinsorten sind ganz verschieden.\nB: Ja, mit Orange, mit Kirsche, klassisch...",exampleSrc:"A: The varieties are quite different.\nB: Yes, with orange, cherry, classic...",funFact:"Literally means 'shifted apart.' Things shifted away from each other are different."},
{type:"mc",q:"'Das ist mir egal' means:",opts:["I don't care","I am sad","I disagree","I am hungry"],ans:"I don't care",hint:"Both options are equal to you. Neither matters more."},
{type:"teach",trg:"blöd",src:"stupid / annoying",note:"Colloquial. 'Das ist blöd' = That's annoying. Milder than dumm.",example:"A: Ich habe meinen Schlüssel vergessen.\nB: Das ist blöd! Hast du einen Ersatzschlüssel?",exampleSrc:"A: I forgot my key.\nB: That's annoying! Do you have a spare?",funFact:"Originally meant 'weak-sighted' in Old German. Now mostly means 'annoying.'"},
{type:"teach",trg:"dumm",src:"dumb / stupid",note:"Stronger than blöd. Dumm wie Brot = dumb as bread.",example:"A: War das eine dumme Idee?\nB: Nein! Manchmal muss man Risiken eingehen.",exampleSrc:"A: Was that a stupid idea?\nB: No! Sometimes you have to take risks.",funFact:"'Dumm wie Brot' exists because bread just sits there doing nothing."},
{type:"teach",trg:"faul",src:"lazy",note:"Also means 'rotten' (fauler Apfel). Context decides.",example:"A: Bist du heute faul?\nB: Ja! Ich bleibe auf dem Sofa.",exampleSrc:"A: Are you lazy today?\nB: Yes! I'm staying on the sofa.",funFact:"Faulenzen on Sundays is protected by Sonntagsruhe law in Germany."},
{type:"teach",trg:"streng",src:"strict",note:"Strenge Regeln = strict rules. Hildi ist streng aber fair.",example:"A: Ist dein Chef streng?\nB: Ja, aber er ist auch fair.",exampleSrc:"A: Is your boss strict?\nB: Yes, but he is also fair.",funFact:"Being streng in Germany is often positive: it means you have standards."},
{type:"fb",s:"Hildi ist {1}, aber sie hat ein großes Herz.",a:["streng"],opts:["streng","faul","dumm","egal"],hint:"She has strict rules, but she cares deeply underneath.",sSrc:"Hildi is {1}, but she has a big heart."},
{type:"teach",trg:"deutlich",src:"clear / distinct",note:"Bitte sprechen Sie deutlich = Please speak clearly.",example:"A: Können Sie das deutlicher sagen?\nB: Natürlich. Ich wiederhole langsam.",exampleSrc:"A: Can you say that more clearly?\nB: Of course. I'll repeat slowly.",funFact:"Comes from 'deutsch' via 'diutisc' (of the people). Speaking clearly = speaking for the people."},
{type:"teach",trg:"eigen",src:"own",note:"Mein eigenes Zimmer = my own room.",example:"A: Hast du eine eigene Wohnung?\nB: Nein, nur ein eigenes Zimmer.",exampleSrc:"A: Do you have your own apartment?\nB: No, just my own room.",funFact:"Eigentum, Eigenschaft, eigenartig. 'Eigen' spawns dozens of compound words."},
{type:"mc",q:"'Sprechen Sie deutlich' asks someone to:",opts:["speak clearly","speak quietly","speak German","speak faster"],ans:"speak clearly",hint:"You want to understand every word. Clear and distinct."},
{type:"teach",trg:"damals",src:"back then / at that time",note:"Temporal adverb for the past. Damals war alles anders.",example:"A: Damals gab es kein Internet.\nB: Wirklich? Wie habt ihr kommuniziert?\nA: Mit Briefen!",exampleSrc:"A: Back then there was no internet.\nB: Really? How did you communicate?\nA: With letters!",funFact:"Heinrich says 'damals' constantly. For someone born in the 1930s, it covers a LOT of history."},
{type:"teach",trg:"übermorgen",src:"the day after tomorrow",note:"Über (beyond) + morgen (tomorrow). One word in German!",example:"A: Wann kommt das Paket?\nB: Übermorgen. Am Donnerstag.",exampleSrc:"A: When does the package arrive?\nB: Day after tomorrow. Thursday.",funFact:"German has übermorgen and vorgestern. English needs 3+ words for each."},
{type:"teach",trg:"vorgestern",src:"the day before yesterday",note:"Vor (before) + gestern (yesterday).",example:"A: Wann war das Konzert?\nB: Vorgestern. Am Dienstag.",exampleSrc:"A: When was the concert?\nB: Day before yesterday. Tuesday.",funFact:"Some dialects even have 'vorvorgestern' (3 days ago). Efficient!"},
{type:"teach",trg:"zeigen",src:"to show",note:"Regular: ich zeige, du zeigst. Zeig mal! = Show me!",example:"A: Kann ich dir etwas zeigen?\nB: Ja! Was ist es?\nA: Mein neues Bild!",exampleSrc:"A: Can I show you something?\nB: Yes! What is it?\nA: My new painting!",funFact:"Zeigefinger = index finger (literally: showing finger)."},
{type:"teach",trg:"üben",src:"to practice",note:"Regular: ich übe, du übst. Übung macht den Meister!",example:"A: Übst du jeden Tag Deutsch?\nB: Ja, mindestens eine Stunde.\nA: Übung macht den Meister!",exampleSrc:"A: Do you practice German every day?\nB: Yes, at least one hour.\nA: Practice makes perfect!",funFact:"Every German teacher says 'Übung macht den Meister.' The most-used learning proverb."},
{type:"teach",trg:"die Übung",src:"the exercise / the practice",gender:"f",example:"A: Wie wird man besser?\nB: Nur durch Übung! Übung macht den Meister.\nA: Dann übe ich jeden Tag.",exampleSrc:"A: How do you get better?\nB: Only through practice! Practice makes perfect.\nA: Then I will practice every day.",note:"die Übung, feminine. Plural: die Übungen. From the verb üben (to practice).",funFact:"The proverb 'Übung macht den Meister' (practice makes the master) is used in every German classroom, sports club, and music lesson."},
{type:"fb",s:"{1} macht den Meister!",a:["Übung"],opts:["Übung","Ordnung","Bildung","Erfahrung"],hint:"Practice makes perfect. Which word means 'practice'?",sSrc:"{1} makes perfect!"},
{type:"teach",trg:"aussprechen",src:"to pronounce",note:"Separable: ich spreche aus. Wie spricht man das aus?",example:"A: Wie spricht man 'Eichhörnchen' aus?\nB: Das ist schwer! Aich-hörn-chen.",exampleSrc:"A: How do you pronounce 'Eichhörnchen'?\nB: That's hard! Aich-hörn-chen.",funFact:"'Eichhörnchen' (squirrel) is the word Germans use to test foreigners. Nobody gets it right first time."},
{type:"drag_fill",s:"{1} war alles anders. Aber {2} haben wir Internet und Handys.",blanks:{"1":"Damals","2":"heute"},pool:["Damals","heute","Morgen","Gestern","übermorgen","vorgestern"],hint:"Back then vs now. Past contrasted with present.",sSrc:"{1} everything was different. But {2} we have the internet and mobile phones."},
{type:"teach",trg:"blond",src:"blond / fair-haired",example:"A: Hildi ist blond, oder?\nB: Ja, sie hat blonde Haare.\nA: Und Verumius?",exampleSrc:"A: Hildi is blond, right?\nB: Yes, she has blond hair.\nA: And Verumius?",note:"blond: same word as English. Endings change: blonder Mann, blonde Frau, blondes Kind.",funFact:"Germany has one of the highest percentages of natural blonds in the world, especially in the north."},
{type:"teach",trg:"einmal",src:"once / one time",example:"A: Warst du schon einmal in Wien?\nB: Ja, einmal. Es war wunderschon.\nA: Ich mochte auch einmal dorthin.",exampleSrc:"A: Have you ever been to Vienna?\nB: Yes, once. It was wonderful.\nA: I would like to go there too.",note:"einmal = once. Zweimal = twice. Dreimal = three times. Also used in 'Es war einmal...' (Once upon a time).",funFact:"Every German fairy tale starts with 'Es war einmal...' (Once upon a time). The Brothers Grimm made this opening famous worldwide."},
{type:"teach",trg:"wurscht",src:"doesn't matter (colloquial)",example:"A: Willst du Pizza oder Pasta?\nB: Das ist mir wurscht!\nA: Na gut, dann Pizza.",exampleSrc:"A: Do you want pizza or pasta?\nB: I don't care!\nA: Alright, pizza then.",note:"Colloquial southern German variant of 'egal.' Very common in Bavaria and Austria. From Wurst (sausage).",funFact:"'Das ist mir Wurst' or 'wurscht' literally means 'that is sausage to me.' Nobody knows exactly why sausage means indifference, but it has been used since the 1800s."},
{type:"match",pairs:[{trg:"egal",src:"doesn't matter"},{trg:"streng",src:"strict"},{trg:"faul",src:"lazy"},{trg:"deutlich",src:"clear"},{trg:"damals",src:"back then"},{trg:"übermorgen",src:"day after tomorrow"},{trg:"üben",src:"to practice"},{trg:"zeigen",src:"to show"}]},
{type:"tip",title:"German Christmas Traditions",text:"Weihnachten starts December 24 (Heiligabend), not December 25.\n\n- Adventskranz: 4 candles, one lit each Sunday before Christmas\n- Adventskalender: 24 doors, one per day in December\n- Nikolaus (Dec 6): shoes by the door, filled with sweets\n- Heiligabend: family dinner, gifts, church\n- Weihnachtsgans: roast goose, the traditional Christmas meal\n- Stille Nacht: world's most famous carol, written in Austria 1818",deepDive:"The Weihnachtsmarkt tradition dates to the 14th century. Dresden's Striezelmarkt (1434) is the oldest. Every city has one. Many Germans visit 5-10 different markets each season."},
{type:"mc",q:"Walking through snow, Verumius feels:",opts:["warm and content, like he belongs","cold and lonely","angry about the weather","worried about tomorrow"],ans:"warm and content, like he belongs",hint:"Heinrich's bread in his bag. Glühwein warmth in his heart."}
]}

]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 12: Halbjahresbilanz
// Story: Cafe with Yilmaz, document montage, KD's first joke, group chat
// CEFR: A2.3 - Imperative expanded, Konjunktiv II, coord conj, adverbs, A2 capstone
// ═══════════════════════════════════════════════════════════════
{n:12,lang:"de",srcLang:"en",track:"v2",title:"Halbjahresbilanz",sub:"Six months in Germany: reflection, KD's first joke, the decision to stay",icon:"🎉",level:"A2.3",color:"#7B5EE8",lessons:[
// ─── U12 L1: Im Literaturcafé ───
{id:"deu_r12l1",title:"Im Literaturcafé",icon:"☕",xp:15,board:true,steps:[
{type:"intro",title:"Im Literaturcafé",desc:"Six months in Germany. Verumius meets Yilmaz at a Berlin Literaturcafé for coffee and Kuchen. For the first time, they talk not as teacher and student, but as friends.",goals:["Express opinions and thoughts","Talk about experiences and ideas","Use abstract nouns in conversation"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-literaturcafe",trg:"Ein Literaturcafé in Prenzlauer Berg. Bücherregale an den Wänden, freiliegende Backsteine, warmes Nachmittagslicht. Yilmaz sitzt am Fenster mit einem Milchkaffee. Sie trägt keine Brille heute. Verumius kommt herein und lächelt.",src:"A literary café in Prenzlauer Berg. Bookshelves on the walls, exposed brick, warm afternoon light. Yilmaz sits at the window with a milky coffee. She is not wearing glasses today. Verumius walks in and smiles."},
{type:"story",speaker:"Verumius",trg:"Yilmaz! Schön, dich hier zu sehen. Sechs Monate in Deutschland. Ich kann es kaum glauben.",src:"Yilmaz! Nice to see you here. Six months in Germany. I can barely believe it."},
{type:"story",speaker:"Yilmaz",trg:"Sechs Monate! Und du sprichst schon so gut. Ich habe eine Frage: Was denkst du über deine Zeit hier? Ehrlich.",src:"Six months! And you already speak so well. I have a question: What do you think about your time here? Honestly."},
{type:"teach",trg:"die Meinung",src:"the opinion",note:"Feminine noun. Plural: die Meinungen.",example:"A: Was ist deine Meinung?\nB: Meiner Meinung nach ist Berlin toll.",exampleSrc:"A: What is your opinion?\nB: In my opinion, Berlin is great.",funFact:"'Meiner Meinung nach' (in my opinion) is one of the most used phrases in German debates. Germans love a well-structured opinion. The noun comes from 'meinen' (to think/mean)."},
{type:"teach",trg:"die Idee",src:"the idea",note:"Feminine noun. Plural: die Ideen. From French/Latin.",example:"A: Ich habe eine Idee!\nB: Wirklich? Erzähl mal!",exampleSrc:"A: I have an idea!\nB: Really? Tell me!",funFact:"German borrowed 'Idee' from French, which got it from Latin, which got it from Greek 'idea' (form, pattern). The word traveled 2,500 years through four languages to reach your vocabulary list."},
{type:"teach",trg:"die Geschichte",src:"the story / history",note:"Feminine noun. Plural: die Geschichten. Both meanings common.",example:"A: Kennst du die Geschichte von Berlin?\nB: Ja, es ist eine lange Geschichte!",exampleSrc:"A: Do you know the history of Berlin?\nB: Yes, it's a long story!",funFact:"In German, 'story' and 'history' are the same word. Context decides. 'Eine lustige Geschichte' = a funny story. 'Die deutsche Geschichte' = German history. Every story IS history, in a way."},
{type:"teach",trg:"die Erfahrung",src:"the experience",note:"Feminine noun. Plural: die Erfahrungen. From 'erfahren' (to experience).",example:"A: Hast du Erfahrung mit Kochen?\nB: Ja, ich habe viel Erfahrung.",exampleSrc:"A: Do you have experience with cooking?\nB: Yes, I have a lot of experience.",funFact:"'Erfahrung' comes from 'fahren' (to travel). Originally, experience was what you gained by TRAVELING. You had to leave home to learn something new. The word still carries that spirit."},
{type:"mc",q:"Yilmaz asks 'Was ist deine Meinung?' What does she want to know?",opts:["Your name","Your opinion","Your address","Your age"],ans:"Your opinion",hint:"She is asking what you think about something."},
{type:"fb",s:"Das war eine tolle {1}!",a:["Erfahrung"],opts:["Erfahrung","Meinung","Qualität","Nachricht"],hint:"Which feminine noun means an experience you lived through?",sSrc:"That was a great {1}!"},
{type:"teach",trg:"die Situation",src:"the situation",note:"Feminine noun. Plural: die Situationen. Same as English.",example:"A: Wie ist die Situation?\nB: Die Situation ist kompliziert.",exampleSrc:"A: How is the situation?\nB: The situation is complicated.",funFact:"A perfect cognate. Same spelling, same meaning, just different pronunciation. German stresses the last syllable: Si-tu-a-TION. Most Latin-origin words ending in '-tion' work the same in German."},
{type:"teach",trg:"die Qualität",src:"the quality",note:"Feminine noun. Plural: die Qualitäten.",example:"A: Wie ist die Qualität?\nB: Die Qualität ist sehr gut.",exampleSrc:"A: How is the quality?\nB: The quality is very good.",funFact:"Another Latin import. Notice the umlaut: Qualität, not Qualitat. German adds umlauts to borrowed words like a passport stamp. Universität, Nationalität, Realität. The '-tät' ending always means feminine."},
{type:"teach",trg:"die Person",src:"the person",note:"Feminine noun. Plural: die Personen. Always feminine, even for men.",example:"A: Wer ist diese Person?\nB: Das ist eine wichtige Person.",exampleSrc:"A: Who is this person?\nB: That is an important person.",funFact:"Grammatical gender and real gender are different things. 'Die Person' is feminine even when talking about a man. 'Das Mädchen' (the girl) is NEUTER. German grammar follows word endings, not biology."},
{type:"mc",q:"All these nouns share something. Which article do they use: die Meinung, die Idee, die Geschichte, die Erfahrung?",opts:["der (masculine)","die (feminine)","das (neuter)","ein (indefinite)"],ans:"die (feminine)",hint:"Look at the article that appears before each noun."},
{type:"story",speaker:"Verumius",trg:"Ich denke, diese sechs Monate waren die beste Erfahrung meines Lebens. Ich hoffe, dass es so weitergeht.",src:"I think these six months were the best experience of my life. I hope it continues like this."},
{type:"teach",trg:"die Nachricht",src:"the news / message",note:"Feminine noun. Plural: die Nachrichten. TV news: die Nachrichten.",example:"A: Hast du die Nachricht gelesen?\nB: Ja, das sind gute Nachrichten!",exampleSrc:"A: Did you read the message?\nB: Yes, that is good news!",funFact:"'Nachricht' literally means 'something to direct yourself after' (nach + richten). The plural 'Nachrichten' is used for TV news. 'Die Tagesschau' is Germany's most watched Nachrichtensendung (news program)."},
{type:"teach",trg:"das Interview",src:"the interview",note:"Neuter noun. Plural: die Interviews. Borrowed from English.",example:"A: Ich habe morgen ein Interview.\nB: Viel Glück! Du schaffst das.",exampleSrc:"A: I have an interview tomorrow.\nB: Good luck! You can do it.",funFact:"One of many English words in modern German. Germans also use 'der Job,' 'das Meeting,' 'der Computer.' But watch out: 'das Handy' means mobile phone, NOT handy. That is a false friend!"},
{type:"teach",trg:"schön",src:"beautiful / nice",example:"A: Die Stadt ist wirklich schön!\nB: Ja, besonders im Winter.\nA: Schön, dass wir hier sind.",exampleSrc:"A: The city is really beautiful!\nB: Yes, especially in winter.\nA: Nice that we are here.",note:"schön: beautiful, nice, lovely. Also used as a filler: 'Schön!' (Great!). Comparative: schöner, superlative: am schönsten.",funFact:"Germans use 'schön' constantly: schönes Wetter, schöne Grüße, schön gemacht, na schön. It is one of the most versatile adjectives in German."},
{type:"teach",trg:"hoffen",src:"to hope",note:"Regular verb: ich hoffe, du hoffst, er hofft.",example:"A: Ich hoffe, ob alles gut wird.\nB: Ich hoffe es auch!",exampleSrc:"A: I hope everything will be fine.\nB: I hope so too!",funFact:"'Hoffen' and English 'hope' are related through Germanic roots. 'Ich hoffe auf besseres Wetter' (I hope for better weather). Germans hope 'auf' (on/for) things, not just hope them."},
{type:"teach",trg:"denken",src:"to think",note:"Irregular past, but regular present: ich denke, du denkst.",example:"A: Was denkst du?\nB: Ich denke, das ist eine gute Idee.",exampleSrc:"A: What do you think?\nB: I think that is a good idea.",funFact:"'Denken' and English 'think' come from the same root. And remember 'Danke' (thank you)? Same family! Thinking and thanking were once the same concept: keeping something in mind."},
{type:"teach",trg:"meinen",src:"to mean / to think (opinion)",note:"Used for personal opinions: 'Ich meine, dass...'",example:"A: Was meinst du damit?\nB: Ich meine, wir sollten gehen.",exampleSrc:"A: What do you mean by that?\nB: I mean, we should go.",funFact:"'Meinen' and 'die Meinung' are a family. But careful: 'meinen' is softer than 'denken.' 'Ich denke' = I think (after reflection). 'Ich meine' = I reckon/believe (more casual opinion)."},
{type:"mc",q:"Verumius sagt: 'Ich hoffe, dass es so weitergeht.' What does he express?",opts:["A complaint about Germany","A wish that things continue well","A question about the future","A fear of going home"],ans:"A wish that things continue well",hint:"The verb 'hoffen' expresses positive expectation about what comes next."},
{type:"fb",s:"Was {1} du über Berlin?",a:["denkst"],opts:["denkst","hoffst","meinst","sagst"],hint:"Which verb asks what someone thinks after reflection?",sSrc:"What do you {1} about Berlin?"},
{type:"tip",title:"Literaturcafés: Germany's Living Rooms",text:"Germany has a deep café culture. A Literaturcafé combines coffee with books and often hosts readings.\n\nKey vocabulary:\nder Milchkaffee: milky coffee\nder Kuchen: cake\ndie Lesung: a reading event\ndie Buchhandlung: bookshop\n\nIn German cafés, you can sit for hours with one coffee. Nobody will rush you. It is your living room away from home."},
{type:"mc",q:"'Die Qualität ist sehr gut.' What is being described?",opts:["The price","The quality","The quantity","The person"],ans:"The quality",hint:"This feminine cognate looks almost the same in English."},
{type:"fb",s:"Hast du die {1} im Radio gehört?",a:["Nachricht"],opts:["Nachricht","Geschichte","Meinung","Idee"],hint:"Which word means a news item or message you receive?",sSrc:"Did you hear the {1} on the radio?"},
{type:"mc",q:"Which sentence correctly uses 'meinen' to express an opinion?",opts:["Ich meine, das Café ist schön.","Ich meine nach Berlin.","Ich meine einen Kaffee.","Ich meine um drei Uhr."],ans:"Ich meine, das Café ist schön.",hint:"This verb introduces a personal opinion or belief."},
{type:"match",pairs:[{trg:"die Meinung",src:"the opinion"},{trg:"die Erfahrung",src:"the experience"},{trg:"die Nachricht",src:"the news/message"},{trg:"hoffen",src:"to hope"},{trg:"denken",src:"to think"},{trg:"meinen",src:"to mean/think (opinion)"}]},
{type:"drag_fill",s:"Ich {1}, dass du eine gute {2} hast. {3} Meinung nach ist das eine tolle {4}.",blanks:{"1":"denke","2":"Idee","3":"Meiner","4":"Erfahrung"},pool:["denke","Idee","Meiner","Erfahrung","hoffe","Geschichte","Seiner","Qualität"],hint:"Build a sentence combining thinking, ideas, opinions, and experiences.",sSrc:"I {1} that you have a good {2}. In {3} opinion that is a great {4}."}
]}
,

{id:"deu_r12l2",title:"Papierkram",icon:"📄",xp:15,board:true,steps:[
{type:"intro",title:"Papierkram",desc:"Work, admin, and tech vocabulary for everyday German life. From job applications to passwords, this is the language of getting things done.",goals:["Learn 16 work/admin/tech nouns","Use time adverbs: schon, noch, erst, gerade","Talk about office life and digital tools"]},
{type:"teach",trg:"die Bewerbung",src:"application (job)",phonetic:"beh-VEHR-boong",example:"A: Hast du die Bewerbung schon geschickt?\nB: Nein, ich schreibe sie heute Abend.",exampleSrc:"A: Have you already sent the application?\nB: No, I'm writing it tonight.",note:"From 'bewerben' (to apply). Always die.",funFact:"Germans often include a professional photo with job applications. It is still common practice."},
{type:"teach",trg:"die Ausbildung",src:"training, apprenticeship",phonetic:"OWS-bil-doong",example:"A: Was macht dein Bruder?\nB: Er macht eine Ausbildung als Koch.",exampleSrc:"A: What does your brother do?\nB: He is doing an apprenticeship as a cook.",note:"Aus (out) + Bildung (education). Always die.",funFact:"Germany's dual Ausbildung system combines school and on-the-job training. Over 300 recognized trades use it."},
{type:"teach",trg:"das Büro",src:"office",phonetic:"bue-ROH",example:"A: Wo arbeitest du?\nB: Ich arbeite in einem Büro in der Stadt.",exampleSrc:"A: Where do you work?\nB: I work in an office in the city.",note:"From French 'bureau'. Always das.",funFact:"Many German offices still close doors between rooms. An open door signals you are available for a chat."},
{type:"teach",trg:"das Gehalt",src:"salary",phonetic:"geh-HALT",example:"A: Bist du zufrieden mit dem Gehalt?\nB: Ja, es ist ganz okay.",exampleSrc:"A: Are you happy with the salary?\nB: Yes, it's quite okay.",note:"Always das. Plural: die Gehälter.",funFact:"In Germany, talking about your salary with colleagues is considered very impolite. Many people never share the number."},
{type:"teach",trg:"der Vertrag",src:"contract",phonetic:"fehr-TRAHK",example:"A: Hast du den Vertrag schon unterschrieben?\nB: Noch nicht, ich lese ihn erst morgen.",exampleSrc:"A: Have you already signed the contract?\nB: Not yet, I'll read it tomorrow first.",note:"Always der. Plural: die Verträge.",funFact:"Germans love contracts. Even a gym membership comes with a detailed Vertrag, often with a long cancellation period."},
{type:"teach",trg:"die Übersetzung",src:"translation",phonetic:"ue-ber-ZET-soong",example:"A: Kannst du die Übersetzung prüfen?\nB: Klar, schick mir die Datei.",exampleSrc:"A: Can you check the translation?\nB: Sure, send me the file.",note:"From 'übersetzen' (to translate). Always die.",funFact:"German compound words are famously hard to translate. Schadenfreude and Wanderlust have been borrowed into English directly."},
{type:"teach",trg:"das Zeugnis",src:"certificate, report card",phonetic:"TSOYG-nis",example:"A: Brauchst du das Zeugnis für die Bewerbung?\nB: Ja, ich muss es kopieren.",exampleSrc:"A: Do you need the certificate for the application?\nB: Yes, I have to copy it.",note:"Always das. Plural: die Zeugnisse.",funFact:"When you leave a German job, you receive a coded Arbeitszeugnis. Phrases like 'stets bemüht' (always tried hard) actually mean poor performance."},
{type:"teach",trg:"der Artikel",src:"article",phonetic:"ar-TEE-kel",example:"A: Hast du den Artikel gelesen?\nB: Welchen Artikel meinst du?",exampleSrc:"A: Have you read the article?\nB: Which article do you mean?",note:"Always der. Also means grammatical article (der/die/das).",funFact:"The word Artikel is used both for newspaper articles and grammar articles. Context always makes the meaning clear."},
{type:"teach",trg:"das Blatt",src:"sheet (of paper), leaf",phonetic:"BLAHT",example:"A: Ich brauche ein Blatt Papier.\nB: Hier, nimm eins von meinem Block.",exampleSrc:"A: I need a sheet of paper.\nB: Here, take one from my notepad.",note:"Always das. Plural: die Blätter. Two meanings: paper and leaf.",funFact:"The expression 'kein Blatt vor den Mund nehmen' means to speak bluntly, literally 'to put no leaf in front of your mouth'."},
{type:"teach",trg:"die Datei",src:"file (digital)",phonetic:"dah-TY",example:"A: Wo ist die Datei?\nB: Ich habe sie dir per Mail geschickt.",exampleSrc:"A: Where is the file?\nB: I sent it to you by email.",note:"Always die. Only for digital files, not paper folders.",funFact:"German IT vocabulary mixes English loans (der Link, das Update) with German creations (die Datei from 'Daten' meaning data)."},
{type:"teach",trg:"die Homepage",src:"homepage",phonetic:"HOHM-paydsh",example:"A: Hast du unsere neue Homepage gesehen?\nB: Ja, sie sieht sehr gut aus!",exampleSrc:"A: Have you seen our new homepage?\nB: Yes, it looks very good!",note:"English loanword. Always die.",funFact:"Germans often say Homepage when they mean the entire website, not just the landing page. Die Webseite is the more precise term."},
{type:"teach",trg:"der Link",src:"link",phonetic:"LINK",example:"A: Kannst du mir den Link schicken?\nB: Klar, ich schicke ihn dir gerade.",exampleSrc:"A: Can you send me the link?\nB: Sure, I'm sending it to you right now.",note:"English loanword. Always der.",funFact:"Despite many English tech loanwords, official German tries to use native terms. Der Verweis exists but der Link won the everyday battle."},
{type:"teach",trg:"die Mail",src:"email",phonetic:"MAYL",example:"A: Hast du meine Mail bekommen?\nB: Ja, ich antworte gleich.",exampleSrc:"A: Did you get my email?\nB: Yes, I'll reply shortly.",note:"Short for die E-Mail. Always die.",funFact:"Germans often write very formal emails, even internally. Starting with 'Sehr geehrte Damen und Herren' (Dear ladies and gentlemen) is standard for unknown recipients."},
{type:"teach",trg:"die Mailbox",src:"mailbox (voicemail)",phonetic:"MAYL-boks",example:"A: Ich habe angerufen, aber nur die Mailbox gehört.\nB: Tut mir leid, mein Mobiltelefon war aus.",exampleSrc:"A: I called but only got the voicemail.\nB: Sorry, my mobile phone was off.",note:"In German, Mailbox usually means voicemail, not a physical letterbox.",funFact:"The physical letterbox is der Briefkasten in German. Die Mailbox almost always means voicemail on the phone."},
{type:"teach",trg:"das Mobiltelefon",src:"mobile phone",phonetic:"mo-BEEL-teh-leh-fohn",example:"A: Wo ist dein Mobiltelefon?\nB: Es liegt noch im Büro.",exampleSrc:"A: Where is your mobile phone?\nB: It's still in the office.",note:"Always das. Everyday speech: das Handy.",funFact:"Germans say 'Handy' for mobile phone, an English-sounding word that English speakers never use. It confuses many visitors."},
{type:"teach",trg:"das Passwort",src:"password",phonetic:"PAHS-vort",example:"A: Ich habe mein Passwort vergessen.\nB: Du kannst es auf der Homepage zurücksetzen.",exampleSrc:"A: I forgot my password.\nB: You can reset it on the homepage.",note:"Always das. Plural: die Passwörter.",funFact:"The German Federal Office for IT Security recommends passwords of at least 8 characters. They publish guidelines every year."},
{type:"tip",title:"Zeitadverbien: schon, noch, erst, gerade",text:"German has four key time adverbs that add precision:\n\n• schon (already): Ich habe schon gegessen.\n• noch (still/yet): Er arbeitet noch.\n• erst (only just/not until): Sie kommt erst um neun.\n• gerade (right now/just): Ich lese gerade die Mail.\n\nThese go after the conjugated verb in main clauses. They change the feel of a sentence completely.",deepDive:"schon vs. erst are a natural pair.\nschon = earlier than expected: 'Du bist schon da!' (You're here already!)\nerst = later than expected: 'Du bist erst da?' (You're only here now?)\n\nnoch vs. schon are another pair.\nnoch nicht = not yet: 'Ich habe noch nicht gegessen.' (I haven't eaten yet.)\nschon = already done: 'Ich habe schon gegessen.' (I've already eaten.)\n\ngerade = happening at this exact moment: 'Was machst du gerade?' (What are you doing right now?)"},
{type:"mc",q:"'Ich habe mein ___ vergessen.' Was fehlt?",opts:["Passwort","Gehalt","Vertrag","Ausbildung"],ans:"Passwort",hint:"You forgot something you need to log in."},
{type:"fb",s:"Die {1} liegt auf deinem Schreibtisch.",a:"Bewerbung",opts:["Bewerbung","Gehalt","Link","Passwort"],hint:"A document you send when applying for a job.",sSrc:"The {1} is on your desk."},
{type:"mc",q:"Was bedeutet 'die Datei'?",opts:["a digital file","a paper folder","an office desk","a mailbox"],ans:"a digital file",hint:"Think about what you store on a computer."},
{type:"fb",s:"Hast du den Vertrag {1} unterschrieben?",a:"schon",opts:["schon","noch","gerade","erst"],hint:"The speaker expects it might be done already.",sSrc:"Have you {1} signed the contract?"},
{type:"mc",q:"'Er macht eine Ausbildung als Koch.' Was macht er?",opts:["He is doing an apprenticeship as a cook","He is cooking at the office","He is writing a contract","He is reading an article"],ans:"He is doing an apprenticeship as a cook",hint:"Ausbildung combines learning at school and on the job."},
{type:"fb",s:"Ich lese {1} die Mail von meinem Chef.",a:"gerade",opts:["gerade","schon","erst","noch"],hint:"This adverb means 'right now, at this moment'.",sSrc:"I am reading {1} the email from my boss."},
{type:"match",pairs:[{trg:"das Büro",src:"office"},{trg:"das Gehalt",src:"salary"},{trg:"das Zeugnis",src:"certificate"},{trg:"das Blatt",src:"sheet/leaf"},{trg:"die Übersetzung",src:"translation"}]},
{type:"mc",q:"'Die Mailbox' bedeutet auf Deutsch meistens...",opts:["voicemail","physical letterbox","email inbox","homepage"],ans:"voicemail",hint:"Not a box you find on the street. Think phone."},
{type:"fb",s:"Kannst du mir den {1} per Mail schicken?",a:"Link",opts:["Link","Blatt","Büro","Gehalt"],hint:"A clickable address that takes you to a website.",sSrc:"Can you send me the {1} by email?"},
{type:"drag_fill",s:"Sie kommt {1} um neun, aber er ist {2} da.",blanks:{"1":"erst","2":"schon"},pool:["erst","schon","noch","gerade"],hint:"She arrives later than expected, he arrived earlier than expected.",sSrc:"She is {1} coming at nine, but he is {2} there."},
{type:"mc",q:"Welches Wort passt? 'Ich brauche ein ___ Papier.'",opts:["Blatt","Datei","Homepage","Mailbox"],ans:"Blatt",hint:"A physical piece you can write on with a pen."},
{type:"fb",s:"Er arbeitet {1} im Büro. Er kommt um acht nach Hause.",a:"noch",opts:["noch","schon","erst","gerade"],hint:"He is still there and has not left yet.",sSrc:"He is {1} working in the office. He comes home at eight."},
{type:"mc",q:"Was braucht man für eine Bewerbung in Deutschland oft?",opts:["ein Zeugnis","ein Passwort","eine Homepage","eine Mailbox"],ans:"ein Zeugnis",hint:"An official document proving your qualifications."},
{type:"drag_fill",s:"Ich habe die {1} schon auf die {2} hochgeladen.",blanks:{"1":"Datei","2":"Homepage"},pool:["Datei","Homepage","Mailbox","Vertrag"],hint:"A digital file goes onto a website.",sSrc:"I have already uploaded the {1} to the {2}."},
{type:"fb",s:"Das {1} ist zu niedrig, sagt er.",a:"Gehalt",opts:["Gehalt","Büro","Blatt","Zeugnis"],hint:"The amount of money you earn each month at work.",sSrc:"The {1} is too low, he says."},
{type:"match",pairs:[{trg:"die Mail",src:"email"},{trg:"der Link",src:"link"},{trg:"die Datei",src:"file (digital)"},{trg:"die Homepage",src:"homepage"},{trg:"das Mobiltelefon",src:"mobile phone"}]},
{type:"teach",trg:"geduldig",src:"patient (adjective)",note:"Geduld (patience) + -ig. Sei geduldig! = Be patient!",example:"A: Wann kommt das Ergebnis?\nB: Nächste Woche. Sei geduldig!\nA: Ich versuche es!",exampleSrc:"A: When does the result come?\nB: Next week. Be patient!\nA: I'm trying!",funFact:"Geduld comes from 'dulden' (to endure). A patient person is one who can endure waiting. The medical 'Patient' shares the same Latin root."}
]},

// U12 L3: Rückblick - Story dev + grammar (conjunctions + adverb categories)
{id:"deu_r12l3",title:"Rückblick",icon:"\uD83D\uDD19",xp:15,board:true,steps:[
{type:"intro",title:"Rückblick",desc:"Verumius spreads his German documents across the kitchen table: Mietvertrag, Krankenversicherung, Steuernummer, Anmeldung, GEZ. Six months in Germany. Time to connect the dots.",goals:["Learn 12 new vocabulary words for daily life","Master coordinating conjunctions (ADUSO)","Categorize adverbs by time, place, and manner"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-kitchen-documents",trg:"Verumius sitzt am Küchentisch. Vor ihm liegen Papiere: der Mietvertrag, die Krankenversicherung, die Steuernummer, die Anmeldung, der GEZ-Brief. Er nimmt einen Stift und macht Notizen.",src:"Verumius sits at the kitchen table. In front of him lie papers: the rental contract, the health insurance, the tax number, the registration, the GEZ letter. He picks up a pen and makes notes."},
{type:"teach",trg:"der Kontakt",src:"the contact",note:"Masculine noun. Plural: die Kontakte. Used for people and connections.",example:"A: Hast du den Kontakt von der Vermieterin?\nB: Ja, ich habe ihre Nummer.",exampleSrc:"A: Do you have the landlady's contact?\nB: Yes, I have her number.",funFact:"Germans distinguish 'Kontakt' (a connection you maintain) from 'Bekanntschaft' (an acquaintance). Having someone's number makes them a Kontakt."},
{type:"teach",trg:"der Mitarbeiter",src:"the colleague / coworker",note:"Masculine. Feminine: die Mitarbeiterin. Literally: with-worker.",example:"A: Wer ist das?\nB: Das ist mein Mitarbeiter aus dem Büro.",exampleSrc:"A: Who is that?\nB: That is my colleague from the office.",funFact:"'Mit' (with) + 'Arbeiter' (worker) = someone who works with you. German builds job titles this way: Mitbewohner (roommate) = with-resident, Mitschüler (classmate) = with-pupil."},
{type:"teach",trg:"der Kredit",src:"the credit / loan",note:"Masculine noun. Plural: die Kredite. From Latin 'creditum.'",example:"A: Brauchst du einen Kredit für die Wohnung?\nB: Nein, ich habe genug gespart.",exampleSrc:"A: Do you need a loan for the apartment?\nB: No, I saved enough.",funFact:"In Germany, paying cash is still very common. Many restaurants and small shops do not accept cards. Germans say 'Nur Bargeld' (cash only) more than you would expect."},
{type:"teach",trg:"die Kenntnis",src:"the knowledge / skill",note:"Feminine noun. Plural: die Kenntnisse. Often used in job ads.",example:"A: Welche Kenntnisse brauchst du für den Job?\nB: Man braucht gute Deutschkenntnisse.",exampleSrc:"A: What skills do you need for the job?\nB: You need good German language skills.",funFact:"Job ads in Germany love the word 'Kenntnisse.' 'Deutschkenntnisse' (German skills), 'EDV-Kenntnisse' (computer skills), 'Fachkenntnisse' (specialist knowledge). Compound it and conquer the job market."},
{type:"mc",q:"What does 'die Kenntnis' mean?",opts:["the contact","the knowledge","the loan","the note"],ans:"the knowledge",hint:"This feminine noun appears constantly in German job advertisements."},
{type:"teach",trg:"die Notiz",src:"the note",note:"Feminine noun. Plural: die Notizen. From Latin 'notitia.'",example:"A: Schreibst du eine Notiz?\nB: Ja, ich schreibe alles auf einen Zettel.",exampleSrc:"A: Are you writing a note?\nB: Yes, I'm writing everything on a slip of paper.",funFact:"Germans are famous for their love of written notes. 'Sich Notizen machen' (to take notes) is practically a national hobby. Meetings without Notizen? Unthinkable."},
{type:"teach",trg:"der Stift",src:"the pen / pencil",note:"Masculine noun. Plural: die Stifte. Covers both pens and pencils.",example:"A: Hast du einen Stift?\nB: Ja, hier ist ein Kugelschreiber.",exampleSrc:"A: Do you have a pen?\nB: Yes, here is a ballpoint pen.",funFact:"'Stift' is the generic word. A 'Kugelschreiber' (ball-writer) is a ballpoint pen, a 'Bleistift' (lead-stick) is a pencil, and a 'Filzstift' (felt-stick) is a marker. Germans name their writing tools precisely."},
{type:"teach",trg:"die Tafel",src:"the board / blackboard",note:"Feminine noun. Plural: die Tafeln. Also means a bar of chocolate!",example:"A: Der Lehrer schreibt an die Tafel.\nB: Ich kann es nicht lesen.",exampleSrc:"A: The teacher writes on the board.\nB: I can't read it.",funFact:"'Eine Tafel Schokolade' means a bar of chocolate. Same word, completely different thing. Context saves you: classroom = board, supermarket = chocolate bar."},
{type:"teach",trg:"der Zettel",src:"the slip of paper / note",note:"Masculine noun. Plural: die Zettel. Smaller than a Notiz.",example:"A: Was steht auf dem Zettel?\nB: Die Telefonnummer vom Vermieter.",exampleSrc:"A: What's on the slip of paper?\nB: The landlord's phone number.",funFact:"Germans leave 'Zettel' everywhere: on doors ('Bitte klingeln'), on shared fridges ('Das ist MEIN Joghurt!'), on car windshields ('Sie parken falsch!'). The Zettel is Germany's passive-aggressive weapon of choice."},
{type:"mc",q:"Verumius picks up 'einen Stift' and writes on 'einen Zettel.' What is he doing?",opts:["Picking up a pen and writing on a slip of paper","Picking up a book and reading a letter","Picking up a board and drawing a picture","Picking up a note and folding it"],ans:"Picking up a pen and writing on a slip of paper",hint:"Think about which items are small enough to hold and write on."},
{type:"teach",trg:"die Zahl",src:"the number",note:"Feminine noun. Plural: die Zahlen. Related to 'zahlen' (to pay).",example:"A: Was ist deine Telefonnummer?\nB: Die Zahl ist 030 555 1234.",exampleSrc:"A: What is your phone number?\nB: The number is 030 555 1234.",funFact:"'Zahl' (number) and 'zahlen' (to pay) share a root. In medieval markets, you literally 'counted out' your coins. Paying was counting."},
{type:"teach",trg:"das Stück",src:"the piece / item",note:"Neuter noun. Plural: die Stücke. Very versatile counter word.",example:"A: Wie viele Stücke Kuchen möchtest du?\nB: Zwei Stück, bitte.",exampleSrc:"A: How many pieces of cake would you like?\nB: Two pieces, please.",funFact:"'Stück' appears in dozens of compounds: Frühstück (breakfast, literally 'early-piece'), Theaterstück (play), Musikstück (musical piece), Meisterstück (masterpiece). The humble 'piece' builds grand things."},
{type:"teach",trg:"reden",src:"to talk / to speak",note:"Regular verb. Similar to 'sprechen' but more casual, conversational.",example:"A: Worüber redet ihr?\nB: Wir reden über die Arbeit.",exampleSrc:"A: What are you talking about?\nB: We are talking about work.",funFact:"'Reden' is chatting. 'Sprechen' is speaking. You 'sprichst' a language, but you 'redest' with your friends. A 'Rede' is a formal speech, ironically from the casual verb."},
{type:"teach",trg:"rechnen",src:"to calculate / to do math",note:"Regular verb. 'Rechnen mit' = to expect, to count on.",example:"A: Kannst du gut rechnen?\nB: Ja, ich rechne gern mit Zahlen.",exampleSrc:"A: Can you calculate well?\nB: Yes, I like working with numbers.",funFact:"'Rechnen mit' has a sneaky second meaning: 'to expect.' 'Ich rechne mit Regen' = I expect rain. You are literally 'calculating' the probability in your head."},
{type:"teach",trg:"die Adresse",src:"the address",note:"Feminine noun. Plural: die Adressen. Borrowed from French.",example:"A: Was ist deine Adresse?\nB: Schillerstraße 12, 10625 Berlin.\nA: Und die E-Mail-Adresse?\nB: verumius@email.de",exampleSrc:"A: What is your address?\nB: Schillerstraße 12, 10625 Berlin.\nA: And the email address?\nB: verumius@email.de",funFact:"German addresses follow a specific format: street name + house number, then postal code + city. The postal code (Postleitzahl) always has 5 digits. Berlin codes start with 1, Munich with 8. You need your Adresse for everything: bank, Anmeldung, insurance, doctors."},
{type:"teach",trg:"das Gymnasium",src:"the grammar school / high school (academic track)",note:"Neuter noun. Plural: die Gymnasien.\nNOT a gym for sports! That is die Turnhalle.",example:"A: Wo hat Mia die Schule besucht?\nB: Auf einem Gymnasium in München.\nA: Was ist ein Gymnasium?\nB: Eine Schule, die zum Abitur führt.",exampleSrc:"A: Where did Mia go to school?\nB: At a Gymnasium in Munich.\nA: What is a Gymnasium?\nB: A school that leads to the Abitur exam.",funFact:"The German school system splits children at age 10 into three tracks: Hauptschule (basic), Realschule (intermediate), and Gymnasium (academic). Only Gymnasium leads to the Abitur, which you need for university. 'Gymnasium' comes from Greek 'gymnasion' (place of exercise), but in German it means brain exercise, not body exercise!"},
{type:"teach",trg:"der Hafen",src:"the harbor / port",note:"Masculine noun. Plural: die Häfen (note the umlaut!).\nHamburg has the biggest Hafen in Germany.",example:"A: Der Hamburger Hafen ist riesig!\nB: Ja, er ist der drittgrößte Hafen in Europa.\nA: Kann man den Hafen besichtigen?\nB: Natürlich! Es gibt sogar Hafenrundfahrten.",exampleSrc:"A: The Hamburg harbor is enormous!\nB: Yes, it is the third largest port in Europe.\nA: Can you visit the harbor?\nB: Of course! There are even harbor tours.",funFact:"The Hamburg Hafen celebrated its birthday every May with the 'Hafengeburtstag,' the world's largest port festival. Over a million visitors watch tall ships, fireworks, and tugboat ballets. 'Flughafen' (airport) is literally 'flight harbor.'"},
{type:"teach",trg:"der Unterricht",src:"the lesson / class / instruction",note:"Masculine noun. No common plural.\nUsed for school lessons and any kind of formal instruction.",example:"A: Wann beginnt der Unterricht?\nB: Um acht Uhr. Sei pünktlich!\nA: Was für Unterricht hast du heute?\nB: Deutsch und Mathematik.",exampleSrc:"A: When does the lesson start?\nB: At eight o'clock. Be on time!\nA: What kind of lessons do you have today?\nB: German and Mathematics.",funFact:"'Unterricht' comes from 'unterrichten' (to instruct, to inform). In German schools, lessons are called 'Stunden' (hours): 'Wir haben heute sechs Stunden Unterricht.' (We have six hours of lessons today.) Each Stunde is 45 minutes, not 60."},
{type:"match",pairs:[{trg:"der Kontakt",src:"contact"},{trg:"der Stift",src:"pen"},{trg:"die Notiz",src:"note"},{trg:"der Zettel",src:"slip of paper"},{trg:"die Zahl",src:"number"},{trg:"reden",src:"to talk"}]},
{type:"story",speaker:"narrator",mood:"thoughtful",art:"de-kitchen-documents-2",trg:"Verumius schaut auf seine Notizen und rechnet. Er hat Kontakte, aber er braucht mehr Kenntnisse. Er hat einen Mietvertrag, aber er braucht auch einen Kredit. Er redet gut Deutsch, aber er versteht nicht alles.",src:"Verumius looks at his notes and calculates. He has contacts, but he needs more knowledge. He has a rental contract, but he also needs a loan. He talks good German, but he doesn't understand everything."},
{type:"tip",title:"ADUSO: The 5 Coordinating Conjunctions",text:"German has exactly 5 coordinating conjunctions. They connect two main clauses and do NOT change the word order.\n\nA = aber (but)\nD = denn (because)\nU = und (and)\nS = sondern (but rather, after a negative)\nO = oder (or)\n\nWord order stays the same: Subject + Verb.\n'Ich lerne Deutsch und ich arbeite in Berlin.'\n'Er spricht kein Französisch, sondern er spricht Deutsch.'\n\nThese 5 words NEVER push the verb to the end.",deepDive:"Why does 'denn' not change word order? Because coordinating conjunctions join EQUAL clauses. Neither clause is 'inside' the other. Compare with 'weil' (because, subordinating): 'Ich lerne, weil ich Deutsch brauche.' Here the verb 'brauche' goes to the END. With 'denn': 'Ich lerne, denn ich brauche Deutsch.' Verb stays in position 2. Same meaning, different grammar. You will learn subordinating conjunctions later."},
{type:"mc",q:"Which mnemonic helps you remember the 5 German coordinating conjunctions?",opts:["ADUSO","ABCDE","VOWEL","KRAFT"],ans:"ADUSO",hint:"Each letter stands for one conjunction: A, D, U, S, O."},
{type:"mc",q:"'Ich habe einen Mietvertrag, aber ich brauche einen Kredit.' What does 'aber' mean?",opts:["and","because","but","or"],ans:"but",hint:"This conjunction introduces a contrast between two facts."},
{type:"fb",s:"Er lernt Deutsch, {1} er wohnt in Berlin.",a:["denn"],opts:["denn","aber","sondern","oder"],hint:"He learns German BECAUSE he lives in Berlin. Which ADUSO word fits?",sSrc:"He is learning German {1} he lives in Berlin."},
{type:"mc",q:"'Sie spricht kein Englisch, sondern sie spricht Spanisch.' When do you use 'sondern'?",opts:["After a positive statement with emphasis","After any question about languages","After a negative statement to correct it","In any position within the sentence"],ans:"After a negative statement to correct it",hint:"The first clause says 'kein Englisch,' negating something before offering the correction."},
{type:"fb",s:"Möchtest du Kaffee {1} Tee?",a:["oder"],opts:["oder","und","aber","denn"],hint:"You are being offered a choice between two drinks.",sSrc:"Would you like coffee {1} tea?"},
{type:"drag_fill",s:"Verumius hat Kontakte {1} er braucht mehr Kenntnisse. Er redet Deutsch {2} er versteht nicht alles.",blanks:{"1":"und","2":"aber"},pool:["und","aber","denn","oder","sondern"],hint:"First: adding two facts together. Second: introducing a contrast.",sSrc:"Verumius has contacts {1} he needs more knowledge. He speaks German {2} he does not understand everything."},
{type:"mc",q:"Which sentence has CORRECT word order after a coordinating conjunction?",opts:["Ich lerne Deutsch und ich gehe zur Schule.","Ich lerne Deutsch und gehe ich zur Schule.","Ich lerne Deutsch und zur Schule ich gehe.","Ich lerne Deutsch und zur Schule gehe ich."],ans:"Ich lerne Deutsch und ich gehe zur Schule.",hint:"After ADUSO conjunctions, the word order stays normal: subject then verb."},
{type:"tip",title:"Adverb Categories: Time, Place, Manner",text:"German adverbs fall into three main categories:\n\nTime (wann?): heute, morgen, gestern, oft, manchmal, immer, nie, bald, schon, noch\nPlace (wo?): hier, dort, oben, unten, draußen, drinnen, links, rechts, überall\nManner (wie?): gut, schlecht, schnell, langsam, gern, leider, vielleicht, besonders\n\nIn a sentence with multiple adverbs, the default order is: Time before Place before Manner.\n'Ich arbeite heute hier gern.' = I like working here today.",deepDive:"The time-place-manner order is a tendency, not an unbreakable rule. German is flexible. But for natural-sounding sentences, TeKaMoLo (Temporal, Kausal, Modal, Lokal) is the standard order that native speakers default to. You can break it for emphasis, but learn the default first."},
{type:"mc",q:"'Verumius schreibt heute hier schnell.' What is the adverb order?",opts:["Manner, Place, Time","Place, Time, Manner","Time, Place, Manner","Time, Manner, Place"],ans:"Time, Place, Manner",hint:"'Heute' tells when, 'hier' tells where, 'schnell' tells how."},
{type:"fb",s:"Ich rechne {1} mit Zahlen.",a:["gern"],opts:["gern","hier","morgen","schnell"],hint:"Which manner adverb means you enjoy doing something?",sSrc:"I {1} work with numbers."},
{type:"drag_fill",s:"Er redet {1} viel, {2} er versteht nicht alles, {3} er macht Notizen.",blanks:{"1":"heute","2":"aber","3":"und"},pool:["heute","aber","und","denn","dort"],hint:"A time adverb first, then a contrast conjunction, then an adding conjunction.",sSrc:"He talks {1} a lot, {2} he does not understand everything, {3} he takes notes."},
{type:"mc",q:"'Verumius hat keine Schulden, sondern er hat einen Kredit.' Is this correct?",opts:["No, 'aber' fits better after a negative","No, 'denn' is needed for giving a reason","Yes, it corrects the negative 'keine Schulden'","No, 'und' simply adds without correcting"],ans:"Yes, it corrects the negative 'keine Schulden'",hint:"The first clause contains 'keine' (a negation). What follows replaces and contrasts it."},
{type:"fb",s:"Die Mitarbeiterin redet schnell, {1} ich verstehe sie nicht.",a:["denn"],opts:["denn","und","oder","sondern"],hint:"The second clause gives the REASON why he does not understand.",sSrc:"The colleague speaks quickly, {1} I do not understand her."},
{type:"match",pairs:[{trg:"und",src:"and"},{trg:"oder",src:"or"},{trg:"aber",src:"but"},{trg:"denn",src:"because"},{trg:"sondern",src:"but rather"},{trg:"das Stück",src:"piece"}]}
]}
,

{id:"deu_r12l4",title:"Was wäre wenn?",icon:"📐",xp:20,board:true,steps:[
{type:"intro",title:"Was wäre wenn?",desc:"Verumius and Hildi sit in a café, daydreaming about what they would do if they could. Time to master imperatives with separable and irregular verbs, revisit ob-clauses, and sharpen your Konjunktiv II. Plus: subordinate clause word order under pressure.",goals:["Form imperatives with separable and irregular verbs","Combine ob with new vocabulary","Use Konjunktiv II in wishes and hypotheticals","Master subordinate clause word order with all conjunctions"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-cafe-daydream",trg:"Im Café am Gendarmenmarkt. Draußen regnet es. Verumius und Hildi trinken Kaffee und planen das nächste Halbjahr. Aber die Pläne werden schnell zu Träumen.",src:"In the café at Gendarmenmarkt. Outside it is raining. Verumius and Hildi drink coffee and plan the next half-year. But the plans quickly turn to dreams."},
{type:"story",speaker:"Hildi",trg:"Steh auf, Verumius! Hör auf zu träumen! Wir müssen planen, nicht träumen. Oder... was würdest du tun, wenn du alles schaffen könntest?",src:"Get up, Verumius! Stop dreaming! We need to plan, not dream. Or... what would you do if you could accomplish anything?"},
{type:"teach",trg:"lassen",src:"to let / to leave",note:"Irregular: ich lasse, du lässt, er lässt. Stem change a to ä.",example:"A: Lass mich in Ruhe!\nB: Okay, ich lasse dich allein.",exampleSrc:"A: Leave me alone!\nB: Okay, I'll leave you alone.",funFact:"'Lassen' is a chameleon verb. 'Lass uns gehen' = let's go. 'Ich lasse es reparieren' = I'm having it repaired. 'Lass das!' = Stop that! One verb, three completely different uses."},
{type:"teach",trg:"schaffen",src:"to manage / to accomplish",note:"Regular: ich schaffe, du schaffst. 'Das schaffe ich!' = I can do this!",example:"A: Schaffst du die Prüfung?\nB: Ja, ich schaffe das!",exampleSrc:"A: Will you pass the exam?\nB: Yes, I can do it!",funFact:"'Schaffen' has a secret twin: 'schaffen' (regular) means 'to manage.' But 'schaffen' (irregular: schuf, geschaffen) means 'to create.' God 'schuf' the world, but you 'schaffst' your homework."},
{type:"teach",trg:"versuchen",src:"to try / to attempt",note:"Regular: ich versuche, du versuchst. Often with 'zu' + infinitive.",example:"A: Versuch es nochmal!\nB: Okay, ich versuche es.",exampleSrc:"A: Try it again!\nB: Okay, I'll try.",funFact:"'Versuchen' contains 'suchen' (to search). To try something is literally 'to search thoroughly.' A 'Versuchung' is a temptation, something that lures you into searching."},
{type:"teach",trg:"vorbereiten",src:"to prepare",note:"Separable: ich bereite ... vor, du bereitest ... vor.",example:"A: Bereitest du das Essen vor?\nB: Ja, ich bereite alles vor.",exampleSrc:"A: Are you preparing the food?\nB: Yes, I'm preparing everything.",funFact:"'Vor' (before) + 'bereiten' (to make ready). You 'make ready beforehand.' In a subordinate clause, it reunites: 'weil ich alles vorbereite.' Separable verbs play hide-and-seek with their prefix!"},
{type:"teach",trg:"wählen",src:"to choose / to vote",note:"Regular: ich wähle, du wählst. Used for elections and menus.",example:"A: Was wählst du?\nB: Ich wähle den Kaffee mit Milch.",exampleSrc:"A: What are you choosing?\nB: I'm choosing the coffee with milk.",funFact:"'Wählen' means both 'to choose' and 'to vote.' A 'Wahl' is an election. 'Die Qual der Wahl' (the agony of choice) is a beloved German rhyme for when you cannot decide."},
{type:"teach",trg:"prüfen",src:"to test / to examine",note:"Regular: ich prüfe, du prüfst. A 'Prüfung' is an exam.",example:"A: Prüf bitte die Rechnung!\nB: Alles stimmt.",exampleSrc:"A: Please check the bill!\nB: Everything is correct.",funFact:"Every German car gets a 'TÜV-Prüfung' (technical inspection) every two years. Germans love prüfen: testing, checking, verifying. The 'Prüfung' (exam) is sacred in German education."},
{type:"teach",trg:"planen",src:"to plan",note:"Regular: ich plane, du planst. 'Einen Plan machen' = to make a plan.",example:"A: Was planst du für morgen?\nB: Ich plane einen Ausflug nach Potsdam.",exampleSrc:"A: What are you planning for tomorrow?\nB: I'm planning a trip to Potsdam.",funFact:"Germans are famous for planning. 'Planwirtschaft' = planned economy. 'Fahrplan' = train schedule. 'Stadtplan' = city map. If it exists, Germans have a plan for it."},
{type:"teach",trg:"sparen",src:"to save (money)",note:"Regular: ich spare, du sparst. 'Ein Sparkonto' = a savings account.",example:"A: Sparst du für etwas Besonderes?\nB: Ja, ich spare für eine Reise.",exampleSrc:"A: Are you saving for something special?\nB: Yes, I'm saving for a trip.",funFact:"Germany is a nation of savers. The 'Sparbuch' (savings book) was every child's first financial tool. 'Sparschwein' (savings pig) is the word for piggy bank. Pigs are lucky in German culture!"},
{type:"mc",q:"Which verb means 'to try' or 'to attempt'?",opts:["versuchen","vorbereiten","prüfen","wählen"],ans:"versuchen",hint:"This word contains 'suchen' (to search) with a prefix."},
{type:"fb",s:"Ich {1} für eine Reise nach Japan.",a:["spare"],opts:["spare","plane","schaffe","prüfe"],hint:"Which verb means putting money aside for the future?",sSrc:"I am {1} for a trip to Japan."},
{type:"tip",title:"Imperative: Separable and Irregular Verbs",text:"Separable verbs split in the imperative. The prefix goes to the end:\n\nvorbereiten: Bereite dich vor! (Prepare yourself!)\naufstehen: Steh auf! (Get up!)\nzumachen: Mach die Tür zu! (Close the door!)\n\nIrregular verbs with e to i stem change keep the change:\n\ngeben: Gib mir das Buch! (not 'Geb')\nnehmen: Nimm Platz! (not 'Nehm')\nlesen: Lies das! (not 'Les')\n\nSein has a special form: Sei ruhig! (Be quiet!)",deepDive:"Why do separable verbs split? The prefix carries meaning (auf = up, vor = before, zu = closed), and in main clauses it jumps to the end for emphasis. The imperative is a main clause, so the same rule applies. In a subordinate clause, the prefix stays attached: 'Ich sage, dass du aufstehen sollst.'"},
{type:"mc",q:"How do you say 'Get up!' using the separable verb 'aufstehen'?",opts:["Steh auf!","Aufsteh!","Stehe auf!","Auf steh!"],ans:"Steh auf!",hint:"The prefix separates and moves to the end of the command."},
{type:"fb",s:"{1} mir bitte das Salz!",a:["Gib"],opts:["Gib","Geb","Gibt","Geben"],hint:"The irregular verb 'geben' changes its stem vowel in the du-imperative.",sSrc:"{1} me the salt please!"},
{type:"mc",q:"Which imperative form of 'nehmen' is correct?",opts:["Nimm!","Nehm!","Nimmt!","Nehme!"],ans:"Nimm!",hint:"Like geben to Gib, this verb changes its stem vowel from e to i."},
{type:"mc",q:"How do you say 'Be patient!' using 'sein'?",opts:["Sei geduldig!","Bist geduldig!","Seid geduldig!","Sein geduldig!"],ans:"Sei geduldig!",hint:"The verb 'sein' has a completely unique imperative form for the du-form."},
{type:"tip",title:"ob: Whether or Not",text:"'ob' means 'whether' and sends the verb to the END of its clause:\n\nIch weiß nicht, ob er kommt.\n(I don't know whether he is coming.)\n\nWeißt du, ob das Café offen ist?\n(Do you know whether the café is open?)\n\nob works like weil, dass, wenn: verb LAST.\nDon't confuse ob with wenn (if/when for conditions).",deepDive:"'ob' is used for indirect yes/no questions. Any yes/no question can become an ob-clause: 'Kommt er?' (Is he coming?) becomes 'Ich frage, ob er kommt' (I ask whether he is coming). The original verb-first order flips to verb-last."},
{type:"fb",s:"Ich frage mich, {1} ich das schaffe.",a:["ob"],opts:["ob","wenn","dass","weil"],hint:"Which conjunction means 'whether' and introduces indirect yes/no questions?",sSrc:"I wonder {1} I will manage it."},
{type:"mc",q:"'Weißt du, ob Hildi morgen ___?' Which verb form fits the ob-clause?",opts:["kommt","kommen","kommst","komme"],ans:"kommt",hint:"In an ob-clause the verb goes to the end, conjugated for the subject 'Hildi.'"},
{type:"drag_fill",s:"Ich weiß nicht, {1} er das Essen {2}.",blanks:{"1":"ob","2":"vorbereitet"},pool:["ob","vorbereitet","wenn","bereitet vor","dass"],hint:"In the ob-clause, the separable verb stays TOGETHER because the verb goes to the end.",sSrc:"I do not know {1} he {2} the food."},
{type:"teach",trg:"hatte",src:"had (simple past of haben)",example:"A: Hattest du gestern frei?\nB: Ja, ich hatte einen freien Tag.\nA: Schön! Was hast du gemacht?",exampleSrc:"A: Did you have a day off yesterday?\nB: Yes, I had a free day.\nA: Nice! What did you do?",note:"Präteritum of haben: ich hatte, du hattest, er hatte, wir hatten. Used in writing and with modal verbs.",funFact:"Germans prefer Perfekt (ich habe gehabt) in speech but Präteritum (ich hatte) in writing. The exception: haben and sein almost always use Präteritum even in speech."},
{type:"teach",trg:"ginge",src:"would go (Konjunktiv II of gehen)",example:"A: Wenn es mir besser ginge, würde ich mitkommen.\nB: Ruh dich aus! Morgen ginge es bestimmt.\nA: Ich hoffe es!",exampleSrc:"A: If I felt better, I would come along.\nB: Rest up! Tomorrow it would surely work.\nA: I hope so!",note:"Konjunktiv II of gehen: ich ginge, du gingest, er ginge. From Präteritum 'ging' + umlaut pattern. Often replaced by 'würde gehen' in speech.",funFact:"'Es ginge' is a polite way to say 'it would work.' At the Amt: 'Ginge es auch morgen?' (Would tomorrow also work?) sounds much softer than 'Geht es morgen?'"},
{type:"tip",title:"Konjunktiv II: Dreaming Big",text:"Review: würde + infinitive for wishes.\n\nWenn ich Zeit hätte, würde ich mehr sparen.\n(If I had time, I would save more.)\n\nWas würdest du tun, wenn du alles schaffen könntest?\n(What would you do if you could accomplish anything?)\n\nKey irregular forms:\nwäre (would be), hätte (would have)\nkönnte (could), müsste (would have to)\nwüsste (would know), dürfte (would be allowed to)",deepDive:"Wenn-clauses with Konjunktiv II always have verb-last order in the wenn-part, and the main clause starts with the conjugated verb: 'Wenn ich reich wäre, würde ich reisen.' This is verb-second in the main clause because 'wenn ich reich wäre' counts as position 1."},
{type:"mc",q:"'Wenn ich mehr Geld ___, würde ich eine Reise planen.' Which form completes this?",opts:["hätte","habe","hatte","würde haben"],ans:"hätte",hint:"This hypothetical needs the Konjunktiv II form of 'haben.'"},
{type:"fb",s:"Wenn ich du {1}, würde ich es versuchen.",a:["wäre"],opts:["wäre","würde","hätte","könnte"],hint:"Which Konjunktiv II form means 'were' from the verb 'sein'?",sSrc:"If I {1} you, I would try it."},
{type:"drag_fill",s:"Wenn ich alles {1}, {2} ich zuerst Deutsch {3}.",blanks:{"1":"schaffen könnte","2":"würde","3":"prüfen"},pool:["schaffen könnte","würde","prüfen","schaffen kann","werde","geprüft"],hint:"The wenn-clause needs Konjunktiv II. The main clause needs the subjunctive helper + infinitive.",sSrc:"If I {1} everything, I {2} first {3} German."},
{type:"tip",title:"Subordinate Clause Word Order: All Conjunctions",text:"ALL these conjunctions send the verb to the END:\n\nweil (because): Ich spare, weil ich reisen will.\ndass (that): Ich glaube, dass er es schafft.\nob (whether): Ich frage, ob sie kommt.\nwenn (if/when): Wenn ich könnte, würde ich planen.\nobwohl (although): Er plant, obwohl er müde ist.\n\nSeparable verbs REUNITE at the end:\nIch weiß, dass er alles vorbereitet. (not 'bereitet vor').",deepDive:"The verb-last rule in subordinate clauses is one of German's most consistent rules. No matter which subordinating conjunction you use, the conjugated verb goes to the final position. With modals: 'weil ich planen muss' (the modal goes last, the infinitive sits before it). With separable verbs: the prefix reattaches because there is no sentence end to jump to."},
{type:"mc",q:"'Er spart Geld, _____ er eine Reise plant.' Which conjunction means 'because'?",opts:["weil","ob","dass","wenn"],ans:"weil",hint:"This conjunction explains the reason and sends the verb to the end."},
{type:"drag_fill",s:"Ich glaube, {1} sie alles gut {2}, {3} sie sich immer {4}.",blanks:{"1":"dass","2":"schafft","3":"weil","4":"vorbereitet"},pool:["dass","schafft","weil","vorbereitet","ob","bereitet vor"],hint:"Both clauses need verb-last order. The separable verb 'vorbereiten' stays together in a subordinate clause.",sSrc:"I believe {1} she does everything well {2} she always {3} herself {4}."},
{type:"fb",s:"Steh {1}! Wir müssen alles vorbereiten.",a:["auf"],opts:["auf","an","vor","zu"],hint:"Complete this separable imperative. The verb means 'to get up.'",sSrc:"Get {1}! We have to prepare everything."},
{type:"mc",q:"'Wenn ich es versuchen könnte, ___ ich es sofort tun.' What fills the blank?",opts:["würde","wäre","hätte","müsste"],ans:"würde",hint:"The main clause of a wenn-Konjunktiv II needs the general 'would' form with an infinitive."},
{type:"match",pairs:[{trg:"lassen",src:"to let / to leave"},{trg:"schaffen",src:"to manage"},{trg:"versuchen",src:"to try"},{trg:"vorbereiten",src:"to prepare"},{trg:"wählen",src:"to choose / to vote"},{trg:"prüfen",src:"to test"},{trg:"planen",src:"to plan"},{trg:"sparen",src:"to save (money)"}]}
]}
,

{id:"deu_r12l5",title:"Gefühle",icon:"💭",xp:15,board:true,steps:[
{type:"intro",title:"Gefühle",desc:"Träume, Wünsche und alles dazwischen. Lerne 16 wichtige Substantive für Emotionen und abstrakte Begriffe.",goals:["16 neue Substantive lernen","Grammatik aus Lektion 1\u20134 wiederholen","Abstrakte Begriffe im Kontext verwenden"]},
{type:"teach",trg:"der Traum",src:"dream",gender:"m",note:"Plural: die Träume. Umlaut im Plural.",funFact:"Deutsche sagen 'Traumjob' für ihren perfekten Beruf.",example:"A: Hattest du letzte Nacht einen Traum?\nB: Ja, ich habe von meinem Urlaub geträumt.",exampleSrc:"A: Did you have a dream last night?\nB: Yes, I dreamed about my vacation."},
{type:"teach",trg:"der Wunsch",src:"wish",gender:"m",note:"Plural: die Wünsche. Verb: sich etwas wünschen.",funFact:"Zum Geburtstag sagt man 'Herzlichen Glückwunsch!' mit Wunsch drin.",example:"A: Hast du einen Wunsch?\nB: Ja, ich wünsche mir mehr Freizeit.",exampleSrc:"A: Do you have a wish?\nB: Yes, I wish for more free time."},
{type:"teach",trg:"das Ziel",src:"goal",gender:"n",note:"Plural: die Ziele. Auch: destination (Reiseziel).",funFact:"'Zielstrebig' bedeutet determined, wörtlich: striving toward a goal.",example:"A: Was ist dein Ziel für dieses Jahr?\nB: Ich möchte besser Deutsch sprechen.",exampleSrc:"A: What is your goal for this year?\nB: I want to speak better German."},
{type:"teach",trg:"der Unterschied",src:"difference",gender:"m",note:"Plural: die Unterschiede. Adjektiv: unterschiedlich.",funFact:"Unter + schied kommt von 'scheiden' (to separate). Wörtlich: what separates below.",example:"A: Was ist der Unterschied zwischen Traum und Wunsch?\nB: Ein Traum kommt nachts, ein Wunsch kommt vom Herzen.",exampleSrc:"A: What is the difference between dream and wish?\nB: A dream comes at night, a wish comes from the heart."},
{type:"teach",trg:"das Gegenteil",src:"opposite",gender:"n",note:"Plural: die Gegenteile. gegen (against) + Teil (part).",funFact:"Deutsche lieben Gegensatzpaare: heiß/kalt, groß/klein, laut/leise.",example:"A: Was ist das Gegenteil von Stress?\nB: Ich glaube, das Gegenteil ist Ruhe.",exampleSrc:"A: What is the opposite of stress?\nB: I think the opposite is peace."},
{type:"teach",trg:"die Menge",src:"quantity, crowd",gender:"f",note:"Plural: die Mengen. 'Eine Menge Leute' heißt a lot of people.",funFact:"In der Mathematik ist 'die Menge' auch ein set, wie in der Mengenlehre.",example:"A: Wie war das Konzert?\nB: Toll! Es war eine riesige Menge da.",exampleSrc:"A: How was the concert?\nB: Great! There was a huge crowd there."},
{type:"teach",trg:"die Reihe",src:"row, series",gender:"f",note:"Plural: die Reihen. 'Ich bin an der Reihe' heißt it's my turn.",funFact:"'Der Reihe nach' bedeutet one after another, in order.",example:"A: Wer ist jetzt an der Reihe?\nB: Du bist an der Reihe!",exampleSrc:"A: Whose turn is it now?\nB: It's your turn!"},
{type:"teach",trg:"der Rest",src:"rest, remainder",gender:"m",note:"Plural: die Reste. 'Den Rest' kann man auch für Essensreste benutzen.",funFact:"'Gib ihm den Rest!' heißt umgangssprachlich: finish him off!",example:"A: Möchtest du den Rest vom Kuchen?\nB: Nein danke, ich bin satt.",exampleSrc:"A: Would you like the rest of the cake?\nB: No thanks, I'm full."},
{type:"teach",trg:"die Ruhe",src:"peace, quiet",gender:"f",note:"Kein Plural. Adjektiv: ruhig (calm, quiet).",funFact:"'Immer mit der Ruhe!' ist ein beliebter Spruch: take it easy!",example:"A: Ich brauche etwas Ruhe.\nB: Soll ich das Radio ausmachen?",exampleSrc:"A: I need some peace and quiet.\nB: Should I turn off the radio?"},
{type:"teach",trg:"die Sache",src:"thing, matter",gender:"f",note:"Plural: die Sachen. Auch: belongings (Nimm deine Sachen mit!).",funFact:"'Zur Sache kommen' heißt to get to the point.",example:"A: Ich muss dir eine wichtige Sache sagen.\nB: Was für eine Sache denn?",exampleSrc:"A: I need to tell you an important thing.\nB: What kind of thing?"},
{type:"teach",trg:"der Stress",src:"stress",gender:"m",note:"Kein Plural. Verb: stressen. 'Ich bin gestresst.'",funFact:"Das Wort kommt direkt aus dem Englischen und wird genauso benutzt.",example:"A: Du siehst müde aus. Hast du viel Stress?\nB: Ja, die Arbeit stresst mich gerade sehr.",exampleSrc:"A: You look tired. Do you have a lot of stress?\nB: Yes, work is really stressing me out right now."},
{type:"teach",trg:"die Liebe",src:"love",gender:"f",note:"Kein Plural. Adjektiv: lieb. Verb: lieben.",funFact:"'Liebe geht durch den Magen' heißt: the way to someone's heart is through their stomach.",example:"A: Glaubst du an die große Liebe?\nB: Ja, aber man muss Geduld haben.",exampleSrc:"A: Do you believe in true love?\nB: Yes, but you have to be patient."},
{type:"teach",trg:"der Spaß",src:"fun",gender:"m",note:"Plural: die Späße. 'Spaß machen' heißt to be fun.",funFact:"'Spaß beiseite!' heißt joking aside, jetzt wird es ernst.",example:"A: Macht der Kurs dir Spaß?\nB: Ja, Deutsch lernen macht mir großen Spaß!",exampleSrc:"A: Is the course fun for you?\nB: Yes, learning German is a lot of fun for me!"},
{type:"teach",trg:"die Lüge",src:"lie",gender:"f",note:"Plural: die Lügen. Verb: lügen (to lie). Er lügt.",funFact:"'Lügen haben kurze Beine' heißt: lies have short legs, also die Wahrheit kommt raus.",example:"A: War das eine Lüge?\nB: Nein, ich sage dir die Wahrheit!",exampleSrc:"A: Was that a lie?\nB: No, I'm telling you the truth!"},
{type:"teach",trg:"der Titel",src:"title",gender:"m",note:"Plural: die Titel. Auch für Bücher, Lieder und akademische Titel.",funFact:"In Deutschland benutzt man akademische Titel oft: Herr Dr. Müller, Frau Prof. Schmidt.",example:"A: Wie ist der Titel des Buches?\nB: Der Titel ist 'Der kleine Prinz'.",exampleSrc:"A: What is the title of the book?\nB: The title is 'The Little Prince'."},
{type:"teach",trg:"der Vorschlag",src:"suggestion, proposal",gender:"m",note:"Plural: die Vorschläge. Verb: vorschlagen (separable).",funFact:"Vor (before) + Schlag (hit/strike). Wörtlich: a strike put forward.",example:"A: Ich habe einen Vorschlag.\nB: Was schlägst du vor?",exampleSrc:"A: I have a suggestion.\nB: What do you suggest?"},
{type:"mc",q:"Was bedeutet 'der Unterschied'?",opts:["difference","opposite","remainder","quantity"],ans:"difference",hint:"Es beschreibt, was zwei Dinge voneinander trennt."},
{type:"fb",s:"Ich habe einen {1} für das Wochenende.",a:"Vorschlag",opts:["Vorschlag","Unterschied","Gegenteil","Titel"],hint:"Jemand hat eine Idee und schlägt etwas vor.",sSrc:"I have a {1} for the weekend."},
{type:"mc",q:"'Lügen haben kurze Beine.' Was bedeutet das?",opts:["Die Wahrheit kommt immer raus","Man soll schnell laufen","Lügen machen Spaß","Beine sind wichtig"],ans:"Die Wahrheit kommt immer raus",hint:"Es ist ein Sprichwort über Ehrlichkeit."},
{type:"fb",s:"Wenn ich müde bin, brauche ich {1}.",a:"Ruhe",opts:["Ruhe","Stress","Menge","Reihe"],hint:"Das Gegenteil von Lärm und Hektik.",sSrc:"When I am tired, I need {1}."},
{type:"drag_fill",s:"Ich weiß nicht, ob er seinen {1} erreichen kann, aber sein {2} ist groß.",blanks:{"1":"Traum","2":"Wunsch"},pool:["Traum","Wunsch","Rest","Titel","Spaß"],hint:"Erst kommt etwas, das man nachts hat, dann etwas, das man sich erhofft.",sSrc:"I do not know whether he can reach his {1}, but his {2} is great."},
{type:"mc",q:"Welcher Satz benutzt 'die Reihe' richtig?",opts:["Du bist an der Reihe.","Die Reihe ist sehr müde.","Ich esse eine Reihe.","Er kauft die Reihe."],ans:"Du bist an der Reihe.",hint:"Dieses Wort wird oft benutzt, wenn man auf etwas wartet."},
{type:"fb",s:"Das {1} von Liebe ist Hass.",a:"Gegenteil",opts:["Gegenteil","Ziel","Rest","Unterschied"],hint:"Das Wort beschreibt die entgegengesetzte Bedeutung.",sSrc:"The {1} of love is hate."},
{type:"mc",q:"'Mein Ziel ist es, Deutsch zu sprechen.' Was ist 'das Ziel'?",opts:["goal","dream","fun","lie"],ans:"goal",hint:"Etwas, das man erreichen möchte."},
{type:"drag_fill",s:"Er hat viel {1} bei der Arbeit, aber am Abend macht ihm Kochen großen {2}.",blanks:{"1":"Stress","2":"Spaß"},pool:["Stress","Spaß","Liebe","Ruhe","Lüge"],hint:"Zuerst etwas Negatives bei der Arbeit, dann etwas Positives am Abend.",sSrc:"He has a lot of {1} at work, but in the evening cooking gives him great {2}."},
{type:"match",pairs:[{trg:"der Traum",src:"dream"},{trg:"die Ruhe",src:"peace"},{trg:"die Lüge",src:"lie"},{trg:"der Vorschlag",src:"suggestion"},{trg:"die Sache",src:"thing"}]}
]},

// U12 L6: KD lacht. Story climax. Bürgeramt scene. Heavy A2 grammar review.
{id:"deu_r12l6",title:"KD lacht",icon:"\uD83D\uDE10",xp:20,board:true,steps:[
{type:"intro",title:"KD lacht",desc:"Back at the Bürgeramt. This time Verumius has ALL the right documents. KD processes everything smoothly. And then something impossible happens...",goals:["Review all A2 grammar in multi-construct sentences","Learn 10 new vocabulary words","Witness the impossible: KD smiles"]},
{type:"story",speaker:"narrator",mood:"confident",art:"de-buergeramt-desk",trg:"Bürgeramt, Zimmer 4. KD sitzt hinter ihrem Schreibtisch. Verumius legt einen perfekten Stapel Dokumente auf den Tisch. Alles ist da. Alles ist richtig.",src:"Bürgeramt, Room 4. KD sits behind her desk. Verumius places a perfect stack of documents on the table. Everything is there. Everything is correct."},
{type:"story",speaker:"KD",mood:"neutral",trg:"Personalausweis. Meldebescheinigung. Gehaltsnachweis. Krankenversicherung. Alles vollständig. Das ist... ungewöhnlich.",src:"ID card. Registration certificate. Proof of income. Health insurance. Everything complete. That is... unusual."},
{type:"story",speaker:"narrator",mood:"surprised",trg:"KD tippt schnell auf ihrem Laptop. Der Service ist schnell und effizient. Dann schaut sie aus dem Fenster und sagt trocken: 'Bei dem Wetter braucht man keine Erlaubnis zum Weinen. Das macht der Regen schon.' Ihre Lippe zuckt. War das ein Lächeln?",src:"KD types quickly on her laptop. The service is fast and efficient. Then she looks out the window and says dryly: 'With this weather, you don't need permission to cry. The rain does it for you.' Her lip twitches. Was that a smile?"},
{type:"teach",trg:"die Erlaubnis",src:"the permission",note:"Feminine noun. Plural: die Erlaubnisse. From 'erlauben' (to allow).",example:"A: Hast du die Erlaubnis bekommen?\nB: Ja, ich habe die Erlaubnis gestern bekommen.",exampleSrc:"A: Did you get the permission?\nB: Yes, I got the permission yesterday.",funFact:"Germans need an 'Erlaubnis' for surprisingly many things: building a fence, cutting down a tree, even owning certain dog breeds. Bureaucracy is a national sport."},
{type:"teach",trg:"die Ermäßigung",src:"the discount / reduction",note:"Feminine noun. From 'ermäßigen' (to reduce). Common at museums and trains.",example:"A: Gibt es eine Ermäßigung für Studenten?\nB: Ja, Studenten bekommen eine Ermäßigung von 50 Prozent.",exampleSrc:"A: Is there a discount for students?\nB: Yes, students get a 50 percent discount.",funFact:"The 'BahnCard 50' gives 50% Ermäßigung on all Deutsche Bahn trains. Germans plan their train discounts like military operations."},
{type:"teach",trg:"der Bescheid",src:"the notice / notification",note:"Masculine noun. Official communication from authorities. 'Bescheid wissen' = to be informed.",example:"A: Wann kommt der Bescheid vom Amt?\nB: Der Bescheid kommt in zwei Wochen.",exampleSrc:"A: When does the notice from the office come?\nB: The notice comes in two weeks.",funFact:"'Bescheid geben' means to let someone know. 'Ich gebe dir Bescheid' is one of the most useful everyday phrases in German. Literal: 'I give you notice.'"},
{type:"mc",q:"KD says Verumius doesn't need 'Erlaubnis zum Weinen.' What does she mean?",opts:["Permission to cry","Permission to leave","Permission to work","Permission to stay"],ans:"Permission to cry",hint:"'Weinen' is the verb for shedding tears."},
{type:"teach",trg:"das Paar",src:"the pair / couple",note:"Neuter noun. 'Ein Paar Schuhe' = a pair of shoes. 'Ein Paar' (capitalized) = a couple.",example:"A: Sind die beiden ein Paar?\nB: Ja, sie sind seit drei Jahren ein Paar.",exampleSrc:"A: Are those two a couple?\nB: Yes, they have been a couple for three years.",funFact:"Careful with capitalization! 'Ein Paar' (capital P) = a couple/pair. 'Ein paar' (lowercase) = a few/some. 'Ein Paar Schuhe' = one pair of shoes. 'Ein paar Schuhe' = a few shoes."},
{type:"teach",trg:"die Webseite",src:"the website",note:"Feminine noun. Compound: Web + Seite (page). Also 'die Website.'",example:"A: Hast du die Webseite schon besucht?\nB: Ja, ich habe mich auf der Webseite angemeldet.",exampleSrc:"A: Have you visited the website yet?\nB: Yes, I registered on the website.",funFact:"Germans say both 'Webseite' (half-translated: Web + Seite/page) and 'Website' (full English). The government prefers 'Internetseite' or 'Internetauftritt' (internet appearance). Classic."},
{type:"teach",trg:"der Laptop",src:"the laptop",note:"Masculine noun. Borrowed directly from English. Plural: die Laptops.",example:"A: Wo ist dein Laptop?\nB: Mein Laptop steht auf dem Schreibtisch.",exampleSrc:"A: Where is your laptop?\nB: My laptop is on the desk.",funFact:"German assigns gender to borrowed words too. Laptop is 'der' (masculine), E-Mail is 'die' (feminine), and Handy (mobile phone) is 'das' (neuter). No logic. Just feelings."},
{type:"fb",s:"Mein Laptop steht auf {1} Schreibtisch.",a:["dem"],opts:["dem","den","der","das"],hint:"After 'auf' with a static location, which case follows?",sSrc:"My laptop is on {1} desk."},
{type:"teach",trg:"das Tablet",src:"the tablet",note:"Neuter noun. Borrowed from English. Plural: die Tablets.",example:"A: Ich habe mir ein neues Tablet gekauft.\nB: Auf dem Tablet kann man gut lesen.",exampleSrc:"A: I bought myself a new tablet.\nB: You can read well on the tablet.",funFact:"Some Germans insist on saying 'der Tablet-Computer' for the full compound. Others just say 'das iPad' regardless of brand, like 'Tempo' for tissues."},
{type:"teach",trg:"der Service",src:"the service",note:"Masculine noun. Pronounced with French stress: ser-VEES. Used for customer service.",example:"A: Wie war der Service im Restaurant?\nB: Der Service war sehr gut.",exampleSrc:"A: How was the service in the restaurant?\nB: The service was very good.",funFact:"German has two words: 'der Service' (pronounced French, for customer service) and 'der Dienst' (native German, for public service/duty). KD provides 'Dienst.' Whether it feels like 'Service' depends on her mood."},
{type:"teach",trg:"der Babysitter",src:"the babysitter",note:"Masculine noun. Used for all genders in casual speech. Feminine: die Babysitterin.",example:"A: Wir brauchen einen Babysitter für Samstag.\nB: Ich habe schon einen Babysitter gefunden.",exampleSrc:"A: We need a babysitter for Saturday.\nB: I already found a babysitter.",funFact:"Germans borrow English job titles constantly: Babysitter, Manager, Designer, Influencer. Each gets a German article and a feminine '-in' form. Globalization meets grammar."},
{type:"teach",trg:"die Chefin",src:"the (female) boss",note:"Feminine of 'der Chef.' The '-in' suffix marks feminine job titles.",example:"A: Wer ist deine Chefin?\nB: Meine Chefin heißt Frau Schneider. Sie ist sehr nett.",exampleSrc:"A: Who is your boss?\nB: My boss is called Mrs. Schneider. She is very nice.",funFact:"Germany had a fierce debate about gendering job titles. Traditionally 'der Chef' covered everyone. Now 'die Chefin' is standard for women. Some texts use 'Chef:in' or 'Chef*in' to include everyone. Language evolves!"},
{type:"mc",q:"'Meine Chefin hat mir einen Bescheid geschickt.' Who sent the notice?",opts:["My male boss","My female boss","My colleague","My babysitter"],ans:"My female boss",hint:"The '-in' suffix on 'Chef' tells you the gender."},
{type:"tip",title:"A2 Grammar Power Review",text:"You have learned all of these in A2. Let's combine them!\n\n1. Perfekt: Ich habe/bin + Partizip II\n2. Dative: mit dem/der/den + noun\n3. Wechselpräpositionen: auf den Tisch (wohin?) vs. auf dem Tisch (wo?)\n4. weil/dass/wenn/ob: verb goes to the END\n5. Reflexive: sich freuen, sich anmelden\n6. Adjective endings: ein neuer Laptop, das neue Tablet\n7. Konjunktiv II: würde + Infinitiv, wäre, hätte\n8. Conjunctions: aber, oder, denn, und (V2) vs. weil, dass, wenn (verb-final)"},
{type:"mc",q:"'Ich habe mich auf der Webseite angemeldet, weil ich eine Ermäßigung wollte.' Why did the person register?",opts:["Because they wanted a discount","Because they needed permission","Because they got a notification","Because they bought a laptop"],ans:"Because they wanted a discount",hint:"The 'weil' clause explains the reason. What does 'Ermäßigung' mean?"},
{type:"fb",s:"Wenn ich die Erlaubnis {1}, kann ich den Antrag stellen.",a:["bekomme"],opts:["bekomme","bekommen","bekam","bekommt"],hint:"In a 'wenn' clause, the conjugated verb goes to the end. Subject is 'ich.'",sSrc:"If I {1} permission, I can submit the application."},
{type:"drag_fill",s:"KD hat {1} auf {2} Laptop die Dokumente {3}.",blanks:{"1":"schnell","2":"ihrem","3":"geprüft"},pool:["schnell","ihrem","geprüft","langsam","seinem","geschrieben"],hint:"Perfekt + dative possessive + adverb. 'Auf' with static location takes dative.",sSrc:"KD has {1} checked the documents on {2} laptop {3}."},
{type:"mc",q:"'Wenn das Wetter schöner wäre, würde ich draußen sitzen.' What tense is this?",opts:["Simple past (Präteritum)","Present tense (Präsens)","Konjunktiv II (subjunctive)","Future tense (Futur I)"],ans:"Konjunktiv II (subjunctive)",hint:"'Wäre' and 'würde' signal an unreal or hypothetical situation."},
{type:"drag_fill",s:"Er hat {1} über die neue Ermäßigung {2}, weil er {3} Paar Schuhe kaufen {4}.",blanks:{"1":"sich","2":"gefreut","3":"ein","4":"wollte"},pool:["sich","gefreut","ein","wollte","mich","gesucht","einen","konnte"],hint:"Reflexive Perfekt + weil-clause with modal verb at the end.",sSrc:"He {1} about the new discount {2} because he {3} a pair of shoes {4}."},
{type:"fb",s:"Die Chefin hat den Bescheid an {1} neuen Babysitter geschickt.",a:["den"],opts:["den","dem","der","das"],hint:"'An' + accusative when indicating the recipient of a directed action.",sSrc:"The boss sent the notification to {1} new babysitter."},
{type:"mc",q:"'Ich hätte gern eine Ermäßigung.' What is the speaker doing?",opts:["Demanding a discount angrily","Politely requesting a discount","Refusing a discount","Complaining about a discount"],ans:"Politely requesting a discount",hint:"'Hätte gern' is the polite Konjunktiv II form for making requests."},
{type:"drag_fill",s:"Nachdem Verumius {1} auf der Webseite {2} hatte, bekam er {3} Bescheid per E-Mail.",blanks:{"1":"sich","2":"angemeldet","3":"einen"},pool:["sich","angemeldet","einen","mich","abgemeldet","einem"],hint:"Reflexive Plusquamperfekt in the nachdem clause. 'Bescheid' is masculine: einen.",sSrc:"After Verumius {1} registered on the website {2}, he received {3} notification by email."},
{type:"fb",s:"Wenn ich ein Tablet {1}, würde ich die Webseite öffnen.",a:["hätte"],opts:["hätte","habe","hatte","hat"],hint:"This is an unreal condition. The 'wenn' clause needs Konjunktiv II of 'haben.'",sSrc:"If I {1} a tablet, I would open the website."},
{type:"mc",q:"'Stell den Laptop auf den Tisch!' What grammar is used here?",opts:["Konjunktiv II polite request form","Perfekt narration of a past event","Imperative with Wechselpräposition","Passive voice descriptive instruction"],ans:"Imperative with Wechselpräposition",hint:"'Stell!' is a command form. 'Auf den Tisch' shows direction (accusative)."},
{type:"drag_fill",s:"Die Chefin sagte, {1} der Service besser {2} {3}, wenn alle Mitarbeiter pünktlich {4}.",blanks:{"1":"dass","2":"sein","3":"würde","4":"kämen"},pool:["dass","sein","würde","kämen","weil","haben","konnte","kommen"],hint:"Dass-clause + Konjunktiv II. The subjunctive helper goes to the end of the clause.",sSrc:"The boss said {1} the service {2} be better {3} if all employees {4} punctual."},
{type:"story",speaker:"narrator",mood:"warm",trg:"KD stempelt das letzte Dokument. Sie schaut Verumius an. 'Sie haben alles richtig gemacht. Das passiert selten.' Dann, ganz leise: 'Kommen Sie gut nach Hause.' War das... Freundlichkeit?",src:"KD stamps the last document. She looks at Verumius. 'You did everything right. That rarely happens.' Then, very quietly: 'Get home safely.' Was that... friendliness?"},
{type:"match",pairs:[{trg:"die Erlaubnis",src:"the permission"},{trg:"die Ermäßigung",src:"the discount"},{trg:"der Bescheid",src:"the notice"},{trg:"das Paar",src:"the pair/couple"},{trg:"die Webseite",src:"the website"},{trg:"der Laptop",src:"the laptop"},{trg:"das Tablet",src:"the tablet"},{trg:"der Service",src:"the service"},{trg:"der Babysitter",src:"the babysitter"},{trg:"die Chefin",src:"the female boss"}]}
]}
,

// U12 L7: Noch mehr Wörter - Remaining A2 verbs and adjectives
{id:"deu_r12l7",title:"Noch mehr Wörter",icon:"\uD83D\uDCDA",xp:15,board:true,steps:[
{type:"intro",title:"Noch mehr Wörter",desc:"Twenty more verbs that Germans use every day at work, in emails, and in difficult conversations. Master these and your A2 vocabulary is nearly complete.",goals:["Learn 20 essential A2 verbs","Use reflexive verbs with sich","Practice formal and informal register"]},

// ─── Group 1: Office & Work Verbs ───
{type:"teach",trg:"ändern",src:"to change",note:"Regular verb. Ich ändere, du änderst, er ändert.",example:"A: Können wir den Termin ändern?\nB: Ja, ich ändere ihn sofort.",exampleSrc:"A: Can we change the appointment?\nB: Yes, I'll change it right away.",funFact:"'Ändern' comes from 'ander' (other). To change something is literally to 'make it other.' The noun is 'die Änderung' (the change)."},
{type:"teach",trg:"beenden",src:"to end / to finish",note:"Regular. Ich beende, du beendest. The 'be-' prefix is inseparable.",example:"A: Wann beendest du das Projekt?\nB: Ich beende es morgen.",exampleSrc:"A: When will you finish the project?\nB: I'll finish it tomorrow.",funFact:"'Be-' is one of German's most common inseparable prefixes. Unlike 'auf-' or 'an-', it never splits off. Beenden, beginnen, bekommen: 'be-' always stays glued."},
{type:"teach",trg:"notieren",src:"to note down / to write down",note:"Regular. Ich notiere, du notierst. From Latin 'notare.'",example:"A: Notieren Sie bitte die Telefonnummer.\nB: Moment, ich notiere sie.",exampleSrc:"A: Please note down the phone number.\nB: One moment, I'm writing it down.",funFact:"German borrowed this from Latin via French. 'Notiz' (note), 'notieren' (to note), 'Notizbuch' (notebook). The Latin root 'nota' means a mark or sign."},
{type:"teach",trg:"kündigen",src:"to quit / to terminate (a contract)",note:"Regular. Ich kündige, du kündigst. Used for jobs and contracts.",example:"A: Warum hast du gekündigt?\nB: Ich habe eine bessere Stelle gefunden.",exampleSrc:"A: Why did you quit?\nB: I found a better position.",funFact:"'Kündigen' comes from 'kund' (known). To quit is to 'make known' your departure. The noun 'die Kündigung' appears in every German employment contract."},
{type:"mc",q:"Your colleague says 'Ich muss den Termin ändern.' What does she want to do?",opts:["Cancel the meeting","Change the appointment","Start the project","Finish the work"],ans:"Change the appointment",hint:"The verb means to make something different from what it was."},
{type:"fb",s:"Bitte {1} Sie die Adresse.",a:["notieren"],opts:["notieren","kündigen","beenden","ändern"],hint:"Which verb means to write something down for later reference?",sSrc:"Please {1} the address."},

// ─── Group 2: Communication Verbs ───
{type:"teach",trg:"beantworten",src:"to answer (a question/email)",note:"Regular. Ich beantworte, du beantwortest. Inseparable 'be-' prefix.",example:"A: Hast du meine E-Mail beantwortet?\nB: Nein, ich beantworte sie heute Abend.",exampleSrc:"A: Did you answer my email?\nB: No, I'll answer it this evening.",funFact:"'Beantworten' always needs a direct object (the question/email). 'Antworten' (without 'be-') takes a dative person: 'Ich antworte dir' vs. 'Ich beantworte deine Frage.'"},
{type:"teach",trg:"berichten",src:"to report",note:"Regular. Ich berichte, du berichtest. Inseparable prefix.",example:"A: Die Zeitung berichtet über den Unfall.\nB: Was berichten sie genau?",exampleSrc:"A: The newspaper is reporting on the accident.\nB: What exactly are they reporting?",funFact:"'Bericht' (report) + '-en' makes the verb. Germans love turning nouns into verbs: Arbeit to arbeiten, Antwort to antworten, Bericht to berichten."},
{type:"teach",trg:"beraten",src:"to advise / to consult",note:"Irregular: er berät (stem change a to ä). Inseparable prefix.",example:"A: Wer berät Sie bei Steuerfragen?\nB: Mein Steuerberater berät mich.",exampleSrc:"A: Who advises you on tax questions?\nB: My tax advisor advises me.",funFact:"'Steuerberater' (tax advisor) is one of Germany's most important professions. Germans take taxes very seriously, and nearly everyone has one."},
{type:"teach",trg:"übersetzen",src:"to translate",note:"Regular with inseparable 'über-'. Ich übersetze, du übersetzt.",example:"A: Kannst du das ins Englische übersetzen?\nB: Ja, ich übersetze es dir.",exampleSrc:"A: Can you translate that into English?\nB: Yes, I'll translate it for you.",funFact:"Literally 'to set over' from one language to another. The noun 'der Übersetzer' means translator. Fun twist: 'übersetzen' with separable stress means 'to cross over' (a river)."},
{type:"mc",q:"'Können Sie meinen Brief beantworten?' What is being asked?",opts:["Can you write my letter?","Can you translate my letter?","Can you answer my letter?","Can you send my letter?"],ans:"Can you answer my letter?",hint:"The inseparable 'be-' prefix is attached to 'Antwort' (answer)."},
{type:"fb",s:"Kannst du den Text ins Deutsche {1}?",a:["übersetzen"],opts:["übersetzen","berichten","beantworten","beraten"],hint:"Which verb means converting words from one language to another?",sSrc:"Can you {1} the text into German?"},

// ─── Group 3: Reflexive & Formal Verbs ───
{type:"teach",trg:"sich bedanken",src:"to thank / to express thanks",note:"Reflexive. Ich bedanke mich, du bedankst dich.",example:"A: Ich möchte mich bei Ihnen bedanken.\nB: Oh, das ist sehr nett von Ihnen!",exampleSrc:"A: I would like to thank you.\nB: Oh, that is very kind of you!",funFact:"The reflexive 'sich' makes it literally 'to thank oneself.' German reflexives often express actions you do for your own benefit. More formal than simply saying 'Danke.'"},
{type:"teach",trg:"sich beschweren",src:"to complain",note:"Reflexive. Ich beschwere mich, du beschwerst dich.",example:"A: Ich beschwere mich über den Lärm.\nB: Bei wem beschwerst du dich?",exampleSrc:"A: I'm complaining about the noise.\nB: Who are you complaining to?",funFact:"Uses 'über' (about) for the topic and 'bei' (to/at) for the person. 'Die Beschwerde' (complaint) is a word every German tenant knows well."},
{type:"teach",trg:"sich bewerben",src:"to apply (for a job/position)",note:"Irregular reflexive: er bewirbt sich (stem change e to i).",example:"A: Ich bewerbe mich um die Stelle.\nB: Viel Glück bei deiner Bewerbung!",exampleSrc:"A: I'm applying for the position.\nB: Good luck with your application!",funFact:"The noun 'die Bewerbung' (application) is sacred in German job culture. A proper Bewerbung includes a cover letter, CV with photo, and copies of all certificates. Missing one piece? Straight to the rejection pile."},
{type:"teach",trg:"begründen",src:"to justify / to give reasons for",note:"Regular. Ich begründe, du begründest. From 'Grund' (reason).",example:"A: Können Sie Ihre Entscheidung begründen?\nB: Ja, ich begründe sie gern.",exampleSrc:"A: Can you justify your decision?\nB: Yes, I'll gladly give my reasons.",funFact:"'Grund' means both 'reason' and 'ground/bottom.' To justify is to 'give it a ground to stand on.' Very German: even arguments need solid foundations."},
{type:"mc",q:"'Ich bewerbe mich um die Stelle als Lehrer.' What is the speaker doing?",opts:["Quitting a teaching job","Complaining about the teacher","Applying for a teaching position","Thanking the teacher"],ans:"Applying for a teaching position",hint:"The reflexive verb 'sich bewerben um' indicates seeking a specific role."},
{type:"fb",s:"Ich möchte mich bei Ihnen {1}.",a:["bedanken"],opts:["bedanken","beschweren","bewerben","begründen"],hint:"Which reflexive verb expresses gratitude formally?",sSrc:"I would like to {1} you."},

// ─── Group 4: Remaining Essential Verbs ───
{type:"teach",trg:"bestehen",src:"to pass (an exam) / to exist",note:"Irregular: bestand, bestanden. 'Die Prüfung bestehen' = to pass the exam.",example:"A: Hast du die Prüfung bestanden?\nB: Ja, ich habe sie bestanden!",exampleSrc:"A: Did you pass the exam?\nB: Yes, I passed it!",funFact:"'Bestehen' has two very different meanings: 'to pass' (an exam) and 'to exist/consist of.' 'Das Problem besteht seit Jahren' = The problem has existed for years."},
{type:"teach",trg:"bestätigen",src:"to confirm",note:"Regular. Ich bestätige, du bestätigst. Very common in emails.",example:"A: Können Sie den Termin bestätigen?\nB: Ja, hiermit bestätige ich den Termin.",exampleSrc:"A: Can you confirm the appointment?\nB: Yes, I hereby confirm the appointment.",funFact:"'Hiermit bestätige ich...' (I hereby confirm...) is the classic opening of German business emails. Formal, precise, and very satisfying to write."},
{type:"teach",trg:"verbieten",src:"to forbid / to prohibit",note:"Irregular: verbot, verboten. 'Verboten' is Germany's favorite sign.",example:"A: Rauchen ist hier verboten.\nB: Oh, Entschuldigung! Ich wusste das nicht.",exampleSrc:"A: Smoking is forbidden here.\nB: Oh, sorry! I didn't know that.",funFact:"'Verboten' might be the most German word ever. Germans love rules and signs: Betreten verboten (no trespassing), Rauchen verboten (no smoking), Fotografieren verboten (no photos). If it exists, it can be verboten."},
{type:"teach",trg:"verschieben",src:"to postpone / to move to a later date",note:"Irregular: verschob, verschoben. Inseparable prefix.",example:"A: Wir müssen das Meeting verschieben.\nB: Auf wann verschieben wir es?",exampleSrc:"A: We have to postpone the meeting.\nB: To when shall we postpone it?",funFact:"Literally 'to push away.' 'Ver-' intensifies + 'schieben' (to push). Germans also say 'auf die lange Bank schieben' (to push onto the long bench) for procrastinating."},
{type:"mc",q:"A sign says 'Fotografieren verboten.' What must you NOT do?",opts:["Eat here","Park here","Take photos","Enter this area"],ans:"Take photos",hint:"'Fotografieren' looks very similar to its English equivalent."},
{type:"fb",s:"Können wir das Meeting auf Freitag {1}?",a:["verschieben"],opts:["verschieben","verbieten","bestehen","bestätigen"],hint:"Which verb means to push an event to a later time?",sSrc:"Can we {1} the meeting to Friday?"},

// ─── Group 5: Final Verbs ───
{type:"teach",trg:"lügen",src:"to lie (tell an untruth)",note:"Irregular: log, gelogen. Ich lüge, du lügst.",example:"A: Lügst du?\nB: Nein, ich lüge nie!",exampleSrc:"A: Are you lying?\nB: No, I never lie!",funFact:"'Lügen' and English 'lie' are direct cousins from the same Germanic root. The saying 'Lügen haben kurze Beine' (lies have short legs) means lies don't get you far."},
{type:"teach",trg:"merken",src:"to notice / to remember",note:"Regular. 'Sich merken' (reflexive) = to memorize.",example:"A: Hast du das gemerkt?\nB: Ja, ich habe es sofort gemerkt.",exampleSrc:"A: Did you notice that?\nB: Yes, I noticed it immediately.",funFact:"Two uses in one verb: 'merken' = to notice, 'sich merken' = to remember. 'Merk dir das!' (Remember that!) is something German parents say constantly."},
{type:"teach",trg:"nennen",src:"to name / to call",note:"Irregular: nannte, genannt. 'Man nennt ihn...' = They call him...",example:"A: Wie nennt man das auf Deutsch?\nB: Man nennt es 'Schmetterling.'",exampleSrc:"A: What do you call that in German?\nB: You call it 'Schmetterling' (butterfly).",funFact:"'Nennen' is related to English 'name.' The past participle 'genannt' appears in historical texts: 'Karl der Große, auch Karl I. genannt' (Charlemagne, also called Charles I)."},
{type:"teach",trg:"leidtun",src:"to be sorry",note:"Separable. 'Es tut mir leid' = I'm sorry. Literally: 'It does suffering to me.'",example:"A: Es tut mir leid, ich bin zu spät.\nB: Kein Problem!",exampleSrc:"A: I'm sorry, I'm late.\nB: No problem!",funFact:"One of German's most poetic phrases. 'Leid' means suffering/sorrow, 'tun' means to do. Saying sorry in German is admitting 'it causes me sorrow.' Deeply emotional for such a practical language."},
{type:"mc",q:"'Es tut mir leid, ich kann heute nicht kommen.' What is the speaker expressing?",opts:["Excitement about coming","A request to come later","An apology for not being able to come","A complaint about the event"],ans:"An apology for not being able to come",hint:"The phrase at the beginning expresses regret or sorrow."},
{type:"drag_fill",s:"Wie {1} man das auf Deutsch? Man {2} es 'Rathaus.'",blanks:{"1":"nennt","2":"nennt"},pool:["nennt","merkt","lügt","sagt"],hint:"Both blanks need the same verb meaning 'to call or name.'",sSrc:"How do you {1} that in German? You {2} it 'Rathaus.'"},
{type:"match",pairs:[{trg:"ändern",src:"to change"},{trg:"kündigen",src:"to quit"},{trg:"übersetzen",src:"to translate"},{trg:"sich bewerben",src:"to apply"},{trg:"verbieten",src:"to forbid"},{trg:"leidtun",src:"to be sorry"},{trg:"bestätigen",src:"to confirm"},{trg:"verschieben",src:"to postpone"}]},
{type:"match",pairs:[{trg:"beantworten",src:"to answer"},{trg:"berichten",src:"to report"},{trg:"beraten",src:"to advise"},{trg:"sich bedanken",src:"to thank"},{trg:"sich beschweren",src:"to complain"},{trg:"bestehen",src:"to pass (exam)"},{trg:"lügen",src:"to lie"},{trg:"merken",src:"to notice"}]},
{type:"teach",trg:"eintragen",src:"to register / to enter (data)",example:"A: Tragen Sie bitte Ihren Namen ein.\nB: Hier? In diese Zeile?\nA: Ja, genau dort.",exampleSrc:"A: Please enter your name.\nB: Here? On this line?\nA: Yes, right there.",note:"Separable: ich trage ein. Used for forms, lists, and calendars.",funFact:"Germans love forms. 'Bitte eintragen' (please fill in) appears on every official document."},
{type:"teach",trg:"ganz",src:"whole / quite / entirely",example:"A: Hast du das ganze Buch gelesen?\nB: Ja, ganz! Es war ganz toll.",exampleSrc:"A: Did you read the whole book?\nB: Yes, all of it! It was quite great.",note:"ganz = whole (adjective) or quite/entirely (adverb). Context decides the meaning.",funFact:"'Ganz und gar' means completely. 'Ganz und gar nicht' means not at all. Tiny word, big range."},
{type:"teach",trg:"preiswert",src:"affordable / good value",example:"A: Das Restaurant ist preiswert.\nB: Ja, und das Essen schmeckt gut!",exampleSrc:"A: The restaurant is affordable.\nB: Yes, and the food tastes good!",note:"Preis (price) + wert (worth). Literally: worth the price. Nicer than 'billig' (cheap).",funFact:"Germans avoid saying 'billig' for good deals because it implies low quality. 'Preiswert' or 'günstig' sound much better."},
{type:"teach",trg:"privat",src:"private",example:"A: Ist das eine private Frage?\nB: Ja, du musst nicht antworten.",exampleSrc:"A: Is that a private question?\nB: Yes, you don't have to answer.",note:"Cognate with English. Privat: for personal matters, not public.",funFact:"Germans value Privatsphäre (privacy) highly. Asking about salary or rent is considered very privat."},
{type:"teach",trg:"schriftlich",src:"written / in writing",example:"A: Bitte bestätigen Sie schriftlich.\nB: Ich schicke Ihnen eine Mail.",exampleSrc:"A: Please confirm in writing.\nB: I will send you an email.",note:"From Schrift (writing/font). Mündlich = oral, schriftlich = written.",funFact:"German bureaucracy loves the word 'schriftlich.' Nothing is official until it is schriftlich."},
{type:"teach",trg:"stressig",src:"stressful",example:"A: Wie war dein Tag?\nB: Sehr stressig! Ich brauche Ruhe.",exampleSrc:"A: How was your day?\nB: Very stressful! I need rest.",note:"Stress + -ig ending. Colloquial but widely used.",funFact:"'Stressig' entered German from English stress. The -ig suffix makes it an adjective, following the same pattern as sonnig, windig."},
{type:"teach",trg:"schrecklich",src:"terrible / dreadful",example:"A: Wie war das Wetter?\nB: Schrecklich! Es hat den ganzen Tag geregnet.",exampleSrc:"A: How was the weather?\nB: Terrible! It rained all day.",note:"From Schreck (fright/shock). Schrecklich = causing fright.",funFact:"Also used for emphasis: 'schrecklich nett' (terribly nice). Like English 'awfully good.'"},
{type:"teach",trg:"nirgends",src:"nowhere",example:"A: Wo ist mein Schlüssel?\nB: Nirgends! Ich habe überall gesucht.",exampleSrc:"A: Where is my key?\nB: Nowhere! I looked everywhere.",note:"Opposite of überall (everywhere). Also: nirgendwo (same meaning).",funFact:"Nirgends and überall are a natural pair. Germans love opposites: nirgends/überall, niemand/jemand, nichts/alles."},
{type:"teach",trg:"wenigstens",src:"at least",example:"A: Ich habe die Prüfung nicht bestanden.\nB: Wenigstens hast du es versucht!",exampleSrc:"A: I didn't pass the exam.\nB: At least you tried!",note:"From wenig (little) + -stens. Similar to mindestens but more emotional/consoling.",funFact:"'Wenigstens' is for consolation: 'at least this happened.' 'Mindestens' is for minimums: 'at least 3 hours.'"},
{type:"teach",trg:"einverstanden",src:"agreed / in agreement",example:"A: Treffen wir uns um drei?\nB: Einverstanden!\nA: Super, bis dann!",exampleSrc:"A: Shall we meet at three?\nB: Agreed!\nA: Great, see you then!",note:"Ein + verstanden (understood). 'Ich bin einverstanden' = I agree. Very formal.",funFact:"On contracts: 'Hiermit erkläre ich mich einverstanden' (I hereby declare my agreement). The most German sentence ever written."}
]}
,

{id:"deu_r12l8",title:"Das letzte Kapitel",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Das letzte Kapitel",desc:"Zwanzig neue Wörter zum Abschluss: Alltag, Schule und mehr.",goals:["20 neue Nomen und Adjektive lernen","Über Schule und Alltag sprechen","Wortschatz festigen"]},
{type:"teach",trg:"das Fach",src:"subject / compartment",phonetic:"fakh",example:"A: Welches Fach magst du am liebsten?\nB: Ich mag Mathe, das ist mein bestes Fach.",exampleSrc:"A: Which subject do you like best?\nB: I like maths, that's my best subject.",note:"Neuter. Plural: Fächer. Means both a school subject and a compartment.",funFact:"In Germany, students often have 12 or more Fächer on their timetable."},
{type:"teach",trg:"die Fundsache",src:"lost property",phonetic:"FOONT-za-khuh",example:"A: Ist das deine Fundsache?\nB: Ja, ich habe meinen Schirm im Bus vergessen.",exampleSrc:"A: Is that your lost property?\nB: Yes, I forgot my umbrella on the bus.",note:"Feminine. Compound: Fund (find) + Sache (thing).",funFact:"German trains have a central Fundbüro (lost property office) in every major station."},
{type:"teach",trg:"die Geldbörse",src:"wallet",phonetic:"GELT-beur-zuh",example:"A: Hast du deine Geldbörse dabei?\nB: Oh nein, sie liegt noch zu Hause!",exampleSrc:"A: Do you have your wallet with you?\nB: Oh no, it's still at home!",note:"Feminine. Compound: Geld (money) + Börse (purse).",funFact:"Germans still use cash more than most Europeans, so a good Geldbörse is essential."},
{type:"teach",trg:"die Note",src:"grade",phonetic:"NOH-tuh",example:"A: Welche Note hast du in Deutsch bekommen?\nB: Ich habe eine Zwei bekommen!",exampleSrc:"A: What grade did you get in German?\nB: I got a two!",note:"Feminine. German grades go from 1 (best) to 6 (worst).",funFact:"A German 1 is called 'sehr gut' (very good). Anything below 4 is a fail."},
{type:"teach",trg:"das Produkt",src:"product",phonetic:"pro-DUKT",example:"A: Ist das ein gutes Produkt?\nB: Ja, die Qualität ist wirklich toll.",exampleSrc:"A: Is that a good product?\nB: Yes, the quality is really great.",note:"Neuter. Plural: Produkte. Cognate with English 'product'.",funFact:"'Made in Germany' was originally a British warning label in 1887. Germans turned it into a quality mark."},
{type:"mc",q:"Was bedeutet 'die Note' auf Englisch?",opts:["grade","note (music only)","notebook","nothing"],ans:"grade",hint:"Think of school results, not music."},
{type:"teach",trg:"der Rentner",src:"retiree (male)",phonetic:"RENT-nuh",example:"A: Ist dein Opa schon Rentner?\nB: Ja, er ist seit zwei Jahren Rentner.",exampleSrc:"A: Is your grandpa retired already?\nB: Yes, he's been retired for two years.",note:"Masculine. Female form: die Rentnerin.",funFact:"Germany's retirement age is gradually rising to 67 by 2031."},
{type:"teach",trg:"die Rentnerin",src:"retiree (female)",phonetic:"RENT-nuh-rin",example:"A: Was macht die Rentnerin jeden Morgen?\nB: Sie geht im Park spazieren.",exampleSrc:"A: What does the retiree do every morning?\nB: She goes for a walk in the park.",note:"Feminine. The -in suffix marks female form, as with many German professions.",funFact:"Over 20% of Germany's population are Rentner or Rentnerinnen."},
{type:"teach",trg:"das Schlafzimmer",src:"bedroom",phonetic:"SHLAHF-tsim-uh",example:"A: Wie groß ist dein Schlafzimmer?\nB: Es ist ziemlich klein, aber gemütlich.",exampleSrc:"A: How big is your bedroom?\nB: It's quite small but cosy.",note:"Neuter. Compound: Schlaf (sleep) + Zimmer (room).",funFact:"Germans love airing their Schlafzimmer daily, even in winter. Fresh air is serious business."},
{type:"teach",trg:"das Schloss",src:"castle / lock",phonetic:"shloss",example:"A: Hast du das Schloss in Heidelberg gesehen?\nB: Ja, es war wunderschön!",exampleSrc:"A: Have you seen the castle in Heidelberg?\nB: Yes, it was beautiful!",note:"Neuter. Plural: Schlösser. Context tells you: castle or lock.",funFact:"Germany has over 20,000 Schlösser and castles. That's more than any other country in Europe."},
{type:"fb",s:"Mein {1} ist sehr klein, aber ich schlafe gut.",a:"Schlafzimmer",opts:["Schlafzimmer","Schloss","Fach","Supermarkt"],hint:"Where do you sleep at home?",sSrc:"My {1} is very small, but I sleep well."},
{type:"teach",trg:"die Schülerin",src:"female student (school)",phonetic:"SHOO-luh-rin",example:"A: Ist Lisa eine gute Schülerin?\nB: Ja, sie bekommt immer gute Noten.",exampleSrc:"A: Is Lisa a good student?\nB: Yes, she always gets good grades.",note:"Feminine. Male form: der Schüler. For school students, not university.",funFact:"German Schüler and Schülerinnen typically don't wear school uniforms."},
{type:"teach",trg:"die Seite",src:"page / side",phonetic:"ZAI-tuh",example:"A: Auf welcher Seite ist die Übung?\nB: Auf Seite 42, ganz unten.",exampleSrc:"A: On which page is the exercise?\nB: On page 42, at the bottom.",note:"Feminine. Dual meaning: page of a book, or side of something.",funFact:"The German word Webseite (webpage) uses this same Seite for 'page'."},
{type:"teach",trg:"die Studentin",src:"female student (university)",phonetic:"shtoo-DEN-tin",example:"A: Was studiert die Studentin?\nB: Sie studiert Medizin in Berlin.",exampleSrc:"A: What does the student study?\nB: She studies medicine in Berlin.",note:"Feminine. Male form: der Student. Only for university students.",funFact:"German universities charge almost no tuition. Most Studenten pay under 300 EUR per semester."},
{type:"mc",q:"Welches Wort beschreibt eine Frau an der Universität?",opts:["die Studentin","die Schülerin","die Rentnerin","die Kollegin"],ans:"die Studentin",hint:"University, not school or workplace."},
{type:"teach",trg:"der Supermarkt",src:"supermarket",phonetic:"ZOO-puh-markt",example:"A: Gehst du heute zum Supermarkt?\nB: Ja, wir brauchen Milch und Brot.",exampleSrc:"A: Are you going to the supermarket today?\nB: Yes, we need milk and bread.",note:"Masculine. Plural: Supermärkte. Direct cognate with English.",funFact:"German supermarkets close on Sundays. Forgetting your Saturday shopping is a real problem."},
{type:"teach",trg:"das Taschengeld",src:"pocket money",phonetic:"TA-shen-gelt",example:"A: Bekommst du Taschengeld?\nB: Ja, zehn Euro pro Woche.",exampleSrc:"A: Do you get pocket money?\nB: Yes, ten euros per week.",note:"Neuter. Compound: Tasche (pocket/bag) + Geld (money).",funFact:"Studies show German children get an average of 25 EUR Taschengeld per month."},
{type:"teach",trg:"die Tasse",src:"cup",phonetic:"TA-suh",example:"A: Möchtest du eine Tasse Kaffee?\nB: Ja, gerne, mit Milch bitte.",exampleSrc:"A: Would you like a cup of coffee?\nB: Yes, please, with milk.",note:"Feminine. Plural: Tassen. Used for cups with handles (mugs too).",funFact:"Germans drink about 164 litres of coffee per person per year. That's a lot of Tassen."},
{type:"teach",trg:"die Universität",src:"university",phonetic:"oo-nee-ver-zee-TAYT",example:"A: An welcher Universität studierst du?\nB: Ich studiere an der Universität München.",exampleSrc:"A: At which university do you study?\nB: I study at the University of Munich.",note:"Feminine. Often shortened to Uni in everyday speech.",funFact:"The oldest German Universität is Heidelberg, founded in 1386."},
{type:"fb",s:"Möchtest du eine {1} Tee?",a:"Tasse",opts:["Tasse","Seite","Geldbörse","Note"],hint:"A container you drink from.",sSrc:"Would you like a {1} of tea?"},
{type:"teach",trg:"die Werkstatt",src:"workshop / garage",phonetic:"VERK-shtat",example:"A: Wo ist dein Auto?\nB: Es ist in der Werkstatt, der Motor ist kaputt.",exampleSrc:"A: Where is your car?\nB: It's in the workshop, the engine is broken.",note:"Feminine. Plural: Werkstätten. Werk (work) + Statt (place).",funFact:"Germany's TÜV vehicle inspections are famously strict. Werkstätten are always busy before TÜV dates."},
{type:"teach",trg:"die Kollegin",src:"female colleague",phonetic:"ko-LAY-gin",example:"A: Kennst du meine Kollegin Frau Weber?\nB: Ja, sie arbeitet im dritten Stock.",exampleSrc:"A: Do you know my colleague Mrs Weber?\nB: Yes, she works on the third floor.",note:"Feminine. Male form: der Kollege (not Kolleg!).",funFact:"Germans typically use Sie (formal you) with Kollegen unless they agree to switch to du."},
{type:"teach",trg:"aktuell",src:"current / up-to-date",phonetic:"ak-too-ELL",example:"A: Ist das die aktuelle Speisekarte?\nB: Ja, wir haben sie letzte Woche geändert.",exampleSrc:"A: Is this the current menu?\nB: Yes, we changed it last week.",note:"False friend alert! Aktuell does NOT mean 'actual'. It means 'current'.",funFact:"This is the most famous German false friend. 'Tatsächlich' is the real word for 'actually'."},
{type:"teach",trg:"echt",src:"real / genuine / really",phonetic:"ekht",example:"A: Ist der Ring echt?\nB: Ja, das ist echtes Gold!",exampleSrc:"A: Is the ring real?\nB: Yes, that's real gold!",note:"Adjective and adverb. Also used colloquially: 'Echt?' means 'Really?'",funFact:"Young Germans use 'echt' constantly in speech, similar to 'literally' in English."},
{type:"teach",trg:"eigentlich",src:"actually / really",phonetic:"AI-gent-likh",example:"A: Was wolltest du eigentlich sagen?\nB: Ich wollte fragen, ob du morgen Zeit hast.",exampleSrc:"A: What did you actually want to say?\nB: I wanted to ask if you have time tomorrow.",note:"Adverb. Often softens a question: 'Wie heißt du eigentlich?' (What's your name, by the way?)",funFact:"Eigentlich is one of those untranslatable German words. It can mean 'actually', 'really', or 'by the way'."},
{type:"teach",trg:"total",src:"total / totally",example:"A: Das war total verrückt!\nB: Ja, total! Aber auch lustig.",exampleSrc:"A: That was totally crazy!\nB: Yes, totally! But also funny.",note:"Cognate. Used as adjective and adverb. Very colloquial when used for emphasis.",funFact:"Young Germans use 'total' like Americans use 'totally.' 'Das ist total cool!' Borrowed directly from English."},
{type:"teach",trg:"heraus",src:"out (from inside)",example:"A: Komm heraus!\nB: Ich komme gleich raus!",exampleSrc:"A: Come out!\nB: I am coming out right away!",note:"Direction adverb: movement from inside to outside. Short form: raus. Many compounds: herausfinden, herausgeben.",funFact:"'Heraus' is formal, 'raus' is everyday. 'Raus hier!' (Get out!) is one of the first commands kids learn."},
{type:"teach",trg:"herein",src:"in / inside (come in)",example:"A: Darf ich?\nB: Ja, herein!\nA: Danke!",exampleSrc:"A: May I?\nB: Yes, come in!\nA: Thank you!",note:"Direction adverb: movement from outside to inside. Short form: rein. Herein! = Come in!",funFact:"When you knock on an office door in Germany, the answer is often just 'Herein!' One word. No 'please.' Very efficient."},
{type:"teach",trg:"der/die Nächste",src:"the next person",example:"A: Der Nächste bitte!\nB: Das bin ich!",exampleSrc:"A: Next please!\nB: That is me!",note:"From nächst (next). Der Nächste (masc.) or die Nächste (fem.). Used at counters and waiting rooms.",funFact:"'Der Nächste bitte!' is the universal sound of German waiting rooms, post offices, and bakery counters."},
{type:"tip",title:"Das deutsche Notensystem",text:"German schools use grades 1 to 6:\n1 = sehr gut (very good)\n2 = gut (good)\n3 = befriedigend (satisfactory)\n4 = ausreichend (sufficient, the minimum pass)\n5 = mangelhaft (poor)\n6 = ungenügend (insufficient)\nAt university, grades range from 1.0 to 5.0, with 4.0 as the pass threshold.",deepDive:"German report cards (Zeugnisse) are issued twice a year. The Halbjahreszeugnis comes in January/February, the Jahreszeugnis at the end of the school year in summer. Grades are taken very seriously: the Abitur average (Numerus Clausus) determines which university programmes you can enter."},
{type:"mc",q:"'Aktuell' bedeutet auf Englisch...",opts:["current","actual","active","acute"],ans:"current",hint:"A famous false friend for English speakers."},
{type:"mc",q:"Welches Wort passt? 'Das Buch hat 200 ___.'",opts:["Seiten","Noten","Fächer","Tassen"],ans:"Seiten",hint:"Think about what books are made of."},
{type:"fb",s:"Der Ring ist nicht {1}, er ist nur aus Plastik.",a:"echt",opts:["echt","aktuell","eigentlich","gut"],hint:"Genuine, the real thing.",sSrc:"The ring is not {1}, it is only made of plastic."},
{type:"mc",q:"Was ist eine Geldbörse?",opts:["a wallet","a money tree","a bank","a stock exchange"],ans:"a wallet",hint:"You carry it and keep cash inside."},
{type:"drag_fill",s:"Meine {1} arbeitet an der {2} in Hamburg.",blanks:{"1":"Kollegin","2":"Universität"},pool:["Kollegin","Universität","Werkstatt","Rentnerin"],hint:"A female colleague at a place of higher education.",sSrc:"My {1} works at the {2} in Hamburg."},
{type:"match",pairs:[{trg:"das Taschengeld",src:"pocket money"},{trg:"die Werkstatt",src:"workshop"},{trg:"der Supermarkt",src:"supermarket"},{trg:"die Fundsache",src:"lost property"},{trg:"das Schloss",src:"castle / lock"}]},
{type:"mc",q:"Lisa ist 16 und geht aufs Gymnasium. Wie nennt man sie?",opts:["eine Schülerin","eine Studentin","eine Rentnerin","eine Kollegin"],ans:"eine Schülerin",hint:"Someone who attends a school, not a university."},
{type:"fb",s:"Was hast du {1} heute Abend vor?",a:"eigentlich",opts:["eigentlich","aktuell","echt","endlich"],hint:"Softens the question, means 'actually' or 'by the way'.",sSrc:"What are you {1} planning for this evening?"},
{type:"drag_fill",s:"Die {1} bekommt immer gute {2} in jedem {3}.",blanks:{"1":"Schülerin","2":"Noten","3":"Fach"},pool:["Schülerin","Noten","Fach","Seite","Studentin"],hint:"A school student gets good grades in every subject.",sSrc:"The {1} always gets good {2} in every {3}."},
{type:"match",pairs:[{trg:"aktuell",src:"current"},{trg:"echt",src:"real / genuine"},{trg:"eigentlich",src:"actually"},{trg:"die Note",src:"grade"},{trg:"die Tasse",src:"cup"}]}
]},

{id:"deu_r12l9",title:"Die große Prüfung",icon:"✅",xp:30,board:true,steps:[
{type:"intro",title:"Die große Prüfung",desc:"Six months in Germany. Six units of grammar. Twenty-five constructs. This is the A2 capstone quiz. No new vocabulary, no hints from Hildi. Just you and the language.",goals:["Test ALL 25 A2 grammar constructs","Combine multiple constructs in single sentences","Prove you are ready for B1"]},

// 1. Perfekt haben + subordinate word order (multi)
{type:"fb",s:"Ich glaube, dass er das Buch schon {1} hat.",a:["gelesen"],opts:["gelesen","lesen","liest","las"],hint:"Perfekt in a dass-clause: the auxiliary goes to the very end.",sSrc:"I believe that he has already {1} the book."},

// 2. Perfekt sein + Partizip II (multi)
{type:"mc",q:"Mia sagt: 'Wir ___ gestern nach Hamburg ___.' Which pair completes the Perfekt?",opts:["sind ... gefahren","haben ... gefahren","sind ... fahren","haben ... fahrt"],ans:"sind ... gefahren",hint:"Motion verbs use a specific auxiliary in the Perfekt."},

// 3. Präteritum modals + dative (multi)
{type:"fb",s:"Der Arzt konnte {1} leider nicht helfen.",a:["mir"],opts:["mir","mich","ich","mein"],hint:"Helfen always takes a specific case for the person being helped.",sSrc:"The doctor unfortunately could not help {1}."},

// 4. Dative full + Wechselpräp (multi)
{type:"drag_fill",s:"Die Katze liegt {1} dem Tisch, aber der Hund springt {2} das Sofa.",blanks:{"1":"unter","2":"auf"},pool:["unter","auf","in","neben","über","an"],hint:"Lying somewhere is static (dative). Jumping somewhere is movement (accusative).",sSrc:"The cat is lying {1} the table, but the dog jumps {2} the sofa."},

// 5. Verbs with dative
{type:"mc",q:"'Das Essen ___ meiner Mutter sehr gut.' Which verb fits?",opts:["schmeckt","gefällt","braucht","gehört"],ans:"schmeckt",hint:"This dative verb describes how food tastes to someone."},

// 6. weil-clause + verb-final (multi)
{type:"fb",s:"Ich bleibe zu Hause, weil ich krank {1}.",a:["bin"],opts:["bin","ist","sein","bist"],hint:"In a weil-clause, the conjugated verb moves to which position?",sSrc:"I am staying at home because I {1} ill."},

// 7. dass-clause + reflexive verb (multi)
{type:"drag_fill",s:"Weißt du, dass {1} der Verein morgen {2}?",blanks:{"1":"sich","2":"trifft"},pool:["sich","mich","trifft","treffen","treffe","dich"],hint:"Sich treffen in a dass-clause: reflexive pronoun near the subject, verb at the end.",sSrc:"Do you know that {1} the club is meeting tomorrow {2}?"},

// 8. wenn-clause + Konjunktiv II (multi)
{type:"mc",q:"'Wenn ich mehr Zeit ___, ___ ich nach Italien fahren.' Fill both gaps.",opts:["hätte ... würde","habe ... werde","hatte ... wollte","hätte ... wollte"],ans:"hätte ... würde",hint:"This is an unreal condition about the present. Both verbs need a special mood."},

// 9. ob-clause + subordinate word order (multi)
{type:"fb",s:"Ich weiß nicht, ob er morgen {1}.",a:["kommt"],opts:["kommt","kommen","komme","kam"],hint:"After ob, the conjugated verb goes to a specific position in the clause.",sSrc:"I do not know whether he {1} tomorrow."},

// 10. Adjective declension nominative (definite + indefinite)
{type:"mc",q:"Which is correct? 'Ein ___ Pullover hängt im Schrank.'",opts:["warmer","warme","warmes","warmen"],ans:"warmer",hint:"After ein with a masculine noun, the adjective must show the gender."},

// 11. Adjective declension accusative + dative (multi)
{type:"drag_fill",s:"Ich kaufe {1} Schal und gebe ihn {2} Freund.",blanks:{"1":"den roten","2":"meinem besten"},pool:["den roten","der rote","dem roten","meinem besten","meinen besten","mein bester"],hint:"Buying uses accusative. Giving to someone uses dative.",sSrc:"I buy {1} scarf and give it to {2} friend."},

// 12. Possessives across cases + temporal prep (multi)
{type:"fb",s:"Nach {1} Geburtstag hat sie ihre Geschenke geöffnet.",a:["ihrem"],opts:["ihrem","ihrer","ihr","ihren"],hint:"Nach takes dative. Geburtstag is masculine. Which possessive form fits?",sSrc:"After {1} birthday she opened her presents."},

// 13. Comparative + superlative (multi)
{type:"mc",q:"'Berlin ist größer als München, aber Hamburg hat den ___ Hafen.' Which superlative fits?",opts:["größten","größer","großen","großes"],ans:"größten",hint:"After a definite article in accusative, the superlative adjective needs a specific ending."},

// 14. Reflexive verbs + reflexive pronouns (multi)
{type:"drag_fill",s:"Wir freuen {1} auf die Ferien und erinnern {2} an den letzten Sommer.",blanks:{"1":"uns","2":"uns"},pool:["uns","euch","sich","mich","mir","dich"],hint:"Both verbs are reflexive. The subject is wir, so both pronouns match.",sSrc:"We are looking forward {1} to the holidays and we remember {2} last summer."},

// 15. Imperative expanded (separable + irregular)
{type:"mc",q:"Your friend is sleeping late. Which imperative is correct?",opts:["Steh auf!","Stehe auf!","Aufstehen du!","Du steh auf!"],ans:"Steh auf!",hint:"Separable verbs in imperative: the prefix separates and goes to the end."},

// 16. Coordinating conjunctions + Perfekt (multi)
{type:"fb",s:"Ich wollte ins Kino gehen, {1} ich habe den Film schon gesehen.",a:["aber"],opts:["aber","weil","dass","denn"],hint:"You need a conjunction that shows contrast and keeps normal word order.",sSrc:"I wanted to go to the cinema, {1} I have already seen the film."},

// 17. Adverbs (time/manner) + verb position
{type:"mc",q:"'Verumius lernt ___ ___ Deutsch.' Which adverb order is correct?",opts:["jetzt gern","gern jetzt","Deutsch gern","jetzt Deutsch"],ans:"jetzt gern",hint:"In German, time adverbs typically come before manner adverbs."},

// 18. Temporal prepositions + dative (multi)
{type:"drag_fill",s:"{1} zwei Wochen lerne ich Deutsch und {2} dem Unterricht übe ich zu Hause.",blanks:{"1":"Seit","2":"nach"},pool:["Seit","Nach","nach","Vor","Während","Bis"],hint:"One preposition means 'for an ongoing duration.' The other means 'after.'",sSrc:"{1} two weeks I have been learning German and {2} class I practise at home."},

// 19. Wechselpräp + adjective declension accusative (multi)
{type:"fb",s:"Ich stelle die Blumen auf {1} Tisch.",a:["den kleinen"],opts:["den kleinen","dem kleinen","der kleine","das kleine"],hint:"Placing something is movement (accusative). The table is masculine.",sSrc:"I put the flowers on {1} table."},

// 20. Konjunktiv II + dative verb (multi)
{type:"mc",q:"'Es ___ mir besser, wenn ich mehr schlafen ___.' Fill both gaps.",opts:["ginge ... würde","geht ... werde","ging ... wollte","gehe ... würde"],ans:"ginge ... würde",hint:"Both verbs express an unreal wish. The first is an irregular Konjunktiv II form."},

// 21. Match: Grammar construct recognition
{type:"match",pairs:[{trg:"Ich habe das gemacht.",src:"Perfekt (haben)"},{trg:"Sie ist gefahren.",src:"Perfekt (sein)"},{trg:"Er konnte nicht kommen.",src:"Präteritum modal"},{trg:"Steh bitte auf!",src:"Imperative (separable)"},{trg:"Ich würde gern bleiben.",src:"Konjunktiv II"},{trg:"weil er müde ist",src:"Subordinate clause"}]},

// 22. weil + Perfekt sein + Partizip II (triple construct)
{type:"fb",s:"Er ist müde, weil er gestern spät nach Hause {1} ist.",a:["gekommen"],opts:["gekommen","kommen","kommt","kam"],hint:"This is Perfekt with sein inside a weil-clause. The auxiliary stays at the end.",sSrc:"He is tired because he {1} home late yesterday."},

// 23. Reflexive + wenn-clause + possessive (triple construct)
{type:"drag_fill",s:"Wenn ich {1} nicht beeile, verpasse ich {2} Zug.",blanks:{"1":"mich","2":"meinen"},pool:["mich","mir","sich","meinen","mein","meinem"],hint:"Sich beeilen takes accusative reflexive. The train is masculine accusative.",sSrc:"If I do not hurry {1}, I will miss {2} train."},

// 24. Adjective declension (no article, strong) + comparative
{type:"mc",q:"'Bei ___ Wetter bleibe ich lieber drinnen.' Which form is correct?",opts:["kaltem","kaltes","kalter","kalte"],ans:"kaltem",hint:"Bei takes dative. Without an article, the adjective must show the case itself."},

// 25. dass-clause + Konjunktiv II + temporal prep (triple construct)
{type:"fb",s:"Er sagt, dass er seit einer Woche krank {1}.",a:["wäre"],opts:["wäre","ist","war","sei"],hint:"Inside a dass-clause expressing an unreal or reported claim. Which mood?",sSrc:"He says that he {1} ill for a week."},

// 26. Full sentence reconstruction: 5 constructs
{type:"drag_fill",s:"Opa Heinrich erzählt, dass er {1} fünfzig Jahren {2} besten Bäcker {3} Stadt {4} hat.",blanks:{"1":"seit","2":"den","3":"der","4":"gefunden"},pool:["seit","den","der","gefunden","vor","dem","die","finden"],hint:"Temporal prep (ongoing) + accusative superlative + genitive article + Partizip II at clause end.",sSrc:"Opa Heinrich says that {1} fifty years he has {4} the best baker {2} the city {3}."},

// 27. Multi-construct: imperative + dative + Wechselpräp
{type:"mc",q:"Hildi says to Verumius: 'Leg ___ Mantel auf ___ Stuhl!' Which pair is correct?",opts:["deinen ... den","deinem ... dem","dein ... der","deiner ... dem"],ans:"deinen ... den",hint:"Legen is movement (accusative for both the object and the Wechselpräposition)."},

// 28. Grand finale: ob + reflexive + comparative + Perfekt (quad construct)
{type:"drag_fill",s:"Ich frage mich, ob ich {1} schneller verbessert {2} als {3} anderen Studenten.",blanks:{"1":"mich","2":"habe","3":"die"},pool:["mich","mir","sich","habe","bin","hat","die","den","der"],hint:"Sich verbessern (acc reflexive) in Perfekt (haben) inside an ob-clause. Plural article for comparison.",sSrc:"I wonder whether I have improved {1} faster {2} than {3} other students."}
]}
,

{id:"deu_r12l10",title:"Ich will bleiben",icon:"🎉",xp:20,board:true,steps:[
{type:"intro",title:"Ich will bleiben",desc:"Six months in Germany. Group chat celebration. Verumius has decided: he wants to stay. Time to learn the final vocabulary batch.",goals:["Personality and opinion adjectives","Essential adverbs and particles","The A2 finale: bridge to B1"]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-couch-phone",trg:"Verumius sitzt auf dem Sofa. Das Handy leuchtet. Lukas: 'Sechs Monate! Wahnsinn!' Mia: 'Du bist jetzt fast ein Berliner.' Yilmaz: 'Ich bin stolz auf dich.' Unter der Tür: ein Zettel von Hildi. 'Gut gemacht. H.'",src:"Verumius sits on the sofa. The phone glows. Lukas: 'Six months! Crazy!' Mia: 'You are almost a Berliner now.' Yilmaz: 'I am proud of you.' Under the door: a note from Hildi. 'Well done. H.'"},
{type:"teach",trg:"freundlich",src:"friendly",note:"Freund (friend) + -lich. Ein freundlicher Mensch.",example:"A: Die Leute hier sind sehr freundlich.\nB: Ja, besonders die Nachbarn.",exampleSrc:"A: The people here are very friendly.\nB: Yes, especially the neighbors.",funFact:"Freundlich comes from Freund (friend). The -lich suffix turns nouns into adjectives, like English -ly."},
{type:"teach",trg:"traurig",src:"sad",note:"Ich bin traurig = I am sad. Trauer = grief/mourning.",example:"A: Warum bist du traurig?\nB: Mein Freund ist weggezogen.",exampleSrc:"A: Why are you sad?\nB: My friend moved away.",funFact:"Trauer (grief) is the root. Traurig is the adjective. Trauerfeier is a funeral. Heavy word family."},
{type:"teach",trg:"wirklich",src:"really / truly",note:"Wirklich? = Really? Very common response in conversation.",example:"A: Ich lerne seit sechs Monaten Deutsch.\nB: Wirklich? Dein Deutsch ist toll!",exampleSrc:"A: I have been learning German for six months.\nB: Really? Your German is great!",funFact:"From wirken (to have an effect). Something 'wirklich' truly has an effect, it truly exists."},
{type:"teach",trg:"wahrscheinlich",src:"probably",note:"Wahr (true) + scheinlich (seeming). Likely true.",example:"A: Kommt er morgen?\nB: Wahrscheinlich. Er hat es versprochen.",exampleSrc:"A: Is he coming tomorrow?\nB: Probably. He promised.",funFact:"17 letters! One of the longer everyday German words. Wahr-schein-lich: truth-seeming-ly."},
{type:"mc",q:"'Dein Deutsch ist wirklich gut!' This is:",opts:["a genuine compliment","a sarcastic comment","a question","a command"],ans:"a genuine compliment",hint:"Wirklich means truly, really. This person means it."},
{type:"teach",trg:"natürlich",src:"of course / natural",note:"Natürlich! = Of course! Also means 'natural' (natürliche Zutaten).",example:"A: Kannst du mir helfen?\nB: Natürlich! Was brauchst du?",exampleSrc:"A: Can you help me?\nB: Of course! What do you need?",funFact:"Natürlich is German's go-to 'of course.' More enthusiastic than 'ja' but less formal than 'selbstverständlich.'"},
{type:"teach",trg:"genau",src:"exact / exactly",note:"Genau! = Exactly! Used constantly in conversation to agree.",example:"A: Also treffen wir uns um drei?\nB: Genau! Am Hauptbahnhof.",exampleSrc:"A: So we meet at three?\nB: Exactly! At the main station.",funFact:"Germans say 'genau' like Americans say 'right' or 'exactly.' You'll hear it 50 times per conversation."},
{type:"teach",trg:"doch",src:"yet / but / actually (particle)",note:"The most German word. Contradicts a negative: 'Nein!' - 'Doch!'",example:"A: Du sprichst kein Deutsch.\nB: Doch! Ich spreche Deutsch!",exampleSrc:"A: You don't speak German.\nB: Yes I do! I speak German!",funFact:"Doch has no direct English equivalent. It contradicts negatives. 'You can't do that' - 'Doch!' (Yes I can!). Untranslatable."},
{type:"fb",s:"Du kannst das nicht! - {1}! Ich kann das!",a:["Doch"],opts:["Doch","Nein","Ja","Aber"],hint:"Contradicting a negative statement. The uniquely German word.",sSrc:"You cannot do that! - {1}! I can do that!"},
{type:"teach",trg:"schade",src:"shame / pity / too bad",note:"Das ist schade! = That's a shame! Wie schade! = What a pity!",example:"A: Ich kann morgen nicht kommen.\nB: Schade! Wir vermissen dich.",exampleSrc:"A: I can't come tomorrow.\nB: Too bad! We'll miss you.",funFact:"Schade originally meant 'damage/harm.' 'Es ist schade' = it is damaging, regrettable. Softened over centuries."},
{type:"teach",trg:"unbedingt",src:"absolutely / by all means",note:"Un- (not) + bedingt (conditional). Unconditionally!",example:"A: Musst du das unbedingt heute machen?\nB: Ja, unbedingt! Es ist dringend.",exampleSrc:"A: Do you absolutely have to do that today?\nB: Yes, absolutely! It's urgent.",funFact:"Unbedingt literally means 'unconditional.' When you say 'unbedingt!', you mean there are zero conditions: it MUST happen."},
{type:"teach",trg:"kostenlos",src:"free (no cost)",note:"Kosten (cost) + los (without). Also: gratis, umsonst.",example:"A: Ist der Eintritt kostenlos?\nB: Ja, am ersten Sonntag im Monat.",exampleSrc:"A: Is the entrance free?\nB: Yes, on the first Sunday of the month.",funFact:"German has 3 words for free: kostenlos (no cost), gratis (Latin loan), umsonst (also means 'in vain')."},
{type:"mc",q:"The museum is 'kostenlos' on Sundays. This means:",opts:["free entrance","closed","expensive","members only"],ans:"free entrance",hint:"Kosten = cost. Los = without. Without cost."},
{type:"teach",trg:"sonst",src:"otherwise / else",note:"Was möchtest du sonst? = What else would you like?",example:"A: Brauchst du sonst noch etwas?\nB: Nein, danke. Das ist alles.",exampleSrc:"A: Do you need anything else?\nB: No, thanks. That's everything.",funFact:"Sonst covers both 'otherwise' (condition) and 'else' (addition). Context: 'Beeil dich, sonst...' = hurry, otherwise..."},
{type:"teach",trg:"außerdem",src:"besides / moreover",note:"Außer (except) + dem. A formal connector for adding information.",example:"A: Warum lernst du Deutsch?\nB: Ich lebe in Berlin. Außerdem liebe ich die Sprache.",exampleSrc:"A: Why are you learning German?\nB: I live in Berlin. Besides, I love the language.",funFact:"Außerdem is a sentence adverb. It goes in position 1 or after the verb. Great for written arguments."},
{type:"teach",trg:"mindestens",src:"at least",note:"Mindest (least/minimum) + -ens. Mindestens eine Stunde = at least one hour.",example:"A: Wie lange übst du jeden Tag?\nB: Mindestens eine Stunde.\nA: Das ist viel!",exampleSrc:"A: How long do you practice every day?\nB: At least one hour.\nA: That's a lot!",funFact:"Mindestlohn = minimum wage. Mindestalter = minimum age. The prefix mindest- means 'minimum.'"},
{type:"teach",trg:"deshalb",src:"therefore / that's why",note:"Connector. Ich war krank, deshalb bin ich zu Hause geblieben.",example:"A: Warum bist du nicht gekommen?\nB: Ich war krank, deshalb bin ich geblieben.",exampleSrc:"A: Why didn't you come?\nB: I was sick, that's why I stayed.",funFact:"Deshalb, darum, deswegen all mean 'therefore.' Germans love having 3 words for the same connector."},
{type:"fb",s:"Ich war müde, {1} bin ich früh ins Bett gegangen.",a:["deshalb"],opts:["deshalb","trotzdem","außerdem","sonst"],hint:"I was tired, THEREFORE I went to bed early. Cause and effect.",sSrc:"I was tired, {1} I went to bed early."},
{type:"teach",trg:"einige",src:"some / several",note:"Einige Leute = some people. More than 'ein paar' but less than 'viele.'",example:"A: Hast du Freunde in Berlin?\nB: Ja, einige. Wir treffen uns oft.",exampleSrc:"A: Do you have friends in Berlin?\nB: Yes, some. We meet often.",funFact:"The scale: wenige (few) < ein paar (a couple) < einige (some) < viele (many) < alle (all)."},
{type:"teach",trg:"überall",src:"everywhere",note:"Über (over) + all (all). In every place.",example:"A: Wo findet man gutes Brot in Deutschland?\nB: Überall! Es gibt überall Bäckereien.",exampleSrc:"A: Where can you find good bread in Germany?\nB: Everywhere! There are bakeries everywhere.",funFact:"Überall is the opposite of nirgends (nowhere). Über (over) + all (all) = over all places."},
{type:"teach",trg:"zum Beispiel",src:"for example",note:"Abbreviated: z.B. Very common in writing and speech.",example:"A: Was machst du in deiner Freizeit?\nB: Viele Sachen. Zum Beispiel joggen und malen.",exampleSrc:"A: What do you do in your free time?\nB: Many things. For example, jogging and painting.",funFact:"z.B. is the German equivalent of 'e.g.' You see it everywhere in formal writing."},
{type:"drag_fill",s:"Ich lerne {1} eine Stunde Deutsch pro Tag. {2} lese ich deutsche Nachrichten.",blanks:{"1":"mindestens","2":"Außerdem"},pool:["mindestens","Außerdem","deshalb","sonst","überall","natürlich"],hint:"AT LEAST one hour. BESIDES that, I also read news.",sSrc:"I learn {1} one hour of German per day. {2} I read German news."},
{type:"teach",trg:"der Ehepartner",src:"the spouse",gender:"m",example:"A: Kommt dein Ehepartner auch?\nB: Ja, wir kommen zusammen.\nA: Schön, ich freue mich!",exampleSrc:"A: Is your spouse coming too?\nB: Yes, we are coming together.\nA: Great, I am looking forward to it!",note:"Masculine. Feminine form: die Ehepartnerin. Ehe (marriage) + Partner.",funFact:"On official German forms, you must always state your Familienstand: ledig, verheiratet, geschieden, or verwitwet."},
{type:"teach",trg:"die Zitrone",src:"the lemon",gender:"f",example:"A: Möchtest du Zitrone im Tee?\nB: Ja, bitte! Mit Zitrone schmeckt er besser.",exampleSrc:"A: Would you like lemon in your tea?\nB: Yes, please! It tastes better with lemon.",note:"die Zitrone, feminine. Plural: die Zitronen. Also: Zitronensaft (lemon juice).",funFact:"Germans love Zitrone in water and tea. The phrase 'eine saure Zitrone' (a sour lemon) describes a grumpy person."},
{type:"teach",trg:"sich erinnern",src:"to remember",example:"A: Erinnerst du dich an den ersten Tag?\nB: Ja, ich erinnere mich gut daran!",exampleSrc:"A: Do you remember the first day?\nB: Yes, I remember it well!",note:"Reflexive verb: sich erinnern an + accusative. Ich erinnere mich, du erinnerst dich.",funFact:"'Erinnerung' (memory/souvenir) is one of the most emotional German words. 'Zur Erinnerung' means 'in memory of.'"},
{type:"teach",trg:"erreichen",src:"to reach / to achieve",example:"A: Hast du dein Ziel erreicht?\nB: Ja, endlich! Nach sechs Monaten.",exampleSrc:"A: Did you reach your goal?\nB: Yes, finally! After six months.",note:"Regular: ich erreiche, du erreichst. Er- prefix is inseparable.",funFact:"The noun 'die Erreichbarkeit' (reachability) appears on German business cards to indicate when someone can be contacted."},
{type:"teach",trg:"klappen",src:"to work out / to succeed",example:"A: Hat alles geklappt?\nB: Ja, es hat super geklappt!\nA: Das freut mich!",exampleSrc:"A: Did everything work out?\nB: Yes, it worked out great!\nA: I am glad!",note:"Regular: es klappt. Very common in everyday speech. 'Hat geklappt!' = It worked!",funFact:"'Klappt's?' is a casual way to ask 'Is it working?' Used constantly in offices and kitchens."},
{type:"teach",trg:"kontrollieren",src:"to check / to control",example:"A: Kontrollierst du bitte die Liste?\nB: Ja, ich kontrolliere sie sofort.",exampleSrc:"A: Can you check the list?\nB: Yes, I will check it right away.",note:"Regular: ich kontrolliere. From French 'contrôler.' Used for checking documents, tickets, etc.",funFact:"Ticket controllers (Kontrolleure) on German trains and buses are famous for their thoroughness."},
{type:"teach",trg:"ausgeben",src:"to spend (money)",example:"A: Wie viel gibst du pro Monat aus?\nB: Zu viel! Ich muss sparen.",exampleSrc:"A: How much do you spend per month?\nB: Too much! I need to save.",note:"Separable: ich gebe aus, du gibst aus. Irregular: stem change e to i.",funFact:"Germans track spending carefully. The word 'Ausgaben' (expenses) appears on every household budget plan."},
{type:"match",pairs:[{trg:"freundlich",src:"friendly"},{trg:"traurig",src:"sad"},{trg:"wirklich",src:"really"},{trg:"doch",src:"yes (contradicting)"},{trg:"deshalb",src:"therefore"},{trg:"überall",src:"everywhere"},{trg:"kostenlos",src:"free"},{trg:"genau",src:"exactly"}]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-couch-night",trg:"Verumius legt das Handy hin. Sechs Monate. Eine Wohnung. Freunde. Eine Sprache, die langsam seine wird. Er denkt an die Ankunft am Flughafen. Den falschen Zug. Die 14-seitige Hausordnung. Den Müll. Den Arzt. Den Lauftreff. Die Deutsche Bahn. Den Glühwein. Und jetzt: KD hat gelacht. Alles ist möglich. Er will bleiben.",src:"Verumius puts down the phone. Six months. An apartment. Friends. A language that is slowly becoming his. He thinks about arriving at the airport. The wrong train. The 14-page house rules. The trash. The doctor. The running club. Deutsche Bahn. The Glühwein. And now: KD laughed. Anything is possible. He wants to stay."},
{type:"tip",title:"A2 Complete: Verumius Belongs",text:"Unit 12 is the end of A2.\n\nVerumius can now:\n1. Talk about the past (Perfekt, Prateritum modals)\n2. Express opinions (Ich denke, dass...)\n3. Compare things (besser als, am besten)\n4. Describe people and objects (adjective declension)\n5. Navigate German bureaucracy\n6. Have real conversations with friends\n\nBut A2 is just daily communication.\nB1 is where adventure begins.\n\n'Ich will bleiben. Das bedeutet: einen Job.'",deepDive:"A2 covered 612 Goethe words and 25 grammar constructs. Verumius has grown from tourist to resident. The next challenge: professional German, job applications, and deeper cultural integration."},
{type:"mc",q:"What has Verumius decided at the end of A2?",opts:["He wants to stay in Germany","He wants to go home","He wants to move to Munich","He wants to become a teacher"],ans:"He wants to stay in Germany",hint:"'Ich will bleiben.' The verb 'bleiben' is key. Think about what this requires."}
]}

]}

